CREATE FUNCTION [dbo].[FN_CalculateDepreciation] (@ProductId nvarchar(20),@DepCalMethod nvarchar(100),@Dateto Date)
RETURNS numeric(16,2) 

AS BEGIN

--select dbo.FN_CalculateDepreciation(CodeNo,DepMethod,'2021-01-01') as OBDepAmount,
--(dbo.FN_CalculateDepreciation(CodeNo,DepMethod,'2021-12-31')-dbo.FN_CalculateDepreciation(CodeNo,DepMethod,'2021-01-01')) AS DepThisPeriod,
--Purchasedate , DepRate , TotalPrice ,*  
--from FixedAssetRegister
--where valid = 1 and Purchasedate between '2021-01-01' and '2021-12-31'


DECLARE @Balance numeric(16,2); 
DECLARE @CalDep numeric(16,2); 
DECLARE @CalTotalDep numeric(16,2); 
DECLARE @NoofYear int=0;
DECLARE	@Counter int= 1 ;

SET @CalTotalDep = 0

IF @DepCalMethod = 'Diminishing Balance'
	BEGIN
	--SET @NoofYear = (select Year(@Dateto) - Year(Purchasedate)  AS NoofYear from FixedAssetRegister where CodeNo = @ProductId and Valid = 1 AND DepMethod = 'Diminishing Balance' AND Purchasedate < @Dateto );
	SET @NoofYear = (select DATEDIFF(m,Purchasedate,@Dateto)+1  AS NoofYear from FixedAssetRegister where CodeNo = @ProductId and Valid = 1 AND DepMethod = 'Diminishing Balance' AND Purchasedate <= @Dateto );
	SET @Balance = (select TotalPrice AS Balance from FixedAssetRegister where CodeNo = @ProductId and Valid = 1 AND DepMethod = 'Diminishing Balance');
	WHILE @Counter< = @NoofYear
		BEGIN
			SET @CalDep = (SELECT  (@Balance * 0.01 * (DepRate/12)) as depcal  from FixedAssetRegister where CodeNo = @ProductId and Valid = 1 AND DepMethod = 'Diminishing Balance' ) ;
			SET @Balance = @Balance-@CalDep
			SET @CalTotalDep=@CalTotalDep+@CalDep
			SET @Counter= @Counter + 1
		END
		--set @CalTotalDep = (select CASE WHEN @CalTotalDep <0 then 0 else @CalTotalDep end)
		RETURN @CalTotalDep
	END

IF @DepCalMethod = 'Straight Line'
	BEGIN
		SET @CalTotalDep = 	(SELECT  (TotalPrice * 0.01 * (DepRate/12) * ((DATEDIFF(m,purchasedate,@Dateto)+1))) as depcal
						from FixedAssetRegister 
						where CodeNo = @ProductId and Valid = 1 
						AND DepMethod = 'Straight Line' AND PurchaseDate <= @dateTo)
						
	END
--	set @CalTotalDep = (select CASE WHEN @CalTotalDep <0 then 0 else @CalTotalDep end)
	RETURN @CalTotalDep
END

GO
