CREATE FUNCTION [dbo].[fnc_DiagInvName]
(
@InvNo as nvarchar(20),
@InvDate as nvarchar(20),
@BranchId as Int
)  
RETURNS nvarchar(1000)  
AS
begin
return
(  
	Select InvstName = STUFF((
	SELECT ','+ShortDesc 
	From InvDetails where BranchId = a.BranchId AND InvNo = a.InvNo and InvDate = a.InvDate
	and Valid = 1 order by ShortDesc FOR XML PATH ('')), 1, 1, '' ) 
	from InvDetails a
	where BranchId = @BranchId AND a.InvNo = @InvNo and a.InvDate = @InvDate
	group by InvNo, InvDate, BranchId
); 
end
