CREATE FUNCTION [dbo].[fnc_DiagXrayRpt]
(
@InvNo as nvarchar(20),
@InvDate as nvarchar(20)
)  
RETURNS nvarchar(1000)  
AS
begin
return
(  
	Select InvstName = STUFF((
	SELECT ','+ShortDesc 
	From InvDetails a , ClinicalChart b 
	where a.pcode=b.pcode and  InvNo = a.InvNo and InvDate = a.InvDate and a.InvNo = @InvNo and a.InvDate = @InvDate
	and b.SubSubDeptName IN ('X-ray','MRI')
	and a.Valid = 1 order by a.ShortDesc FOR XML PATH ('')), 1, 1, '' ) 
); 
end



