/****** Object:  UserDefinedFunction [dbo].[fnc_FA_CalBalanceDimilisingAmount]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [dbo].[fnc_FA_CalBalanceDimilisingAmount] (@BV float, @ND int,@DeclingBalPC float)	
RETURNS float	
AS	
BEGIN	
	DECLARE @DepreciationAmt float 
    SET @DepreciationAmt = 0
    
	select @DepreciationAmt = @BV*(1-POWER((1-(@DeclingBalPC)/100),(365/365)))
	
	SELECT @DepreciationAmt =round(((@DepreciationAmt*@ND)/365),3)
	
    RETURN @DepreciationAmt
    
END 	

