CREATE FUNCTION [dbo].[fnc_InPreviousIssueQty] (@DeptName VARCHaR(50), @ProductCode VARCHAR(50), @BranchId INT)
RETURNS @Result TABLE (IssueDate DATE, Quantity INT)
AS
BEGIN
	DECLARE @trDate DATE;
	SELECT @trDAte = MAX(TrDate) 
	FROM InvStockLedger 
	WHERE BranchId = @BranchId AND Valid = 1 AND OutQty!= 0 AND IssueDeptName = @DeptName AND ProductCode = @ProductCode;
	
	INSERT INTO @Result(IssueDate, Quantity)
	SELECT TrDate, SUM(OutQty) AS OutQty 
	FROM InvStockLedger 
	where BranchId = @BranchId AND Valid = 1 AND OutQty!= 0 AND IssueDeptName = @DeptName AND ProductCode = @ProductCode and TrDate = @trDate
	GROUP BY TrDate
	--ORDER BY id DESC;
	RETURN
END 
GO
