CREATE FUNCTION [dbo].[fnc_InPreviousPurchaseInfo] (@ProductCode VARCHAR(50), @BranchId INT)
RETURNS @Result TABLE (LastPurchaseDate DATE, Quantity INT)
AS
BEGIN
	DECLARE @trDate DATE;
	SELECT @trDAte = MAX(TrDate) 
	FROM InvStockLedger 
	WHERE BranchId = @BranchId AND Valid = 1 AND InQty> 0 AND ProductCode = @ProductCode;
	
	INSERT INTO @Result(LastPurchaseDate, Quantity)
	SELECT TrDate, SUM(InQty) AS InQty 
	FROM InvStockLedger 
	where BranchId = @BranchId AND Valid = 1 AND InQty> 0 AND ProductCode = @ProductCode and TrDate = @trDate
	GROUP BY TrDate
	--ORDER BY id DESC;
	RETURN
END 
