CREATE FUNCTION [dbo].[fncDiagRemarks]
(
@InvNo as nvarchar(20),
@InvDate as nvarchar(20),
@BranchId as int
)  
RETURNS nvarchar(1000)  
AS
begin
return
(  
    SELECT Comments = STUFF((
	SELECT Comments+','+SPACE(5)
	From SalesLedger where BranchId = @BranchId AND PrevInvNo = a.PrevInvNo and PreInvDate = a.PreInvDate
