CREATE FUNCTION [dbo].[RPAD]
(
    @string VARCHAR(MAX), -- Initial string
    @length INT,          -- Size of final string
    @pad CHAR             -- Pad character
)
RETURNS VARCHAR(MAX)
AS
BEGIN
    RETURN @string+REPLICATE(@pad, @length - LEN(@string))  ;
END

