/****** Object:  View [dbo].[VW_MIS_SaleCollDeptWise]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE VIEW [dbo].[VW_MIS_SaleCollDeptWise] AS

SELECT 1 AS SlNo, 'INDOOR' AS MainDept, c.SubSubPno AS DeptName, a.ReleaseDate as RefDate, b.RefNo, b.PatientId, b.PatientName, SUM(b.NoU*b.Charge+b.ServiceCharge) AS Sales, 
SUM(b.Less) AS Less, 0 as RtnAmt,
0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, SUM(b.ReturnAmt) AS CashReturn, a.BranchId
FROM PatientAdmission a
LEFT JOIN PatientLedger b ON a.PatientId = b.PatientId AND a.BranchId = b.BranchId
LEFT JOIN BedInformation c ON b.BedNo = c.BedNo AND a.BranchId = c.BranchId
WHERE a.IsRelease = 1 AND b.valid = 1 AND a.BranchId = 1
GROUP BY c.SubSubPno, a.ReleaseDate, b.RefNo, b.PatientId, b.PatientName, a.BranchId
UNION ALL
SELECT 1 AS SlNo, 'INDOOR' AS MainDept, 'Advance Collection' AS DeptName, b.RefDate, b.RefNo, PatientId, PatientName, 0 AS Sales, 0 AS Less, 0 as RtnAmt,
SUM(b.CashAmt) AS ByCash, SUM(b.CardAmt) AS ByCard, SUM(b.ChequeAmt) AS ByCheque, 0 AS CashReturn, b.BranchId
FROM PatientLedger b
WHERE b.valid = 1 AND b.BranchId = 1 AND b.Status <> 'Advance Collection'
GROUP BY b.RefDate, b.RefNo, b.PatientId, b.PatientName, b.BranchId
HAVING SUM(b.CashAmt+b.CardAmt+b.ChequeAmt) <> 0
UNION ALL
SELECT 1 AS SlNo, 'INDOOR' AS MainDept, 'Advance Collection' AS DeptName, b.RefDate, b.RefNo, PatientId, PatientName, 0 AS Sales, 0 AS Less, 0 as RtnAmt,
SUM(b.CashAmt) AS ByCash, SUM(b.CardAmt) AS ByCard, SUM(b.ChequeAmt) AS ByCheque, 0 AS CashReturn, b.BranchId
FROM PatientLedger b
WHERE b.valid = 1 AND b.BranchId = 1 AND b.Status = 'Advance Collection'
GROUP BY b.RefDate, b.RefNo, b.PatientId, b.PatientName, b.BranchId
UNION ALL
select 2 as slno, 'OUTDOOR' AS MainDept, Department AS DeptName, RefDate, RefNo, PatientId, Particulars, SUM(Sales) AS Sales, SUM(Less) AS Less, SUM(ReturnNet) AS RtnAmt,
SUM(ByCash) AS ByCash, SUM(ByCard) AS ByCard, SUM(ChequeAmount) AS ByCheque, SUM(ReturnCash) AS CashReturn, BranchId
from SalesLedger 
where valid = 1 AND Department <> 'Ambulance' --and PtStatus <> 'Indoor'
AND BranchId = 1
GROUP BY Department, RefDate, RefNo, PatientId, Particulars, BranchId
--UNION ALL
--SELECT 3 as slno,'OUTDOOR' AS MainDept, 'MEDICINE' AS DeptName, TrDate, TrNo, PatientId, Particulars, SUM(SALES) AS Sales, SUM(LessAmt) AS Less, SUM(ReturnAmt) AS RtnAmt,
--SUM(CashAmt) AS ByCash, SUM(CardAmt) AS ByCard, SUM(ChequeAmt) AS ByCheque, SUM(CashReturn) AS CashReturn, BranchId
--FROM PharSalesLedger 
--where valid = 1 and PtStatus <> 'Indoor' AND BranchId = 1
--GROUP BY TrDate, TrNo, PatientId, Particulars, BranchId
UNION ALL 
SELECT 4 as slno, 'OUTDOOR' AS MainDept, 'OPD TICKET' AS DeptName, TrDate, TrNo, '' AS PatientId, Name AS PatientName, SUM(Amount) AS Sales, 0 as Less, 0 AS RtnAmt,
SUM(Amount) as CashAmt, 0 as CardAmt, 0 as ChequeAmt, SUM(a.RtnAmount) as CashReturn, a.BranchId
FROM OPDTicketMaster a
where a.valid = 1 AND BranchId = 1
GROUP BY TrDate, TrNo, Name, a.BranchId
UNION ALL 
SELECT 5 as slno, 'OUTDOOR' AS MainDept, 'Registration' AS DeptName, a.TrDate, a.TrNo, '' AS PatientId, a.PatientName, SUM(a.Amount) AS Sales, 0 as Less, 0 AS RtnAmt,
SUM(a.Amount) as CashAmt, 0 as CardAmt, 0 as ChequeAmt, 0 as CashReturn, a.BranchId
FROM RegistrationFees a
where a.valid = 1 AND BranchId = 1
GROUP BY a.TrDate, a.TrNo, a.PatientName, a.BranchId
UNION ALL
SELECT 6 as slno, 'AMBULANCE' As MainDept, 'Ambulance' AS DeptName, RefDate, RefNo, PatientId, PatientName, SUM(TotalCharge) AS Sales, SUM(Less), 0 AS RtnAmt,
SUM(CashAmt) as ByCash, SUM(CardAmt) as ByCard, SUM(ChequeAmt) as ByCheque, 0 AS CashReturn, BranchId
FROM AmbulanceLedger
where BranchId = 1 AND valid = 1
GROUP BY RefDate, RefNo, PatientId, PatientName, BranchId
UNION ALL
SELECT 7 AS SlNo, 'Indoor Refund' AS AcCode, 'Indoor Refund' AS DeptName, TrDate, TrNo, PatientId, PatientName, 0 AS Sales, 0 AS Less, 0 AS RtnAmt, 
0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, Amount AS CashReturn, 1 AS BranchId
FROM CashReturn WHERE Amount <> 0 AND Valid=1
GROUP BY TrDate, TrNo, PatientId, PatientName, Amount





GO
