SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VW_AppointmentList]
AS
	SELECT ISNULL(b.RegNo, '') AS RegNo, a.Id, a.SlNo, a.AppDate, a.VisitDate, a.DrCode, a.DrName, a.PatientName, a.MobileNo, a.Dob, 
	a.AgeYear+'Y '+a.AgeMonth+'M '+a.AgeDay+'D' AS Age, a.Sex, a.IsArrival, a.ArrivalTime, a.VisitDesc, a.UserName, a.EntryDate, a.VisitAmt, a.PaymentNo, a.BranchId, a.PtType, c.Name AS ShiftName
	FROM PatientAppointment a 
	LEFT JOIN PatientRegistration b on a.BranchId = b.BranchId AND a.RegNo = b.RegNo
	LEFT JOIN BaseTable c ON a.ShiftTypeId=c.Id
	WHERE a.Valid = 1
GO
