GO

CREATE VIEW [dbo].[VW_GET_DATEWISE_PURCHASE]
AS
SELECT a.Id,d.Name AS PnoName,a.InvoiceNo,a.InvoiceDate,a.SuppId,b.ReceiptNo,b.ReceiptDate,a.PayableAmount as PurchaseAmount,
a.UserName,c.Name As SuppName,a.Pno, a.EntryDate
FROM tbl_PURCHASE_LEDGER a 
LEFT JOIN tbl_STOCK_IN_MAIN b ON a.InvoiceNo=b.InvoiceNo AND a.InvoiceDate=b.InvoiceDate AND a.Pno=b.Pno
LEFT JOIN tbl_SUPPLIER_INFO_MASTER c ON a.SuppId=c.Id 
LEFT JOIN tbl_COMPANY_INFORMATION d ON d.Id=a.Pno
WHERE a.Status='Purchase' AND a.PayableAmount>0






