/****** Object:  View [dbo].[VW_PharCurrentStock]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE view [dbo].[VW_PharCurrentStock] as 
SELECT a.Id, ISNULL(c.Company_Id,'-') AS CompanyId, a.ProductId, a.ProductName, (CASE WHEN a.ProductNameFull = '0' THEN '' ELSE a.ProductNameFull END) AS Generic, a.ProductUnit, a.PharDeptId, a.PharDeptName, a.ProductGroup, a.WholeSalePrice, a.RackNo, d.Name AS ProductGroupName,
sum(ISNULL(b.InQty,0) - ISNULL(b.OutQty,0)) AS CurrentStock, a.TP, a.SalePrice, c.Name as CompanyName, ISNULL(b.ExpireDate,'') as ExpiryDate, 
ISNULL(b.UnitId,0) AS UnitId, ISNULL(b.StoreId,0) As StoreId, ISNULL(b.BranchId,0) AS BranchId, a.ReminderStock
FROM PharProductInfo a
LEFT JOIN PharmaCurrentStock b ON a.Id = b.ProductId
LEFT JOIN PharCompanyInfo c ON a.CompanyId = c.Company_Id
LEFT JOIN PharPdGroup d on a.ProductGroup = d.Id
WHERE a.IsActive=1
GROUP BY a.Id, c.Company_Id, a.ProductId, a.ProductName, a.ProductNameFull, a.ProductUnit, a.PharDeptId, a.PharDeptName, a.ProductGroup, a.WholeSalePrice, a.RackNo, a.TP, a.SalePrice, d.Name,
c.Name,b.ExpireDate, b.UnitId, b.StoreId, b.BranchId, a.ReminderStock
--having sum(b.InQty - b.OutQty) >= 0
GO
