/****** Object:  View [dbo].[VW_PharPdWiseCurrStock]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VW_PharPdWiseCurrStock]
AS
	--select ISNULL(c.Company_Id, '') AS CompanyId, a.ProductName, a.ProductUnit, a.ProductGroup, a.WholeSalePrice, sum(ISNULL(b.InQty,0) - ISNULL(b.OutQty,0)) AS CurrentStock,
	--a.TP, a.SalePrice, ISNULL(c.Name,'') AS CompanyName, ISNULL(b.ExpireDate,'') AS ExpiryDate, ISNULL(b.UnitId, 0) AS UnitId, ISNULL(b.StoreId, 0) as StoreId,
	--ISNULL(b.BranchId, 0) AS BranchId, ISNULL(d.SubSubPno, '') AS StoreName
	--from PharProductInfo a
	--LEFT JOIN PharStockLedger b ON a.Id = b.ProductId
	--LEFT JOIN PharCompanyInfo c ON a.CompanyId = c.Company_Id
	--left join ProjectInformations d ON b.StoreId = d.PnoCode
	--GROUP BY c.Company_Id, a.ProductName, a.ProductUnit, a.ProductGroup, a.WholeSalePrice,
	--a.TP, a.SalePrice, c.Name, b.ExpireDate, b.UnitId, b.StoreId, b.BranchId, d.SubSubPno 
	--having sum(b.InQty - b.OutQty) != 0

	--select ISNULL(a.CompanyId, '') AS CompanyId,a.ProductName, a.ProductUnit, a.ProductGroup, a.WholeSalePrice, sum(ISNULL(b.InQty,0)+ isnull(b.RtnQty,0) - ISNULL(b.OutQty,0) ) AS CurrentStock,
	--a.TP, a.SalePrice, ISNULL(a.CompanyName,'') AS CompanyName,ISNULL(b.UnitId, 0) AS UnitId, ISNULL(b.StoreId, 0) as StoreId,
	--ISNULL(b.BranchId, 0) AS BranchId, ISNULL(d.SubSubPno, '') AS StoreName
	--from PharProductInfo a
	----LEFT JOIN PharmaCurrentStock b ON a.Id = b.ProductId
	--LEFT JOIN PharStockLedger b ON a.ProductName = b.ProductName 
	--left join ProjectInformations d ON b.StoreId = d.PnoCode
	--GROUP BY a.CompanyId, a.ProductName, a.ProductUnit, a.ProductGroup, a.WholeSalePrice,
	--a.TP, a.SalePrice, a.CompanyName, b.UnitId, b.StoreId, b.BranchId, d.SubSubPno 
	--having sum(isnull(b.InQty,0)+isnull(b.RtnQty,0)-isnull(b.OutQty,0)) != 0
	select ISNULL(a.CompanyId, '') AS CompanyId,a.ProductName, a.ProductUnit, a.ProductGroup, a.WholeSalePrice, sum(ISNULL(b.InQty,0) - ISNULL(b.OutQty,0) ) AS CurrentStock,
	a.TP, a.SalePrice, ISNULL(a.CompanyName,'') AS CompanyName,ISNULL(b.UnitId, 0) AS UnitId, ISNULL(b.StoreId, 0) as StoreId,
	ISNULL(b.BranchId, 0) AS BranchId, ISNULL(d.SubSubPno, '') AS StoreName
	from PharProductInfo a
	LEFT JOIN PharmaCurrentStock b ON a.Id = b.ProductId
	--LEFT JOIN PharStockLedger b ON a.ProductName = b.ProductName 
	left join ProjectInformations d ON b.StoreId = d.PnoCode
	GROUP BY a.CompanyId, a.ProductName, a.ProductUnit, a.ProductGroup, a.WholeSalePrice,
	a.TP, a.SalePrice, a.CompanyName, b.UnitId, b.StoreId, b.BranchId, d.SubSubPno 
	having sum(isnull(b.InQty,0)-isnull(b.OutQty,0)) != 0
