LEFT JOIN tbl_COMPANY_INFORMATION e ON e.Id=a.Pno
LEFT JOIN tbl_BRAND f ON f.Id=d.BrandId
LEFT JOIN tbl_ITEM_MAIN_CATEGORY g ON g.Id=d.MainCatId 







