/****** Object:  View [dbo].[VW_GET_OUTSTANDING]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE VIEW [dbo].[VW_GET_OUTSTANDING]
AS
SELECT 'Creditor' AS GroupName, a.Pno,c.Name AS BranchName,a.SuppId AS PartyId,b.Name AS PartyName,b.Address,b.MobileNo,ROUND(SUM(a.PayableAmount-a.PaymentAmount-a.ReturnAmount),2) AS BalAmt
FROM tbl_PURCHASE_LEDGER a LEFT JOIN tbl_SUPPLIER_INFO_MASTER b ON a.SuppId=b.Id
LEFT JOIN tbl_COMPANY_INFORMATION c ON c.Id=a.Pno 
GROUP BY a.SuppId,a.Pno,b.Name,b.Address,b.MobileNo,c.Name
having ROUND(SUM(a.PayableAmount-a.PaymentAmount-a.ReturnAmount),2)>0
UNION ALL
SELECT 'Debitor' AS GroupName,a.Pno,c.Name AS BranchName,a.CustId As PartyId,b.Name AS PartyName,b.Address,b.MobileNo, ROUND(SUM(a.SalesAmount-a.LessAmount-a.CollectionAmount-a.ReturnAmount),2) AS BalAmt 
FROM tbl_SALES_LEDGER a LEFT JOIN tbl_CUSTOMER b ON a.CustId=b.Id
LEFT JOIN tbl_COMPANY_INFORMATION c ON c.Id=a.Pno
GROUP BY a.CustId,a.Pno,b.Name,b.Address,b.MobileNo,c.Name
having ROUND(SUM(a.SalesAmount-a.LessAmount-a.CollectionAmount-a.ReturnAmount),2)>0







