/****** Object:  View [dbo].[VW_DIAGNOSIS_INV_LIST_AFTER_RETURN]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE VIEW [dbo].[VW_DIAGNOSIS_INV_LIST_AFTER_RETURN] AS 
	select  a.PtStatus as AdmissionType,a.InvNo,a.InvDate,a.DeptName,a.MobNo,a.PatientId,a.PatientName,a.RegNo,a.BedNo,a.Age,a.DOB,a.Sex,
	a.Address, a.ConsultantCode,a.ConsultantName,a.RefDrCode,a.RefDrName,a.IsCorporate,a.CorporateCode,a.CorporateName,a.LessAmount,
	a.LessPcOrTk, a.DiscountFrom, b.Amount*b.Quantity as TotalAmt ,a.VatAmount,a.CashAmt,a.CardAmt,a.CardNo,a.CardBank, a.ReturnDate, a.ReturnBy,
	a.ChequeAmt,a.ChequeNo, a.ChequeBank, a.ChequeDate,b.RptDeliveryTime,a.Remarks,b.PCode,b.ShortDesc,b.Quantity,b.Amount,
	b.TotalAmount,b.IsUrgent, b.RptDeliveryDate, b.Valid, a.Username, a.EntryTime ReplacyByEntryTime, c.Name as UnitName, ISNULL(d.DonorName,'') AS DonorName,
	 ISNULL(d.DonorAge,'') AS DonorAge, ISNULL(d.DonorGender,'') AS DonorGender, b.GLessAmt as Discount, a.BranchId,
	(select SUM(Collection) as Coll from SalesLedger where BranchId = a.BranchId AND PrevInvNo = a.InvNo) AdvanceAmt,
	(select SUM(Less) as Coll from SalesLedger where BranchId = a.BranchId AND PrevInvNo = a.InvNo) TotalLess,
	(select SUM(ReturnAmt) as Coll from InvMaster where BranchId = a.BranchId AND InvNo = a.InvNo) ReturnAmt,
	(select SUM(ReturnLess) as Coll from InvMaster where BranchId = a.BranchId AND InvNo = a.InvNo) LessReturn,
	(select SUM(ReturnNet) as Coll from InvMaster where BranchId = a.BranchId AND InvNo = a.InvNo) NetReturn,
	(select SUM(ReturnCash) as Coll from InvMaster where BranchId = a.BranchId AND InvNo = a.InvNo) CashReturn,
	(select SUM(ReturnDue) as Coll from InvMaster where BranchId = a.BranchId AND InvNo = a.InvNo) DueReturn,
	(select DISTINCT TOP 1 ReturnBy from InvReturn m where m.BranchId = a.BranchId AND m.InvNo = a.InvNo) ReturnPostBy,
	(select DISTINCT TOP 1 EntryDateTime from InvReturn m where m.BranchId = a.BranchId AND m.InvNo = a.InvNo) As EntryTime
	from InvMaster a
	left join invDetails b on a.InvNo=b.InvNo and a.InvDate=b.InvDate AND a.BranchId = b.BranchId
	left join tbl_COMPANY_INFORMATION c on a.CostCenterName = c.Id AND a.BranchId = c.BranchId
	left join DonorInfo d on a.InvNo = d.InvNo AND a.BranchId = d.BranchId
	left join ClinicalChart e on b.PCode = e.PCode AND a.BranchId = e.BranchId
	where a.Valid <> 0 and b.Valid <> 0 And a.ReturnAmt> 0

GO
