/****** Object:  View [dbo].[VW_GET_SALES_RETURN_LIST]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[VW_GET_SALES_RETURN_LIST]
AS
SELECT a.TotalProduct,a.TotalDiscount,a.TotalVat,a.TotalPrice,a.RefNo,a.RefDate,g.Name AS BranchName,a.Pno,a.InvoiceNo,a.InvoiceDate,a.CustId,b.ItemId,b.BarcodeId,b.ItemDiscount,b.PurchasePrice,b.Quantity,b.SalesPrice,c.Model,c.Name AS ItemName,c.MainCatId,c.BrandId,d.Name As CatName,e.Name AS BrandName,Isnull(a.Remarks,'N/A') AS Remarks,a.UserName,f.Name AS CustName,f.Address,f.MobileNo,h.ReturnAmount AS AdjustAmt,h.CashReturnAmount,a.EntryDate,g.Name AS PnoName  
FROM tbl_SALES_RETURN_MASTER a 
LEFT JOIN tbl_SALES_RETURN_DETAIL b ON a.InvoiceNo=b.InvoiceNo AND a.InvoiceDate=b.InvoiceDate AND a.Pno=b.Pno
LEFT JOIN tbl_ITEM c ON b.ItemId=c.Id
LEFT JOIN tbl_ITEM_MAIN_CATEGORY d ON c.MainCatId=d.Id
LEFT JOIN tbl_BRAND e ON c.BrandId=e.Id
LEFT JOIN tbl_CUSTOMER f ON a.CustId=f.Id
LEFT JOIN tbl_COMPANY_INFORMATION g On g.Id=a.Pno
LEFT JOIN tbl_SALES_LEDGER h On h.TrNo=a.InvoiceNo WHERE h.SalesAmount=0 AND h.Pno=a.Pno 






