/****** Object:  View [dbo].[VW_GET_VOUCHER_LIST]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE VIEW [dbo].[VW_GET_VOUCHER_LIST] AS

select a.Code, b.Description,ISNULL(SUBSTRING((SELECT DISTINCT ',' + d.Description+SPACE(2)+'('+c.Naration+')' FROM tbl_TRANSACT c, tbl_CHART_OF_ACCOUNTS d where c.TrNo = a.TrNo and c.Code = d.Code FOR XML PATH('')), 2 , 1000),'') As Narration, 
sum(a.Debit) as Debit, SUM(a.Credit) Credit, a.TrNo, a.Trans_dt, a.Pno, a.VrRefNo, a.UserName, Max(a.EntryDate) as EntryDate, c.Name as Unit, a.VoucherType
from tbl_TRANSACT a, tbl_CHART_OF_ACCOUNTS b, tbl_COMPANY_INFORMATION c 
where a.Code = b.Code and a.CostCenter = c.Id and a.Code = '2101020001' and a.Valid = 1
AND a.BranchId = b.BranchId AND b.BranchId = c.BranchId 
group by a.Code, b.Description, a.TrNo, a.Pno, a.Trans_dt, a.VrRefNo, a.UserName, c.Name, a.VoucherType
UNION ALL
select a.Code, b.Description, a.Naration, a.Debit, a.Credit, a.TrNo, a.Trans_dt, a.Pno, a.VrRefNo, a.UserName, Max(a.EntryDate) as EntryDate, c.Name,
a.VoucherType
from tbl_TRANSACT a, tbl_CHART_OF_ACCOUNTS b , tbl_COMPANY_INFORMATION c 
where a.Code = b.Code and a.CostCenter = c.Id and a.Code <> '2101020001'
AND a.BranchId = b.BranchId AND b.BranchId = c.BranchId 
group by a.Code, b.Description, a.Naration, a.Debit, a.Credit, a.TrNo, a.Trans_dt, a.Pno, a.VrRefNo, a.UserName, c.Name, a.VoucherType


--SELECT a.id,a.Code,a.DEBIT,a.CREDIT,a.Trans_dt,a.TRNO,b.Description,a.Remark,a.VoucherType,a.UserName,a.Naration,a.Pno, a.EntryDate
--FROM tbl_TRANsACT a LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code=b.Code 
--WHERE a.Valid = 1 

