CREATE VIEW [dbo].[VW_INSTALLMENT_LEDGER]
AS
SELECT a.InvoiceNo,a.InvoiceDate,a.CustId,c.Name AS CustName,c.Address,c.MobileNo,a.TotalAmount AS SalesAmt,a.InstallmentSize,a.LessAmount, a.InstallmentAmount,b.DueDate ,a.Pno,Isnull(d.TrDate,b.DueDate) AS CollDate,Isnull(d.CollectionAmount,0) AS CollAmt,b.Id,a.CashAmount,a.CardAmount
FROm tbl_SALES_MAIN AS a LEFT JOIN tbl_INSTALLMENT_INFO b ON a.InvoiceNo=b.InvoiceNo AND a.InvoiceDate=b.InvoiceDate AND a.Pno=b.Pno
LEFT JOIN tbl_CUSTOMER c ON a.CustId=c.Id 
LEFT JOIN tbl_SALES_LEDGER d ON a.CustId=d.CustId AND a.InvoiceNo=d.InvoiceNo AND a.InvoiceDate=d.InvoiceDate AND a.Pno=d.Pno AND d.SalesCollStatus=3 AND MONTH(d.TrDate)=MONTH(b.DueDate)
WHERE a.InstallmentAmount<>0 







