SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE View [dbo].[VW_LABTESTMAPPING] as 
	select '' AS OrderId, right(a.InvNo, 9) AS BillNo, a.InvDate AS BillDate, GETDATE() AS EntryTime, YEAR(a.InvDate) AS AYear, 
	a.PatientName AS PatientName, a.Age AS PatientAge, a.sex as Gender, a.ConsultantName+' '+d.Degree AS DoctorsName, a.MobNo AS TelephoneNo,
	Address AS PatientAddress, (CASE WHEN a.PatientId ='' THEN 'OUTDOOR' ELSE 'INDOOR' END) AS PatientStatus, a.RegNo AS PatientId,
	b.PCode AS ItemId, b.ShortDesc AS ItemDes, 0 as IsTransfer, a.ConsultantCode AS DrCode, a.BranchId, b.LabNo,
	(SELECT SUM(Sales-Less-Collection-ReturnDue) FROM SalesLedger WHERE BranchId = a.BranchId AND PrevInvNo = a.InvNo AND Valid = 1) AS DueAmt,
	Isnull((SELECT DISTINCT BedNo From PatientAdmission WHERE PatientId=a.PatientId and BranchId = a.BranchId),'') AS BedNo
	From InvMaster a
	LEFT JOIN InvDetails b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo And b.Valid=1
	left join ClinicalChart c on c.BranchId=a.BranchId and c.PCode=b.PCode
	left join DrInfo d on d.DrCode = a.ConsultantCode
	where a.DeptName='DIAGNOSTIC' And a.valid=1 AND c.PCode IS NOT NULL
	--and a.InvNo = 'DIA240301105'


GO
