CREATE VIEW [dbo].[VW_IRREGULER_CUSTOMER] AS
SELECT  *
FROM    (
        SELECT   a.ID,a.InvoiceNo,a.InvoiceDate,a.CustId,b.Name as CustomerName,b.MobileNo,b.Address, a.TotalAmount,a.TotalProduct,a.UserName,a.Pno, ROW_NUMBER() OVER (PARTITION BY CustId ORDER BY InvoiceDate DESC) rn
        FROM tbl_SALES_MAIN a LEFT JOIN tbl_CUSTOMER b ON a.CustId=b.Id 
        ) x
WHERE   x.rn = 1 and InvoiceDate<GetDate() - 90





