CREATE VIEW [dbo].[VW_ProcedureEntryForDr]
AS
select c.SubSubPno, a.RefNo, a.RefDate, a.PatientId, b.AdmissionDate, b.AdmissionTime, a.PatientName, b.PatientSex, b.PatientAge, b.PatientAddress, a.BedNo, a.Remarks, 
a.RegNo, a.Code, d.Description AS Particulars, a.DrCode, a.DrName, a.Charge, a.Unit, a.NoU, (a.Charge * a.NoU) as TotalAmount, a.BranchId
from PatientLedger a
LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
LEFT JOIN BedInformation c ON a.BranchId = b.BranchId AND b.BedNo = c.BedNo
LEFT JOIN ClinicalChart d ON a.BranchId = d.BranchId AND a.Code = d.PCode
where b.IsRelease = 0 AND a.Status = 'Procedure Entry For Dr' and a.valid = 1 

