GO

CREATE VIEW [dbo].[VW_ITEM_LIST_BY_PNO] AS
SELECT h.Name AS ColorName,b.WarrantyMonth,b.SalesPrice,a.PurchasePrice,b.ItemCode,
b.Id,b.Model,a.Pno,b.Name,c.Name as BranchName,d.Name AS BrandName,e.Name AS MainCatName,f.Name AS SubCatName,g.Name AS SubSubCatName,ISNULL(SUM(InQty-OutQty+RtnQty-PRtnQty),0) AS BalQty
FROM tbl_STOCK_LEDGER AS a
LEFT JOIN tbl_ITEM AS b ON a.ItemId=b.Id
LEFT JOIN tbl_COMPANY_INFORMATION AS c ON a.Pno=c.Id
LEFT JOIN tbl_BRAND AS d ON b.BrandId=d.Id
LEFT JOIN tbl_ITEM_MAIN_CATEGORY AS e ON e.Id=b.MainCatId
LEFT JOIN tbl_ITEM_SUB_CATEGORY AS f ON f.Id=b.SubCatId
LEFT JOIN tbl_ITEM_SUB_SUB_CATEGORY AS g On g.Id=b.SubSubCatId
LEFT JOIN tbl_COLOR AS h ON h.Id=b.ColorId
GROUP BY b.Id,a.Pno,b.Name,c.Name,d.Name,e.Name,f.Name,g.Name,b.Model,b.WarrantyMonth,b.SalesPrice,a.PurchasePrice,h.Name,b.ItemCode




