/****** Object:  View [dbo].[VW_ITEM_OPENING_RECEIVE_LIST]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[VW_ITEM_OPENING_RECEIVE_LIST]
AS
SELECT g.Name AS BranchName, a.Pno,a.InvoiceNo,a.InvoiceDate,a.SuppId,e.Address as SuppAddress,
e.MobileNo as SuppMobileNo,e.Name as SuppName,a.ItemId,b.Model,b.Name AS ItemName,b.BrandId,d.Name as BrandName,b.MainCatId,
c.Name as CategoryName,SUM(a.InQty) as InQty,a.PurchasePrice,g.Name AS GodownName, h.ShipmentNo,
(SELECT STUFF( -- Remove first comma
(
	SELECT  ', ' + BarcodeId FROM -- create comma separated values
	(
	  SELECT BarcodeId FROM tbl_STOCK_LEDGER where ItemId=a.ItemId and StockStatus=5
	) AS T FOR XML PATH('')
)
,1,1,'') AS BarcodeId) AS BarcodeId
FROM tbl_STOCK_ITEM_OPENING h
Left Join tbl_STOCK_LEDGER a on a.InvoiceNo=h.InvoiceNo and a.InvoiceDate=h.InvoiceDate
LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id
LEFT JOIN tbl_ITEM_MAIN_CATEGORY c ON b.MainCatId=c.Id
LEFT JOIN tbl_BRAND d ON b.BrandId=d.Id
LEFT JOIN tbl_SUPPLIER_INFO_MASTER e ON a.SuppId=e.Id
LEFT JOIN tbl_COMPANY_INFORMATION g ON g.Id=a.Pno
where a.StockStatus=5
group by g.Name, a.Pno,a.InvoiceNo,a.InvoiceDate,a.SuppId,e.Address,
e.MobileNo,e.Name,a.ItemId,b.Model,b.Name,b.BrandId,d.Name,b.MainCatId,
c.Name,a.PurchasePrice,g.Name, h.ShipmentNo





