GO
CREATE VIEW [dbo].[VW_NEW_ITEM_WISE_RECEIVE_LIST]
AS

SELECT f.Id AS MasterId, f.Remarks,g.Name AS BranchName, a.Pno,a.InvoiceNo,a.InvoiceDate,a.SuppId,e.Address as SuppAddress,
e.MobileNo as SuppMobileNo,e.Name as SuppName,a.ItemId,b.Model,b.Name AS ItemName,b.BrandId,d.Name as BrandName,b.MainCatId,
c.Name as CategoryName,SUM(a.Quantity) as Quantity,a.PurchasePrice,f.ReceiptNo,f.ReceiptDate,f.UserName,f.PaymentAmount,f.EntryDate,
Isnull(h.Name,g.Name) AS GodownName, j.Name as UnitName, b.UnitPerCtn,
(SELECT STUFF( -- Remove first comma
(
	SELECT  ', ' + BarcodeId FROM -- create comma separated values
	(
	  SELECT BarcodeId FROM tbl_STOCK_IN_DETAIL where ItemId=a.ItemId
	) AS T FOR XML PATH('')
)
,1,1,'') AS BarcodeId) AS BarcodeId
FROM tbl_STOCK_IN_DETAIL a 
LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id
LEFT JOIN tbl_ITEM_MAIN_CATEGORY c ON b.MainCatId=c.Id
LEFT JOIN tbl_BRAND d ON b.BrandId=d.Id
LEFT JOIN tbl_SUPPLIER_INFO_MASTER e ON a.SuppId=e.Id
LEFT JOIN tbl_STOCK_IN_MAIN f ON a.InvoiceNo=f.InvoiceNo 
LEFT JOIN tbl_COMPANY_INFORMATION g ON g.Id=a.Pno 
LEFT JOIN tbl_COMPANY_INFORMATION h ON h.Id=f.GodownId 
LEFT JOIN tbl_PURCHASE_LEDGER i ON a.InvoiceNo=i.InvoiceNo AND a.InvoiceDate=i.InvoiceDate
LEFT JOIN tbl_ITEM_UNIT j ON b.UnitId=j.Id
where a.Pno=f.Pno 
group by f.Id, f.Remarks,g.Name, a.Pno,a.InvoiceNo,a.InvoiceDate,a.SuppId,e.Address,
e.MobileNo,e.Name,a.ItemId,b.Model,b.Name,b.BrandId,d.Name,b.MainCatId,
c.Name,a.PurchasePrice,f.ReceiptNo,f.ReceiptDate,f.UserName,f.PaymentAmount,f.EntryDate,h.Name,g.Name, j.Name, b.UnitPerCtn






GO
