CREATE VIEW [dbo].[VW_PATIENT_APPOINMENT]
AS
	select a.Id, a.DrCode, a.DrName+b.Degree AS DrName, b.DrNameInEnglish, b.DrNameInBangla, b.DesignationInEnglish, b.DesignationInBangla, b.DrVisitNew, b.DrVisitOld,
	b.DeptName, b.Speciality, b.RoomNo, a.SlNo, a.AppDate, a.VisitDate, a.PatientName, a.MobileNo, b.DrStatus, b.DrAvailibility, b.DrType, b.RefType,
	a.Dob, a.AgeYear+'Y '+a.AgeMonth+'M '+a.AgeDay+'D' as Age, a.Sex as Gender, a.PtType, c.DrCode AS RefDrCode, b.NoOfPtPerday, d.IntroduceBy, d.BloodGroup,
	c.DrName+ ' ' + c.Degree AS RefDrName, c.MRId, c.MRName, a.ArrivalTime, a.UserName, a.EntryDate, d.RegNo, a.Address  PatientAddress, d.Nationality, 
	d.CorporateId, d.CorporateName, a.Remarks, a.ArrivalBy, a.LogDtls, d.PatientType
	from PatientAppointment a
	LEFT JOIN DrInfo b ON a.BranchId=b.BranchId AND a.DrCode=b.DrCode
	LEFT JOIN DrInfo c ON a.BranchId=c.BranchId AND a.RefDrCode=c.DrCode
	LEFT JOIN PatientRegistration d ON a.BranchId=d.BranchId AND a.RegNo=d.RegNo
	where IsArrival = 1 AND a.Valid=1 --AND a.Id=150
