CREATE VIEW [dbo].[VW_PATIENT_DISCHARGE]
AS


SELECT cc.ReceiptNo, cc.RefDate, bb.UnderDrCode, bb.UnderDrName, bb.AdmissionDate, bb.AdmissionTime, cc.ReleaseDate, cc.EntryDateTime as ReleaseDateTime, 
bb.PatientName , bb.BedNo, bb.PatientAddress, bb.PatientAge, bb.RegNo, bb.PatientSex, bb.PatientTel, aa.*, cc.AdvanceAmt as AdvColl, cc.UserDtls, cc.Remarks
FROM (
select a.BranchId, a.CostCenterName AS UnitId, a.PatientId, a.Particulars Status, b.SubSubPno, a.Charge, SUM(a.NoU) NoU, 
SUM(a.ServiceCharge) ServiceCharge, Sum(a.Charge*a.NoU+a.ServiceCharge) as TotalAmount, SUM(a.Less) Less,
SUM(a.Charge*a.NoU+a.ServiceCharge-a.Less) as NetTotalAmount
from PatientLedger a, BedInformation b, PatientRegistration c
where a.BranchId = b.BranchId AND a.BranchId = c.BranchId ANd b.BranchId = c.BranchId AND a.BedNo = b.BedNo and a.RegNo = c.RegNo and a.TotalAmount > 0 and a.Status NOT IN ('Advance Collection', 'Patient Release') and a.Valid = 1
group by a.BranchId, a.PatientId, a.Particulars, b.SubSubPno, a.Charge, a.CostCenterName
UNION ALL
select a.BranchId, a.CostCenterName AS UnitId, a.PatientId, a.Department as Status, b.SubSubPno, SUM(a.Sales-a.ReturnAmount) as Amount, 1 as NoU,
0 as ServiceCharge, SUM(a.Sales-a.ReturnAmount) as TotalAmount, SUM(a.Less) as Less, SUM(a.Sales-a.Less-a.ReturnAmount) as NetTotalAmount
from SalesLedger a, BedInformation b 
where a.BranchId = b.BranchId AND a.BedNo = b.BedNo and a.PtStatus = 'Indoor' and a.Valid <> 0
group by a.BranchId, a.PatientId, a.Department, b.SubSubPno, a.CostCenterName 
UNION ALL
select a.BranchId, a.CostCenterName AS UnitId, a.PatientId, 'Medicine' as Status, b.SubSubPno, sum(Sales) as Amount, 1 as NoU,
0 as ServiceCharge, SUM(a.Sales) as TotalAmount, sum(a.LessAmt) as Less, SUM(a.Sales-a.LessAmt) as NetTotalAmount 
from PharSalesLedger a, BedInformation b where a.BranchId = b.BranchId AND a.BedNo = b.BedNo and a.PtStatus = 'Indoor' and a.Valid = 1
group by a.BranchId, a.PatientId, b.SubSubPno, a.CostCenterName 
) aa , PatientAdmission bb, PatientReleaseMaster cc, PatientLedger dd
where aa.BranchId = bb.BranchId AND aa.BranchId = cc.BranchId AND aa.BranchId = dd.BranchId AND bb.BranchId = cc.BranchId AND bb.BranchId = dd.BranchId AND cc.BranchId = dd.BranchId AND aa.UnitId = bb.CostCenterName AND aa.UnitId = cc.CostCenterName AND aa.UnitId = dd.CostCenterName AND bb.CostCenterName = cc.CostCenterName AND bb.CostCenterName = dd.CostCenterName AND cc.CostCenterName = dd.CostCenterName
AND aa.PatientId = bb.PatientId and aa.PatientId = cc.PatientID and bb.PatientId = dd.PatientId 
and dd.Valid = 1 and cc.Valid = 1 and bb.Valid = 1
group by cc.ReceiptNo, cc.RefDate, bb.UnderDrCode, bb.UnderDrName, bb.AdmissionDate, bb.AdmissionTime, cc.ReleaseDate, cc.EntryDateTime, 
bb.PatientName , bb.BedNo, bb.PatientAddress, bb.PatientAge, bb.RegNo, bb.PatientSex, bb.PatientTel, aa.PatientId, aa.Status, aa.SubSubPno,
aa.Charge, aa.NoU, aa.ServiceCharge, aa.TotalAmount, aa.Less, aa.NetTotalAmount, cc.UserDtls, cc.Remarks, cc.AdvanceAmt, bb.BranchId, aa.BranchId, aa.UnitId

GO
