CREATE VIEW [dbo].[VW_RETURN_ITEM_LIST] AS

SELECT a.InvoiceNo,a.ItemId,d.ItemCode,a.SalesPrice,a.Pno,d.Name,d.Model,b.InvoiceDate,SUM(a.OutQty-a.RtnQty) AS BalQty, aa.ItemDiscount
FROM (select invoiceNo, ItemId, sum(ItemDiscount) as ItemDiscount from tbl_SALES_DETAIL group by invoiceNo, ItemId) aa,tbl_STOCK_LEDGER a 
left join tbl_SALES_MAIN b on a.InvoiceNo=b.InvoiceNo AND a.Pno=b.Pno
left join tbl_ITEM d on a.ItemId=d.Id
