d.Name AS CustomerName,d.MobileNo,c.TotalAmount,c.TotalProduct,c.UserName,SUM(e.ItemDiscount) as ItemDiscount,c.LessAmount,c.InstallmentAmount,
c.InstallmentSize,c.CashAmount,c.CardAmount,c.CardNumber,c.CardNameId,ISNULL(e.ItemVat,0) AS ItemVat, c.GCardSerialNo, c.IsCondition,
