/****** Object:  View [dbo].[VW_TIME_TO_TIME_DUE_PAYMENT]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VW_TIME_TO_TIME_DUE_PAYMENT]
AS

select a.ReceiptNo, a.RegNo, a.RefNo, a.PaymentDate, a.PatientId, a.PatientName, a.AdmissionDate, a.AdmissionTime, a.PatientAddress, a.ReceiveAmt, 
(select ISNULL(sum(ReceiveAmt),0) from TimeToTimeDuePayment where BranchId = a.BranchId AND PatientId = a.Patientid and EntryDateTime < a.EntryDateTime  and Valid = 1) as PrevAdv, 
a.Remarks, a.BedNo, a.FloorNo, a.DeptName, a.CashAmt, a.CardAmt, a.CardNo, a.CardBank, 
a.ChequeAmt, a.ChequeNo, a.ChequeBank, a.ChequeDate, a.UserDetails, a.BranchId, a.CostCenterName AS UnitId, 
c.DrCode, c.DrName+''+d.Degree AS DrName, c.UnderDrCode, c.UnderDrName+''+e.Degree As UnderDrName, a.UserName
from TimeToTimeDuePayment a, PatientAdmission c, DrInfo d, DrInfo e
where a.PatientId = c.PatientId ANd a.BranchId =e.BranchId ANd c.DrCode = d.DrCode ANd a.BranchId = d.BranchId ANd c.UnderDrCode = e.DrCode
AND a.BranchId = c.BranchId and c.IsRelease = 0 and a.Valid = 1
GO
