GO
SET QUOTED_IDENTIFIER ON
GO

CREATE view [dbo].[VW_PharReminderStockReport] 
AS --- Select * From VW_PharReminderStockReport
--SELECT a.Id, b.CompanyId, b.CompanyName, a.ProductId, a.ProductName, c.Name as ProductGroup, a.ReminderStock, b.ReOrder,  MAX(a.ExpiryDate) AS ExpiryDate,
--a.TP, a.SalePrice, a.UnitId, a.StoreId, a.BranchId, a.CurrentStock AS CurrentStock
--FROM VW_PharCurrentStock a 
--left join PharProductInfo b On a.Id=b.Id
--left join PharPdGroup c On a.ProductGroup=c.Id 
--WHERE CurrentStock != 0 AND a.ReminderStock >= a.CurrentStock
--GROUP BY a.Id, a.CompanyId, a.ProductId, a.ProductName, c.Name, a.ReminderStock, b.ReOrder,
--a.TP, a.SalePrice, a.CompanyName, UnitId, StoreId, BranchId, a.CurrentStock

SELECT a.Id, b.CompanyId, b.CompanyName, a.ProductId, a.ProductName, c.Name as ProductGroup, a.ReminderStock, b.ReOrder,  MAX(a.ExpiryDate) AS ExpiryDate,
a.TP, a.SalePrice, a.UnitId, a.StoreId, a.BranchId, sum(a.CurrentStock) AS CurrentStock
FROM VW_PharCurrentStock a 
left join PharProductInfo b On a.Id=b.Id
left join PharPdGroup c On a.ProductGroup=c.Id 
WHERE CurrentStock != 0 
GROUP BY a.Id, b.CompanyId, a.ProductId, a.ProductName, c.Name, a.ReminderStock, b.ReOrder,
a.TP, a.SalePrice, b.CompanyName, UnitId, StoreId, BranchId
HAVING a.ReminderStock >= sum(a.CurrentStock)
GO
