/****** Object:  View [dbo].[PHAR_ITEM_LIST_FOR_RETURN]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE VIEW [dbo].[PHAR_ITEM_LIST_FOR_RETURN] AS

With z as
(
	Select BranchId, InvNo as SaleNo, SUm(Sales) As Sales, SUm(Collection+DueColl-CashReturn) As Collection, Sum(DueLess+LessAmt-LessAdjust) As Less
	From PharSalesLedger Where Valid=1 And PtStatus != 'Indoor'
	Group By BranchId, InvNo
),
StockBalance AS
(
    SELECT BranchId, InvNo aS SaleNo, ProductId, ExpireDate, SUM(OutQty - RtnQty) AS BalQty
	FROM PharStockLedger
    GROUP BY BranchId, InvNo, ProductId, ExpireDate
)
Select a.SaleNo, a.SaleDate, a.PtStatus, a.RegNo, a.DeptName, a.PatientId, a.PatientName, a.BedNo, c.Sales As TotalAmt, c.Less As LessAmt, c.Collection As AdvanceAmt, b.ExpireDate, b.CompanyId, b.ProductName, b.TP, b.SalePrice, b.ItemLess/b.ProductQty As ItemLess, b.ProductId, a.BranchId, b.UnitId, b.StoreId, d.BalQty, a.Valid
From PharSalesMaster a
Inner Join PharSalesDetails b On a.SaleNo=b.SaleNo And a.BranchId=b.BranchId And b.Valid=1
Left Join z c On a.BranchId=c.BranchId and a.SaleNo=c.SaleNo
Left Join StockBalance d On a.BranchId=d.BranchId And a.SaleNo=d.SaleNo And b.ProductId=d.ProductId and b.ExpireDate=d.ExpireDate
Where a.SaleDate>DATEADD(MONTH, -2, GETDATE())


--	SELECT DISTINCT a.SaleNo, a.SaleDate, b.PtStatus, a.RegNo, a.DeptName, b.PatientId,b.PatientName, b.BedNo, b.TotalAmt, b.LessAmt, b.AdvanceAmt, 
--	a.ExpireDate, a.CompanyId, a.TP, a.ProductName, a.SalePrice, a.ItemLess, a.ProductId, a.BranchId, a.UnitId, a.StoreId, 
--	(Select SUM(OutQty-RtnQty) from PharStockLedger where InvNo=a.SaleNo and ProductId=a.ProductId AND ExpireDate = a.ExpireDate) as BalQty, a.Valid
--	FROM PharSalesDetails a 
--	left join PharSalesMaster b on a.SaleNo=b.SaleNo AND a.BranchId = b.BranchId ANd a.UnitId = b.UnitId And a.Valid=b.Valid
--	WHERE a.Valid=1 AND b.PtStatus='Outdoor'

GO
