SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VW_FixedAssetCurrentStock]
AS  --- SELECT * FROM VW_FixedAssetCurrentStock
	select a.ProductCode, a.ProductName, c.Unit, a.BatchNo, ISNULL(a.ExpDate, '') AS ExpDate, a.storeName AS StoreName, a.UnitId, a.PPrice, a.BranchId,
	SUM(a.InQty+a.RtnQty+a.BonusQty-a.OutQty-a.PRtnQty) as CurrQty
	from FixedAssetStockLedger a
	LEFT JOIN tbl_COMPANY_INFORMATION b ON a.UnitId = b.Id AND a.BranchId = b.BranchId
	LEFT JOIN FixedAssetRegister c ON a.ProductCode = c.AssetCode and a.BranchId = c.BranchId
	WHERE a.Valid = 1
	GROUP BY a.ProductCode, a.ProductName, c.Unit, a.BatchNo, a.storeName, a.UnitId, a.PPrice, a.BranchId, 
	ISNULL(a.ExpDate, '1900-01-01')
	HAVING SUM(a.InQty+a.RtnQty+a.BonusQty-a.OutQty-a.PRtnQty) <> 0
GO
