--11012024
CREATE VIEW [dbo].[VW_PATIENT_ADMISSION]
AS
SELECT a.PatientId, a.RegNo, a.AdmissionDate, a.AdmissionTime, a.PatientName, a.PatientAge, a.PatientSex, a.BedNo, g.EntryDateTime AS ReleaseDate,
a.EntryDateTime as AdmissionDateTime, a.Religion, a.PatientTel, a.SpouseName, a.PatientAddress, a.MediDrCode, a.MediDrName, a.OperationCode, a.OperationName,
a.Guardian1, a.Guardian2, a.Relation1, a.Relation2, a.Phone1, a.Phone2, a.DrName AS DrName, a.DrCode, a.AdmittedDept, a.AmbulanceCode, a.AmbulanceName, 
a.DriverName, a.MeterFrom, a.MeterTo, a.CorporateName, a.BrokerCode, a.BrokerCode AS SourceCode, h.DrName AS SourceName,
ISNULL(a.UnderDrCode,'') AS UnderDrCode, ISNULL(a.UnderDrName, '') AS UnderDrName, a.UserName, b.Name as Unit, c.FatherName, d.FloorNo, a.Remarks, 
c.Occupation, a.BranchId, c.BloodGroup, a.PackCode, a.PackName, a.ContractAmount
FROM PatientAdmission a
LEFT JOIN tbl_COMPANY_INFORMATION b ON a.CostCenterName = b.Id
LEFT JOIN PatientRegistration c On a.BranchId = c.BranchId AND a.RegNo = c.RegNo AND c.Valid = 1
LEFT JOIN BedInformation d ON a.BranchId = d.BranchId ANd a.FirstBedNo = d.BedNo
LEFT JOIN DrInfo e ON a.BranchId = e.BranchId AND a.DrCode =e.DrCode
LEFT JOIN DrInfo f ON a.BranchId = f.BranchId AND a.UnderDrCode =f.DrCode
LEFT JOIN PatientReleaseMaster g ON a.BranchId = g.BranchId AND a.PatientId = g.PatientID AND g.Valid = 1
LEFT JOIN DrInfo h ON a.BranchId = h.BranchId AND a.BrokerCode =h.DrCode
WHERE a.Valid = 1
GO
