CREATE VIEW [dbo].[VW_AMBULANCE_DUE_COLLECTION]
AS
select a.RefNo, a.RefDate, a.PatientId, a.PatientName, a.Less, a.ReceiveAmt, a.CashAmt, 
a.CardAmt, a.ChequeAmt, a.CardNo, a.CardBank, a.ChequeNo, a.ChequeBank, a.ChequeDate,
a.PrevReceiptNo, a.PrevReceiptDate, 
(select sum(TotalCharge-ReceiveAmt-Less)
from AmbulanceLedger 
where PrevReceiptNo=a.PrevReceiptNo and EntryDateTime < a.EntryDateTime) as PrevDue,
a.UserName, a.EntryDateTime, a.Remarks
from AmbulanceLedger a
where a.InputFrom IN ('Collection','Patient Release', 'Indoor Due Collection')

