--27022025
CREATE VIEW [dbo].[VW_AMBULANCE]
AS
	select a.ReceiptNo, a.ReceiptDate, a.RegNo, a.PatientId, a.PatientName, a.Address, a.Gender, a.Age, a.DriverName, a.AmbulanceNo, a.DestinationFrom,
	a.DestinationTo, a.MeterFrom, a.MeterTo, a.FromDate, a.FromTime, a.ToDate, a.ToTime, a.TotalDistance, a.TotalCharge, a.Less, a.NetPayable, a.CashAmt, 
	a.CardAmt, a.ChequeAmt, a.TotalAdvanceAmt, /* a.DueAmt, */ a.CardNo, a.CardBank, a.ChequeNo, a.ChequeDate, a.Remarks, a.UserName, a.EntryDateTime, 
	a.RefDrCode, a.RefDrName, a.ConsultantCode, a.ConsultantName,
	(SELECT SUM(TotalCharge-Less-ReceiveAmt) FROM AmbulanceLedger where BranchId = a.BranchId AND PrevReceiptNo=a.ReceiptNo) AS DueAmt,
	--(Select TOP 1 UserName +'-'+Cast(ReceiveAmt AS VARCHAR) from AmbulanceLedger where BranchId = a.BranchId AND InputFrom = 'Collection' AND PrevReceiptNo = a.ReceiptNo ORDER BY RefNo DESC) as DueCollectBy, 

	ISNULL(SUBSTRING((SELECT UserName+':'+Cast(ReceiveAmt AS VARCHAR)+CHAR(10) FROM AmbulanceLedger where BranchId = a.BranchId AND InputFrom = 'Collection' AND PrevReceiptNo = a.ReceiptNo ORDER BY RefNo DESC FOR XML PATH('')), 1 , 1000),'') As DueCollectBy,

	(Select TOP 1 EntryDateTime from AmbulanceLedger where BranchId = a.BranchId AND InputFrom = 'Collection' AND PrevReceiptNo = a.ReceiptNo ORDER BY RefNo DESC) AS DueCollectDateTime
	from AmbulanceMaster a 
	--LEFT JOIN AmbulanceLedger b ON a.RegNo = b.RegNo AND a.PatientId = b.PatientId AND a.Valid = b.Valid AND a.BranchId = b.BranchId
	where a.Valid = 1
