CREATE VIEW [dbo].[VW_IndoorIndentMedicineList]
AS
	SELECT distinct a.RefDate, a.RefNo, b.PatientId, a.UserName, a.BranchId, a.RegNo, b.BedNo, e.Department,  b.PatientAge, b.PatientSex, 
	b.PatientName, c.Id, c.ProductName, (CASE WHEN SUM(c.CurrentStock) < a.Qty THEN 0 ELSE SUM(c.CurrentStock)-a.Qty END) AS AvailableStock, 
	a.Qty AS ReqQty, c.SalePrice, b.AdmissionDate, b.PatientTel, a.Qty*c.SalePrice AS SubTotal, c.CompanyId, 
	c.TP AS PPrice, c.StoreId, c.ReminderStock, MAX(a.EntryDateTime) AS EntryDateTime,
	SUM(c.CurrentStock) AS CurrentStock, c.Generic, b.UnderDrCode, b.UnderDrName
	FROM CommonMedicine a
	LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.RegNo = b.RegNo AND b.Valid = 1 AND b.IsRelease = 0
	LEFT JOIN VW_PharCurrentStock c ON c.BranchId IN (0, a.BranchId) AND a.ProductId = c.Id
	LEFT JOIN BedInformation d ON a.BranchId = d.BranchId AND b.BedNo = d.BedNo
	LEFT JOIN IndoorMedicineReqMaster e On a.RefNo=e.RequistionNo AND a.BranchId=e.BranchId AND a.Valid=e.Valid
	WHERE a.IsDone = 0 AND a.Status = 'Indoor Medicine Requsition' AND a.DoneBy IS NULL AND b.PatientId IS NOT NULL AND c.Id IS NOT NULL
	GROUP BY a.RefDate, a.RefNo, b.PatientId, a.UserName, a.BranchId, a.RegNo, b.BedNo, e.Department, b.PatientAge, b.PatientSex, b.PatientName, 
	c.Id, c.ProductName, a.Qty, c.SalePrice, a.Qty*c.SalePrice, c.CompanyId, c.TP, c.StoreId, c.ReminderStock, c.Generic, b.AdmissionDate, b.PatientTel, b.UnderDrCode, b.UnderDrName


