/****** Object:  View [dbo].[VW_DIAGNOSIS_INV_LIST]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO




CREATE VIEW [dbo].[VW_DIAGNOSIS_INV_LIST] 
AS
	WITH ci AS 
	(
		select BranchId, RefNo AS IndentNo, UserName, MAX(EntryDateTime) AS EntryTime from CommonInvestigations WHERE IsDone = 1 GROUP BY BranchId, RefNo, UserName
	)

	select a.PtStatus as AdmissionType, a.InvNo, a.InvDate, a.DeptName, a.MobNo, a.PatientId, a.BabyOf+' '+a.PatientName AS PatientName, a.RegNo, a.BedNo, 
	a.Age, a.DOB, a.Sex, a.Address, a.ConsultantCode,a.ConsultantName+''+h.Degree AS ConsultantName, i.NationalId, i.EmpIdNo,  i.Email, a.RefDrCode,
	a.RefDrName+''+g.Degree AS RefDrName, a.IsCorporate, a.CorporateCode, a.CorporateName, a.LessAmount, a.LessPcOrTk, a.DiscountFrom, a.VatAmount, a.CashAmt, 
	a.CardAmt, a.CardNo, a.CardBank, a.ChequeAmt, a.ChequeNo, a.ChequeBank, a.ChequeDate, a.Remarks, a.Username, a.EntryTime, ISNULL(d.DonorName,'') AS DonorName, 
	ISNULL(d.DonorAge,'') AS DonorAge, ISNULL(d.DonorGender,'') AS DonorGender, g.MRId, g.MRName, a.BranchId, j.Name AS BranchName, c.Id AS UnitId, c.Name as UnitName,
	a.BrokerCode, ISNULL(f.DrName,'') AS BrokerName, b.RptDeliveryTime, b.PCode, b.ShortDesc, b.Amount, b.Quantity, b.TotalAmount as TotalAmt, a.HCCode, a.HcDesc,
	RTRIM(LTRIM(b.IsUrgent)) AS IsUrgent, b.RptDeliveryDate, b.FixedLess AS PCodeFixedLess, b.SpecialLess AS PCodeUserLess, b.GLessAmt as Discount, 
	k.UserName AS IndentBy, k.EntryTime AS IndentEntryTime, k.IndentNo, b.Valid, a.CollTime, a.PatientType,
	(CASE WHEN b.TotalAmount != 0 THEN (b.SpecialLess/b.TotalAmount)*100 ELSE 0 END) AS PCodeSpecialLessPercent, 
	(CASE WHEN b.TotalAmount != 0 THEN (b.FixedLess/b.TotalAmount*100) ELSE 0 END) AS PCodeFixedLessPercent, b.TotalAmount-b.GLessAmt AS PCodeNet, 
	(select SUM(Collection+AdjustAmt) as Coll from SalesLedger where Valid <> 0 AND PrevInvNo = a.InvNo AND BranchId = a.BranchId) AdvanceAmt,
	(select SUM(Less) as Coll from SalesLedger where Valid <> 0 AND PrevInvNo = a.InvNo AND BranchId = a.BranchId) TotalLess, a.FixedLess
	from InvMaster a
	left join InvDetails b on a.InvNo=b.InvNo and a.InvDate=b.InvDate AND a.BranchId = b.BranchId and b.Valid != 0
	left join tbl_COMPANY_INFORMATION c on a.CostCenterName = c.Id AND a.BranchId = c.BranchId
	left join DonorInfo d on a.InvNo = d.InvNo AND a.BranchId = d.BranchId
	left join ClinicalChart e on b.PCode = e.PCode AND a.BranchId = e.BranchId
	LEFT JOIN DrInfo f on a.BrokerCode = f.DrCode AND a.BranchId = f.BranchId
	LEFT JOIN DrInfo g on a.RefDrCode = g.DrCode AND a.BranchId = g.BranchId
	LEFT JOIN DrInfo h on a.ConsultantCode = h.DrCode AND a.BranchId = h.BranchId
	LEFT JOIN PatientRegistration i ON a.BranchId = i.BranchId AND a.RegNo = i.RegNo
	LEFT JOIN tbl_BranchInfo j ON j.Id = b.BranchId
	left join ci k on k.BranchId = a.BranchId and k.IndentNo = a.IndentNo
	where a.Valid = 1 --and a.InvNo = 'DIA240200257'



GO
