/****** Object:  View [dbo].[VW_StudentDailyCollection]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE View [dbo].[VW_StudentDailyCollection]
AS

select 'Collection' AS InstituteName, RefNo AS MrNo, RefNo AS PaidTrNo, RefDate AS PaidTrDate, Name, '' AS RollNo,
'' AS BatchNo, '' AS AccountNo, '' AS BankName, '' AS BankBrName, '' AS CollectionType, RefDate AS  PaidDate,
0 AS [Tution Fee], 0 AS [Tution Late Fee], 0 AS [Session Charge], 0 AS [Hostel Seat Rent],
0 AS [Hostel Placement Fee], 0 AS [Library Late Fee], 0 AS [Exam Fee], 0 AS [Registration Fee], 0 AS [Employee Recruitment],
0 AS [Re-admission Fee], 0 AS [BM&DC Registration Fee], ReceiveAmt AS Miscellaneous, 0 AS [Admission Fee], 0 AS [For Internship Allowance],
0 AS [After 1 Year Payment], 0 AS [Session Fee]
from tbl_AccountsFeesCollection_Master a
UNION ALL
Select InstituteName, MrNo, PaidTrNo, PaidTrDate, Name, RollNo,
BatchNo, AccountNo, BankName, BankBrName, CollectionType, PaidDate,
[Tution Fee], [Tution Late Fee], [Session Charge], [Hostel Seat Rent],
[Hostel Placement Fee], [Library Late Fee], [Exam Fee],
[Registration Fee], [Employee Recruitment], [Re-admission Fee], [BM&DC Registration Fee], Miscellaneous, [Admission Fee], [For Internship Allowance], [After 1 Year Payment], [Session Fee]
 From (
Select b.NameOfInstitute AS InstituteName, a.MrNo, a.PaidTrNo, a.PaidTrDate, b.Name, a.RollNo, a.BatchNo, a.Particulars,
sum(isnull(a.ReceiveAmt, 0)) as CollectAmt, b.AccountNo, b.BankName, b.BankBrName, b.CollectionType, a.PaidDate
From tbl_StudentFeesCollectionDtls a, tbl_StudentFeesCollection b
Where a.Valid=1 AND b.Valid=1 AND a.MrNo=b.MrNo AND a.PaidTrNo=b.PaidTrNo AND a.PaidTrDate=b.PaidTrDate AND a.RollNo=b.RollNo
AND a.BatchNo=b.BatchNo AND a.Session=b.Session
Group By b.NameOfInstitute, a.MrNo, a.PaidTrNo, a.PaidTrDate, b.Name, a.RollNo, a.BatchNo, a.Particulars, b.AccountNo,
b.BankName, b.BankBrName, b.CollectionType, a.PaidDate) t 
PIVOT ( Sum(CollectAmt) for Particulars IN([Tution Fee], [Tution Late Fee],[Session Charge],[Hostel Seat Rent],[Hostel Placement Fee],[Library Late Fee],[Exam Fee],[Registration Fee],[Employee Recruitment],[Re-admission Fee],[BM&DC Registration Fee],[Miscellaneous],[Admission Fee], [For Internship Allowance], [After 1 Year Payment],[Session Fee])
) 
as Pivot_Table; 


GO
