Create view [dbo].[VW_PharStockTransferListByCentralStore]
AS
	select a.TrNo as TransferNo, a.TrDate as TransferDate, a.UserName AS TransferBy, a.ProductReqNo as ReqNo, 
	a.ProductReqDate as ReqDate, b.UserName AS ReqBy, a.ProductId, a.ProductName, (b.ReqQty) as ReqQty, 
	SUM(a.StockOutQty) AS TransferQty, a.BranchId, a.ToStoreId, a.FromStoreId
	from PharStockTransfer a
	Left Join PharProductReqCentralStoreDetails b on a.BranchId=b.BranchId and a.ProductReqNo=b.TrNo And a.ProductId=b.ProductCode
	--Where a.TrNo='250700004'
	Group by a.TrNo, a.TrDate, a.UserName, a.ProductReqNo, a.ProductReqDate, b.UserName, a.ProductId, a.ProductName, 
	b.ReqQty, a.BranchId, a.ToStoreId, a.FromStoreId

