CREATE View [dbo].[VW_DiagDueForPatientRelDeptWise]
AS
	Select ISNULL(SUM(a.Sales-a.Less-a.Collection-a.ReturnDue-a.AdjustAmt), 0) as Due, a.BranchId, a.PatientId, a.Department, a.RegNo
	from SalesLedger a
	Where a.Valid=1 And a.PtStatus='Indoor' --And b.PatientId='PA250800467'
	Group By a.BranchId, a.PatientId, a.Department, a.RegNo
	Having ISNULL(SUM(Sales-Less-Collection-ReturnDue-AdjustAmt), 0) != 0

