CREATE VIEW [dbo].[VW_LabParaMeterDefination]
AS
	SELECT a.TestCode, b.Id SpecimenId, a.Specimen, a.GroupSlNo, a.ParameterSlNo, a.Parameter, a.Alias, a.NormalValue, 
	ISNULL(c.Id,'') as UnitId, a.Unit, a.Result, ISNULL(d.Id,'') as ReportingId, a.ReportingGroup, a.Method
	FROM lab_Parameter_Definition a
	LEFT JOIN lab_SpecimenSetup b ON a.Specimen = b.Name
	LEFT JOIN lab_UnitSetup c ON a.Unit = c.Name
	LEFT JOIN lab_ReportingGroupSetup d ON a.ReportingGroup = d.Name
