create VIEW [dbo].[VW_AllTypeOfIntruducer] 
AS
	select DrCode AS Code, DrName AS FName,DeptName AS Department, 'Doctor' As RefBy , BranchId 
	from drinfo WHERE DrType <> 'Marketing' and Status = 1 AND DrName <> ''
	UNION ALL
	select DrCode , DrName,DeptName , 'Marketing Agent' As RefBy , BranchId 
	from drinfo WHERE DrType = 'Marketing' and Status = 1 AND DrName <> ''
	UNION ALL
	SELECT MrId , MRName, MRAddress ,'MR' , BranchId 
	FROM tbl_MRInfo WHERE Valid = 1 AND MRName <> ''
	UNION ALL
	SELECT Code ,Name , Designation , 'Staff' , BranchId 
	FROM HREmployeeMaster WHERE WorkingStatus = 'Working' AND Name <> ''
	UNION ALL
	select RollNo,Name,BatchNo , 'Student' , BranchId 
	from tbl_StudentAdmission where valid = 1 and Name <> '' AND BatchNo <> ''
