Create VIew [dbo].[VW_AmbulaneDueListForIndoorCollection]
AS
	Select BranchId, PatientId, Sum(a.TotalCharge-a.Less-a.ReceiveAmt-a.AdjustAmt) AS Due
	from AmbulanceLedger a
	Where a.Valid=1 And PtStatus='Indoor'
	group by BranchId, PatientId
	Having Sum(a.TotalCharge-a.Less-a.ReceiveAmt-a.AdjustAmt) > 0
