CREATE VIEW [dbo].[VW_DiscCardRegNoWise]
AS
SELECT DISTINCT a.RegNo, a.BranchId, a.CardTypeId, PCode, c.Amount AS DiscountAmt, c.PcOrTk
FROM PatientRegistration a
LEFT JOIN DiscountCardRegMain b ON a.BranchId = b.BranchId AND a.CardTypeId = b.CardTypeId
LEFT JOIN DiscountCardRegistration c ON a.BranchId = c.BranchId AND b.Id = c.Id
WHERE a.CardTypeId IS NOT NULL
