/****** Object:  View [dbo].[VW_OutdoorAndPharmacySales]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VW_OutdoorAndPharmacySales]
AS
		-- Sales
	SELECT SUM(TotalAmt-TotalLess) AS Sales, 0 AS Collection, 0 AS Due,
	CASE WHEN b.DrType = 'B2B' THEN 'B2B' ELSE 'B2C' END AS SalesType, a.InvDate AS RefDate, a.BranchId
	FROM InvMaster a
	LEFT JOIN DrInfo b ON a.BranchId=b.BranchId AND a.RefDrCode=b.DrCode
	WHERE a.Valid=1
	GROUP BY a.InvDate, a.BranchId, b.DrType
	--SELECT SUM(a.Sales-a.Less-a.ReturnNet) AS Sales, SUM(a.Collection-a.ReturnCash) AS Collection, 0 AS Due,
	--CASE WHEN c.DrType = 'B2B' THEN 'B2B' ELSE 'B2C' END AS SalesType, a.RefDate, a.BranchId 
	--FROM SalesLedger a
	--LEFT JOIN InvMaster b ON a.BranchId=b.BranchId AND a.PrevInvNo=b.InvNo AND b.Valid=1
	--LEFT JOIN DrInfo c ON a.BranchId=c.BranchId AND b.RefDrCode=c.DrCode
	--WHERE a.Valid=1
	--GROUP BY c.DrType, a.RefDate, a.BranchId

	--Collection
	UNION ALL
	SELECT 0 AS Sales, SUM(a.Collection-a.ReturnCash) AS Collection, 0 AS Due,
	CASE WHEN c.DrType = 'B2B' THEN 'B2B' ELSE 'B2C' END AS SalesType, a.RefDate, a.BranchId 
	FROM SalesLedger a
	LEFT JOIN InvMaster b ON a.BranchId=b.BranchId AND a.PrevInvNo=b.InvNo AND b.Valid=1
	LEFT JOIN DrInfo c ON a.BranchId=c.BranchId AND b.RefDrCode=c.DrCode
	WHERE a.Valid=1
	GROUP BY c.DrType, a.RefDate, a.BranchId

	--Sales & Collection
	UNION ALL
	SELECT SUM(Sales-LessAmt-DueLess-ReturnAmt) AS Sales, SUM(a.Collection+a.DueColl-a.CashReturn) AS Collection, 0 AS Due,
	'Pharmacy' AS SalesType, a.TrDate, a.BranchId 
	FROM PharSalesLedger a
	WHERE a.Valid=1
	GROUP BY a.TrDate, a.BranchId
	--ORDER BY 3

	--Due
	UNION ALL
	SELECT 0 AS Sales, 0 AS Collection, SUM(a.Sales-a.Less-a.Collection-a.ReturnDue) AS Due,
	CASE WHEN c.DrType = 'B2B' THEN 'B2B' ELSE 'B2C' END AS SalesType, b.InvDate AS RefDate, a.BranchId 
	FROM SalesLedger a
	LEFT JOIN InvMaster b ON a.BranchId=b.BranchId AND a.PrevInvNo=b.InvNo AND b.Valid=1
	LEFT JOIN DrInfo c ON a.BranchId=c.BranchId AND b.RefDrCode=c.DrCode
	WHERE a.Valid=1 --and a.PreInvDate between '2024-02-01' and '2024-02-29'
	GROUP BY c.DrType, b.InvDate, a.BranchId
	HAVING SUM(a.Sales-a.Less-a.Collection-a.ReturnDue) != 0

	-- Revenue Start
	UNION ALL
	SELECT SUM(Amount*Quantity-GLessAmt) AS Sales, 0 AS Collection, 0 AS Due,
	'Laborator' AS SalesType, InvDate AS RefDate, BranchId 
	FROM InvDetails
	WHERE Valid=1 and SubDeptName IN ('LabTest', 'Microbiology')
	GROUP BY InvDate, BranchId

	UNION ALL
	SELECT SUM(Amount*Quantity-GLessAmt) AS Sales, 0 AS Collection, 0 AS Due,
	'Imaging' AS SalesType, InvDate AS RefDate, BranchId 
	FROM InvDetails
	WHERE Valid=1 and SubDeptName NOT IN ('LabTest', 'Microbiology')
	GROUP BY InvDate, BranchId
	-- Revenue End
GO
