--26102024
CREATE VIEW [dbo].[PHAR_STOCK_IN_DETAILS]
AS --- Select * From PHAR_STOCK_IN_DETAILS
SELECT a.Id, a.InvoiceNo, a.InvoiceDate, c.Id as ProductId, c.ProductName as ProductName, a.ProductQty, a.Bonus as BonusQty,
a.SlipNo, ISNULL(b.SlipDate, a.InvoiceDate) as SlipDate, a.created_at AS EntryDateTime,
a.ExpireDate, a.InvPrice, a.TotalTP, a.VatAmt, a.DiscountAmt,  a.Total,
a.SalesPrice, ISNULL(e.Company_Id,'') AS CompanyId, ISNULL(e.Name, '') AS CompanyName,b.Remarks, b.UserName, b.PaymentAmt,
b.Less, b.PurchaseAmt, a.BranchId, a.CostCenterName, a.StoreId, d.SubSubPno AS StoreName
FROM PharStockInMain b
LEFT JOIN PharStockInDetails a ON b.BranchId = a.BranchId AND a.InvoiceNo = b.InvoiceNo AND a.Valid = 1
LEFT JOIN PharProductInfo c ON a.ProductId = c.Id
LEFT JOIN ProjectInformations d ON a.StoreId = d.PnoCode
LEFT JOIN PharCompanyInfo e On b.CompanyId = e.Company_Id
WHERE b.Valid=1
GO
