/****** Object:  View [dbo].[VW_GastroInvListForRevenueDistribute]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

Create View [dbo].[VW_GastroInvListForRevenueDistribute]
AS
	Select a.InvNo, a.InvDate, a.RegNo, a.PatientId, a.PatientName, a.MobNo, a.Age, a.Sex, a.BedNo, a.PtStatus,
	a.ConsultantCode+' - '+a.ConsultantName As Consultant, a.RefDrCode+' - '+a.RefDrName As Referred, a.BranchId,
	Sum(b.Sales-b.ReturnAmount) As Sales, SUm(b.Less-b.ReturnLess) As Less, Sum(b.Collection-b.ReturnCash) As Collection,
	Sum(b.ReturnAmount) As ReturnAmount, Sum(b.ReturnLess) As LessAdjust, SUm(b.ReturnDue) As DueAdjust, Sum(b.ReturnCash) As CashReturn,
	Sum(b.Sales-b.Less-b.Collection-b.ReturnDue) As Due
	From InvMaster a
	LEft Join SalesLedger b On a.BranchId=b.BranchId And a.InvNo=b.PrevInvNo And b.Valid=1
	Where a.Valid=1
	Group by a.InvNo, a.InvDate, a.RegNo, a.PatientId, a.PatientName, a.MobNo, a.Age, a.Sex, a.BedNo, a.PtStatus,
	a.ConsultantCode+' - '+a.ConsultantName, a.RefDrCode+' - '+a.RefDrName, a.BranchId
GO
