SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE VIEW [dbo].[PHAR_SALES_DETAILS]
AS

with mi as
(
	select m.BranchId, m.RefNo AS IndentNo, MAX(m.EntryDateTime) AS IndentTime, m.UserName AS IndentBy, n.Department as IndentDept
	from CommonMedicine m
	left join IndoorMedicineReqMaster n on m.RefNo = n.RequistionNo and n.Valid=1 --and m.RefDate = n.RequsitionDate
	where m.valid = 1 and m.isdone =1 GROUP BY m.RefNo, m.UserName, m.BranchId, n.Department
)

select a.SaleNo, a.SaleDate, a.ProductName, SUM(a.ProductQty) AS ProductQty, a.SalePrice, a.TP, sum(a.ItemLess) as ItemLess,a.PatientId, a.BedNo, b.GivenAmount, b.ChangeAmount, b.PatientName, b.PtStatus, b.TotalAmt, b.LessAmt, b.MediLess, b.SurgLess, b.InhLess, b.DeptLess, b.AdvanceAmt, b.PaidAmt, b.CashAmt, b.CardAmt, b.ChequeAmt, b.CardNo, b.CardBank, b.ChequeNo, b.ChequeBank, b.ChequeDate, b.Remarks, b.UserName, MAX(a.ExpireDate) AS ExpireDate, a.CompanyId, a.BranchId, b.EntryDateTime, c.IndentNo, c.IndentTime, c.IndentBy, c.IndentDept, b.StoreId, d.SubSubPno
from PharSalesDetails a
left join PharSalesMaster b on b.BranchId = a.BranchId and b.SaleNo = a.SaleNo and b.Valid = 1
left join mi c on c.branchId = b.BranchId and c.IndentNo = b.IndentNo
INNER JOIN ProjectInformations d on d.PnoCode = b.StoreId and d.Valid = 1
where a.Valid=1
GROUP BY a.SaleNo, a.SaleDate, a.ProductName, a.SalePrice, a.TP,a.PatientId, a.BedNo, b.GivenAmount, b.ChangeAmount, b.PatientName, b.PtStatus, b.TotalAmt, b.LessAmt, b.MediLess, b.SurgLess, b.InhLess, b.DeptLess, b.AdvanceAmt, b.PaidAmt, b.CashAmt, b.CardAmt, b.ChequeAmt, b.CardNo, b.CardBank, b.ChequeNo, b.ChequeBank, b.ChequeDate, b.Remarks, b.UserName, a.CompanyId, a.BranchId, b.EntryDateTime, c.IndentNo, c.IndentTime, c.IndentBy, c.IndentDept, b.StoreId, d.SubSubPno

GO
