CREATE VIEW [dbo].[VW_InvDetailsForDischargeCertificate]
AS
	SELECT DISTINCT ROW_NUMBER() OVER(PARTITION BY PatientId ORDER BY PatientId) AS RowNumber, a.BranchId, a.PatientId,a.ReportFileName 
	--, a.ReportGroupName a.InvNo, a.InvDate, 
	FROM (
		SELECT DISTINCT a.BranchId, a.PatientId, b.ReportFileName--, a.InvNo, a.InvDate--, b.ReportGroupName--, b.LabReportFileName 
		FROM InvDetails a
		LEFT JOIN ClinicalChart b ON a.BranchId = a.BranchId AND a.PCode = b.PCode
		WHERE b.DeptName='DIAGNOSTIC' AND b.SubDeptName = 'LabTest' and a.PtStatus = 'Indoor' --and a.PatientId = 'PA240200125'
	) a
