CREATE view [dbo].[VW_PharCurrentStockTransfer] as 
SELECT ISNULL(a.CompanyId,'-') AS CompanyId, a.CompanyName as CompanyName, a.Id,  a.ProductName, a.UnitType,
sum(ISNULL(b.InQty,0) - ISNULL(b.OutQty,0)) AS CurrentStock, b.TP,   ISNULL(b.ExpireDate,'') as ExpiryDate, ISNULL(b.StoreId,0) As StoreId, ISNULL(b.UnitId,0) AS UnitId, ISNULL(b.BranchId, 1) AS BranchId, 0 as VatAmt, 0 as DiscountAmt, 0 as NetPrice, e.Name as ProductCategory
FROM PharProductInfo a
LEFT JOIN PharmaCurrentStock b ON a.Id = b.ProductId
LEFT JOIN PharPdGroup e On a.ProductGroup=e.Id
WHERE a.Valid = 1 
GROUP BY a.CompanyId, a.CompanyName, a.Id, a.ProductName, a.UnitType, b.TP,  b.ExpireDate, b.StoreId, b.UnitId, b.BranchId, e.Name
HAVING sum(ISNULL(b.InQty,0) - ISNULL(b.OutQty,0))  > 0
