CREATE View [dbo].[VW_HRIncrement]
AS
Select * 
From 
(Select b.Code, sum(isnull(b.Amount, 0)) as IncrementAmt, c.SalaryName, b.Valid
From HREmployeeDtls b, HRSalaryType c
Where b.Valid=1 and b.SalaryType = c.SalaryType AND b.SalaryTypeId=c.SlNo and c.Validity=1 and c.ShowInBasic=1
Group By b.Code, c.SalaryName, b.Valid) t 
PIVOT (Sum(IncrementAmt) for SalaryName IN([Allow Basic],[Allow Conveyance],[Allow House Rent],[Allow Medical])) 
as Pivot_Table;    



