/****** Object:  View [dbo].[vw_LoanAndAdvanceLedger]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE view [dbo].[vw_LoanAndAdvanceLedger] as 
SELECT aa.EmpCode , aa.LoanType , SUM(aa.LoanAmount - aa.PaymentAmt-aa.AdjustedAmt) AS Balance  , 
SUM(aa.InstallmentAmt) AS InstallmentAmt, aa.UnitId, aa.BranchId 
FROM (
select EmpCode,LoanAmount , 0 as PaymentAmt , InstallmentAmt ,AdjustedAmt , 'Loan' as LoanType, UnitId, BranchId 
from HRLoanAndAdvance 
where valid = 1
and LoanType = 'Loan'
UNION ALL
select EmpCode,LoanAmount , 0 as PaymentAmt , LoanAmount,AdjustedAmt , 'Advance' as LoanType , UnitId, BranchId
from HRLoanAndAdvance 
where valid = 1
and LoanType = 'Advance'
UNION ALL
select code, 0,0 , 0,Amount , 'Loan', UnitId, BranchId
from Payregister 
where valid = 1 and SalaryTypeId IN (30) 
and Amount <> 0
UNION ALL
select code, 0,0 , 0,Amount , 'Advance', UnitId, BranchId
from Payregister 
where valid = 1 and SalaryTypeId IN (31) 
and Amount <> 0) aa
group by aa.EmpCode , aa.LoanType, aa.UnitId, aa.BranchId







