SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO




CREATE VIEW [dbo].[VW_GET_ITEM_DETAILS]
AS
SELECT a.Id, a.ItemCode, a.Name, a.Model,a.MainCatId,b.Name as MainCatName,a.BrandId,c.Name as BrandName,a.ReOrderQty,a.SubCatId,d.Name AS SubCatName,
a.SubSubCatId, e.Name AS SubSubCatName,a.ColumnId,a.RowId,Isnull(g.Number,'0') as ColumnName, Isnull(h.number,'0') as RowName,
Isnull((Select top 1 PurchasePrice from tbl_STOCK_LEDGER WHERE  ItemId=a.Id AND InQty>0 AND TrDate=(SELECT Max(TrDate) 
from tbl_STOCK_LEDGER WHERE InQty>0 AND ItemId=a.Id) ),0) as LastPurchasePrice,a.WarrantyMonth,a.ColorId,
Isnull(f.Name,'N/A') As ColorName,a.UnitId, Isnull(i.Name,'N/A') As UnitName,UnitPerCtn,a.TradePrice,a.ReceivingVat,a.SalesPrice,
a.SalesVat,a.Discount,a.Valid,a.MasterPack,a.CommercialBox,a.ProdUnitPacket,a.ProdUnitPacketUnit
FROM tbl_ITEM a 
LEFT JOIN tbl_ITEM_MAIN_CATEGORY  b ON a.MainCatId=b.Id
LEFT JOIN tbl_BRAND c ON a.BrandId=c.Id 
LEFT JOIN tbl_ITEM_SUB_CATEGORY d ON a.SubCatId=d.Id 
LEFT JOIN tbl_ITEM_SUB_SUB_CATEGORY e ON a.SubSubCatId=e.Id 
LEFT JOIN tbl_Color f ON a.ColorId=f.Id 
LEFT JOIN tbl_ITEM_COLUMN g ON a.ColumnId=g.Id 
LEFT JOIN tbl_ITEM_ROW h ON a.RowId=h.Id 
LEFT JOIN tbl_ITEM_UNIT i ON a.UnitId=i.Id 






GO
/****** Object:  View [dbo].[VW_MIS_SaleCollDeptWiseTotalSale]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VW_MIS_SaleCollDeptWiseTotalSale] AS

SELECT 1 AS SlNo, 'INDOOR' AS MainDept, c.SubSubPno AS DeptName, a.ReleaseDate AS RefDate, d.PCode AS Code, d.Description AS Name,
COUNT(b.Code) as Qty, SUM(b.NoU*b.Charge+b.ServiceCharge) AS Sales, a.BranchId
FROM PatientAdmission a
LEFT JOIN PatientLedger b ON a.PatientId = b.PatientId AND a.BranchId = b.BranchId
LEFT JOIN BedInformation c ON b.BedNo = c.BedNo AND a.BranchId = c.BranchId
LEFT JOIN ClinicalChart d on b.Code = d.PCode AND a.BranchId = d.BranchId
WHERE a.IsRelease = 1 AND b.valid = 1 AND a.BranchId = 1
GROUP BY c.SubSubPno, a.ReleaseDate, d.PCode, d.Description, a.BranchId
HAVING SUM(b.NoU*b.Charge+b.ServiceCharge) <> 0

UNION ALL

select 2 as slno, 'OUTDOOR' AS MainDept, a.DeptName, InvDate AS RefDate, '' as PCode, b.SubDeptName AS Name,
COUNT(b.SubDeptName) AS Qty, SUM(Amount*Quantity) AS Sales, a.BranchId
from InvDetails a
LEFT JOIN ClinicalChart b ON a.PCode = b.PCode ANd a.BranchId = b.BranchId
where valid <> 0 and PtStatus <> 'Indoor' AND a.DeptName <> 'Ambulance'
AND a.BranchId = 1
GROUP BY a.DeptName, a.InvDate, b.SubDeptName, a.BranchId

--UNION ALL
--SELECT 3 as slno,'OUTDOOR' AS MainDept, 'MEDICINE' AS DeptName, TrDate AS RefDate, '0009' AS Code, 'Medicine' AS Name,
--1 AS Qty, SUM(SALES) AS Sales, BranchId
--FROM PharSalesLedger 
--where valid = 1 and PtStatus <> 'Indoor' AND BranchId = 1
--GROUP BY TrDate, BranchId
UNION ALL 
SELECT 4 as slno, 'OUTDOOR' AS MainDept, 'OPD TICKET' AS DeptName, TrDate, '' as Code, 'OPD Ticket' AS Name,
1 AS Qty, SUM(Amount) AS Sales, a.BranchId
FROM OPDTicketMaster a
where a.valid = 1 AND BranchId = 1
GROUP BY TrDate, a.BranchId
UNION ALL 
SELECT 5 as slno, 'OUTDOOR' AS MainDept, 'Registration' AS DeptName, a.TrDate, '' AS Code, 'Registration' AS Name,
1 As Qty, SUM(a.Amount) AS Sales, a.BranchId
FROM RegistrationFees a
where a.valid = 1 AND BranchId = 1
GROUP BY a.TrDate, a.BranchId
UNION ALL
SELECT 6 as slno, 'AMBULANCE' As MainDept, 'Ambulance' AS DeptName, RefDate, '' AS Code, 'Ambulance' AS Name,
1 AS Qty, SUM(TotalCharge) AS Sales, BranchId
FROM AmbulanceLedger
where BranchId = 1 AND valid = 1
GROUP BY RefDate, BranchId


GO
