SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[VW_GET_NEW_ITEM_BAL_QTY_BY_BARCODE_ID] 
AS
SELECT a.suppId,c.Name AS BranchName,a.ItemId,b.Name AS ITEM_NAME,b.ItemCode,a.BarcodeId,b.Model,b.UnitName,b.SalesPrice,b.ColumnName,b.RowName,b.ColumnId,b.RowId,
a.PurchasePrice,SUM(a.InQty-a.OutQty-a.PRtnQty+RtnQty)AS BalQty,a.WarrantyMonth,b.MainCatId,b.MainCatName,b.SubCatId,b.SubCatName,
b.SubSubCatId,b.SubSubCatName,b.BrandId,b.BrandName,a.Pno, Isnull(d.BonusFor,0) as BonusFor,Isnull(d.BonusQty,0) as BonusQty,Isnull(d.BonusEndDate,getdate()) as BonusEndDate, b.TradePrice,a.BatchNo,a.ExpiryDate,a.MfgDate,
b.MasterPack,b.CommercialBox,b.SalesVat,b.Discount
FROM tbl_STOCK_LEDGER AS a 
LEFT JOIN VW_GET_ITEM_DETAILS b ON a.ItemId=b.Id 
LEFT JOIN tbl_COMPANY_INFORMATION c ON c.Id=a.Pno
LEFT JOIN tbl_BONUS_INFO d ON a.ItemId=d.ItemId 
GROUP BY a.suppId,c.Name,a.ItemId,b.Name,b.ItemCode,a.BarcodeId,b.Model,b.UnitName,b.SalesPrice,b.ColumnName,b.RowName,b.ColumnId,b.RowId,a.PurchasePrice,b.TradePrice,b.MasterPack,b.CommercialBox,
a.WarrantyMonth,b.MainCatId,b.MainCatName,b.SubCatId,b.SubCatName,b.SubSubCatId,b.SubSubCatName,b.BrandId,b.BrandName,a.Pno, d.BonusFor,d.BonusQty,d.BonusEndDate,a.BatchNo,a.ExpiryDate,a.MfgDate,b.SalesVat,b.Discount

HAVING SUM(a.InQty-a.OutQty-a.PRtnQty+RtnQty)> 0



GO
/****** Object:  View [dbo].[VW_CRITICAL_QTY]    Script Date: 3/12/2026 6:25:13 AM ******/
