GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[VW_CRITICAL_QTY] AS 

SELECT SUM(a.Quantity) As Qty,a.ItemId,b.Name AS ItemName, a.Pno, c.Name as CatName,b.SubCatId,
ISNULL((SELECT SUM(BalQty) FROM VW_GET_NEW_ITEM_BAL_QTY_BY_BARCODE_ID WHERE ItemId=a.ItemId),0) AS CurrQty 
FROm tbl_SALES_DETAIL a LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id
LEFT JOIN tbl_ITEM_SUB_CATEGORY c ON b.SubCatId=c.Id
GROUP BY a.ItemId,b.Name, a.Pno,c.Name,b.SubCatId
Having ISNULL((SELECT SUM(BalQty) FROM VW_GET_NEW_ITEM_BAL_QTY_BY_BARCODE_ID WHERE ItemId=a.ItemId),0) < 1






GO
