GO
SET QUOTED_IDENTIFIER ON
GO
CREATE view [dbo].[PHAR_SALES_COLL_SUMMARY]
as --- Select * From PHAR_SALES_COLL_SUMMARY
	select a.TrDate, SUM(a.Sales) as TotalAmt, SUM(a.Collection) as AdvanceAmt, SUM(a.LessAmt) As LessAmt, SUM(a.Sales-a.LessAmt-a.Collection) as DueAmt,
	SUM(a.DueColl) as DueColl, SUM(a.DueLess) as DueLess, SUM(a.CashReturn) as CashReturn, sum(a.CashAmt) as CashAmt, sum(a.CardAmt) as CardAmt, 
	sum(a.ChequeAmt) as ChequeAmt, SUM(a.AdjustAmt) AS AdjustAmt,
	a.PtStatus, a.CostCenterName, a.BranchId, a.Valid, a.UnitId, a.StoreId, b.SubSubPno
	from PharSalesLedger a
	INNER JOIN ProjectInformations b On a.StoreId=b.PnoCode
	--where Valid=1 ---AND PtStatus != 'Indoor'
	WHERE a.Valid=1
	group by a.TrDate, a.PtStatus, a.CostCenterName, BranchId, a.Valid, a.UnitId, a.StoreId, b.SubSubPno


GO
