SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VW_DAILY_COLLECTION_SUMMARY_FROM_ALL_DEPARTMENT]
AS
SELECT a.UserName,a.InvoiceDate,SUM(a.CashAmount) AS CashAmount,SUM(a.CardAmount) AS CardAmount,'Intime Collection' AS Status,a.Pno,c.Name As PnoName 
from tbl_SALES_MAIN a LEFT JOIN tbl_COMPANY_INFORMATION b ON a.Pno=b.Id  LEFT JOIN tbl_COMPANY_INFORMATION c ON a.pno=c.Id WHERE a.Valid=1
Group by a.UserName,a.InvoiceDate,a.Pno,c.Name
UNION ALL
SELECT a.UserName,a.TrDate,SUM(a.CashAmount) AS CashAmount,SUM(a.CardAmount) AS CardAmount,'Due Collection' AS Status ,a.Pno,c.Name As PnoName 
from tbl_DUE_COLLECTION a LEFT JOIN tbl_COMPANY_INFORMATION b ON a.Pno=b.Id LEFT JOIN tbl_COMPANY_INFORMATION c ON a.pno=c.Id WHERE a.Valid=1 
 Group by a.UserName,a.TrDate,a.Pno,c.Name 
--UNION ALL
--SELECT a.UserName,a.TrDate AS InvoiceDate,SUM(a.CashReturnAmount-a.CashReturnAmount*2) AS CashAmount,0 AS CardAmount,'Cash Return' AS Status ,a.Pno,c.Name As PnoName  
--from tbl_SALES_LEDGER  a LEFT JOIN tbl_COMPANY_INFORMATION b ON a.Pno=b.Id LEFT JOIN tbl_COMPANY_INFORMATION c ON a.pno=c.Id WHERE a.Valid=1 
--AND a.ReturnAmount>0 Group by a.UserName,a.TrDate,a.Pno,c.Name
UNION ALL
SELECT a.UserName,a.Trans_dt AS   InvoiceDate,SUM(a.Debit-a.Debit*2) AS CashAmount,0 AS CardAmount,'Cash Expense' AS Status ,a.Pno,b.Name As PnoName  
from VW_ExpenseList  a LEFT JOIN tbl_COMPANY_INFORMATION b ON a.Pno=b.Id 
Group by a.UserName,a.Trans_dt,a.Pno,b.Name








GO
