CREATE VIEW [dbo].[VW_GET_NEW_ITEM_BAL_QTY_BY_BARCODE_AND_SUPPID] 
AS
SELECT a.SuppId,a.ItemId,b.Name AS ITEM_NAME,a.BarcodeId,b.Model,b.SalesPrice,
a.PurchasePrice,SUM(a.InQty-a.OutQty-a.PRtnQty+RtnQty)AS BalQty,a.WarrantyMonth,b.MainCatId,b.MainCatName,b.SubCatId,b.SubCatName,b.SubSubCatId,b.SubSubCatName,b.BrandId,b.BrandName,a.Pno
FROM tbl_STOCK_LEDGER AS a 
LEFT JOIN VW_GET_ITEM_DETAILS b ON a.ItemId=b.Id 
GROUP BY  a.SuppId,a.ItemId,b.Name,a.BarcodeId,b.Model,b.SalesPrice,a.PurchasePrice,a.WarrantyMonth,b.MainCatId,b.MainCatName,b.SubCatId,b.SubCatName,b.SubSubCatId,b.SubSubCatName,b.BrandId,b.BrandName,a.Pno
HAVING SUM(a.InQty-a.OutQty-a.PRtnQty+RtnQty)> 0







GO
