CREATE VIEW [dbo].[VW_GET_NEW_ITEM_BAL_QTY_BY_ITEM_ID] 
AS
SELECT c.Name AS BranchName,a.ItemId,b.Name AS ITEM_NAME,b.Model,b.SalesPrice,b.ColumnName,b.RowName,b.ColumnId,b.RowId,
a.PurchasePrice,SUM(a.InQty-a.OutQty-a.PRtnQty+RtnQty)AS BalQty,a.WarrantyMonth,b.MainCatId,b.MainCatName,b.SubCatId,b.SubCatName,
b.SubSubCatId,b.SubSubCatName,b.BrandId,b.BrandName,a.Pno
FROM tbl_STOCK_LEDGER AS a 
LEFT JOIN VW_GET_ITEM_DETAILS b ON a.ItemId=b.Id 
LEFT JOIN tbl_COMPANY_INFORMATION c ON c.Id=a.Pno
GROUP BY c.Name,a.ItemId,b.Name,b.Model,b.SalesPrice,b.ColumnName,b.RowName,b.ColumnId,b.RowId,a.PurchasePrice,
a.WarrantyMonth,b.MainCatId,b.MainCatName,b.SubCatId,b.SubCatName,b.SubSubCatId,b.SubSubCatName,b.BrandId,b.BrandName,a.Pno
HAVING SUM(a.InQty-a.OutQty-a.PRtnQty+RtnQty)> 0









