CREATE VIEW [dbo].[VW_GET_PARTY_INVOICE_WISE_DUE_LIST] AS

--SELECT aa.InvoiceNo, aa.InvoiceDate, aa.PayableAmount, aa.LessAmount, aa.PaidAmount, aa.CashAmount, aa.CardAmount, aa.ChequeAmount, aa.DueAmount--, bb.Particulars AS InvoiceType, bb.CompanyID AS SupplierId, cc.Name AS SupplierName
--FROM(
SELECT a.PINo AS InvoiceNo, a.PIDate AS InvoiceDate, a.CompanyID AS SupplierId, SUM(a.PurchaseAmt) AS PayableAmount, SUM(a.Less) AS LessAmount, SUM(a.PaymentAmt) AS PaidAmount, SUM(a.CashAmt) AS CashAmount, SUM(a.CardAmt) AS CardAmount, SUM(a.ChequeAmt) AS ChequeAmount, SUM(a.PurchaseAmt-a.Less-a.CashAmt-a.CardAmt-a.ChequeAmt) AS DueAmount
FROM PharmaPurchaseLedger a
LEFT JOIN PharStockInMain c ON a.RefNo = c.InvoiceNo AND a.RefDate = c.InvoiceDate
WHERE a.Valid = 1 --AND a.CompanyID = 'A001' AND a.PIDate = '2023-04-07'
GROUP BY a.PINo, a.PIDate, a.CompanyID
HAVING SUM(a.PurchaseAmt-a.Less-a.CashAmt-a.CardAmt-a.ChequeAmt) <> 0
--) aa
--LEFT JOIN PharmaPurchaseLedger bb ON aa.InvoiceNo = bb.PINo AND aa.InvoiceDate = bb.PIDate
--LEFT JOIN PharCompanyInfo cc ON bb.CompanyID = cc.Company_Id


