/****** Object:  View [dbo].[VW_PROCEDURE_ENTRY_FOR_DR]    Script Date: 3/12/2026 6:25:13 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VW_PROCEDURE_ENTRY_FOR_DR]
AS
	select a.RefNo, a.RefDate, b.BedNo, b.PatientSex, b.UnderDrName+''+e.Degree AS UnderDrName, b.AdmissionDate, b.AdmissionTime, a.EntryDateTime,
	a.PatientName, a.PatientId, a.Code, f.Description+' '+g.DrName+' '+g.Degree AS Particulars, a.Charge, a.Unit, a.NoU, a.TotalAmount, a.BranchId, ISNULL(d.PaidAmt, 0) AS PaidAmt
	from PatientLedger a
	LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
	LEFT JOIN BedInformation c ON a.BranchId = c.BranchId AND b.BedNo = c.BedNo
	LEFT JOIN IndoorDrLedger d ON a.BranchId = d.BranchId AND a.RefDate = d.RefDate AND a.RefNo = d.RefNo 
	AND a.DrCode = d.DrCode AND d.Valid = 1 AND a.Code = d.PCode
	LEFT JOIN DrInfo e ON a.BranchId = e.BranchId AND b.UnderDrCode = e.DrCode
	LEFT JOIN DrInfo g ON a.BranchId = g.BranchId AND a.DrCode = g.DrCode
	LEFT JOIN ClinicalChart f ON a.BranchId = f.BranchId ANd a.Code = f.PCode
	where a.Status = 'Procedure Entry For Dr' and a.Valid = 1 --and a.RefNo = 'DV240800001' --AND b.isRelease = 0 
GO
