CREATE VIEW [dbo].[HP_DEPARTMENT_LEDGER] AS

select a.PatientId, a.BedNo, a.Department, SUM(a.SalesAmount) as SalesAmount, SUM(a.Collection) as Collection, SUM(a.ReturnAmt) as ReturnAmt, SUM(a.Adjust) as Adjust, SUM(a.Less) as Less, a.BranchId From (
select a.PatientId, a.Particulars, a.BedNo, b.SubSubPno as Department, a.Charge*a.NoU+a.ServiceCharge as SalesAmount, 
a.Collection, a.ReturnAmt, a.Adjust as Adjust, a.Less, a.BranchId
from PatientLedger a, BedInformation b where a.BranchId = b.BranchId AND a.BedNo=b.BedNo and a.Valid = 1
--UNION ALL
--select a.PatientId, 'Diagnostic Bill', a.BedNo, b.SubSubPno as Department, 0 as SalesAmount, 
--0 as Collection, 0 as ReturnAmt, 0 as Adjust, a.Less as Less 
--from SalesLedger a, BedInformation b where a.BedNo = b.BedNo and a.PtStatus = 'Indoor' and a.PatientId = 'PA220100115'
--UNION ALL
--select a.PatientId, 'Medicine Bill' , a.BedNo, b.SubSubPno as Department, 0 as SalesAmount, 0 as Collection, 0 as ReturnAmt, 0 as Adjust, a.LessAmt as Less from PharSalesLedger a, BedInformation b where a.BedNo = b.BedNo and a.PtStatus = 'Indoor' and a.PatientId = 'PA220100115'
) a
group by a.PatientId, a.BedNo, a.Department, a.BranchId

