CREATE VIEW [dbo].[VW_InvPurchaseRequisitionList]
AS
	select a.ReqNo, a.ReqDate, a.Department, a.ReqFrom, a.Note, a.UserName, a.UnitId, a.BranchId, 
		SUBSTRING(
				(SELECT ', ' + c.ProductCategory
				 FROM InvPurchaseRequisitionDetails b
				 LEFT JOIN InvItemRegistration c ON b.ProductCode=c.ProductCode
				 WHERE a.BranchId = b.BranchId AND a.ReqNo = b.ReqNo
				 GROUP BY c.ProductCategory
				 ORDER BY c.ProductCategory
				 FOR XML PATH('')), 3, 1000
			 )	AS Categories
	from InvPurchaseRequisitionMain a 
	where a.Valid=1
GO
