CREATE VIEW [dbo].[VW_CUSTOMER_LIST] AS
SELECT a.*,ISNULL((SELECT SalesAmount  FROM tbl_SALES_LEDGER 
WHERE CustId=a.Id and InvoiceNo like 'OB%' and SalesAmount>0),0) AS OpeningDue,
ISNULL((Select TOP 1 InvoiceDate from tbl_SALES_LEDGER WHERE CustId=a.Id and InvoiceNo like 'SI%' ORDER BY InvoiceDate DESC), '2019-12-07 00:00:00') as LastBuy
from tbl_customer a WHERE a.valid=1




