GO







CREATE VIEW [dbo].[VW_DATEWISE_COLLECTION]
AS
SELECT a.Pno,1 as Sl,a.Id,'IntimeCollection' AS CollType, a.InvoiceNo,a.InvoiceDate,a.CustId,b.Name as CustName,b.MobileNo,a.LessAmount,a.CashAmount,a.CardAmount,a.UserName,c.Name AS PnoName,a.AreaName,a.EntryDate
FROM tbl_SALES_MAIN AS a LEFT JOIN tbl_CUSTOMER b ON a.CustId=b.Id 
LEFT JOIN tbl_COMPANY_INFORMATION AS c ON c.Id=a.Pno
where a.CashAmount>0 or a.CardAmount>0
UNION ALL
SELECT a.Pno,2 AS Sl,a.Id,'DueCollection' AS CollType, a.TrNo AS  InvoiceNo,a.TrDate AS InvoiceDate,a.CustId,b.Name as CustName,b.MobileNo,a.LessAmount,a.CashAmount,a.CardAmount,a.UserName ,c.Name AS PnoName,'N/A' as AreaName,a.EntryDate
FROM tbl_DUE_COLLECTION AS a LEFT JOIN tbl_CUSTOMER b ON a.CustId=b.Id
LEFT JOIN tbl_COMPANY_INFORMATION AS c ON c.Id=a.Pno
where a.CashAmount>0 or a.CardAmount>0














