	Inner Join PasswordDtls b On a.ControllerName=b.ControllerName and a.ActionName=b.ActionName --a.SlNo=b.SlNo And a.SubSlNo=b.SubSlNo --And a.ControllerName=b.ControllerName
	Where a.WillShow=1

