CREATE VIEW [dbo].[VW_DIAGNOSIS_DUE_COLL_LIST] AS 

select a.RefNo, a.RefDate, a.PrevInvNo, a.PreInvDate, a.Particulars, a.ByCash, a.ByCard, a.CardNo, a.CardBank, a.ChequeAmount, 
a.ChequeNo, 
(
select sum(Sales-Less-Collection-ReturnNet) 
from SalesLedger 
where Valid <> 0 AND BranchId = a.BranchId AND PrevInvNo=a.PrevInvNo and PostingDateTime < a.PostingDateTime
) as Due,
a.Collection, a.Less, b.PCode, b.ShortDesc, b.TotalAmount, b.RptDeliveryDate, a.UserName, a.Remarks, a.Department, a.BranchId
from SalesLedger a, InvDetails b 
where a.CRType ='Collection' and a.PrevInvNo=b.InvNo AND a.BranchId = b.BranchId and a.Valid <> 0 

