                         dbo.HospitalDischargeMaster.Sex, dbo.HospitalDischargeMaster.Age, dbo.HospitalDischargeMaster.Address, dbo.HospitalDischargeMaster.Phone, dbo.HospitalDischargeMaster.AdmissionDate, 
                         dbo.HospitalDischargeMaster.AdmissionTime, dbo.HospitalDischargeMaster.ReleaseDate, dbo.HospitalDischargeMaster.ReleaseTime, dbo.HospitalDischargeMaster.Religion, dbo.HospitalDischargeMaster.UnderDr, 
