--09102025 add PtStatus.
CREATE VIEW [dbo].[VW_IndoorIndentList]
WITH SCHEMABINDING
AS
	SELECT a.RefDate, a.RefNo, b.PatientId, a.UserName, a.RegNo, a.BranchId, MAX(a.EntryDateTime) AS EntryDateTime,
	b.BedNo, b.PatientTel, ISNULL(b.IsPharmaDone, 0) AS IsPharmaDone,
	Case When c.SubSubPno = 'Ward' THen 'Outdoor' Else 'Indoor' End As PtStatus
	FROM dbo.CommonMedicine a
	LEFT JOIN dbo.PatientAdmission b ON a.BranchId = b.BranchId AND a.RegNo = b.RegNo AND b.Valid = 1 AND b.IsRelease = 0
	Left Join dbo.BedInformation c On b.BedNo=c.BedNo And a.BranchId=c.BranchId
	WHERE a.IsDone = 0 AND a.Valid = 1 AND a.Status = 'Indoor Medicine Requsition'
	AND a.DoneBy IS NULL AND b.PatientId IS NOT NULL
	GROUP BY a.RefDate, a.RefNo, b.PatientId, a.UserName, a.RegNo, a.BranchId, b.IsPharmaDone, b.BedNo, 
	b.PatientTel, c.SubSubPno
GO
