CREATE VIEW [dbo].[VW_DUE_COLLECTION]
AS
SELECT a.*,b.Name As CustName,b.Address,b.MobileNo,ISNULL(d.Name,'N/A') AS ItemName,ISNULL(d.Model,'N/A') AS Model,
ISNULL(c.Quantity,0) AS Quantity ,(SELECT SUM(SalesAmount-CollectionAmount-LessAmount-ReturnAmount)
FROM tbl_SALES_LEDGER WHERE InvoiceNo=a.InvoiceNo AND CustId=a.CustId AND TrDate <=a.TrDate) AS DueAmt
FROM tbl_DUE_COLLECTION a LEFT JOIN tbl_CUSTOMER b ON a.CustId=b.Id
LEFT JOIN tbl_SALES_DETAIL c ON a.InvoiceNo=c.InvoiceNo AND a.CustId=c.CustId AND a.Pno=c.Pno
LEFT JOIN tbl_ITEM d ON c.ItemId=d.Id







