CREATE View [dbo].[VW_IpdPatientListForPharSales]
With SchemaBinding
As
	Select  a.Id, a.RegNo, a.PatientId, a.AdmissionDate, a.AdmissionTime, a.PatientName, a.PatientSex, 
	a.PatientAge, a.PatientAddress, a.DrCode, a.DrName, a.BedNo, a.PatientType, a.PatientTel, a.AdmittedDept,
	a.UnderDrCode, a.UnderDrName, a.CorporateId, a.CorporateName, a.BranchId,
	datediff(day, a.AdmissionDate, Isnull(a.ReleaseDate, Getdate())) as TotalDays, a.PackCode, a.IsRelease, ISNULL(b.IsDone, 1) AS IsPrescribe,
	Case When c.SubSubPno = 'Ward' THen 'Outdoor' Else 'Indoor' End As PtStatus, a.IsPharmaDone
	From dbo.PatientAdmission a
	Left Join dbo.CommonMedicine b On a.BranchId = b.BranchId ANd a.RegNo = b.RegNo AND b.Valid = 1 AND b.IsDone = 0
	Left Join dbo.BedInformation c on a.BranchId=c.BranchId And a.BedNo=c.BedNo
	Where a.BranchId=1 And a.Valid=1

