CREATE VIEW [dbo].[VW_DUE_PAYMENT]
AS
--SELECT a.*,b.Name As SuppName,b.Address,b.MobileNo,
--Isnull((SELECT Isnull(SUM(PayableAmount-PaymentAmount-ReturnAmount),0)
--from tbl_PURCHASE_LEDGER where SuppId=a.SuppId and Pno=a.Pno),0) as CurrentDue
--FROM tbl_LC_PAYMENT a LEFT JOIN tbl_SUPPLIER_INFO_MASTER b ON a.SuppId=b.Id
SELECT a.*,b.Name As SuppName,b.Address,b.MobileNo,
Isnull((SELECT Isnull(SUM(PayableAmount-PaymentAmount-ReturnAmount),0) from tbl_PURCHASE_LEDGER where SuppId=a.SuppId and Pno=a.Pno),0) as CurrentDue
FROM tbl_DUE_PAYMENT a LEFT JOIN tbl_SUPPLIER_INFO_MASTER b ON a.SuppId=b.Id



