CREATE VIEW [dbo].[PHAR_STOCK_TRANSFER] AS 
SELECT a.TrNo, a.TrDate, a.FromBranchId, b.name as FromBranch, a.FromUnitId, d.name as FromUnit, a.FromStoreId, c.SubSubPno as FromStore, a.ToBranchId, e.name as ToBranch, a.ToUnitId, g.name as ToUnit, a.ToStoreId, f.SubSubPno as ToStore, CompanyId, ProductId, ProductName, StockOutQty, TP, TotalTp, a.UserName, a.EntryDateTime from PharStockTransfer a 
left join tbl_BranchInfo b on a.FromBranchId=b.Id
left join ProjectInformations c on a.FromStoreId=c.PnoCode
left join tbl_COMPANY_INFORMATION d on a.FromUnitId=d.id
left join tbl_BranchInfo e on a.ToBranchId=e.Id
left join ProjectInformations f on a.ToStoreId=f.PnoCode
left join tbl_COMPANY_INFORMATION g on a.ToUnitId=g.id

