GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[VW_DUELIST]
AS
SELECT c.Name AS PnoName,a.Pno,a.InvoiceNo, a.InvoiceDate, a.CustId,
SUM(a.SalesAmount - a.LessAmount - a.CollectionAmount - a.ReturnAmount) AS DueBal, b.Name AS CustName,
b.MobileNo, b.Address, STUFF((SELECT ',' +  CONVERT(varchar, n.Name) 
FROM tbl_SALES_DETAIL m   
LEFT JOIN tbl_ITEM n ON m.ItemId=n.Id  AND m.InvoiceNo=a.InvoiceNo FOR XML PATH('')), 1, 1, '') ItemName
FROM tbl_SALES_LEDGER AS a 
LEFT OUTER JOIN tbl_CUSTOMER AS b ON a.CustId = b.Id
LEFT JOIN tbl_COMPANY_INFORMATION AS c On a.Pno=c.Id
GROUP BY c.Name,a.Pno,a.InvoiceNo, a.InvoiceDate, a.CustId, b.Name, b.MobileNo, b.Address
HAVING (SUM(a.SalesAmount - a.LessAmount - a.CollectionAmount - a.ReturnAmount) > 0)





