CREATE VIEW [dbo].[VW_INDOOR_PTN_STATUS]
AS
SELECT 'DIA'+a.InvNo AS InvNo, a.InvDate, b.MasterCode AS PCode, a.AliasNo, a.Result, a.Unit, a.NormalValue, a.ReportingGroupName, a.ReportHeaderName,
a.GroupSlNo AS GSlNo, a.SerialNo AS SlNo, 1 AS BranchId
FROM LabDb.dbo.tb_MachineDataDtls a
LEFT JOIN LabDb.dbo.tb_VacutainerSetup b ON a.TestCode = b.ItemId
WHERE InvNo IS NOT NULL
--select * from LabDb_ASH.dbo.tb_MachineDataDtls where invno = '230700004'

GO
