/****** Object:  StoredProcedure [dbo].[PHAR_INDOOR_PATIENT_DETAILS]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROC [dbo].[PHAR_INDOOR_PATIENT_DETAILS] (@patientId as nvarchar(20), @BranchId int, @RegNo VARCHAR(20))
AS
Begin
SELECT aa.InvNo, aa.InvDate, aa.PatientId, aa.PatientName, aa.BedNo, aa.ProductName, aa.SalesQty, aa.RtnQty, aa.SalePrice, aa.TotalAmt,
aa.PtStatus, aa.UserName, bb.Collection, bb.LessAmt, bb.ReturnAmt, bb.CashReturn, aa.EntryDateTime 
from
(
	select a.SaleNo as InvNo, a.SaleDate as InvDate,a.PatientId, b.PatientName, b.BedNo, a.ProductName,
	a.ProductQty as SalesQty, 0 as RtnQty, a.SalePrice, a.ProductQty * a.SalePrice as TotalAmt,
	b.PtStatus, a.UserName, b.EntryDateTime
	from PharSalesDetails a
	left join PharSalesMaster b on a.SaleNo=b.SaleNo AND b.Valid = 1 AND a.BranchId=b.BranchId
	WHERE a.Valid = 1 AND b.BranchId = @BranchId AND b.RegNo = @RegNo AND b.PatientId LIKE '%'+@patientId+'%'
) aa,
(
	SELECT PatientId, SUM(Collection+DueColl+AdjustAmt) AS Collection, SUM(LessAmt+DueLess+LessAdjust) AS LessAmt,
	SUM(ReturnAmt) AS ReturnAmt, SUM(CashReturn) AS CashReturn
	FROM PharSalesLedger
	WHERE Valid = 1 AND BranchId = @BranchId AND RegNo = @RegNo AND PatientId LIKE '%'+@patientId+'%'
	GROUP BY PatientId
) bb
WHERE aa.PatientId = bb.PatientId and aa.PatientId=@patientId

UNION ALL
SELECT a.ReturnNo, a.ReturnDate, a.PatientId, a.PatientName, a.BedNo, b.ProductName, 0 AS SalesQty, b.ProductQty, b.SalePrice, -(b.ProductQty*b.SalePrice) AS Total, a.PtStatus, a.UserName, 0 AS Collection, -LessAmt, a.TotalRtn AS ReturnAmt, -a.CashReturn, a.EntryDateTime
FROM PharSalesReturnMaster a
LEFT JOIN PharSalesReturnDetails b ON a.BranchId=b.BranchId AND a.ReturnNo=b.ReturnNo AND a.PatientId=b.PatientId
where a.BranchId=@BranchId AND a.PatientId=@patientId

END

GO
/****** Object:  StoredProcedure [dbo].[PHAR_INDOOR_PATIENT_DETAILS_AMOUNT]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[PHAR_INDOOR_PATIENT_DETAILS_AMOUNT] (@PatientId nvarchar(50), @BranchId int, @RegNo VARCHAR(20))
AS
BEGIN
SELECT TrNo, TrDate, PatientId, SUM(Collection+DueColl) AS Collection, SUM(LessAmt+DueLess) AS LessAmt,
SUM(CashReturn) AS ReturnAmt
FROM PharSalesLedger
WHERE Valid = 1 AND BranchId = @BranchId AND RegNo = @RegNo AND PatientId LIKE '%'+@patientId+'%'
GROUP BY TrNo, TrDate, PatientId
HAVING SUM(Collection+DueColl) > 0
end
GO
