SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



CREATE PROC [dbo].[RegFees] (@FromDate date, @ToDate date, @UserName nvarchar(50))
AS
if @UserName <> ''
BEGIN
SELECT RegNo, PatientName, TrNo, TrDate, TrType, Amount, UserName, EntryDateTime as EntryTime FROM RegistrationFees where Valid = 1 and TrDate BETWEEN @FromDate AND @ToDate AND UserName = @UserName ORDER BY TrNo
end
Else
BEGIN
SELECT RegNo, PatientName, TrNo, TrDate, TrType, Amount, UserName, EntryDateTime as EntryTime FROM RegistrationFees where Valid = 1 and TrDate BETWEEN @FromDate AND @ToDate ORDER BY TrNo
end


GO
/****** Object:  StoredProcedure [dbo].[SP_AC_CompareRpt]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE Procedure [dbo].[SP_AC_CompareRpt] @DateFrom date ,@DateTo date , @ACCode nvarchar(20), @BranchId INT
AS
BEGIN /* EXEC SP_AC_CompareRpt  '2022-06-22','2022-06-22', '', 1 */

drop table tmpCompareAC
drop table tmpCrossExp

select SUBSTRING(a.Code,1,6)+'0000' as code , b.Description ,
SUM(a.Debit) as Dr , SUM(a.credit) as Cr , b.RPTType 
INTO tmpCompareAC
from tbl_TRANSACT a, tbl_CHART_OF_ACCOUNTS b
where a.Valid = 1 
AND Trans_dt BETWEEN @DateFrom AND @DateTo AND a.CODE LIKE @ACCode + '%'
and a.Code = b.Code 
and a.VoucherType IN ('Bank Payment','Cash Payment')
AND a.Code NOT LIKE '2101'+'%'
GROUP BY SUBSTRING(a.Code,1,6),b.RPTType ,b.Description
ORDER BY SUBSTRING(a.Code,1,6)

INSERT INTO tmpCompareAC(Code, Description, Cr, Dr, RPTType)
VALUES('4102050000', 'Entertainment-College', 0, 0, 'Trust'),
('4102050000', 'Entertainment-College', 0, 0, 'Accounts'),
('4102050000', 'Entertainment-College', 0, 0, 'Hospital'),
('4102050000', 'Entertainment-College', 0, 0, 'College'),
('4102050000', 'Entertainment-College', 0, 0, 'Nursing')

UPDATE tmpCompareAC SET Description = b.Description
FROM tmpCompareAC a , tbl_CHART_OF_ACCOUNTS b
WHERE a.code = b.Code

DECLARE @cols AS NVARCHAR(MAX), @query AS NVARCHAR(MAX);

SET @cols = STUFF((SELECT distinct ',' + QUOTENAME(c.RPTType) 
            FROM tmpCompareAC c
            FOR XML PATH(''), TYPE
            ).value('.', 'NVARCHAR(MAX)') 
        ,1,1,'')
    
set @query = 'SELECT ROW_NUMBER() OVER (order by Code) AS RowId, Code, Description, ' + @cols + ' INTO tmpCrossExp 
	from 
    (
		select code, Description, (Dr-cr) As Bal, RPTType
        from tmpCompareAC
    ) x
    pivot 
    (
		SUM(Bal)
        for RPTType in (' + @cols + ')
    ) p'
execute(@query)

SELECT ROW_NUMBER() OVER (order by Code) as SlNo, CostDept, Code, Description, Income INTO #z FROM (
	SELECT CostDept, Code, Description, Income FROM (
		SELECT 'Hospital' AS CostDept, a.Code, b.Description, SUM(Credit) AS Income 
		FROM tbl_TRANSACT a
		LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code = b.Code
		WHERE BranchId = @BranchId AND a.Valid = 1 AND a.Trans_dt BETWEEN @DateFrom and @DateTo AND a.Code LIKE '310101%'
		GROUP BY a.Code, b.Description
		UNION ALL
		SELECT 'Hospital' AS CostDept, a.Code, b.Description, -sum(Debit) AS Income
		FROM tbl_TRANSACT a
		LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code = b.Code
		WHERE BranchId = @BranchId AND a.Valid = 1 AND a.Trans_dt BETWEEN @DateFrom and @DateTo AND a.Code LIKE '310201%'
		GROUP BY a.Code, b.Description
	) Hospital
	UNION ALL
	SELECT 'College' AS CostDept, a.Code, b.Description, SUM(Credit) AS Income 
	FROM tbl_TRANSACT a
	LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code = b.Code
	WHERE BranchId = @BranchId AND a.Valid = 1 AND a.Trans_dt BETWEEN @DateFrom and @DateTo AND a.Code LIKE '310102%'
	GROUP BY a.Code, b.Description
	UNION ALL
	SELECT 'Nursing' AS CostDept, a.Code, b.Description, SUM(Credit) AS Income 
	FROM tbl_TRANSACT a
	LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code = b.Code
	WHERE BranchId = @BranchId AND a.Valid = 1 AND a.Trans_dt BETWEEN @DateFrom and @DateTo AND a.Code LIKE '310103%'
	GROUP BY a.Code, b.Description
	UNION ALL
	SELECT 'Account Fees Collection' AS CostDept, a.Code, b.Description, SUM(Credit) AS Income 
	FROM tbl_TRANSACT a
	LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code = b.Code
	WHERE BranchId = @BranchId AND a.Valid = 1 AND a.Trans_dt BETWEEN @DateFrom and @DateTo AND a.Code LIKE '310104%'
	GROUP BY a.Code, b.Description
) AS Income

alter table #z add gid int
update #z set gid = 5 where CostDept = 'College'
update #z set gid = 4 where CostDept = 'Hospital'
update #z set gid = 3 where CostDept = 'Nursing'
update #z set gid = 2 where CostDept = 'Trust'
update #z set gid = 1 where CostDept = 'Accounts'

--select * from tmpCrossExp order by code 
--select * from #z

SELECT gid, b.SlNo, b.CostDept, b.Code AS InCode, b.Description AS InDescription, b.Income,
a.RowId, a.Code AS ExCode, a.Description AS ExDescription, ISNULL(a.Accounts, 0) AS Accounts,
ISNULL(a.College, 0) AS College, ISNULL(a.Hospital, 0) AS Hospital, ISNULL(a.Nursing, 0) AS Nursing,
ISNULL(a.Trust, 0) AS Trust
FROM tmpCrossExp a
LEFT JOIN #z b on a.RowId = b.SlNo
ORDER BY gid DESC
END
GO
