CREATE PROC [dbo].[Sp_AccVoucherListSmz] @DateFrom DATE, @DateTo DATE, @BranchId INT, @VoucherType VARCHAR(20)
AS
BEGIN /* EXEC Sp_AccVoucherListSmz '2022-07-03', '2022-07-03', 1, '' */
select 999999 AS Id, a.Code, b.Description, a.CostDept, 
ISNULL(SUBSTRING((SELECT ',' + bb.Description+SPACE(2)+'('+aa.Naration+')' FROM tbl_TRANSACT aa, tbl_CHART_OF_ACCOUNTS bb where aa.Valid = 1 AND aa.BranchId = 1 and aa.TrNo = a.TrNo AND aa.Trans_dt = a.Trans_dt and aa.Code = bb.Code and aa.CorD = 'D' Group by aa.ContraCode, bb.Description, aa.Naration FOR XML PATH('')), 2 , 1000),'') As Narration,
SUM(a.Debit) AS Debit, SUM(a.Credit) AS Credit, a.TrNo, a.Trans_dt, a.Pno, a.RefNo AS VrRefNo, a.UserName, a.VoucherType, a.Remark, a.PartyName, a.ChequeNo
from tbl_TRANSACT AS a
LEFT JOIN tbl_CHART_OF_ACCOUNTS AS b ON a.Code = b.Code
where a.BranchId = @BranchId AND a.Valid = 1 AND a.CorD = 'C' and a.Trans_dt BETWEEN @DateFrom AND @DateTo AND VoucherType LIKE '%Payment%'
group by a.Code, a.TrNo, a.Trans_dt, a.Pno, a.RefNo, b.Description, a.CostDept, a.UserName, a.VoucherType, a.Remark, a.PartyName, a.ChequeNo
UNION ALL
select a.Id, a.Code, b.Description, a.CostDept, a.Naration As Narration,
SUM(a.Debit) AS Debit, SUM(a.Credit) AS Credit, a.TrNo, a.Trans_dt, a.Pno, a.RefNo AS VrRefNo, a.UserName, a.VoucherType, a.Remark, a.PartyName, a.ChequeNo
from tbl_TRANSACT AS a
LEFT JOIN tbl_CHART_OF_ACCOUNTS AS b ON a.Code = b.Code
where a.BranchId = @BranchId AND a.Valid = 1 and a.CorD = 'D' AND a.Trans_dt BETWEEN @DateFrom AND @DateTo AND VoucherType LIKE '%Payment%'
group by a.Id, a.Code, a.TrNo, a.Trans_dt, a.Pno, a.RefNo, b.Description, a.CostDept, a.UserName, a.VoucherType, a.Remark, a.Naration, a.PartyName, a.ChequeNo

END
GO
