CREATE PROC [dbo].[SP_AdmPtListDeptWise](@BranchId int, @FromDate datetime, @ToDate datetime)
AS
BEGIN
SELECT aaa.Department, aaa.BedType, aaa.DrCode, aaa.DrDept , aaa.DrName, SUM(aaa.PayingBed) AS PayingBed, SUM(aaa.NonPayingBed) AS NonPayingBed,
SUM(aaa.PayingBed+aaa.NonPayingBed) AS Total, SUM(aaa.PrevBed) AS PrevBed, aaa.Admission, aaa.Release, aaa.CurrentPtn as CurrentPtn FROM (
	select aa.Department, aa.DeptName AS DrDept, aa.KindsofBed BedType, aa.DrCode, aa.DrName, aa.PayingBed, aa.NonPayingBed, aa.PrevBed, cc.Admission, cc.Release, cc.CurrentPtn from
	(
	select c.SubSubPno AS Department, c.KindsofBed, b.DrCode, b.DeptName, b.DrName, COUNT(a.BedNo) AS PayingBed, 0 AS NonPayingBed, 0 AS PrevBed from PatientAdmission a, DrInfo b, BedInformation c
	WHERE a.BranchId = b.BranchId AND b.BranchId = c.BranchId AND a.BranchId = c.BranchId AND a.UnderDrCode = b.DrCode AND a.BedNo = c.BedNo AND c.PaidType = 1 AND a.Valid = 1 AND a.BranchId = @BranchId AND a.EntryDateTime BETWEEN @FromDate ANd @ToDate
	GROUP BY c.SubSubPno, c.KindsofBed, b.DrCode, b.DeptName, b.DrName
	UNION ALL
	select c.SubSubPno AS Department, c.KindsofBed, b.DrCode, b.DeptName, b.DrName, 0 AS PayingBed, COUNT(a.BedNo) AS NonPayingBed, 0 AS PrevBed from PatientAdmission a, DrInfo b, BedInformation c
	WHERE a.BranchId = b.BranchId AND b.BranchId = c.BranchId AND a.BranchId = c.BranchId AND a.UnderDrCode = b.DrCode AND a.BedNo = c.BedNo AND c.PaidType = 0 AND a.Valid = 1 AND a.BranchId = @BranchId AND a.EntryDateTime BETWEEN @FromDate ANd @ToDate
	GROUP BY c.SubSubPno, c.KindsofBed, b.DrCode, b.DeptName, b.DrName
	UNION ALL
	select c.SubSubPno AS Department, c.KindsofBed, b.DrCode, b.DeptName, b.DrName, 0 AS PayingBed, 0 AS NonPayingBed, COUNT(a.BedNo) AS PrevBed
	from PatientAdmission a, DrInfo b, BedInformation c
	WHERE a.BranchId = b.BranchId AND b.BranchId = c.BranchId AND a.BranchId = c.BranchId AND a.UnderDrCode = b.DrCode 
	AND a.BedNo = c.BedNo AND a.IsRelease = 0 AND a.Valid = 1 AND a.BranchId = 1 --AND a.EntryDateTime >= @FromDate AND a.EntryDateTime <= @ToDate
	GROUP BY c.SubSubPno, c.KindsofBed, b.DrCode, b.DeptName, b.DrName
	)aa,
	(
		SELECT SUM(bb.Admission) AS Admission, SUM(bb.Release) AS Release, SUM(bb.CurrentPtn) AS CurrentPtn from
		(
			select COUNT(a.BedNo) AS Admission, 0 AS Release, 0 As CurrentPtn from PatientAdmission a
			WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.EntryDateTime BETWEEN @FromDate ANd @ToDate --) bb,
			UNION ALL
			select 0 AS Release, COUNT(a.ReceiptNo) AS Release, 0 AS CurrentPtn from PatientReleaseMaster a
			WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.EntryDateTime BETWEEN @FromDate ANd @ToDate
			UNION ALL
			select 0 AS Release, 0 AS Release, COUNT(a.BedNo) AS CurrentPtn from PatientAdmission a
			WHERE a.IsRelease = 0 AND a.Valid = 1 AND a.BranchId = @BranchId
		) bb
	) cc
	) aaa
	GROUP BY aaa.Department, aaa.BedType, aaa.DrCode, aaa.DrName, aaa.DrDept, aaa.Admission, aaa.Release, aaa.CurrentPtn
end
GO
