CREATE PROC [dbo].[Sp_AmbulanceDiscountReport] @BranchId INT, @DateFrom VARCHAR(20), @DateTo VARCHAR(20), @PtStatus NVARCHAR(20)
AS
BEGIN /* EXEC Sp_AmbulanceDiscountReport 1, '2022-12-01', '2024-12-28', 'Indoor' */
SELECT a.RefDate, a.RefNo, b.PtStatus, b.RegNo, b.PatientId, b.BedNo, b.Mobile, b.PatientName, b.Gender, b.Age, a.UserName, a.Remarks,
b.DriverName, b.AmbulanceNo, UPPER(b.DestinationFrom + ' to ' + DestinationTo) AS Destination, a.TotalCharge, a.Less,
(SELECT SUM(TotalCharge-Less-ReceiveAmt-AdjustAmt) FROM AmbulanceLedger WHERE BranchId = a.BranchId AND PrevReceiptNo = b.ReceiptNo) as Due
FROM AmbulanceLedger a
LEFT JOIN AmbulanceMaster b ON a.BranchId = b.BranchId ANd a.PrevReceiptNo = b.ReceiptNo
WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.RefDate BETWEEN @DateFrom AND @DateTo
AND a.Less != 0 AND b.PtStatus LIKE '%'+@PtStatus+'%'
END
GO
