CREATE PROC [dbo].[Sp_AmbulanceDueCollectionRpt] @BranchId INT, @DateFrom VARCHAR(20), @DateTo VARCHAR(20), @PtStatus NVARCHAR(20)
AS /* EXEC Sp_AmbulanceDueCollectionRpt 1, '2022-12-10', '2024-05-30', 'Indoor' */
BEGIN
SELECT a.RefNo, a.RefDate, a.PrevReceiptDate, a.PrevReceiptNo, a.EntryDateTime, a.RegNo, a.PatientId,
a.BedNo, b.Age, a.PatientName, b.AmbulanceNo, a.ReceiveAmt, a.CashAmt, a.CardAmt, a.ChequeAmt,
a.PtStatus, a.UserName, b.DriverName, b.DestinationFrom +' to '+b.DestinationTo AS Destination, a.Mobile,
a.Remarks, DATEDIFF(DAY, a.PrevReceiptDate, a.RefDate) AS Days
FROM AmbulanceLedger a
LEFT JOIN AmbulanceMaster b ON a.BranchId = b.BranchId AND a.PrevReceiptNo=b.ReceiptNo
WHERE a.BranchId = @BranchId AND a.RefDate BETWEEN @DateFrom AND @DateTo AND a.Valid = 1 AND  a.InputFrom != 'Sales' AND a.PtStatus LIKE '%'+@PtStatus+'%'
END
GO
