CREATE PROC [dbo].[Sp_AmbulanceDueInvoiceRegisterRpt] @BranchId INT, @DateFrom VARCHAR(20), @DateTo VARCHAR(20), @PtStatus NVARCHAR(20)
AS /* EXEC Sp_AmbulanceDueInvoiceRegisterRpt 1, '2020-01-01', '2024-07-11', 'Indoor' */
BEGIN

SELECT ReceiptNo AS InvNo, ReceiptDate AS InvDate, RegNo, PatientId, BedNo, Age, PatientName, AmbulanceNo, PtStatus, DriverName, DestinationFrom + ' to '+DestinationTo AS Destination, Mobile, UserName, Remarks, TotalCharge, Less, TotalAdvanceAmt AS ReceiveAmt, CashAmt, CardAmt, ChequeAmt,
(a.TotalCharge-a.Less-a.TotalAdvanceAmt) AS Due
FROM AmbulanceMaster a 
where a.Valid = 1 AND a.BranchId = @BranchId ANd ReceiptDate BETWEEN @DateFrom AND @DateTo AND a.PtStatus LIKE '%'+@PtStatus+'%'
AND (a.TotalCharge-a.Less-a.TotalAdvanceAmt) != 0

----select a.PrevReceiptDate AS InvDate, a.PrevReceiptNo AS InvNo, a.RegNo, a.PatientId, a.BedNo, b.Age, a.PatientName, b.AmbulanceNo,
----a.PtStatus, b.DriverName, b.DestinationFrom +' to '+b.DestinationTo AS Destination, a.Mobile, b.UserName, b.Remarks,
------SUBSTRING((SELECT ',' + Remarks FROM AmbulanceLedger where BranchId = a.BranchId AND PrevReceiptDate = a.PrevReceiptDate AND PrevReceiptNo = a.PrevReceiptNo FOR XML PATH('')), 2 , 300) As Remarks,
----SUM(a.TotalCharge) AS TotalCharge, SUM(a.Less) AS Less, SUM(a.ReceiveAmt) AS ReceiveAmt, SUM(a.CashAmt) AS CashAmt,
----SUM(a.CardAmt) AS CardAmt, SUM(a.ChequeAmt) AS ChequeAmt, SUM(a.TotalCharge-a.Less-a.ReceiveAmt-a.AdjustAmt) AS Due
----from AmbulanceLedger a
----LEFT JOIN AmbulanceMaster b ON a.BranchId = b.BranchId AND a.PrevReceiptNo=b.ReceiptNo
----WHERE a.BranchId = @BranchId AND a.PrevReceiptDate BETWEEN @DateFrom AND @DateTo AND a.Valid = 1 AND a.PtStatus LIKE '%'+@PtStatus+'%'
----GROUP BY a.PrevReceiptDate, a.PrevReceiptNo, a.RegNo, a.PatientId, a.BedNo, b.Age, a.PatientName, b.AmbulanceNo,
----a.PtStatus, b.DriverName, b.DestinationFrom +' to '+b.DestinationTo, a.Mobile, b.UserName, b.Remarks
----HAVING SUM(a.TotalCharge-a.Less-a.ReceiveAmt-a.AdjustAmt) != 0

END
