CREATE PROCEDURE [dbo].[SP_AmbulanceDueStatement] @BranchId INT, @DateFrom NVARCHAR(20), @DateTo NVARCHAR(20), @PtStatus NVARCHAR(20)
AS --- EXEC SP_AmbulanceDueStatement 1, '2024-01-01', '2024-05-31', 'Indoor'
BEGIN
	SELECT a.ReceiptNo, a.ReceiptDate, a.PatientId, a.PatientName, a.Mobile, SUM(b.TotalCharge) AS Sales, SUM(b.Less) AS Less, 
	SUM(b.ReceiveAmt) AS Collection, SUM(b.TotalCharge - b.Less - b.ReceiveAmt) AS Due,  ISNULL(a.Remarks,'') AS Remarks, a.UserName, a.EntryDateTime, a.PtStatus
	FROM AmbulanceMaster a
	LEFT JOIN AmbulanceLedger b ON a.ReceiptNo = b.PrevReceiptNo AND a.RegNo = b.RegNo AND a.Valid = b.Valid AND a.BranchId = b.BranchId
	WHERE a.Valid = 1 AND b.Valid = 1 AND a.BranchId = @BranchId AND a.ReceiptDate BETWEEN @DateFrom AND @DateTo AND a.PtStatus LIKE '%'+@PtStatus+'%'
	GROUP BY a.ReceiptNo, a.ReceiptDate, a.PatientId, a.PatientName, a.Mobile, a.Remarks, a.UserName, a.EntryDateTime, a.PtStatus
	HAVING SUM(b.TotalCharge - b.Less - b.ReceiveAmt) != 0
END
GO
