CREATE PROC [dbo].[Sp_AmbulanceIncomeRptUser] @BranchId INT, @DateFrom VARCHAR(20), @DateTo VARCHAR(20), @UserName VARCHAR(50), @PtStatus NVARCHAR(20)
AS
BEGIN /* EXEC Sp_AmbulanceIncomeRptUser 1, '2022-12-01', '2022-12-28', '' */
SELECT a.RefDate, a.RefNo, a.RegNo, a.PatientId, a.BedNo, a.Mobile, a.PatientName, b.BedNo, b.Gender,
b.Age, b.DriverName, b.AmbulanceNo, b.DestinationFrom+' to '+b.DestinationTo AS Destination,
a.PtStatus, a.UserName, a.Remarks,
a.ReceiveAmt AS Advance, 0 AS DueColl, a.CashAmt, a.CardAmt, a.ChequeAmt
FROM AmbulanceLedger a
LEFT JOIN AmbulanceMaster b ON a.BranchId = b.BranchId AND a.PrevReceiptDate = b.ReceiptDate AND a.PrevReceiptNo = b.ReceiptNo
WHERE a.BranchId = @BranchId ANd a.Valid = 1 AND a.RefDate BETWEEN @DateFrom AND @DateTo ANd a.InputFrom = 'Sales' AND a.UserName LIKE '%'+@UserName+'%' AND a.PtStatus LIKE '%'+@PtStatus+'%'
ANd a.ReceiveAmt != 0 
UNION
SELECT a.RefDate, a.RefNo, a.RegNo, a.PatientId, a.BedNo, a.Mobile, a.PatientName, b.BedNo, b.Gender,
b.Age, b.DriverName, b.AmbulanceNo, b.DestinationFrom+' to '+b.DestinationTo AS Destination,
a.PtStatus, a.UserName, a.Remarks,
0 AS Advance, a.ReceiveAmt AS DueColl, a.CashAmt, a.CardAmt, a.ChequeAmt
FROM AmbulanceLedger a
LEFT JOIN AmbulanceMaster b ON a.BranchId = b.BranchId AND a.PrevReceiptDate = b.ReceiptDate AND a.PrevReceiptNo = b.ReceiptNo
WHERE a.BranchId = @BranchId ANd a.Valid = 1 AND a.RefDate BETWEEN @DateFrom AND @DateTo ANd a.InputFrom != 'Sales' AND a.UserName LIKE '%'+@UserName+'%' AND a.PtStatus LIKE '%'+@PtStatus+'%'
ANd a.ReceiveAmt != 0 
END
