CREATE PROC [dbo].[Sp_AmbulanceInvoiceHistory] @BranchId INT, @DateFrom VARCHAR(20), @DateTo VARCHAR(20), @PtStatus NVARCHAR(20)
AS
BEGIN /* EXEC Sp_AmbulanceInvoiceHistory 1, '2022-12-18', '2022-12-24' */
SELECT b.PtStatus, b.ReceiptDate, b.ReceiptNo, b.RegNo, b.PatientId, b.BedNo, b.Mobile, b.PatientName, b.Address, b.Gender, b.Age, 
b.DriverName, b.AmbulanceNo, UPPER(b.DestinationFrom + ' to ' + b.DestinationTo) AS Destination, b.Remarks, b.UserName,
SUM(a.TotalCharge) AS TotalCharge, SUM(a.Less) AS Less, SUM(a.ReceiveAmt) AS ReceiveAmt, SUM(a.CashAmt) AS CashAmt,
SUM(a.AdjustAmt) AS AdjustAmt, SUM(a.CardAmt) AS CardAmt, SUM(a.ChequeAmt) AS ChequeAmt,
SUM(a.TotalCharge-a.Less-a.ReceiveAmt-a.AdjustAmt) AS Due
FROM AmbulanceLedger a
LEFT JOIN AmbulanceMaster b ON a.BranchId = b.BranchId ANd a.PrevReceiptDate = b.ReceiptDate AND a.PrevReceiptNo=b.ReceiptNo
WHERE a.BranchId = @BranchId AND a.Valid = 1 AND b.ReceiptDate BETWEEN @DateFrom AND @DateTo AND b.PtStatus LIKE '%'+@PtStatus+'%'
GROUP BY b.PtStatus, b.ReceiptDate, b.ReceiptNo, b.RegNo, b.PatientId, b.BedNo, b.Mobile, b.PatientName, b.Address, b.Gender,
b.Age, b.DriverName, b.AmbulanceNo, UPPER(b.DestinationFrom + ' to ' + b.DestinationTo), b.Remarks, b.UserName
END
GO
