CREATE Procedure [dbo].[SP_AppoinmentReport_ALL] @BranchId int , @DateFrom date, @DateTo date, @DeptName nvarchar(50), @DrCode nvarchar(20), @PtType nvarchar(20), @DrType VARCHaR(50)
AS  --------- EXEC SP_AppoinmentReport_ALL 1, '2025-01-16', '2025-01-20','','', '', 'Rsef'
BEGIN
	Select a.AppDate, a.VisitDate, b.DrCode, b.DrName, a.PatientName, a.MobileNo, a.Dob, a.SlNo as AgeYear, a.Sex, a.UserName, a.EntryDate, b.DeptName,
	a.PtType as PtType, c.Name ShiftName, a.VisitAmt, a.VisitDesc, d.MRId, d.MRName, e.PatientAddress, e.CorporateId, '' AS CorporateName
	From PatientAppointment a
	Left join DrInfo b On (CASE WHEN @DrType='Ref' THEN a.RefDrCode ELSE a.DrCode END)=b.DrCode AND a.BranchId=b.BranchId AND a.Valid=1
	left join BaseTable c on a.ShiftTypeId=c.Id
	LEFT JOIN DrInfo d on a.BranchId=d.BranchId AND a.RefDrCode=d.DrCode
	LEFT JOIN PatientRegistration e on a.BranchId=e.BranchId AND a.RegNo=e.RegNo
	WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.VisitDate BETWEEN @DateFrom AND @DateTo 
	AND (CASE WHEN @DrType='Ref' THEN a.RefDrCode ELSE a.DrCode END) LIKE '%'+@DrCode+'%'
	AND (b.DeptName + PtType) LIKE '%'+@DeptName + '%'+ @PtType

	Order by a.SlNo ASC
END
GO
