CREATE PROCEDURE [dbo].[SP_Appointment_ChamberReportDatewise] @DateFrom DATE, @DateTo DATE, @BranchId INT
AS
BEGIN -- SP_Appointment_ChamberReportDatewise '2023-09-01', '2023-09-30', 1
	with GetDates As  
	(  
		select DATEADD(day, 0, @DateFrom) as TheDate
		UNION ALL  
		select DATEADD(day, 1, TheDate) from GetDates  
		where TheDate < @DateTo  
	) 
	SELECT TheDate, DATENAME(WEEKDAY, TheDate) AS DayName INTO #z FROM GetDates

	--  drop table #z

	SELECT d.DrCode, d.DrName+' '+d.Degree AS DrName, d.Speciality, d.DeptName, d.DrStatus, d.RoomNo, d.Tel, d.Email, d.DrDOB, d.PresentAdd, d.MRName, a.TheDate AS Date, a.DayName, 
	(CASE WHEN c.BranchId IS NULL THEN b.ChOpCl ELSE 'Leave' END) AS ChOpCl, b.StartTime, b.FinishingTime, b.Duration
	FROM #z a
	LEFT JOIN ChamberTimeDrWise b ON a.DayName = b.Day
	LEFT JOIN DrLeaveInfo c ON a.TheDate=c.LeaveFrom AND b.DrCode = c.DrCode AND c.BranchId = @BranchId
	LEFT JOIN DrInfo d ON b.DrCode = d.DrCode AND d.BranchId = @BranchId AND d.Status = 1
	WHERE d.DrCode IS NOT NULL
	ORDER BY b.DrCode, a.TheDate
END
GO
