CREATE PROC [dbo].[SP_AppointmentMoneyReciept](@MoneyreceipNo nvarchar(20), @VisitDate nvarchar(20), @DrCode nvarchar(20), @branchId int)
AS
BEGIN
	select ISNULL(b.RegNo,'') as RegNo, a.SlNo, a.AppDate, a.VisitDate, a.DrCode, a.DrName, a.PatientName, a.MobileNo, 
	(a.AgeYear+'Y '+a.AgeMonth+'M '+a.AgeDay+'D') AS FullAge, a.Sex as Gender, a.CollectBy AS UserName, a.VisitDesc, a.VisitAmtFor, a.VisitAmt, 
	a.PaymentNo, a.ArrivalBy, a.ArrivalTime, a.Address, a.RefDrCode, a.RefDrName
	from PatientAppointment a 
	left join PatientRegistration b on a.MobileNo = b.TelephoneNo and a.PatientName = b.PatientName AND a.BranchId = b.BranchId
	where a.IsArrival = 1 and a.Valid = 1 and a.PaymentNo = @MoneyreceipNo and a.VisitDate = @VisitDate and a.DrCode = @DrCode 
	AND a.BranchId = b.BranchId AND a.BranchId = @branchId
END
