CREATE Procedure [dbo].[SP_B2BClientChartInfo] @BranchId int, @ClientId nvarchar(20)
AS --- SP_B2BClientChartInfo 1, 'B0050'
BEGIN
select a.B2BCode as ClientId, b.DrName as ClientName, a.PCode, c.Description, a.B2BPrice, c.DeptName, c.SubDeptName, c.SubSubDeptName, a.EntryDateTime, a.UserName, c.Charge
From B2BPriceChart a 
Left join DrInfo b On a.B2BCode=b.DrCode AND DrType='B2B' AND Status=1 
AND a.BranchId=b.BranchId
Left join ClinicalChart c On a.PCode=c.PCode AND a.BranchId=c.BranchId
WHERE a.valid=1 AND a.BranchId=@BranchId AND a.B2BCode=@ClientId
END
