CREATE PROC [dbo].[SP_BedUpdate] @OldBedName VARCHaR(100), @NewBedName VARCHAR(100)
as
BEGIN
	update PatientAdmission set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update ChangeBedInfo set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update PatientLedger set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update TimeToTimeDuePayment set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update PatientReleaseMaster set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update PatientReleaseDetails set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update ProbablyPatientRelease set BedNo = @NewBedName WHERE BedNo = @OldBedName

	update PharSalesLedger set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update PharSalesMaster set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update PharSalesDetails set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update PharSalesReturnDetails set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update PharSalesReturnMaster set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update PharStockLedger set BedNo = @NewBedName WHERE BedNo = @OldBedName

	update SalesLedger set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update InvMaster set BedNo = @NewBedName WHERE BedNo = @OldBedName
	update InvDetails set BedNo = @NewBedName WHERE BedNo = @OldBedName
END
