CREATE PROC [dbo].[SP_BillDetails] (@PatientId nvarchar(20),@RegNo nvarchar(20))   AS
BEGIN

SELECT bb.UnderDrCode, bb.UnderDrName, bb.AdmissionDate, bb.AdmissionTime, bb.ReleaseDate, bb.EntryDateTime as ReleaseDateTime, 
bb.PatientName , bb.BedNo, bb.PatientAddress, bb.PatientAge, bb.RegNo, bb.PatientSex, bb.PatientTel, aa.*
FROM (
select a.RefNo, a.RefDate ,a.PatientId, a.Particulars Status, b.SubSubPno, a.Charge, a.NoU, 
a.ServiceCharge, a.Charge*a.NoU+a.ServiceCharge as TotalAmount, a.Less,
a.Charge*a.NoU+a.ServiceCharge-a.Less as NetTotalAmount, a.DrAmount
from PatientLedger a, BedInformation b, PatientRegistration c
where a.BedNo = b.BedNo and a.RegNo = c.RegNo and a.Valid = 1 And a.PatientId = @PatientId and a.RegNo = @RegNo
--and a.TotalAmount <> 0 and a.Status NOT IN ('Advance Collection', 'Patient Release')
group by a.RefNo, a.RefDate,a.PatientId, a.Particulars, b.SubSubPno, a.Charge, a.NoU, a.ServiceCharge, 
a.TotalAmount, a.Less, a.DrAmount, a.DrCode
UNION ALL
select '','', a.PatientId, UPPER(a.DeptName), b.SubSubPno, sum(a.Amount), 1, sum(a.ServiceCharge), sum((a.Amount*a.Quantity)+a.ServiceCharge), sum(a.Less1),
(sum(a.Amount*a.Quantity+a.ServiceCharge)-sum(a.Less1)) as NetTotalAmount, 0
from InvDetails a, BedInformation b
where a.Bedno = b.BedNo And a.Valid = 1 and a.PatientId = @PatientId and a.RegNo = @RegNo
group by a.PatientId, a.DeptName, a.RegNo, b.SubSubPno
--, a.Quantity
UNION ALL
select '', '', a.PatientId,'Medicine', b.SubSubPno, 0, 0, 0, sum(a.SalePrice*a.ProductQty) TotalAmount, 0, 
sum(a.SalePrice*a.ProductQty) NetTotalAmount, 0 from PharSalesDetails a, BedInformation b
where a.BedNo = b.BedNo And a.PatientId = @PatientId and a.RegNo = @RegNo
group by a.PatientId, a.RegNo, b.SubSubPno
) aa , PatientAdmission bb, PatientLedger dd
where aa.PatientId = bb.PatientId and bb.PatientId = dd.PatientId

group by bb.UnderDrCode, bb.UnderDrName, bb.AdmissionDate, bb.AdmissionTime, bb.ReleaseDate, bb.EntryDateTime, 
bb.PatientName , bb.BedNo, bb.PatientAddress, bb.PatientAge, bb.RegNo, bb.PatientSex, bb.PatientTel, aa.PatientId, aa.Status, aa.SubSubPno,
aa.Charge, aa.NoU, aa.RefNo, aa.RefDate,
aa.ServiceCharge, aa.TotalAmount, aa.Less,
aa.NetTotalAmount, aa.DrAmount

end





GO
