CREATE PROC [dbo].[SP_BloodTrunsfusion](@InvNo nvarchar(20), @InvDate nvarchar(20), @BranchId int, @UnitId int)
AS
BEGIN
select a.InvNo, a.Invdate, a.PatientId, a.BedNo, a.RegNo, a.PtStatus, a.PtnName, a.PtnAge, a.PtnSex, a.PtnBG, a.PtnRF, a.DnrName, a.DnrAge, a.DnrSex, a.DnrBG, a.DnrRF, a.DrCode, a.DrName, a.Comments, b.Parameter as TestName,
ISNULL([dbo].[fnc_CrossDefaultValue](b.Parameter),'') as DefaultValue, b.Result, a.UserName, a.BagNo,
a.LabInchargeName, isnull((Select TOP 1 Designation from LabSignatureDrInfo where Name = a.LabInchargeName),'') LabInchargeDegree, a.CheckedByName, 
isnull((Select TOP 1 Designation from LabSignatureDrInfo where Name = a.CheckedByName),'') as CheckedByDegree, a.SignatureDrName as ConsultantName, isnull((Select TOP 1 Designation from LabSignatureDrInfo where Name = a.SignatureDrName),'') ConsultantDegree from lab_CrossMatchingMaster a, lab_CrossMatchingDtls b
where a.BranchId = b.BranchId AND a.InvNo = b.InvNo and a.Invdate = b.InvDate and b.Result != '' and a.InvNo = @InvNo and a.Invdate = @InvDate AND a.BranchId = @BranchId

END
