CREATE PROC [dbo].[SP_CalculateDRHonorium_Summarized](@DateFrom date, @DateTo Date, @branchId int)
AS
BEGIN
select RefDrCode, DrName, Tel, SUM(TotalSales) as TotalSales, sum(LessAmt) LessAmt,SUM(PathCom+ElisaCom+USGCom+CTScanCom+XRayCom+BMDCom+ECGCom+ECHOCom+EEGCom
+ETTCom+MRICom+OTHERSCom) as TotalHonorarium,  sum(LessByDr) as DrLess,SUM(PathCom+ElisaCom+USGCom+CTScanCom+XRayCom+BMDCom+ECGCom+ECHOCom+EEGCom
+ETTCom+MRICom+OTHERSCom-LessByDr) as NetDrHonorarium from tmpDrCommForWeb WHERE BranchId = 1
--where InvDate BETWEEN @DateFrom and @DateTo
group by RefDrCode, DrName, Tel
Having SUM(PathCom+ElisaCom+USGCom+CTScanCom+XRayCom+BMDCom+ECGCom+ECHOCom+EEGCom
+ETTCom+MRICom+OTHERSCom-LessByDr) > 0
order by RefDrCode
END
GO
