CREATE Procedure [dbo].[SP_Canteen_CountedList_FoodItem_Report] @BranchId nvarchar(2), @DateFrom nvarchar(20), @DateTo nvarchar(20)
AS  --- Exec SP_Canteen_CountedList_FoodItem_Report 1,'2024-09-01','2024-09-30'
BEGIN
SELECT aa.ProductCode, aa.ProductName, sum(aa.SalesQty) as SalesQty, sum(aa.UnitPrice) as UnitPrice, sum(aa.SalesPrice) as SalesPrice, sum(aa.DueQty) as DueQty, sum(aa.DueUnitPrice) as DueUnitPrice, sum(aa.DuePrice) as DuePrice,
sum(aa.PaidQty) as PaidQty, sum(aa.PaidUnitPrice) as PaidUnitPrice, sum(aa.PaidPrice) as PaidPrice, (cc.Name) FoodCategory, bb.MealCategory
FROM  (
Select ProductCode, ProductName, sum(SalesQty) as SalesQty, SalePrice as UnitPrice, sum(SalePrice*SalesQty) as SalesPrice,
0 as DueQty, 0 as DueUnitPrice, 0 as DuePrice, 0 as PaidQty, 0 as PaidUnitPrice, 0 as PaidPrice
 From CanteenSalesDetails a left join CanteenSalesMaster b On a.InvoiceNo=b.InvoiceNo AND a.Valid=b.Valid AND a.BranchId=b.BranchId
WHERE a.Valid=1 AND a.BranchId=@BranchId  AND a.InvoiceDate Between @DateFrom AND @DateTo
GROUP BY ProductCode, ProductName,SalePrice
UNION ALL
Select ProductCode, ProductName, 0 as SalesQty, 0 as UnitPrice, 0 as SalesPrice,
 sum(SalesQty) as DueQty, SalePrice as DueUnitPrice, sum(SalePrice*SalesQty) as DuePrice, 0 as PaidQty, 0 as PaidUnitPrice,
 0 as PaidPrice
 From CanteenSalesDetails a left join CanteenSalesMaster b On a.InvoiceNo=b.InvoiceNo AND a.Valid=b.Valid AND a.BranchId=b.BranchId
WHERE a.Valid=1 AND a.BranchId=@BranchId  AND a.InvoiceDate Between @DateFrom AND @DateTo AND b.TotalCollection=0
GROUP BY ProductCode, ProductName, SalePrice
UNION ALL
Select ProductCode, ProductName, 0 as SalesQty, 0 as UnitPrice, 0 as SalesPrice,
 0 as DueQty, 0 as DueUnitPrice, 0 as DuePrice,
 sum(SalesQty) as PaidQty, SalePrice as PaidUnitPrice, sum(SalePrice*SalesQty) as PaidPrice
 From CanteenSalesDetails a left join CanteenSalesMaster b On a.InvoiceNo=b.InvoiceNo AND a.Valid=b.Valid AND a.BranchId=b.BranchId
WHERE a.Valid=1 AND a.BranchId=@BranchId  AND a.InvoiceDate Between @DateFrom AND @DateTo AND b.TotalCollection > 0
GROUP BY ProductCode, ProductName, SalePrice
) aa
left join CanteenProductSetup bb on aa.ProductCode = bb.Code
left join FoodCategory cc on bb.FoodCategoryId = cc.Id
GROUP BY aa.ProductCode, aa.ProductName, cc.Name, bb.MealCategory
ORDER BY ProductCode
END
GO
