CREATE Procedure [dbo].[SP_Canteen_CustomerWise_Details_Report] @BranchId int , @RegNo nvarchar(20), @customerType nvarchar(50) 
AS ---- EXEC SP_Canteen_CustomerWise_Details_Report 1, 'PR231101299'
BEGIN
SELECT aa.InvNo, aa.InvDate, aa.PatientId, aa.RegNo, aa.PatientName, aa.BedNo, aa.ProductName, aa.SalesQty, aa.RtnQty, aa.SalePrice, aa.TotalAmt, aa.ProReturnAmt, aa.CustomerType, aa.UserName, 
bb.GrandTotal, bb.VAT, bb.LessAmt, bb.PayableAmt,  bb.Collection,   bb.ReturnAmt, bb.CashReturn from
(
	select a.InvoiceNo as InvNo, a.InvoiceDate as InvDate,a.PatientId, a.RegNo, b.PatientName + CustomerName as PatientName, b.BedNo, a.ProductName,
	a.SalesQty as SalesQty, 0 as RtnQty, a.SalePrice, a.SalesQty * a.SalePrice as TotalAmt, 0 as ProReturnAmt,
	b.CustomerType, a.UserName
	from CanteenSalesDetails a
	left join CanteenSalesMaster b on a.InvoiceNo=b.InvoiceNo AND b.Valid = 1 AND a.BranchId=b.BranchId
	WHERE a.Valid = 1 AND b.BranchId = @BranchId AND b.CustomerType=@customerType AND (b.RegNo + b.PatientId) LIKE '%'+@RegNo +'%'

	UNION ALL
	select a.InvoiceNo as InvNo, a.InvoiceDate as InvDate,a.PatientId, a.RegNo, b.PatientName + CustomerName as PatientName, b.BedNo, a.ProductName,
	0 as SalesQty, a.ReturnQty as RtnQty, a.UnitSalesPrice,0 as TotalAmt, UnitSalesPrice * ReturnQty as ProReturnAmt,
	b.CustomerType, a.UserName
	from CanteenStockLedger a
	left join CanteenSalesLedger b on a.InvoiceNo=b.InvoiceNo AND b.Valid = 1 AND a.BranchId=b.BranchId
	WHERE a.Valid = 1 AND b.BranchId = 1 AND b.CustomerType=@customerType AND (b.RegNo + b.PatientId) LIKE '%'+@RegNo+'%'
) aa,
(
	SELECT PatientId,RegNo, SUM(GrandTotal) as GrandTotal, sum(TotalVAT) as VAT, sum(TotalPayableAmt) as PayableAmt, SUM(TotalCollection) AS Collection, 
	SUM(FixedLessAmt) + SUM(GeneralLessAmt) AS LessAmt,
	SUM(ReturnAmt) AS ReturnAmt, SUM(CashReturn) AS CashReturn
	FROM CanteenSalesLedger
	WHERE Valid = 1 AND BranchId = @BranchId  AND CustomerType=@customerType AND  (RegNo + PatientId) LIKE '%'+@RegNo +'%'
	GROUP BY PatientId, RegNo
) bb
WHERE aa.RegNo = bb.RegNo And aa.PatientId=bb.PatientId AND CustomerType=@customerType AND (aa.RegNo + aa.PatientId) LIKE '%'+@RegNo +'%'
ORDER BY InvNo
END
GO
