CREATE Procedure [dbo].[SP_Canteen_CustomerWise_Details_Report_DateRange] @BranchId int , @RegNo nvarchar(20), @DateFrom date, @DateTo date, @CustomerType nvarchar(20)
AS ----  EXEC SP_Canteen_CustomerWise_Details_Report_DateRange 1, 'PA230700118', '2023-07-01', '2023-07-31', ''
SELECT aa.InvNo, aa.InvDate, aa.PatientId, aa.RegNo, aa.PatientName, aa.BedNo, aa.ProductName, aa.SalesQty, aa.RtnQty, aa.SalePrice, aa.TotalAmt, aa.CustomerType, aa.UserName, 
bb.GrandTotal, bb.VAT, bb.LessAmt, bb.PayableAmt,  bb.Collection,   bb.ReturnAmt, bb.CashReturn from
(
select a.InvoiceNo as InvNo, a.InvoiceDate as InvDate,a.PatientId, a.RegNo, b.PatientName + CustomerName as PatientName, b.BedNo, a.ProductName,
a.SalesQty as SalesQty, 0 as RtnQty, a.SalePrice, a.SalesQty * a.SalePrice as TotalAmt,
b.CustomerType, a.UserName
from CanteenSalesDetails a
left join CanteenSalesMaster b on a.InvoiceNo=b.InvoiceNo AND b.Valid = 1 AND a.BranchId=b.BranchId
WHERE a.Valid = 1 AND b.BranchId = @BranchId AND (b.RegNo + b.PatientId) LIKE '%'+@RegNo +'%' AND b.InvoiceDate BETWEEN  @DateFrom AND  @DateTo AND CustomerType LIKE '%'+@CustomerType+'%'
) aa,
(
SELECT PatientId,RegNo, SUM(GrandTotal) as GrandTotal, sum(TotalVAT) as VAT, sum(TotalPayableAmt) as PayableAmt,  SUM(TotalCollection) AS Collection, SUM(FixedLessAmt) + SUM(GeneralLessAmt) AS LessAmt,
SUM(ReturnAmt) AS ReturnAmt, SUM(CashReturn) AS CashReturn
FROM CanteenSalesLedger
WHERE Valid = 1 AND BranchId = @BranchId  AND (RegNo + PatientId) LIKE '%'+@RegNo +'%' AND InvoiceDate BETWEEN  @DateFrom AND  @DateTo AND CustomerType LIKE '%'+@CustomerType+'%'
GROUP BY PatientId, RegNo
) bb
WHERE aa.RegNo = bb.RegNo And aa.PatientId=bb.PatientId AND (aa.RegNo + aa.PatientId) LIKE '%'+@RegNo +'%' AND aa.InvDate BETWEEN  @DateFrom AND  @DateTo AND aa.CustomerType LIKE '%'+@CustomerType+'%'
GO
