CREATE Procedure [dbo].[SP_Canteen_MealDistributed_Report_SMZ] @BranchId int , @dateFrom date, @dateTo date
AS
/* exec SP_Canteen_MealDistributed_Report_SMZ 1, '05-22-2023','05-23-2023' */
SELECT aa.TRDate, SUM(aa.Breakfast) as BreakfastQty, sum(aa.MorningSnacks) as MorningSnacksQty, sum(aa.Lunch) as LunchQty , sum(aa.EveningSnacks) as EveningSnacksQty,
sum(aa.Dinner) as DinnerQty, sum(aa.Seheri) as SeheriQty, sum(aa.Iftar) as IftarQty,
sum(aa.BreakfastAmount) as BreakfastAmt, sum(aa.MorningSnackAmt) as MorningSnacksAmt, SUM(aa.LunchAmt) as LunchAmt, sum(aa.EveningSnackAmt) as EveningSnackAmt,
sum(aa.DinnerAmt) as DinnerAmt, sum(aa.SeheriAmt) as SeheriAmt, SUM(aa.IftarAmt) as IftarAmt
 FROM (
Select TRDate, count(MealTypeId) as Breakfast, 0 as MorningSnacks, 0 as Lunch, 0 as EveningSnacks, 0 as Dinner, 0 as Seheri, 0 as Iftar, 0 as BreakfastAmount, 0 as MorningSnackAmt, 0 as LunchAmt , 0 as EveningSnackAmt, 0 as DinnerAmt, 0 as SeheriAmt, 0 as IftarAmt, Valid, BranchId 
FROM CanteenMealLedger
WHERE  Valid=1 AND MealTypeId=1 
group by TRDate, Valid, BranchId 
UNION All
Select TRDate, 0 as MealTypeId, count(MealTypeId) as MorningSnacks, 0 as Lunch, 0 as EveningSnacks,  0 as Dinner, 0 as Seheri, 0 as Iftar, 0 as BreakfastAmount, 0 as MorningSnackAmt, 0 as LunchAmt, 0 as EveningSnackAmt, 0 as DinnerAmt, 0 as SeheriAmt , 0 as IftarAmt, Valid, BranchId 
FROM CanteenMealLedger 
WHERE  Valid=1 AND MealTypeId=2
group by TRDate, Valid, BranchId 
UNION All
Select TRDate, 0 as Breakfast, 0 as MorningSnacks , count(MealTypeId) as Lunch,  0 as EveningSnacks,  0 as Dinner, 0 as Seheri, 0 as Iftar, 0 as BreakfastAmount, 0 as MorningSnackAmt, 0 as LunchAmt, 0 as EveningSnackAmt, 0 as DinnerAmt, 0 as SeheriAmt, 0 as IftarAmt, Valid, BranchId 
FROM CanteenMealLedger
WHERE  Valid=1 AND MealTypeId=3 
group by TRDate, Valid, BranchId 
UNION All
Select TRDate, 0 as Breakfast, 0 as MorningSnacks , 0 as Lunch, count(MealTypeId) as EveningSnacks,  0 as Dinner, 0 as Seheri, 0 as Iftar, 0 as BreakfastAmount, 0 as MorningSnackAmt, 0 as LunchAmt, 0 as EveningSnackAmt, 0 as DinnerAmt, 0 as SeheriAmt, 0 as IftarAmt, Valid, BranchId
FROM CanteenMealLedger 
WHERE  Valid=1 AND MealTypeId=4 
group by TRDate, Valid, BranchId 
UNION All
Select TRDate, 0 as Breakfast, 0 as MorningSnacks , 0 as Lunch, 0 as EveningSnacks, count(MealTypeId) as Dinner, 0 as Seheri, 0 as Iftar, 0 as BreakfastAmount, 0 as MorningSnackAmt, 0 as LunchAmt, 0 as EveningSnackAmt, 0 as DinnerAmt, 0 as SeheriAmt, 0 as IftarAmt, Valid, BranchId
FROM CanteenMealLedger 
WHERE  Valid=1 AND MealTypeId=5
group by TRDate, Valid, BranchId 
UNION All
Select TRDate, 0 as Breakfast, 0 as MorningSnacks , 0 as Lunch, 0 as EveningSnacks, 0 as Dinner, count(MealTypeId) as Seheri, 0 as Iftar,  0 as BreakfastAmount, 0 as MorningSnackAmt, 0 as LunchAmt, 0 as EveningSnackAmt, 0 as DinnerAmt, 0 as SeheriAmt, 0 as IftarAmt, Valid, BranchId
FROM CanteenMealLedger 
WHERE  Valid=1 AND MealTypeId=6
group by TRDate, Valid, BranchId 
UNION All
Select TRDate, 0 as Breakfast, 0 as MorningSnacks , 0 as Lunch, 0 as EveningSnacks, 0 as Dinner, 0 as Seheri, count(MealTypeId) as Iftar, 0 as BreakfastAmount, 0 as MorningSnackAmt, 0 as LunchAmt, 0 as EveningSnackAmt, 0 as DinnerAmt, 0 as SeheriAmt, 0 as IftarAmt, Valid, BranchId
FROM CanteenMealLedger
WHERE  Valid=1 AND MealTypeId=7
group by TRDate, Valid, BranchId 
UNION All
Select TRDate, 0 as Breakfast, 0 as MorningSnacks, 0 as Lunch,  0 as EveningSnacks,  0 as Dinner, 0 as Seheri, 0 as Iftar,  SalesAmt as BreakfastAmount, 0 as MorningSnackAmt, 0 as LunchAmt, 0 as EveningSnackAmt, 0 as DinnerAmt, 0 as SeheriAmt , 0 as IftarAmt, Valid, BranchId
From CanteenMealLedger
WHERE Valid=1 AND MealTypeId=1 
UNION All
SELECT TRDate ,0 as Breakfast, 0 as MorningSnacks, 0 as Lunch,  0 as EveningSnacks,  0 as Dinner, 0 as Seheri, 0 as Iftar,  0 as BreakfastAmount, SalesAmt as MorningSnackAmt ,0 as LunchAmt, 0 as EveningSnackAmt, 0 as DinnerAmt, 0 as SeheriAmt , 0 as IftarAmt, Valid, BranchId
FROM  CanteenMealLedger
WHERE Valid=1 AND MealTypeId=2 
UNION All
SELECT TRDate, 0 as Breakfast, 0 as MorningSnacks, 0 as Lunch,  0 as EveningSnacks,  0 as Dinner, 0 as Seheri, 0 as Iftar, 0 as BreakfastAmount, 0 as MorningSnackAmt , SalesAmt as LunchAmt, 0 as EveningSnackAmt, 0 as DinnerAmt, 0 as SeheriAmt , 0 as IftarAmt, Valid, BranchId
FROM CanteenMealLedger
WHERE Valid=1 AND MealTypeId=3 
UNION ALL
SELECT TRDate, 0 as Breakfast, 0 as MorningSnacks, 0 as Lunch,  0 as EveningSnacks,  0 as Dinner, 0 as Seheri, 0 as Iftar, 0 as BreakfastAmount, 0 as MorningSnackAmt , 0 as LunchAmt , SalesAmt as EveningSnackAmt, 0 as DinnerAmt, 0 as SeheriAmt , 0 as IftarAmt, Valid, BranchId
FROM CanteenMealLedger
WHERE Valid=1 AND MealTypeId=4 
UNION All
SELECT TRDate, 0 as Breakfast, 0 as MorningSnacks, 0 as Lunch,  0 as EveningSnacks,  0 as Dinner, 0 as Seheri, 0 as Iftar, 0 as BreakfastAmount, 0 as MorningSnackAmt , 0 as LunchAmt , 0 as EveningSnackAmt, SalesAmt as DinnerAmt, 0 as SeheriAmt , 0 as IftarAmt, Valid, BranchId
FROM CanteenMealLedger
WHERE Valid=1 AND MealTypeId=5
UNION All
SELECT TRDate, 0 as Breakfast, 0 as MorningSnacks, 0 as Lunch,  0 as EveningSnacks,  0 as Dinner, 0 as Seheri, 0 as Iftar, 0 as BreakfastAmount, 0 as MorningSnackAmt , 0 as LunchAmt , 0 as EveningSnackAmt, 0 as DinnerAmt, SalesAmt as SeheriAmt , 0 as IftarAmt, Valid, BranchId
FROM CanteenMealLedger
WHERE Valid=1 AND MealTypeId=6
UNION All
SELECT TRDate, 0 as Breakfast, 0 as MorningSnacks, 0 as Lunch,  0 as EveningSnacks,  0 as Dinner, 0 as Seheri, 0 as Iftar, 0 as BreakfastAmount, 0 as MorningSnackAmt , 0 as LunchAmt , 0 as EveningSnackAmt, 0 as DinnerAmt, 0 as SeheriAmt, SalesAmt as IftarAmt, Valid, BranchId
FROM CanteenMealLedger
WHERE Valid=1 AND MealTypeId=7
) aa 
WHERE aa.Valid=1 AND BranchId=@BranchId AND aa.TRDate Between @dateFrom AND @dateTo
GROUP BY aa.TRDate

---------------------------------------------------------------
GO
