CREATE PROCEDURE [dbo].[SP_Canteen_RawStockledgerSmz] (@datefrom date, @dateto date,@branchId int, @itemCode nvarchar(10))
AS
BEGIN -- exec SP_Canteen_RawStockledgerSmz '2025-05-01','2025-05-28',1,''
	SELECT aa.ItemCode , bb.ProductName ,  (CASE WHEN SUM(aa.CBQty) <> 0 THEN  SUM(aa.CBAmt) / SUM(aa.CBQty) END) AS UnitPrice,
	SUM(aa.OBQty) as OBQty , SUM(aa.OBAmt) as OBAmt, SUM(aa.InQty) as InQty ,SUM(aa.InAmt) as InAmt, SUM(aa.OutQty) as OutQty , SUM(aa.OutAmt) as OutAmt , SUM(aa.CBQty) as CBQty, SUM(aa.CBAmt) as CBAmt
	FROM (
	Select ItemCode , (InQty-OutQty) AS OBQty ,((InQty*UnitCostPrice) -(OutQty*UnitCostPrice)) AS OBAmt, 0 as InQty , 0 as InAmt ,0 as OutQty ,0 as OutAmt, 0 as CBQty , 0 as CBAmt
	From CanteenRawStockLedger
	where valid = 1 AND BranchId = @branchId 
	AND InvoiceDate < @datefrom 
	UNION ALL
	Select ItemCode , 0 AS OBQty ,0 AS OBAmt, InQty , (Inqty*UnitCostPrice) as InAmt ,OutQty ,(OutQty*UnitCostPrice) as OutAmt, 0 as CBQty , 0 as CBAmt
	From CanteenRawStockLedger
	where valid = 1 AND BranchId = @branchId 
	AND InvoiceDate between @datefrom AND @dateto 
	UNION ALL
	Select ItemCode , 0 AS OBQty ,0 AS OBAmt, 0 as InQty , 0 as InAmt ,0 as OutQty ,0 as OutAmt, (InQty-OutQty) as CBQty , ((InQty*UnitCostPrice) -(OutQty*UnitCostPrice)) as CBAmt
	From CanteenRawStockLedger
	where valid = 1 AND BranchId = @branchId 
	AND InvoiceDate <= @dateTo) aa , CanteenItemRegistration bb
	WHERE aa.ItemCode = bb.ProductCode
	AND (aa.ItemCode + ProductName ) LIKE '%'+@itemCode+'%'
	GROUP BY aa.ItemCode , bb.ProductName
	HAVING Sum(CBQty + CBAmt) !=0
END
GO
