CREATE PROCEDURE [dbo].[SP_Canteen_StockledgerDetails] (@datefrom date, @dateto date,@branchId int , @ItemCode nvarchar(10))
AS
BEGIN --EXEC SP_Canteen_StockledgerDetails '2023-01-01','2023-05-16',1 , '0001'
SELECT bb.MealCategoryId , bb.MealCategory , aa.InvoiceDate , aa.InvoiceNo , aa.PurchasePrice , aa.ItemCode , bb.ProductName ,  
--(CASE WHEN SUM(aa.CBAmt) > 0 THEN  SUM(aa.CBAmt) / SUM(aa.CBQty) END) AS UnitPrice,
SUM(aa.OBQty) as OBQty , SUM(aa.OBAmt) as OBAmt, SUM(aa.InQty) as InQty ,SUM(aa.InAmt) as InAmt, SUM(aa.OutQty) as OutQty , SUM(aa.OutAmt) as OutAmt , SUM(aa.CBQty) as CBQty, SUM(aa.CBAmt) as CBAmt , aa.ExpireDate 
FROM (
Select ItemCode , NULL as InvoiceDate , '' as InvoiceNo , 0 as UnitCostPrice , 0 as vat , 0 as PurchasePrice, (InQty-OutQty) AS OBQty ,((InQty*PurchasePrice) -(OutQty*PurchasePrice)) AS OBAmt, 0 as InQty , 0 as InAmt ,0 as OutQty ,0 as OutAmt, 0 as CBQty , 0 as CBAmt , ExpireDate 
From CanteenStockLedger
where valid = 1 
AND InvoiceDate < @datefrom  AND BranchId = @branchId AND ItemCode = @ItemCode 
UNION ALL
Select ItemCode ,InvoiceDate , InvoiceNo ,UnitCostPrice , vat , PurchasePrice ,   0 AS OBQty ,0 AS OBAmt, InQty , (Inqty*PurchasePrice) as InAmt ,OutQty ,(OutQty*PurchasePrice) as OutAmt, 0 as CBQty , 0 as CBAmt , ExpireDate 
From CanteenStockLedger
where valid = 1 
AND InvoiceDate between @datefrom AND @dateto  AND BranchId = @branchId AND ItemCode = @ItemCode 
UNION ALL
Select ItemCode , NULL as InvoiceDate , '' as InvoiceNo ,0 as UnitCostPrice , 0 as vat , 0 as PurchasePrice , 0 AS OBQty ,0 AS OBAmt, 0 as InQty , 0 as InAmt ,0 as OutQty ,0 as OutAmt, (InQty-OutQty) as CBQty , ((InQty*PurchasePrice) -(OutQty*PurchasePrice)) as CBAmt , ExpireDate
From CanteenStockLedger
where valid = 1 
AND InvoiceDate <= @dateTo AND BranchId = @branchId AND ItemCode = @ItemCode 
) aa , CanteenProductSetup bb
WHERE aa.ItemCode = bb.Code 
GROUP BY bb.MealCategoryId , bb.MealCategory,aa.ItemCode , bb.ProductName ,aa.InvoiceDate , aa.InvoiceNo , aa.PurchasePrice , aa.ItemCode , bb.ProductName , aa.ExpireDate 
ORDER BY aa.InvoiceNo, aa.InvoiceDate
END
