CREATE Procedure [dbo].[SP_CanteenCustomerWiseSMZRpt] @BranchId int, @RegNo nvarchar(20), @customerType nvarchar(50)
AS -- EXEC SP_CanteenCustomerWiseSMZRpt 1, 'PR230700262'
BEGIN
SELECT aa.InvoiceNo, aa.InvoiceDate, aa.Name, aa.PatientId, aa.RegNo, aa.CustomerType, aa.UserName, aa.GrandTotal, aa.TotalVAT, aa.TotalLess, aa.TotalPayableAmt, aa.TotalCollection,
 SUM(aa.DueLess) as DueLess, sum(aa.DueCollection) as DueCollection,   aa.PaymentStatus, aa.EntryDateTime  FROM 
 (
select a.InvoiceNo , a.InvoiceDate, (a.PatientName + a.CustomerName) as Name, a.PatientId, a.RegNo , a.CustomerType, a.UserName, a.GrandTotal, a.TotalVAT , 
(a.FixedLessAmt + a.GeneralLessAmt ) as TotalLess , a.TotalPayableAmt , a.TotalCollection, 0 as DueLess, 0 as DueCollection , '' as PaymentStatus, a.EntryDateTime
 FROM CanteenSalesLedger a
 WHERE a.Valid=1  AND a.BranchId=@BranchId AND a.CustomerType=@customerType  AND (a.RegNo + a.PatientId) LIKE '%'+@RegNo+'%' AND PaymentStatus !='Due Collection'
 UNION ALL
 select  a.InvoiceNo , a.InvoiceDate , (a.PatientName + a.CustomerName) as Name, a.PatientId, a.RegNo ,a.CustomerType, a.UserName,  a.GrandTotal,a.TotalVAT , 
 0 as TotalLess ,  a.TotalPayableAmt , 0 as  TotalCollection , 0 as DueLess, (a.TotalCollection) as DueCollection , a.PaymentStatus , a.EntryDateTime
 FROM CanteenSalesLedger a 
 WHERE a.Valid=1  AND a.BranchId=@BranchId AND a.CustomerType=@customerType AND (a.RegNo + a.PatientId) LIKE '%'+@RegNo+'%' AND PaymentStatus ='Due Collection'
 UNION ALL
 select  a.InvoiceNo ,a.InvoiceDate , (a.PatientName + a.CustomerName) as Name, a.PatientId, a.RegNo ,a.CustomerType, a.UserName,  a.GrandTotal, a.TotalVAT , 0 as TotalLess,
  a.TotalPayableAmt , 0 as  TotalCollection , (a.FixedLessAmt + a.GeneralLessAmt ) as DueLess , 0 as DueCollection ,  a.PaymentStatus, a.EntryDateTime
 FROM CanteenSalesLedger a 
  WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.CustomerType=@customerType AND (a.RegNo + a.PatientId) LIKE '%'+@RegNo+'%' AND PaymentStatus ='Due Collection'
  ) aa
  GROUP BY aa.InvoiceNo, aa.InvoiceDate, aa.Name, aa.PatientId, aa.RegNo, aa.CustomerType, aa.UserName, aa.GrandTotal, aa.TotalVAT,
  aa.TotalLess, aa.TotalPayableAmt, aa.TotalCollection, aa.PaymentStatus, aa.EntryDateTime
  ORDER BY aa.EntryDateTime
END
GO
