CREATE Procedure [dbo].[SP_CanteenDailySalesCustomerTypeWiseSMZ] @BranchId int , @DateFrom date , @DateTo date, @CustomerType nvarchar(20)
AS ----- EXEC SP_DailySalesCustomerTypeWiseSMZ 1, '2023-08-01', '2023-08-24', 'Outdoor'
BEGIN
SELECT aa.CustomerType, sum(aa.BreakfastQty) as BreakfastQty, sum(aa.BreakfastTotal) as BreakfastTotal, sum(aa.LunchQty) as LunchQty, sum(aa.LunchTotal) as LunchTotal,
sum(aa.EveningQty) as EveningQty, sum(aa.EveningTotal) as EveningTotal , sum(aa.DinnerQty) as DinnerQty , sum(aa.DinnerTotal) as DinnerTotal,
sum(aa.IftarQty) as IftarQty , sum(aa.IftarTotal) as IftarTotal, sum(aa.SehriQty) as SehriQty , sum(SehriTotal) as SehriTotal FROM 
(
select CustomerType, InvoiceDate, count(MealType) as BreakfastQty , sum(TotalPayableAmt) as BreakfastTotal , 0 as LunchQty, 0 as LunchTotal, 0 as EveningQty, 0 as EveningTotal,
 0 as DinnerQty, 0 as DinnerTotal,  0 as IftarQty, 0 as IftarTotal, 0 as SehriQty, 0 as SehriTotal
 From CanteenSalesLedger 
 WHERE MealType='Breakfast' AND Valid=1 AND BranchId=@BranchId  AND InvoiceDate Between @DateFrom AND @DateTo
 GROUP BY CustomerType, InvoiceDate
 UNION ALL 
 select CustomerType, InvoiceDate, 0 as BreakfastQty, 0 as BreakfastTotal, count(MealType) as LunchQty , sum(TotalPayableAmt) as LunchTotal, 0 as EveningQty, 0 as EveningTotal,
 0 as DinnerQty, 0 as DinnerTotal, 0 as IftarQty, 0 as IftarTotal, 0 as SehriQty, 0 as SehriTotal
 From CanteenSalesLedger 
 WHERE MealType='Lunch' AND Valid=1 AND BranchId=@BranchId  AND InvoiceDate Between @DateFrom AND @DateTo
 GROUP BY CustomerType, InvoiceDate
 UNION ALL
 select CustomerType, InvoiceDate, 0 as BreakfastQty, 0 as BreakfastTotal, 0 as LunchQty, 0 as LunchTotal, count(MealType) as EveningQty , sum(TotalPayableAmt) as EveningTotal,
 0 as DinnerQty, 0 as DinnerTotal,  0 as IftarQty, 0 as IftarTotal, 0 as SehriQty, 0 as SehriTotal
 From CanteenSalesLedger 
 WHERE MealType='Evening' AND Valid=1 AND BranchId=@BranchId  AND InvoiceDate Between @DateFrom AND @DateTo
 GROUP BY CustomerType, InvoiceDate
 UNION ALL
 select CustomerType, InvoiceDate, 0 as BreakfastQty, 0 as BreakfastTotal, 0 as LunchQty, 0 as LunchTotal, 0 as EveningQty, 0 as EveningTotal, count(MealType) as DinnerQty , sum(TotalPayableAmt) as DinnerTotal, 0 as IftarQty, 0 as IftarTotal, 0 as SehriQty, 0 as SehriTotal
 From CanteenSalesLedger 
 WHERE MealType='Dinner' AND Valid=1 AND BranchId=@BranchId  AND InvoiceDate Between @DateFrom AND @DateTo
 GROUP BY CustomerType, InvoiceDate
 UNION ALL
 select CustomerType, InvoiceDate, 0 as BreakfastQty, 0 as BreakfastTotal, 0 as LunchQty, 0 as LunchTotal, 0 as EveningQty, 0 as EveningTotal, 0 as DinnerQty, 0 as DinnerTotal, count(MealType) as IftarQty , sum(TotalPayableAmt) as IftarTotal , 0 as SehriQty, 0 as SehriTotal
 From CanteenSalesLedger 
 WHERE MealType='Iftar' AND Valid=1 AND BranchId=@BranchId  AND InvoiceDate Between @DateFrom AND @DateTo
 GROUP BY CustomerType, InvoiceDate
 UNION ALL
 select CustomerType, InvoiceDate, 0 as BreakfastQty, 0 as BreakfastTotal, 0 as LunchQty, 0 as LunchTotal, 0 as EveningQty, 0 as EveningTotal, 0 as DinnerQty, 0 as DinnerTotal,
 0 as IftarQty, 0 as  IftarTotal, count(MealType) as SehriQty , sum(TotalPayableAmt) as SehriTotal
 From CanteenSalesLedger 
 WHERE MealType='Sehri' AND Valid=1 AND BranchId=@BranchId AND InvoiceDate Between @DateFrom AND @DateTo
 GROUP BY CustomerType, InvoiceDate
 ) aa
 WHERE aa.InvoiceDate BETWEEN @DateFrom AND @DateTo AND CustomerType LIKE '%'+@CustomerType+'%'
 GROUP BY aa.CustomerType
 ORDER BY aa.CustomerType
 END
GO
