CREATE Procedure [dbo].[SP_CanteenDiscountReportDetails] @BranchId int, @DateFrom varchar(20), @DateTo varchar(20), @CustomerType nvarchar(20), @UserName nvarchar(20)
AS -----   Exec SP_CanteenDiscountReportDetails 1,'2023-01-01','2023-12-31','',''
SELECT aa.CustomerType, aa.UserName, aa.InvoiceNo, aa.InvoiceDate,  aa.PatientId, aa.RegNo, aa.Name,  sum(InvLess) as InvLess ,sum(DueLess) as DueLess, (sum(InvLess) + sum(DueLess)) as TotalLess   FROM 
(
select CustomerType, UserName, PatientId, RegNo,InvoiceNo, InvoiceDate, (CustomerName + PatientName) as Name ,sum(GeneralLessAmt) + sum(FixedLessAmt) as InvLess, 0 as DueLess
From CanteenSalesLedger  
where Valid=1 AND BranchId=1 AND InvoiceDate between @DateFrom AND  @DateTo AND PaymentStatus != 'Due Collection' AND (CustomerType + UserName) LIKE '%'+@CustomerType+'%' + @UserName
GROUP BY CustomerType, UserName , PatientId, RegNo,InvoiceNo, InvoiceDate,  CustomerType, CustomerName , PatientName
Having sum(GeneralLessAmt) + sum(FixedLessAmt) > 0
UNION ALL
select CustomerType, UserName, PatientId, RegNo, InvoiceNo, InvoiceDate, (CustomerName + PatientName) as Name ,  0 as InvLess,  sum(GeneralLessAmt) + sum(FixedLessAmt) as DueLess  From CanteenSalesLedger  
where Valid=1 AND BranchId=1 AND InvoiceDate between @DateFrom AND  @DateTo AND PaymentStatus = 'Due Collection' AND (CustomerType + UserName) LIKE '%'+@CustomerType+'%' + @UserName
GROUP BY CustomerType, UserName, PatientId, RegNo,InvoiceNo, InvoiceDate,  CustomerType,  CustomerName , PatientName
Having sum(GeneralLessAmt) + sum(FixedLessAmt) > 0
) aa
GROUP BY aa.CustomerType, aa.UserName, aa.PatientId, aa.RegNo, aa.InvoiceNo, aa.InvoiceDate, aa.Name
ORDER BY InvoiceDate, CustomerType, UserName, InvoiceNo
GO
