CREATE Procedure [dbo].[SP_CanteenDiscountReportSMZ] @BranchId int, @DateFrom varchar(20), @DateTo varchar(20), @CustomerType nvarchar(20), @UserName nvarchar(20)
AS --- Exec SP_CanteenDiscountReportSMZ 1,'2023-01-01','2023-12-31','',''
SELECT aa.CustomerType, aa.UserName, sum(InvLess) as InvLess ,sum(DueLess) as DueLess, (sum(InvLess) + sum(DueLess)) as TotalLess   FROM 
(
select  CustomerType, UserName, sum(GeneralLessAmt) + sum(FixedLessAmt) as InvLess, 0 as DueLess 
From CanteenSalesLedger  
where Valid=1 AND BranchId=@BranchId AND InvoiceDate between @DateFrom AND @DateTo AND PaymentStatus != 'Due Collection' AND (CustomerType + UserName)  LIKE '%'+@CustomerType+'%' +  @UserName
GROUP BY CustomerType, UserName, InvoiceDate
Having sum(GeneralLessAmt) + sum(FixedLessAmt) > 0
UNION ALL
select   CustomerType, UserName, 0 as InvLess,  sum(GeneralLessAmt) + sum(FixedLessAmt) as DueLess  From CanteenSalesLedger  
where Valid=1 AND BranchId=@BranchId AND InvoiceDate between @DateFrom AND @DateTo AND PaymentStatus = 'Due Collection' AND (CustomerType + UserName)  LIKE '%'+@CustomerType+'%' +  @UserName
GROUP BY CustomerType, UserName
Having sum(GeneralLessAmt) + sum(FixedLessAmt) > 0
) aa
GROUP BY aa.CustomerType, aa.UserName
GO
