CREATE Procedure [dbo].[SP_CanteenDueStatement] @branchId int, @dateFrom date, @dateTo date, @customerType nvarchar(20), @patientId nvarchar(20), @regNo nvarchar(20)
AS ----- EXEC SP_CanteenDueStatement 1,'', '', '', '', ''
   ----- EXEC SP_CanteenDueStatement 1,'2023-07-01', '2023-08-31', '', '', ''
if @dateFrom='' AND @dateTo=''
   BEGIN
       Select a.PatientId, a.RegNo, CASE WHEN CustomerType !='Indoor' THEN ISNULL(c.PatientName, '')  ELSE ISNULL(b.PatientName,'') END AS Name, 
       MobileNo, CustomerType,
       sum(GrandTotal) as GrandTotal, sum(FixedLessAmt) as Fixedless , sum(GeneralLessAmt) as GenLess,
       sum(TotalVAT) as Vat, sum(GrandTotal+TotalVAT-FixedLessAmt-GeneralLessAmt) As Payable, sum(TotalCollection) as Collection, 
       sum(GrandTotal+TotalVAT - FixedLessAmt - GeneralLessAmt - ReturnAmt - TotalCollection) AS Due
       From CanteenSalesLedger a left join PatientAdmission b On a.PatientId=b.PatientId AND a.Valid=1 AND a.BranchId=b.BranchId
       left join PatientRegistration c On a.RegNo=c.RegNo AND a.Valid=c.Valid AND a.BranchId=c.BranchId
       WHERE a.Valid=1 AND a.BranchId=@branchId AND a.CustomerType <> 'Outdoor'  
	   AND a.CustomerType LIKE '%'+@customerType AND a.PatientId LIKE '%'+@patientId+'%' AND a.RegNo LIKE +'%'+ @regNo+'%'
       GROUP BY a.PatientId, a.RegNo, b.PatientName, c.PatientName, a.MobileNo, a.CustomerType
       HAVING sum(GrandTotal+TotalVAT - FixedLessAmt - GeneralLessAmt - ReturnAmt - TotalCollection) > 0
       ORDER BY PatientId
   END
ELSE
   BEGIN
   Select a.PatientId, a.RegNo, CASE WHEN CustomerType !='Indoor' THEN ISNULL(c.PatientName, '')  ELSE ISNULL(b.PatientName,'') END AS Name, 
       MobileNo, CustomerType,
       sum(GrandTotal) as GrandTotal, sum(FixedLessAmt) as Fixedless , sum(GeneralLessAmt) as GenLess,
       sum(TotalVAT) as Vat, sum(GrandTotal+TotalVAT-FixedLessAmt-GeneralLessAmt) As Payable, sum(TotalCollection) as Collection, 
       sum(GrandTotal+TotalVAT - FixedLessAmt - GeneralLessAmt - ReturnAmt - TotalCollection) AS Due
       From CanteenSalesLedger a left join PatientAdmission b On a.PatientId=b.PatientId AND a.Valid=1 AND a.BranchId=b.BranchId
       left join PatientRegistration c On a.RegNo=c.RegNo AND a.Valid=c.Valid AND a.BranchId=c.BranchId
       WHERE a.Valid=1 AND a.BranchId=@branchId AND a.TrDate Between @dateFrom AND @dateTo AND  a.CustomerType <> 'Outdoor'  
	   AND a.CustomerType LIKE '%'+@customerType AND a.PatientId LIKE '%'+@patientId+'%' AND a.RegNo LIKE +'%'+ @regNo+'%'
       GROUP BY a.PatientId, a.RegNo, b.PatientName, c.PatientName, a.MobileNo, a.CustomerType
       HAVING sum(GrandTotal+TotalVAT - FixedLessAmt - GeneralLessAmt - ReturnAmt - TotalCollection) > 0
       ORDER BY PatientId
   END
GO
