CREATE Procedure [dbo].[SP_CanteenFoodSalesInvoice] @BranchId int , @InvoiceNo varchar(20), @InvoiceDate varchar(20)
AS /* exec SP_CanteenFoodSalesInvoice 1,'CAN2307200011','2023-07-20' */
BEGIN 
Select a.InvoiceNo, a.InvoiceDate,a.CustomerName+''+a.PatientName as Name, a.CustomerType, a.MobileNo, c.MealCategory, ISNULL(d.TableNo,'') AS TableNo, a.PatientId,
a.PatientName, a.RegNo, a.BedNo, a.DrCode, a.Phone, a.PackageCode, a.PackageName, a.MealType, a.GrandTotal, FixedLessAmt, GeneralLessAmt, TotalVAT,
a.TotalPayableAmt, a.TotalCollection, a.TotalDueAmt, a.CashAmt, a.CardAmt, a.ChequeAmt, a.CardNo, a.CardBank, 
a.ChequeNo, a.ChequeBank, a.ChequeDate, b.ProductCode, b.ProductName, b.CurrentQty, b.SalesQty, b.SalePrice,
b.TotalSalesPrice, b.ExpireDate, a.Remarks, a.UserName, a.EntryDateTime
 From CanteenSalesMaster a left join CanteenSalesDetails b On a.InvoiceNo=b.InvoiceNo AND a.BranchId=b.BranchId AND a.Valid=b.Valid left join
 CanteenMealCategory c On a.MealCategoryId= c.Id left join CanteenTableSetup d On a.TableId= d.Id AND a.BranchId=b.BranchId
WHERE a.Valid= 1 AND a.BranchId= @BranchId AND a.InvoiceNo=@InvoiceNo AND a.InvoiceDate= @InvoiceDate
END
