CREATE Procedure [dbo].[SP_CanteenIncomeReportUserWiseSMZ] @BranchId int ,@DateFrom varchar(20), @DateTo varchar(20), @CustomerType nvarchar(20), @UserName nvarchar(20)
AS
/* exec SP_CanteenIncomeReporUserWiseSMZ 1,'2023-06-01', '2023-06-30','',''  */
Select a.CustomerType, a.InvoiceDate, a.UserName, 
 sum(a.TotalCollection) as AdvanceCollection, sum(ISNULL(b.TotalReceive,0)) as DueCollection, 
(sum(ISNULL(a.CashAmt,0)) +  sum(ISNULL(b.CashAmount,0))) as CashAmt , 
(sum(ISNULL(a.CardAmt,0)) + sum(ISNULL(b.CardAmount,0))) as CardAmt, (Sum(ISNULL(a.ChequeAmt,0)) + Sum(ISNULL(b.ChequeAmount,0))) as ChequeAmt 
From CanteenSalesMaster a left join CanteenDueCollection b On a.InvoiceNo=b.SalesInvoiceNo AND a.BranchId=b.BranchId AND a.Valid=b.Valid
WHERE a.Valid=1 AND a.BranchId=@BranchId AND InvoiceDate between @DateFrom AND @DateTo AND a.CustomerType + a.UserName  LIKE '%'+@CustomerType+'%' + @UserName
GROUP BY a.CustomerType, a.InvoiceDate, a.UserName
Having  (sum(a.TotalCollection) + sum(ISNULL(b.TotalReceive,0))) > 0
Order BY InvoiceDate, CustomerType
GO
