CREATE Procedure [dbo].[SP_CanteenInvoiceHistoryReport] @BranchId int, @DateFrom date, @DateTo date, @customerType nvarchar(20), @patientId nvarchar(20), @regNo nvarchar(20) 
AS 
BEGIN
--- exec SP_CanteenInvoiceHistoryReport 1, '2023-08-01', '2023-08-31','','',''
Select ROW_NUMBER() Over(Partition By a.InvoiceDate Order BY a.InvoiceNo) as SlNo, a.InvoiceDate, a.InvoiceNo, a.PatientId, a.RegNo ,a.CustomerName+ a.PatientName as Name, a.MobileNo,
 CustomerType,
ISNULL(SUBSTRING((
SELECT DISTINCT ProductName+' ,'+SPACE(2) 
From CanteenSalesDetails 
where InvoiceNo = a.InvoiceNo and InvoiceDate = a.InvoiceDate AND Valid = 1  
FOR XML PATH('')), 1 , 1000),'') As ProductName, (a.GrandTotal + a.TotalVAT) AS GrandTotal, (a.FixedLessAmt + a.GeneralLessAmt) AS Less , TotalCollection as Collection, 
TotalDueAmt as TotalDue, a.Remarks, a.UserName
From CanteenSalesMaster a left join CanteenSalesDetails b On a.InvoiceNo=b.InvoiceNo
WHERE a.Valid=1 AND  a.BranchId=@BranchId AND a.InvoiceDate Between @DateFrom AND @DateTo AND a.CustomerType + a.PatientId + a.RegNo LIKE '%'+@customerType+'%'+ @patientId+'%'+ @regNo +'%'
GROUP BY a.InvoiceDate, a.InvoiceNo, a.PatientId, a.RegNo, a.CustomerName, a.PatientName, a.MobileNo, CustomerType, a.GrandTotal, a.TotalVAT, a.FixedLessAmt,
a.GeneralLessAmt, TotalCollection, TotalDueAmt, a.Remarks, a.UserName
END
GO
