CREATE PROCEDURE [dbo].[sp_CanteenMealDeptWise] (@dateFrom date , @dateTo date,@BranchId Int)
AS 
/* exec [sp_CanteenMealDeptWise] '2023-01-01' , '2023-12-31',1  */
BEGIN
	select TRDate,Category, MealType,1 as SlNo,'Qty' as Type,COUNT(MealType) as Total
	from CanteenMealLedger
	where valid = 1 
	and TRDate BETWEEN @dateFrom and @dateTo and BranchId = @BranchId 
	GROUP BY TRDate,MealType,Category
	UNION ALL
	select TRDate,Category,MealType,2 as slno ,'Amount' as Type,SUM(SalesAmt) AS Total
	from CanteenMealLedger
	where valid = 1 
	and TRDate BETWEEN @dateFrom and @dateTo and BranchId = @BranchId 
	GROUP BY TRDate,MealType,Category
	UNION ALL
	select  TRDate,'Total','Total',3 as slno,'Total Amount' as Type,SUM(SalesAmt) AS Total
	from CanteenMealLedger
	where valid = 1 
	and TRDate BETWEEN @dateFrom and @dateTo and BranchId = @BranchId 
	Group by TRDate
END

GO
