create procedure [dbo].[sp_CanteenMealDeptWiseForUI] (@dateFrom date,@dateTo date , @branchId int)
AS	-- EXEC sp_CanteenMealDeptWiseForUI '2023-01-01','2023-12-31',1
begin 
	Select 2 as slno,MealType, (space(5)+Category) as Category, count(MealType) as Qty, sum(SalesAmt) as Amount  
	From CanteenMealLedger
	where valid = 1 and TRDate between @dateFrom  and @dateTo and BranchId = @branchId 
	Group by MealType, Category
	Union All
	Select 10 as slno,'Total','Total', count(MealType) as Qty, sum(SalesAmt) as Amount  
	From CanteenMealLedger
	where valid = 1 and TRDate between @dateFrom  and @dateTo and BranchId = @branchId 
	UNION ALL
	Select 1 as slno,MealType, MealType as Category, count(MealType) as Qty, sum(SalesAmt) as Amount  
	From CanteenMealLedger
	where valid = 1 and TRDate between @dateFrom  and @dateTo and BranchId = @branchId 
	Group by MealType
	ORDER BY MealType , slno 
end

--------------------------------------------------------------------------
GO
