CREATE Procedure [dbo].[SP_CanteenMealDistribution_DeptWise_Report] @BranchId int , @DateFrom date, @DateTo date, @MealTypeId nvarchar(20)
AS
/* exec SP_CanteenMealDistribution_DeptWise_Report 1,'2023-05-23','2023-05-24','' */
Select aa.TRDate, ISNULL(sum(aa.Cabin),0) as CabinQty, sum(aa.Ward) as WardQty, sum(aa.ICU) as ICUQty, sum(aa.CCU) as CCUQty, sum(aa.HDU) as HDUQty,
sum(aa.NICU) as NICUQty , sum(aa.PICU) as PICUQty, sum(aa.Dialysis) as DialysisQty, sum(aa.CabinAmt) as CabinAmount, sum(aa.WardAmt) as WardAmount,
sum(aa.ICUAmt) as ICUAmount, sum(aa.CCUAmt) as CCUAmount, sum(aa.HDUAmt) as HDUAmount, sum(aa.NICUAmt) as NICUAmount, sum(aa.PICUAmt) as PICUAmount,
sum(aa.DialysisAmount) as DialysisAmount
FROM
(
Select TRDate, count(len( Category)) as Cabin , 0 as Ward , 0 as ICU , 0 as CCU, 0 as HDU,  0 as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt, 0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt,  0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
 FROM CanteenMealLedger
WHERE Category='Cabin' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate , 0 as Cabin, Count(len(Category)) as Ward ,0 as ICU, 0 as CCU, 0 as HDU, 0 as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt, 0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt,  0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE Category='Ward' AND Valid=1 
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate, 0 as Cabin, 0 as Ward , count(len(Category)) as ICU, 0 as CCU, 0 as HDU, 0 as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt, 0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt,  0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE Category='ICU'AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate, 0 as Cabin , 0 as Ward, 0 as ICU, count(len(Category)) as CCU, 0 as HDU, 0 as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt, 0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt,  0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE Category='CCU' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate, 0 as Cabin, 0 as Ward, 0 as ICU, 0 as CCU, count(len(Category)) as HDU, 0 as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt, 0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt, 0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger 
WHERE Category='HDU' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate, 0 as Cabin, 0 as Ward, 0 as ICU, 0 as CCU, 0 as HDU , count(len(Category)) as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt, 0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt, 0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE Category='NICU' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate, 0 as Cabin, 0 as Ward, 0 as ICU, 0 as CCU, 0 as HDU,  0 as NICU, count(len(Category)) as PICU, 0 as Dialysis, 0 as CabinAmt, 0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt, 0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE Category='PICU' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate,  0 as Cabin, 0 as Ward, 0 as ICU, 0 as CCU, 0 as HDU,  0 as NICU, 0 as PICU, count(len(Category)) as Dialysis, 0 as CabinAmt,0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt, 0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE  Category='Dialysis' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate,  0 as Cabin, 0 as Ward, 0 as ICU, 0 as CCU, 0 as HDU,  0 as NICU, 0 as PICU, 0 as Dialysis, sum(SalesAmt) as CabinAmt, 0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt, 0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE  Category='Cabin' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate,  0 as Cabin, 0 as Ward, 0 as ICU, 0 as CCU, 0 as HDU,  0 as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt , sum(SalesAmt) as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt, 0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE  Category='Ward' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate,  0 as Cabin, 0 as Ward, 0 as ICU, 0 as CCU, 0 as HDU,  0 as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt , 0 as WardAmt,
sum(SalesAmt) as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt,0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE  Category='ICU' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate,  0 as Cabin, 0 as Ward, 0 as ICU, 0 as CCU, 0 as HDU,  0 as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt , 0 as WardAmt,
0 as ICUAmt, sum(SalesAmt) as CCUAmt, 0 as HDUAmt, 0 as NICUAmt,  0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE  Category='CCU' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate,  0 as Cabin, 0 as Ward, 0 as ICU, 0 as CCU, 0 as HDU,  0 as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt , 0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, sum(SalesAmt) as HDUAmt, 0 as NICUAmt,  0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE  Category='HDU' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate,  0 as Cabin, 0 as Ward, 0 as ICU, 0 as CCU, 0 as HDU,  0 as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt , 0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, sum(SalesAmt) as NICUAmt, 0 as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE  Category='NICU' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate,  0 as Cabin, 0 as Ward, 0 as ICU, 0 as CCU, 0 as HDU,  0 as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt , 0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt, sum(SalesAmt) as PICUAmt, 0 as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE  Category='PICU' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
UNION All
Select TRDate,  0 as Cabin, 0 as Ward, 0 as ICU, 0 as CCU, 0 as HDU,  0 as NICU, 0 as PICU, 0 as Dialysis, 0 as CabinAmt , 0 as WardAmt,
0 as ICUAmt, 0 as CCUAmt, 0 as HDUAmt, 0 as NICUAmt, 0 as PICUAmt,  sum(SalesAmt) as DialysisAmount, Valid, BranchId, MealTypeId
FROM CanteenMealLedger
WHERE  Category='Dialysis' AND Valid=1
GROUP BY TRDate, Valid, BranchId, MealTypeId
) aa
WHERE  aa.Valid=1 AND aa.BranchId=@BranchId AND aa.TRDate BETWEEN @DateFrom AND @DateTo AND aa.MealTypeId LIKE '%'+@MealTypeId +'%'
GROUP BY TRDate
GO
