CREATE procedure [dbo].[sp_CanteenMealDistributionDtls] (@DateFrom date, @DateTo date, @BranchId int, @MealTypeAndCategory nvarchar(50) )
AS -- EXEC sp_CanteenMealDistributionDtls '2023-01-01','2023-12-31', 1, 'Breakfast'
BEGIN
select TRDate, TRNo, PatientId , PatientName , BedNo , SalesAmt , FoodMenu , ServeTime, TRTime as PostingTime , UserName as PostBy , Category , MealType 
from CanteenMealLedger 
where valid = 1  AND TRDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId
AND (MealType+Category) LIKE  '%'+@MealTypeAndCategory+'%'
order by trdate,trno 
END
GO
