CREATE PROCEDURE [dbo].[sp_CanteenMealTypeWise] (@dateFrom date , @dateTo date,@BranchId Int)
AS 
/* exec sp_CanteenMealTypeWise '2023-01-01' , '2023-12-31',1  */
BEGIN
	select TRDate,MealType,1 as SlNo,'Total Qty' as Type,COUNT(MealType) as Total
	from CanteenMealLedger
	where valid = 1 
	and TRDate BETWEEN @dateFrom and @dateTo and BranchId = @BranchId 
	GROUP BY TRDate,MealType
	UNION ALL
	select TRDate,MealType,2 as slno ,'Total Amount' as Type,SUM(SalesAmt) AS Total
	from CanteenMealLedger
	where valid = 1 
	and TRDate BETWEEN @dateFrom and @dateTo and BranchId = @BranchId 
	GROUP BY TRDate,MealType
	UNION ALL
	select TRDate,'Total',3 as slno,'Total(Tk)' as Type,SUM(SalesAmt) AS Total
	from CanteenMealLedger
	where valid = 1 
	and TRDate BETWEEN @dateFrom and @dateTo and BranchId = @BranchId 
	Group By TRDate
END

