CREATE Procedure [dbo].[sp_CanteenMealTypeWiseForUI]  (@Datefrom date, @DateTo date, @BranchId int )
AS
-- exec sp_CanteenMealTypeWiseForUI '2023-01-01', '2023-12-31', 1
BEGIN
select 1 as Sl,  MealType ,count(MealType) as Qty, 
sum(SalesAmt) as Amount 
From CanteenMealLedger
where Valid=1 And TRDate Between @Datefrom AND @DateTo AND BranchId=@BranchId
group by  MealType
Union All
select 2, 'Total' ,count(MealType) as Qty, 
ISNULL(sum(SalesAmt),0) as Amount From CanteenMealLedger
where Valid=1 And TRDate Between  @Datefrom AND @DateTo AND BranchId=@BranchId
order by Sl,MealType
END
GO
