CREATE Procedure [dbo].[SP_CanteenPivotDynamicTable]  @BranchId varchar(2), @DateFrom Varchar(20), @DateTo Varchar(20)
AS
/* Exec SP_PivotDynamicTable '1','2023-05-23', '2023-05-25' */
begin
DECLARE @cols  AS NVARCHAR(MAX)='';
DECLARE @query AS NVARCHAR(MAX)='';
SELECT @cols = @cols + QUOTENAME(MealType) + ',' FROM (select distinct MealType from CanteenMealLedger WHERE Valid=1 AND BranchId=@BranchId AND TRDate BETWEEN @DateFrom AND @DateTo ) as tmp
select @cols = substring(@cols, 0, len(@cols)) --trim "," at end
set @query = 
'SELECT *  from 
(
	select TrDate,MealType, MealTypeId  from CanteenMealLedger where Valid=1 AND BranchId=''' + @BranchId + ''' AND TRDate  BETWEEN (''' + @DateFrom + ''') AND (''' + @DateTo+''') 
) src
pivot 
(
    count(MealTypeId) for MealType in (' + @cols + ')
) piv'

execute(@query) 
END
GO
