CREATE ProceDure [dbo].[SP_CanteenProductInfo] @BranchId int
AS -- EXEC SP_CanteenProductInfo 1
BEGIN
Select a.Id, a.MealCategoryId , a.MealCategory, a.Code, a.ProductName, a.CostPrice, a.SalesAmt, a.VAT, a.UserName, a.PostingDateTime, a. BranchId, (b.Name) as FoodCategory
