CREATE PROCEDURE [dbo].[SP_CanteenProductRefundInvoice] @BranchId int, @RefundNo nvarchar(20), @RefundDate date
AS  ---  EXEC SP_CanteenProductRefundInvoice 1, 'CPR240100001', '2024-01-11'
BEGIN
Select a.RefundNo, a.RefundDate, a.SalesInvNo, a.SalesInvDate,
a.CustomerType, a.PatientId, a.PatientRegNo, a.CustomerName, a.MealType,
a.UserName, a.EntryDateTime, a.PayableAmt, a.PaidAmt,  a.ReturnAmt as TotalReturn,
b.ProductCode, c.ProductName, b.UnitPrice, b.ReturnQty, b.ReturnAmt 
From CanteenProductRefundMaster a
left join CanteenProductRefundDetails b On a.RefundNo=b.RefundNo AND a.SalesInvNo=b.SalesInvNo AND a.BranchId=b.BranchId AND 
a.UnitId=b.UnitId AND a.Valid=b.Valid
left join CanteenProductSetup c On b.ProductCode=c.Code 
WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.RefundNo = @RefundNo AND a.RefundDate=@RefundDate
END
GO
