Create Procedure [dbo].[SP_CanteenPurchasePaymentInvoice] @BranchId int , @refNo nvarchar(20), @refDate date
AS ----- EXEC SP_CanteenPurchasePaymentInvoice 1, 'CP250700277', '2025-07-22'
BEGIN 
	select a.RefNo, a.RefDate, a.SupplierId CompanyID, b.Name, a.PINo, a.PIDate, (a.LessAmount) as Less,
	(a.PaymentAmount) as PaymentAmt, a.UserName, a.EntryDateTime AS EntryTime, (a.VatAmt) As VatAmt, 
	(a.AITAmt) As AITAmt, (a.AdjustAmt) As AdjustAmt
	From CanteenPurchaseLedger a 
	left join CanteenSupplierInfo b On a.SupplierId=b.SupplierId AND a.Valid=b.Valid
	WHERE a.Valid=1 AND a.BranchId=@BranchId AND RefNo=@refNo AND RefDate =@refDate
