Create PROC [dbo].[SP_CanteenRawMaterialsDateWise] (@StoreName NVARCHAR(50), @DateFrom NVARCHAR(10) = NULL, @DateTo NVARCHAR(10) = NULL, @UnitId INT, @BranchId INT, @ProductCategory NVARCHAR(50) = NULL, @ProductCode NVARCHAR(20) = NULL)
AS --- EXEC SP_CanteenRawMaterialsDateWise 'Canteen','2024-10-10' , '2024-10-14' , 1 , 1, '',''
BEGIN
DECLARE @StartDate DATE = CASE WHEN ISNULL(@DateFrom, '') = '' THEN NULL ELSE CAST(@DateFrom AS DATE) END;
DECLARE @EndDate DATE = CASE WHEN ISNULL(@DateTo, '') = '' THEN NULL ELSE CAST(@DateTo AS DATE) END;
select a.RRNo, a.RRDate, a.InvoiceNo, a.InvoiceDate, a.SupplierId, a.SupplierName, a.NetPrice AS TotalAmt from CanteenPurchaseReceivingDetails a
LEFT JOIN CanteenItemRegistration b ON a.ProductCode = b.ProductCode AND a.Valid = b.Valid
WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.UnitId = @UnitId AND (@StartDate IS NULL OR @EndDate IS NULL OR a.RRDate BETWEEN @StartDate AND @EndDate) AND b.StoreName = @StoreName AND (@ProductCategory IS NULL OR b.ProductCategory LIKE '%' + @ProductCategory + '%') AND (@ProductCode IS NULL OR a.ProductCode LIKE '%' + @ProductCode + '%')
END
GO
