CREATE PROC [dbo].[SP_CanteenRawMaterialsIssueRpt] (@StoreName NVARCHAR(50), @DateFrom NVARCHAR(10) = NULL, @DateTo NVARCHAR(10) = NULL, @UnitId INT, @BranchId INT, @ProductCategory NVARCHAR(50) = NULL, @ProductCode NVARCHAR(20) = NULL, @IssueDept NVARCHAR(20) = NULL)
AS --- EXEC SP_CanteenRawMaterialsIssueRpt 'Canteen','' , '' , 1 , 1, '','',''
BEGIN
DECLARE @StartDate DATE = CASE WHEN ISNULL(@DateFrom, '') = '' THEN NULL ELSE CAST(@DateFrom AS DATE) END;
DECLARE @EndDate DATE = CASE WHEN ISNULL(@DateTo, '') = '' THEN NULL ELSE CAST(@DateTo AS DATE) END;
select a.IssueNo, a.IssueDate, a.IssueDept, a.Store, a.ProductCode, a.ProductName, a.Unit, a.Price, (a.CurrQty) as Qty,  a.CurrUnit, a.IssueUnit, a.IssueQty, sum(a.CurrQty - a.IssueQty) as CurrQty, a.UserName, a.EntryDateTime from CanteenRawMaterialsIssue a
LEFT JOIN CanteenItemRegistration b ON a.ProductCode = b.ProductCode AND a.Valid = b.Valid
where a.Valid = 1  AND a.BranchId = @BranchId AND a.UnitId = @UnitId AND (@StartDate IS NULL OR @EndDate IS NULL OR a.IssueDate BETWEEN @StartDate AND @EndDate) AND a.Store = @StoreName AND (@ProductCategory IS NULL OR b.ProductCategory LIKE '%' + @ProductCategory + '%')AND (@ProductCode IS NULL OR a.ProductCode LIKE '%' + @ProductCode + '%') AND (@IssueDept IS NULL OR a.IssueDept LIKE '%'+@IssueDept+'%')
group by a.IssueNo, a.IssueDate, a.IssueDept, a.Store, a.ProductCode, a.ProductName, a.Unit, a.Price, a.CurrQty, a.CurrUnit, a.IssueUnit, a.IssueQty, a.UserName, a.EntryDateTime
--HAVING sum(a.CurrQty - a.IssueQty) <> 0
END
GO
