CREATE PROC [dbo].[SP_CanteenRawMaterialsReceive](@GrnNo nvarchar(50), @GrnDate date, @UnitId int, @BranchId int)
AS
BEGIN /* SP_CanteenRawMaterialsReceive  'RR240900001', '2024-09-29', 1, 1 */
SELECT a.RRNo, a.RRDate, a.InvoiceNo, a.InvoiceDate, a.SupplierName, a.StoreName, b.ProductCode, b.ProductName, 
b.Unit, b.Price, b.Qty, b.Total, b.VatAmount, b.DiscountAmount, b.NetPrice, ISNULL(b.ExpDate, '') AS ExpDate, 
a.UserName, a.Note, a.ServiceChargeAmt, a.LabourChargeAmt, a.CarringChargeAmt, a.MiscellaneousChargeAmt, a.TotalNetPrice, a.EntryDateTime
