Create PROC [dbo].[SP_CanteenRawMaterialsSummary]
(@StoreName NVARCHAR(50), @DateFrom NVARCHAR(10) = NULL, @DateTo NVARCHAR(10) = NULL, @UnitId INT, @BranchId INT, @ProductCategory NVARCHAR(50) = NULL, @ProductCode NVARCHAR(20) = NULL)
as 
begin
select a.ItemCode, b.ProductName, b.Unit, 'Canteen' AS storeName, 
b.ProductCategory, sum(a.InQty-a.OutQty+a.BonusQty) as OpeningQty, 0 as ReeiveQty, 0 as IssueQty, AVG(a.TotalPurchasePrice) AS TotalPurchasePrice
from CanteenRawStockLedger a,CanteenItemRegistration b 
where a.ItemCode=b.ProductCode AND a.Valid = 1 and a.BranchId = @BranchId
AND a.TrDate<@DateFrom and a.UnitId = @UnitId 
AND (@ProductCategory='' OR b.ProductCategory = @ProductCategory) AND (@ProductCode='' OR a.ItemCode = @ProductCode )
group by a.ItemCode, b.ProductName, b.Unit, b.storeName, b.ProductCategory
UNION
select a.ItemCode, b.ProductName, b.Unit, 'Canteen' AS storeName, 
b.ProductCategory, 0 as OpeningQty, sum(a.InQty) as ReeiveQty, sum(a.OutQty) as IssueQty,  a.TotalPurchasePrice 
from CanteenRawStockLedger a,CanteenItemRegistration b 
where a.ItemCode=b.ProductCode AND a.Valid = 1 and a.BranchId = @BranchId
AND a.TrDate BETWEEN @DateFrom AND @DateTo  and a.UnitId = @UnitId 
AND (@ProductCategory='' OR b.ProductCategory = @ProductCategory) AND (@ProductCode='' OR a.ItemCode = @ProductCode )
group by a.ItemCode, b.ProductName, b.Unit, b.storeName, b.ProductCategory, a.TotalPurchasePrice
end
GO
