CREATE Procedure [dbo].[SP_CanteenSalesReporSMZ] @BranchId int ,@DateFrom varchar(20), @DateTo varchar(20), @CustomerType nvarchar(20)
AS 
/* exec SP_CanteenSalesReporSMZ 1,'2023-06-01', '2023-06-30',''  */
Select CustomerType, InvoiceDate, sum(GrandTotal) as GrandTotal, sum(TotalVAT) as TotalVAT, sum(FixedLessAmt) + sum(GeneralLessAmt) as TotalLessAmt , 
sum(TotalPayableAmt) as TotalPayableAmt, sum(TotalCollection) as TotalCollection, sum(TotalDueAmt) as TotalDueAmt, sum(CashAmt) as CashAmt, sum(CardAmt) as CardAmt, sum(ChequeAmt) as ChequeAmt  From CanteenSalesMaster 
WHERE Valid=1 AND BranchId=@BranchId AND InvoiceDate Between @DateFrom AND @DateTo AND CustomerType LIKE '%'+@CustomerType+'%'
GROUP BY CustomerType, InvoiceDate
ORDER BY  InvoiceDate, CustomerType
GO
