CREATE Procedure [dbo].[SP_CanteenWasteFoodClearDtlsReport] @BranchId int , @DateFrom date, @DateTo date, @mealCategoryId nvarchar(2)
AS --- SP_CanteenWasteFoodClearDtlsReport 1,'2023-07-25', '2023-07-25',''
select b.ExpireDate, a.MealCategoryId,  d.MealCategory, a.InvoiceDate, b.ItemCode, b.ItemName, sum(c.InQty) as InQty , b.CurrentQty,
 b.WasteQty, a.UserName, a.EntryDateTime
from CanteenWasteFoodClearMaster a 
left join CanteenWasteFoodClearDtls b On a.InvoiceNo=b.InvoiceNo AND a.BranchId=b.BranchId AND a.Valid=b.Valid 
left join CanteenStockLedger c On b.ItemCode=c.ItemCode AND b.Valid=c.Valid AND b.BranchId=c.BranchId AND b.ExpireDate=c.ExpireDate
left join CanteenMealCategory d On a.MealCategoryId=d.Id AND a.Valid=d.Valid 
Where a.Valid=1 AND a.BranchId=@BranchId AND b.InvoiceDate Between @DateFrom AND @DateTo AND a.MealCategoryId LIKE '%'+@mealCategoryId+'%'
GROUP BY  b.ExpireDate, a.MealCategoryId, d.MealCategory, a.InvoiceDate, b.ItemCode, b.ItemName, b.CurrentQty,
b.WasteQty , a.UserName, a.EntryDateTime
ORDER BY  b.ExpireDate, a.MealCategoryId
GO
