select a.MealCategoryId, b.MealCategory, sum(TotalQty) as  WasteFoodQty , sum(TotalAmount) as WasteFoodAmount From CanteenWasteFoodClearMaster a left join CanteenMealCategory b On a.MealCategoryId=b.Id
