CREATE Procedure [dbo].[SP_CanteenWasteFoodClearSMZReport] @BranchId int , @DateFrom date, @DateTo date, @MealCatagoryId nvarchar(2)
AS ---- Exec SP_CanteenWasteFoodClearSMZReport 1, '2023-07-01', '2023-07-31',''
SELECT  a.MealCatagoryId , b.MealCategory, sum(a.StockInQty) as TotalStockQty, sum(a.SalesQty) TotalSalesQty , sum(a.StockInQty) -  sum(a.SalesQty) as CurrentQty,  sum(a.WasteQty) as TotalWasteQty FROM
(
select  MealCatagoryId ,sum(InQty) as StockInQty, 0 as SalesQty, 0 as  WasteQty, Valid, BranchId 
From CanteenStockLedger 
where Valid=1 AND BranchId=@BranchId AND Status='IN' AND MealCatagoryId LIKE '%'+@MealCatagoryId+'%'
GROUP BY MealCatagoryId, Valid , BranchId , InvoiceDate
UNION ALL
select  MealCatagoryId, 0 as  StockInQty, sum(OutQty) as SalesQty, 0 as  WasteQty, Valid, BranchId From CanteenStockLedger 
where Valid=1 AND BranchId=@BranchId AND Status='OUT' AND InvoiceDate BETWEEN @DateFrom AND @DateTo AND  MealCatagoryId LIKE '%'+@MealCatagoryId+'%'
GROUP BY MealCatagoryId, Valid , BranchId , InvoiceDate 
UNION All
select MealCatagoryId,  0 as  StockInQty, 0 as SalesQty , SUM(OutQty) as WasteQty, Valid, BranchId From CanteenStockLedger
where Valid=1 AND BranchId=@BranchId AND Status='Waste' AND InvoiceDate BETWEEN @DateFrom AND @DateTo AND MealCatagoryId LIKE '%'+@MealCatagoryId+'%'
GROUP BY MealCatagoryId , Valid , BranchId , InvoiceDate
) a left join CanteenMealCategory b On a.MealCatagoryId=b.Id AND a.Valid=b.Valid
WHERE a.Valid=1 AND a.BranchId=@BranchId
GROUP BY  a.MealCatagoryId , b.MealCategory
ORDER BY a.MealCatagoryId
GO
