CREATE PROC [dbo].[Sp_ChamberTime] @BranchId INT, @DrCode VARCHAR(50)
AS
BEGIN --  Sp_ChamberTime 1, 0028
	SELECT a.DrCode, b.DrName+b.Degree AS DrName, b.Tel, b.DrVisitNew, b.DrVisitOld, b.DeptName, a.Day AS DaysName, a.StartTime, a.FinishingTime, a.Duration, a.UserName
	FROM ChamberTimeDrWise a 
	LEFT JOIN DrInfo b ON b.BranchId = a.BranchId AND b.DrCode = a.DrCode
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.DrCode = @DrCode
END
