--13122023
CREATE PROC [dbo].[Sp_ChangedBedInfo] @Id INT
AS
BEGIN /* Sp_ChangedBedInfo 80 */
	select a.id, a.BedCharge, a.BedNo, a.PrevBed, a.Days, a.EntryDateTime, a.UserName, CONVERT(varchar(50), a.ReleaseDate)+a.ChangedTime ChangedTime, b.RegNo, 
	b.PatientName, b.PatientId, b.PatientSex, b.PatientTel, b.PatientAge, b.PatientAddress, c.SubSubPno AS CurrDept, c.FloorNo as CurrFloor, d.SubSubPno AS PrevDept, 
	d.FloorNo AS PrevFloor, e.DrCode, e.DrName+e.Degree AS Drname, f.DrCode AS UdnerDrCode, f.DrName+f.Degree AS UnderDrName
	from ChangeBedInfo a
	left join PatientAdmission b on b.BranchId = a.BranchId and b.PatientId = a.PatientId
	left join BedInformation c on c.BranchId = a.BranchId and c.BedNo = a.BedNo
	left join BedInformation d on d.BranchId = a.BranchId and d.BedNo = a.PrevBed
	left join DrInfo e on e.BranchId = a.BranchId and e.DrCode = b.DrCode
	left join DrInfo f on f.BranchId = a.BranchId and f.DrCode = b.UnderDrCode
	where a.Id = 80
END
GO
