Create PROCEDURE [dbo].[SP_Collection_RPT_UserWise_DeptWise_Details](@DateFrom Date,@DateTo Date,@UserName nvarchar(50), @DeptName nvarchar(50)) AS 
IF @UserName = '' 
	BEGIN
		select Username,Department,Refdate,RefNo,PreInvDate AS InvDate,PrevInvNo AS InvNo,Particulars,Collection AS Advance,0 as DueColl ,ByCash , ByCard , ChequeAmount ,(ByCash+ByCard+ChequeAmount) AS TotalColl, PostingDateTime
		from SalesLedger 
		where valid = 1 and refdate BETWEEN @DateFrom and @DateTo 
		and PreInvDate BETWEEN @DateFrom and @DateTo 
		and Collection <> 0 AND Department = @DeptName
		UNION ALL
		select Username,Department,Refdate,RefNo,PreInvDate AS InvDate,PrevInvNo,Particulars,0 AS Advance,Collection as				DueColl  ,
		ByCash , ByCard , ChequeAmount ,(ByCash+ByCard+ChequeAmount) AS TotalColl, PostingDateTime
		from SalesLedger 
		where valid = 1 and refdate BETWEEN @DateFrom and @DateTo 
		and PreInvDate NOT BETWEEN @DateFrom and @DateTo 
		and Collection <> 0 AND Department = @DeptName
		UNION ALL
		select UserName,'INDOOR',PaymentDate,ReceiptNo,RefDate ,RefNo,PatientId + '-'+PatientName+BedNo,					 
		ReceiveAmt,0,CashAmt,CardAmt ,ChequeAmt,(CashAmt+CardAmt+ChequeAmt) as Total, EntryDateTime
		from TimeToTimeDuePayment  
		where valid = 1 and ReceiveAmt <> 0
		and PaymentDate BETWEEN @DateFrom and @DateTo AND 'INDOOR' = @DeptName
		UNION ALL
		select UserName,'INDOOR',ReceiptDate ,ReceiptNo,ReceiptDate ,ReceiptNo,PatientId + '-'+ PatientName,
		0,CollAmt,CashAmt,CardAmt ,ChequeAmt,(CashAmt+CardAmt+ChequeAmt) as Total, EntryDateTime
		from PatientSettlementDetails  
		where valid = 1 and CollAmt <> 0
		and ReceiptDate BETWEEN @DateFrom and @DateTo 
		and valid = 1 AND 'INDOOR' = @DeptName
		UNION ALL
		select UserName,'PHARMACY',TRDate ,TRNO,InvDate ,InvNo,PatientId + '-'+ PatientName,
		Collection,0,CashAmt,CardAmt ,ChequeAmt,(CashAmt+CardAmt+ChequeAmt) as Total, EntryDateTime
		from PharSalesLedger  
		where valid = 1 and Collection <> 0
		and TrDate BETWEEN @DateFrom and @DateTo 
		and valid = 1 AND 'PHARMACY' = @DeptName
	END
ELSE
	BEGIN
		select Username,Department,Refdate,RefNo,PreInvDate AS InvDate,PrevInvNo AS InvNo,Particulars,Collection AS Advance,0		as	DueColl ,ByCash , ByCard , ChequeAmount ,(ByCash+ByCard+ChequeAmount) AS TotalColl, PostingDateTime
		from SalesLedger 
		where valid = 1 and refdate BETWEEN @DateFrom and @DateTo 
		and PreInvDate BETWEEN @DateFrom and @DateTo 
		and Collection <> 0 AND UserName = @UserName AND Department = @DeptName
		UNION ALL
		select Username,Department,Refdate,RefNo,PreInvDate AS InvDate,PrevInvNo,Particulars,0 AS Advance,Collection as				DueColl  ,
		ByCash , ByCard , ChequeAmount ,(ByCash+ByCard+ChequeAmount) AS TotalColl, PostingDateTime
		from SalesLedger 
		where valid = 1 and refdate BETWEEN @DateFrom and @DateTo 
		and PreInvDate NOT BETWEEN @DateFrom and @DateTo 
		and Collection <> 0 AND UserName = @UserName AND Department = @DeptName
		UNION ALL
		select UserName,'INDOOR',PaymentDate,ReceiptNo,RefDate ,RefNo,PatientId + '-'+PatientName+BedNo,					 
		ReceiveAmt,0,CashAmt,CardAmt ,ChequeAmt,(CashAmt+CardAmt+ChequeAmt) as Total, EntryDateTime
		from TimeToTimeDuePayment  
		where valid = 1 and ReceiveAmt <> 0 AND UserName = @UserName 
		and PaymentDate BETWEEN @DateFrom and @DateTo AND 'INDOOR' = @DeptName
		UNION ALL
		select UserName,'INDOOR',ReceiptDate ,ReceiptNo,ReceiptDate ,ReceiptNo,PatientId + '-'+ PatientName,
		0,CollAmt,CashAmt,CardAmt ,ChequeAmt,(CashAmt+CardAmt+ChequeAmt) as Total, EntryDateTime
		from PatientSettlementDetails  
		where valid = 1 and CollAmt <> 0 AND UserName = @UserName 
		and ReceiptDate BETWEEN @DateFrom and @DateTo 
		and valid = 1 AND 'INDOOR' = @DeptName
		UNION ALL
		select UserName,'PHARMACY',TRDate ,TRNO,InvDate ,InvNo,PatientId + '-'+ PatientName,
		Collection,0,CashAmt,CardAmt ,ChequeAmt,(CashAmt+CardAmt+ChequeAmt) as Total, EntryDateTime
		from PharSalesLedger  
		where valid = 1 and Collection <> 0 AND UserName = @UserName 
		and TrDate BETWEEN @DateFrom and @DateTo 
		and valid = 1 AND 'PHARMACY' = @DeptName
	END






GO
