CREATE PROCEDURE [dbo].[SP_Collection_RPT_UserWise_Details](@DateFrom Date,@DateTo Date,@UserName nvarchar(50), @BranchId int, @UnitId int) AS 
IF @UserName = '' 
	BEGIN
		select Username as UserName, Department, Refdate, RefNo, RegNo, Particulars, PPhone, PtStatus, Collection AS Advance, 0 as DueColl, ByCash, ByCard, ChequeAmount, (ByCash+ByCard+ChequeAmount) AS TotalColl, 0 as Refund, PostingDateTime
		from SalesLedger
		where valid <> 0 AND CRType = 'Sales' and RefDate BETWEEN @DateFrom and @DateTo
		AND BranchId = @BranchId
		--and PreInvDate BETWEEN @DateFrom and @DateTo 
		and Collection <> 0
		--UNION ALL
		--select Username, Department, Refdate, RefNo, RegNo, Particulars, PPhone, Collection AS Advance,0 as DueColl  ,
		--ByCash , ByCard , ChequeAmount ,(ByCash+ByCard+ChequeAmount) AS TotalColl, 0 as Refund, PostingDateTime
		--from SalesLedger  
		--where valid <> 0 AND CRType = 'Sales' and refdate BETWEEN @DateFrom and @DateTo 
		----and PreInvDate NOT BETWEEN @DateFrom and @DateTo 
		--and Collection <> 0
		UNION ALL
		select Username, Department, Refdate, RefNo, RegNo, Particulars, PPhone, PtStatus, 0 AS Advance, Collection as DueColl  ,
		ByCash , ByCard , ChequeAmount ,(ByCash+ByCard+ChequeAmount) AS TotalColl, 0 as Refund, PostingDateTime
		from SalesLedger  
		where valid <> 0 AND CRType = 'Collection' and RefDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId
		--and PreInvDate NOT BETWEEN @DateFrom and @DateTo 
		and Collection <> 0
		UNION ALL
		select UserName, 'INDOOR', RefDate, RefNo, RegNo, PatientId + '-'+PatientName+BedNo, '' as PPhone, 'Indoor' AS PtStatus, Collection, 0 as DueColl,
		CashAmt,CardAmt ,ChequeAmt,(CashAmt+CardAmt+ChequeAmt) as Total, 0 as Refund, EntryDateTime
		from PatientLedger  
		where valid = 1 and Collection <> 0 AND BranchId = @BranchId
		and RefDate BETWEEN @DateFrom and @DateTo 
		--UNION ALL
		--select UserName,'PHARMACY', TRDate, TRNO, RegNo, PatientId + '-'+ PatientName, '' as PPhone,
		--Collection,0,CashAmt,CardAmt ,ChequeAmt,(CashAmt+CardAmt+ChequeAmt) as Total, 0 as Refund, EntryDateTime
		--from PharSalesLedger  
		--where valid <> 0 and Collection <> 0 and PtStatus = 'Indooor' AND BranchId = @BranchId
		--and TrDate BETWEEN @DateFrom and @DateTo 
		--and valid = 1 
		UNION ALL
		select a.UserName,'Card Print' as Department, a.TrDate AS RefDate, a.TrNO AS RefNo, a.RegNo, a.PatientName as Particulars, 
		b.TelephoneNo as PPhone, 'Outdoor' as PtStatus, a.Amount as Advance, 0 as DueColl, a.Amount as Cash, 0 AS Card, 0 as ChequeAmt, 
		a.Amount as Total, 0 as Refund, a.EntryDateTime
		from RegistrationFees a, PatientRegistration b
		where a.valid = 1 AND a.BranchId = b.BranchId and a.Amount <> 0 and a.RegNo = b.RegNo
		and a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
		and a.valid = 1 
		UNION ALL
		select UserName,'OPD Ticket' as Department, TrDate AS RefDate, TrNO AS RefNo, RegNo, Name as Particulars, PhoneNo,
		'Outdoor' AS PtStatus, Amount as Advance, 0 as DueColl, Amount as Cash, 0 AS Card, 0 as ChequeAmt, 
		Amount as Total, 0 as Refund, EntryDateTime
		from OPDTicketMaster 
		where valid = 1 and Amount <> 0
		and TrDate BETWEEN @DateFrom and @DateTo --AND BranchId = @BranchId
		and valid = 1
		UNION ALL
		select UserName,'Outdor Refund' as Department, TrDate AS RefDate, TrNo AS RefNo, RegNo, PatientName as Particulars, MobNo, 'Indoor' AS PtStatus,
		0 Advance, 0 as DueColl, 0 Cash, 0 AS Card, 0 as ChequeAmt, 0 as Total, Amount as Refund, EntryDateTime
		from CashReturn 
		where valid = 1 and Amount <> 0
		and TrDate BETWEEN @DateFrom and @DateTo 
		and valid = 1
		UNION ALL
		select b.UserName, 'Invoice Return' AS Department, b.RtnInvDate as RefDate, b.RtnInvNo as RefNo, a.RegNo,  a.Particulars, PPhone as MobNo,
		a.PtStatus, 0 AS Advance,0 as DueColl, 0 Cash, 0 AS Card, 0 as ChequeAmt, 
		0 as Total, a.ReturnCash as Refund, MAX(b.EntryDateTime) as EntryDateTime
		from SalesLedger a, InvReturn b 
		where a.PrevInvNo = b.InvNo AND a.BranchId = b.BranchId and a.Valid <> 0 and b.Valid = 1
		AND b.RtnInvDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
		group by b.UserName, b.RtnInvDate, b.RtnInvNo, a.RegNo, a.Particulars, a.PPhone, a.ReturnCash, a.PtStatus
		UNION ALL
		select UserName,'Indoor Return' as Department, RefDate, RefNo, '' AS RegNo, PatientName as Particulars, '' as MobNo, 'Indoor' AS PtStatus,
		0 Advance, 0 as DueColl, 0 Cash, 0 AS Card, 0 as ChequeAmt, 0 as Total, ReturnAmt as Refund, EntryDateTime
		from PatientLedger 
		where valid = 1 AND ReturnAmt <> 0
		aND RefDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId 
		UNION ALL  
		select a.UserName,'OPD Refund' as Department, a.TrDate, a.TrNo, a.RegNo AS RegNo, a.PatientName as Particulars, a.MobNo, b.PtStatus,
		0 Advance, 0 as DueColl, 0 Cash, 0 AS Card, 0 as ChequeAmt, 0 as Total, a.Amount as Refund, a.EntryDateTime
		from InvRefund a
		LEFT JOIN InvMaster b ON a.InvNo = b.InvNo AND a.InvDate = b.InvDate AND a.BranchId = b.BranchId
		where a.valid = 1 AND a.Amount <> 0
		aND a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
		UNION ALL
		select b.UserName,'OPD Ticket Refund' as Department, b.TrDate, a.TrNo, a.RegNo, a.Name as Particulars, '' as MobNo, 'Outdoor' AS PtStatus,
		0 Advance, 0 as DueColl, 0 Cash, 0 AS Card, 0 as ChequeAmt, 0 as Total, a.RtnAmount as Refund, b.EntryDateTime
		from OPDTicketMaster a
		left join OPDTicketReturn b on a.Id = b.OpdId
		where a.valid = 1 and b.Valid = 1 AND RtnAmount <> 0 --AND BranchId = @BranchId
		aND b.TrDate BETWEEN @DateFrom and @DateTo 
	END
ELSE
	BEGIN
		select Username as UserName, Department, Refdate, RefNo, RegNo, Particulars, PPhone, PtStatus, Collection AS Advance, 0 as DueColl, ByCash, ByCard, ChequeAmount, (ByCash+ByCard+ChequeAmount) AS TotalColl, 0 as Refund, PostingDateTime
		from SalesLedger 
		where valid <> 0 AND CRType = 'Sales' and RefDate BETWEEN @DateFrom and @DateTo
		AND BranchId = @BranchId
		and Collection <> 0 AND UserName = @UserName
		UNION ALL
		select Username, Department, Refdate, RefNo, RegNo, Particulars, PPhone, PtStatus, 0 AS Advance,Collection as DueColl  ,
		ByCash , ByCard , ChequeAmount ,(ByCash+ByCard+ChequeAmount) AS TotalColl, 0 as Refund, PostingDateTime
		from SalesLedger 
		where valid <> 0 AND CRType = 'Collection' and RefDate BETWEEN @DateFrom and @DateTo 
		AND BranchId = @BranchId
		and Collection <> 0 AND UserName = @UserName 
		UNION ALL
		select UserName, 'INDOOR', RefDate, RefNo, RegNo, PatientId + '-'+PatientName+BedNo, '' as PPhone, 'Indoor' AS PtStatus, Collection, 0 as DueColl,
		CashAmt,CardAmt ,ChequeAmt,(CashAmt+CardAmt+ChequeAmt) as Total, 0 as Refund, EntryDateTime
		from PatientLedger  
		where valid = 1 and Collection <> 0 AND BranchId = @BranchId
		and RefDate BETWEEN @DateFrom and @DateTo AND UserName = @UserName
		--UNION ALL
		--select UserName,'PHARMACY', TRDate, TRNO, RegNo, PatientId + '-'+ PatientName, '' as PPhone,
		--Collection,0,CashAmt,CardAmt ,ChequeAmt,(CashAmt+CardAmt+ChequeAmt) as Total, 0 as Refund, EntryDateTime
		--from PharSalesLedger  
		--where valid <> 0 and Collection <> 0 and PtStatus = 'Indooor' AND UserName = @UserName 
		--and TrDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId 
		--and valid = 1 
		UNION ALL
		select a.UserName,'Card Print' as Department, a.TrDate AS RefDate, a.TrNO AS RefNo, a.RegNo, a.PatientName as Particulars, 
		b.TelephoneNo as PPhone, 'Outdoor' AS PtStatus, a.Amount as Advance, 0 as DueColl, a.Amount as Cash, 0 AS Card, 
		0 as ChequeAmt, a.Amount as Total, 0 as Refund, a.EntryDateTime
		from RegistrationFees a, PatientRegistration b
		where a.valid = 1 AND a.BranchId = b.BranchId and a.Amount <> 0 and a.RegNo = b.RegNo
		and a.TrDate BETWEEN @DateFrom and @DateTo AND a.UserName = @UserName AND a.BranchId = @BranchId 
		and a.valid = 1 
		UNION ALL
		select UserName,'OPD Ticket' as Department, TrDate AS RefDate, TrNO AS RefNo, RegNo, Name as Particulars, PhoneNo, 'Outdoor' as PtStatus,
		Amount as Advance, 0 as DueColl, Amount as Cash, 0 AS Card, 0 as ChequeAmt, Amount as Total, 0 as Refund, EntryDateTime
		from OPDTicketMaster 
		where valid = 1 and Amount <> 0
		and TrDate BETWEEN @DateFrom and @DateTo AND UserName = @UserName --AND BranchId = @BranchId
		and valid = 1
		UNION ALL
		select UserName,'Outdoor Refund' as Department, TrDate AS RefDate, TrNo AS RefNo, RegNo, PatientName as Particulars, MobNo, 'Outdoor' AS PtStatus,
		0 Advance, 0 as DueColl, 0 Cash, 0 AS Card, 0 as ChequeAmt, 0 as Total, Amount as Refund, EntryDateTime
		from CashReturn 
		where valid = 1 and Amount <> 0
		and TrDate BETWEEN @DateFrom and @DateTo and UserName = @UserName
		UNION ALL
		select b.UserName, 'Invoice Return' AS Department, b.RtnInvDate as RefDate, b.RtnInvNo as RefNo, a.RegNo,  a.Particulars, PPhone as MobNo, 
		a.PtStatus, 0  AS Advance,0 as DueColl, 0 Cash, 0 AS Card, 0 as ChequeAmt, 0 as Total, a.ReturnCash as Refund, 
		MAX(b.EntryDateTime) as EntryDateTime
		from SalesLedger a, InvReturn b 
		where a.PrevInvNo = b.InvNo AND a.BranchId = b.BranchId and a.Valid <> 0 and b.Valid = 1 AND a.BranchId = @BranchId 
		AND b.RtnInvDate BETWEEN @DateFrom and @DateTo and b.UserName = @UserName  
		group by b.UserName, b.RtnInvDate, b.RtnInvNo, a.RegNo, a.Particulars, a.PPhone, a.ReturnCash, a.PtStatus
		UNION ALL
		select UserName,'Indoor Return' as Department, RefDate, RefNo, '' AS RegNo, PatientName as Particulars, '' as MobNo, 'Indoor' AS PtStatus,
		0 Advance, 0 as DueColl, 0 Cash, 0 AS Card, 0 as ChequeAmt, 0 as Total, ReturnAmt as Refund, EntryDateTime
		from PatientLedger 
		where valid = 1 AND ReturnAmt <> 0 AND BranchId = @BranchId
		aND RefDate BETWEEN @DateFrom and @DateTo and UserName = @UserName
		UNION ALL  
		select a.UserName,'OPD Refund' as Department, a.TrDate, a.TrNo, a.RegNo AS RegNo, a.PatientName as Particulars, a.MobNo, b.PtStatus,
		0 Advance, 0 as DueColl, 0 Cash, 0 AS Card, 0 as ChequeAmt, 0 as Total, a.Amount as Refund, a.EntryDateTime
		from InvRefund a
		LEFT JOIN InvMaster b ON a.InvNo = b.InvNo AND a.InvDate = b.InvDate AND a.BranchId = b.BranchId
		where a.valid = 1 AND a.Amount <> 0
		aND a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId and a.UserName = @UserName
		UNION ALL
		Select b.UserName,'OPD Ticket Refund' as Department, b.TrDate, a.TrNo, a.RegNo, a.Name as Particulars, '' as MobNo, 'Outdoor' AS PtStatus,
		0 Advance, 0 as DueColl, 0 Cash, 0 AS Card, 0 as ChequeAmt, 0 as Total, a.RtnAmount as Refund, b.EntryDateTime
		from OPDTicketMaster a
		left join OPDTicketReturn b on a.Id = b.OpdId
		where a.valid = 1 and b.Valid = 1 AND RtnAmount <> 0 --AND BranchId = @BranchId
		aND b.TrDate BETWEEN @DateFrom and @DateTo and b.UserName = @UserName
	END	
	


GO
