--16072025
CREATE PROCEDURE [dbo].[Sp_CommonInvestigations] @BranchId INT, @RefNo VARCHAR(20)--, @PtStatus VARCHAR(50)
AS
BEGIN /* EXEC Sp_CommonInvestigations 1, 'PR220200076' */
	SELECT a.RefNo, a.RefDate, a.PCode, b.Description, 1 AS Quantity, b.Charge, GETDATE()+b.ReportDeliverDuration AS ReportDeliveryDate, 
	(CASE WHEN b.RefFeePcOrTk = '%' THEN (Charge*RefFee)/100 ELSE RefFee END) AS MaxDrCom, b.CanGiveLess,
	(CASE WHEN b.LessType = '%' THEN (b.Charge*b.LessAmount)/100 ELSE b.LessAmount END) AS FixedLess, b.SubDeptName
	FROM CommonInvestigations a
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.PCode = b.PCode
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.IsDone = 0 ANd (a.RefNo+a.RegNo) LIKE '%'+@RefNo+'%'
	AND b.PCode IS NOT NULL
END
GO
