CREATE Procedure [dbo].[sp_ConsultantPayableDtls] (@dateFrom date , @dateTo date , @BranchId int , @DrCode nvarchar(20))
AS
BEGIN -- EXEC sp_ConsultantPayableDtls '2023-01-01' , '2023-12-31',1,''
select DrCode,DrName,DateofExam,InvNo, InvDate ,PatientName,Pcode,Description,Particulars , DeptName, 
0 as TotalAmount , PCorTk,Payable ,Less,Paid , 0 as OpBal 
from ImagingDoctorLedger 
where valid = 1 and BranchId = @BranchId 
and DateofExam BETWEEN @dateFrom  and @dateTo 
AND DrCode LIKE '%'+@DrCode +'%'
UNION ALL
select DrCode,DrName,DATEADD(day,-1,@dateFrom) as DateofExam,'-' as InvNo, NULL as InvDate , '' as PatientName,'' as Pcode,
'OPENING Balance' as Description,'' as Particulars ,
'' as DeptName,0 as TotalAmount , '' as PCorTk,0 as Payable ,0 as Less,0 as Paid , SUM(Payable -less-paid) 
from ImagingDoctorLedger 
where valid = 1 and BranchId = @BranchId 
and DateofExam < @dateFrom 
AND DrCode LIKE '%'+@DrCode +'%'
GROUP BY DrCode,DrName
END
GO
