-------------------------------------------------------------------------------------
CREATE PROCEDURE [dbo].[sp_ConsultantPayableSummarized] (@dateFrom date , @dateTo date , @BranchId int)
AS 
BEGIN  -- sp_ConsultantPayableSummarized '2023-12-01','2023-12-31',1
SELECT aa.DrCode , aa.Drname , SUM(aa.OPBal) as OPBal , SUM(aa.Payable) as Payable , SUM(aa.Less) AS Less ,  SUM(aa.Paid) AS Paid , SUM(aa.CB ) as CB 
FROM (
select DrCode,DrName,(Payable-Less-Paid) AS OPBal , 0 as Payable, 0 as Less, 0 as Paid , 0 as CB
from ImagingDoctorLedger 
where valid = 1 and BranchId = @BranchId 
and DateofExam < @dateFrom 
UNION ALL
select DrCode,DrName,0 AS OPBal , Payable,Less,Paid , 0 as CB
from ImagingDoctorLedger 
where valid = 1 and BranchId = @BranchId 
and DateofExam BETWEEN @dateFrom  AND @dateTo 
UNION ALL
select DrCode,DrName,0 AS OPBal , 0 as Payable, 0 as Less, 0 as Paid , (Payable-Less-Paid) as CB
from ImagingDoctorLedger 
where valid = 1 and BranchId = @BranchId 
and DateofExam < @dateTo) aa
GROUP BY aa.DrCode , aa.Drname
END
GO
