--26082025
CREATE PROC [dbo].[Sp_CorporateBill] @BranchId INT, @DateFrom DATE, @DateTo DATE, @CorporateId INT, @Type varchar(50)
AS
BEGIN -- Sp_CorporateBill 1, '2024-12-01', '2024-12-01', 0, 'App'

SELECT aa.DeptName+' Bill' AS Department, 'Outdoor' AS PtStatus, bb.RegNo, bb.PatientId, bb.PatientName, bb.Age, bb.Sex, bb.Address, bb.MobNo,
aa.InvNo, bb.InvDate, bb.UserName, bb.Remarks, cc.Id AS CardTypeId, cc.CardType, cc.CorporateId, cc.CorporateName, cc.PhoneNo AS CorporatePhone, 
cc.Address AS CorporateAddress, cc.Email AS CorporateEmail, cc.MRId, cc.MRName,
SUM(aa.Sales) AS Sales, SUM(aa.Less) AS Less, SUM(aa.Sales-aa.Less) AS NetSales, 
SUM(aa.Collection) AS Collection, SUM(aa.CashReturn) AS CashReturn, SUM(aa.DueAdjust) AS DueAdjust, SUM(aa.Sales-aa.Less-aa.Collection-aa.DueAdjust) AS Due
Into #z
FROM 
(
	SELECT a.DeptName, a.InvNo, a.BranchId, CAST(a.CorporateCode AS INT) AS CardTypeId, b.Sales, b.Less, b.Collection, 0 AS CashReturn, 0 AS DueAdjust, c.MRId, c.MRName
	FROM InvMaster a
	INNER JOIN SalesLedger b ON a.BranchId=b.BranchId AND a.InvNo=b.PrevInvNo AND b.Valid=1
	LEFT JOIN DrInfo c ON a.BranchId=c.BranchId AND a.RefDrCode=c.DrCode
	WHERE a.BranchId=@BranchId AND a.Valid=1 AND a.PtStatus='Outdoor'
	AND a.CorporateCode != '' AND a.InvDate BETWEEN @DateFrom AND @DateTo
	UNION ALL
	SELECT a.DeptName, a.InvNo, a.BranchId, a.CorporateCode AS CardTypeId, 0 AS Sales, 0 AS NetSales, 0 AS Collection, a.ReturnCash AS CashReturn, a.ReturnDue AS DueAdjust, c.MRId, c.MRName
	FROM InvMaster a
	INNER JOIN InvReturn b ON a.BranchId=b.BranchId AND a.InvNo=b.InvNo AND b.Valid=1
	LEFT JOIN DrInfo c ON a.BranchId=c.BranchId AND a.RefDrCode=c.DrCode
	WHERE a.BranchId=@BranchId AND a.Valid=1 AND a.PtStatus='Outdoor'
	AND a.CorporateCode != '' AND b.RtnInvDate BETWEEN @DateFrom AND @DateTo
	GROUP BY a.DeptName, a.InvNo, a.BranchId, a.CorporateCode, b.RtnInvNo, b.UserName, a.ReturnCash, a.ReturnDue, c.MRId, c.MRName
) aa
INNER JOIN InvMaster bb on aa.BranchId=bb.BranchId AND aa.InvNo=bb.InvNo
INNER JOIN VW_CorporateCardTypeList cc ON aa.BranchId=cc.BranchId AND aa.CardTypeId=cc.Id
WHERE bb.BranchId=@BranchId AND CASE WHEN @CorporateId = 0 THEN 0 ELSE cc.CorporateId END = @CorporateId
GROUP BY aa.DeptName, bb.RegNo, bb.PatientId, bb.PatientName, bb.DOB, bb.Age, bb.Sex, bb.Address, bb.MobNo, aa.InvNo, 
bb.InvDate, bb.UserName, bb.Remarks, cc.Id, cc.CardType, cc.CorporateId, cc.CorporateName, cc.PhoneNo, cc.Address, cc.Email, cc.MRId, cc.MRName
UNION ALL
SELECT 'Ambulance' AS DeptName, 'Outdoor' AS PtStatus, a.RegNo, a.PatientId, a.PatientName, b.AgeDetail, b.Gender, b.PatientAddress, b.TelephoneNo,
a.ReceiptNo AS InvNo, a.ReceiptDate, a.UserName, a.Remarks, c.Id AS CardTypeId, c.CardType, c.CorporateId, c.CorporateName, c.PhoneNo, c.Address, c.Email, c.MrId AS MRId, c.MrName AS MRName,
SUM(lg.TotalCharge) AS Sales, SUM(lg.Less) AS Less, SUM(lg.TotalCharge-lg.Less) AS NetSales, SUM(ReceiveAmt) AS Collection, 0 AS CashREturn, 0 AS DueAdjust, SUM(lg.TotalCharge-lg.Less-lg.ReceiveAmt) AS Due
FROM AmbulanceMaster a
INNER JOIN AmbulanceLedger lg on a.BranchId = lg.BranchId AND a.ReceiptNo=lg.PrevReceiptNo
INNER JOIN PatientRegistration b ON a.BranchId=b.BranchId AND a.RegNo=b.RegNo
INNER JOIN VW_CorporateCardTypeList c ON a.BranchId=c.BranchId AND b.CardTypeId=c.Id
WHERE a.BranchId=@BranchId AND a.Valid=1 AND a.PtStatus='Outdoor'
AND CASE WHEN @CorporateId = 0 THEN 0 ELSE c.CorporateId END = @CorporateId AND a.ReceiptDate BETWEEN @DateFrom AND @DateTo
GROUP BY a.RegNo, a.PatientId, a.PatientName, b.DOB, b.AgeDetail, b.Gender, b.PatientAddress, b.TelephoneNo, c.MrId, c.MrName,
a.ReceiptNo, a.ReceiptDate, a.UserName, a.Remarks, b.CorporateId, a.BranchId, c.Id, c.CardType, c.CorporateId, c.CorporateName, c.PhoneNo, c.Address, c.Email

UNION ALL
SELECT 'IPD Bill' AS DeptName, 'Indoor' AS PtStatus, b.RegNo, b.PatientId, b.PatientName, b.PatientAge, b.PatientSex, b.PatientAddress, b.PatientTel, 
rel.ReceiptNo, rel.ReleaseDate, rel.UserName, rel.Remarks, c.Id AS CardTypeId, c.CardType, c.CorporateId, c.CorporateName, c.PhoneNo AS CorporatePhone, 
c.Address AS CorporateAddress, c.Email AS CorporateEmail, c.MrId AS MRId, c.MrName AS MRName, 
SUM(a.Sales) AS Sales, SUM(a.Less) AS Less, SUM(a.Sales-a.Less) AS NetSales, SUM(a.Collection) AS Collection, SUM(a.CashReturn) As CashReturn, SUM(a.DueAdjust) AS DueAdjust, 
SUM(a.Sales+a.CashReturn-a.Less-a.Collection-a.DueAdjust) AS Due
FROM (
	SELECT a.PatientId, a.BranchId, CAST(a.CorporateId AS INT) AS CardTypeId,
	SUM(b.NoU*b.Charge+b.ServiceCharge) AS Sales, SUM(b.Less) AS Less, SUM(b.Collection) AS Collection, SUM(b.ReturnAmt) AS CashReturn, 0 AS DueAdjust
	FROM PatientAdmission a
	INNER JOIN PatientReleaseMaster rel ON a.BranchId=rel.BranchId AND a.PatientId=rel.PatientId AND rel.Valid=1
	INNER JOIN PatientLedger b ON a.BranchId=b.BranchId AND a.PatientId=b.PatientId AND b.Valid=1
	WHERE a.BranchId=@BranchId AND rel.ReleaseDate BETWEEN @DateFrom AND @DateTo AND a.CorporateId != ''
	GROUP BY a.PatientId, a.BranchId, a.CorporateId
	UNION ALL
	SELECT a.PatientId, a.BranchId, CAST(a.CorporateId AS INT) AS CardTypeId,
	SUM(b.Sales) AS Sales, SUM(b.Less) AS Less, SUM(b.Collection) AS Collection, SUM(b.ReturnCash) AS CashReturn, SUM(b.ReturnDue) AS DueAdjust
	FROM PatientAdmission a
	INNER JOIN PatientReleaseMaster rel ON a.BranchId=rel.BranchId AND a.PatientId=rel.PatientId AND rel.Valid=1
	INNER JOIN SalesLedger b ON a.BranchId=b.BranchId AND a.PatientId=b.PatientId AND b.Valid=1
	WHERE a.BranchId=@BranchId AND rel.ReleaseDate BETWEEN @DateFrom AND @DateTo AND a.CorporateId != ''
	GROUP BY a.PatientId, a.BranchId, a.CorporateId

	--UNION ALL
	--SELECT a.PatientId, a.BranchId, CAST(a.CorporateId AS INT) AS CardTypeId,
	--SUM(b.Sales) AS Sales, SUM(b.LessAmt+b.DueLess) AS Less, SUM(b.Collection+b.DueColl) AS Collection, SUM(b.CashReturn) AS CashReturn, SUM(b.ReturnAmt) AS DueAdjust
	--FROM PatientAdmission a
	--INNER JOIN PatientReleaseMaster rel ON a.BranchId=rel.BranchId AND a.PatientId=rel.PatientId AND rel.Valid=1
	--INNER JOIN PharSalesLedger b ON a.BranchId=b.BranchId AND a.PatientId=b.PatientId AND b.Valid=1
	--WHERE a.BranchId=@BranchId AND rel.ReleaseDate BETWEEN @DateFrom AND @DateTo AND a.CorporateId != ''
	--GROUP BY a.PatientId, a.BranchId, a.CorporateId

	UNION ALL
	SELECT a.PatientId, a.BranchId, CAST(a.CorporateId AS INT) AS CardTypeId,
	SUM(b.TotalCharge) AS Sales, SUM(b.Less) AS Less, SUM(b.ReceiveAmt) AS Collection, 0 AS CashReturn, 0 AS DueAdjust
	FROM PatientAdmission a
	INNER JOIN AmbulanceLedger b ON a.BranchId=b.BranchId AND a.PatientId=b.PatientId AND b.Valid=1
	INNER JOIN PatientReleaseMaster rel ON a.BranchId=rel.BranchId AND a.PatientId=rel.PatientId AND rel.Valid=1
	WHERE a.BranchId=@BranchId AND rel.ReleaseDate BETWEEN @DateFrom AND @DateTo AND a.CorporateId != ''
	GROUP BY a.PatientId, a.BranchId, a.CorporateId
) a
INNER JOIN PatientAdmission b ON a.BranchId=b.BranchId AND a.PatientId=b.PatientId
INNER JOIN VW_CorporateCardTypeList c ON a.BranchId=c.BranchId AND b.CorporateId=c.Id
INNER JOIN PatientReleaseMaster rel ON a.BranchId=rel.BranchId AND a.PatientId=rel.PatientId AND rel.Valid=1
WHERE b.BranchId=@BranchId AND CASE WHEN @CorporateId = 0 THEN 0 ELSE c.CorporateId END = @CorporateId
GROUP BY b.RegNo, b.PatientId, b.PatientName, b.PatientAge, b.PatientSex, b.PatientAddress, b.PatientTel, c.MrId, c.MrName,
rel.ReceiptNo, rel.ReleaseDate, rel.UserName, rel.Remarks, c.Id, c.CardType, c.CorporateId, c.CorporateName, c.PhoneNo, c.Address, c.Email

UNION ALL
SELECT 'IPD Medicine Bill' AS DeptName, 'Indoor' AS PtStatus, b.RegNo, b.PatientId, b.PatientName, b.PatientAge, b.PatientSex, b.PatientAddress, b.PatientTel, 
rel.ReceiptNo, rel.ReleaseDate, rel.UserName, rel.Remarks, c.Id AS CardTypeId, c.CardType, c.CorporateId, c.CorporateName, c.PhoneNo AS CorporatePhone, 
c.Address AS CorporateAddress, c.Email AS CorporateEmail, c.MrId AS MRId, c.MrName AS MRName, 
SUM(a.Sales) AS Sales, SUM(a.Less) AS Less, SUM(a.Sales-a.Less) AS NetSales, SUM(a.Collection) AS Collection, SUM(a.CashReturn) As CashReturn, SUM(a.DueAdjust) AS DueAdjust, 
SUM(a.Due) AS Due
FROM (
	SELECT a.PatientId, a.BranchId, CAST(a.CorporateId AS INT) AS CardTypeId,
	SUM(b.Sales) AS Sales, SUM(b.LessAmt+b.DueLess) AS Less, SUM(b.Collection+b.DueColl) AS Collection, 
	SUM(b.ReturnAmt) AS CashReturn, 0 AS DueAdjust, SUM(Sales-b.LessAmt-b.Collection-b.DueLess-b.DueColl-b.ReturnAmt) AS Due
	FROM PatientAdmission a
	INNER JOIN PatientReleaseMaster rel ON a.BranchId=rel.BranchId AND a.PatientId=rel.PatientId AND rel.Valid=1
	INNER JOIN PharSalesLedger b ON a.BranchId=b.BranchId AND a.PatientId=b.PatientId AND b.Valid=1
	WHERE a.BranchId=@BranchId AND rel.ReleaseDate BETWEEN @DateFrom AND @DateTo AND a.CorporateId != ''
	GROUP BY a.PatientId, a.BranchId, a.CorporateId
) a
INNER JOIN PatientAdmission b ON a.BranchId=b.BranchId AND a.PatientId=b.PatientId
INNER JOIN VW_CorporateCardTypeList c ON a.BranchId=c.BranchId AND b.CorporateId=c.Id
INNER JOIN PatientReleaseMaster rel ON a.BranchId=rel.BranchId AND a.PatientId=rel.PatientId AND rel.Valid=1
WHERE b.BranchId=@BranchId AND CASE WHEN @CorporateId = 0 THEN 0 ELSE c.CorporateId END = @CorporateId
GROUP BY b.RegNo, b.PatientId, b.PatientName, b.PatientAge, b.PatientSex, b.PatientAddress, b.PatientTel, c.MrId, c.MrName,
rel.ReceiptNo, rel.ReleaseDate, rel.UserName, rel.Remarks, c.Id, c.CardType, c.CorporateId, c.CorporateName, c.PhoneNo, c.Address, c.Email

UNION ALL
SELECT 'Medicine Bill' AS Department, LEFT(a.PtStatus, 7), a.RegNo, a.PatientId, a.PatientName, b.AgeDetail, b.Gender, b.PatientAddress, b.TelephoneNo, 
a.SaleNo, a.SaleDate AS SaleDate, a.UserName, a.Remarks, b.CardTypeId, c.CardType, c.CorporateId, c.CorporateName, c.PhoneNo, c.Address, c.Email, c.MrId AS MRId, c.MrName AS MRName, 
SUM(d.Sales) AS Sales, SUM(d.LessAmt+d.DueLess) AS Less,
SUM(d.Sales-d.LessAmt-d.DueLess) AS NetSales, SUM(d.Collection+d.DueColl) AS Collection, SUM(d.CashReturn) AS CashReturn, SUM(d.ReturnAmt) 
AS DueAdjust, SUM(Sales-d.LessAmt-d.Collection-d.DueLess-d.DueColl-d.ReturnAmt) AS Due
FROM PharSalesMaster a
LEFT JOIN PatientRegistration b ON a.BranchId=b.BranchId AND a.RegNo=b.RegNo
LEFT JOIN VW_CorporateCardTypeList c ON a.CorporateId=c.Id AnD a.BranchId=c.BranchId
LEFT JOIN PharSalesLedger d ON a.BranchId=d.BranchId AND a.SaleNo=d.InvNo AND d.valid=1
WHERE a.BranchId=@BranchId AND a.Valid=1 AND a.PtStatus!='Indoor' AND a.CorporateId != 0
AND CASE WHEN @CorporateId = 0 THEN 0 ELSE a.CorporateId END = @CorporateId
AND a.SaleDate BETWEEN @DateFrom AND @DateTo
GROUP BY a.PtStatus, a.RegNo, a.PatientId, a.PatientName, b.AgeDetail, b.Gender, b.PatientAddress, b.TelephoneNo, a.UserName, a.Remarks, c.MrId, c.MrName, 
a.SaleNo, a.SaleDate, b.CardTypeId, c.CardType, c.CorporateId, c.CorporateName, c.PhoneNo, c.Address, c.Email

UNION ALL
SELECT 'OPD Ticket' AS Department, 'Outdoor', a.RegNo, a.RegNo, a.Name, b.AgeDetail, b.Gender, b.PatientAddress, b.TelephoneNo, 
CONVERT(VARCHAR(20),a.Id), a.TrDate AS SaleDate, a.UserName, a.Remarks, b.CardTypeId, c.CardType, c.CorporateId, c.CorporateName, c.PhoneNo, c.Address, c.Email, c.MrId AS MRId, c.MrName AS MRName, 
SUM(d.Charge) AS Sales, SUM(d.Less) AS Less,
SUM(d.Charge-d.Less) AS NetSales, SUM(d.Received) AS Collection, SUM(d.CashReturn) AS CashReturn, 0 
AS DueAdjust, SUM(d.Charge-d.Less-d.Received) AS Due
FROM OPDTicketMaster a
LEFT JOIN PatientRegistration b ON a.BranchId=b.BranchId AND a.RegNo=b.RegNo
LEFT JOIN VW_CorporateCardTypeList c ON b.CorporateId=c.Id AnD a.BranchId=c.BranchId
LEFT JOIN OPDTicketLedger d ON a.BranchId=d.BranchId AND a.Id=d.OpdTicketId AND d.valid=1
WHERE a.BranchId=@BranchId AND a.Valid=1 AND b.CorporateId != 0
AND CASE WHEN @CorporateId = 0 THEN 0 ELSE b.CorporateId END = @CorporateId
AND a.TrDate BETWEEN @DateFrom AND @DateTo AND (d.Charge+d.Less+d.Received)>0
GROUP BY a.RegNo, a.Name, b.AgeDetail, b.Gender, b.PatientAddress, b.TelephoneNo, a.UserName, a.Remarks, c.MrId, c.MrName,
a.Id, a.TrDate, b.CardTypeId, c.CardType, c.CorporateId, c.CorporateName, c.PhoneNo, c.Address, c.Email

update #z set PatientName = a.PatientName+' ( OT )'
from #z a
Left Join PatientLedger b on a.PatientId= b.PatientId And b.BranchId=@BranchId and b.code IN ('0371', '0273') and b.valid=1
WHERE b.Code IS NOT NULL

select * from #z
Where (@Type!= 'App' Or Collection =0 )

END
GO
