-- FOR Aurora End NetTotal, Less

CREATE PROCEDURE [dbo].[sp_CorporateClientDtlsReport] (@DateFrom Date , @DateTo Date , @BranchId integer , @CorporateName nvarchar(50) )
AS -- EXEC sp_CorporateClientDtlsReport '2024-12-01', '2024-12-30', 1, 'Aichi Hospital Ltd.' 
BEGIN
SELECT aa.InvDate,aa.InvNo , aa.PatientName , aa.PTType , aa.RegNo , aa.patientId,aa.Age , aa.MobNo ,
aa.DrCode , aa.DrName , aa.ServiceType ,aa.PCode,aa.ShortDesc ,aa.Quantity , aa.TotalAmount ,aa.discountAmt ,
aa.NetAmt,aa.BillCreatedBy,aa.ConsultantCode,aa.TreatingDrName ,
aa.AdmittedDrname,aa.AdmissionDate , aa.DischargeDate , aa.CorporateCode , aa.CorporateName , aa.BranchId ,
bb.MRId , bb.MRName  
FROM 
(
	select a.InvDate,a.InvNo , a.PatientName , a.PTType , a.RegNo , a.patientId,a.Age , a.MobNo ,
	a.DrCode , a.DrName , b.subDeptName as ServiceType ,b.PCode,b.ShortDesc ,b.Quantity , b.TotalAmount ,b.discountAmt ,
	(b.TotalAmount-b.discountAmt) As NetAmt,a.UserName as BillCreatedBy,a.ConsultantCode,a.ConsultantName as TreatingDrName ,
	space(50) as AdmittedDrname,null as AdmissionDate , Null AS DischargeDate , a.CorporateCode , a.CorporateName , a.BranchId 
	--INTO tmpCorporateClientReport
	from InvMaster a , InvDetails b
	where a.InvNo = b.InvNo and a.InvDate = b.InvDate and a.BranchId = b.BranchId and b.Valid = 1 
	and a.InvDate BETWEEN @DateFrom  and @DateTo and a.BranchId = @BranchId 
	and a.CorporateName <> ''
	and a.Valid = 1 AND a.CorporateName LIKE '%'+@CorporateName +'%'
	UNION ALL
	select a.RefDate , a.refNo , b.PatientName,'Indoor' as  PTType , b.RegNo , b.PatientId,b.PatientAge,b.PatientTel,
	b.UnderDrCode , b.UnderDrName,b.AdmittedDept , a.Code as PCode,a.Particulars as ShortDesc,a.NoU ,a.TotalAmount ,
	a.less,(a.TotalAmount-a.Less) as  NetAmt , a.UserName as BillCreatedBy,a.DrCode, a.DrName,  
	b.UnderDrName ,b.AdmissionDate , b.ReleaseDate  , b.CorporateId , b.CorporateName , b.BranchId       
	from PatientLedger a , PatientAdmission b
	where a.PatientId = b.PatientId and a.BranchId = b.BranchId 
	and a.Valid = 1
	and b.ReleaseDate  BETWEEN @DateFrom  and @DateTo and b.BranchId = @BranchId 
	AND b.CorporateName LIKE '%'+@CorporateName +'%'
	and b.CorporateName <> '') aa ,DrInfo bb
	WHERE aa.DrCode = bb.DrCode  and aa.BranchId = bb.BranchId 
END
GO
