--12072025
CREATE PROC [dbo].[SP_COUNTED_LIST_OF_TESTED_ITEM] @DateFrom nvarchar(20), @DateTo varchar(20), @branchId int, @unitId varchar(50), @rptDept VARCHAR(50), @pCode VARCHAR(50), @PtStatus VARCHAR(50), @SubDeptName varchar(150), @SubSubDeptName varchar(150)
AS
BEGIN /* EXEC SP_COUNTED_LIST_OF_TESTED_ITEM '2025-06-01','2025-06-10', 1, '', 'DIAGNOSTIC', '', '', '', 'Blood Bank' */
	select a.PCode, a.ShortDesc, SUM(a.Quantity) TestedItem, ISNULL(b.SubSubDeptName, '') AS SubSubDeptName, a.Amount, SUM(a.Quantity*a.Amount) as TotalCharge
	from InvDetails a
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.PCode = b.PCode AND a.Valid = 1
	where a.BranchId = @branchId AND InvDate between @DateFrom and @DateTo AND a.PCode LIKE '%'+@pCode+'%'
	AND a.DeptName = @rptDept AND b.SubSubDeptName NOT IN ('Neddle') AND a.PtStatus LIKE '%'+@PtStatus+'%'
	AND Case When @SubDeptName = '' THEN '' ELSE b.SubDeptName END = @SubDeptName
	AND Case When @SubSubDeptName = '' THEN '' ELSE b.SubSubDeptName END = @SubSubDeptName
	group by a.PCode, a.ShortDesc, b.SubSubDeptName, a.Amount
END
GO
