CREATE PROC [dbo].[SP_CountedListOfTestedItemDrWise] @DateFrom nvarchar(20), @DateTo varchar(20), @branchId int, @unitId varchar(50), @rptDept VARCHAR(50), @drCode VARCHAR(50), @PtStatus VARCHAR(20)
AS
BEGIN /* EXEC SP_CountedListOfTestedItemDrWise '2022-09-01','2022-09-05', 1, '', 'DIAGNOSTIC', 'DR0001' */
	select a.PCode, a.ShortDesc, c.ConsultantCode, d.DrName AS ConsultantName, b.SubSubDeptName, d.DeptName, a.Amount AS Charge, SUM(a.Quantity) TestedItem, SUM(a.Quantity*a.Amount) as TotalCharge
	from InvDetails a
	LEFT JOIN InvMaster c ON a.BranchId = c.BranchId AND a.InvDate = c.InvDate AND a.InvNo = c.InvNo
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.PCode = b.PCode
	LEFT JOIN DrInfo d ON a.BranchId = d.BranchId AND a.ConsultantCode = d.DrCode
	where a.BranchId = @branchId AND a.InvDate between @DateFrom and @DateTo AND a.Valid = 1
	AND a.DeptName = @rptDept AND c.ConsultantCode LIKE '%'+@drCode+'%' AND c.PtStatus LIKE '%'+@PtStatus+'%'
	group by a.PCode, a.ShortDesc, b.SubSubDeptName, a.Amount, c.ConsultantCode, d.DrName, d.DeptName
END
GO
