CREATE PROCEDURE [dbo].[SP_CreateSalary] (@SalaryDate Date, @UserName nvarchar(50), @UnitId int, @BranchId int)
AS 
BEGIN /* SP_CreateSalary '2023-03-01', '', 1, 1 */

    DECLARE @DateFrom Datetime,@DateTo Datetime
    SET @DateFrom=@SalaryDate 
	SET @DateTo=EOMONTH(@DateFrom)
	   
	--exec SP_HRAttendenceReport_SMZ @DateFrom,@DateTo,'','','',''

	INSERT INTO  Payregister (Code, EmpId,EmpName,SalaryType, SalaryTypeId,SalaryFName, Amount, Valid, UserName, 
	PNo, SalaryDate, TrNo, 
	TRDate, AttYear, AttMonth, AttMName, deptName, DesignName, 
	EmpBankName, EmpBankBrName, EmpBankAcNo, ComBankName, ComBankBrName, ComBankAcNo, PaymentType, 
	Projectname, Grade, PostedBy, AcPostingNo, ACPostingDate,DaysPresent,DaysAbsent,TotalWorkDays,
    PaymentAmtCash, PaymentAmtBank, WorkingStatus,deptCode,DesigCode, UnitId, BranchId, LateIn, LeaveWithoutPay)

	SELECT a.Code, a.EmpId, a.Name, b.SalaryType, c.Slno, c.SalaryName, b.Amount, 1 AS Valid, @UserName AS UserName,
	a.pno, @SalaryDate AS SalaryDate, CONVERT(nvarchar(10), cast(right(Year(@SalaryDate),2) AS nvarchar(2))+RIGHT('0' + RTRIM(MONTH(@SalaryDate)), 2)) AS TrNo, 
	@SalaryDate AS TrDate, year(@SalaryDate) AS AttYear, month(@SalaryDate) AS AttMonth, DATENAME(month,@SalaryDate) AS AttMName, a.Department, a.Designation,
	a.EmpBankName, a.EmpBankBrName, a.EmpBankAccountNo, a.ComBankName, a.ComBankBrName, a.ComBankAccountNo, a.PaymentType,
	a.Project, a.Grade ,'Auto' PostedBy, '' AcPostingNo, '' ACPostingDate, e.WorkingDays, e.Absent, DAY(EOMonth (@SalaryDate)) TotalWorkDays,
	a.PaymentAmtCash, a.PaymentAmtBank, a.WorkingStatus,a.deptCode,a.DesigCode, a.UnitId, a.BranchId, e.LateIn, e.LeaveWithoutPay
	FROM HREmployeeMaster a
	LEFT JOIN HREmployeeDtls b ON a.Code = b.Code AND b.Valid = 1 AND a.BranchId = b.BranchId AND a.EmpId = b.EmpId
	LEFT JOIN HRSalaryType c ON b.SalaryTypeId = c.SlNo
	LEFT JOIN EmpWorkingStatus d ON a.Code = d.EmpCode AND d.Valid = 1
	LEFT JOIN tmp_HRAttendenceReportSMZ e On a.Code=e.employeecode
	WHERE a.valid = 1 AND (d.WorkingStatusId = 1 OR d.WorkingStatusId IS NULL)
	and a.EmpId NOT IN (SELECT DISTINCT EmpId FROM Payregister WHERE AttYear = year(@SalaryDate) and AttMonth = month(@SalaryDate) AND Valid = 1)

	
----	SELECT a.Code , a.EmpId ,a.Name , b.SalaryType ,c.Slno, c.SalaryName , b.Amount ,1,@UserName,a.pno,  
----	DATEADD(mm, DATEDIFF(mm, 0, @SalaryDate), 0),
----	CONVERT(nvarchar(50), cast(right(Year(@SalaryDate),2) as nvarchar(2))+dbo.LPAD(month(@SalaryDate),2,'0')) , 
----	@SalaryDate,year(@SalaryDate),month(@SalaryDate),DATENAME(month,@SalaryDate), a.Department , 
----	a.Designation,a.EmpBankName, a.EmpBankBrName, a.EmpBankAccountNo, a.ComBankName, a.ComBankBrName, a.ComBankAccountNo, a.PaymentType,
----	a.Project, a.Grade ,'Auto', '', '', 0, 0, DAY(EOMonth (@SalaryDate)), a.PaymentAmtCash, a.PaymentAmtBank, a.WorkingStatus,a.deptCode,a.DesigCode,
