	UPDATE Payregister SET amount = b.installmentamt
	FROM Payregister a , vw_LoanAndAdvanceLedger  b
	where a.code = b.EmpCode and b.Balance <> 0 
	and a.SalaryTypeId = 30 and b.LoanType='Loan'
	and TRDate =  CAST(@SalaryDate AS  Date) 
	--and a.BranchId=@BranchId and a.UnitId=@UnitId
	and a.EmpId IN (SELECT EmpId FROM Payregister WHERE AttYear = year(@SalaryDate) and AttMonth = month(@SalaryDate) AND a.Valid = 1 
	--and BranchId=@BranchId and UnitId=@UnitId
	)
	
	UPDATE Payregister SET amount = b.installmentamt
	FROM Payregister a , vw_LoanAndAdvanceLedger  b
	where a.code = b.EmpCode and b.Balance <> 0 
	and a.SalaryTypeId = 31 and b.LoanType='Advance'
	and TRDate =  CAST(@SalaryDate AS  Date) --and a.BranchId=@BranchId and a.UnitId=@UnitId
	and a.EmpId IN (SELECT EmpId FROM Payregister WHERE AttYear = year(@SalaryDate) and AttMonth = month(@SalaryDate) AND a.Valid = 1
	--and BranchId=@BranchId and UnitId=@UnitId
	)
		
	UPDATE Payregister SET amount = b.deductionAmt
	FROM Payregister a , HRSalaryDeduction  b
	where a.code = b.empCode and b.deductionAmt <> 0 
	and a.SalaryTypeId = b.DeductionID 
	and a.AttYear = b. AttYear AND a.AttMonth = b.AttMonth 
	AND b.AttYear = year(@SalaryDate) and b.AttMonth = month(@SalaryDate) AND a.Valid = 1
	--and a.BranchId=@BranchId and a.UnitId=@UnitId
	
	UPDATE Payregister SET amount = b.AdditionAmt
	FROM Payregister a , HRSalaryAddition  b
	where a.code = b.empCode and b.AdditionAmt <> 0 
	and a.SalaryTypeId = b.AdditionId   
	and a.AttYear = b. AttYear AND a.AttMonth = b.AttMonth 
	AND b.AttYear = year(@SalaryDate) and b.AttMonth = month(@SalaryDate) AND a.Valid = 1
	--and a.BranchId=@BranchId and a.UnitId=@UnitId
	
END


