CREATE PROC [dbo].[SP_CURRENT_PATIENT_DUE] (@IsRelease As int, @BranchId int, @UnitId int)
AS
if @IsRelease = 1
	BEGIN
	SELECT aa.PatientId, aa.PatientName, aa.BedNo, aa.AdmissionDate, CAST(aa.ReleaseDate AS date) AS ReleaseDate, bb.UserName, SUM(aa.Sales) AS Sales, SUM(aa.Collection) AS TotalCollection, SUM(aa.Less) AS Less, SUM(aa.Sales-aa.Collection-aa.Less) AS Due FROM (
		select a.PatientId, a.PatientName, a.BedNo, a.AdmissionDate, a.ReleaseDate, a.UserName, a.BranchId, (b.Charge*b.NoU)+(b.ServiceCharge) AS Sales,
		b.Collection As Collection, b.Less
		from PatientAdmission a
		LEFT JOIN PatientLedger b ON a.PatientId = b.PatientId AND a.BranchId = b.BranchId AND b.Status NOT IN ('Patient Settlement', 'Patient Release')
		WHERE a.Valid = 1 AND b.Valid = 1 AND a.IsRelease = @IsRelease AND a.BranchId = @BranchId
		UNION ALL
		select a.PatientId, a.PatientName, a.BedNo, a.AdmissionDate, a.ReleaseDate, a.UserName, a.BranchId, 0 AS Sales,
		b.Collection, b.Less
		from PatientAdmission a
		LEFT JOIN PatientLedger b ON a.PatientId = b.PatientId AND a.BranchId = b.BranchId AND b.Status IN ('Patient Settlement') and a.Valid = 1
		WHERE a.Valid = 1 AND b.Valid = 1 AND a.IsRelease = @IsRelease AND a.BranchId = @BranchId
		UNION ALL
		SELECT a.PatientId, a.PatientName, a.BedNo, a.AdmissionDate, a.ReleaseDate, a.UserName, a.BranchId, b.Sales-b.ReturnNet AS Sales,
		b.Collection-b.ReturnCash AS Coll, b.Less
		FROM PatientAdmission a
		LEFT JOIN SalesLedger b ON a.PatientId = b.PatientId AND a.BranchId = b.BranchId
		WHERE a.Valid = 1 AND b.Valid != 0 AND a.IsRelease = @IsRelease AND a.BranchId = @BranchId
		UNION ALL
		SELECT a.PatientId, a.PatientName, a.BedNo, a.AdmissionDate, a.ReleaseDate, a.UserName, a.BranchId, b.Sales,
		b.Collection+b.DueColl AS Collection, b.LessAmt+b.DueLess AS Less
		FROM PatientAdmission a
		LEFT JOIN PharSalesLedger b ON a.PatientId = b.PatientId AND a.BranchId = b.BranchId
		WHERE a.Valid = 1 AND b.Valid <> 0 AND a.IsRelease = @IsRelease AND a.BranchId = @BranchId
		UNION ALL
		SELECT a.PatientId, a.PatientName, a.BedNo, a.AdmissionDate, a.ReleaseDate, a.UserName, a.BranchId, (b.TotalCharge) AS Sales,
		(b.ReceiveAmt) AS Collection, b.Less
		FROM PatientAdmission a
		LEFT JOIN AmbulanceLedger b ON a.PatientId = b.PatientId AND a.BranchId = b.BranchId
		WHERE a.Valid = 1 AND b.Valid = 1 AND a.IsRelease = @IsRelease AND a.BranchId = @BranchId
	) aa
	LEFT JOIN PatientReleaseMaster bb ON aa.PatientId = bb.PatientID AND aa.BranchId = bb.BranchId
	GROUP BY aa.PatientId, aa.PatientName, aa.BedNo, aa.AdmissionDate, aa.ReleaseDate, bb.UserName
	HAVING SUM(aa.Sales-aa.Collection-aa.Less) != 0
	END
else
	BEGIN
	
	SELECT aa.PatientId, aa.PatientName, aa.BedNo, aa.AdmissionDate, '0001-01-01' ReleaseDate, aa.UserName, SUM(aa.Sales) AS Sales, SUM(aa.Collection) AS TotalCollection, SUM(aa.Less) AS Less, SUM(aa.Sales-aa.Collection-aa.Less) AS Due FROM (
		select a.PatientId, a.PatientName, a.BedNo, a.AdmissionDate, a.ReleaseDate, a.UserName, a.BranchId, (b.Charge*b.NoU)+(b.ServiceCharge) AS Sales,
		b.Collection As Collection, b.Less
		from PatientAdmission a
		LEFT JOIN PatientLedger b ON a.PatientId = b.PatientId AND a.BranchId = b.BranchId AND b.Status NOT IN ('Patient Settlement', 'Patient Release')
		WHERE a.Valid = 1 AND b.Valid = 1 AND a.IsRelease = @IsRelease AND a.BranchId = @BranchId
		UNION ALL
		select a.PatientId, a.PatientName, a.BedNo, a.AdmissionDate, a.ReleaseDate, a.UserName, a.BranchId, 0 AS Sales,
		b.Collection, b.Less
		from PatientAdmission a
		LEFT JOIN PatientLedger b ON a.PatientId = b.PatientId AND a.BranchId = b.BranchId AND b.Status IN ('Patient Settlement') and a.Valid = 1
		WHERE a.Valid = 1 AND b.Valid = 1 AND a.IsRelease = @IsRelease AND a.BranchId = @BranchId
		UNION ALL
		SELECT a.PatientId, a.PatientName, a.BedNo, a.AdmissionDate, a.ReleaseDate, a.UserName, a.BranchId, b.Sales-b.ReturnNet AS Sales,
		b.Collection-b.ReturnCash AS Coll, b.Less
		FROM PatientAdmission a
		LEFT JOIN SalesLedger b ON a.PatientId = b.PatientId AND a.BranchId = b.BranchId
		WHERE a.Valid = 1 AND b.Valid != 0 AND a.IsRelease = @IsRelease AND a.BranchId = @BranchId
		UNION ALL
		SELECT a.PatientId, a.PatientName, a.BedNo, a.AdmissionDate, a.ReleaseDate, a.UserName, a.BranchId, b.Sales,
		b.Collection, b.LessAmt+b.DueLess AS Less
		FROM PatientAdmission a
		LEFT JOIN PharSalesLedger b ON a.PatientId = b.PatientId AND a.BranchId = b.BranchId
		WHERE a.Valid = 1 AND b.Valid = 1 AND a.IsRelease = @IsRelease AND a.BranchId = @BranchId
		UNION ALL
		SELECT a.PatientId, a.PatientName, a.BedNo, a.AdmissionDate, a.ReleaseDate, a.UserName, a.BranchId, (b.TotalCharge) AS Sales,
		(b.ReceiveAmt) AS Collection, b.Less
		FROM PatientAdmission a
		LEFT JOIN AmbulanceLedger b ON a.PatientId = b.PatientId AND a.BranchId = b.BranchId
		WHERE a.Valid = 1 AND b.Valid = 1 AND a.IsRelease = @IsRelease AND a.BranchId = @BranchId
	) aa
	GROUP BY aa.PatientId, aa.PatientName, aa.BedNo, aa.AdmissionDate, aa.ReleaseDate, aa.UserName
	HAVING SUM(aa.Sales-aa.Collection-aa.Less) != 0

	END
GO
