CREATE PROC [dbo].[SP_CurrentAdmittedPatient] @branchId int, @dateFrom VARCHAR(20), @dateTo VARCHAR(20), @drCode VARCHAR(50), @type VARCHAR(20), @status VARCHAR(30), @floorNo VARCHAR(50)
AS
BEGIN /* EXEC SP_CurrentAdmittedPatient 1, '2022-01-01', '2023-12-31', '', '', 'All', '' */

/* EXEC SP_CurrentAdmittedPatient 1, '', '', '', 'dept', '', '' */

--drop table #z

DECLARE @isRelease INT = 0;
If @dateFrom = '' BEGIN SET @dateFrom = '2020-01-01' END;
If @dateTo = '' BEGIN SET @dateTo = FORMAT(GETDATE(), 'yyyy-MM-dd') END;
IF @status = 'All' BEGIN SET @isRelease = 1 END;

IF @type = 'RefDr' 
	BEGIN
		select a.PatientId, a.DrCode as RefDrCode, A.DrName as RefDrName, a.UnderDrCode, a.UnderDrName, b.SubSubPno as Dept, 
		a.BedNo,a.PatientName, a.PatientAge, a.PatientSex,a.PatientTel, a.AdmissionDate, a.PatientAddress, a.BedCharge, a.UserName,
		a.BranchId, b.FloorNo, a.RefByCode, a.RefByName
		--INTO #Z
		from PatientAdmission a
		LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
		where a.BranchId = b.BranchId AND a.BedNo = b.BedNo and a.Valid = 1 AND a.BranchId = @branchId 
		AND a.AdmissionDate BETWEEN @dateFrom AND @dateTo AND a.DrCode LIKE '%'+@drCode+'%' 
		AND b.FloorNo LIKE '%'+@floorNo+'%' AND a.IsRelease IN (0, @isRelease)	
		UNION ALL
		select a.PatientId, a.DrCode as RefDrCode, A.DrName as RefDrName, a.UnderDrCode, a.UnderDrName, '' as Dept, 
		b.BedNo,'Attendance of '+a.bedNo, a.PatientAge, a.PatientSex,a.PatientTel, a.AdmissionDate, a.PatientAddress, a.BedCharge, 
		a.UserName, a.BranchId, '', a.RefByCode, a.RefByName
		from PatientAdmission a
		LEFT JOIN PatientExtraBed b ON a.BranchId = b.BranchId AND a.PatientId=b.PatientId and b.valid = 1
		where a.BranchId = b.BranchId and a.Valid = 1 AND a.BranchId = @branchId 
		AND a.PatientId=b.PatientId and b.valid = 1 and b.IsRelease = 0
		AND a.AdmissionDate BETWEEN @dateFrom AND @dateTo AND a.UnderDrCode LIKE '%'+@drCode+'%'
		AND a.IsRelease IN (0, @isRelease)
		Order by a.PatientId

		--SELECT 'Total Admitted Patient :'+ COUNT(*) AS T1 FROm #Z where Dept <> '-'
		--SELECT 'Total Attendant :'+ COUNT(*) AS T2 FROm #Z where Dept = '-'

	END
ELSE
	BEGIN
		select a.PatientId, a.DrCode as RefDrCode, A.DrName as RefDrName, a.UnderDrCode, a.UnderDrName, b.SubSubPno as Dept, 
		a.BedNo,a.PatientName, a.PatientAge, a.PatientSex,a.PatientTel, a.AdmissionDate, a.PatientAddress, a.BedCharge, 
		a.UserName, a.BranchId, b.FloorNo, a.RefByCode, a.RefByName
		--INTO #Z
		from PatientAdmission a
		LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
		where a.BranchId = b.BranchId AND a.BedNo = b.BedNo and a.Valid = 1 AND a.BranchId = @branchId 
		AND a.AdmissionDate BETWEEN @dateFrom AND @dateTo AND a.UnderDrCode LIKE '%'+@drCode+'%'
		AND b.FloorNo LIKE '%'+@floorNo+'%' AND a.IsRelease IN (0, @isRelease)
		UNION ALL
		select a.PatientId, a.DrCode as RefDrCode, A.DrName as RefDrName, a.UnderDrCode, a.UnderDrName, '' as Dept, 
		b.BedNo,'Attendance of '+a.bedNo, a.PatientAge, a.PatientSex,a.PatientTel, a.AdmissionDate, a.PatientAddress, a.BedCharge, 
		a.UserName, a.BranchId, '', a.RefByCode, a.RefByName
		from PatientAdmission a
		LEFT JOIN PatientExtraBed b ON a.BranchId = b.BranchId AND a.PatientId=b.PatientId and b.valid = 1
		where a.BranchId = b.BranchId and a.Valid = 1 AND a.BranchId = @branchId 
		AND a.PatientId=b.PatientId and b.valid = 1 and b.IsRelease = 0
		AND a.AdmissionDate BETWEEN @dateFrom AND @dateTo AND a.UnderDrCode LIKE '%'+@drCode+'%'
		AND a.IsRelease IN (0, @isRelease)
		Order by a.PatientId

--		SELECT 'Total Admitted Patient :'+ COUNT(*) FROm #Z where Dept <> '-'
--		SELECT 'Total Attendant :'+ COUNT(*) FROm #Z where Dept = '-'


	END
END
GO
