CREATE PROC [dbo].[SP_DailyOutSampleReport] @BranchId INT, @DateFrom DATETIME, @DateTo DATETIME, @InstituteId Int
AS
BEGIN
	SELECT a.TrDate, a.TrNo, a.InvoiceNo, a.InvoiceDate, a.PCode, a.Description, a.Charge, a.OutSampleCharge, a.InstituteName, a.IsUrgent, a.DelivaryDate, a.UserName, b.PatientName, b.PtStatus, b.RegNo, b.ConsultantCode, b.ConsultantName,b.RefDrCode, b.RefDrName, b.PatientId, b.Sex, b.Age, b.MobNo, b.DeptName, c.SubDeptName, c.SubSubDeptName
	FROM OutSample a
	LEFT JOIN InvMaster b ON a.BranchId=b.BranchId AND a.InvoiceNo=b.InvNo AND a.InvoiceDate=b.InvDate
	LEFT JOIN ClinicalChart c ON a.BranchId=c.BranchId AND a.PCode=c.PCode
	WHERE a.Valid=1 AND a.BranchId = @BranchId AND a.EntryDateTime BETWEEN @DateFrom AND @DateTo and CASE WHEN @InstituteId!=0 THEN a.InstituteId else 0 END = @InstituteId
END
GO
