CREATE PROCEDURE [dbo].[sp_Dashboard_AvailableBed](@BranchId int)
AS 
BEGIN
	select BedNo, FloorNo, KindsofBed AS BedType, ChargePerDay AS Charge 
	from BedInformation 
	where Status= 'Running' and isBooked = 0 AND BranchId = @BranchId
	ORDER BY KindsofBed
END
