CREATE PROCEDURE [dbo].[sp_Dashboard_DeptWiseCurrentPatient](@BranchId nvarchar(50))
AS 
BEGIN /* EXEC sp_Dashboard_DeptWiseCurrentPatient 3 */
	SELECT a.SubSubPno, SUM(TotalBed) AS TotalBed, SUM(a.OccupiedBed) AS OccupiedBed, SUM(a.AvailableBed) AS AvailableBed
	FROM (
		SELECT a.SubSubPno, 0 AS TotalBed, COUNT(a.IsBooked) AS OccupiedBed, 0 AS AvailableBed
		FROM BedInformation a 
		WHERE a.BranchId = @BranchId AND isBooked = 1 AND a.Status = 'Running'
		GROUP BY a.SubSubPno
		UNION ALL
		SELECT a.SubSubPno, COUNT(a.isBooked) AS TotalBed, 0 AS OccupiedBed, 0 AS AvailableBed
		FROM BedInformation a
		WHERE a.BranchId = @BranchId AND a.Status = 'Running'
		GROUP BY a.SubSubPno
		UNION ALL
		SELECT a.SubSubPno, 0 AS TotalBed, 0 AS OccupiedBed, COUNT(a.IsBooked) AS AvailableBed
		FROM BedInformation a 
		WHERE a.BranchId = @BranchId AND isBooked = 0 AND a.Status = 'Running'
		GROUP BY a.SubSubPno
	) a
	GROUP BY a.SubSubPno
	ORDER BY a.SubSubPno

	--select b.SubSubPno, Count(*) NoOfPtAdmitted
	--from PatientAdmission a, BedInformation b
	--where IsRelease = 0 AND a.BranchId = b.BranchId AND a.BranchId = @BranchId
	--and a.BedNo = b.BedNo 
	--GROUP BY b.SubSubPno
	--ORDER BY b.SubSubPno
END
GO
