CREATE PROC [dbo].[SP_DATE_WISE_PATIENT_LIST](@DateFrom nvarchar(20), @DateTo nvarchar(20))
AS
BEGIN

select @DateFrom as FromDate, @DateTo as ToDate, a.DrCode RefDrCode, a.DrName ReDrName,a.PatientId, a.PatientName, 
a.BedNo, a.PatientAge, a.PatientTel, a.AdmissionDate, ISNULL((a.ReleaseDate),'1900-01-01') ReleaseDate, 
sum(aa.Sales) as Sales, sum(aa.TotalCollection) as TotalCollection, sum(aa.Less) as Less, sum(aa.Sales)-sum(aa.Less)-sum(aa.TotalCollection) as Due
FROM
(
select a.PatientId, (sum(a.Charge*a.NoU)+sum(a.ServiceCharge)) Sales,
SUM(a.Collection) TotalCollection, sum(a.Less) Less, (sum(a.Charge*a.NoU)+sum(a.ServiceCharge)-Sum(a.Less))-SUM(a.Collection) Due
from PatientLedger a
--where a.PatientId = b.PatientId
group by a.PatientId
UNION ALL
select a.PatientId, (SUM(a.Amount*a.Quantity)+SUM(a.ServiceCharge)),
0, sum(a.Less1), SUM(a.Amount*a.Quantity)+SUM(a.ServiceCharge)
from InvDetails a
group by a.PatientId
UNION ALL
select a.PatientId, sum(a.ProductQty*a.SalePrice), 0, 0, sum(a.productQty*a.SalePrice)
from PharSalesDetails a
group by a.PatientId

) aa, PatientAdmission a
where a.PatientId = aa.PatientId and a.AdmissionDate between @DateFrom and @DateTo
--and a.IsRelease = 0
group by a.DrCode, a.DrName, a.PatientId, a.PatientName, a.BedNo, a.PatientAge, a.PatientTel, a.AdmissionDate,
a.ReleaseDate
having sum(aa.Sales)-sum(aa.TotalCollection) != 0

END





GO
