CREATE PROCEDURE [dbo].[SP_DepartmentWiseItemWiseTotalSales] (@DateFrom DateTime,@DateTo DateTime,@MainDept nvarchar(30),@SubDept nvarchar(30), @branchId int, @unitId int)
AS 
if (@SubDept='INDOOR')
	BEGIN
		select @MainDept as MainDept, row_number() over (order by c.InvestigationCode) as SlNo, @SubDept as DeptName, '' as SubDeptName, 
		c.InvestigationCode AS PCode, c.SortDescription AS Description, SUM(CONVERT(INT, c.NoOfUnit)) AS NOU, SUM(c.NetTotal+c.ServiceCharge) AS Totalamt
		from PatientReleaseDetails c
		WHERE c.Valid = 1 AND c.BranchId = @branchId and c.ReleaseDate BETWEEN @DateFrom and @DateTo
		group by c.InvestigationCode, c.SortDescription

	END
else
	BEGIN

		SELECT UPPER(a.PtStatus) AS MainDept,2 as SlNo,UPPER(a.DeptName) AS DeptName,UPPER(b.SubDeptName) AS SubDeptName, a.PCode,b.Description, count(*) as NOU, 
		SUM(Amount*Quantity)  as Totalamt FROM InvDetails a
		LEFT JOIN ClinicalChart b ON a.PCode = b.PCode AND a.BranchId = b.BranchId
		WHERE a.PtStatus = @MainDept AND a.Valid <> 0
		AND a.DeptName = @SubDept AND a.BranchId = @branchId
		and a.InvDate BETWEEN @DateFrom and @DateTo
		GROUP BY a.PCode,b.Description,a.DeptName,b.SubDeptName, a.PtStatus

		UNION ALL
		select UPPER(PtStatus) AS MainDepartment,1 as SlNo,'AMBULANCE','AMBULANCE','-','Ambulance No' as ProductName , COUNT(*),SUM(TotalCharge)
		from AmbulanceLedger 
		where valid = 1 and PtStatus=@MainDept 
		and 'Ambulance' = @SubDept AND BranchId = @branchId
		and RefDate  BETWEEN @DateFrom and @DateTo
		GROUP BY PtStatus

		UNION ALL
		select 'OUTDOOR' AS MainDepartment,3 as SlNo,'MEDICINE','MEDICINE','-', ProductName , SUM(ProductQty),SUM(ProductQty*SalePrice)
		from PharSalesDetails where valid <> 0
		AND PTStatus = @MainDept AND BranchId = @branchId 
		AND DeptName = @SubDept 
		and SaleDate BETWEEN @DateFrom and @DateTo
		GROUP BY ProductName
		ORDER BY slno,DeptName,SubDeptName,PCode

	END
GO
