CREATE PROC [dbo].[sp_DepartmentWiseMonthlyTestCount]
@BranchId INT,
@DateFrom DATETIME,
@DateTo DATETIME 
AS -- EXEC sp_DepartmentWiseMonthlyTestCount 1, '2024-01-01', '2024-12-31'
BEGIN
SELECT a.PtStatus,COUNT(a.PCode) AS TotalTest,b.SubDeptName,RIGHT(CONCAT('00', convert(nvarchar(20),MONTH(InvDate))), 2)+'-'+convert(varchar(20),DATENAME(M,InvDate))+'-'+CONVERT(VARCHAR(10),YEAR(InvDate)) As MonthName
FROM InvDetails a ,ClinicalChart b
WHERE a.PCode=b.PCode AND a.BranchId=b.BranchId
AND a.DeptName='Diagnostic' AND a.DeptName=b.DeptName
AND a.InvDate BETWEEN @DateFrom and @DateTo
AND a.BranchId=@BranchId
GROUP BY a.PtStatus,b.SubDeptName,RIGHT(CONCAT('00', convert(nvarchar(20),MONTH(InvDate))), 2)+'-'+convert(varchar(20),DATENAME(M,InvDate))+'-'+CONVERT(VARCHAR(10),YEAR(InvDate))
ORDER BY b.SubDeptName
END
GO
