CREATE PROC [dbo].[SP_DepartmentWisePatientCountReport]
@BranchId INT,
@DateFrom DATETIME,
@DateTo DATETIME
AS
BEGIN
SELECT a.MainDeptName,a.MonthName,COUNT(a.PatientId) AS TotalPatient
FROM
	(SELECT b.SubSubPno AS MainDeptName,a.PatientId,a.PatientName,RIGHT(CONCAT('00', convert(nvarchar(20),MONTH(c.AdmissionDate))), 2)+'-'+convert(varchar(20),DATENAME(M,c.AdmissionDate))+'-'+CONVERT(VARCHAR(10),YEAR(c.AdmissionDate)) As MonthName
    FROM PatientLedger a,BedInformation b,PatientAdmission c
	WHERE a.BedNo=b.BedNo AND c.AdmissionDate BETWEEN @DateFrom AND @DateTo AND a.BranchId=@BranchId AND a.PatientId=c.PatientId
	GROUP BY b.SubSubPno,a.PatientId,a.PatientName,RIGHT(CONCAT('00', convert(nvarchar(20),MONTH(c.AdmissionDate))), 2)+'-'+convert(varchar(20),DATENAME(M,c.AdmissionDate))+'-'+CONVERT(VARCHAR(10),YEAR(c.AdmissionDate))) a
GROUP BY a.MainDeptName,a.MonthName
END
GO
