CREATE PROCEDURE [dbo].[SP_Diag_DiscountReport] @DateFrom date, @DateTo Date, @BranchId INT, @UnitId nvarchar(50), @DeptName VARCHAR(50), @PtStatus VARCHAR(20)
AS 
BEGIN /* SP_Diag_DiscountReport '2023-07-19','2023-07-19', 1, 1, 'DIAGNOSTIC', '' */
	SELECT a.DeptName, a.InvDate, a.InvNo, a.PatientId, a.PatientName, a.UserName, a.PtStatus, a.TotalAmt AS Sales,
	a.TotalLess AS InvLess, a.LessPcOrTk AS InvLessPcOrTk, a.DiscountFrom AS InvLessFrom, a.UserName AS InvUserName, a.Remarks AS InvRemarks,
	0 AS DueLess, 'Tk.' AS DueLessPcOrTk, '' AS DueLessFrom, '' AS DueLessUserName, '' AS DueLessRemarks,
	(SELECT SUM(Sales-Less-Collection-ReturnDue) FROM SalesLedger WHERE Valid = 1 AND BranchId = a.BranchId AND PreInvDate=a.InvDate AND PrevInvNo=a.InvNo) AS Due
	FROM InvMaster a 
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.InvDate BETWEEN @DateFrom AND @DateTo AND a.LessAmount != 0 
	AND a.DeptName = @DeptName AND a.PtStatus LIKE '%'+@PtStatus+'%'
	UNION ALL
	SELECT b.DeptName, a.PaidDate, a.TrNo, b.PatientId, b.PatientName, a.UserName, b.PtStatus, 0 AS Sales,
	0 AS InvLess, 'Tk' AS InvLessPcOrTk, '' AS InvLessFrom, '' AS InvUserName, '' AS InvRemarks,
	a.Less AS DueLess, 'Tk.' As DueLessPcOrTk, a.LessFrom AS DueLessFrom, a.UserName AS DueLessUserName, a.Remarks AS DueLessRemarks,
	(SELECT SUM(Sales-Less-Collection-ReturnDue) FROM SalesLedger WHERE Valid = 1 AND BranchId = a.BranchId AND PreInvDate=a.InvDate AND PrevInvNo=a.InvNo) AS Due
	FROM InvPaid a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvDate = b.InvDate AND a.InvNo = b.InvNo
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.Less != 0  AND a.PaidDate BETWEEN @DateFrom AND @DateTo 
	AND a.DeptName = @DeptName AND b.PtStatus LIKE '%'+@PtStatus+'%'
END
GO
