CREATE PROC [dbo].[SP_Diag_DueCollDeptwiseInvDetails] @BranchId INT, @InvNo VARCHAR(50), @Department VARCHAR(50)
AS
BEGIN /* EXEC SP_Diag_DueCollDeptwiseInvDetails 1, 'DIA231100001', 'DIAGNOSTIC' */
	SELECT b.SubDeptName, SUM(a.Amount*a.Quantity) AS Amount, SUM(a.GLessAmt) AS PrevLess, SUM(a.MaxDrCom) AS MaxDrCom
	FROM InvDetails a
	LEFT JOIN ClinicalChart b oN b.BranchId = a.BranchId AND b.PCode = a.PCode
	WHERE a.BranchId = @BranchId AND a.DeptName = @Department AND a.InvNo = @InvNo AND b.CanGiveLess = 1
	GROUP BY b.SubDeptName
END
GO
