CREATE PROCEDURE [dbo].[SP_Diag_IncomeReportUserWise] (@DateFrom datetime, @DateTo datetime, @UserName nvarchar(50), @BranchId INT, @DeptName VARCHAR(50), @PtStatus VARCHAR(20))
AS
BEGIN /* EXEC SP_Diag_IncomeReportUserWise '2024-09-01', '2024-09-05', 'S004',1,'DIAGNOSTIC',''  */
	SELECT a.PtStatus, a.DeptName, a.InvDate, a.InvNo, a.PatientId, a.PatientName, a.MobNo, a.Age,
	a.Sex AS Gender, a.UserName, a.ConsultantCode, a.ConsultantName,
	a.AdvanceAmt, 0 AS DueColl, 0 AS Refund, a.CashAmt, a.CardAmt, a.ChequeAmt
	FROM InvMaster a
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.AdvanceAmt != 0 
	AND a.InvDate BETWEEN @DateFrom AND @DateTo AND (a.UserName+a.ConsultantCode) LIKE '%'+@UserName+'%'
	AND a.PtStatus LIKE '%'+@PtStatus+'%'
	AND a.DeptName = @DeptName
	UNION ALL
	SELECT b.PtStatus, b.DeptName, a.PaidDate AS InvDate, a.TrNo AS InvNo, b.PatientId, b.PatientName, b.MobNo, b.Age,
	b.Sex AS Gender, a.UserName, b.ConsultantCode, b.ConsultantName,
	0 AdvanceAmt, a.PaidAmt AS DueColl, 0 AS Refund, a.CashAmt, a.CardAmt, a.ChequeAmt
	FROM InvPaid a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvDate = b.InvDate AND a.InvNo = b.InvNo AND b.Valid = 1
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.PaidDate BETWEEN @DateFrom AND @DateTo 
	AND (a.UserName+b.ConsultantCode) LIKE '%'+@UserName+'%'
	AND b.PtStatus LIKE '%'+@PtStatus+'%'
	AND b.DeptName = @DeptName
	UNION ALL
	SELECT DISTINCT b.PtStatus, b.DeptName, a.RtnInvDate AS InvDate, a.RtnInvNo AS InvNo, b.PatientId, b.PatientName, b.MobNo, b.Age,
	b.Sex AS Gender, a.UserName, b.ConsultantCode, b.ConsultantName,
	0 AdvanceAmt, 0 AS DueColl, a.ReturnCash AS Refund, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt
	FROM InvReturn a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId ANd a.InvDate = b.InvDate AND a.InvNo = b.InvNo AND b.Valid = 1
	where a.BranchId = @BranchId AND a.Valid = 1 AND RtnInvDate BETWEEN @DateFrom AND @DateTo 
	AND (a.UserName+b.ConsultantCode) LIKE '%'+@UserName+'%'
	AND b.PtStatus LIKE '%'+@PtStatus+'%'
	AND b.DeptName = @DeptName
	UNION ALL
	SELECT b.PtStatus, b.DeptName, a.TrDate AS InvDate, a.TrNo AS InvNo, b.PatientId, b.PatientName, b.MobNo, b.Age,
	b.Sex AS Gender, a.UserName, b.ConsultantCode, b.ConsultantName,
	0 AdvanceAmt, 0 AS DueColl, a.Amount AS Refund, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt
	FROM InvRefund a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.Valid = 1 ANd a.InvDate = b.InvDate AND a.InvNo = b.InvNo 
	where a.BranchId = @BranchId AND a.Valid = 1 AND TrDate BETWEEN @DateFrom AND @DateTo 
	AND (a.UserName+b.ConsultantCode) LIKE '%'+@UserName+'%'
	AND b.PtStatus LIKE '%'+@PtStatus+'%'
	AND b.DeptName = @DeptName
	ORDER BY InvDate
END
GO
