CREATE PROCEDURE [dbo].[SP_Diag_InvoiceRegisterConsDrWise] (@DateFrom datetime,@DateTo datetime, @DrCode nvarchar(20), @BranchId nvarchar(50), @unitId nvarchar(50))
AS
if @DrCode = ''
	BEGIN
		select @DateFrom as FromDate, @DateTo as ToDate, b.ConsultantCode, b.ConsultantName, a.PrevInvNo as InvNo, a.PreInvDate as Invdate, a.Particulars as PatientName, b.Age, b.Sex, 
		[dbo].[fnc_DiagInvName] (a.PrevInvNo, a.PreInvDate) as InvstName, SUM(a.Sales) as Total, SUM(a.Less) as Less, 
		SUM(a.Collection) as Advance, 0 as Vat, (SUM(a.Sales)-SUM(a.Less)-sum(a.Collection)) as Due,
		[dbo].fncDiagRemarks (a.PrevInvNo, a.PreInvDate) as Comments
		from SalesLedger a, InvMaster b
		where a.PrevInvNo = b.InvNo and a.PreInvDate = b.InvDate AND a.BranchId = b.BranchId
		AND a.PreInvDate BETWEEN @DateFrom and @DateTo AND CAST(a.BranchId AS nvarchar)+a.CostCenterName LIKE '%'+@BranchId+'%'+@unitId+'%'
		group by b.ConsultantCode, b.ConsultantName, a.PrevInvNo, a.PreInvDate, a.Particulars, b.Age, b.Sex
	END
else
	BEGIN
		select @DateFrom as FromDate, @DateTo as ToDate, b.ConsultantCode, b.ConsultantName, a.PrevInvNo as InvNo, a.PreInvDate as Invdate, a.Particulars as PatientName, b.Age, b.Sex, 
		[dbo].[fnc_DiagInvName] (a.PrevInvNo, a.PreInvDate) as InvstName, SUM(a.Sales) as Total, SUM(a.Less) as Less, 
		SUM(a.Collection) as Advance, 0 as Vat, (SUM(a.Sales)-SUM(a.Less)-sum(a.Collection)) as Due,
		[dbo].fncDiagRemarks (a.PrevInvNo, a.PreInvDate) as Comments
		from SalesLedger a, InvMaster b
		where a.PrevInvNo = b.InvNo and a.PreInvDate = b.InvDate AND a.BranchId = b.BranchId
		AND a.PreInvDate BETWEEN @DateFrom and @DateTo AND b.ConsultantCode = @DrCode AND CAST(a.BranchId AS nvarchar)+a.CostCenterName LIKE '%'+@BranchId+'%'+@unitId+'%'
		group by b.ConsultantCode, b.ConsultantName, a.PrevInvNo, a.PreInvDate, a.Particulars, b.Age, b.Sex
	END

GO
