		[dbo].[fnc_DiagInvName] (a.PrevInvNo, a.PreInvDate) as InvstName, SUM(a.Sales) as Total, SUM(a.Less) as Less, 
		SUM(a.Collection) as Advance, 0 as Vat, (SUM(a.Sales)-SUM(a.Less)-sum(a.Collection)) as Due,
