CREATE PROC [dbo].[SP_Diag_LabReportBeforeProcess] @BranchId INT, @DateFrom DATE, @DateTo DATE, @PtStatus VARCHAR(20), @SubDeptName VARCHAR(20), @SubSubDeptName VARCHAR(20)
AS
BEGIN /* EXEC SP_Diag_LabReportBeforeProcess 1, '2023-11-01', '2024-08-30', '', '', '' */
	SELECT a.InvNo, a.InvDate, a.RegNo, a.PatientId, c.MobNo, c.PatientName, a.PCode, b.Description, b.DeptName, b.SubDeptName, b.SubSubDeptName, 
	c.Dob, c.Age, c.ConsultantCode, c.ConsultantName, c.RefDrCode, c.RefDrName,	c.Sex, c.BedNo, c.UserName, c.PtStatus
	FROM InvDetails a
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.PCode = b.PCode
	LEFT JOIN InvMaster c On a.BranchId = c.BranchId AND a.InvNo = c.InvNo
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.InvDate between @DateFrom and @DateTo
	AND a.PtStatus LIKE '%'+@PtStatus+'%' AND b.SubDeptName like '%'+@SubDeptName+'%' AND b.SubSubDeptName LIKE '%'+@SubSubDeptName+'%' and b.PCode IS NOT NULL
END
