CREATE PROC [dbo].[SP_Diag_PCodeAmountBySubDept] @BranchId INT, @InvNo VARCHAR(50), @DeptName VARCHAR(50), @SubDeptName VARCHAR(50)
AS
BEGIN /* EXEC SP_Diag_PCodeAmountBySubDept 1, 'DIA231007216', 'DIAGNOSTIC', 'LabTest' */
	SELECT a.PCode, SUM(a.Amount*a.Quantity-a.GLessAmt-a.GDueLess) AS Amount
	FROM InvDetails a
	LEFT JOIN ClinicalChart b oN b.BranchId = a.BranchId AND b.PCode = a.PCode
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.DeptName = @DeptName 
	AND a.InvNo = @InvNo AND b.SubDeptName = @SubDeptName AND b.CanGiveLess = 1
	GROUP BY a.PCode
END
