SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE proc [dbo].[SP_DIAG_SALES_REPORT] @DateFrom as nvarchar(20), @DateTo as nvarchar(20), @branchId INT, @unitId nvarchar(50), @Department VARCHAR(50), @PtStatus VARCHAR(20)
AS
Begin /* EXEC SP_DIAG_SALES_REPORT '2026-01-20','2026-01-20', 1,'1', 'Physiotherapy', '' */
SELECT a.BranchId, InvNo, PtStatus, Department, RefDate, RefNo, PatientId, Particulars, PPhone, Sales, Less, Collection, UserName, Comments, DueLess, DueColl, DueUserName, DueComments,
CashReturn, ByCash, ByCard, AdjustAmt As ByCheque, DueAdjust, (SELECT SUM(Sales-Less-Collection-ReturnDue-AdjustAmt) FROM SalesLedger z WHERE z.Valid= 1 AND z.BranchId = a.BranchId AND z.PrevInvNo = a.InvNo) AS Due
FROM
(
	SELECT a.BranchId, a.PrevInvNo AS InvNo, a.PtStatus, a.Department, a.RefDate, a.RefNo, a.PatientId, a.Particulars, a.PPhone, a.Sales, a.Less, a.Collection, 
	a.UserName, a.Remarks AS Comments, 0 AS DueLess, 0 AS DueColl, '' AS DueUserName, '' AS DueComments, 0 AS CashReturn, a.ByCash, a.ByCard,
	a.ChequeAmount AS ByCheque, 0 AS DueAdjust, a.AdjustAmt
	FROM SalesLedger a
	WHERE a.Valid = 1 And a.BranchId = @branchId AND a.Department = @Department AND a.RefDate BETWEEN @DateFrom AND @DateTo
	AND a.PtStatus LIKE '%'+@PtStatus+'%' AND a.CRType = 'Sales'
	UNION ALL
	SELECT a.BranchId, a.RefNo AS PrevInvNo, a.PtStatus, a.Department, a.RefDate, a.RefNo, a.PatientId, a.Particulars, a.PPhone, a.Sales, 0 AS Less, 0 As Collection, 
	'' AS UserName, '' AS Comments, Less AS DueLess, Collection AS DueColl, a.UserName AS DueUserName, a.Remarks AS DueComments, 0 AS CashReturn, a.ByCash, a.ByCard,
	a.ChequeAmount AS ByCheque, ReturnDue AS DueAdjust, a.AdjustAmt
	FROM SalesLedger a
	WHERE a.Valid = 1 And a.BranchId = @branchId AND a.Department = @Department AND a.RefDate BETWEEN @DateFrom AND @DateTo
	AND a.PtStatus LIKE '%'+@PtStatus+'%' AND a.CRType != 'Sales'
	UNION ALL
	select a.BranchId, b.InvNo AS InvNo, a.PtStatus, a.DeptName AS Department, b.RtnInvDate AS RefDate, b.RtnInvNo AS RefNo, a.PatientId, a.PatientName, a.MobNo,
	0 AS Sales, 0 AS Less, 0 AS Collection, 
	'' AS UserName, '' AS Comments, 0 AS DueLess, 0 AS DueColl, '' AS DueUserName, '' AS DueComments, Max(a.ReturnCash) AS CashReturn, 0 AS ByCash, 0 AS ByCard, 
	0 AS ByCheque, 0 AS DueAdjust, 0 AdjustAmt
	from InvReturn b
	left join InvMaster a on a.BranchId = b.BranchId AND a.InvNo = b.InvNo and a.Valid = 1
	WHERE a.BranchId = @branchId and b.valid = 1 AND a.DeptName = @Department AND b.RtnInvDate BETWEEN @DateFrom AND @DateTo
	AND a.PtStatus LIKE '%'+@PtStatus+'%'
	GROUP BY a.BranchId, b.InvNo, a.PtStatus, a.DeptName, b.RtnInvDate, b.RtnInvNo, a.PatientId, a.PatientName, a.MobNo
	having max(a.ReturnCash) > 0
) a
END
GO
/****** Object:  StoredProcedure [dbo].[SP_Diag_TopContributor]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
