CREATE procedure [dbo].[SP_Diag_TopContributor] @DateFrom nvarchar(20), @DateTo nvarchar(20),@DrType nvarchar(30), @BranchId INT, @UnitId nvarchar(50), @DeptName VARCHAR(50), @PtStatus VARCHAR(20), @DrCode VARCHaR(20)
AS /* EXEC SP_Diag_TopContributor '2022-12-01','2022-12-30','RefDr', 1, '1', 'DIAGNOSTIC', 'Indoor', '' */
	if @DrType = 'RefDr'
		BEGIN
			select a.PtStatus, b.RefDrCode AS DrCode, b.RefDrName AS DrName, SUM(a.Sales-a.ReturnAmount) AS TotalSales,
			SUM(a.Less-a.ReturnLess) AS TotalLess, SUM(a.Sales-a.Less-a.ReturnNet) AS NetTotal, '' as PresentAdd
			from SalesLedger a, InvMaster b
			where a.BranchId = b.BranchId AND a.PrevInvNo = b.InvNo AND a.PreInvDate = b.InvDate
			AND a.Valid = 1 AND a.PreInvDate BETWEEN @DateFrom and @DateTo 
			AND a.BranchId = @BranchId AND a.Department = @DeptName AND a.PtStatus LIKE '%'+@PtStatus+'%' AND b.RefDrCode like '%'+@DrCode+'%'
			group by a.PtStatus, b.RefDrCode, b.RefDrName
			order by SUM(a.Sales-a.Less) desc
		END
	else
		BEGIN
			select a.PtStatus, b.ConsultantCode AS DrCode, b.ConsultantName AS DrName, SUM(a.Sales-a.ReturnAmount) AS TotalSales,
			SUM(a.Less-a.ReturnLess) AS TotalLess, SUM(a.Sales-a.Less-a.ReturnNet) AS NetTotal, '' as PresentAdd
			from SalesLedger a, InvMaster b
			where a.BranchId = b.BranchId AND a.PrevInvNo = b.InvNo AND a.PreInvDate = b.InvDate AND a.Valid = 1 AND a.PreInvDate BETWEEN @DateFrom and @DateTo 
			AND a.BranchId = @BranchId AND a.Department = @DeptName AND a.PtStatus LIKE '%'+@PtStatus+'%' AND b.ConsultantCode like '%'+@DrCode+'%'
			group by a.PtStatus, b.ConsultantCode, b.ConsultantName
			order by SUM(a.Sales-a.Less) desc
		END
GO
