CREATE PROCEDURE [dbo].[SP_DiagBroker](@DateFrom date, @DateTo date, @BranchId int, @UnitId int)
AS
BEGIN

select a.InvNo, a.InvDate, a.RegNo, a.PatientName, a.Sex, a.BrokerCode, b.DrName AS BrokerName, SUM(TotalAmt) AS TotalAmt, SUM(TotalAmt)*0.15 AS BrokerAmt from InvMaster a
LEFT JOIN DrInfo b ON a.BrokerCode = b.DrCode AND a.BranchId = b.BranchId
where a.BrokerCode != '' AND a.InvDate BETWEEN @DateFrom ANd @DateTo AND a.BranchId = @BranchId
GROUP BY a.InvNo, a.InvDate, a.RegNo, a.PatientName, a.Sex, a.BrokerCode, b.DrName
ORDER BY SUM(TotalAmt)*0.15 DESC

END
