CREATE PROC [dbo].[SP_DiagDueCollDeptWiseRpt] @BranchId INT, @RefNo VARCHAR(20), @RefDate DATE
AS
BEGIN /* EXEC SP_DiagDueCollDeptWiseRpt 1, 'DIC231101520', '2023-11-12' */
	SELECT a.TrNo AS RefNo, a.PaidDate AS RefDate, b.InvNo AS PrevInvNo, b.InvDate AS PreInvDate, b.PatientName AS Particulars, a.CashAmt AS ByCash,
	a.CardAmt AS Bycard, a.CardNo, a.CardBank, a.ChequeAmt, a.ChequeNo, 
	(
		select sum(Sales-Less-Collection-ReturnDue) 
		from SalesLedger 
		where Valid = 1 AND BranchId = a.BranchId AND PrevInvNo=b.InvNo and PostingDateTime < a.EntryTime
	) AS Due, 
	a.PaidAmt AS Collection, a.Less, c.PCode, c.ShortDesc, c.TotalAmount, c.GDueLess, c.RptDeliveryDate, c.Valid AS ReturnStatus, a.UserName, a.Remarks, b.DeptName AS Department, a.BranchId
	FROM InvPaid a
	LEFT JOIN InvMaster b ON b.BranchId = a.BranchId AND b.InvNo = a.InvNo AND b.Valid = 1
	LEFT JOIN InvDetails c ON c.BranchId = a.BranchId AND c.InvNo = a.InvNo
	WHERE a.BranchId = @BranchId AND a.TrNo = @RefNo AND a.PaidDate = @RefDate
END
GO
/****** Object:  StoredProcedure [dbo].[Sp_DiagDueCollList]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
