CREATE PROC [dbo].[Sp_DiagDueCollList] @Branch INT, @TrNo VARCHAR(50)
AS
BEGIN -- Sp_DiagDueCollList 1, 'DIC240701226'
	DECLARE @BranchId INT, @InvNo VARCHAR(50), @EntryTime DATETIME;

	SELECT @BranchId=BranchId, @InvNo=InvNo, @EntryTime=EntryTime FROM InvPaid WHERE BranchId =@Branch AND TrNo = @TrNo

	SELECT @BranchId AS BranchId, @InvNo AS InvNo, SUM(Sales) AS Sales, SUM(Collection) AS PrevCollection, SUM(Less) AS PrevLess, SUM(Sales+ProcServiceCharge-Less-Collection-ReturnDue) AS PrevDue 
	INTO #z
	FROM SalesLedger a 
	WHERE BranchId = @BranchId AND PrevInvNo=@InvNo AND PostingDateTime<@EntryTime

	SELECT a.InvNo, a.InvDate, a.PaidDate AS TrDate, a.TrNo, a.Remarks, a.UserName, a.EntryTime, a.PaidAmt, a.Less, a.CashAmt, 
	a.CardAmt, a.CardNo, a.CardBank, a.ChequeAmt, a.ChequeNo, a.ChequeBank, a.ChequeDate, b.RegNo, b.PatientId, b.BedNo, b.PatientName, b.Address, 
	b.Age, b.DOB, b.Sex, b.PtStatus, b.MobNo, b.UserName AS InvUserName, b.Remarks AS InvRemarks, b.EntryTime AS InvEntryTime, b.ConsultantCode, 
	b.ConsultantName, b.RefDrCode, b.RefDrName,
	c.PCode, c.ShortDesc, c.TotalAmount, c.RptDeliveryDate, d.Sales, d.PrevLess, d.PrevCollection, d.PrevDue
	FROM InvPaid a
	INNER JOIN InvMaster b oN b.BranchId = a.BranchId AND b.InvNo = a.InvNo
	INNER JOIN InvDetails c ON c.BranchId = c.BranchId AND c.InvNo = b.InvNo
	INNER JOIN #z d ON d.BranchId = a.BranchId AND d.InvNo = b.InvNo
	WHERE a.BranchId = @Branch AND a.TrNo=@TrNo
END
GO
/****** Object:  StoredProcedure [dbo].[SP_DiagHonorariumForSms]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROC [dbo].[SP_DiagHonorariumForSms] @BranchId INT, @DateFrom DATE, @DateTo DATE, @DrCode VARCHAR(20), @InvNo VARCHAR(20)
AS
BEGIN /* EXEC SP_DiagHonorariumForSms 1, '2023-01-01', '2023-01-15', 'A003', 'DIA230101040' */
SELECT a.BranchId, a.PrevInvNo AS InvNo, SUM(a.LessByDr) AS DrLess
INTO #z
FROM SalesLedger a 
LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.PrevInvNo = b.InvNo
WHERE a.BranchId = @BranchId AND b.RefDrCode = @DrCode AND a.PaidDate BETWEEN @DateFrom AND @DateTo
GROUP BY a.BranchId, a.PrevInvNo
HAVING SUM(a.Sales-a.Less-a.Collection-a.ReturnNet) = 0

SELECT SUM(aa.Prev) AS Prev, SUM(aa.Curr) AS Curr FROM (
SELECT a.InvNo, sum(MaxDrCom)-b.DrLess AS Prev, 0 AS Curr
FROM InvDetails a
LEFT JOIN #z b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
WHERE a.BranchId = @BranchId AND a.RefDrCode = @DrCode AND a.InvNo != @InvNo AND a.PaidDate BETWEEN @DateFrom AND @DateTo AND a.InvNo != ''
AND a.InvNo IN (SELECT InvNo FROM #z)
group by a.InvNo, b.DrLess
UNION ALL
SELECT a.InvNo, 0 AS Prev, sum(MaxDrCom)-b.DrLess AS Curr
FROM InvDetails a
LEFT JOIN #z b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
WHERE a.BranchId = @BranchId AND a.RefDrCode = @DrCode AND a.InvNo = @InvNo AND a.PaidDate BETWEEN @DateFrom AND @DateTo 
AND a.InvNo IN (SELECT InvNo FROM #z)
group by a.InvNo, b.DrLess
--order by a.InvNo
) aa

END
GO
