GO
CREATE PROCEDURE [dbo].[Sp_DiagInvCollHistory] @BranchId INT, @InvNo VARCHAR(20)
AS
BEGIN -- Sp_DiagInvCollHistory 1, 'DIA240600002'
	select CRType AS Type, MAX(PostingDateTime) AS EntryTime, UserName, RefNo, SUM(Less) AS Less, SUM(Collection) AS Collection, 
	0 AS ReturnAmt, 0 AS LessAdjust, 0 AS DueAdjust, 0 AS CashReturn
	from SalesLedger 
	where BranchId = @BranchId AND PrevInvNo = @InvNo AND Valid = 1 
	GROUP BY CRType, UserName, RefNo
	UNION ALL
	SELECT DISTINCT 'Return' AS Type, MAX(EntryDateTime) AS EntryDateTime, UserName, RtnInvNo AS TrNo, 0 AS Less, 0 AS Collection, 
	ReturnAmt AS ReturnAmt, ReturnLess AS LessAdjust, (ReturnAmt-ReturnLess-ReturnCash) AS DueAdjust, ReturnCash AS CashReturn
	FROM InvReturn 
	WHERE Valid = 1 AND BranchId = @BranchId AND InvNo = @InvNo
	GROUP BY UserName, RtnInvNo, ReturnAmt, ReturnLess, ReturnCash
	ORDER BY EntryTime
END
GO
