CREATE PROC [dbo].[SP_DiagInvoiceRegister] @DateFrom datetime, @DateTo datetime, @DrCode varchar(20), @BranchId INT, @unitId varchar(50), @DeptName VARCHAR(50), @DrType VARCHAR(50), @PtStatus VARCHAR(20)
AS
/* EXEC SP_DiagInvoiceRegister '2022-09-01', '2022-09-03', 'DR0050', 1 , '1', 'DIAGNOSTIC', 'Consultant' */

IF @DrType = 'Consultant'
	BEGIN
		SELECT a.RefDrCode, a.RefDrName, a.ConsultantCode, a.ConsultantName, a.InvNo, a.InvDate, a.PatientName, a.MobNo, a.Age, a.Sex, 
		[dbo].[fnc_DiagInvName] (a.InvNo, a.InvDate, a.BranchId) as InvstName, [dbo].fncDiagRemarks (a.InvNo, a.InvDate, a.BranchId) as Comments,
		SUM(b.Sales) AS Sales, SUM(b.Less) As Less, SUM(b.Collection) AS Collection, SUM(b.ReturnAmount) AS ReturnAmt, SUM(b.ReturnCash) AS CashRtn,
		SUM(b.ReturnLess) AS LessAdjust, SUM(b.ReturnDue) AS DueAdjust, SUM(b.Sales-b.Less-b.Collection-b.ReturnDue) AS Due
		FROM InvMaster a
		LEFT JOIN SalesLedger b ON a.BranchId = b.BranchId AND a.InvDate = b.PreInvDate AND a.InvNo = b.PrevInvNo and b.Valid = 1
		WHERE a.valid = 1 and a.BranchId = @BranchId AND a.DeptName = @DeptName AND a.InvDate BETWEEN @DateFrom AND @DateTo AND a.ConsultantCode LIKE '%'+@DrCode+'%'
		AND a.PtStatus LIKE '%'+@PtStatus+'%'
		GROUP BY a.RefDrCode, a.RefDrName, a.ConsultantCode, a.ConsultantName, a.InvNo, a.InvDate, a.PatientName, a.MobNo, a.Age, a.Sex, a.BranchId
		ORDER BY a.InvNo
	END
ELSE
	BEGIN
		SELECT a.RefDrCode, a.RefDrName, a.ConsultantCode, a.ConsultantName, a.InvNo, a.InvDate, a.PatientName, a.MobNo, a.Age, a.Sex, 
		[dbo].[fnc_DiagInvName] (a.InvNo, a.InvDate, a.BranchId) as InvstName, [dbo].fncDiagRemarks (a.InvNo, a.InvDate, a.BranchId) as Comments,
		SUM(b.Sales) AS Sales, SUM(b.Less) As Less, SUM(b.Collection) AS Collection, SUM(b.ReturnAmount) AS ReturnAmt, SUM(b.ReturnCash) AS CashRtn,
		SUM(b.ReturnLess) AS LessAdjust, SUM(b.ReturnDue) AS DueAdjust, SUM(b.Sales-b.Less-b.Collection-b.ReturnDue) AS Due
		FROM InvMaster a
		LEFT JOIN SalesLedger b ON a.BranchId = b.BranchId AND a.InvDate = b.PreInvDate AND a.InvNo = b.PrevInvNo and b.Valid = 1
		WHERE a.valid = 1 and a.BranchId = @BranchId AND a.DeptName = @DeptName AND a.InvDate BETWEEN @DateFrom AND @DateTo AND a.RefDrCode LIKE '%'+@DrCode+'%'
		AND a.PtStatus LIKE '%'+@PtStatus+'%'
		GROUP BY a.RefDrCode, a.RefDrName, a.ConsultantCode, a.ConsultantName, a.InvNo, a.InvDate, a.PatientName, a.MobNo, a.Age, a.Sex, a.BranchId
		ORDER BY a.InvNo
	END
GO
