CREATE PROCEDURE [dbo].[SP_DIAGNOSIS_DUE_COLLECTION_REPORT] (@DateFrom varchar(20), @DateTo varchar(20), @DrCode varchar(20), 
@branchId varchar(50), @unitId varchar(50), @deptName VARCHAR(50), @DrType VARCHAR(50), @PtStatus VARCHAR(20))
AS
/* EXEC SP_DIAGNOSIS_DUE_COLLECTION_REPORT '2022-01-01', '2024-09-30', 'SSSS', 1, '1', 'DIAGNOSTIC','Consultant', 'Outdoor' */
IF @DrType = 'Consultant'
BEGIN
SELECT b.RefDrCode, b.RefDrName, b.ConsultantCode, b.ConsultantName, a.PaidDate, a.InvDate, a.TrNo, a.InvNo, DATEDIFF(DAY, a.InvDate, a.PaidDate) NoOfDays, a.PaidAmt, a.Less, a.CashAmt, a.CardAmt,
a.CardNo, a.CardBank, a.ChequeAmt, a.ChequeNo, a.ChequeBank, a.ChequeDate, a.Comments, b.PtStatus, b.PatientName, b.RegNo
FROM InvPaid a
LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvDate = b.InvDate AND a.InvNo = b.InvNo
where a.Valid = 1 and a.PaidDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @branchId ANd b.DeptName = @deptName
AND b.PtStatus LIKE '%'+@PtStatus+'%' AND B.ConsultantCode LIKE '%'+@DrCode+'%'
order by a.InvNo
END
ELSE
BEGIN
SELECT b.RefDrCode, b.RefDrName, b.ConsultantCode, b.ConsultantName, a.PaidDate, a.InvDate, a.TrNo, a.InvNo, DATEDIFF(DAY, a.InvDate, a.PaidDate) NoOfDays, a.PaidAmt, a.Less, a.CashAmt, a.CardAmt,
a.CardNo, a.CardBank, a.ChequeAmt, a.ChequeNo, a.ChequeBank, a.ChequeDate, a.Comments, b.PtStatus, b.PatientName, b.RegNo
FROM InvPaid a
LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvDate = b.InvDate AND a.InvNo = b.InvNo
where a.Valid = 1 and a.PaidDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @branchId ANd b.DeptName = @deptName
AND b.PtStatus LIKE '%'+@PtStatus+'%' AND b.RefDrCode LIKE '%'+@DrCode+'%'
order by a.InvNo
END
GO
