CREATE Procedure [dbo].[SP_DiagnosisDueStatementReport] @branchId int , @dateFrom date, @dateTo date, @department nvarchar(20), @refDrCode nvarchar(20), @consultantDrCode nvarchar(20), @PtStatus VARCHAR(20)
AS
IF @dateFrom='' AND @dateTo=''
   BEGIN /* SP_DiagnosisDueStatementReport 1, '2023-09-01', '2025-09-10', 'DIAGNOSTIC', '', '', '' */
        Select a.PrevInvNo as InvNo, a.PreInvDate AS InvDate, a.PatientId, a.Particulars, a.PPhone, b.RefDrCode, b.RefDrName, sum(a.Sales) as Sales, sum(a.Less) as Less, 
		sum(a.Collection) as TotalCollection, SUM(Sales-a.Less-a.Collection-(a.ReturnAmount-a.ReturnCash-a.ReturnLess)) AS Due, ISNULL(b.Comments, '') AS Comments,a.PtStatus, 
		a.Department, LEFT(b.UserName,20) as UserName, b.Remarks, sum(a.ReturnDue) as ReturnNet,a.BranchId
        From SalesLedger a 
        Left join InvMaster b On a.PrevInvNo=b.InvNo and a.BranchId=b.BranchId AND a.Valid=1 AND b.Valid = 1 
        WHERE a.Valid=1 AND a.BranchId=@branchId AND a.Department=@department 
		AND (b.RefDrCode + b.ConsultantCode) LIKE '%'+@refDrCode+'%'+@consultantDrCode+'%'
		--AND a.PtStatus LIKE '%'+@PtStatus+'%' 
		AND a.PtStatus != 'Indoor'
        GROUP BY a.PrevInvNo, a.PreInvDate, a.Particulars, a.PPhone, b.RefDrCode, b.RefDrName, b.Comments, a.PtStatus, 
		a.Department, a.PatientId, LEFT(b.UserName,20), b.Remarks,a.BranchId
        HAVING SUM(Sales-a.Less-a.Collection-(a.ReturnAmount-a.ReturnCash-a.ReturnLess))  > 0
   END
ELSE
   BEGIN
        Select a.PrevInvNo as InvNo, a.PreInvDate AS InvDate, a.PatientId, a.Particulars, a.PPhone, b.RefDrCode, b.RefDrName, sum(a.Sales) as Sales, sum(a.Less) as Less, 
		sum(a.Collection) as TotalCollection, SUM(Sales-a.Less-a.Collection-(a.ReturnAmount-a.ReturnCash-a.ReturnLess)) AS Due, ISNULL(b.Comments, '') AS Comments, a.PtStatus,
		a.Department, LEFT(b.UserName,20) as UserName, b.Remarks, sum(a.ReturnDue) as ReturnNet,a.BranchId
        From SalesLedger a 
        Left join InvMaster b On a.PrevInvNo=b.InvNo and a.BranchId=b.BranchId AND a.Valid=1 AND b.Valid = 1 
        WHERE a.Valid=1 AND a.BranchId=@branchId AND a.Department=@department AND (b.RefDrCode + b.ConsultantCode) LIKE '%'+@refDrCode+'%'+@consultantDrCode+'%'
		AND a.PreInvDate BETWEEN @dateFrom AND @dateTo 
		--AND b.PtStatus LIKE '%'+@PtStatus+'%'
		AND a.PtStatus != 'Indoor'
        GROUP BY a.PrevInvNo, a.PreInvDate, a.Particulars, a.PPhone, b.RefDrCode, b.RefDrName, b.Comments, a.PtStatus, 
		a.Department, a.PatientId, LEFT(b.UserName,20), b.Remarks,a.BranchId
        HAVING SUM(Sales-a.Less-a.Collection-(a.ReturnAmount-a.ReturnCash-a.ReturnLess))  > 0
  END
GO
