CREATE PROC [dbo].[SP_Discharge_Certificate](@DischargeNo nvarchar(20), @DischargeDate nvarchar(20))
AS
BEGIN
select Medicine = STUFF((SELECT MedicineName + char(10)+space(10)+DoseInfo+space(5)+Days+' Days'+char(10) From HospitalDischargeMedicine 
where DischargeNo = a.DischargeNo and Valid = 1 order by MedicineName FOR XML PATH ('')), 1, 0, '' ), Advice = STUFF((SELECT Advice + char(10) From HospitalDischargeAdvice
where DischargeNo = a.DischargeNo and Valid = 1 order by Advice FOR XML PATH ('')), 1, 0, '' ), a.DischargeNo, a.DischargeDate, a.PatientId, a.PatientName, a.Sex as Gender, a.Age, a.Address, a.Phone, a.AdmissionDate, a.AdmissionTime, a.ReleaseDate, a.ReleaseTime, a.Religion, a.UnderDr, a.BedNo, a.TotalDays, a.Diagnosis, a.Investigation, a.AllergyDrugHistory, a.TreatmentGiven, a.CaseHistory, a.PersonalHistory, a.OTNote, a.UserName, b.RegNo, c.DeptName
from HospitalDischargeMaster a, PatientAdmission b, DrInfo c
where a.PatientId = b.PatientId and b.UnderDrCode = c.DrCode and a.DischargeNo = @DischargeNo and a.DischargeDate = @DischargeDate

END




GO
