CREATE PROCEDURE [dbo].[SP_DiscountCardReg] (@BranchId INT, @CorporateId INT)
AS --- EXEC SP_DiscountCardReg 1, 117
BEGIN
	SELECT b.CorporateName, b.CardType, a.DeptName, a.SubDeptName, a.Amount, a.PcOrTk, a.UserName, a.EntryDateTime FROM DiscountCardRegMain a
	LEFT JOIN CorporateCardType b ON a.CardTypeId=b.Id AND a.BranchId = b.BranchId
	WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.CorporateId=@CorporateId
	GROUP BY b.CorporateName, b.CardType, a.DeptName, a.SubDeptName, a.Amount, a.PcOrTk, a.UserName, a.EntryDateTime
	ORDER BY b.CorporateName
END
