CREATE Procedure [dbo].[SP_DoctorAppointmentRptSMZ] @BranchId int, @DateFrom date, @DateTo date, @DrCode nvarchar(20), @DeptName nvarchar(50)
AS ------ EXEC SP_DoctorAppointmentRptSMZ 1, '2023-07-01', '2024-10-27', '', ''
BEGIN
	SELECT aa.AppDate,  aa.DrCode as DrCode, ISNULL(aa.DrName,'') as DrName,aa.DeptName, SUM(aa.New) as New , SUM(aa.Old) as Old, SUM(aa.New + aa.Old) as Total FROM
	(
	select a.AppDate, a.DrCode, b.DrName , COUNT(PtType) as New , 0 as Old,b.DeptName From PatientAppointment a 
	left join DrInfo b On a.DrCode=b.DrCode AND a.Valid=1
	WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.PtType = 'New' AND a.AppDate Between @DateFrom AND @DateTo 
	AND (a.Drcode + b.DeptName) LIKE '%'+@DrCode+'%'+ @DeptName+'%'
	GROUP BY a.AppDate,  a.DrCode, b.DrName,b.DeptName
	UNION ALL
	select  a.AppDate, a.DrCode, b.DrName , 0 as New, COUNT(PtType) as Old,b.DeptName From PatientAppointment 
	a left join DrInfo b On a.DrCode=b.DrCode AND a.Valid=1
	WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.PtType = 'Old' AND a.AppDate Between @DateFrom AND @DateTo 
	AND (a.Drcode + b.DeptName) LIKE '%'+@DrCode+'%'+ @DeptName+'%'
	GROUP BY a.AppDate, a.DrCode, b.DrName,b.DeptName
	) aa 
	GROUP BY aa.AppDate, aa.DrCode, aa.DrName,aa.DeptName
	ORDER BY aa.DeptName,aa.AppDate, aa.DrCode
END
GO
