create PROCEDURE [dbo].[SP_DoctorInAndOutRpt] (@BranchId int , @DateFrom date, @DateTo date, @DeptName nvarchar(50), @DrCode nvarchar(20), @Type  nvarchar(20))
AS --- EXEC SP_DoctorInAndOutRpt 1, '2022-02-01', '2024-04-23', '', '', 'In' 
BEGIN
IF @Type = 'In' 
SELECT a.DrCode, a.DrName, (a.InTime) as Time, a.UserName, a.EntryDateTime FROM DrInOutTimes a
Left join DrInfo b On a.DrCode=b.DrCode AND a.BranchId=b.BranchId AND a.Valid=1
WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.Date BETWEEN @DateFrom AND @DateTo AND (b.DeptName + b.DrCode) LIKE '%'+@DeptName+'%' + @DrCode + '%'
IF @Type = 'Out'
SELECT a.DrCode, a.DrName, (a.OutTime) as Time, a.UserName, a.EntryDateTime FROM DrInOutTimes a
Left join DrInfo b On a.DrCode=b.DrCode AND a.BranchId=b.BranchId AND a.Valid=1
WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.Date BETWEEN @DateFrom AND @DateTo AND (b.DeptName + b.DrCode) LIKE '%'+@DeptName+'%' + @DrCode + '%'
END
