CREATE PROCEDURE [dbo].[SP_DrHonorariumDuePaid](@DateFrom date, @DateTo date, @BranchId int)
AS
BEGIN
select RefDrCode AS DrCode, DrName, Tel AS MobileNo, IsPaid , SUM(TotalSales) AS TotalSales, SUM(LessAmt) AS LessAmt, SUM(TotalHonorarium) AS TotalHonorarium, 
SUM(LessByDr) LessByDr, SUM(TotalHonorarium-LessByDr) AS NetHonorarium
from DrHonorariumLedger 
where InvPaidDate BETWEEN @DateFrom AND @DateTo AND MONTH(InvPaidDate) = MONTH(@DateFrom) and BranchId = @BranchId
GROUP BY RefDrCode, DrName, Tel, IsPaid
ORDER BY RefDrCode
END
