CREATE PROC [dbo].[SP_DrIncentive] (@month date)
AS
BEGIN		/* EXEC SP_DrIncentive '2023-06-01' */

	/* Start Only Paid Invoice List Insert #z */
	SELECT DISTINCT BranchId, PreInvDate AS InvDate, PrevInvNo AS InvNo, 0 AS Due, (SUM(Less)/SUM(Sales))*100 AS LessPc
	INTO #z 
	FROM SalesLedger
	WHERE BranchId = 1 AND Department = 'Diagnostic' AND MONTH(PaidDate) = MONTH(@month) AND YEAR(PaidDate) = YEAR(@month) 
	GROUP BY BranchId, PreInvDate, PrevInvNo
	HAVING SUM(Sales-Less-Collection-ReturnCash) = 0
	/* End Only Paid Invoice List Insert #z */

	/* START Diagnostic Dr wise Invoice List Insert #zz */
	SELECT a.InvNo, c.ConsultantCode AS DrCode, c.ConsultantName AS DrName, b.SubDeptName,
	SUM(a.Amount*a.Quantity) AS TotalAmount, ISNULL(d.Less,0) AS Less
	INTO #zz
	FROM InvDetails a
	LEFT JOIN InvMaster c ON a.BranchId = c.BranchId AND a.InvDate = c.InvDate AND a.InvNo = c.InvNo
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.PCode = b.PCode
	LEFT JOIN InvLess d ON a.BranchId = d.BranchId AND a.InvDate = d.InvDate AND a.InvNo = d.InvNo AND b.SubDeptName = d.GroupName
	LEFT JOIN #z e ON a.BranchId = e.BranchId AND c.InvDate = e.InvDate AND c.InvNo = e.InvNo
	WHERE a.Valid = 1 AND MONTH(a.PaidDate) = MONTH(@month) AND YEAR(a.PaidDate) = YEAR(@month) AND e.Due = 0
	AND b.SubDeptName IN ('LabTest', 'Radiology') AND e.LessPc < 20
	GROUP BY a.InvNo, c.ConsultantCode, c.ConsultantName, b.SubDeptName, d.Less
	order by c.ConsultantCode
	/* End Diagnostic Dr wise Invoice List Insert #zz */

	SELECT aa.DrCode, ISNULL(bb.DrName,'') AS DrName, SUM(aa.TtlDrVisit) as TtlDrVisit, (SUM(aa.TtlDrVisit)*.1) as InDrVisit, SUM(aa.ttlOtCharge) AS TtlOT, (SUM(aa.ttlOtCharge)*10*0.01) as InOT, SUM(aa.ttlSurgicalCharge) as ttlSurgical, (SUM(aa.ttlSurgicalCharge)*10*0.01) as InSurgical, SUM(aa.ttlOPDTicket) as TtlOPDTicket, (SUM(aa.ttlOPDTicket)*10*0.01) as InOPDTicket, SUM(aa.ttlDental) as TtlDental, SUM(aa.ttlDental*10*0.01) as InDental, SUM(aa.PathRad) AS PathRad, SUM(aa.PathRad*.10) AS InPathRad, SUM(aa.ptnAdmission) AS NoOfAdmission, SUM(aa.ptnAdmission*50) AS InOfAdmission FROM (

	/* Start Indoor Dr Visit */
	select a.DrCode, a.DrName ,SUM(a.Charge*a.NoU) as TtlDrVisit, 0 as ttlOtCharge, 0 as ttlSurgicalCharge, 0 as ttlOPDTicket,
	0 as ttlDental, 0 AS PathRad, 0 as ptnAdmission
	from PatientLedger a 
	where a.Valid = 1 AND a.DrCode NOT LIKE '%H%' AND a.Status = 'Procedure Entry For Dr' AND MONTH(a.RefDate) = MONTH(@month) AND YEAR(a.RefDate) = YEAR(@month)
	group by a.DrCode, a.DrName
	/* End Indoor Dr Visit */

	--/* Start General OT charge for indoor patient */
	--UNION ALL
	--select a.DrCode, a.DrName ,0 as TtlDrVisit, SUM(a.Charge*a.NoU) as ttlOtCharge, 0 as ttlSurgicalCharge, 0 as ttlOPDTicket,
	--0 as ttlDental, 0 AS PathRad, 0 as ptnAdmission
	--from PatientLedger a, ClinicalChart b
	--where a.Code = b.PCode AND a.Valid = 1 AND a.DrCode NOT LIKE '%H%' AND b.SubSubDeptName = 'General OT' AND a.DrCode != 'N/A' AND MONTH(a.RefDate) = MONTH(@month) AND YEAR(a.RefDate) = YEAR(@month) -- AND a.Status = 'Procedure Entry'
	--group by a.DrCode, a.DrName
	--/* End General OT charge for indoor patient*/

	/* Start General OT charge for indoor patient */
	UNION ALL
	select a.DrCode, a.DrName ,0 as TtlDrVisit, SUM(a.Charge*a.NoU) as ttlOtCharge, 0 as ttlSurgicalCharge, 0 as ttlOPDTicket,
	0 as ttlDental, 0 AS PathRad, 0 as ptnAdmission
	from PatientLedger a
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.Code = b.PCode
	LEFT JOIN DrInfo c ON a.BranchId = c.BranchId AND a.DrCode = c.DrCode
	LEFT JOIN PatientReleaseMaster d ON a.BranchId = d.BranchId AND a.PatientId = d.PatientID
	where a.Valid = 1 AND c.DrStatus = 'Indoor Dr' AND b.SubSubDeptName = 'General OT' and d.valid = 1
	AND MONTH(d.ReleaseDate) = MONTH(@Month) AND YEAR(d.ReleaseDate) = YEAR(@Month)
	group by a.DrCode, a.DrName
	/* End General OT charge for indoor patient*/

	/* Start General Ot and Emergency Charge from Diagnostic invoice*/
	UNION ALL
	select a.ConsultantCode, c.DrName, 0 as TtlDrVisit, 0 as TtlOtCharge, ISNULL(SUM((a.Amount*a.Quantity)-a.ReturnAmt),0) as TtlSurgicalCharge, 0 as TtlOPDTicket,
	0 as ttlDental, 0 AS PathRad, 0 as ptnAdmission
	from InvDetails a, ClinicalChart b, DrInfo c 
	WHERE a.PCode = b.PCode AND a.ConsultantCode = c.DrCode AND a.Valid <> 0 AND b.SubSubDeptName IN('General OT', 'Emergency') AND MONTH(a.InvDate) = MONTH(@month) AND YEAR(a.InvDate) = YEAR(@month)
	GROUP BY a.ConsultantCode, c.DrName
	HAVING ISNULL(SUM((a.Amount*a.Quantity)-a.ReturnAmt),0) > 0
	/* End General Ot and Emergency Charge from Diagnostic invoice*/

	/* start Data from Diagnostic invoice for fixed code*/
	UNION ALL
	/*Pcode R1701, 1702 21=2d, 22=4d by wahedul islam*/
	select 'DR0021' AS DrCode, 'Prof. Dr. Md. Nazrul Islam' AS DrName, 0 as TtlDrVisit, 0 as TtlOtCharge, ISNULL(SUM((a.Amount*a.Quantity)-a.ReturnAmt),0) as TtlSurgicalCharge, 0 as TtlOPDTicket,
	0 as ttlDental, 0 AS PathRad, 0 as ptnAdmission
	from InvDetails a, ClinicalChart b, DrInfo c 
	WHERE a.PCode = b.PCode AND a.ConsultantCode = c.DrCode AND a.Valid <> 0 AND b.PCode IN ('1702') AND MONTH(a.InvDate) = MONTH(@month) AND YEAR(a.InvDate) = YEAR(@month)
	HAVING ISNULL(SUM((a.Amount*a.Quantity)-a.ReturnAmt),0) > 0
	UNION ALL
	select 'DR0022' AS DrCode, 'Asso. Prof. Dr. Rownak Jahan Tamanna' AS DrName, 0 as TtlDrVisit, 0 as TtlOtCharge, ISNULL(SUM((a.Amount*a.Quantity)-a.ReturnAmt),0) as TtlSurgicalCharge, 0 as TtlOPDTicket,
	0 as ttlDental, 0 AS PathRad, 0 as ptnAdmission
	from InvDetails a, ClinicalChart b, DrInfo c 
	WHERE a.PCode = b.PCode AND a.ConsultantCode = c.DrCode AND a.Valid <> 0 AND b.PCode IN ('R1701') AND MONTH(a.InvDate) = MONTH(@month) AND YEAR(a.InvDate) = YEAR(@month)
	HAVING ISNULL(SUM((a.Amount*a.Quantity)-a.ReturnAmt),0) > 0
	/* End Data from Diagnostic invoice for fixed code*/

	/* Start Data from Opd ticket*/
	UNION ALL
	select a.DrCode, b.DrName, 0 as TtlDrVisit, 0 as ttlOtCharge, 0 as ttlSurgicalCharge, SUM(a.Amount-ISNULL(a.RtnAmount,0)) as ttlOPDTicket,
	0 as ttlDental, 0 AS PathRad, 0 as ptnAdmission
	from OPDTicketMaster a, DrInfo b
	WHERE a.DrCode = b.DrCode AND MONTH(a.TrDate) = MONTH(@month) AND YEAR(a.TrDate) = YEAR(@month) AND Valid = 1
	GROUP BY a.DrCode, b.DrName
	HAVING SUM(a.Amount-ISNULL(a.RtnAmount,0)) > 0
	/* End Data from Opd ticket*/

	/* Start Data for dental department*/
	UNION ALL
	select a.RefDrCode, c.DrName, 0 as TtlDrVisit, 0 as TtlOtCharge, 0 as TtlSurgicalCharge, 0 as TtlOPDTicket,
	ISNULL(SUM((a.Amount*a.Quantity)-a.ReturnAmt),0) as ttlDental, 0 AS PathRad, 0 as ptnAdmission
	from InvDetails a, ClinicalChart b, DrInfo c 
	WHERE a.PCode = b.PCode AND a.RefDrCode = c.DrCode AND a.Valid <> 0 AND a.DeptName = 'Dental' AND MONTH(a.InvDate) = MONTH(@month) AND YEAR(a.InvDate) = YEAR(@month)
	GROUP BY a.RefDrCode, c.DrName
	HAVING ISNULL(SUM((a.Amount*a.Quantity)-a.ReturnAmt),0) > 0
	/* end Data for dental department*/

	/* Start Patient List */
	UNION ALL
	select a.DrCode, a.DrName, 0 as TtlDrVisit, 0 as TtlOtCharge, 0 as TtlSurgicalCharge, 0 as TtlOPDTicket,
	0 as ttlDental, 0 AS PathRad, COUNT(PatientId) as ptnAdmission
	from PatientAdmission a 
	WHERE a.Valid = 1 AND DrCode IN ('DR0101','DR0108','DR0129','DR0134', 'DR0047','DR0057') AND MONTH(a.AdmissionDate) = MONTH(@month) AND YEAR(a.AdmissionDate) = YEAR(@month)
	GROUP BY a.DrCode, a.DrName
	HAVING COUNT(PatientId) > 0
	/* End Patient List */

	/* Start Pathology and radiology data */
	UNION ALL
	select a.DrCode, ISNULL(a.DrName, '') AS DrName, 0 as TtlDrVisit, 0 as TtlOtCharge, 0 as TtlSurgicalCharge, 0 as TtlOPDTicket,
	0 as ttlDental, SUM(a.TotalAmount-a.Less) AS PathRad, 0 as ptnAdmission
	from #zz a 
	WHERE a.DrCode NOT LIKE '%H%'
	GROUP BY a.DrCode, a.DrName
	/* Start Pathology and radiology data */

	) aa
	LEFT JOIN DrInfo bb ON aa.DrCode = bb.DrCode
	GROUP BY aa.DrCode, bb.DrName
	ORDER BY aa.DrCode
end
GO
/****** Object:  StoredProcedure [dbo].[Sp_DrIncentiveOutdoor]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
