CREATE PROC [dbo].[Sp_DrIncentiveOutdoor] @Month date, @BranchId INT
AS
BEGIN /* EXEC Sp_DrIncentiveOutdoor '2023-09-01', 1 */
	/* Start Only Paid Invoice List Insert #z */
	SELECT DISTINCT a.BranchId, PreInvDate AS InvDate, PrevInvNo AS InvNo, 0 AS Due, (SUM(Less)/SUM(Sales))*100 AS LessPc
	INTO #z 
	FROM SalesLedger a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.PrevInvNo = b.InvNo
	LEFT JOIN DrInfo c ON a.BranchId = c.BranchId AND b.ConsultantCode = c.DrCode
	WHERE a.BranchId = @BranchId AND Department = 'Diagnostic' AND MONTH(PaidDate) = MONTH(@Month)
	AND YEAR(PaidDate) = YEAR(@month) AND c.DrStatus = 'Outdoor Dr'
	GROUP BY a.BranchId, PreInvDate, PrevInvNo
	HAVING SUM(a.Sales-a.Less-a.Collection-a.ReturnCash-a.AdjustAmt) = 0
	/* End Only Paid Invoice List Insert #z */

	/* START Diagnostic Dr wise Invoice List Insert #zz */
	SELECT c.ConsultantCode AS DrCode, c.ConsultantName AS DrName, b.SubDeptName,
	SUM(a.Amount*a.Quantity) AS TotalAmount, ISNULL(d.Less,0) AS Less
	INTO #zz
	FROM InvDetails a
	LEFT JOIN InvMaster c ON a.BranchId = c.BranchId AND a.InvDate = c.InvDate AND a.InvNo = c.InvNo
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.PCode = b.PCode
	LEFT JOIN InvLess d ON a.BranchId = d.BranchId AND a.InvDate = d.InvDate AND a.InvNo = d.InvNo AND b.SubDeptName = d.GroupName
	LEFT JOIN #z e ON a.BranchId = e.BranchId AND c.InvDate = e.InvDate AND c.InvNo = e.InvNo
	WHERE a.Valid = 1 AND MONTH(a.PaidDate) = MONTH(@Month) AND YEAR(PaidDate) = YEAR(@month) AND e.Due = 0
	AND b.SubDeptName IN ('LabTest', 'Radiology') AND e.LessPc < 20
	GROUP BY a.InvNo, c.ConsultantCode, c.ConsultantName, b.SubDeptName, d.Less
	order by c.ConsultantCode
	/* End Diagnostic Dr wise Invoice List Insert #zz */

	SELECT aa.DrCode, ISNULL(bb.DrName,'') AS DrName, SUM(aa.TtlDrVisit) as TtlDrVisit, SUM(aa.InDrVisit) as InDrVisit,
	SUM(aa.ttlOtCharge) AS TtlOT, (SUM(aa.InOtCharge)) as InOT, SUM(aa.ttlSurgicalCharge) as ttlSurgical,
	(SUM(aa.ttlSurgicalCharge)*60*0.01) as InSurgical, SUM(aa.ttlOPDTicket) as TtlOPDTicket,
	(SUM(aa.ttlOPDTicket)*10*0.01) as InOPDTicket, SUM(aa.ttlDental) as TtlDental, SUM(aa.ttlDental*10*0.01) as InDental,
	SUM(aa.PathRad) AS PathRad, SUM(aa.PathRad*.10) AS InPathRad 
	FROM (

	/* Start Indoor Doctor Visit */
	SELECT a.DrCode, a.DrName, SUM(a.TotalAmount) AS TtlDrVisit, SUM((CASE WHEN Charge = 200 THEN Charge WHEN Charge = 600 THEN 500 WHEN Charge = 800 THEN 600 WHEN Charge = 2000 THEN 1500 WHEN Charge = 1000 THEN 600 ELSE 0.005 END)*NoU) AS InDrVisit, 0 as ttlOtCharge, 0 AS InOtCharge, 0 as ttlSurgicalCharge, 0 as ttlOPDTicket,
	0 as ttlDental, 0 AS PathRad
	FROM PatientLedger a
	LEFT JOIN DrInfo b ON a.BranchId = b.BranchId AND a.DrCode = b.DrCode
	WHERE a.BranchId = @BranchId ANd a.Valid = 1 AND MONTH(a.RefDate) = MONTH(@Month) AND YEAR(a.RefDate) = YEAR(@Month)
	AND b.DrStatus = 'Outdoor Dr' AND a.Status = 'Procedure Entry For Dr' AND a.TotalAmount != 0
	GROUP BY a.DrCode, a.DrName
	/* End Indoor Doctor Visit */

	/* Start General OT charge for indoor patient */
	UNION ALL
	select a.DrCode, a.DrName, 0 as TtlDrVisit, 0 AS InDrVisit, SUM(a.TotalAmount-a.less) as ttlOtCharge, SUM((a.TotalAmount*60*.01)-a.Less) as InOtCharge, 0 as ttlSurgicalCharge, 0 as ttlOPDTicket,
	0 as ttlDental, 0 AS PathRad
	from PatientLedger a
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.Code = b.PCode
	LEFT JOIN DrInfo c ON a.BranchId = c.BranchId AND a.DrCode = c.DrCode
	LEFT JOIN PatientReleaseMaster d ON a.BranchId = d.BranchId AND a.PatientId = d.PatientID
	where a.BranchId = @BranchId ANd a.Valid = 1 AND c.DrStatus = 'Outdoor Dr' AND b.SubSubDeptName = 'General OT' And d.Valid = 1
	AND MONTH(d.ReleaseDate) = MONTH(@Month) AND YEAR(d.ReleaseDate) = YEAR(@Month)
	group by a.DrCode, a.DrName
	/* End General OT charge for indoor patient*/


	/* Start General Ot and Emergency Charge from Diagnostic invoice*/
	UNION ALL
	select a.ConsultantCode, c.DrName, 0 as TtlDrVisit, 0 AS InDrVisit, 0 as ttlOtCharge, 0 as InOtCharge, ISNULL(SUM((a.Amount*a.Quantity)-a.ReturnAmt),0) as TtlSurgicalCharge, 0 as TtlOPDTicket,
	0 as ttlDental, 0 AS PathRad
	from InvDetails a
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.PCode = b.PCode
	LEFT JOIN DrInfo c ON a.BranchId = c.BranchId AND a.ConsultantCode = c.DrCode
	WHERE a.BranchId = @BranchId ANd a.Valid = 1 AND b.SubSubDeptName IN('General OT', 'Emergency') 
	AND MONTH(a.InvDate) = MONTH(@Month)
	AND YEAR(a.InvDate) = YEAR(@Month) AND c.DrStatus = 'Outdoor Dr'
	GROUP BY a.ConsultantCode, c.DrName
	HAVING ISNULL(SUM((a.Amount*a.Quantity)-a.ReturnAmt),0) > 0
	/* End General Ot and Emergency Charge from Diagnostic invoice*/

	/* Start Data from Opd ticket*/
	UNION ALL
	select a.DrCode, b.DrName, 0 as TtlDrVisit, 0 AS InDrVisit, 0 as ttlOtCharge, 0 as InOtCharge, 0 as ttlSurgicalCharge, SUM(a.Amount-ISNULL(a.RtnAmount,0)) as ttlOPDTicket,
	0 as ttlDental, 0 AS PathRad
	from OPDTicketMaster a
	LEFT JOIN DrInfo b ON a.BranchId = b.BranchId ANd a.DrCode = b.DrCode
	WHERE a.BranchId = @BranchId And a.DrCode = b.DrCode AND MONTH(a.TrDate) = MONTH(@Month) 
	AND YEAR(a.TrDate) = YEAR(@Month) AND Valid = 1 AND b.DrStatus = 'Outdoor Dr'
	GROUP BY a.DrCode, b.DrName
	HAVING SUM(a.Amount-ISNULL(a.RtnAmount,0)) != 0
	/* End Data from Opd ticket*/

	/* Start Data for dental department*/
	UNION ALL
	select a.RefDrCode, c.DrName, 0 as TtlDrVisit, 0 AS InDrVisit, 0 as ttlOtCharge, 0 as InOtCharge, 0 as TtlSurgicalCharge, 0 as TtlOPDTicket,
	ISNULL(SUM((a.Amount*a.Quantity)-a.ReturnAmt),0) as ttlDental, 0 AS PathRad
	from InvDetails a
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.PCode = b.PCode
	LEFT JOIN DrInfo c ON a.BranchId = c.BranchId AND a.ConsultantCode = c.DrCode
	WHERE a.BranchId = @BranchId ANd a.Valid = 1 AND a.DeptName = 'Dental' AND MONTH(a.InvDate) = MONTH(@Month) 
	AND YEAR(a.InvDate) = YEAR(@Month) AND c.DrStatus = 'Outdoor Dr'
	GROUP BY a.RefDrCode, c.DrName
	HAVING ISNULL(SUM((a.Amount*a.Quantity)-a.ReturnAmt),0) > 0
	/* end Data for dental department*/

	/* Start Pathology and radiology data */
	UNION ALL
	select a.DrCode, ISNULL(a.DrName, '') AS DrName, 0 as TtlDrVisit, 0 AS InDrVisit, 0 as ttlOtCharge, 0 as InOtCharge, 0 as TtlSurgicalCharge, 0 as TtlOPDTicket,
	0 as ttlDental, SUM(a.TotalAmount-a.Less) AS PathRad
	from #zz a 
	GROUP BY a.DrCode, a.DrName
	/* Start Pathology and radiology data */

	) aa
	LEFT JOIN DrInfo bb ON aa.DrCode = bb.DrCode
	GROUP BY aa.DrCode, bb.DrName
	ORDER BY aa.DrCode

END
GO
/****** Object:  StoredProcedure [dbo].[SP_DrPerformanceSummarized]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SP_DrPerformanceSummarized](@DateFrom nvarchar(50), @DateTo nvarchar(50))
AS
BEGIN

--EXEC SP_DrPerformanceSummarized '2022-01-01','2022-05-01'

SELECT aa.BranchId, aa.BranchName, SUM(aa.Appointted) AS Appointted, SUM(Arrived) AS Arrived, SUM(aa.IndoorSales) As IndoorSales,
SUM(aa.DiagSales) AS DiagSales, SUM(aa.PharSales) AS PharSales, SUM(aa.Ambulance) AS Ambulance, SUM(aa.OPDTicket) AS OpdTicket, SUM(Others) AS Others 
FROM (
Select a.BranchId, b.Name AS BranchName, COUNT(a.DrCode) AS Appointted, 0 as Arrived,
0 as IndoorSales, 0 as DiagSales, 0 AS PharSales, 0 AS Ambulance, 0 AS OPDTicket, 0 AS Others
from PatientAppointment a
LEFT JOIN tbl_BranchInfo b ON a.BranchId = b.Id
WHERE VisitDate BETWEEN @DateFrom AND @DateTo
AND a.Valid = 1
GROUP BY a.BranchId, b.Name

UNION ALL

Select a.BranchId, b.Name AS BranchName, 0 AS Appointted, COUNT(a.IsArrival) as Arrived,
0 as IndoorSales, 0 as DiagSales, 0 AS PharSales, 0 AS Ambulance, 0 AS OPDTicket, 0 AS Others 
from PatientAppointment a
LEFT JOIN tbl_BranchInfo b ON a.BranchId = b.Id
WHERE VisitDate BETWEEN @DateFrom AND @DateTo
AND a.Valid = 1 AND a.IsArrival = 1
GROUP BY a.BranchId, b.Name

UNION ALL

Select a.BranchId, c.Name AS BranchName, 0 AS Appointted, 0 as Arrived,
SUM(a.NetTotal) as IndoorSales, 0 as DiagSales, 0 AS PharSales, 0 AS Ambulance, 0 AS OPDTicket, 0 AS Others 
from PatientSettlementDetails a, PatientAdmission b, tbl_BranchInfo c
WHERE a.PatientId = b.PatientId AND a.BranchId = b.BranchId AND a.BranchId = c.Id
AND a.CostCenterName = b.CostCenterName AND a.ReceiptDate BETWEEN @DateFrom AND @DateTo
AND a.Valid = 1
GROUP BY a.BranchId, c.Name

UNION ALL

Select a.BranchId, c.Name AS BranchName, 0 AS Appointted, 0 as Arrived,
0 as IndoorSales, SUM(a.Sales-a.Less) as DiagSales, 0 AS PharSales, 0 AS Ambulance, 0 AS OPDTicket, 0 AS Others
from SalesLedger a, InvMaster b, tbl_BranchInfo c
WHERE a.PrevInvNo = b.InvNo AND a.BranchId = b.BranchId AND a.CostCenterName = b.CostCenterName AND a.CostCenterName = c.Id
AND a.PreInvDate BETWEEN @DateFrom AND @DateTo AND a.Department = 'Diagnostic'
AND a.Valid <> 0 AND a.PtStatus <> 'Indoor'
GROUP BY a.BranchId, c.Name

UNION ALL

Select a.BranchId, d.Name AS BranchName, 0 AS Appointted, 0 as Arrived,
0 as IndoorSales, 0 as DiagSales, SUM(a.Sales-a.LessAmt-a.DueLess) AS PharSales, 0 AS Ambulance, 0 AS OPDTicket, 0 AS Others 
from PharSalesLedger a
LEFT JOIN PharSalesMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.SaleNo AND a.InvDate = b.SaleDate
LEFT JOIN DrInfo c ON a.BranchId = c.BranchId AND b.DrCode = c.DrCode
LEFT JOIN tbl_BranchInfo d ON a.BranchId = d.Id
WHERE a.InvDate BETWEEN @DateFrom AND @DateTo AND a.Valid <> 0 AND a.PtStatus <> 'Indoor'
GROUP BY a.BranchId, d.Name
HAVING SUM(a.Sales-a.LessAmt-a.DueLess) <> 0
UNION ALL
Select a.BranchId, c.Name AS BranchName, 0 AS Appointted, 0 as Arrived,
0 as IndoorSales, 0 as DiagSales, 0 AS PharSales, 0 AS Ambulance, 0 AS OPDTicket, SUM(a.Sales-a.Less) AS Others 
from SalesLedger a, InvMaster b, tbl_BranchInfo c
WHERE a.PrevInvNo = b.InvNo AND a.BranchId = b.BranchId AND a.CostCenterName = b.CostCenterName AND a.BranchId = c.Id
AND a.PreInvDate BETWEEN @DateFrom AND @DateTo AND a.Department <> 'Diagnostic'
AND a.Valid <> 0 AND a.PtStatus <> 'Indoor'
GROUP BY a.BranchId, c.Name

UNION ALL

SELECT a.BranchId, b.Name AS BranchName, 0 AS Appointted, 0 as Arrived,
0 as IndoorSales, 0 as DiagSales, 0 AS PharSales, SUM(a.NetPayable) AS Ambulance, 0 AS OPDTicket, 0 AS Others
FROM AmbulanceLedger a
LEFT JOIN tbl_BranchInfo b ON a.BranchId = b.Id
WHERE RefDate BETWEEN @DateFrom AND @DateTo
GROUP BY a.BranchId, b.Name

UNION ALL

select a.BranchId, d.Name AS BranchName, 0 AS Appointted, 0 as Arrived,
0 as IndoorSales, 0 as DiagSales, 0 AS PharSales, 0 AS Ambulance, SUM(a.Amount) AS OPDTicket, 0 AS Others
from OPDTicketMaster a
LEFT JOIN OPDTicketReturn b ON a.Id = b.OpdId
LEFT JOIN DrInfo c ON a.DrCode = c.DrCode AND a.CostCenterName = c.CostCentername
LEFT JOIN tbl_BranchInfo d ON a.BranchId = d.Id
WHERE a.TrDate BETWEEN @DateFrom AND @DateTo AND b.Id IS NULL
GROUP BY a.BranchId, d.Name
) aa
GROUP BY aa.BranchId, aa.BranchName

END

GO
/****** Object:  StoredProcedure [dbo].[SP_DrReportFee]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SP_DrReportFee] (@DateFrom date,@DateTo Date, @DrCode nvarchar(20), @BranchId int)
AS 

if @DrCode <> '' 
	BEGIN
		SELECT a.InvNo,a.InvDate, b.PatientId , b.PatientName ,
		a.RptDrCode , a.RptDrName , a.PCode,c.Description,c.Charge, 1 as NOU, c.Charge AS TotalAmount ,
		(SELECT CASE c.ReportfeePcOrTk WHEN 'Tk.' then c.ReportFee ELSE (c.Charge * c.ReportFee * 0.01) END) AS DrPayable, 
		c.ReportFee , c.ReportFeePcOrTk ,b.RegNo ,c.SubSubDeptName as PaymentGroup
		from HPUSGAndXRayReport a , InvMaster b , ClinicalChart c
		where a.Valid = 1 and a.InvNo = b.InvNo and a.InvDate = b.InvDate 
		AND a.RptDrCode = @DrCode 
		and b.Valid=1 
		and a.PCode = c.PCode 
		AND a.InvDate BETWEEN @DateFrom AND @DateTo AND b.BranchId = @BranchId
		UNION ALL
		select a.RefNo ,a.RefDate,a.PatientId , a.PatientName ,
		a.DrCode ,a.DrName ,a.Code,a.Particulars ,a.Charge ,a.NoU,a.DrAmount,
		a.DrAmount,
		a.DrAmount,'Tk.',a.RegNo ,b.Description
		from PatientLedger a , ClinicalChart b
		where a.Code =b.Pcode and a.Valid = 1  
		AND a.DrCode  = @DrCode 
		AND a.RefDate BETWEEN @DateFrom AND @DateTo AND b.BranchId = @BranchId 
		and a.DrAmount <> 0
	END
ELSE
	BEGIN
		SELECT a.InvNo,a.InvDate, b.PatientId , b.PatientName ,
		a.RptDrCode , a.RptDrName , a.PCode,c.Description,c.Charge, 1 as NOU, c.Charge AS TotalAmount ,
		(SELECT CASE c.ReportfeePcOrTk WHEN 'Tk.' then c.ReportFee ELSE (c.Charge * c.ReportFee * 0.01) END) AS DrPayable, 
		c.ReportFee , c.ReportFeePcOrTk ,b.RegNo ,c.SubSubDeptName as PaymentGroup
		from HPUSGAndXRayReport a , InvMaster b , ClinicalChart c
		where a.Valid = 1 and a.InvNo = b.InvNo and a.InvDate = b.InvDate 
		and b.Valid=1 
		and a.PCode = c.PCode 
		AND a.InvDate BETWEEN @DateFrom AND @DateTo AND b.BranchId = @BranchId 
		UNION ALL
		select a.RefNo ,a.RefDate,a.PatientId , a.PatientName ,
		a.DrCode ,a.DrName ,a.Code,a.Particulars ,a.Charge ,a.NoU,a.DrAmount,
		a.DrAmount,
		a.DrAmount,'Tk.',a.RegNo ,b.Description
		from PatientLedger a , ClinicalChart b
		where a.Code =b.Pcode and a.Valid = 1  
		AND a.RefDate BETWEEN @DateFrom AND @DateTo AND b.BranchId = @BranchId 
		and a.DrAmount <> 0
	END

GO
/****** Object:  StoredProcedure [dbo].[sp_DrShareReport]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[sp_DrShareReport] (@DateFrom date ,@DateTo Date , @BranchId integer)
AS
BEGIN

	--drop table #OPDTicket
	--drop table  #LabSales
	--drop table  #RadioSales
	--drop table  #OthersSales

	--DROP table #OTMOrning
	--DROp TABLE #OTEvening
	--DROP TABLE #Procedure
	--DROP TABLE #DrVisit
	--DROp TABLE #PatientAdmit


	
	
	select a.OpdTicketId as OPDId,SUM(a.Received - a.CashReturn) AS Amount ,a.BranchId
	INTO #OPDTicket
	from OPDTicketLedger a 
	where a.valid <> 0 
	and a.RefDate BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId 
	GROUP BY a.OpdTicketId,a.BranchId
	HAVING SUM(a.Received - a.CashReturn) <> 0

	

	select a.ConsultantCode as DrCode , a.PCode, SUM(a.TotalAmount) as TSales ,a.BranchId  
	INTO #LabSales
	from Invdetails a , ClinicalChart b 
	where a.PCode = b.PCode and a.valid = 1 and a.BranchId = b.BranchId  
	AND a.InvDate BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId 
	and b.SubDeptName IN ('LabTest') 
	GROUP BY a.ConsultantCode , a.PCode,a.BranchId

	select a.ConsultantCode as DrCode, a.PCode, SUM(a.TotalAmount) as TSales ,a.BranchId  
	INTO #RadioSales
	from Invdetails a , ClinicalChart b
	where a.PCode = b.PCode and a.valid = 1 and a.BranchId = b.BranchId  
	AND a.InvDate BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId 
	and b.SubDeptName IN ('Radiology') 
	GROUP BY a.ConsultantCode , a.PCode ,a.BranchId  

	select a.ConsultantCode as DrCode , a.PCode, SUM(a.TotalAmount) as TSales ,a.BranchId  
	INTO #OthersSales
	from Invdetails a , ClinicalChart b
	where a.PCode = b.PCode and a.valid = 1 and a.BranchId = b.BranchId  
	AND a.InvDate BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId 
	and b.SubDeptName NOT IN ('LabTest','Radiology') 
	GROUP BY a.ConsultantCode , a.PCode,a.BranchId  


	

	SELECT a.DrCode,a.Code,SUM(a.TotalAmount - a.Less - a.ReturnAmt) as TSales,a.BranchId 
	INTO #OTMOrning 
	from patientledger a , PatientAdmission b
	where a.PatientId = b.PatientId and a.BranchId = b.BranchID and b.IsRelease = 1 and b.valid = 1
	and a.RefDate BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId 
	AND a.valid <> 0 
	AND a.Code in ('0104','0354','0355','0377','2415','3680','5250','5308','5351','5501','5791','5916','5922','5941','5950',
	'5952','6109','6678','6738','7045','7145','7178')
	AND CONVERT(varchar, a.entryDateTime,108) BETWEEN '08:00:00' AND '14:30:00'
	GROUP BY a.DrCode,a.Code,a.BranchId 


	SELECT a.DrCode,a.Code,SUM(a.TotalAmount - a.Less - a.ReturnAmt) as TSales,a.BranchId 
	INTO #OTEvening 
	from patientledger a , PatientAdmission b
	where a.valid <> 0 and a.PatientId = b.PatientId and b.Isrelease = 1 and b.valid = 1
	and a.RefDate BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId 
	AND a.Code in ('0104','0354','0355','0377','2415','3680','5250','5308','5351','5501','5791','5916','5922','5941','5950',
	'5952','6109','6678','6738','7045','7145','7178')
	AND CONVERT(varchar, a.entryDateTime,108) NOT BETWEEN '08:00:00' AND '14:30:00'
	GROUP BY a.DrCode,a.Code,a.BranchId 



	SELECT b.UnderDrCode as DrCode,a.Code,SUM(a.TotalAmount - a.Less - a.ReturnAmt) as TSales,a.BranchId 
	INTO #Procedure 
	from patientledger a , PatientAdmission b
	where a.PatientId = b.PatientId and a.BranchId = b.BranchId 
	AND a.RefDate BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId 
	AND a.valid <> 0 and b.IsRelease = 1 and b.valid = 1
	AND a.Code NOT IN ('0104','0354','0355','0377','2415','3680','5250','5308','5351','5501','5791',
	'5916','5922','5941','5950','5952','6109','6678','6738','7045','7145','7178')
	AND CONVERT(varchar, a.entryDateTime,108) NOT BETWEEN '08:00:00' AND '14:30:00'
	GROUP BY b.UnderDrCode,a.Code,a.BranchId 

	SELECT a.drcode , a.code, SUM(a.TotalAmount) AS TSales , a.BranchId 
	INTO #DrVisit
	from PatientLedger a , PatientAdmission b
	where a.PatientId = b.PatientId AND b.IsRelease = 1 and b.valid = 1
	and a.RefDate BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId 
	AND a.status in ('Procedure Entry For Dr')
	GROUP BY a.drcode , a.code,a.BranchId 

	SELECT UnderDrCode as drcode , COUNT(PatientId) as Code,  0 as  TSales , BranchId 
	INTO #PatientAdmit
	from PatientAdmission 
	where Valid = 1
	AND AdmissionDate BETWEEN @DateFrom AND @DateTo AND BranchId = @BranchId 
	GROUP BY UnderDrCode,BranchId 


		SELECT aa.DrCode, bb.DrName, 
		SUM(aa.NoPath) AS NoPath , SUM(aa.TPathSales) AS TPathSales,
		aa.PathAmt , aa.PathAmtpcOrTk,SUM(aa.PathShare) as PathShare ,
		SUM(aa.NoRadio) AS NoRadio,SUM(aa.TRadioSales) As TRadioSales, aa.RadioAmt,
		aa.RadioAmtpcOrTk,SUM(aa.RadioShare) As RadioShare ,
		SUM(aa.NoOthers) NoOthers,SUM(aa.TOtherSales) As TOtherSales, aa.Others , aa.OtherspcOrTk  ,
		SUM(aa.OthersShare) AS OthersShare ,
		SUM(aa.NOPD) as NOPD , SUM(aa.TOPDSales) As TOPDSales , aa.OPDTicket,aa.OPDpcOrTk , SUM(aa.OPDShare) as OPDShare,
		SUM(aa.NOTMorning) AS NOTMorning , SUM(aa.TOTMorningSales) as TOTMorningSales , aa.MorningOT , aa.MorningOTpcOrTk , 
		SUM(aa.OTMorningShare) as OTMorningShare ,
		SUM(aa.NOTEvening) AS NOTEvening ,SUM(aa.TOEveningSales) AS TOEveningSales , aa.EveningOT , aa.EveningOTpcOrTk , 
		SUM(aa.OTEveningShare) AS OTEveningShare ,
		SUM(aa.NProcedure) As NProcedure , SUM(aa.TProcedureSales) AS TProcedureSales , 
		aa.ProAmt as ProcedureAmt ,aa.ProAmtpcOrTk as ProcedureAmtpcOrTk , SUM(aa.ProcedureShare) as ProcedureShare,
		SUM(aa.NDrViist) AS NoOfIPDVisit ,SUM(aa.TDrVisitSales) AS IPDVisitSales, aa.IPDVisit , 
		aa.IPDVisitpcOrTk ,SUM(aa.VisitShare) AS IPDVisitShare, SUM(aa.NoofAdmittedPt)  as NoofAdmittedPt,
		SUM(aa.TPathSales+aa.TRadioSales+aa.TOtherSales+aa.TOPDSales+aa.TOTMorningSales+aa.TOEveningSales+
		aa.TProcedureSales+aa.TDrVisitSales) AS TotalSales , 
		SUM(aa.PathShare+aa.RadioShare+aa.OthersShare+OTMorningShare+aa.OTEveningShare+
		aa.ProcedureShare+aa.VisitShare) as TotalShare,cc.TDS , cc.TDSPCorTk,
		(SUM(aa.PathShare+aa.RadioShare+aa.OthersShare+OTMorningShare+aa.OTEveningShare+
		aa.ProcedureShare+aa.VisitShare)*0.01*cc.TDS) as TotalTDS , 
		SUM(aa.PathShare+aa.RadioShare+aa.OthersShare+OTMorningShare+aa.OTEveningShare+
		aa.ProcedureShare+aa.VisitShare) -
		(SUM(aa.PathShare+aa.RadioShare+aa.OthersShare+OTMorningShare+aa.OTEveningShare+
		aa.ProcedureShare+aa.VisitShare)*0.01*cc.TDS) as TotalAfterTDS
		FROM (
		SELECT a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk  ,
		Count(a.PCode) AS NoPath , SUM(a.TSales) as TPathSales,
		SUM(case when b.PathAmtpcOrTk <> '%' THEN b.PathAmt else a.TSales * 0.01 * b.PathAmt END) AS PathShare ,
		0 as NoRadio,0 as TRadioSales, 0 as RadioShare ,
		0 as NoOthers,0 as TOtherSales, 0 as OthersShare ,
		0 as NOPD , 0 as TOPDSales , b.OPDTicket , b.OPDpcOrTk , 0 AS OPDShare ,
		0 as NOTMorning , 0 as TOTMorningSales , b.MorningOT , b.MorningOTpcOrTk , 0 AS OTMorningShare ,
		0 as NOTEvening , 0 as TOEveningSales , b.EveningOT , b.EveningOTpcOrTk , 0 AS OTEveningShare ,
		0 as NProcedure , 0 as TProcedureSales , b.ProAmt , b.ProAmtpcOrTk , 0 AS ProcedureShare ,
		0 as NDrViist , 0 as TDrVisitSales , b.IPDVisit , b.IPDVisitpcOrTk , 0 AS VisitShare ,
		0 as NoofAdmittedPt
		FROM  #LabSales a, DrWiseProfitShare b
		WHERE a.DrCode = b.DrCode 
		GROUP BY a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk,
		b.OPDTicket , b.OPDpcOrTk ,b.MorningOT , b.MorningOTpcOrTk ,b.EveningOT , b.EveningOTpcOrTk ,
		b.ProAmt , b.ProAmtpcOrTk,b.IPDVisit , b.IPDVisitpcOrTk
		UNION ALL
		SELECT a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk  ,
		0 as NoPath,0 as TPathSales,0 as PathShare,
		Count(a.PCode) AS NoRadio , SUM(a.TSales) as TRadioSales,
		SUM(case when b.RadioAmtpcOrTk <> '%' THEN b.RadioAmt else a.TSales * 0.01 * b.RadioAmt END) AS RadioShare  ,
		0 as NoOthers,0 as TOtherSales, 0 as OthersShare ,
		0 as NOPD , 0 as TOPDSales , b.OPDTicket , b.OPDpcOrTk , 0 AS OPDShare,
		0 as NOTMorning , 0 as TOTMorningSales , b.MorningOT , b.MorningOTpcOrTk , 0 AS OTMorningShare ,
		0 as NOTEvening , 0 as TOEveningSales , b.EveningOT , b.EveningOTpcOrTk , 0 AS OTEveningShare ,
		0 as NProcedure , 0 as TProcedureSales , b.ProAmt , b.ProAmtpcOrTk , 0 AS ProcedureShare ,
		0 as NDrViist , 0 as TDrVisitSales , b.IPDVisit , b.IPDVisitpcOrTk , 0 AS VisitShare ,
		0 as NoofAdmittedPt
		FROM  #RadioSales a, DrWiseProfitShare b
		WHERE a.DrCode = b.DrCode 
		GROUP BY a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk,
		b.OPDTicket , b.OPDpcOrTk,b.MorningOT , b.MorningOTpcOrTk ,b.EveningOT , b.EveningOTpcOrTk ,
		b.ProAmt , b.ProAmtpcOrTk,b.IPDVisit , b.IPDVisitpcOrTk
		UNION ALL
		SELECT a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk  ,
		0 as NoPath,0 as TPathSales, 0 as PathShare ,
		0 as NoRadio,0 as TRadioSales, 0 as RadioShare ,
		Count(a.PCode) AS NoOthers , SUM(a.TSales) as TOthersSales,
		SUM(case when b.OtherspcOrTk <> '%' THEN b.Others else a.TSales * 0.01 * b.Others END) AS OthersShare  ,
		0 as NOPD , 0 as TOPDSales , b.OPDTicket , b.OPDpcOrTk , 0 AS OPDShare,
		0 as NOTMorning , 0 as TOTMorningSales , b.MorningOT , b.MorningOTpcOrTk , 0 AS OTMorningShare ,
		0 as NOTEvening , 0 as TOEveningSales , b.EveningOT , b.EveningOTpcOrTk , 0 AS OTEveningShare ,
		0 as NProcedure , 0 as TProcedureSales , b.ProAmt , b.ProAmtpcOrTk , 0 AS ProcedureShare,
		0 as NDrViist , 0 as TDrVisitSales , b.IPDVisit , b.IPDVisitpcOrTk , 0 AS VisitShare ,
		0 as NoofAdmittedPt 
		FROM  #OthersSales a, DrWiseProfitShare b
		WHERE a.DrCode = b.DrCode 
		GROUP BY a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk,
		b.OPDTicket , b.OPDpcOrTk,b.MorningOT , b.MorningOTpcOrTk ,b.EveningOT , b.EveningOTpcOrTk ,
		b.ProAmt , b.ProAmtpcOrTk,b.IPDVisit , b.IPDVisitpcOrTk
		UNION ALL
		SELECT a.DrCode, b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk  ,
		0 AS NoPath , 0 as TPathSales,
		0 AS PathShare ,
		0 as NoRadio,0 as TRadioSales, 0 as RadioShare ,
		0 as NoOthers,0 as TOtherSales, 0 as OthersShare ,
		count(*) as NOPD , SUM(c.Amount) as TOPDSales , b.OPDTicket , b.OPDpcOrTk , 
		SUM(case when b.OPDpcOrTk <> '%' THEN b.OPDTicket else c.Amount * 0.01 * b.OPDTicket END) AS OPDShare ,
		0 as NOTMorning , 0 as TOTMorningSales , b.MorningOT , b.MorningOTpcOrTk , 0 AS OTMorningShare ,
		0 as NOTEvening , 0 as TOEveningSales , b.EveningOT , b.EveningOTpcOrTk , 0 AS OTEveningShare ,
		0 as NProcedure , 0 as TProcedureSales , b.ProAmt , b.ProAmtpcOrTk , 0 AS ProcedureShare,
		0 as NDrViist , 0 as TDrVisitSales , b.IPDVisit , b.IPDVisitpcOrTk , 0 AS VisitShare ,
		0 as NoofAdmittedPt
		from OPDTicketMaster a , DrWiseProfitShare b ,#OPDTicket c  
		WHERE a.Id = c.OPDId and a.BranchId = c.BranchId AND a.BranchId=c.BranchId
		AND a.DrCode = b.DrCode 
		GROUP BY a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk,
		b.OPDTicket , b.OPDpcOrTk,b.MorningOT , b.MorningOTpcOrTk ,b.EveningOT , b.EveningOTpcOrTk ,
		b.ProAmt , b.ProAmtpcOrTk,b.IPDVisit , b.IPDVisitpcOrTk
		UNION ALL		
		SELECT a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk  ,
		0 as NoPath,0 as TPathSales,0 as PathShare,
		0 AS NoRadio , 0 as TRadioSales,0 AS RadioShare  ,
		0 as NoOthers,0 as TOtherSales, 0 as OthersShare ,
		0 as NOPD , 0 as TOPDSales , b.OPDTicket , b.OPDpcOrTk , 0 AS OPDShare,
		Count(a.Code) as NOTMorning , SUM(a.TSales) as TOTMorningSales , b.MorningOT , b.MorningOTpcOrTk , 
		SUM(case when b.MorningOTpcOrTk <> '%' THEN b.MorningOT else a.TSales * 0.01 * b.MorningOT END) AS OTMorningShare ,
		0 as NOTEvening , 0 as TOEveningSales , b.EveningOT , b.EveningOTpcOrTk , 0 AS OTEveningShare ,
		0 as NProcedure , 0 as TProcedureSales , b.ProAmt , b.ProAmtpcOrTk , 0 AS ProcedureShare ,
		0 as NDrViist , 0 as TDrVisitSales , b.IPDVisit , b.IPDVisitpcOrTk , 0 AS VisitShare ,
		0 as NoofAdmittedPt
		FROM  #OTMOrning a, DrWiseProfitShare b
		WHERE a.DrCode = b.DrCode 
		GROUP BY a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk,
		b.OPDTicket , b.OPDpcOrTk,b.MorningOT , b.MorningOTpcOrTk ,b.MorningOT , 
		b.MorningOTpcOrTk ,b.EveningOT , b.EveningOTpcOrTk ,b.ProAmt , b.ProAmtpcOrTk,b.IPDVisit , b.IPDVisitpcOrTk
		UNION ALL		
		SELECT a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk  ,
		0 as NoPath,0 as TPathSales,0 as PathShare,
		0 AS NoRadio , 0 as TRadioSales,0 AS RadioShare  ,
		0 as NoOthers,0 as TOtherSales, 0 as OthersShare ,
		0 as NOPD , 0 as TOPDSales , b.OPDTicket , b.OPDpcOrTk , 0 AS OPDShare,
		0 as NOTMorning , 0 as TOTMorningSales , b.MorningOT , b.MorningOTpcOrTk , 
		0 AS OTMorningShare ,
		Count(a.Code) as NOTEvening , SUM(a.TSales) as TOEveningSales , b.EveningOT , b.EveningOTpcOrTk , 
		SUM(case when b.EveningOTpcOrTk <> '%' THEN b.EveningOT else a.TSales * 0.01 * b.EveningOT END) AS OTEveningShare ,
		0 as NProcedure , 0 as TProcedureSales , b.ProAmt , b.ProAmtpcOrTk , 0 AS ProcedureShare ,
		0 as NDrViist , 0 as TDrVisitSales , b.IPDVisit , b.IPDVisitpcOrTk , 0 AS VisitShare ,
		0 as NoofAdmittedPt
		FROM  #OTEvening a, DrWiseProfitShare b
		WHERE a.DrCode = b.DrCode 
		GROUP BY a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk,
		b.OPDTicket , b.OPDpcOrTk,b.MorningOT , b.MorningOTpcOrTk ,b.MorningOT , 
		b.MorningOTpcOrTk ,b.EveningOT , b.EveningOTpcOrTk ,b.ProAmt , b.ProAmtpcOrTk,b.IPDVisit , b.IPDVisitpcOrTk
		UNION ALL
		SELECT a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk  ,
		0 as NoPath,0 as TPathSales,0 as PathShare,
		0 AS NoRadio , 0 as TRadioSales,0 AS RadioShare  ,
		0 as NoOthers,0 as TOtherSales, 0 as OthersShare ,
		0 as NOPD , 0 as TOPDSales , b.OPDTicket , b.OPDpcOrTk , 0 AS OPDShare,
		0 as NOTMorning , 0 as TOTMorningSales , b.MorningOT , b.MorningOTpcOrTk , 
		0 AS OTMorningShare ,
		0 as NOTEvening , 0 as TOEveningSales , b.EveningOT , b.EveningOTpcOrTk , 
		0 AS OTEveningShare ,
		Count(a.Code) as NProcedure , SUM(a.TSales) as TProcedureSales , b.ProAmt , b.ProAmtpcOrTk , 
		SUM(case when b.ProAmtpcOrTk <> '%' THEN b.ProAmt else a.TSales * 0.01 * b.ProAmt END) AS ProcedureShare ,
		0 as NDrViist , 0 as TDrVisitSales , b.IPDVisit , b.IPDVisitpcOrTk , 0 AS VisitShare ,
		0 as NoofAdmittedPt
		FROM  #Procedure a, DrWiseProfitShare b
		WHERE a.DrCode = b.DrCode 
		GROUP BY a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk,
		b.OPDTicket , b.OPDpcOrTk,b.MorningOT , b.MorningOTpcOrTk ,b.EveningOT , b.EveningOTpcOrTk ,
		b.ProAmt,b.ProAmtpcOrTk,b.IPDVisit , b.IPDVisitpcOrTk
		UNION ALL
		SELECT a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk  ,
		0 as NoPath,0 as TPathSales,0 as PathShare,
		0 AS NoRadio , 0 as TRadioSales,0 AS RadioShare  ,
		0 as NoOthers,0 as TOtherSales, 0 as OthersShare ,
		0 as NOPD , 0 as TOPDSales , b.OPDTicket , b.OPDpcOrTk , 0 AS OPDShare,
		0 as NOTMorning , 0 as TOTMorningSales , b.MorningOT , b.MorningOTpcOrTk , 
		0 AS OTMorningShare ,
		0 as NOTEvening , 0 as TOEveningSales , b.EveningOT , b.EveningOTpcOrTk , 
		0 AS OTEveningShare ,
		0 as NProcedure , 0 as TProcedureSales , b.ProAmt , b.ProAmtpcOrTk , 0 AS ProcedureShare ,
		Count(a.Code) as NDrViist , SUM(a.TSales) as TDrVisitSales , b.IPDVisit , b.IPDVisitpcOrTk , 
		SUM(case when b.IPDVisitpcOrTk <> '%' THEN b.IPDVisit else a.TSales * 0.01 * b.IPDVisit END) AS VisitShare ,
		0 as NoofAdmittedPt
		FROM  #DrVisit a, DrWiseProfitShare b
		WHERE a.DrCode = b.DrCode 
		GROUP BY a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk,
		b.OPDTicket , b.OPDpcOrTk,b.MorningOT , b.MorningOTpcOrTk ,b.EveningOT , b.EveningOTpcOrTk ,
		b.ProAmt,b.ProAmtpcOrTk,b.IPDVisit , b.IPDVisitpcOrTk
		UNION ALL
		SELECT a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk  ,
		0 as NoPath,0 as TPathSales,0 as PathShare,
		0 AS NoRadio , 0 as TRadioSales,0 AS RadioShare  ,
		0 as NoOthers,0 as TOtherSales, 0 as OthersShare ,
		0 as NOPD , 0 as TOPDSales , b.OPDTicket , b.OPDpcOrTk , 0 AS OPDShare,
		0 as NOTMorning , 0 as TOTMorningSales , b.MorningOT , b.MorningOTpcOrTk , 
		0 AS OTMorningShare ,
		0 as NOTEvening , 0 as TOEveningSales , b.EveningOT , b.EveningOTpcOrTk , 
		0 AS OTEveningShare ,
		0 as NProcedure , 0 as TProcedureSales , b.ProAmt , b.ProAmtpcOrTk , 0 AS ProcedureShare ,
		0 as NDrViist , SUM(a.TSales) as TDrVisitSales , b.IPDVisit , b.IPDVisitpcOrTk , 
		SUM(case when b.IPDVisitpcOrTk <> '%' THEN b.IPDVisit else a.TSales * 0.01 * b.IPDVisit END) AS VisitShare ,
		Count(a.Code) as NoofAdmittedPt
		FROM  #PatientAdmit a, DrWiseProfitShare b
		WHERE a.DrCode = b.DrCode 
		GROUP BY a.DrCode,b.PathAmt , b.PathAmtpcOrTk , b.RadioAmt  , b.RadioAmtpcOrTk,b.Others , b.OtherspcOrTk,
		b.OPDTicket , b.OPDpcOrTk,b.MorningOT , b.MorningOTpcOrTk ,b.EveningOT , b.EveningOTpcOrTk ,
		b.ProAmt,b.ProAmtpcOrTk,b.IPDVisit , b.IPDVisitpcOrTk) aa , drInfo bb , DrWiseProfitShare cc
		WHERE aa.DrCode = bb.DrCode AND bb.BranchId = @BranchId  and aa.DrCode = cc.DrCode and cc.BranchId = @BranchId 
		GROUP BY aa.DrCode,aa.PathAmt , aa.PathAmtpcOrTk , aa.RadioAmt  , aa.RadioAmtpcOrTk,aa.Others , aa.OtherspcOrTk,
		aa.OPDTicket , aa.OPDpcOrTk,aa.MorningOT , aa.MorningOTpcOrTk ,aa.EveningOT , aa.EveningOTpcOrTk ,
		aa.ProAmt , aa.ProAmtpcOrTk ,aa.IPDVisit,aa.IPDVisitpcOrTk , bb.DrName , cc.TDS ,cc.TDSPCorTk
		ORDER BY DrCode 
END
