CREATE procedure [dbo].[SP_DUE_INVOICE_REGISTER] @DateFrom nvarchar(20), @DateTo nvarchar(20), @BranchId INT, @unitId nvarchar(50), @DeptName VARCHAR(50), @PtStatus VARCHAR(20)
AS
BEGIN /* SP_DUE_INVOICE_REGISTER '2022-12-11','2022-12-15', 1, '1', 'DIAGNOSTIC' */

	select b.InvNo, b.InvDate, b.PatientId, b.PatientName Particulars, b.MobNo AS PPhone, b.RefDrCode, b.RefDrName, b.TotalAmt AS Sales, b.TotalLess AS Less, b.AdvanceAmt AS Paid, 
	(b.TotalAmt-b.TotalLess-b.AdvanceAmt-b.ReturnDue) AS Due, b.Comments, b.PtStatus, b.Remarks, b.UserName
	from InvMaster b
	where b.BranchId = @BranchId AND b.Valid = 1 
	and b.InvDate BETWEEN @DateFrom and @DateTo AND b.DeptName = @DeptName AND b.PtStatus LIKE '%'+@PtStatus+'%'
	AND (b.TotalAmt-b.TotalLess-b.AdvanceAmt-b.ReturnDue) != 0

	
	--select a.PrevInvNo InvNo, a.PreInvDate InvDate, a.PatientId, a.Particulars, a.PPhone, b.RefDrCode, b.RefDrName, sum(a.Sales) Sales, sum(a.Less) Less, sum(a.Collection) Paid, 
	--sum(a.Sales-a.Less-a.Collection-a.ReturnDue) Due, dbo.fncDiagRemarks(a.PrevInvNo, a.PreInvDate, a.BranchId) as Comments, a.PtStatus, b.Remarks, b.UserName
	--from SalesLedger a
	--LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.PreInvDate = b.InvDate AND a.PrevInvNo = b.InvNo
	--where a.BranchId = @BranchId AND a.Valid = 1 
	--and a.PreInvDate BETWEEN @DateFrom and @DateTo AND a.Department = @DeptName AND b.PtStatus LIKE '%'+@PtStatus+'%'
	--group by a.PrevInvNo, a.PreInvDate, a.PatientId, a.Particulars, a.PPhone, a.PtStatus, a.BranchId, b.RefDrCode, b.RefDrName, b.Remarks, b.UserName
	--having sum(a.Sales-a.Less-a.Collection-a.ReturnDue) != 0
END
