/****** Object:  StoredProcedure [dbo].[SP_EmpTrackingInfo]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROC [dbo].[SP_EmpTrackingInfo] @BranchId INT, @Date DATE
AS
BEGIN /* EXEC SP_EmpTrackingInfo 1, '2023-02-05' */
	SELECT SUM(TotalEmp) AS TotalEmp, SUM(PresentEmp) AS PresentEmp, SUM(LeaveEmp) AS LeaveEmp, SUM(TotalEmp-PresentEmp-LeaveEmp) AS AbsentEmp FROM(
		SELECT DISTINCT COUNT(Code) AS TotalEmp, 0 AS PresentEmp, 0 AS LeaveEmp, 0 AS AbsentEmp
		FROM HREmployeeMaster 
		WHERE Valid = 1 AND BranchId = @BranchId AND WorkingStatusId = 1
		UNION ALL
		SELECT DISTINCT 0 AS TotalEmp, COUNT(EmployeeCode) AS PresentEmp, 0 AS LeaveEmp, 0 AS AbsentEmp FROM
		(	
			SELECT DISTINCT EmployeeCode FROM HR_CardTime WHERE Valid = 1 AND CONVERT(VARCHAR, CardTime, 23) = @Date
		) a
		UNION ALL
		SELECT DISTINCT 0 AS TotalEmp, 0 AS PresentEmp, COUNT(EmpId) AS LeaveEmp, 0 AS AbsentEmp
		FROM EmpLeaveInfoDtls
		WHERE BranchId = @BranchId AND Valid = 1 AND LeaveFrom = @Date
		GROUP BY EmpId
	) a
END
GO
