CREATE procedure [dbo].[sp_FixedAsset_CalculateDepriciation] (@DateFrom date,@DateTo date)
AS 
DROP table tmpFixedAssetDepCal
BEGIN
	SELECT aa.AssetType,aa.DepMethod,aa.DepRate,  SUM(aa.OB) As OpeningAsset ,  SUM(aa.AddPurchase) AS AddPurchase , 
	SUM(aa.OB+aa.AddPurchase-aa.CarringAmt) as TotalAsset, 
	ROUND(SUM(aa.OPDep),0) as OPDep,ROUND(SUM(aa.CurrentDept),0) as CurrentYrDep  , 
	ROUND(sum(aa.OPDep+aa.CurrentDept),0) AS TotalDep ,
	ROUND(SUM(isnull(aa.OB,0)+ISNULL(aa.AddPurchase,0)-ISNULL(aa.OPDep,0)-ISNULL(aa.CurrentDept,0)-ISNULL(aa.CarringAmt,0)),0) AS BookValue,	SUM(CarringAmt) AS SalvaseValue, @DateFrom as DateFrom , @DateTo as DateTo
--	,aa.ACCode , aa.ACName ,aa.Depreciationcode,aa.DepreciationACName
	INTO tmpFixedAssetDepCal
	FROM (
	SELECT Purchasedate,AssetType , TotalPrice AS OB , (TotalPrice * 0.01 * DepRate * (year(@DateFrom)-year(Purchasedate))) as OPDep ,  
	0 as AddPurchase , 0 as CurrentDept , DepMethod,DepRate ,ACCode , ACName, 
	Depreciationcode,DepreciationACName , CarringAmt
	from FixedAssetRegister
	where valid = 1 
	and Purchasedate < @DateFrom
	and DepMethod = 'Straight Line'
	UNION ALL
	select Purchasedate , AssetType , 0 as OB , 0 as OBDep, TotalPrice AS Purchase, 
	(TotalPrice * 0.01 * (DepRate/12) * (12-MONTH(Purchasedate)+1)) as CurrentDept,DepMethod,DepRate,
	ACCode , ACName ,Depreciationcode,DepreciationACName ,CarringAmt
	from FixedAssetRegister
	where valid = 1 
	and Purchasedate BETWEEN @DateFrom and @DateTo 
	and DepMethod = 'Straight Line') aa
	GROUP BY aa.AssetType,aa.DepMethod,aa.DepRate
--	,aa.ACCode , aa.ACName ,aa.Depreciationcode,aa.DepreciationACName
	ORDER BY AssetType 
	
	
	--select a.Code,b.Description , SUM(CREDIT-DEBIT) as Bal
	--from transact a , ChartOfAcc b
	--where a.Code=b.Code 
	--and a.Code IN (SELECT DepreciationCode from FixedAssetRegister where valid = 1)
	--and a.Trans_dt < @DateFrom and a.VALID <> 0 
	--group by a.Code,b.Description

	
	
END







GO
