CREATE PROC [dbo].[SP_FixedAssetIssueAgainstReq](@ReqNo nvarchar(50), @ReqDate date, @UnitId int, @BranchId int)
AS ---- exec SP_FixedAssetIssueAgainstReq 'GI231000001', '2023-10-05', 1, 1 
BEGIN
select a.ReqNo, a.ReqDate, a.GinNo, a.GinDate, a.IssueTo, a.Note, b.ProductCode, b.ProductName, ISNULL(b.IssueToDtls,'') AS Details,
 SUM(b.ReqInQty) AS Total_ReqQty, SUM(b.ReqApprovedQty) as AppQty, SUM(b.ReqOutQty) AS IssueQty,
 SUM(b.ReqInQty - b.ReqOutQty) AS Pending_Qty
from FixedAssetProductIssueMain a, FixedAssetReqLedger b
WHERE a.ReqNo= b.PrevReqNo AND a.ReqDate = b.PrevReqDate AND a.Valid = 1 and b.Valid = 1 AND a.GinNo = @ReqNo AND a.GinDate = @ReqDate
AND a.UnitId = b.UnitId AND a.BranchId = b.BranchId AND a.UnitId = @UnitId AND a.BranchId = @BranchId
GROUP BY a.ReqNo, a.ReqDate, a.GinNo, a.GinDate, a.IssueTo, a.Note, b.ProductCode, b.ProductName, b.IssueToDtls
END
GO
