CREATE PROCEDURE [dbo].[SP_FixedAssetProductIssuingReportDtls] 
(@BranchId int, @UnitId int, @datefrom date, @dateto date, @StoreName nvarchar(20), @Category nvarchar(50), @IssueDeptName nvarchar(50), @ProductCode nvarchar(20) ) 
AS
BEGIN /* SP_FixedAssetProductIssuingReportDtls 1, 1, '2023-09-01', '2023-09-07', '', '', '', ''  */
	SELECT a.storeName,  a.ProductCode, a.ProductName, a.Unit, a.IssueDeptName AS Department,
	 sum(a.OutQty) as OutQty, sum(a.PPrice*a.OutQty) AS TotalAmt
	FROM FixedAssetStockLedger a
	LEFT JOIN FixedAssetRegister b ON a.ProductCode = b.AssetCode
	WHERE a.Valid=1 AND b.Valid = 1 AND a.UnitId = @UnitId AND a.BranchId = @BranchId AND TrDate BETWEEN @datefrom AND @dateto AND a.OutQty <> 0 
	AND (a.StoreName+ b.AssetType + ISNULL(a.IssueDeptName,'') + a.ProductCode) LIKE '%'+@StoreName +'%'+ @Category +'%'+ @IssueDeptName +'%'+ @ProductCode +'%'	
	GROUP BY  a.storeName,  a.ProductCode, a.ProductName, a.Unit,  a.IssueDeptName
	ORDER BY ProductCode
END
GO
