CREATE PROCEDURE [dbo].[SP_FixedAssetProductReceiveReport] (@BranchId int,  @UnitId int,  @datefrom date, @dateto date, @StoreName nvarchar(20), @Category nvarchar(50), @SupplierCode nvarchar(10),  @ProductCode nvarchar(20)) 
AS
BEGIN /* EXEC SP_FixedAssetProductReceiveReport  1, 1, '2023-08-01', '2023-08-01','', '', '' ,''  */

	SELECT a.storeName, a.TrDate, a.TrNo, a.InvoiceNo, a.InvoiceDate, a.supplierid, a.SupplierName, a.ProductCode, a.ProductName,  a.Unit, a.BatchNo, ISNULL(a.ExpDate, '1990-01-01') AS ExpDate, a.PPrice, a.InQty, (a.PPrice * a.InQty) as TotalAmt, b.AssetType
        FROM FixedAssetStockLedger a LEFT JOIN FixedAssetRegister b ON a.ProductCode = b.AssetCode
        WHERE a.Valid=1 AND b.Valid = 1 AND a.UnitId = @UnitId AND a.BranchId = @BranchId AND a.InQty <> 0 
        AND (a.StoreName+ b.AssetType + a.SupplierId + a.ProductCode) LIKE '%'+@StoreName +'%'+ @Category +'%' +@SupplierCode+'%'+ @ProductCode +'%' AND TrDate BETWEEN @datefrom AND @dateto
END
GO
/****** Object:  StoredProcedure [dbo].[SP_FixedAssetProductReceiveReportDtls]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SP_FixedAssetProductReceiveReportDtls] (@BranchId int, @UnitId int, @datefrom date, @dateto date, @StoreName nvarchar(20), @Category nvarchar(50), @SupplierCode nvarchar(10), @ProductCode nvarchar(20) ) 
AS
BEGIN /* EXEC SP_FixedAssetProductReceiveReportDtls 1, 1, '2023-11-01', '2023-11-31', '', '', '' ,'' */

		SELECT a.storeName, a.ProductCode, a.ProductName, a.SupplierId, a.SupplierName,
		a.Unit, (case when SUM(a.InQty) <> 0 then (SUM(a.PPrice * a.InQty)/SUM(a.InQty)) end ) as PPrice, SUM(a.InQty) AS InQty, 
		SUM(a.PPrice * a.InQty) as TotalAmt, b.AssetType, a.UserName, a.EntryDateTime
		FROM FixedAssetStockLedger a
		LEFT JOIN FixedAssetRegister b ON a.ProductCode = b.AssetCode
		WHERE a.Valid=1 AND b.Valid = 1 AND a.BranchId = @BranchId AND a.UnitId = @UnitId  
	        AND TrDate BETWEEN @datefrom AND @dateto
		AND a.InQty <> 0 
		AND (a.StoreName + b.AssetType + a.SupplierId + a.ProductCode) LIKE '%'+@StoreName +'%'+ @Category+'%'+@SupplierCode +'%'+@ProductCode +'%'		
		GROUP BY a.storeName, a.ProductCode, a.ProductName,  a.SupplierId, a.SupplierName, a.Unit, b.AssetType, a.UserName, a.EntryDateTime
		ORDER BY b.AssetType, a.ProductName
END
GO
/****** Object:  StoredProcedure [dbo].[SP_FixedAssetProductReceivingReportSMZ]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SP_FixedAssetProductReceivingReportSMZ] (@BranchId int, @UnitId int, @datefrom date, @dateto date, @StoreName nvarchar(20), @Category nvarchar(50), @SupplierCode nvarchar(10), @ProductCode nvarchar(20)) 
AS
BEGIN  /* EXEC SP_FixedAssetProductReceivingReportSMZ 1, 1, '2023-08-01', '2023-12-01', '', '', '' ,'' */
		SELECT a.storeName, a.SupplierId, a.SupplierName,
		ROUND((case when SUM(a.InQty) <> 0 then (SUM(a.PPrice * a.InQty)/SUM(a.InQty)) end),2) as PPrice, SUM(a.InQty) AS InQty, 
		SUM(a.PPrice * a.InQty) as TotalAmt, b.AssetType
		FROM FixedAssetStockLedger a
		LEFT JOIN FixedAssetRegister b ON a.ProductCode = b.AssetCode
		WHERE a.Valid=1 AND b.Valid = 1 AND a.BranchId = @BranchId AND a.UnitId = @UnitId  
	        AND TrDate BETWEEN @datefrom AND @dateto
		AND a.InQty <> 0 
		AND (a.StoreName + b.AssetType + a.SupplierId + a.ProductCode) LIKE '%'+@StoreName +'%'+ @Category+'%'+@SupplierCode +'%'+@ProductCode +'%'
		GROUP BY a.storeName, b.AssetType, a.SupplierId, a.SupplierName
		ORDER BY b.AssetType
END
GO
