CREATE PROC [dbo].[SP_FixedAssetProIssueWithoutReq](@TrNo nvarchar(50), @TrDate date, @UnitId int, @BranchId int)
AS
BEGIN /* EXEC SP_FixedAssetProIssueWithoutReq 'FWR231100001', '2023-11-09', 1, 1  */
	Select a.TrNo, a.TrDate, a.FromUnit, a.FromStore, a.ToUnit, a.ToStore, a.ProductCode, a.ProductName, a.Unit, a.BatchNo, ISNULL(a.ExpDate, '') AS ExpDate, a.IssueQty, 
	a.Note, b.AssetType, a.Price, a.TotalAmt, a.ReqNo, ISNULL(a.ReqDate, '') AS ReqDate, a.UserName
	FROM FixedAssetProIssueWithoutReq a
	LEFT JOIN FixedAssetRegister b ON a.BranchId = b.BranchId AND a.ProductCode = b.AssetCode
	WHERE a.Valid = 1 AND a.TrNo= @TrNo AND a.TrDate= @TrDate
	AND a.UnitId = @UnitId AND a.BranchId = @BranchId
END
