CREATE PROCEDURE  [dbo].[SP_FixedAssetPurReqReport] (@ReqFrom nvarchar(50), @dateFrom date , @dateto date, @UnitId int, @BranchId int) 
AS
BEGIN
	if @ReqFrom <> '' 
		BEGIN
			SELECT a.ReqDate , a.ReqNo , b.EDD , b.ProductCode , b.ProductName , b.ReqQty , b.Details , 
			a.ReqFrom  , a.EntryDateTime , a.UserName AS PostedBy 
			FROM FixedAssetPurReqMain a , FixedAssetPurReqDetails b
			WHERE a.ReqNo = b.ReqNo AND a.ReqDate = b.ReqDate AND a.Valid = 1 AND b.Valid = 1
			AND a.UnitId = b.UnitId AND a.BranchId = b.BranchId AND a.UnitId = @UnitId AND a.BranchId = @BranchId
			AND a.ReqDate BETWEEN @dateFrom  AND @dateto 
			AND a.ReqFrom = @ReqFrom
		END
	ELSE
		BEGIN
			SELECT a.ReqDate , a.ReqNo , b.EDD , b.ProductCode , b.ProductName , b.ReqQty , b.Details , 
			a.ReqFrom  , a.EntryDateTime , a.UserName AS PostedBy 
			FROM FixedAssetPurReqMain a , FixedAssetPurReqDetails b
			WHERE a.ReqNo = b.ReqNo AND a.ReqDate = b.ReqDate AND a.Valid = 1 AND b.Valid = 1
			AND a.UnitId = b.UnitId AND a.BranchId = b.BranchId AND a.UnitId = @UnitId AND a.BranchId = @BranchId
			AND a.ReqDate BETWEEN @dateFrom  AND @dateto 
		END
END
