CREATE PROC [dbo].[SP_FixedAssetReqApproval](@TrNo nvarchar(50), @TrDate date, @UnitId int, @BranchId int)
AS --- EXEC SP_FixedAssetReqApproval 'RA251100001', '',1,1
BEGIN
	Select a.TrNo,a.TrDate,a.ReqFrom,a.Department, a.PrevReqNo,a.PrevReqDate,a.UserName, b.ProductCode,b.ProductName, b.IssueToDtls, b.Unit,
	b.ReqQty as ReqInQty, b.ApprovedQty as ReqApprovedQty, Isnull(SUM((c.InQty+c.RtnQty+c.BonusQty)-(c.PRtnQty+C.OutQty)),0) AS CurrentStock
	From FixedAssetReqApprovalMain a
	Left Join FixedAssetReqApprovalDetails b On a.BranchId=b.BranchId And a.TrNo=b.ReqNo And b.Valid=1
	Left Join FixedAssetStockLedger c On a.BranchId=c.BranchId AND b.ProductCode=c.ProductCode And c.Valid=1
	Where a.BranchId=@BranchId And a.TrNo=@TrNo
	GROUP BY a.TrNo,a.TrDate,a.ReqFrom,a.Department, a.PrevReqNo,a.PrevReqDate,a.UserName, b.ProductCode,b.ProductName, b.IssueToDtls, b.Unit, b.ReqQty, b.ApprovedQty
	
--select a.TrNo,a.TrDate,a.ReqFrom,a.Department, a.PrevReqNo,a.PrevReqDate,a.UserName, b.ProductCode,b.ProductName, b.IssueToDtls, b.Unit, b.ReqQty as ReqInQty, b.ApprovedQty as ReqApprovedQty, SUM((c.InQty+c.RtnQty+c.BonusQty)-(c.PRtnQty+C.OutQty)) AS CurrentStock from FixedAssetReqApprovalMain a, FixedAssetReqApprovalDetails b, FixedAssetStockLedger c WHERE a.TrNo = b.ReqNo AND a.TrDate = b.ReqDate AND b.ProductCode = c.ProductCode AND a.Valid = 1 AND b.Valid = 1 ANd c.Valid = 1 AND a.TrNo = @TrNo AND a.TrDate = @TrDate AND a.UnitId = b.UnitId AND a.UnitId = c.UnitId AND a.BranchId = b.BranchId AND a.BranchId = c.BranchId AND a.UnitId = @UnitId AND a.BranchId = @BranchId
--GROUP BY a.TrNo,a.TrDate,a.ReqFrom,a.Department, a.PrevReqNo,a.PrevReqDate,a.UserName, b.ProductCode,b.ProductName, b.IssueToDtls, b.Unit, b.ReqQty, b.ApprovedQty

END
