CREATE PROCEDURE [dbo].[SP_FixedProductIssuingReports] 
(@BranchId int, @UnitId int, @datefrom date, @dateto date, @StoreName nvarchar(20), @Category nvarchar(50), @IssueDeptName nvarchar(50), @ProductCode nvarchar(20) ) 
AS
BEGIN /* EXEC  SP_FixedProductIssuingReports 1, 1, '2023-01-01', '2023-12-01', '', '',  '', ''  */
	SELECT a.storeName,a.TrDate, a.TrNo, a.InvoiceNo, a.InvoiceDate, a.ProductCode, a.ProductName, a.Unit,
	a.BatchNo,  ISNULL(a.ExpDate, '1990-01-01') AS ExpDate, a.PPrice, a.OutQty,(a.PPrice*a.OutQty) AS TotalAmt, 
	a.ReqFrom AS IssueTo, a.IssueDeptName AS Department, a.IssueToDtls, b.AssetType, a.UserName, a.EntryDateTime
	FROM FixedAssetStockLedger a
	LEFT JOIN FixedAssetRegister b ON a.ProductCode = b.AssetCode
	WHERE a.Valid=1 AND b.Valid = 1 AND a.UnitId = @UnitId AND a.BranchId = @BranchId AND a.OutQty <> 0 
	AND (a.StoreName+ b.AssetType + ISNULL(a.IssueDeptName,'') + a.ProductCode) LIKE '%'+@StoreName +'%'+ @Category +'%'+@IssueDeptName +'%'+ @ProductCode +'%' AND TrDate BETWEEN @datefrom AND @dateto
	ORDER BY a.TrNo, a.TrDate
END
GO
