CREATE PROCEDURE [dbo].[SP_FixedProductIssuingReportSMZ] 
(@BranchId int, @UnitId int, @datefrom date, @dateto date, @StoreName nvarchar(20), @Category nvarchar(50), @IssueDeptName nvarchar(50), @ProductCode nvarchar(20) ) 
AS
BEGIN /* SP_FixedProductIssuingReportSMZ 1, 1, '2023-01-01', '2023-12-01', '', '', '', ''  */
	SELECT a.storeName, b.AssetType, a.IssueDeptName AS Department, sum(a.OutQty) as IssueQty, sum(a.PPrice*a.OutQty) AS TotalA	 
	FROM FixedAssetStockLedger a
	LEFT JOIN FixedAssetRegister b ON a.ProductCode = b.AssetCode
	WHERE a.Valid=1 AND b.Valid = 1 AND a.UnitId = @UnitId AND a.BranchId = @BranchId AND a.OutQty <> 0 
	AND (a.StoreName+ b.AssetType + ISNULL(a.IssueDeptName,'') + a.ProductCode) LIKE '%'+@StoreName +'%'+ @Category +'%'+@IssueDeptName +'%'+ @ProductCode +'%'
	AND TrDate BETWEEN @datefrom AND @dateto
	GROUP BY  a.storeName, a.IssueDeptName , b.AssetType
	ORDER BY AssetType
END
GO
