			SUM(aa.CB) AS CB , SUM(aa.CBamt) AS CBAmt , ROUND(isnull((Case when SUM(aa.CB) <> 0 then SUM(aa.CBamt) / SUM(aa.CB) end),0),2) As TP
			FROM (
			select StoreName,ProductCode ,0 as OB, 0 as OBAmt,  (ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0)) as InQty,
			((ISNULL(InQty,0)*PPrice)+(ISNULL(RtnQty,0)*PPrice)+(ISNULL(BonusQty,0)*PPrice)) as InAmt  , 
