			AND bb.AssetType LIKE '%'+@ProductCategory + '%'
			GROUP BY aa.storeName , bb.AssetType,  aa.ProductCode , bb.ProductName , bb.Unit 
			HAVING SUM(aa.CB) <> 0
		END
	ELSE
		BEGIN
			SELECT aa.storeName , bb.AssetType,  aa.ProductCode , bb.ProductName , bb.Unit , 
			SUM(aa.OB) AS OB , SUM(aa.OBAmt) AS OBAmt , SUM(aa.InQty) As InQty , SUM(aa.InAmt) AS InAmt , 
			SUM(aa.OutQty) AS OutQty , SUM(aa.OutAmt) OutAmt ,
