Create PRoc [dbo].[SP_GastroRevenueDistributionInvoice] @Id int
As
Begin
	Select a.RefNo, a.RefDate, a.InvNo, a.InvDate, a.MobileNo, a.RegNo, a.PatientName, a.Age, a.PtStatus, a.Gender, a.TotalAmount,
	a.LessAmount, a.Receive, a.Due, a.DistributeAmount, a.HospitalAmount, a.HospitalAmountType, a.HospitalTotal, a.ConsultantCode,
	a.ConsultantName, a.ConsultantAmount, a.ConsultantAmountType, a.ConsultantTotal, a.Remarks, a.UserName, a.EntryDateTime,
	b.PCode, b.Description, b.DrCode, b.DrName, b.Amount
	from GastroRevenueDistributionMaster a
	Left Join GastroRevenueDistributionDetails b On a.Id=b.MasterId and b.Valid=1
	Where a.Valid=1 and a.Id=@Id
End
