--05112025

CREATE Proc [dbo].[SP_GastroRevenueDistributionReport] @BranchId Int, @DateFrom Date, @DateTo Date
AS
Begin
	SELECT a.BranchId, a.RefNo, a.PCode,
		DrNames = (
			SELECT DISTINCT b.DrName+ ' ('+Convert(varchar, b.Amount)+') ' + ', ' FROM GastroRevenueDistributionDetails b 
			WHERE b.PCode = a.PCode ANd a.BranchId=b.BranchId And a.RefNo=b.RefNo
			FOR XML PATH('')
		),
		SUM(a.Amount) AS TotalAmount
		Into #z
	FROM GastroRevenueDistributionDetails a
	Where a.Valid=1 And a.BranchId=@BranchId And a.RefDate Between @DateFrom and @DateTo
	GROUP BY a.BranchId, a.PCode, RefNo

	Select a.BranchId, a.RefNo, b.InvNo, b.InvDate, b.RefDate, b.MobileNo, b.RegNo, b.PatientName, b.PtStatus, b.TotalAmount,
	b.LessAmount, b.Receive, b.HospitalAmount, b.HospitalAmountType, b.HospitalTotal, b.ConsultantCode, b.ConsultantName,
	b.ConsultantAmount, b.ConsultantAmountType, b.ConsultantTotal, b.Remarks,
	Max(AnesthesiaName) As AnesthesiaName, Sum(AnesthesiaAmt) As AnesthesiaAmt, Max(AssistantName) AS AssistantName, Sum(AssistantAmt) As AssistantAmt,
	SUm(MedicineAmt) As MedicineAmt
	, TestName = (
			SELECT DISTINCT z.ShortDesc + ', ' FROM InvDetails z 
			WHERE z.InvNo=b.InvNo ANd z.BranchId=a.BranchId
			FOR XML PATH('')
		)
	From
	(
		Select BranchId, RefNo, DrNames AS AnesthesiaName, TotalAmount AS AnesthesiaAmt, Space(500) As AssistantName,
		0 As AssistantAmt, 0 As MedicineAmt
		from #z Where BranchId=1 And PCode='6712'
		Union All
		Select BranchId, RefNo, Space(500) As AnesthesiaName, 0 AS AnesthesiaAmt, DrNames As AssistantName,
		TotalAmount As AssistantAmt, 0 As MedicineAmt
		from #z Where BranchId=1 And PCode='0005'
		Union All
		Select BranchId, RefNo, Space(500) As AnesthesiaName, 0 AS AnesthesiaAmt,Space(500) As AssistantName,
		0 As AssistantAmt, TotalAmount As MedicineAmt
		from #z Where BranchId=1 And PCode='5358'
	) a
	Inner Join GastroRevenueDistributionMaster b On a.BranchId=b.BranchId And a.RefNo=b.RefNo
	Where b.Valid=1 And b.BranchId=@BranchId And b.RefDate between @DateFrom and @DateTo
	Group by a.BranchId, a.RefNo, b.InvNo, b.InvDate, b.RefDate, b.MobileNo, b.RegNo, b.PatientName, b.PtStatus, b.TotalAmount,
	b.LessAmount, b.Receive, b.HospitalAmount, b.HospitalAmountType, b.HospitalTotal, b.ConsultantCode, b.ConsultantName,
	b.ConsultantAmount, b.ConsultantAmountType, b.ConsultantTotal, b.Remarks
END
GO
