CREATE PROCEDURE [dbo].[SP_GENERATE_BED_CHARGE]
AS
BEGIN

	-- Normal Bed
	insert into PatientLedger (RefDate, RefNo, PatientId, RegNo, PatientName, BedNo, Code, Unit, NoU, Charge, ServiceCharge, 
	TotalAmount, Less, DrCode, DrName, Particulars, DrAmount, Collection, ReturnAmt, Adjust, CashAmt, CardAmt, ChequeAmt, CardNo, 
	CardBank, ChequeNo, ChequeBank, ChequeDate, IsRelease, Status, Valid, RowId, UserName, 
	IsAcTransfer, TrNo, TrDate, Remarks)
	select GETDATE(), 'TR'+CONVERT(NVARCHAR(10),(SELECT MAX(SUBSTRING(refno,3,20))
	FROM PatientLedger where Code='0002')+ ROW_NUMBER() OVER(ORDER BY (SELECT 1))) as RefNo, a.PatientId, a.RegNo, a.PatientName, a.BedNo,
	'0002', 1, 1, b.ChargePerDay, (b.ChargePerDay* b.ServiceCharge*0.01),
	(b.ChargePerDay+(b.ChargePerDay* b.ServiceCharge*0.01)), 0, a.UnderDrCode, a.UnderDrName, 'Bed Charge', 0, 0, 0, 0, 0, 0, 0, '',
	'', '', '', NULL, 0, 'Auto Generate', 1, 1, 'Auto', 0, '', GETDATE(), ''
	from PatientAdmission a, BedInformation b
	where a.IsRelease = 1 AND a.BedNo = b.BedNo AND a.BedNo not in (select bedno from PatientLedger 
	where RefDate = convert(nvarchar(20),GETDATE(),23) And Code = '0002' And Valid = 1 And isRelease =0)

	--For Ref No Normal Bed
	------SELECT 'TR'+CONVERT(NVARCHAR(10),(SELECT MAX(SUBSTRING(refno,3,20))
	------FROM PatientLedger where Code='0002' and RefNo LIKE 'TR'+'%')+ ROW_NUMBER() OVER(ORDER BY (SELECT 1))) as trno FROM PatientLedger

	--Extra Bed
	insert into PatientLedger (RefDate, RefNo, PatientId, RegNo, PatientName, BedNo, Code, Unit, NoU, Charge, ServiceCharge, 
	TotalAmount, Less, DrCode, DrName, Particulars, DrAmount, Collection, ReturnAmt, Adjust, CashAmt, CardAmt, ChequeAmt, CardNo, 
	CardBank, ChequeNo, ChequeBank, ChequeDate, IsRelease, Status, Valid, RowId, UserName, 
	IsAcTransfer, TrNo, TrDate, Remarks)
	select GETDATE(), 'TR'+CONVERT(NVARCHAR(10),(SELECT MAX(SUBSTRING(refno,3,20))
	FROM PatientLedger where Code='0002' and RefNo LIKE 'TR'+'%')+ ROW_NUMBER() OVER(ORDER BY (SELECT 1))) as RefNo, 
	a.PatientId, a.RegNo, c.PatientName , a.BedNo,
	'0002', 1, 1, b.ChargePerDay, (b.ChargePerDay* b.ServiceCharge*0.01),
	(b.ChargePerDay+(b.ChargePerDay* b.ServiceCharge*0.01)), 0, c.UnderDrCode, c.UnderDrName, 'Bed Charge', 0, 0, 0, 0, 0, 0, 0, '',
	'', '', '', NULL, 0, 'Auto Generate', 1, 1, 'Auto', 0, '', GETDATE(), ''
	from PatientExtraBed a, BedInformation b, PatientAdmission c
	where a.IsRelease = 0 AND a.BedNo = b.BedNo and a.PatientId = c.PatientId AND a.BedNo not in (select bedno from PatientLedger 
	where RefDate = convert(nvarchar(20),GETDATE(),23) And Code = '0002' And Valid = 1 And isRelease =0)

	----------For Ref No Extra Bed
	--------select 'TR'+CONVERT(NVARCHAR(10),(SELECT MAX(SUBSTRING(refno,3,20))
	--------FROM PatientLedger where Code='0002' and RefNo LIKE 'TR'+'%')+ ROW_NUMBER() OVER(ORDER BY (SELECT 1))) as RefNo from PatientLedger
END



GO
