CREATE PROC [dbo].[Sp_GenerateBrockerPolicy] @MasterId INT, @BranchId INT, @DeptName VARCHAR(50), @SubDeptName VARCHAR(50)
AS
BEGIN -- EXEC Sp_GenerateBrockerPolicy 1, 1, '', ''
	INSERT INTO BrokerPolicySetupDtls(MasterId, BranchId, BrokerCode, PCode, Charge, Discount, PcOrTk, UserName, LogDtls, EntryDateTime)
	SELECT a.Id, a.BranchId, a.BrokerCode, b.PCode, b.Charge, a.Discount, a.PcOrTk, a.UserName, a.LogDtls, a.EntryDateTime 
	FROM BrokerPolicySetupMaster a
	RIGHT JOIN ClinicalChart b ON b.BranchId = a.BranchId AND b.DeptName = a.DeptName AND b.SubSubDeptName = a.SubDeptName and b.Status = 1
	WHERE a.BranchId = @BranchId AND a.Id = @MasterId AND b.DeptName = @DeptName AND b.SubSubDeptName = @SubDeptName
END
GO
