CREATE PROC [dbo].[SP_GenerateDiscountCardItemDtls] @SlNo INT, @Id INT, @DeptName NVARCHAR(50), @SubDeptName NVARCHAR(50), @CardTypeId INT, @DiscountAmt int, @PcorTk NVARCHAR(10), @UserName NVARCHAR(100), @BranchId INT
AS /* EXEC SP_GenerateDiscountCardItemDtls '10', 4, 'Medicine', 'Medicine', 4, '5', '%','admin', 1 */
BEGIN
	--UPDATE DiscountCardRegistration SET Valid = 0, LogDtls = 'Cancel For Update By ' + @UserName +' '+ convert(nvarchar(30), getdate(), 23)
	--WHERE BranchId = @BranchId AND Valid = 1 AND CardTypeId = @CardTypeId AND DeptName = @DeptName AND SubDeptName = @SubDeptName

	----drop table DiscountCardRegistration_CancelHistory
	----select * INTO DiscountCardRegistration_CancelHistory from DiscountCardRegistration
	----delete from  DiscountCardRegistration_CancelHistory where Valid = 1
	----delete from DiscountCardRegistration where valid = 0

	INSERT INTO DiscountCardRegistration_CancelHistory(SlNo, Id, CardTypeId, PCode, DeptName, SubDeptName, Description, 
	Charge, Amount, PcOrTk, Valid, UserName, EntryDateTime,LogDtls,BranchId) 
	SELECT SlNo, Id, CardTypeId, PCode, DeptName, SubDeptName, Description, 
	Charge, Amount, PcOrTk, Valid, @UserName, EntryDateTime, 'Cancel For Update By ' + @UserName ,BranchId
	FROM DiscountCardRegistration
	WHERE BranchId = @BranchId AND Valid = 1 AND CardTypeId = @CardTypeId AND DeptName = @DeptName AND SubDeptName = @SubDeptName 
	--AND SubDeptName = @SubDeptName

	DELETE FROM DiscountCardRegistration 
	WHERE BranchId = @BranchId AND CardTypeId = @CardTypeId AND DeptName = @DeptName AND SubDeptName = @SubDeptName

	INSERT INTO DiscountCardRegistration(SlNo, Id, CardTypeId, PCode, DeptName, SubDeptName, Description, 
	Charge, Amount, PcOrTk, Valid, UserName, EntryDateTime,LogDtls,BranchId) 
	SELECT @SlNo, @Id, @CardTypeId, PCode, DeptName, SubDeptName, Description, 
	Charge, @DiscountAmt, @PcorTk, 1, @UserName,
	GETDATE(), 'FromSP', BranchId
	FROM ClinicalChart
	WHERE BranchId = @BranchId AND DeptName = @DeptName AND SubDeptName = @SubDeptName and CorporateLess = 1
	UNION ALL
	SELECT @SlNo, @Id, @CardTypeId, Convert(varchar, 999999), 'Medicine', 'Medicine', 'Medicine', 
	0, @DiscountAmt, @PcorTk, 1, @UserName, Getdate(), 'FromSP', @BranchId
	FROM tbl_ComInfo WHERE @DeptName='Medicine'

	--DELETE FROM DiscountCardRegistration 
	--WHERE BranchId = @BranchId AND CardTypeId = @CardTypeId AND DeptName = @DeptName AND SubDeptName = @SubDeptName

	--INSERT INTO DiscountCardRegistration(SlNo, Id, CardTypeId, PCode, DeptName, SubDeptName, Description, Charge, Amount, PcOrTk, Valid, UserName, EntryDateTime,LogDtls,BranchId) 
	--SELECT @SlNo, @Id, @CardTypeId, PCode, DeptName, SubSubDeptName, Description, Charge, @DiscountAmt, @PcorTk, 1, @UserName,
	--GETDATE(), 'FromSP', BranchId
	--FROM ClinicalChart
	--WHERE BranchId = @BranchId AND DeptName = @DeptName AND SubSubDeptName = @SubDeptName and CanGiveLess = 1
END
