CREATE PROC [dbo].[SP_GenerateDrHonorarium](@dateFrom nvarchar(50), @dateTo date, @BranchId int, @UnitId int)
AS
BEGIN
	EXEC SP_CalculateDRHonorium @dateFrom, @dateTo, '', 0, @BranchId
	INSERT INTO DrHonorariumLedger (RefDrCode, DrName, Tel, InvNo, InvDate, PatientName, MobNo, InvstName, Path, PathCom, ELISA, ElisaCom, USG, USGCom, CTScan,
	CTScanCom, XRay, XRayCom, BMD, BMDCom, ECG, ECGCom, ECHO, ECHOCom, EEG, EEGCom, ETT, ETTCom, MRI, MRICom, OTHERS, OTHERSCom, TotalSales, LessAmt, LessByDr,
	DueAmt, TotalHonorarium, Remarks, PaidDate, InvPaidDate, BranchId)
	SELECT RefDrCode, DrName, Tel, InvNo, InvDate, PatientName, MobNo, InvstName, Path, PathCom, ELISA, ElisaCom, USG, USGCom, CTScan,
	CTScanCom, XRay, XRayCom, BMD, BMDCom, ECG, ECGCom, ECHO, ECHOCom, EEG, EEGCom, ETT, ETTCom, MRI, MRICom, OTHERS, OTHERSCom, TotalSales, LessAmt, LessByDr,
	DueAmt, PathCom+ElisaCom+USGCom+CTScanCom+XRayCom+BMDCom+ECGCom+ECHOCom+EEGCom
+ETTCom+MRICom+OTHERSCom AS TotalHonorarium, ISNULL(Remarks,'') as Remarks, null AS PaidDate, PaidDate, BranchId FROM tmpDrCommForWeb
	where DueAmt = 0
	UPDATE InvDetails set isPaidDrComm = 1 WHERE InvNo IN (SELECT InvNo FROM tmpDrCommForWeb WHERE DueAmt = 0 GROUP BY InvNo)
	UPDATE SalesLedger set isPaid = 1 WHERE PrevInvNo IN (SELECT InvNo FROM tmpDrCommForWeb WHERE DueAmt = 0 GROUP BY InvNo)
END

-----
GO
