CREATE Proc [dbo].[Sp_GenerateGeneralRosterByEmployeeCode] @GenBranchId INT, @GenCode VARCHAR(20), @EmpBranchId INT, @EmpCode VARCHaR(30), @StartDate DATETIME, @EndDate DateTime
AS
BEGIN -- EXEC Sp_GenerateGeneralRosterByEmployeeCode 1, '80320', 1, '80344', '2024-09-01', '2024-09-10'

	delete from EmployeeRosterDetails where BranchId = @EmpBranchId AND Code = @EmpCode and RosterDate between @StartDate and @EndDate
	
	INSERT INTO EmployeeRosterDetails (EmpId, ShiftStatus, DayName, GeneralShift, RosterDate, TimeFrom, TimeTo, row_Id, UserLogs, Valid, 
	PNO, UnitId, BranchId, UserName, IPAddress, Code, DeptCode, DeptName, DesigCode, Designation)

	select a.EmpId, b.ShiftStatus, b.DayName, b.GeneralShift, b.RosterDate, b.TimeFrom, b.TimeTo, b.row_Id, b.UserLogs, 1 AS Valid, 
	1 AS Pno, a.UnitId, a.BranchId, 'Auto' AS UserName, '' AS IpAddress, a.Code, a.DeptCode, a.Department, a.DesigCode, a.Designation 
	from HREmployeeMaster a 
	left join EmployeeRosterDetails b on b.BranchId = @GenBranchId and b.Code = @GenCode
	where a.BranchId = @EmpBranchId AND a.Code = @EmpCode and b.RosterDate between @StartDate and @EndDate and b.valid = 1 
	order by b.row_Id
END
GO
