CREATE procedure [dbo].[sp_GenerateRosterDetails] (@datefrom date,@dateTo date)
AS  ---EXEC sp_GenerateRosterDetails '2024-01-01' , '2024-01-31'

DECLARE @cnt INT = 1;
DECLARE @diff int = 0;
SELECT @diff = DATEDIFF (day,@datefrom ,@dateto)+1;

delete from EmployeeRosterDetails where RosterDate BETWEEN @datefrom and @dateTo 

WHILE @cnt < @diff
BEGIN
--   PRINT 'Inside simulated FOR LOOP on TechOnTheNet.com' + cast(@cnt as nvarchar(20));

	INSERT INTO EmployeeRosterDetails (EmpId , ShiftStatus , DayName ,
	GeneralShift , PNO,RosterDate , row_Id,code,DesigCode , Designation   )
	select empid , 'YES',datename(WEEKDAY ,dateadd(d,@cnt,@datefrom)),'','' as pno,dateadd(d,@cnt,@datefrom),0 ,
	Code ,DesigCode , Designation
	from HREmployeeMaster 
	where WorkingStatus  = 'Working'  
    SET @cnt = @cnt + 1;

	UPDATE EmployeeRosterDetails SET ShiftStatus = b.GeneralShift 
	FROM EmployeeRosterDetails a , EmployeeGroupInfo  b
	WHERE a.EmpId = b.EmpId and a.DayName = b.DayName 
END
