CREATE PROC [dbo].[SP_GET_BAL] (@Pno AS Int,@dateFrom AS date,@dateTo AS date)AS
BEGIN
DELETE FROM tmpBL
INSERT INTO  tmpBL (GMain, slno, GPSl,Code, Description, Balance)
SELECT 1 AS GMain, 2 AS slno, 2 as GPSl, a.Code,b.Description,SUM(Debit-Credit) AS Balance
FROM tbl_TRANSACT a 
LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code=b.Code
WHERE b.Type='Balance Sheet'
AND SUBSTRING(a.Code,1,1) IN ('2')
AND a.Trans_dt<=@dateTo --dateTo
AND a.Pno=@Pno
GROUP By a.Code,b.Description
UNION ALL
SELECT 2 As GMain ,12 AS slno,2 as GPSl, a.Code,b.Description,SUM(Credit-Debit) AS Balance
FROM tbl_TRANSACT a 
LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code=b.Code
WHERE b.Type='Balance Sheet'
AND SUBSTRING(a.Code,1,1) IN ('1')
AND a.Trans_dt<=@dateTo--dateTo
AND a.Pno=@Pno
GROUP By a.Code,b.Description
UNION ALL 
SELECT 1,6,2,'21050001','CLOSING STOCK' AS Particulars,Isnull(SUM(InQty*PurchasePrice-OutQty*PurchasePrice+RtnQty*PurchasePrice-PRtnQty*PurchasePrice),0) AS Bal
FROM tbl_STOCK_LEDGER WHERE TrDate<=@dateTo AND Valid=1 AND Pno=@Pno
UNION ALL 
SELECT 2,12,2,'15060001',Description,Bal  
FROM tmpPLFinal 
WHERE slno =5

INSERT INTO  tmpBL (GMain, slno, GPSl,Code, Description, Balance)
SELECT 2,12,2,'15060001','Unadjusted Profit /Loss',SUM(aa.bal)
from (
SELECT SUM(Balance) as bal
from tmpBL
where gmain=1
UNION ALL 
SELECT (SUM(Balance) *(-1)) as bal
from tmpBL
where gmain=2) aa

-------- Details --------------------
SELECT GMain,slno,GPSl,Code,Description,Balance 
FROM tmpBL  WHERE Balance>0
UNION ALL
SELECT 1,1,1,b.Code,b.Description,SUM(Balance) 
FROM tmpBL a , tbl_CHART_OF_ACCOUNTS b
where SUBSTRING(a.code,1,4)+'0000' = b.Code 
and a.slno=2
GROUP BY b.Code,b.Description
UNION ALL
SELECT 2,11,1,b.Code,b.Description,SUM(Balance) 
FROM tmpBL a , tbl_CHART_OF_ACCOUNTS b
where SUBSTRING(a.code,1,4)+'0000' = b.Code 
and a.slno=12
GROUP BY b.Code,b.Description
UNION ALL
SELECT 1,4,3,'29999999','TOTAL PROPERTY AND ASSET',SUM(Balance)
FROM tmpBL
where GMAIN=1
UNION ALL
SELECT 2,15,3,'19999999','TOTAL CAPITAL AND LIABILITY',SUM(Balance)
FROM tmpBL
where GMAIN=2
UNION ALL
SELECT 1,1,1,'','PROPERTY AND ASSET' ,0 
UNION ALL
SELECT 2,10,1,'','CAPITAL AND LIABILITY' ,0 

ORDER BY GMain,Code,slno
END
DELETE FROM tmpBL WHERE Balance=0






GO
