CREATE PROC [dbo].[SP_GET_INVOICENO] (@StockType Int,@Pno Int)   AS
IF @StockType=1
BEGIN
SELECT 'PI'+
RIGHT('00' + Convert(varchar,DAY(Getdate())), 2)+
RIGHT('00' + Convert(varchar,MONTH(Getdate())), 2)+
RIGHT('00' + Convert(varchar,YEAR(GETDATE())), 2) +
RIGHT('00000'+ Convert(varchar,ISNULL(Max(Convert(integer, RIGHT(InvoiceNo, 5))),0)+ 1), 5) AS InvNo
FROM tbl_STOCK_IN_MAIN  WHERE YEAR(GETDATE())=YEAR(GetDate()) AND Pno=@Pno
END
IF @StockType=2
BEGIN
SELECT  'SI'+
RIGHT('00' + Convert(varchar,DAY(Getdate())), 2)+
RIGHT('00' + Convert(varchar,MONTH(Getdate())), 2)+
RIGHT('00' + Convert(varchar,YEAR(GETDATE())), 2) +
RIGHT('00000'+ Convert(varchar,ISNULL(Max(Convert(integer, RIGHT(InvoiceNo, 5))),0)+ 1), 5)
AS InvNo
FROM tbl_SALES_MAIN  WHERE YEAR(GETDATE())=YEAR(GetDate()) AND Pno=@Pno
END
IF @StockType=3
BEGIN
SELECT 'DP'+RIGHT('00' + Convert(varchar,YEAR(GETDATE())), 2) +
RIGHT('00' + Convert(varchar,MONTH(Getdate())), 2) +
RIGHT('00000'+ Convert(varchar,ISNULL(Max(Convert(integer, RIGHT(TrNo, 5))),0)+ 1), 5) AS InvNo
FROM tbl_DUE_PAYMENT  WHERE YEAR(GETDATE())=YEAR(GetDate()) AND Pno=@Pno
END
IF @StockType=4
BEGIN
SELECT 'ST'+ RIGHT('00' + Convert(varchar,YEAR(GETDATE())), 2) +
RIGHT('00' + Convert(varchar,MONTH(Getdate())), 2) +
RIGHT('00000'+ Convert(varchar,ISNULL(Max(Convert(integer, RIGHT(InvoiceNo, 5))),0)+ 1), 5) AS InvNo
FROM tbl_STOCK_TRANSFER_INFO  WHERE YEAR(GETDATE())=YEAR(GetDate()) AND Pno=@Pno
END
IF @StockType=14
BEGIN
SELECT  'DC'+RIGHT('00' + Convert(varchar,YEAR(GETDATE())), 2) +
RIGHT('00' + Convert(varchar,MONTH(Getdate())), 2) +
RIGHT('00000'+ Convert(varchar,ISNULL(Max(Convert(integer, RIGHT(TrNo, 5))),0)+ 1), 5) AS InvNo
FROM tbl_DUE_COLLECTION  WHERE YEAR(GETDATE())=YEAR(GetDate()) AND Pno=@Pno
END

IF @StockType=5
BEGIN
SELECT 'PRI'+  
RIGHT('00' + Convert(varchar,DAY(Getdate())), 2)+
RIGHT('00' + Convert(varchar,MONTH(Getdate())), 2)+
RIGHT('00' + Convert(varchar,YEAR(GETDATE())), 2) +
RIGHT('00000'+ Convert(varchar,ISNULL(Max(Convert(integer, RIGHT(InvoiceNo, 5))),0)+ 1), 5) AS InvNo
FROM tbl_STOCK_RETURN_MASTER  WHERE YEAR(GETDATE())=YEAR(GetDate()) AND Pno=@Pno
END
IF @StockType=19
BEGIN
SELECT  'SR'+RIGHT('00' + Convert(varchar,YEAR(GETDATE())), 2) +
RIGHT('00' + Convert(varchar,MONTH(Getdate())), 2) +
RIGHT('00000'+ Convert(varchar,ISNULL(Max(Convert(integer, RIGHT(InvoiceNo, 5))),0)+ 1), 5) AS InvNo
FROM tbl_SALES_RETURN_MASTER  WHERE YEAR(GETDATE())=YEAR(GetDate()) AND Pno=@Pno
END

IF @StockType=22
BEGIN
SELECT 'OB'+ 
RIGHT('00' + Convert(varchar,DAY(Getdate())), 2)+
RIGHT('00' + Convert(varchar,MONTH(Getdate())), 2)+
RIGHT('00' + Convert(varchar,YEAR(GETDATE())), 2) +
RIGHT('00000'+ Convert(varchar,ISNULL(Max(Convert(integer, RIGHT(TrNo, 5))),0)+ 1), 5) AS InvNo
FROM tbl_STOCK_LEDGER WHERE LEFT(TrNo,2)='OB'  AND YEAR(GETDATE())=YEAR(GetDate()) AND Pno=@Pno
END
IF @StockType=23
BEGIN
SELECT 'ST'+ RIGHT('00' + Convert(varchar,YEAR(GETDATE())), 2) +
RIGHT('00' + Convert(varchar,MONTH(Getdate())), 2) +
RIGHT('00000'+ Convert(varchar,ISNULL(Max(Convert(integer, RIGHT(TrNo, 5))),0)+ 1), 5) AS InvNo
FROM tbl_STOCK_LEDGER WHERE LEFT(TrNo,2)='ST'  AND YEAR(GETDATE())=YEAR(GetDate()) AND Pno=@Pno
END

IF @StockType=24
BEGIN
SELECT 'SD'+  RIGHT('00' + Convert(varchar,YEAR(GETDATE())), 2) +
RIGHT('00' + Convert(varchar,MONTH(Getdate())), 2) +
RIGHT('00000'+ Convert(varchar,ISNULL(Max(Convert(integer, RIGHT(InvoiceNo, 5))),0)+ 1), 5) AS InvNo
FROM tbl_STOCK_DAMAGE  WHERE YEAR(GETDATE())=YEAR(GetDate()) AND Pno=@Pno
END

IF @StockType=25
BEGIN
SELECT RIGHT('00' + Convert(varchar,YEAR(GETDATE())), 2) +
RIGHT('00' + Convert(varchar,MONTH(Getdate())), 2) +
RIGHT('00000'+ Convert(varchar,ISNULL(Max(Convert(integer, RIGHT(TrNo, 5))),0)+ 1), 5) AS InvNo
FROM tbl_SPECIAL_PRICE_INSTITUTE  WHERE YEAR(GETDATE())=YEAR(GetDate()) AND Pno=@Pno
END




GO
