SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[SP_GET_INVOICEWISE_REPORT](@dateFrom As DateTime , @dateTo As DateTime,@custId As int) AS
IF @custId=0 
SELECT a.InvoiceDate,a.InvoiceNo,a.CustId,b.Name As CustName,SUM(a.TotalAmount) AS SalesAmount,SUM(a.LessAmount) AS InvoiceDiscount,SUM(a.CardAmount) AS CardAmount,SUM(a.CashAmount) AS CashAmount,SUM(a.LessAmount) AS SpecialDiscount
FROM tbl_SALES_MAIN a 
LEFT JOIN tbl_CUSTOMER b ON a.CustId=b.Id 
WHERE a.InvoiceDate Between @dateFrom AND @dateTo
GROUP BY a.InvoiceDate,a.InvoiceNo,a.CustId,b.Name
IF @custId!=0
SELECT a.InvoiceDate,a.InvoiceNo,a.CustId,b.Name As CustName,SUM(a.TotalAmount) AS SalesAmount,SUM(a.LessAmount) AS InvoiceDiscount,SUM(a.CardAmount) AS CardAmount,SUM(a.CashAmount) AS CashAmount,SUM(a.LessAmount) AS SpecialDiscount
FROM tbl_SALES_MAIN a 
LEFT JOIN tbl_CUSTOMER b ON a.CustId=b.Id 
WHERE a.InvoiceDate Between  @dateFrom AND @dateTo AND a.CustId=@custId
GROUP BY a.InvoiceDate,a.InvoiceNo,a.CustId,b.Name






GO
