CREATE PROC [dbo].[SP_Get_LabReportView] @InvNo nvarchar(20), @InvDate date, @Department nvarchar(20), @PCode nvarchar(20), @branchId int, @mailStatus int
AS
BEGIN /* EXEC SP_Get_LabReportView 'DIA240200054', '2024-02-05', 'Hematology', '', 1, 0 */
	SELECT @mailStatus AS MailStatus, a.InvNo, a.InvDate, c.LabNo, c.PCode, c.Parameter, c.AliasNo, c.Result, c.Unit, c.NormalValue, c.ReportingGroupName,
	c.GroupSlNo, c.SerialNo, c.EntrDateTime, a.TestList AS ShortDesc, c.UserName, c.ReportHeaderName, c.IsBold, c.IsPrint, c.Method, b.PatientName, b.Age, b.Sex, b.Address,
	b.MobNo, b.RefDrCode, b.RefDrName, b.ConsultantCode as DrCode, b.ConsultantName+' '+j.Degree as DrName, j.Degree as DrDegree, b.BedNo, b.PtStatus, a.Advise, a.Comments, 
	ISNULL(d.VerifyDateTime, GETDATE()) aS RptDeliveryDate, d.RptDeliveryTime AS RptDeliveryTime,
	a.ReportNo, '' AS ReportFileName, b.CollTime AS InvCollTime, i.CollTime, i.CollUser, i.ReceiveInLabTime, i.ReceiveInLabUser,
	b.PatientId, b.RegNo, e.SignImg AS EsPreparedImg, f.SignImg AS EsCheckedImg, g.SignImg AS EsConsultantImg, h.SignImg AS LabInchargeImg,
	a.CheckedByName, a.CheckedByDegree, a.ConsultantName, a.ConsultantDegree, a.LabInChargeName, a.LabInchargeDegree, a.PreparedByName, a.PreparedByDegree, d.Verify, d.VerifyDateTime, d.VerifyUser,
	STUFF((
			SELECT distinct ',' +  CONVERT(varchar, n.Specimen) FROM lab_MachineDataDtls m 
			LEFT JOIN lab_Parameter_Definition n ON m.PCode=n.TestCode AND m.Result != '' AND m.InvNo=@InvNo where m.ReportFileName = @Department FOR XML PATH('')
		), 1, 1, ''
	) as Specimen

	FROM lab_MachineDataMaster a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo AND a.InvDate = b.InvDate
	LEFT JOIN lab_MachineDataDtls c ON a.BranchId = c.BranchId AND a.InvNo = c.InvNo AND a.InvDate = c.InvDate AND a.ReportNo = c.ReportNo
	LEFT JOIN InvDetails d ON a.BranchId = d.BranchId AND a.InvNo = d.InvNo AND a.InvDate = d.InvDate AND a.PCode = d.PCode
	LEFT JOIN LabSignatureDrInfo e ON a.PreparedId = e.Id AND a.ESPrepared = 1
	LEFT JOIN LabSignatureDrInfo f ON a.CheckedId = f.Id AND a.ESChecked = 1
	LEFT JOIN LabSignatureDrInfo g ON a.ConsultantId = g.Id AND a.ESConsultant = 1
	LEFT JOIN LabSignatureDrInfo h ON a.LabInchargeId = h.Id AND a.ESLabIncharge = 1
	LEFT JOIN Lab_SampleStatusInfo i ON i.BranchId = a.BranchId AND i.InvNo = a.InvNo AND i.TestCode = a.PCode
	LEFT JOIN DrInfo j ON j.DrCode = b.ConsultantCode
	WHERE a.BranchId = @branchId AND a.InvNo = @InvNo AND a.InvDate = @InvDate AND a.PCode LIKE '%'+@PCode+'%' AND c.ReportFileName = @Department
	AND LTRIM(c.Result)<>'' AND LTRIM(c.Parameter)<>''
END
GO
