CREATE PROC [dbo].[SP_Get_LabReportView_All] @InvNo nvarchar(20), @InvDate date, @Department nvarchar(20), @PCode nvarchar(20), @branchId int, @mailStatus int
AS
BEGIN /* EXEC SP_Get_LabReportView 'DIA230400007', '2023-04-05', 'Hematology', '', 1, 5 */
SELECT @mailStatus AS MailStatus, a.InvNo, a.InvDate, c.LabNo, c.PCode, c.Parameter, c.AliasNo, c.Result, c.Unit, c.NormalValue, c.ReportingGroupName,
c.GroupSlNo, c.SerialNo, c.EntrDateTime, a.TestList AS ShortDesc, c.UserName, c.ReportHeaderName, c.IsBold, c.IsPrint,b.PatientName, b.Age, b.Sex,
b.MobNo, b.ConsultantCode as DrCode, b.ConsultantName as DrName, b.BedNo, b.PtStatus, a.Advise, a.Comments, d.RptDeliveryDate, a.ReportNo, '' AS ReportFileName,
b.PatientId, b.RegNo, e.SignImg AS EsPreparedImg, f.SignImg AS EsCheckedImg, g.SignImg AS EsConsultantImg, h.SignImg AS LabInchargeImg,
a.CheckedByName, a.CheckedByDegree, a.ConsultantName, a.ConsultantDegree, a.LabInChargeName, a.LabInchargeDegree, a.PreparedByName, a.PreparedByDegree,
(SELECT DISTINCT Specimen FROM lab_Parameter_Definition WHERE TestCode = a.PCode) AS Specimen 
FROM lab_MachineDataMaster a
LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo AND a.InvDate = b.InvDate
LEFT JOIN lab_MachineDataDtls c ON a.BranchId = c.BranchId AND a.InvNo = c.InvNo AND a.InvDate = c.InvDate AND a.ReportNo = c.ReportNo
LEFT JOIN InvDetails d ON a.BranchId = d.BranchId AND a.InvNo = d.InvNo AND a.InvDate = d.InvDate AND a.PCode = d.PCode
LEFT JOIN LabSignatureDrInfo e ON a.PreparedId = e.Id AND a.ESPrepared = 1
LEFT JOIN LabSignatureDrInfo f ON a.CheckedId = f.Id AND a.ESChecked = 1
LEFT JOIN LabSignatureDrInfo g ON a.ConsultantId = g.Id AND a.ESConsultant = 1
LEFT JOIN LabSignatureDrInfo h ON a.LabInchargeId = h.Id AND a.ESLabIncharge = 1
WHERE a.InvNo = @InvNo AND a.InvDate = @InvDate AND a.PCode LIKE '%'+@PCode+'%' AND c.ReportFileName = @Department
AND LTRIM(c.Result)<>'' AND LTRIM(c.Parameter)<>''
END

GO
