CREATE PROC [dbo].[SP_Get_LabReportView_Deptwise] @PatientId nvarchar(20), @reportfileName nvarchar(20), @branchId int
AS
BEGIN /* EXEC SP_Get_LabReportView_Deptwise 'PA240100053', 'Biochemistry', 1 */
	SELECT 1 AS MailStatus, 'DIA'+a.InvNo AS InvNo, a.InvDate, c.LabNo, c.TestCode AS PCode, c.Parameter, c.AliasNo, c.Result, c.Unit, c.NormalValue, c.ReportingGroupName,
	c.GroupSlNo, c.SerialNo, c.EntryDate AS EntrDateTime, a.TestNameReport AS ShortDesc, c.UserName, c.ReportHeaderName, c.IsBold, c.IsPrint,b.PatientName, b.Age, b.Sex,
	b.MobNo, b.ConsultantCode as DrCode, b.ConsultantName as DrName, b.BedNo, b.PtStatus, '' AS Advise, a.Comments, d.RptDeliveryDate, a.ReportNo, '' AS ReportFileName,
	b.PatientId, b.RegNo,-- '' AS EsPreparedImg, ''  AS EsCheckedImg, ''  AS EsConsultantImg, '' AS LabInchargeImg,
	a.CheckedByName, a.CheckedByDegree, a.ConsultantName, a.ConsultantDegree, a.LabInChargeName, a.LabInchargeDegree, '' AS PreparedByName, '' AS PreparedByDegree,
	(SELECT DISTINCT Specimen FROM lab_Parameter_Definition WHERE TestCode = d.PCode) AS Specimen 
	FROM LabDb.dbo.tb_MachineDataMaster a
	LEFT JOIN InvMaster b ON 'DIA'+a.InvNo=b.InvNo
	LEFT JOIN LabDb.dbo.tb_MachineDataDtls c ON a.InvNo=c.InvNo AND a.ReportNo=c.ReportNo
	LEFT JOIN LabDb.dbo.tb_VacutainerSetup e ON c.TestCode=e.ItemId
	LEFT JOIN InvDetails d ON 'DIA'+a.InvNo=d.InvNo AND e.MasterCode = d.PCode
	WHERE b.PatientId = @PatientId AND c.ReportFileName = @reportfileName
	AND LTRIM(c.Result)<>'' AND LTRIM(c.Parameter)<>''
	ORDER BY a.InvNo
END

GO
