CREATE PROC [dbo].[SP_GET_LEDGER] (@pno int,@code nvarchar(50), @dateFrom date,@dateTo date)AS
BEGIN
select 2 as SlNo, a.ContraCode , b.Description ,Isnull(a.Trans_dt,GETDATE()) AS  Trans_dt, a.TrNo ,  a.Naration , a.Remark , a.Debit , a.Credit,
0 as OPBL,a.code  ,c.Description as MainAC  , 0000000000 as CumBal
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b ,tbl_CHART_OF_ACCOUNTS c
where a.ContraCode = b.code  and a.Valid = 1  and a.code =c.code AND a.Pno=@pno
and a.ContraCode = @code
and a.Trans_dt BETWEEN @dateFrom and @dateTo
UNION ALL
select 1 as SlNo, a.code , b.Description ,GetDate(), '',  'Opening Balance'  , 'Opening Balance' , 0,0,
(CASE WHEN LEFT(a.code,1) IN ('1','3') then SUM(a.Credit-a.Debit) else SUM(a.Debit-a.Credit) END) AS OPBL,a.code ,c.Description as MainAC ,0
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b , tbl_CHART_OF_ACCOUNTS c 
where a.code = b.code  and a.Valid = 1 AND a.Pno=@pno
and a.ContraCode = @code
and a.code =c.code 
and a.Trans_dt < @dateFrom
GROUP BY a.code , b.Description ,c.Description
ORDER BY slNo , code 
END





GO
