CREATE PROC [dbo].[SP_GET_PATIENT_FOR_DISCHARGE_CERTIFICATE] (@patientId as nvarchar(20))
AS
Begin


SELECT a.PatientId, a.PatientName, a.AdmissionDate, a.AdmissionTime, a.PatientSex, a.PatientAge, a.ReleaseDate, DATEDIFF(day, AdmissionDate, ReleaseDate) Days, a.ReleaseTimeRemarks, a.PatientAddress, a.Religion, a.Phone1, a.UnderDrName, a.BedNo, ISNULL((b.OTNote),'') OTNote, aa.InvsName, bb.MedicineName
FROM PatientAdmission a left join tbl_OTSettlementMaster b on a.PatientId = b.PatientId,
(
SELECT PatientId, InvsName = STUFF((
SELECT ','+space(1)+ ShortDesc
From InvDetails where PatientId = a.PatientId and RegNo = a.RegNo and PtStatus = 'Indoor' and Valid = 1
FOR XML PATH ('')), 1, 1, '' )
from InvDetails a 
where a.Valid = 1 and a.PatientId like '%'+@patientId+'%'
group by PatientId, RegNo
) aa,
(
SELECT a.PatientId, MedicineName = STUFF((
SELECT ','+space(1)+ ProductName
From PharSalesDetails where PatientId = a.PatientId and RegNo = a.RegNo and PtStatus = 'Indoor' and Valid = 1
FOR XML PATH ('')), 1, 1, '' )
from PharSalesDetails a
where a.valid = 1 and a.PatientId Like '%'+@patientId+'%'
group by a.PatientId, a.RegNo
) bb
WHERE a.Valid=1
AND a.IsRelease=1 and a.PatientId Like '%'+@patientId+'%'
group by
a.PatientId, a.PatientName, a.AdmissionDate, a.AdmissionTime, a.PatientSex, a.PatientAge, a.ReleaseDate, a.ReleaseTimeRemarks, a.PatientAddress, a.Religion, a.Phone1, a.UnderDrName, a.BedNo, b.OTNote, aa.InvsName, bb.MedicineName


end




