CREATE PROC [dbo].[SP_GET_PATIENT_LEDGER] (@PatientId AS varchar(20), @BranchId int, @UnitId int)AS
BEGIN

select a.Code, a.Particulars, a.DrCode, a.DrName, a.Charge, SUM(a.NoU) as qty, sum(a.TotalAmount) as TotalAmount, sum(a.Less) Less, 
sum(a.ServiceCharge) ServiceCharge 
from PatientLedger as a 
where --a.Charge>0 and 
a.PatientId=@PatientId and a.Valid = 1 AND a.BranchId = @BranchId AND a.CostCenterName = @UnitId and a.Status <> 'Advance Collection'
group by a.Code, a.Particulars, a.DrCode, a.DrName, a.Charge
UNION ALL
select '0011' as Code, 'Diagnosis Bill' as Particulars, '' as DrCode, '' as DrName, ISNULL(SUM(Sales-ReturnAmount),0) as Charge, 1 as Qty,
ISNULL(SUM(Sales-ReturnAmount),0) as TotalAmount, ISNULL(SUM(Less),0) as Less, 0 ServiceCharge
from SalesLedger where Valid <> 0 AND BranchId = @BranchId AND CostCenterName = @UnitId and PatientId = @PatientId having ISNULL(SUM(Sales-ReturnAmount),0) > 0
---Start Monsur Ali Hide
UNION ALL
SELECT '0009' as Code, 'Medicine Bill' as Particulars, '-' as DrCode, '-' as DrName, ISNULL(SUM(a.SalePrice*a.ProductQty),0) as Charge, '1' as qty, 
ISNULL(SUM(a.SalePrice*a.ProductQty),0) as TotalAmount, (select sum(LessAmt) 
from PharSalesMaster where PatientID=b.PatientId AND BranchId = b.BranchId)as Less, isnull(c.ServiceCharge,0)
from PharSalesDetails a left join PharSalesMaster as b on a.SaleNo=b.SaleNo AND a.BranchId = b.BranchId left join ClinicalChart as c on c.PCode='9998' 
where b.PatientID=@PatientId and a.Valid <> 0 AND a.BranchId = @BranchId AND a.CostCenterName = @UnitId
group by  c.ServiceCharge, c.SCPcorTk, b.PatientId, b.BranchId
-----END
UNION ALL
SELECT '0038' as Code, 'Ambulance Bill' as Particulars, '-' as DrCode, '-' as DrName, ISNULL(SUM(a.TotalCharge),0) as Charge, '1' as qty, 
ISNULL(SUM(a.TotalCharge),0) as TotalAmount, SUM(a.Less)as Less, 0 as ServiceCerge
from AmbulanceMaster a
where a.PatientId=@PatientId and a.Valid <> 0 AND a.CostCenterName = @UnitId
HAVING ISNULL(SUM(a.TotalCharge),0) > 0 
END

------
GO
