CREATE PROC [dbo].[SP_GET_PURCHASE_LEDGER] (@pno int ,@suppId int,@dateFrom datetime,@dateTo dateTime) AS


IF @suppId=0
BEGIN
SELECT 0 AS Id,'-' AS TrNo,@dateFrom AS TrDate,'-' AS InvoiceNo,@dateFrom AS InvoiceDate,'-' AS ReceiptNo,@dateFrom As  ReceiptDate,a.SuppId ,b.Name AS SuppName,b.Address,b.MobileNo,0 AS PurchaseAmt,0 AS PaymentAmount,SUM(a.PayableAmount-a.PaymentAmount-a.ReturnAmount) AS BalAmt,0 AS ReturnAmount, 'O/B' AS Status ,a.Pno 
FROM tbl_PURCHASE_LEDGER a LEFT JOIN tbl_SUPPLIER_INFO_MASTER b ON a.SuppId=b.Id 
LEFT JOIN tbl_STOCK_IN_MAIN c ON c.InvoiceNo=a.TrNo AND c.Pno=a.Pno WHERE a.TrDate < @dateFrom AND a.Pno=@pno
GROUP BY a.SuppId,b.Name,b.Address,b.MobileNo,a.Pno
UNION ALL
SELECT a.Id,a.TrNo,a.TrDate,a.InvoiceNo,a.InvoiceDate,c.ReceiptNo,c.ReceiptDate,a.SuppId ,b.Name AS SuppName,b.Address,b.MobileNo,a.PayableAmount AS PurchaseAmt,a.PaymentAmount,0 AS BalAmt,a.ReturnAmount,a.Status ,a.Pno 
FROM tbl_PURCHASE_LEDGER a LEFT JOIN tbl_SUPPLIER_INFO_MASTER b ON a.SuppId=b.Id 
LEFT JOIN tbl_STOCK_IN_MAIN c ON c.InvoiceNo=a.TrNo AND c.Pno=a.Pno WHERE a.TrDate BETWEEN @dateFrom AND @dateTo AND a.Pno=@pno
END
ELSE
BEGIN
SELECT 0 AS Id,'-' AS TrNo,@dateFrom AS TrDate,'-' AS InvoiceNo,@dateFrom AS InvoiceDate,'-' AS ReceiptNo,@dateFrom ReceiptDate,a.SuppId ,b.Name AS SuppName,b.Address,b.MobileNo,0 AS PurchaseAmt,0 AS PaymentAmount,SUM(a.PayableAmount-a.PaymentAmount-a.ReturnAmount) AS BalAmt,0 AS ReturnAmount,'O/B' AS Status ,a.Pno 
FROM tbl_PURCHASE_LEDGER a LEFT JOIN tbl_SUPPLIER_INFO_MASTER b ON a.SuppId=b.Id 
LEFT JOIN tbl_STOCK_IN_MAIN c ON c.InvoiceNo=a.TrNo AND c.Pno=a.Pno WHERE a.TrDate < @dateFrom AND a.Pno=@pno AND a.SuppId=@suppId
GROUP BY a.SuppId,b.Name,b.Address,b.MobileNo,a.Pno
UNION ALL
SELECT a.Id,a.TrNo,a.TrDate,a.InvoiceNo,a.InvoiceDate,c.ReceiptNo,c.ReceiptDate,a.SuppId ,b.Name AS SuppName,b.Address,b.MobileNo,a.PayableAmount AS PurchaseAmt,a.PaymentAmount,0 AS BalAmt,a.ReturnAmount,a.Status ,a.Pno 
FROM tbl_PURCHASE_LEDGER a LEFT JOIN tbl_SUPPLIER_INFO_MASTER b ON a.SuppId=b.Id 
LEFT JOIN tbl_STOCK_IN_MAIN c ON c.InvoiceNo=a.TrNo AND c.Pno=a.Pno WHERE a.TrDate BETWEEN @dateFrom AND @dateTo AND a.Pno=@pno AND a.SuppId=@suppId
END










GO
