CREATE PROC [dbo].[SP_GET_SALES_LEDGER] (@pno int ,@custId int,@dateFrom datetime,@dateTo dateTime) AS
IF @custId=0
BEGIN
SELECT 0 AS Id,'-' AS TrNo,@dateFrom AS TrDate,'-' AS InvoiceNo,@dateFrom AS InvoiceDate,a.CustId ,b.Name AS CustName,b.Address,b.MobileNo,0 AS SalesAmt,0 AS LessAmt,0 AS CollAmt,SUM(a.SalesAmount-a.LessAmount-a.CollectionAmount-a.ReturnAmount) AS BalAmt,0 AS ReturnAmount,0 AS CashReturnAmount, 'O/B' AS Status ,a.Pno 
FROM tbl_SALES_LEDGER a LEFT JOIN tbl_CUSTOMER b ON a.CustId=b.Id WHERE a.Valid=1 AND a.TrDate < @dateFrom AND a.Pno=@pno
GROUP BY a.CustId,b.Name,b.Address,b.MobileNo,a.Pno
UNION ALL
SELECT a.Id,a.TrNo,a.TrDate,a.InvoiceNo,a.InvoiceDate,a.CustId ,b.Name AS CustName,b.Address,b.MobileNo,a.SalesAmount AS SalesAmt,a.LessAmount AS LessAmt,a.CollectionAmount AS CollAmt,0 AS BalAmt,a.ReturnAmount,a.CashReturnAmount,c.Name AS Status ,a.Pno 
FROM tbl_SALES_LEDGER a LEFT JOIN tbl_CUSTOMER b ON a.CustId=b.Id LEFT JOIN tbl_SALES_COLLECTION_STATUS_INFO c ON a.SalesCollStatus=c.Id 
WHERE a.Valid=1 AND  a.TrDate BETWEEN @dateFrom AND @dateTo AND a.Pno=@pno
END
ELSE
BEGIN
SELECT 0 AS Id,'-' AS TrNo,@dateFrom AS TrDate,'-' AS InvoiceNo,@dateFrom AS InvoiceDate,a.CustId ,b.Name AS CustName,b.Address,b.MobileNo,0 AS SalesAmt,0 AS LessAmt,0 AS CollAmt,SUM(a.SalesAmount-a.LessAmount-a.CollectionAmount-a.ReturnAmount) AS BalAmt,0 AS ReturnAmount,0 AS CashReturnAmount, 'O/B' AS Status ,a.Pno 
FROM tbl_SALES_LEDGER a LEFT JOIN tbl_CUSTOMER b ON a.CustId=b.Id WHERE a.Valid=1 AND a.TrDate < @dateFrom AND a.Pno=@pno AND a.CustId=@custId
GROUP BY a.CustId,b.Name,b.Address,b.MobileNo,a.Pno
UNION ALL
SELECT a.Id,a.TrNo,a.TrDate,a.InvoiceNo,a.InvoiceDate,a.CustId ,b.Name AS CustName,b.Address,b.MobileNo,a.SalesAmount AS SalesAmt,a.LessAmount AS LessAmt,a.CollectionAmount AS CollAmt,0 AS BalAmt,a.ReturnAmount,a.CashReturnAmount,c.Name AS Status ,a.Pno 
FROM tbl_SALES_LEDGER a LEFT JOIN tbl_CUSTOMER b ON a.CustId=b.Id LEFT JOIN tbl_SALES_COLLECTION_STATUS_INFO c ON a.SalesCollStatus=c.Id 
WHERE a.Valid=1 AND a.TrDate BETWEEN @dateFrom AND @dateTo AND a.Pno=@pno AND a.CustId=@custId
END






GO
/****** Object:  StoredProcedure [dbo].[SP_GET_TB_DTLS]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROC [dbo].[SP_GET_TB_DTLS] (@Pno AS Int,@dateFrom AS date,@dateTo AS date)AS
BEGIN
DELETE FROM tmpTB
INSERT INTO tmpTB
SELECT aa.Code , aa.Description , (Case WHEN SUBSTRING(aa.Code,1,1) IN ('2','4')  then ISNULL(SUM(aa.Dr - aa.Cr),0) else 0 end) as Dr , 
(Case WHEN SUBSTRING(aa.Code,1,1) IN ('1','3')  then ISNULL(SUM(aa.Cr-aa.Dr),0) else 0 end) as Cr
FROM (
SELECT a.Code,b.Description,SUM(Debit) AS Dr,SUM(Credit) AS Cr
FROM tbl_TRANSACT a 
LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code=b.Code
WHERE b.Type='Balance Sheet'
AND a.Trans_dt<=@dateTo--dateTo 
AND a.Pno=@Pno
GROUP By a.Code,b.Description
UNION ALL
SELECT a.Code,b.Description,SUM(Debit) AS Dr,SUM(Credit) AS Cr
FROM tbl_TRANSACT a 
LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code=b.Code
WHERE b.Type<>'Balance Sheet'
AND a.Trans_dt BETWEEN @dateFrom AND @dateTo--dateTo
AND a.Pno=@Pno
GROUP By a.Code,b.Description) aa
GROUP BY aa.Code , aa.Description

INSERT INTO tmpTB
SELECT '15050101','Last Year P/L',(CASE WHEN ISNULL(SUM(Dr-CR),0)<0 then ABS(ISNULL(SUM(Dr-CR),0)) ELSE 0 END) AS Dr,
(CASE WHEN ISNULL(SUM(Dr-CR),0)>0 then ABS(ISNULL(SUM(Dr-CR),0)) ELSE 0 END) AS CR
FROM tmpTB 
HAVING SUM(Dr-Cr) <> 0


--------------------Details Level
SELECT 2 as slno,code,Description,Dr,Cr
from tmpTB
UNION ALL
SELECT 1,SUBSTRING(a.Code,1,4)+'0000' as GCode,b.Description ,(CASE WHEN Isnull(SUM(Dr-CR),0)>0 then Isnull(SUM(Dr-CR),0) ELSE 0 END) AS Dr,
(CASE WHEN Isnull(SUM(Dr-CR),0)<0 then ABS(Isnull(SUM(Dr-CR),0)) ELSE 0 END) AS CR
from tmpTB a , tbl_CHART_OF_ACCOUNTS b 
where SUBSTRING(a.Code,1,4)+'0000' = b.Code 
GROUP BY SUBSTRING(a.Code,1,4)+'0000',b.Description
UNION ALL
select 3,'99999999','Total',ISNULL(SUM(Dr),0),ISNULL(SUM(Cr),0)
FROM tmpTB
ORDER BY code ,slno 
END






GO
/****** Object:  StoredProcedure [dbo].[SP_GET_TB_SUMMARY]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[SP_GET_TB_SUMMARY] (@Pno AS Int,@dateFrom AS date,@dateTo AS date)AS
BEGIN
DELETE FROM tmpTB
INSERT INTO tmpTB
SELECT aa.Code , aa.Description , (Case WHEN SUBSTRING(aa.Code,1,1) IN ('2','4')  then SUM(aa.Dr - aa.Cr) else 0 end) as Dr , 
(Case WHEN SUBSTRING(aa.Code,1,1) IN ('1','3')  then SUM(aa.Cr-aa.Dr) else 0 end) as Cr
FROM (
SELECT a.Code,b.Description,SUM(Debit) AS Dr,SUM(Credit) AS Cr
FROM tbl_TRANSACT a 
LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code=b.Code
WHERE b.Type='Balance Sheet'
AND a.Trans_dt<=@dateTo--dateTo 
AND a.Pno<=@Pno
GROUP By a.Code,b.Description
UNION ALL
SELECT a.Code,b.Description,SUM(Debit) AS Dr,SUM(Credit) AS Cr
FROM tbl_TRANSACT a 
LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code=b.Code
WHERE b.Type<>'Balance Sheet'
AND a.Trans_dt BETWEEN @dateFrom AND @dateTo--dateTo
AND a.Pno=@Pno
GROUP By a.Code,b.Description) aa
GROUP BY aa.Code , aa.Description

INSERT INTO tmpTB
SELECT '15050101','Last Year P/L', (CASE WHEN SUM(Dr-CR)<0 then ABS(SUM(Dr-CR)) ELSE 0 END) AS Dr,
(CASE WHEN SUM(Dr-CR)>0 then ABS(SUM(Dr-CR)) ELSE 0 END) AS CR
FROM tmpTB 
HAVING SUM(Dr-Cr) <> 0

SELECT 2 AS slno,SUBSTRING(a.Code,1,4)+'0000' as Code,b.Description ,(CASE WHEN SUM(Dr-CR)>0 then SUM(Dr-CR) ELSE 0 END) AS Dr,
(CASE WHEN SUM(Dr-CR)<0 then ABS(SUM(Dr-CR)) ELSE 0 END) AS CR
from tmpTB a , tbl_CHART_OF_ACCOUNTS b 
where SUBSTRING(a.Code,1,4)+'0000' = b.Code 
GROUP BY SUBSTRING(a.Code,1,4)+'0000',b.Description
UNION ALL
SELECT 1,SUBSTRING(a.Code,1,2)+'000000' as Code,b.Description ,(CASE WHEN SUM(Dr-CR)>0 then SUM(Dr-CR) ELSE 0 END) AS Dr,
(CASE WHEN SUM(Dr-CR)<0 then ABS(SUM(Dr-CR)) ELSE 0 END) AS CR
from tmpTB a , tbl_CHART_OF_ACCOUNTS b 
where SUBSTRING(a.Code,1,2)+'000000' = b.Code 
GROUP BY SUBSTRING(a.Code,1,2)+'000000',b.Description
UNION ALL
select 3,'99999999','Total',SUM(Dr),SUM(Cr)
FROM tmpTB
ORDER BY code ,slno 
END










GO
