CREATE PROC [dbo].[SP_GET_VOUCHER_LIST](@TrNo nvarchar(20), @TrDate date, @BranchId int) AS
BEGIN /* EXEC SP_GET_VOUCHER_LIST '23050005', '2023-05-31', 1 */
select 999999 AS Id, a.Code, b.Description, a.CostDept, ISNULL(SUBSTRING((SELECT ',' + bb.Description+SPACE(2)+'('+aa.Naration+')' FROM tbl_TRANSACT aa, tbl_CHART_OF_ACCOUNTS bb where aa.Valid = 1 AND aa.BranchId = 1 and aa.TrNo = a.TrNo AND aa.Trans_dt = a.Trans_dt and aa.Code = bb.Code and aa.CorD = 'D' Group by aa.ContraCode, bb.Description, aa.Naration FOR XML PATH('')), 2 , 1000),'') As Narration, '' AS ChequeNo, NULL AS ChequeDate,
SUM(a.Debit) AS Debit, SUM(a.Credit) AS Credit, a.TrNo, a.Trans_dt, a.Pno, a.RefNo AS VrRefNo, a.UserName, Max(a.EntryDate) as EntryDate, c.Name as Unit, a.VoucherType, a.Remark, '' AS PartyName 
FROM tbl_TRANSACT a, tbl_CHART_OF_ACCOUNTS b, tbl_COMPANY_INFORMATION c
where a.Valid = 1 AND a.Code = b.Code and a.CostCenter = c.Id and a.CorD = 'C' AND a.BranchId = c.BranchId and a.TrNo = @TrNo and a.Trans_dt = @TrDate AND a.BranchId = @BranchId
group by a.Code, a.TrNo, a.Trans_dt, a.Pno, a.RefNo, b.Description, a.CostDept, a.UserName, c.Name, a.VoucherType, a.Remark--, a.PartyName
UNION ALL
select a.Id, a.Code, b.Description, a.CostDept, a.Naration As Narration, a.ChequeNo, a.ChequeDate,
SUM(a.Debit) AS Debit, SUM(a.Credit) AS Credit, a.TrNo, a.Trans_dt, a.Pno, a.RefNo AS VrRefNo, a.UserName, Max(a.EntryDate) as EntryDate, c.Name as Unit, a.VoucherType, a.Remark, a.PartyName
from tbl_TRANSACT a, tbl_CHART_OF_ACCOUNTS b, tbl_COMPANY_INFORMATION c
where a.Valid = 1 AND a.Code = b.Code and a.CostCenter = c.Id and a.CorD = 'D' AND a.BranchId = c.BranchId and a.TrNo = @TrNo and a.Trans_dt = @TrDate AND a.BranchId = @BranchId
group by a.Id, a.Code, a.TrNo, a.Trans_dt, a.Pno, a.RefNo, b.Description, a.CostDept, a.UserName, c.Name, a.VoucherType,
a.Remark, a.Naration, a.PartyName, a.ChequeNo, a.ChequeDate
END
GO
/****** Object:  StoredProcedure [dbo].[SP_GetCentralStorePurchaseReqData]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

-- 26012026 -----@param param add 
CREATE PROCEDURE [dbo].[SP_GetCentralStorePurchaseReqData] @BranchId INT, @StoreId INT, @CompanyId varchar(150), @TrDateFrom DATE, @TrDateTo DATE, @Param Varchar(250)
AS
BEGIN    --  SP_GetCentralStorePurchaseReqData 1, 139, 'S012', '2025-12-01', '2025-12-30', ''
SELECT b.Id, b.ProductName, ISNULL(SUM(a.OpenQty), 0) AS OpenQty, ISNULL(SUM(PurchaseQty), 0) AS PurchaseQty,
ISNULL(SUM(TransferQty), 0) AS TransferQty, ISNULL(SUM(CurrentQty), 0) AS CurrentQty,
ISNULL(SUM(a.PharOpenQty),0) AS PharOpenQty, ISNULL(SUM(a.PharInQty),0) AS PharInQty,
ISNULL(SUM(PharSoldQty), 0) AS PharSoldQty, ISNULL(SUM(a.PharCurrQty), 0) AS PharCurrQty, 
b.ReminderStock, ISNULL(SUM(a.OpenQty), 1) AS IsNotStockIn
Into #z
FROM PharProductInfo b
LEFT JOIN 
(
	SELECT a.ProductId As Id, SUM(a.InQty-a.OutQty) AS OpenQty, 0 AS PurchaseQty, 0 AS TransferQty, 0 AS CurrentQty, 0 AS PharSoldQty, 0 AS PharCurrQty, 0 PharOpenQty, 0 AS PharInQty
	FROM PharmaCurrentStock a
	WHERE a.BranchId=@BranchId AND StoreId=@StoreId AND a.TrDate<@TrDateFrom
	GROUP BY a.ProductId
	HAVING SUM(a.InQty-a.OutQty) > 0

	UNION ALL
	SELECT a.ProductId As Id, 0 AS OpenQty, SUM(a.InQty) AS PurchaseQty, SUM(a.OutQty) AS TransferQty, 0 AS CurrentQty, 0 AS PharSoldQty, 0 AS PharCurrQty, 0 PharOpenQty, 0 AS PharInQty
	FROM PharmaCurrentStock a
	WHERE a.BranchId=@BranchId AND StoreId=@StoreId  AND a.TrDate BETWEEN @TrDateFrom AND @TrDateTo
	GROUP BY a.ProductId
	HAVING SUM(a.InQty+a.OutQty) > 0

	UNION ALL
	SELECT a.ProductId As Id, 0 AS OpenQty, 0 AS PurchaseQty, 0 AS TransferQty, SUM(a.InQty-a.OutQty) AS CurrentQty, 0 AS PharSoldQty, 0 AS PharCurrQty, 0 PharOpenQty, 0 AS PharInQty
	FROM PharmaCurrentStock a
	WHERE a.BranchId=@BranchId AND StoreId=@StoreId
	GROUP BY a.ProductId
	HAVING SUM(a.InQty-a.OutQty) > 0

	-----------------------------------
	UNION ALL
	SELECT a.ProductId As Id, 0 AS OpenQty, 0 AS PurchaseQty, 0 AS TransferQty, 0 AS CurrentQty, 0 AS PharSoldQty, 0 AS PharCurrQty, SUM(a.InQty-a.OutQty) AS PharOpenQty, 0 AS PharInQty
	FROM PharmaCurrentStock a
	WHERE a.BranchId=@BranchId AND StoreId!=@StoreId AND a.TrDate<@TrDateFrom
	GROUP BY a.ProductId
	HAVING SUM(a.InQty-a.OutQty) > 0

	UNION ALL
	SELECT a.ProductId As Id, 0 AS OpenQty, 0 AS PurchaseQty, 0 AS TransferQty, 0 AS CurrentQty, 0 AS PharSoldQty, 0 AS PharCurrQty, 0 AS PharOpenQty, SUM(a.InQty) AS PharInQty
	FROM PharmaCurrentStock a
	WHERE a.BranchId=@BranchId AND StoreId!=@StoreId AND a.TrDate BETWEEN @TrDateFrom AND @TrDateTo
	AND a.InQty != 0
	GROUP BY a.ProductId
	HAVING SUM(a.InQty) > 0

	UNION ALL
	SELECT a.ProductId As Id, 0 AS OpenQty, 0 AS PurchaseQty, 0 AS TransferQty, 0 AS CurrentQty, SUM(a.OutQty) AS PharSoldQty, 0 AS PharCurrQty, 0 PharOpenQty, 0 AS PharInQty
	FROM PharmaCurrentStock a
	WHERE a.BranchId=@BranchId AND StoreId!=@StoreId AND a.TrDate BETWEEN @TrDateFrom AND @TrDateTo
	GROUP BY a.ProductId
	HAVING SUM(a.OutQty) > 0

	UNION ALL
	SELECT a.ProductId As Id, 0 AS OpenQty, 0 AS PurchaseQty, 0 AS TransferQty, 0 AS CurrentQty, 0 AS PharSoldQty, SUM(a.InQty-a.OutQty) AS PharCurrQty, 0 PharOpenQty, 0 AS PharInQty
	FROM PharmaCurrentStock a
	WHERE a.BranchId=@BranchId AND StoreId!=@StoreId
	GROUP BY a.ProductId
	HAVING SUM(a.InQty-a.OutQty) > 0

) a ON b.Id=a.Id
WHERE b.CompanyId=@CompanyId AND b.IsActive=1
GROUP BY b.Id, b.ProductName, b.ReminderStock
ORDER BY b.ProductName

Select * From #z a
Where a.ProductName Like '%'+@Param+'%'
Order by a.ProductName

END
GO
/****** Object:  StoredProcedure [dbo].[SP_GetDepreciationReport]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
