CREATE PROCEDURE [dbo].[SP_GetDepreciationReport](@DateFrom date,@DateTo Date)
AS
-- EXEC SP_GetDepreciationReport '2024-07-01','2025-06-30'

drop table tmpFixedAssetDepCal --tmpFAsset	EXEC SP_GetDepreciationReport '2020-07-01','2021-06-30'
BEGIN


	----select SUM(isnull(dbo.FN_CalculateDepreciationNew(AssetMainCode,DepMethod,'2024-01-01',DateAdd(d,0,'2024-01-01'),0),0))+SUM(OPDepAmt) as OBDepAmount,	
	----SUM(ISNULL(dbo.FN_CalculateDepreciationNew(AssetMainCode,DepMethod,'2024-01-01',DateAdd(d,1,'2024-12-31'),0),0)-ISNULL(dbo.FN_CalculateDepreciationNew(AssetMainCode,DepMethod,'2024-01-01','2024-01-01',0),0)) AS DepThisPeriod,
	----Null as Purchasedate , DepRate ,DepMethod,SUM(TotalPrice) AS TotalPrice ,'' as CodeNo,SPACE(20) as ProductName ,AssetClass as AssetType ,
	----0 as OBBalance , 0 as AddThisPeriod , 0 as SalvaseValue, 0 as TotalAsset , 0 as TotalDepAmount , 0 As BookValue
	----INTO tmpFixedAssetDepCal
	----from FixedAssetRegisterDetails
	----where valid = 1 
	----group by AssetClass,DepRate ,DepMethod


	select SUM(isnull(dbo.FN_CalculateDepreciationNew(AssetMainCode,DepMethod,@DateFrom,DateAdd(d,0,@DateFrom),0),0))+SUM(OPDepAmt) as OBDepAmount,	
	SUM(ISNULL(dbo.FN_CalculateDepreciationNew(AssetMainCode,DepMethod,@DateFrom,DateAdd(d,1,@DateTo),0),0)-ISNULL(dbo.FN_CalculateDepreciationNew(AssetMainCode,DepMethod,@DateFrom,@DateFrom,0),0)) AS DepThisPeriod,
	NULL AS Purchasedate , DepRate ,DepMethod,SUM(TotalPrice) AS TotalPrice ,'' as CodeNo,SPACE(20) as ProductName ,AssetClass as AssetType ,
	0 as OBBalance , 0 as AddThisPeriod , 0 as SalvaseValue, 0 as TotalAsset , 0 as TotalDepAmount , 0 As BookValue
	--INTO tmpFAsset
	INTO tmpFixedAssetDepCal
	from FixedAssetRegisterDetails
	where valid = 1 
	group by AssetClass,DepRate ,DepMethod
	
	--select opDepAmt from FixedAssetRegister
	
	SELECT aa.AssetType ,DepRate ,DepMethod, SUM(aa.OBPurchase) As OBPurchase , SUM(aa.AddThisPeriod) as AddThisPeriod , SUM(aa.CarringAmt) as CarringAmt,
	sum(aa.SalvaseValue) as SalvaseValue
	INTO #tmpDepCal1
	FROM (
	SELECT AssetClass as AssetType ,DepRate ,DepMethod, 0 as OBPurchase,  TotalPrice AS AddThisPeriod, CarringAmt , 0 as SalvaseValue
	FROM  FixedAssetRegisterDetails 
	where valid = 1 and InvoiceDate BETWEEN @DateFrom AND @DateTo 
	UNION ALL
	SELECT AssetClass as AssetType ,DepRate ,DepMethod, TotalPrice as OBPurchase,  0 AS AddThisPeriod, 0 as CarringAmt , 0 as SalvaseValue
	FROM  FixedAssetRegisterDetails 
	where valid = 1 and InvoiceDate < @DateFrom 
	UNION ALL
	SELECT AssetType ,DepRate ,DepMethod, -SalesAmount as OBPurchase,  0 AS AddThisPeriod, 0 as CarringAmt , 0 as SalvaseValue
	FROM  FixedAssetSales 
	where valid = 1 and SalesDate < @DateFrom 
	UNION ALL
	SELECT AssetType ,DepRate ,DepMethod, 0 as OBPurchase,  0 AS AddThisPeriod, 0 as CarringAmt , SalesAmount as SalvaseValue
	FROM  FixedAssetSales 
	where valid = 1 and SalesDate BETWEEN @DateFrom AND @DateTo 
	
	) aa
	GROUP BY AssetType,DepRate ,DepMethod
	
	--select * from #tmpDepCal1 

	UPDATE tmpFixedAssetDepCal SET OBBalance = b.OBPurchase, AddThisPeriod = b.AddThisPeriod ,
	SalvaseValue = isnull(b.CarringAmt,0) + ISNULL(b.SalvaseValue,0)
	FROM tmpFixedAssetDepCal a , #tmpDepCal1 b
	WHERE a.AssetType = b.AssetType AND a.DepRate = b.DepRate AND a.DepMethod=b.DepMethod

	--select * from tmpFixedAssetDepCal

	UPDATE tmpFixedAssetDepCal SET TotalAsset = ISNULL(OBBalance,0)+ ISNULL(AddThisPeriod,0)-ISNULL(SalvaseValue,0),
	TotalDepAmount = ISNULL(OBDepAmount,0) + ISNULL(DepThisPeriod,0) ,  
	BookValue = ISNULL(OBBalance,0)+ ISNULL(AddThisPeriod,0)- (ISNULL(OBDepAmount,0)+ISNULL(DepThisPeriod,0))  

	
--	UPDATE tmpFixedAssetDepCal SET DepThisPeriod = 0 
--	WHERE (OBDepAmount+DepThisPeriod) > TotalPrice 

	UPDATE tmpFixedAssetDepCal SET OBDepAmount = TotalPrice 
	WHERE OBDepAmount > TotalPrice 
	
	UPDATE tmpFixedAssetDepCal SET BookValue=0,OBDepAmount=0,TotalDepAmount=0,DepThisPeriod=0
	WHERE TotalAsset=0

	UPDATE tmpFixedAssetDepCal SET BookValue=0 , totalDepAmount = TotalAsset ,OBDepAmount=TotalAsset ,
	DepThisPeriod = 0 
	WHERE bookValue < 0

	select * from tmpFixedAssetDepCal
END




GO
