--06082025 Add Remarks new column for show inv time remarks
CREATE PROC [dbo].[SP_GetDiagInvoiceReturnData] @InvNo nvarchar(50), @BranchId nvarchar(50)
AS
BEGIN -- SP_GetDiagInvoiceReturnData 'DIA250700121', 1

With zz as
(
	Select IsnULL(Sum(Less), 0) AS DueLess from InvPaid Where InvNo=@InvNo And Valid=1 and BranchId=@BranchId
)
select  aa.PtStatus, aa.MobNo, aa.InvNo, aa.InvDate, aa.PatientId, aa.PatientName, aa.DOB, aa.Sex, aa.Address, aa.RefDrCode, aa.RefDrName, aa.UserName, aa.Remarks,
zz.DueLess AS LessAmount,/*bb.LessAmount,*/ bb.LessPcOrTk, bb.DiscountFrom, bb.TotalLess, bb.TotalAmt, bb.AdvanceAmt, aa.PCode, aa.ShortDesc, aa.Quantity, aa.Amount, aa.TotalAmount, 
ISNULL(aa.CanGiveLess, 0) AS CanGiveLess, aa.GLessAmt
from 
(
	select a.PtStatus, a.MobNo, a.InvNo, a.InvDate, a.PatientId, a.PatientName, a.DOB, a.Sex, a.Address, a.UserName, a.RefDrCode, 
	a.RefDrName, b.PCode, b.ShortDesc, b.Quantity, b.Amount, b.TotalAmount, b.GLessAmt, c.CanGiveLess, a.Remarks
	from InvMaster a
	LEFT JOIN InvDetails b oN a.InvNo = b.InvNo ANd a.InvDate = b.InvDate AND a.BranchId = b.BranchId
	LEFT JOIN ClinicalChart c ON b.PCode = c.PCode ANd a.BranchId = c.BranchId
	WHERE a.Valid <> 0 AND b.Valid <> 0  AND a.IsReturn = 0 AND a.InvNo=@InvNo AND a.BranchId = @BranchId
) aa, 
(
	SELECT SUM(a.Less) AS LessAmount, b.LessPcOrTk, b.DiscountFrom, SUM(a.Less) AS TotalLess, SUM(a.Sales) AS TotalAmt, SUM(a.Collection+a.AdjustAmt) AS AdvanceAmt 
	FROM SalesLedger a 
	LEFT JOIN InvMaster b ON a.PrevInvNo = b.InvNo ANd a.PreInvDate = b.InvDate AND a.BranchId = b.BranchId
	WHERE a.Valid <> 0 AND b.IsReturn = 0 AND a.PrevInvNo = @InvNo AND a.BranchId = @BranchId 
	GROUP BY b.LessPcOrTk, b.DiscountFrom
) bb, zz

end
GO
