CREATE Procedure [dbo].[SP_GetDoctorInfo]  @BranchId int, @searchString nvarchar(50)
AS
Begin
Select DrCode,  DrName From DrInfo  WHERE Status=1 AND BranchId=@BranchId AND (DrCode + DrName) LIKE '%'+@searchString+'%'
END
