CREATE PROCEDURE [dbo].[SP_GETDrHonorarium] (@datefrom date,@dateto date, @drCode nvarchar(50),@invNo nvarchar(100), @branchId int,@PatientStatus NVARCHAR(20)) AS
BEGIN 
select ISNULL(SUM(TotalHonorarium),0) as MaxDrHonorarium, ISNULL(SUM(LessByDr),0) as Less, 
ISNULL(SUM(TotalHonorarium-LessByDr),0) AS NetDrHonorarium 
from DrHonorariumLedger a
WHERE IsPaid = 0 AND BranchId = @branchId 
and a.PatientStatus=@PatientStatus
AND (a.RefDrCode+a.InvNo) LIKE '%'+@drCode+'%'+@invNo+'%' 
AND InvPaidDate BETWEEN @datefrom AND @dateto AND MONTH(InvPaidDate) = MONTH(@datefrom)

END
GO
