CREATE PROC [dbo].[SP_GetInvoicePrint](@Pno AS Int,@InvNo AS varchar(20),@InvDate AS date)
AS
SELECT ISNULL(e.Name,'N/A') AS CardBankName,ISNULL(a.CardNumber,'N/A')AS CardNumber,a.InvoiceNo,a.InvoiceDate,a.CustId,d.Name AS CustomerName,d.MobileNo AS CustomerMobileNo,
d.Address AS CustomerAddress, a.TotalAmount,a.LessAmount AS TotalDiscountAmount,a.CashAmount,a.CardAmount,
a.Remarks,b.ItemId,SUM(b.Quantity) as Quantity,b.SalesPrice,c.Model,c.Name,b.ItemDiscount AS ItemDiscount,a.UserName,a.DeliveryCharge,
c.UnitPerCtn,f.Name as UnitName,a.IsCondition,
(SELECT STUFF( -- Remove first comma
(
	SELECT  ', ' + BarcodeId FROM -- create comma separated values
	(
	  SELECT BarcodeId FROM tbl_SALES_DETAIL where a.InvoiceNo=InvoiceNo AND a.InvoiceDate=InvoiceDate AND a.CustId=CustId AND a.Pno=Pno And b.ItemId=ItemId
	) AS T FOR XML PATH('')
)
,1,1,'') AS BarcodeId) AS BarcodeId,
b.WarrantyMonth,a.Pno, a.EntryDate,
case when a.InstallmentSize!=0 then 'Installment Size:'+ cast(a.InstallmentSize As varchar(10))+ ' Amount: '+ cast(a.InstallmentAmount AS Varchar(20))
else
''
end as InstallmentDesc,a.GCardSerialNo,a.TotalCampaignAmount
FROM tbl_SALES_MAIN a
LEFT JOIN tbl_SALES_DETAIL b ON a.InvoiceNo=b.InvoiceNo AND a.InvoiceDate=b.InvoiceDate AND a.CustId=b.CustId AND a.Pno=b.Pno
LEFT JOIN tbl_ITEM c ON b.ItemId=c.Id
LEFT JOIN tbl_CUSTOMER d ON a.CustId=d.Id
LEFT JOIN tbl_CARD_BANK_INFO e ON e.Id=a.CardNameId
LEFT JOIN tbl_ITEM_UNIT f ON c.UnitId=f.Id

WHERE a.InvoiceNo=@InvNo AND a.InvoiceDate=@InvDate AND a.Pno=@Pno
group by e.Name,a.CardNumber,a.InvoiceNo,a.InvoiceDate,a.CustId,d.Name,d.MobileNo,
d.Address, a.TotalAmount,a.LessAmount,a.CashAmount,a.CardAmount
,a.Remarks,b.ItemId,b.SalesPrice,c.Model,c.Name,b.ItemDiscount,a.UserName,a.DeliveryCharge,c.UnitPerCtn,f.Name,a.IsCondition
,b.WarrantyMonth,a.Pno, a.EntryDate,a.InstallmentSize,a.InstallmentAmount,a.GCardSerialNo,a.TotalCampaignAmount




GO
