CREATE PROCEDURE [dbo].[SP_GetMaxLessForDiagnosis] (@InvNO nvarchar(20),@InvDate date,@BranchId integer)
AS  -- EXEC SP_GetMaxLessForDiagnosis 'DIA241200036', '2024-12-01', 1
BEGIN

	SELECT SUM(Less) AS Less INTO #Less FROM SalesLedger WHERE BranchId = @BranchId AND PrevInvNo = @InvNO AND PreInvDate = @InvDate

	SELECT ISNULL((SUM((CASE WHEN b.LessAmount = 0 THEN 100 END) * 0.01 * a.TotalAmount)- d.Less), 0) as MAXLess
	FROM InvDetails a, ClinicalChart b, InvMaster c, #Less d
	WHERE a.InvNo = c.InvNo and a.InvDate=c.InvDate and a.valid =1 and c.Valid = 1 
	and a.BranchId = c.BranchId 
	AND a.Pcode = b.PCode and a.BranchId = b.BranchId 
	and a.InvNo = @InvNO  AND a.InvDate = @InvDate AND a.BranchId = @BranchId 
	AND b.CanGiveLess = 1
	GROUP BY d.Less
	
	--select (SUM(b.LessAmount * 0.01 * a.TotalAmount) - c.TotalLess) as MAXLess
	--from InvDetails a , ClinicalChart b , InvMaster c 
	--where a.InvNo = c.InvNo and a.InvDate=c.InvDate and a.valid =1 and c.Valid = 1 
	--and a.BranchId = c.BranchId 
	--AND a.Pcode = b.PCode and a.BranchId = b.BranchId 
	--and a.InvNo = @InvNO  AND a.InvDate = @InvDate AND a.BranchId = @BranchId 
	--GROUP BY c.TotalLess 
END
GO
/****** Object:  StoredProcedure [dbo].[SP_GetPatientLedgerItemWise]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SP_GetPatientLedgerItemWise](@PatientId nvarchar(50), @BranchId int, @CardTypeId INT)
AS
BEGIN /* EXEC SP_GetPatientLedgerItemWise 'PA240200085', 1, 0 */
/*Condition for IsInclude Pharmacy bill*/
DECLARE @IncludePharmacy INT, @IsIncludePharmacy INT;
SELECT @IncludePharmacy = PharmacyInclude FROM tbl_ComInfo
IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END;

select sum(a.Amount*a.Quantity) AS TotalSales, ISNULL(b.SubDeptName, 'LabTest') AS dept
into #sales
from InvDetails a
left join ClinicalChart b on b.BranchId = a.BranchId and b.PCode = a.PCode
where a.BranchId = @BranchId and a.Valid = 1 and a.PatientId = @PatientId and b.CanGiveLess = 1 group by b.SubDeptName

select sum(Collection) AS InColl , sum(TotalAmount) as TotalAmount
into #z
from PatientLedger
where BranchId = @BranchId and valid = 1 and PatientId = @PatientId

--SELECT 1 AS SlNo, 'Indoor' AS MainDept, a.Code, a.Particulars, a.DrCode, a.Charge, a.Unit, SUM(a.NoU) AS NoU,
--SUM(a.Charge*a.NoU) AS TotalCharge, SUM(a.Less) AS Less, SUM(a.ServiceCharge) AS ServiceCharge, 0 AS FixedLess, 
--SUM(a.Charge*a.NoU) AS Due, (SUM((a.Charge*a.NoU)+a.ServiceCharge)-(b.InColl/b.TotalAmount)*SUM((a.Charge*a.NoU)+a.ServiceCharge)) as CanLessAmt
--FROM PatientLedger a
--left join #z b on 1 = 1
--WHERE a.BranchId = 1 AND a.Valid = 1 AND a.PatientId = 'PA240200108' AND Status != 'Advance Collection'
--GROUP BY a.Code, a.Particulars, a.DrCode, a.Charge, a.Unit, b.InColl, b.TotalAmount

IF @CardTypeId = 0
BEGIN
	SELECT 1 AS SlNo, 'Indoor' AS MainDept, a.Code, a.Particulars, a.DrCode, a.Charge, a.Unit, SUM(a.NoU) AS NoU,
	SUM(a.Charge*a.NoU) AS TotalCharge, SUM(a.Less) AS Less, SUM(a.ServiceCharge) AS ServiceCharge, 0 AS FixedLess, 
	SUM(a.Charge*a.NoU) AS Due, 0 AS CanLessAmt
	--(SUM((a.Charge*a.NoU)+a.ServiceCharge)-(b.InColl/b.TotalAmount)*SUM((a.Charge*a.NoU)+a.ServiceCharge)) AS Due, 0 as CanLessAmt
	FROM PatientLedger a
	left join #z b on 1 = 1
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.PatientId = @PatientId AND Status != 'Advance Collection'
	GROUP BY a.Code, a.Particulars, a.DrCode, a.Charge, a.Unit, b.InColl, b.TotalAmount
	UNION ALL
	-- DIGNOSIS BILL
	SELECT 2 AS SlNo, DeptName AS MainDept, '0011' AS Code, Particulars, '' AS DrCode, 
	SUM(Charge) AS Charge, '1' AS Unit, 1 AS NoU, SUM(TotalCharge) AS TotalCharge, 
	SUM(Less) AS Less, 0 AS ServiceCharge, SUM(a.FixedLess) AS FixedLess, SUM(Due) AS Due, 0 as CanLessAmt
	FROM (
		SELECT a.DeptName, ISNULL(b.SubDeptName, 'LabTest') AS Particulars, SUM(a.Amount*a.Quantity) AS Charge,
		SUM(a.TotalAmount) AS TotalCharge, 
		ISNULL((CASE WHEN @CardTypeId = 0 THEN (c.Less/c.Sales*g.TotalSales) ELSE SUM(CASE WHEN f.PcOrTk = '%' THEN g.TotalSales*f.DiscountAmt*0.01 ELSE a.Quantity*f.DiscountAmt END) END), 0) AS Less, SUM(a.FixedLess) as FixedLess, 
		isnull((g.TotalSales-(g.TotalSales*c.Collection)/c.Sales/**/-ISNULL((CASE WHEN @CardTypeId = 0 THEN (c.Less/c.Sales*g.TotalSales) ELSE (CASE WHEN f.PcOrTk = '%' THEN g.TotalSales*SUM(f.DiscountAmt*0.01) ELSE SUM(a.Quantity*f.DiscountAmt) END) END), 0)/**/),0) as due
		FROM InvDetails a
		left join ClinicalChart b on a.BranchId = b.BranchId ANd a.PCode = b.PCode
		LEFT join (
		SELECT BranchId, SUM(Sales-ReturnAmount) as Sales, sum(Collection-ReturnCash) as Collection, SUM(Less) AS Less 
		FROM SalesLedger where BranchId = @BranchId ANd Valid = 1 AND PatientId = @PatientId GROUP BY BranchId HAVING SUM(Sales-ReturnAmount) > 0
		) c ON a.BranchId = c.BranchId
		LEFT JOIN VW_DiscCardRegNoWise f ON a.BranchId = f.BranchId AND a.RegNo = f.RegNo AND a.PCode = f.PCode
		LEFT JOIN #sales g on g.dept = b.SubDeptName
		where a.Valid = 1 AND a.BranchId = @BranchId AND a.PatientId = @PatientId AND c.BranchId IS NOT NULL
		group by b.SubDeptName, c.Collection, c.Sales, g.TotalSales, f.PcOrTk, a.DeptName, c.Less
	) a
	GROUP BY a.Particulars, a.DeptName

	UNION ALL
	SELECT 2 AS SlNo, 'Medicine' AS MainDept, '0009' AS Code, 'Medicine Bill' as Particulars, '' as DrCode, SUM(a.Sales) AS Charge, '1' AS Unit, 1 AS NoU,
	SUM(a.Sales) AS TotalCharge, SUM(a.LessAmt) AS Less, 0 AS ServiceCharge, 0 AS FixedLess, SUM(a.Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt-a.AdjustAmt) AS Due, 0 as CanLessAmt
	FROM PharSalesLedger a
	where PatientId = @PatientId AND a.Valid = @IncludePharmacy AND a.BranchId = @BranchId
	HAVING SUM(a.Sales) > 0
	UNION ALL
	SELECT 2 AS SlNo, 'Ambulance' AS MainDept, '0016' AS Code, 'Ambulance Charge' AS Particulars, '' AS DrCode, SUM(a.TotalCharge) AS Charge, '1' AS Unti, 1 AS NoU,
	SUM(a.TotalCharge) AS TotalCharge, SUM(a.Less) AS Less, 0 AS ServiceCharge, 0 AS FixedLess, SUM(a.TotalCharge-a.Less-a.ReceiveAmt-a.AdjustAmt) AS Due, 0 as CanLessAmt
	FROM AmbulanceLedger a
	WHERE a.PatientId = @PatientId AND a.Valid = 1 AND a.BranchId = @BranchId
	HAVING SUM(a.TotalCharge) > 0
END
else
begin
select 1 as SlNo, 'Indoor' AS MainDept, a.Code, a.Particulars, a.DrCode, sum(a.Charge) as Charge, a.Unit, sum(NoU) as NoU,
sum(TotalAmount) as TotalCharge, sum(less) as Less, sum(a.ServiceCharge) as ServiceCharge,
case when c.PcOrTk = '%' then sum(NoU*a.Charge)*isnull(c.Amount, 0)*0.01 else sum(isnull(c.Amount, 0)) end as Fixedless,
sum(TotalAmount+ServiceCharge-case when c.PcOrTk = '%' then NoU*a.Charge*isnull(c.Amount, 0)*0.01 else isnull(c.Amount, 0) end) as Due, 0 as CanLessAmt
from PatientLedger a
left join CardIssue b on a.RegNo = b.RegNo AND b.Valid = 1
left join DiscountCardRegistration c on c.CardTypeId = b.CardTypeId and c.PCode = a.Code and c.Valid = 1
where a.BranchId = @BranchId and a.Valid = 1 and PatientId = @PatientId AND Status != 'Advance Collection'
group by a.code, a.particulars, a.drcode, a.Unit, c.PcOrTk, c.Amount
UNION ALL
-- DIGNOSIS BILL
SELECT 2 AS SlNo, DeptName AS MainDept, '0011' AS Code, Particulars, '' AS DrCode, 
SUM(Charge) AS Charge, '1' AS Unit, 1 AS NoU, SUM(TotalCharge) AS TotalCharge, 
SUM(Less) AS Less, 0 AS ServiceCharge, SUM(a.FixedLess) AS FixedLess, SUM(Due) AS Due, 0 as CanLessAmt
FROM (
	SELECT a.DeptName, ISNULL(b.SubDeptName, 'LabTest') AS Particulars, SUM(a.Amount*a.Quantity) AS Charge,
	SUM(a.TotalAmount) AS TotalCharge, 
	SUM(a.FixedLess) AS Less, ISNULL((CASE WHEN @CardTypeId = 0 THEN (c.Less/c.Sales*g.TotalSales) ELSE SUM(CASE WHEN f.PcOrTk = '%' THEN a.TotalAmount*f.DiscountAmt*0.01 ELSE a.Quantity*f.DiscountAmt END) END), 0) as FixedLess,
	isnull((g.TotalSales-(g.TotalSales*c.Collection)/c.Sales/**/-ISNULL((CASE WHEN @CardTypeId = 0 THEN (c.Less/c.Sales*g.TotalSales) ELSE (CASE WHEN f.PcOrTk = '%' THEN g.TotalSales*SUM(f.DiscountAmt*0.01) ELSE SUM(a.Quantity*f.DiscountAmt) END) END), 0)/**/),0) as due
	FROM InvDetails a
	left join ClinicalChart b on a.BranchId = b.BranchId ANd a.PCode = b.PCode
	LEFT join (
	SELECT BranchId, SUM(Sales-ReturnAmount) as Sales, sum(Collection-ReturnCash) as Collection, SUM(Less) AS Less 
	FROM SalesLedger where BranchId = @BranchId ANd Valid = 1 AND PatientId = @PatientId GROUP BY BranchId HAVING SUM(Sales-ReturnAmount) > 0
	) c ON a.BranchId = c.BranchId
	LEFT JOIN VW_DiscCardRegNoWise f ON a.BranchId = f.BranchId AND a.RegNo = f.RegNo AND a.PCode = f.PCode
	LEFT JOIN #sales g on g.dept = b.SubDeptName
	where a.Valid = 1 AND a.BranchId = @BranchId AND a.PatientId = @PatientId AND c.BranchId IS NOT NULL
	group by b.SubDeptName, c.Collection, c.Sales, g.TotalSales, f.PcOrTk, a.DeptName, c.Less
) a
GROUP BY a.Particulars, a.DeptName

union all
SELECT 3 AS SlNo, 'Medicine' AS MainDept, '0009' AS Code, 'Medicine Bill' as Particulars, '' as DrCode, SUM(a.Sales) AS Charge, '1' AS Unit, 1 AS NoU,
SUM(a.Sales) AS TotalCharge, SUM(a.LessAmt) AS Less, 0 AS ServiceCharge, 0 AS FixedLess, SUM(a.Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt-a.AdjustAmt) AS Due, 0 as CanLessAmt
FROM PharSalesLedger a
where PatientId = @PatientId AND a.Valid = @IncludePharmacy AND a.BranchId = @BranchId
HAVING SUM(a.Sales) > 0
UNION ALL
SELECT 4 AS SlNo, 'Ambulance' AS MainDept, '0016' AS Code, 'Ambulance Charge' AS Particulars, '' AS DrCode, SUM(a.TotalCharge) AS Charge, '1' AS Unti, 1 AS NoU,
SUM(a.TotalCharge) AS TotalCharge, SUM(a.Less) AS Less, 0 AS ServiceCharge, 0 AS FixedLess, SUM(a.TotalCharge-a.Less-a.ReceiveAmt-a.AdjustAmt) AS Due, 0 as CanLessAmt
FROM AmbulanceLedger a
WHERE a.PatientId = @PatientId AND a.Valid = 1 AND a.BranchId = @BranchId
HAVING SUM(a.TotalCharge) > 0
end
END
GO
