CREATE PROCEDURE [dbo].[SP_GetPaySlip] (@attYear nvarchar(4),@MonthNo integer , @EmpCode nvarchar(10), @UnitId int, @BranchId int)
AS 
BEGIN

IF @EmpCode = '' 
	BEGIN
		SELECT aa.rowNo,aa.TrNO,aa.Code ,aa.empName ,  aa.deptName , aa.DesignName , aa.Projectname,aa.daysPresent,aa.DaysAbsent,aa.TotalWorkDays, aa.AttMName, aa.AttYear,
		aa.EarId , aa.EarFName ,aa.Earnings , bb.DedId,bb.DedFName,bb.DedAmount, aa.EmpImage, aa.Signature
		FROM
		(select ROW_NUMBER() OVER(partition by a.code order by a.code) AS RowNo ,a.Trno,a.Code , a.empName ,a.SalaryTypeId AS EarId , a.SalaryFName AS EarFName, a.Amount as Earnings , 0 as DeducFId  , space(20) as DeducFName , 0 as DeductAmt , a.deptName , a.DesignName , a.Projectname , a.daysPresent,a.DaysAbsent,a.TotalWorkDays, a.AttMName, a.AttYear
		, b.EmpImage, b.Signature
		from Payregister a, HREmployeeMaster b where a.AttYear = @attYear and a.AttMonth = @MonthNo
		AND a.UnitId=@UnitId AND a.BranchId=@BranchId AND a.UnitId=b.UnitId AND a.BranchId=b.BranchId 
		and a.Salarytype='e' And a.Valid = 1 
		AND a.Code=b.Code AND a.EmpId=b.EmpId AND b.Valid=1
		AND a.DeptName=b.Department AND a.DesignName=b.Designation)  aa
		 FULL OUTER JOIN 
		(select ROW_NUMBER() OVER(partition by a.code order by a.code) AS RowNo ,a.Trno,a.Code , a.empName ,0 as EarId,Space(10) as EarFName , 0 as Earnings , a.SalaryTypeId AS DedId, 
		a.SalaryFName AS DedFName, a.Amount as DedAmount, b.EmpImage, b.Signature
		from Payregister a, HREmployeeMaster b where a.AttYear = @attYear and a.AttMonth = @MonthNo
		and a.Salarytype='d'  And a.Valid = 1 
		AND a.UnitId=@UnitId AND a.BranchId=@BranchId AND a.UnitId=b.UnitId AND a.BranchId=b.BranchId 
		AND a.Code=b.Code AND a.EmpId=b.EmpId AND b.Valid=1
		AND a.DeptName=b.Department AND a.DesignName=b.Designation) bb
		ON aa.RowNo = bb.RowNo AND aa.Code=bb.code 
	END
ELSE
	BEGIN
		SELECT aa.rowNo,aa.TrNO,aa.Code ,aa.empName ,  aa.deptName , aa.DesignName,  aa.Projectname,aa.daysPresent,aa.DaysAbsent,aa.TotalWorkDays, aa.AttMName, aa.AttYear,
		aa.EarId , aa.EarFName ,aa.Earnings , bb.DedId,bb.DedFName,bb.DedAmount, aa.EmpImage, aa.Signature
		FROM
		(select ROW_NUMBER() OVER(partition by a.code order by a.code) AS RowNo ,a.Trno,a.Code , a.empName ,a.SalaryTypeId AS EarId , a.SalaryFName AS EarFName, a.Amount as Earnings , 0 as DeducFId  , space(20) as DeducFName , 0 as DeductAmt , a.deptName , a.DesignName , a.Projectname , a.daysPresent,a.DaysAbsent,a.TotalWorkDays, a.AttMName, a.AttYear,
		b.EmpImage, b.Signature
		from Payregister a, HREmployeeMaster b where a.AttYear = @attYear and a.AttMonth = @MonthNo
		AND a.UnitId=@UnitId AND a.BranchId=@BranchId AND a.UnitId=b.UnitId AND a.BranchId=b.BranchId 
		and a.Salarytype='e' And a.Valid = 1 and a.Code = @EmpCode AND a.Code=b.Code AND a.EmpId=b.EmpId AND b.Valid=1
		AND a.DeptName=b.Department AND a.DesignName=b.Designation)  aa
		 FULL OUTER JOIN 
		(select ROW_NUMBER() OVER(partition by a.code order by a.code) AS RowNo ,a.Trno,a.Code , a.empName ,0 as EarId,Space(10) as EarFName , 0 as Earnings , a.SalaryTypeId AS DedId, 
		SalaryFName AS DedFName, a.Amount as DedAmount, b.EmpImage, b.Signature  
		from Payregister a, HREmployeeMaster b where a.AttYear = @attYear and a.AttMonth = @MonthNo
		AND a.UnitId=@UnitId AND a.BranchId=@BranchId AND a.UnitId=b.UnitId AND a.BranchId=b.BranchId 
		and a.Salarytype='d'  And a.Valid = 1 and a.Code = @EmpCode AND a.Code=b.Code AND a.EmpId=b.EmpId AND b.Valid=1
		AND a.DeptName=b.Department AND a.DesignName=b.Designation) bb
		ON aa.RowNo = bb.RowNo AND aa.Code=bb.code 
	END
END


GO
/****** Object:  StoredProcedure [dbo].[sp_GetRosterDetailsDynamic]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[sp_GetRosterDetailsDynamic] @DateFrom date, @DateTo date, @DeptCode varchar(20), @DesigCode varchar(20), @BranchId integer
AS 

DROP TABLE tmpRoster

BEGIN  ---EXEC sp_GetRosterDetailsDynamic '2024-07-01','2024-07-10', '146', '', 1
DECLARE @RowCnt int; SET @RowCnt = 0; -- Loop Counter  
DECLARE @tblLoop TABLE (RowNum int ,daysName nvarchar(100),RosterDate date,RecordFor nvarchar(20),EmpId nvarchar(20),EmpCode nvarchar(20))    

--daysname, date in a table order by date in @tblLoop
WHILE @RowCnt < (select DATEdiff (d,@DateFrom, @DateTo))+1
BEGIN  
	INSERT INTO @tblLoop (RowNum , daysName , RosterDate , RecordFor)
	VALUES(@RowCnt,(SELECT DATENAME(DW ,convert(date,DATEADD (d,@RowCnt,@DateFrom),101))),
	(SELECT convert(date,DATEADD (d,@RowCnt,@DateFrom),101)),'Day'+dbo.LPAD (@RowCnt+1,2,'0'))
	SET @RowCnt = @RowCnt + 1
END  

--Days Name in temporary table #days
select RecordFor, daysName, RowNum as DaysValue, 'G2' as Gid, 2 as SlNo, space(100) AS Name, space(100) as Designation, space(100) as Dept, 1 AS IsRoster
INTO #days
FROM @tblLoop

--Date in temporary table #days
UNION ALL
select RecordFor, CONVERT(nvarchar(20), RosterDate), RowNum as DaysValue, 'G1' as Gid, 1 as SlNo, '' AS Name, '' AS Designation, '' AS Dept, 1 AS IsRoster
FROM @tblLoop

UNION ALL
--Day and date with employee information
select RecordFor, CONVERT(nvarchar(20),RosterDate), RowNum as DaysValue, b.Code as Gid, 3 as SlNo, b.Name, b.Designation, b.Department, 0 AS IsRoster
FROM @tblLoop a, HREmployeeMaster b
WHERE b.BranchId = @BranchId AND b.Valid = 1 AND (CASE WHEN @DeptCode = '' THEN '' ELSE b.DeptCode END) = @deptCode AND b.DesigCode LIKE '%'+@DesigCode +'%'
and WorkingStatusId = 1
ORDER By slno , gid , RecordFor

--After Save date in roster
update #days set daysName = b.ShiftId, IsRoster = 1
from #days a
LEFT JOIN EmployeeRosterDetails b on b.RosterDate = a.daysName and b.Code = a.Gid
where a.Gid not in ('G1', 'G2') AND b.ShiftId IS NOT NULL

--Before Save date in roster
UPDATE #days SET daysName = c.Id, IsRoster = 1
FROM #days a, EmployeeGroupInfo b, HRGroupInfo c
WHERE a.SlNo=3 and a.Gid = b.Code and c.ShiftName = b.GeneralShift
and b.Valid = 1 AND a.IsRoster = 0
AND UPPER(datename(dw,cast(daysName as date))) = UPPER(b.DayName)  

select * INTO #t1 from HREmployeeMaster where code not in (SELECT code from EmployeeGroupInfo)

UPDATE #days SET daysName = 'General' where Gid in (SELECT Code From #t1)

DECLARE @cols AS NVARCHAR(MAX), @query AS NVARCHAR(MAX);

SET @cols = STUFF((SELECT distinct ',' + QUOTENAME(c.recordFor) as ColName
                   FROM #days c  ORDER BY ColName
                   FOR XML PATH(''), TYPE 
                   ).value('.', 'NVARCHAR(MAX)')
                 ,1,1,'');

SET @query = 'SELECT slno,Gid,Name,Dept,Designation,' + @cols + ' INTO tmpRoster FROM 
              (
                  SELECT slno, Name, Designation, Dept,	Gid, DaysName, recordFor
				  FROM #days
              ) x
              PIVOT 
              (
                  MAX(DaysName) FOR recordFor IN (' + @cols + ')
              ) p ORDER BY SlNo,Gid';

EXECUTE(@query);

--select * from tmpRoster ORDER BY Dept, Designation
END
GO
