CREATE PROCEDURE [dbo].[sp_GetSalarySheet] (@attyear nvarchar(4),@monthNo integer)
AS 

drop table tmpSalary

DECLARE @cols AS NVARCHAR(MAX),
@query  AS NVARCHAR(MAX);

BEGIN

SET @cols = STUFF((SELECT distinct ',' + QUOTENAME(c.SalaryFName) 
            FROM Payregister c
			where AttYear = @attyear AND AttMonth = @monthNo 
            FOR XML PATH(''), TYPE
            ).value('.', 'NVARCHAR(MAX)') 
        ,1,1,'')

set @query = 'SELECT empid, empname, DeptName, DesignName, DeptCode, DesigCode, ' + @cols + ' INTO tmpSalary from 
            (
                select empid
					, empname
                    , amount
					, DeptName
					, DesignName
					, DeptCode
					, DesigCode
					, salaryFName
                from Payregister
           ) x
            pivot 
            (
                 max(amount)
                for salaryFName in (' + @cols + ')
            ) p '


execute(@query)
select * from tmpSalary
END




GO
