CREATE Procedure [dbo].[SP_GetSMSData] (@SMSFor nvarchar(50), @DrCode nvarchar(20), @DateFrom Date, @DateTo date, @DeptName nvarchar(50))
as 
begin
	IF @SMSFor  = 'Appointed Patient' 
		BEGIN
			IF (@DrCode = '')
				SELECT MobileNo, PatientName as FName , DrCode AS Code 
				FROM PatientAppointment 
				WHERE Valid = 1
				AND VisitDate BETWEEN @DateFrom  AND @DateTo 
				AND LEN(MobileNo)=11
				GROUP BY MobileNo, PatientName ,DrCode
				ORDER BY MobileNo

			ELSE
				SELECT MobileNo, PatientName as FName , DrCode AS Code 
				FROM PatientAppointment 
				WHERE Valid = 1 AND DrCode = @DrCode 
				AND VisitDate BETWEEN @DateFrom  AND @DateTo 
				AND LEN(MobileNo)=11
				GROUP BY MobileNo, PatientName ,DrCode
				ORDER BY MobileNo
		END

	ELSE IF @SMSFor  = 'General Patient'
		SELECT TelephoneNo AS MobileNo, PatientName AS FName , '-' AS Code 
		FROM PatientRegistration 
		WHERE Valid = 1 
		AND RegDate  BETWEEN @DateFrom  AND @DateTo  AND len(TelephoneNo)=11 
		GROUP BY TelephoneNo, PatientName ORDER BY TelephoneNo

	ELSE IF @SMSFor  = 'Consultants/Doctors/Others'
		SELECT Tel AS MobileNo,DrName  AS FName,DrCode AS Code 
		FROM DrInfo 
		WHERE  len(Tel)=11 
		AND (DeptName+DrType) LIKE '%'+@DeptName+'%'
		AND DrAvailibility = 'Available'  
		GROUP BY DrCode, DrName, Tel 
		ORDER BY DrCode
	ELSE IF @SMSFor  = 'Employees'
		SELECT MobileNo,Name as FName ,Code  
		FROM HREmployeeMaster
		WHERE Valid = 1
		AND WorkingStatus = 'Working'
		GROUP BY MobileNo,Name , Code
		ORDER BY MobileNo
	ELSE IF @SMSFor  = 'Individuals'
		SELECT MobNo as MobileNo ,FName , '-' AS Code 
		FROM PhoneBook 
		WHERE VALID = 1
END





GO
