CREATE Procedure [dbo].[SP_GrossProfit_SMZ_CompanyWise] @BranchId int, @UnitId int, @DateFrom date, @DateTo date, @companyId nvarchar(20), @PtStatus nvarchar(15), @StoreId nvarchar(10)
AS --- Exec SP_GrossProfit_SMZ_CompanyWise 1, 1, '2022-01-01', '2023-10-31', '','',''
BEGIN
SELECT a.StoreId, c.SubSubPno as StoreName, a.PtStatus, a.CompanyId, b.Name as CompanyName,  SUM(a.ProductQty) as TSalesQty, SUM(a.ProductQty*a.SalePrice) as TotalSales,SUM(a.ProductQty*a.TP) as TotalTP, SUM((a.SalePrice* a.ProductQty) - (a.ProductQty*a.TP)) as GrossProfit
FROM PharSalesDetails a 
left join PharCompanyInfo b On a.CompanyId=b.Company_Id
Left join ProjectInformations c On a.StoreId=c.PnoCode
where a.Valid=1 AND a.BranchId=@BranchId AND a.UnitId=@UnitId  AND SaleDate Between @DateFrom AND @DateTo AND a.CompanyId + a.PtStatus  LIKE '%'+@companyId+'%' +@PtStatus+'%' AND a.StoreId LIKE '%'+@StoreId+'%'
GROUP BY  a.StoreId, c.SubSubPno, a.PtStatus, a.CompanyId, b.Name
ORDER BY a.StoreId, a.PtStatus, a.CompanyId
END
GO
