CREATE Procedure [dbo].[SP_GrossProfit_SMZ_ProductWise] @BranchId int, @UnitId int, @DateFrom date, @DateTo date, @ProductId nvarchar(10), @PtStatus nvarchar(15), @StoreId nvarchar(10)
AS --- Exec SP_GrossProfit_SMZ_ProductWise 1, 1, '2021-01-01', '2023-12-31', '4402','',''
BEGIN
SELECT a.StoreId, d.SubSubPno as StoreName, a.PtStatus, a.CompanyId, b.Name as CompanyName, a.ProductId , c.ProductName,  SUM(a.ProductQty) as TSalesQty, SUM(a.ProductQty*a.SalePrice) as TotalSales,SUM(a.ProductQty*a.TP) as TotalTP, SUM((a.SalePrice* a.ProductQty) - (a.ProductQty*a.TP)) as GrossProfit
FROM PharSalesDetails a 
left join PharCompanyInfo b On a.CompanyId=b.Company_Id
left join PharProductInfo c On a.ProductId=c.Id
Left join ProjectInformations d On a.StoreId=d.PnoCode
where a.Valid=1 AND a.BranchId=@BranchId AND a.UnitId=@UnitId  AND SaleDate Between @DateFrom AND @DateTo AND a.ProductId LIKE '%'+@ProductId+'%' AND 
 a.PtStatus LIKE '%'+@PtStatus+'%' AND a.StoreId LIKE '%'+@StoreId+'%'
GROUP BY a.StoreId, d.SubSubPno, a.PtStatus, a.CompanyId, b.Name, a.ProductId , c.ProductName
ORDER BY a.StoreId, a.PtStatus, a.CompanyId
END
