CREATE PROCEDURE [dbo].[SP_Hospital_Discharge_Certificate] (@param nvarchar(50), @BranchId INT)
AS 
SELECT DISTINCT Top 100 a.PatientId, a.PatientName, a.AdmissionDate, a.AdmissionTime, a.PatientSex, a.PatientAge, ISNULL(a.ReleaseDate, GETDATE()) AS ReleaseDate, c.EntryTime as ReleaseTime , a.ReleaseTimeRemarks, a.PatientAddress,
a.Religion, a.Phone1, a.UnderDrCode, a.UnderDrName, a.BedNo, DATEDIFF(day, a.AdmissionDate, ISNULL(a.ReleaseDate, GETDATE()))+1 as TotalDays,
ISNULL(SUBSTRING((SELECT DISTINCT ',' + ShortDesc FROM InvDetails where PatientId = a.PatientId and RegNo = a.RegNo FOR XML PATH('')), 2 , 1000),'') As InvsName,
ISNULL(SUBSTRING((SELECT DISTINCT ',' + ProductName FROM PharSalesDetails where PatientId = a.PatientId and RegNo = a.RegNo FOR XML PATH('')), 2 , 1000),'') As Medicine, ISNULL(b.OTNote,'') as OTNote
FROM PatientAdmission a
left join tbl_OTSettlementMaster b on a.PatientId = b.PatientId and a.RegNo = b.RegNo 
left join PatientReleaseMaster c on a.PatientId=c.PatientID and a.RegNo=b.RegNo AND c.BranchId = a.BranchId
WHERE a.BranchId = @BranchId AND a.Valid=1 AND (a.PatientId+a.PatientName+a.PatientTel+a.RegNo) Like '%'+@param+'%'
order by PatientId desc
GO
/****** Object:  StoredProcedure [dbo].[SP_Hospital_ItemWiseSalesReportSummarized]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[SP_Hospital_ItemWiseSalesReportSummarized](@DateFrom nvarchar(20), @DateTo nvarchar(20), @BranchId int, @UnitId int)
AS
	BEGIN
		select aa.Code, aa.Particulars, sum(aa.TotalCharge) as TotalCharge, sum(aa.LessAmt) As LessAmt, sum(aa.NetAmount) as NetAmt from
		(
		select Code, Particulars, SUM((Charge*NoU)+ServiceCharge) as TotalCharge, SUM(Less) as LessAmt, SUM((Charge*NoU)+ServiceCharge-Less) AS NetAmount
		from  PatientLedger 
		where Code <> '0002' and Status <> 'Advance Collection' and Valid = 1 AND BranchId = @BranchId AND CostCenterName = @UnitId and RefDate BETWEEN @DateFrom and @DateTo
		group by Code, Particulars
		UNION ALL
		select Code, LEFT(Particulars,10), SUM((Charge*NoU)+ServiceCharge) as TotalCharge, SUM(Less) as LessAmt, SUM((Charge*NoU)+ServiceCharge-Less) AS NetAmount 
		from  PatientLedger where Code = '0002' AND Valid = 1 AND BranchId = @BranchId AND CostCenterName = @UnitId and RefDate BETWEEN @DateFrom and @DateTo
		group by Code, LEFT(Particulars,10)
		) aa
		group by aa.Code, aa.Particulars
		order by aa.Particulars
	END


GO
