CREATE PROC [dbo].[SP_Hospital_TopContributor](@DateFrom date, @DateTo date, @DrCode nvarchar(20))
AS
if @DrCode = 'RefDr'
BEGIN

select aa.DrCode, aa.DrName, sum(TotalAmt) as TotalAmt, SUM(aa.LessAmt) as LessAmt, SUM(aa.NetTotal) as NetTotal, SUM(aa.PathIncome) AS PathIncome, SUM(aa.MedicineIncome) as MedicineIncome, SUM(aa.Consultant) as Consultant, SUM(aa.DoctorFees) as DoctorFees from (

SELECT a.RefDrCode AS DrCode, c.DrName AS DrName, sum(b.Charge+b.ServiceCharge) AS TotalAmt, sum(b.LessAmt) as LessAmt, sum(b.Charge+b.ServiceCharge-b.LessAmt) AS NetTotal,
 0 AS PathIncome, 0 AS MedicineIncome, 0 AS Consultant, 0 AS DoctorFees
FROM PatientReleaseMaster a ,  PatientReleaseDetails b , DrInfo c  
WHERE a.ReceiptNo = b.ReceiptNo And a.ReleaseDate = b.ReleaseDate And a.Valid = 1  AND a.RefDrCode=c.DrCode AND a.BillStatus=0 
--AND b.InvestigationCode NOT IN ('0011','0186','4025')
AND a.ReleaseDate BETWEEN @DateFrom AND @DateTo
GROUP BY a.RefDrCode,c.DrName

UNION ALL

SELECT a.RefDrCode AS DrCode, c.DrName AS DrName, 0 AS TotalAmt, 0 as LessAmt, 0 AS NetTotal,
sum(b.Charge+b.ServiceCharge-b.LessAmt) AS PathIncome, 0 AS MedicineIncome, 0 AS Consultant, 0 AS DoctorFees
FROM PatientReleaseMaster a ,  PatientReleaseDetails b , DrInfo c  
WHERE a.ReceiptNo = b.ReceiptNo And a.ReleaseDate = b.ReleaseDate And a.Valid = 1  AND a.RefDrCode=c.DrCode AND a.BillStatus=0 
AND b.InvestigationCode IN ('4027')
AND a.ReleaseDate BETWEEN  @DateFrom AND @DateTo
GROUP BY a.RefDrCode,c.DrName

UNION ALL

SELECT a.RefDrCode AS DrCode, c.DrName AS DrName, 0 AS TotalAmt, 0 as LessAmt, 0 AS NetTotal,
0 AS PathIncome, sum(b.Charge+b.ServiceCharge-b.LessAmt) AS MedicineIncome, 0 AS Consultant, 0 AS DoctorFees
FROM PatientReleaseMaster a ,  PatientReleaseDetails b , DrInfo c  
WHERE a.ReceiptNo = b.ReceiptNo And a.ReleaseDate = b.ReleaseDate And a.Valid = 1  AND a.RefDrCode=c.DrCode AND a.BillStatus=0 
AND b.InvestigationCode IN ('0011','0186','4025')
AND a.ReleaseDate BETWEEN  @DateFrom AND @DateTo
GROUP BY a.RefDrCode,c.DrName

UNION ALL

SELECT a.RefDrCode AS DrCode, c.DrName AS DrName, 0 AS TotalAmt, 0 as LessAmt, 0 AS NetTotal,
0 AS PathIncome, 0 AS MedicineIncome, 0 AS Consultant, sum(b.Charge+b.ServiceCharge-b.LessAmt) AS DoctorFees
FROM PatientReleaseMaster a ,  PatientReleaseDetails b , DrInfo c  
WHERE a.ReceiptNo = b.ReceiptNo And a.ReleaseDate = b.ReleaseDate And a.Valid = 1  AND a.RefDrCode=c.DrCode AND a.BillStatus=0 
AND b.InvestigationCode IN ('0004','0005','0006','0007','0037','0056','9991','9992','0061','9990','0054','0061','0063','0054')
AND a.ReleaseDate BETWEEN  @DateFrom AND @DateTo
GROUP BY a.RefDrCode,c.DrName
) aa
group by aa.DrCode, aa.DrName

END
else

BEGIN
select aa.DrCode, aa.DrName, sum(TotalAmt) as TotalAmt, SUM(aa.LessAmt) as LessAmt, SUM(aa.NetTotal) as NetTotal, SUM(aa.PathIncome) AS PathIncome, SUM(aa.MedicineIncome) as MedicineIncome, SUM(aa.Consultant) as Consultant, SUM(aa.DoctorFees) as DoctorFees from (

SELECT a.UnderDrCode AS DrCode, c.DrName AS DrName, sum(b.Charge+b.ServiceCharge) AS TotalAmt, sum(b.LessAmt) as LessAmt, sum(b.Charge+b.ServiceCharge-b.LessAmt) AS NetTotal,
 0 AS PathIncome, 0 AS MedicineIncome, 0 AS Consultant, 0 AS DoctorFees
FROM PatientReleaseMaster a ,  PatientReleaseDetails b , DrInfo c  
WHERE a.ReceiptNo = b.ReceiptNo And a.ReleaseDate = b.ReleaseDate And a.Valid = 1  AND a.UnderDrCode=c.DrCode AND a.BillStatus=0 
--AND b.InvestigationCode NOT IN ('0011','0186','4025')
AND a.ReleaseDate BETWEEN  @DateFrom AND @DateTo
GROUP BY a.UnderDrCode,c.DrName

UNION ALL

SELECT a.UnderDrCode AS DrCode, c.DrName AS DrName, 0 AS TotalAmt, 0 as LessAmt, 0 AS NetTotal,
sum(b.Charge+b.ServiceCharge-b.LessAmt) AS PathIncome, 0 AS MedicineIncome, 0 AS Consultant, 0 AS DoctorFees
FROM PatientReleaseMaster a ,  PatientReleaseDetails b , DrInfo c  
WHERE a.ReceiptNo = b.ReceiptNo And a.ReleaseDate = b.ReleaseDate And a.Valid = 1  AND a.UnderDrCode=c.DrCode AND a.BillStatus=0 
AND b.InvestigationCode IN ('4027')
AND a.ReleaseDate BETWEEN  @DateFrom AND @DateTo
GROUP BY a.UnderDrCode,c.DrName

UNION ALL

SELECT a.UnderDrCode AS DrCode, c.DrName AS DrName, 0 AS TotalAmt, 0 as LessAmt, 0 AS NetTotal,
0 AS PathIncome, sum(b.Charge+b.ServiceCharge-b.LessAmt) AS MedicineIncome, 0 AS Consultant, 0 AS DoctorFees
FROM PatientReleaseMaster a ,  PatientReleaseDetails b , DrInfo c  
WHERE a.ReceiptNo = b.ReceiptNo And a.ReleaseDate = b.ReleaseDate And a.Valid = 1  AND a.UnderDrCode=c.DrCode AND a.BillStatus=0 
AND b.InvestigationCode IN ('0011','0186','4025')
AND a.ReleaseDate BETWEEN  @DateFrom AND @DateTo
GROUP BY a.UnderDrCode,c.DrName

UNION ALL

SELECT a.UnderDrCode AS DrCode, c.DrName AS DrName, 0 AS TotalAmt, 0 as LessAmt, 0 AS NetTotal,
0 AS PathIncome, 0 AS MedicineIncome, 0 AS Consultant, sum(b.Charge+b.ServiceCharge-b.LessAmt) AS DoctorFees
FROM PatientReleaseMaster a ,  PatientReleaseDetails b , DrInfo c  
WHERE a.ReceiptNo = b.ReceiptNo And a.ReleaseDate = b.ReleaseDate And a.Valid = 1  AND a.UnderDrCode=c.DrCode AND a.BillStatus=0 
AND b.InvestigationCode IN ('0004','0005','0006','0007','0037','0056','9991','9992','0061','9990','0054','0061','0063','0054')
AND a.ReleaseDate BETWEEN  @DateFrom AND @DateTo
GROUP BY a.UnderDrCode,c.DrName
) aa
group by aa.DrCode, aa.DrName
END




