/****** Object:  StoredProcedure [dbo].[SP_HospitalAchivementReport]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SP_HospitalAchivementReport] (@datefrom date , @dateto date , @BranchId integer)
AS 
BEGIN ---EXEC SP_HospitalAchivementReport '2023-01-01' , '2023-12-31',1
	select 1 as SlNo,'Admitted Patient' as Particular , COUNT(*)  AS NoofPt
	from PatientAdmission a , BedInformation b
	where a.FirstBedNo = b.BedNo 
	and a.AdmissionDate BETWEEN @datefrom  and @dateto and a.BranchId = @BranchId 
	AND b.BedType IN ('Cabin','General','Ward')
	UNION ALL
	select 2 as SlNo,b.BedType + ' Admitted Patient' as Typpe , COUNT(*)  AS NoofPt
	from PatientAdmission a , BedInformation b
	where a.FirstBedNo = b.BedNo 
	and a.AdmissionDate BETWEEN @datefrom  and @dateto and a.BranchId = @BranchId 
	AND b.BedType NOT IN ('Cabin','General','Ward')
	group by b.BedType
	UNION ALL
	select 3,'OT',count(*) 
	from OTScheduleMaster ----tbl_OTSettlementMaster 
	WHERE Valid = 1
	and RefDate BETWEEN @datefrom  and @dateto --and BranchId = @BranchId 
	UNION ALL
	select 4,'Outdoor Serial', Count(*) from PatientAppointment  --'Total Appointment'
	where VisitDate BETWEEN @datefrom  and @dateto and BranchId = @BranchId 
	and valid =1 
	UNION ALL
	select 5,'Outdoor Patient', Count(*) from PatientAppointment -- 'Total Visited'
	where VisitDate BETWEEN @datefrom  and @dateto and BranchId = @BranchId 
	and IsArrival = 1
	and valid =1 
	UNION ALL
	select 6,'Outdoor Consultant' , count(distinct drcode)  from PatientAppointment -- 'No of Consultant'
	where valid = 1
	and visitDate BETWEEN @datefrom  and @dateto and BranchId = @BranchId 
	UNION ALL
	select 10 as SlNo,b.SubSubDeptName , count(*) as Noofpt 
	from InvDetails a , ClinicalChart b
	where a.PCode = b.PCode and a.branchId=b.BranchId 
	and a.valid = 1 and a.DeptName IN ('DIAGNOSTIC')
	and a.InvDate BETWEEN @datefrom  and @dateto and a.BranchId = @BranchId 
	GROUP BY b.SubSubDeptName
	UNION ALL
	SELECT 11 as SlNo,DeptName, COUNT(*) as NoofPt
	from InvMaster
	WHERE Valid = 1 AND DeptName IN ('Emergency')
	and InvDate BETWEEN @datefrom  and @dateto and BranchId = @BranchId 
	GROUP BY DeptName
	UNION ALL
	SELECT 12 as SlNo,DeptName, COUNT(*) as NoofPt
	from InvMaster
	WHERE Valid = 1 AND DeptName IN ('Dental')
	and InvDate BETWEEN @datefrom  and @dateto and BranchId = @BranchId 
	GROUP BY DeptName
	UNION ALL
	SELECT 13 as SlNo,DeptName, COUNT(*) as NoofPt
	from InvMaster
	WHERE Valid = 1 AND DeptName NOT IN ('Dental','Emergency')
	and InvDate BETWEEN @datefrom  and @dateto and BranchId = @BranchId 
	GROUP BY DeptName
	UNION ALL
	select 14,'Pharmacy Sales '+PtStatus ,  SUM(Sales) as NoofPt
	from pharSalesLedger
	WHERE Valid = 1 
	and TrDate BETWEEN @datefrom  and @dateto and BranchId = @BranchId 
	GROUP BY PtStatus
	UNION ALL
	select 15,'Pharmacy Sales Total' ,  SUM(Sales) as NoofPt
	from pharSalesLedger
	WHERE Valid = 1 
	and TrDate BETWEEN @datefrom  and @dateto and BranchId = @BranchId 
	ORDER BY slno,Particular
END


GO
/****** Object:  StoredProcedure [dbo].[SP_HospitalItemWiseSalesReportDtls]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SP_HospitalItemWiseSalesReportDtls] (@DateFrom DateTime,@DateTo DateTime, @Code nvarchar(30), @BranchId int, @UnitId int)
AS 
if @Code = ''
BEGIN
	select aa.Code, aa.Particulars, aa.RefNo, aa.ReleaseDate, aa.PatientId, aa.PatientName, sum(aa.TotalAmt) as TotalAmt, sum(aa.Less) AS Less, SUM(aa.NetAmt) AS NetAmt from (
	select a.Code, a.Particulars, a.RefNo, b.ReleaseDate, a.PatientId, a.PatientName, SUM((a.Charge*a.NoU)+a.ServiceCharge) As TotalAmt, SUM(a.Less) AS Less, SUM((a.Charge*a.NoU)+a.ServiceCharge-a.Less) As NetAmt
	from PatientLedger a, PatientAdmission b
	where a.PatientId = b.PatientId AND a.BranchId = b.BranchId and a.RegNo = b.RegNo and a.Valid = 1
	and Code <> '0002' and Status <> 'Advance Collection' and b.IsRelease = 1 AND a.BranchId = @BranchId ANd a.CostCenterName = @UnitId and a.RefDate BETWEEN @DateFrom and @DateTo
	group by a.Code, a.Particulars, a.RefNo, b.ReleaseDate, a.PatientId, a.PatientName
--order by a.Particulars
	UNION ALL
	select a.Code, LEFT(a.Particulars,10) as Particulars, a.RefNo, b.ReleaseDate, a.PatientId, a.PatientName, SUM((a.Charge*a.NoU)+a.ServiceCharge) As TotalAmt, SUM(a.Less) AS Less, SUM((a.Charge*a.NoU)+a.ServiceCharge-a.Less) As NetAmt
	from PatientLedger a, PatientAdmission b
	where a.PatientId = b.PatientId AND a.BranchId = b.BranchId and a.RegNo = b.RegNo and a.Valid = 1
	and Code = '0002' and b.IsRelease = 1 and a.BranchId = @BranchId AND a.CostCenterName = @UnitId AND a.RefDate BETWEEN @DateFrom and @DateTo
	group by a.Code, LEFT(a.Particulars,10) , a.RefNo, b.ReleaseDate, a.PatientId, a.PatientName
	) aa
	group by aa.Code, aa.Particulars, aa.RefNo, aa.ReleaseDate, aa.PatientId, aa.PatientName
	order by aa.Particulars
END
else
BEGIN
	select aa.Code, aa.Particulars, aa.RefNo, aa.ReleaseDate, aa.PatientId, aa.PatientName, sum(aa.TotalAmt) as TotalAmt, sum(aa.Less) AS Less, SUM(aa.NetAmt) AS NetAmt from (
	select a.Code, a.Particulars, a.RefNo, b.ReleaseDate, a.PatientId, a.PatientName, SUM((a.Charge*a.NoU)+a.ServiceCharge) As TotalAmt, SUM(a.Less) AS Less, SUM((a.Charge*a.NoU)+a.ServiceCharge-a.Less) As NetAmt
	from PatientLedger a, PatientAdmission b
	where a.PatientId = b.PatientId and a.RegNo = b.RegNo AND a.BranchId = b.BranchId and a.Valid = 1
	and Code <> '0002' and Status <> 'Advance Collection' and b.IsRelease = 1 AND a.BranchId = @BranchId AND a.CostCenterName = @UnitId and a.RefDate BETWEEN @DateFrom and @DateTo and a.Code = @Code
	group by a.Code, a.Particulars, a.RefNo, b.ReleaseDate, a.PatientId, a.PatientName
--order by a.Particulars
	UNION ALL
	select a.Code, LEFT(a.Particulars,10) AS Particulars, a.RefNo, b.ReleaseDate, a.PatientId, a.PatientName, SUM((a.Charge*a.NoU)+a.ServiceCharge) As TotalAmt, SUM(a.Less) AS Less, SUM((a.Charge*a.NoU)+a.ServiceCharge-a.Less) As NetAmt
	from PatientLedger a, PatientAdmission b
	where a.PatientId = b.PatientId and a.RegNo = b.RegNo and a.Valid = 1 AND a.BranchId = b.BranchId
	and Code = '0002' and b.IsRelease = 1 and a.BranchId = @BranchId AND a.CostCenterName = @UnitId AND a.RefDate BETWEEN @DateFrom and @DateTo and a.Code = @Code
	group by a.Code, LEFT(a.Particulars,10), a.RefNo, b.ReleaseDate, a.PatientId, a.PatientName
	) aa
	group by aa.Code, aa.Particulars, aa.RefNo, aa.ReleaseDate, aa.PatientId, aa.PatientName
	order by aa.Particulars
END

---------------
GO
/****** Object:  StoredProcedure [dbo].[SP_HospitalPharmacySalesCollAll]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SP_HospitalPharmacySalesCollAll] (@DateFrom DateTime , @DateTo DateTime, @BranchId int, @UnitId int)
AS 
BEGIN

	--   EXEC SP_HospitalPharmacySalesCollAll '2025-11-01','2025-11-15',1,1

	SELECT aa.DeptName AS DeptName, ROUND(ISNULL(SUM(aa.Sales),0),0) as Sales, ROUND(ISNULL(SUM(aa.Less),0),0) AS Less,
	ROUND(ISNULL(SUM(aa.RtnAmt),0),0) AS RtnAmt, ROUND(ISNULL(SUM(aa.Sales -aa.Less - aa.RtnAmt),0),0) AS NetSales, 
	ROUND(ISNULL(SUM(aa.ByCash),0),0) AS ByCash, ROUND(ISNULL(SUM(aa.ByCard),0),0) AS ByCard, 
	ROUND(ISNULL(SUM(aa.ByCheque),0),0) AS ByCheque, ROUND(ISNULL(SUM(aa.TotalColl),0),0) AS TotalCall, 
	ROUND(ISNULL(SUM(aa.CashReturn),0),0) AS CashReturn ,SUM(TotalPt) AS TotalPt,SUM(aa.DueCollection) AS DueCollection,
	SUM(aa.Sales-aa.Less-aa.RtnAmt-aa.TotalColl-aa.AdvanceAdjust) AS Due, 
	SUM(aa.DueCollLess) As DueCollLess,SUM(aa.AdvanceAmt) AS AdvanceAmt,SUM(aa.AdvanceAdjust) AS AdvanceAdjust,
	SUM(aa.TotalColl+aa.DueCollection+aa.AdvanceAmt-aa.CashReturn) AS NetCollection
	FROM (
	--------START INDOOR---------
	

	SELECT 1 as slno,'INDOOR' AS MainDept, b.SubSubPno AS DeptName, 0 AS Sales, 0 AS Less, 0 AS RtnAmt,
	SUM(a.CashAmt) AS ByCash, SUM(a.CardAmt) AS ByCard, SUM(a.ChequeAmt) AS ByCheque, 
	SUM(a.CashReturn) AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PharSalesLedger a LEFT JOIN ProjectInformations b
	on a.StoreId=b.PnoCode
	where a.Valid = 1 and a.PtStatus = 'Indoor'
	and a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	group by b.SubSubPno


	UNION ALL

	SELECT 1 as slno,'INDOOR' AS MainDept, b.SubSubPno as SubSubPno, 0 AS Sales, 0 AS Less, 0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,sum(a.Collection+a.DueColl) AS TotalColl,
	0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PharSalesLedger a LEFT JOIN ProjectInformations b
	on a.StoreId=b.PnoCode
	where a.Valid = 1 and a.PtStatus = 'Indoor'
	and a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	and a.PatientId IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)
	group by b.SubSubPno

	UNION ALL

	SELECT 1 as slno,'INDOOR' AS MainDept, b.SubSubPno as SubSubPno, 0 AS Sales, 0 AS Less, 0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	sum(a.Collection+a.DueColl) AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PharSalesLedger a LEFT JOIN ProjectInformations b
	on a.StoreId=b.PnoCode
	where a.Valid = 1 and a.PtStatus = 'Indoor'
	and a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	and a.PatientId NOT IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)
	group by b.SubSubPno

	

	UNION ALL

	SELECT 5 as slno,'OUTDOOR' AS MainDept, b.SubSubPno AS DeptName, SUM(SALES) AS Sales, SUM(LessAmt) AS Less, 
	SUM(ReturnAmt) AS RtnAmt,
	SUM(CashAmt) AS ByCash, SUM(CardAmt) AS ByCard, SUM(ChequeAmt) AS ByCheque, 
	SUM(CashReturn) AS CashReturn,SUM(CASE WHEN SALES>0 THEN 1 ELSE 0 END) AS TotalPt,sum(Collection) AS TotalColl,
	SUM(DueColl) AS DueCollection,0 AS Due, SUM(DueLess) As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PharSalesLedger a LEFT JOIN ProjectInformations b
	on a.StoreId=b.PnoCode
	where a.Valid = 1 and a.PtStatus <> 'Indoor'
	and a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	group by  b.SubSubPno

	


	) aa
	GROUP BY aa.DeptName
	
END
GO
/****** Object:  StoredProcedure [dbo].[SP_HospitalSalesCollAll]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SP_HospitalSalesCollAll] (@DateFrom DateTime , @DateTo DateTime, @BranchId int, @UnitId int)
AS 
BEGIN

	--   EXEC SP_HospitalSalesCollAll '2025-11-15','2025-11-15',1,1

	SELECT aa.DeptName AS DeptName, ROUND(ISNULL(SUM(aa.Sales),0),0) as Sales, ROUND(ISNULL(SUM(aa.Less),0),0) AS Less,
	ROUND(ISNULL(SUM(aa.RtnAmt),0),0) AS RtnAmt, ROUND(ISNULL(SUM(aa.Sales -aa.Less - aa.RtnAmt),0),0) AS NetSales, 
	ROUND(ISNULL(SUM(aa.ByCash),0),0) AS ByCash, ROUND(ISNULL(SUM(aa.ByCard),0),0) AS ByCard, 
	ROUND(ISNULL(SUM(aa.ByCheque),0),0) AS ByCheque, ROUND(ISNULL(SUM(aa.TotalColl),0),0) AS TotalCall, 
	ROUND(ISNULL(SUM(aa.CashReturn),0),0) AS CashReturn ,SUM(TotalPt) AS TotalPt,SUM(aa.DueCollection) AS DueCollection,
	SUM(aa.Sales-aa.Less-aa.RtnAmt-aa.TotalColl-aa.AdvanceAdjust) AS Due, 
	SUM(aa.DueCollLess) As DueCollLess,SUM(aa.AdvanceAmt) AS AdvanceAmt,SUM(aa.AdvanceAdjust) AS AdvanceAdjust,
	SUM(aa.TotalColl+aa.DueCollection+aa.AdvanceAmt-aa.CashReturn) AS NetCollection
	FROM (
	--------START INDOOR---------
	SELECT 1 AS SlNo, 'INDOOR' AS MainDept,  'Hospital' AS DeptName, 
	0 AS Sales, 0 AS Less, 0 as RtnAmt,SUM(b.CashAmt) AS ByCash, SUM(b.CardAmt) AS ByCard, SUM(b.ChequeAmt) AS ByCheque, 
	sum(b.ReturnAmt) AS CashReturn,0 AS TotalPt,0 AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,
	0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PatientLedger b LEFT JOIN BedInformation c ON b.BedNo=c.BedNo AND b.BranchId = c.BranchId 
	WHERE b.valid = 1 
	AND b.BranchId = @BranchId 
	and b.RefDate BETWEEN @DateFrom and @DateTo 
	GROUP BY c.SubSubPno
	HAVING SUM(b.CashAmt+b.CardAmt+b.ChequeAmt)>0
	UNION ALL
	SELECT 1 AS SlNo, 'INDOOR' AS MainDept, 'Hospital' AS DeptName, 
	0 AS Sales, 0 AS Less, 0 as RtnAmt,0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,sum(b.Collection) AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,
	0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PatientLedger b LEFT JOIN BedInformation c ON b.BedNo=c.BedNo AND b.BranchId = c.BranchId 
	WHERE b.valid = 1 
	AND b.BranchId = @BranchId 
	and b.RefDate BETWEEN @DateFrom and @DateTo 
	and b.PatientId IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)
	AND b.Status<>'Advance Collection'
	GROUP BY c.SubSubPno
	UNION ALL
	SELECT 1 AS SlNo, 'INDOOR' AS MainDept, 'Hospital' AS DeptName, 0 AS Sales, 0 AS Less, 0 as RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	SUM(b.Collection) AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PatientLedger b LEFT JOIN BedInformation c ON b.BedNo=c.BedNo AND b.BranchId = c.BranchId 
	WHERE b.valid = 1 
	AND b.BranchId = @BranchId 
	and b.RefDate BETWEEN @DateFrom and @DateTo 
	and b.PatientId NOT IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)
	AND b.Status<>'Advance Collection'
	GROUP BY c.SubSubPno
	UNION ALL
	SELECT 1 AS SlNo, 'INDOOR' AS MainDept, 'Hospital' AS DeptName, 0 AS Sales, 0 AS Less, 0 as RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	0 AS DueCollection,0 AS Due, 0 As DueCollLess,SUM(b.Collection) AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PatientLedger b LEFT JOIN BedInformation c ON b.BedNo=c.BedNo AND b.BranchId = c.BranchId  
	WHERE b.valid = 1 
	AND b.BranchId = @BranchId 
	and b.RefDate BETWEEN @DateFrom and @DateTo 
	AND b.Status='Advance Collection'
	GROUP BY c.SubSubPno

	UNION ALL
	SELECT 1 AS SlNo, 'INDOOR' AS MainDept, 'Hospital' AS DeptName, 
	SUM((a.Charge*a.NoOfUnit)+a.ServiceCharge) AS Sales, SUM(LessAmt) AS Less, 0 as RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,
	0 AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PatientReleaseDetails a 
	WHERE a.Valid=1
	AND a.BranchId = @BranchId 
	and a.ReleaseDate BETWEEN @DateFrom and @DateTo 
	GROUP BY a.MainDeptName

	UNION ALL

	SELECT 1 AS SlNo, 'INDOOR' AS MainDept, 'Hospital' AS DeptName, 
	0 AS Sales,0 AS Less, 0 as RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,COUNT(a.PatientID) AS TotalPt,
	0 AS TotalColl,0 AS DueCollection,
	SUM(CASE WHEN a.NetTotalAmt-a.AdvanceAmt-a.NetPaymentAmt+a.ReturnAmt-a.DueCollectionAmt-a.DueCollectionLessAmt>1 THEN
		 a.NetTotalAmt-a.AdvanceAmt-a.NetPaymentAmt+a.ReturnAmt-a.DueCollectionAmt-a.DueCollectionLessAmt ELSE 0 END ) AS Due, 
	0 As DueCollLess,0 AS AdvanceAmt,SUM(AdvanceAmt) AS AdvanceAdjust
	FROM PatientReleaseMaster a 
	WHERE a.Valid=1
	AND a.BranchId = @BranchId 
	and a.ReleaseDate BETWEEN @DateFrom and @DateTo 
	GROUP BY a.MainDeptName

	UNION ALL
	SELECT 1 AS SlNo, 'INDOOR' AS MainDept, 'Hospital' AS DeptName, 
	0 AS Sales, SUM(a.Less) AS Less, 0 as RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,
	0 AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM IndoorDueCollDetails a ,IndoorDueCollMaster b,BedInformation c
	WHERE a.Valid=1 AND a.PatientId=b.PatientId AND a.RefNo=b.RefNo AND a.RefDate=b.RefDate
	AND b.BedNo=c.BedNo
	AND a.BranchId = @BranchId 
	and b.PatientId IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)	
	GROUP BY c.SubSubPno

	UNION ALL
	SELECT 1 AS SlNo, 'INDOOR' AS MainDept, 'Hospital' AS DeptName, 
	0 AS Sales, 0 AS Less, 0 as RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,
	0 AS TotalColl,0 AS DueCollection,0 AS Due, SUM(a.Less) As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM IndoorDueCollDetails a ,IndoorDueCollMaster b,BedInformation c
	WHERE a.Valid=1 AND a.PatientId=b.PatientId AND a.RefNo=b.RefNo AND a.RefDate=b.RefDate
	AND b.BedNo=c.BedNo
	AND a.BranchId = @BranchId 
	and b.PatientId NOT IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)	
	GROUP BY c.SubSubPno

	UNION ALL

	SELECT 1 as slno,'INDOOR' AS MainDept, 'Medicine' as SubSubPno, 0 AS Sales, 0 AS Less, 0 AS RtnAmt,
	SUM(a.CashAmt) AS ByCash, SUM(a.CardAmt) AS ByCard, SUM(a.ChequeAmt) AS ByCheque, 
	SUM(a.CashReturn) AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PharSalesLedger a LEFT JOIN BedInformation b
	on a.BedNo=b.BedNo
	where a.Valid = 1 and a.PtStatus = 'Indoor'
	and a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	group by b.SubSubPno


	UNION ALL

	SELECT 1 as slno,'INDOOR' AS MainDept, 'Medicine' as SubSubPno, 0 AS Sales, 0 AS Less, 0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,sum(a.Collection+a.DueColl) AS TotalColl,
	0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PharSalesLedger a LEFT JOIN BedInformation b
	on a.BedNo=b.BedNo
	where a.Valid = 1 and a.PtStatus = 'Indoor'
	and a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	and a.PatientId IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)
	group by b.SubSubPno

	UNION ALL

	SELECT 1 as slno,'INDOOR' AS MainDept, 'Medicine' as SubSubPno, 0 AS Sales, 0 AS Less, 0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	sum(a.Collection+a.DueColl) AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PharSalesLedger a LEFT JOIN BedInformation b
	on a.BedNo=b.BedNo
	where a.Valid = 1 and a.PtStatus = 'Indoor'
	and a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	and a.PatientId NOT IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)
	group by b.SubSubPno

	UNION ALL
	select 1 as slno, 'INDOOR' AS MainDept, 'Hospital' AS DeptName, 0 AS Sales,0 AS Less,0 AS RtnAmt,
	SUM(ByCash) AS ByCash, SUM(ByCard) AS ByCard, SUM(ChequeAmount) AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	from SalesLedger a LEFT JOIN BedInformation b
	on a.BedNo=b.BedNo
	where valid <> 0 AND a.Department <> 'Ambulance' and a.PtStatus = 'Indoor' 
	And a.RefDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	GROUP BY b.SubSubPno

	UNION ALL

	select 1 as slno, 'INDOOR' AS MainDept, 'Hospital' AS DeptName, 0 AS Sales,0 AS Less,0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,sum(Collection) AS TotalColl,
	0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	from SalesLedger a LEFT JOIN BedInformation b
	on a.BedNo=b.BedNo
	where valid <> 0 AND a.Department <> 'Ambulance' and a.PtStatus = 'Indoor' 
	And a.RefDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	and a.PatientId IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)
	GROUP BY b.SubSubPno

	UNION ALL

	select 1 as slno, 'INDOOR' AS MainDept, 'Hospital' AS DeptName, 0 AS Sales,0 AS Less,0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	sum(Collection)  AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	from SalesLedger a LEFT JOIN BedInformation b
	on a.BedNo=b.BedNo
	where valid <> 0 AND a.Department <> 'Ambulance' and a.PtStatus = 'Indoor' 
	And a.RefDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	and a.PatientId not IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)
	GROUP BY b.SubSubPno
	---------------------------------
	UNION ALL

	select 3 as slno, 'OUTDOOR' AS MainDept, 'Hospital' AS DeptName, SUM(Sales) AS Sales, SUM(Less) AS Less, SUM(ReturnNet) AS RtnAmt,
	SUM(ByCash) AS ByCash, SUM(ByCard) AS ByCard, SUM(ChequeAmount) AS ByCheque, 
	0 AS CashReturn,SUM(CASE WHEN Sales>0 THEN 1 ELSE 0 END) AS TotalPt,sum(case when CRType='Sales' THEN Collection ELSE 0 END) AS TotalColl,
	0 AS DueCollection,0 AS Due, 
	0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	from SalesLedger 
	where valid <> 0 AND Department <> 'Ambulance' and PtStatus <> 'Indoor' 
	and RefDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId
	GROUP BY Department	

	UNION ALL

	select 3 as slno, 'OUTDOOR' AS MainDept, 'Hospital' AS DeptName, SUM(Sales) AS Sales, SUM(Less) AS Less, SUM(ReturnNet) AS RtnAmt,
	SUM(ByCash) AS ByCash, SUM(ByCard) AS ByCard, SUM(ChequeAmount) AS ByCheque, 
	0 AS CashReturn,SUM(CASE WHEN Sales>0 THEN 1 ELSE 0 END) AS TotalPt,sum(case when CRType='Collection' THEN Collection ELSE 0 END) AS TotalColl,
	0 AS DueCollection,0 AS Due, 
	sum(case when CRType='Collection' THEN Less  ELSE 0 END) As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	from SalesLedger 
	where valid <> 0 AND Department <> 'Ambulance' and PtStatus <> 'Indoor' 
	and RefDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId
	and PrevInvNo IN(select InvNo from InvMaster WHERE Valid=1 AND InvDate BETWEEN @DateFrom AND @DateTo)
	GROUP BY Department	

	UNION ALL

	select 3 as slno, 'OUTDOOR' AS MainDept, 'Hospital' AS DeptName, SUM(Sales) AS Sales, SUM(Less) AS Less, SUM(ReturnNet) AS RtnAmt,
	SUM(ByCash) AS ByCash, SUM(ByCard) AS ByCard, SUM(ChequeAmount) AS ByCheque, 
	0 AS CashReturn,SUM(CASE WHEN Sales>0 THEN 1 ELSE 0 END) AS TotalPt,0,
	sum(case when CRType='Collection' THEN Collection ELSE 0 END) AS DueCollection,0 AS Due, 
	sum(case when CRType='Collection' THEN Less  ELSE 0 END) As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	from SalesLedger 
	where valid <> 0 AND Department <> 'Ambulance' and PtStatus <> 'Indoor' 
	and RefDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId
	and PrevInvNo NOT IN(select InvNo from InvMaster WHERE Valid=1 AND InvDate BETWEEN @DateFrom AND @DateTo)
	GROUP BY Department	

	UNION ALL
	
	SELECT 3 AS SlNo, 'OUTDOOR' AS MainDept, 'Hospital' AS DeptName, 
	0 AS Sales,0 AS Less, 0 as RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,COUNT(a.PatientID) AS TotalPt,
	0 AS TotalColl,0 AS DueCollection,
	SUM(Sales-a.Less-a.Collection-(a.ReturnAmount-a.ReturnCash-a.ReturnLess)) AS Due, 
	0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM SalesLedger a
	WHERE a.Valid = 1 AND CONVERT(DATE,a.PreInvDate) BETWEEN @dateFrom AND @dateTo 
	AND a.PtStatus != 'Indoor' AND a.BranchId=@branchId
	GROUP BY PrevInvNo, PreInvDate, a.Department, a.Particulars, a.PPhone, a.BranchId,a.PatientId
	HAVING SUM(Sales-a.Less-a.Collection-(a.ReturnAmount-a.ReturnCash-a.ReturnLess)) > 0

	UNION ALL

	SELECT 3 AS SlNo, 'OUTDOOR' AS MainDept, 'Hospital' AS Department, 0 AS Sales, 0 AS Less, 0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, MAX(a.ReturnCash) AS CashReturn,0 AS TotalPt,
	0 AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM InvReturn a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
	WHERE a.BranchId =@branchId AND a.RtnInvDate BETWEEN @DateFrom AND @DateTo 
	GROUP BY b.DeptName, b.InvNo, a.RtnInvNo

	UNION ALL

	SELECT 5 as slno,'OUTDOOR' AS MainDept, 'MEDICINE' AS DeptName, SUM(SALES) AS Sales, SUM(LessAmt) AS Less, 
	SUM(ReturnAmt) AS RtnAmt,
	SUM(CashAmt) AS ByCash, SUM(CardAmt) AS ByCard, SUM(ChequeAmt) AS ByCheque, 
	SUM(CashReturn) AS CashReturn,SUM(CASE WHEN SALES>0 THEN 1 ELSE 0 END) AS TotalPt,sum(Collection) AS TotalColl,
	SUM(DueColl) AS DueCollection,0 AS Due, SUM(DueLess) As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PharSalesLedger 
	where valid = 1 and PtStatus <> 'Indoor'
	and TrDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId

	

	UNION ALL 

	SELECT 2 as slno, 'OUTDOOR' AS MainDept, 'Hospital' AS DeptName, SUM(Amount) AS Sales, 0 as Less, 0 AS RtnAmt,
	SUM(Amount) as CashAmt, 0 as CardAmt, 0 as ChequeAmt, 
	SUM(a.RtnAmount) as CashReturn,COUNT(TrNo) AS TotalPt,sum(a.Received) AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM OPDTicketMaster a
	where a.valid = 1 and a.TrDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId

	UNION ALL

	SELECT 6 as slno, PtStatus As MainDept, 'Hospital' AS DeptName, SUM(TotalCharge) AS Sales, SUM(Less), 0 AS RtnAmt,
	SUM(CashAmt) as ByCash, SUM(CardAmt) as ByCard, SUM(ChequeAmt) as ByCheque, 0 AS CashReturn,
	SUM(CASE WHEN TotalCharge>0 THEN 1 ELSE 0 END) AS TotalPt,sum(ReceiveAmt) AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM AmbulanceLedger
	where valid = 1 AND PtStatus='OUTDOOR'
	and RefDate BETWEEN @DateFrom and @DateTo
	GROUP BY PtStatus

	UNION ALL
	SELECT 6 as slno, a.PtStatus As MainDept, 'Hospital' AS DeptName, 0 AS Sales, 0, 0 AS RtnAmt,
	0 as ByCash, 0 as ByCard, 0 as ByCheque, 0 AS CashReturn,
	0 AS TotalPt,0 AS TotalColl,0 AS DueCollection,SUM(a.TotalCharge - a.Less - a.ReceiveAmt) AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM AmbulanceLedger a,AmbulanceMaster b
	where a.Valid = 1 AND a.PtStatus='OUTDOOR'
	AND a.PrevReceiptNo=b.ReceiptNo  AND a.RegNo = b.RegNo AND a.Valid = b.Valid AND a.BranchId = b.BranchId
	and b.ReceiptDate BETWEEN @DateFrom and @DateTo
	GROUP BY a.PtStatus

	) aa
	GROUP BY aa.DeptName
	
END
GO
/****** Object:  StoredProcedure [dbo].[SP_HospitalSalesCollMonthWise]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE Proc [dbo].[SP_HospitalSalesCollMonthWise] @BranchId Int, @DateFrom Date, @DateTo Date, @Type Varchar(50), @Department Varchar(50)
AS
Begin --    SP_HospitalSalesCollMonthWise 1, '2025-11-01', '2025-11-20', 'Summary',''
	DECLARE @IncludePharmacy INT, @IsIncludePharmacy INT;
	SELECT @IsIncludePharmacy = PharmacyInclude FROM tbl_ComInfo
	IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END

	SELECT 'Indoor' As Department, Format(d.ReleaseDate, 'MMM yyyy') As DueMonth, Sum(a.HBill+a.DBill+a.MBill) AS Due
	Into #z
	FROM (
		SELECT a.BranchId, a.PatientId, SUM((a.NoU*a.Charge)+ServiceCharge-a.Collection+a.ReturnAmt-Less) AS HBill, 0 AS DBill, 0 AS MBill
		FROM PatientLedger a
		WHERE BranchId = @BranchId AND Valid = 1
		GROUP BY a.BranchId, a.PatientId
		UNION
		SELECT a.BranchId, a.PatientId, 0 AS HBill, SUM(a.Sales-a.Less-a.Collection-a.ReturnDue) AS DBill, 0 AS MBill
		FROM SalesLedger a
		WHERE BranchId = @BranchId AND a.Valid = 1 AND a.PtStatus='Indoor'
		GROUP BY a.BranchId, a.PatientId
		UNION
		SELECT a.BranchId, a.PatientId, 0 AS HBill, 0 AS DBill, SUM(a.Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt) AS MBill
		FROM PharSalesLedger a
		WHERE BranchId = @BranchId AND a.Valid = @IncludePharmacy AND a.PtStatus='Indoor'
		GROUP BY a.BranchId, a.PatientId
	) a
	LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
	LEFT JOIN PatientReleaseMaster d ON a.BranchId = d.BranchId AND b.PatientId = d.PatientID AND d.Valid = 1
	WHERE b.BranchId = @BranchId AND b.IsRelease = 1 AND d.ReleaseDate < @DateFrom
	GROUP BY Format(d.ReleaseDate, 'MMM yyyy')
	Having Sum(a.HBill+a.DBill+a.MBill) > 1
	Union All
	select a.Department, Format(a.PreInvDate, 'MMM yyyy') As InvMonth, Sum(Sales-Less-Collection-ReturnDue) As Due
	from SalesLedger a
	Where a.Valid=1 And a.BranchId=@BranchId
	And a.RefDate<=@DateFrom
	And a.PtStatus<>'Indoor'
	--And a.PrevInvNo='DIA251002953' 
	Group by a.Department, Format(a.PreInvDate, 'MMM yyyy')
	having Sum(Sales-Less-Collection-ReturnDue)<>0
	Union All
	select 'Pharmacy' As Department, Format(a.InvDate, 'MMMM yyyy') As InvMonth, Sum(Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt) As Due
	from PharSalesLedger a
	Where a.Valid=@IncludePharmacy And a.BranchId=@BranchId
	And a.TrDate<=@DateFrom
	And a.PtStatus<>'Indoor'
	Group by Format(a.InvDate, 'MMMM yyyy')
	having Sum(Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt)<>0


	/* Collection */
	SELECT 'Indoor' As Department, Format(b.RefDate, 'MMM yyyy') As PaidMonth, Sum(Collection) As Collection
	Into #zz
	FROM PatientLedger b
	WHERE b.valid = 1 
	AND b.BranchId = @BranchId
	And b.RefDate Between @DateFrom and @DateTo
	and b.PatientId NOT IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate < @DateTo)
	AND b.Status<>'Advance Collection' and Collection<>0
	GROUP by Format(b.RefDate, 'MMM yyyy')
	Union All
	Select a.Department, Format(a.PreInvDate, 'MMM yyyy') As PaidMonth, SUm(Collection) As Collection--, Sum(Sales-Less-Collection-ReturnDue-AdjustAmt) As Due
	FROM SalesLedger a
	Where a.Valid=1 And a.BranchId=@BranchId
	ANd a.RefDate between @DateFrom and @DateTo
	And a.PtStatus<>'Indoor'
	--and a.PreInvDate <> a.RefDate
	And a.PreInvDate < @DateFrom
	--and  a.PrevInvNo='DIA251002953' 
	And Collection<>0
	Group by a.department, Format(a.PreInvDate, 'MMM yyyy')
	Union All
	Select 'Pharmacy', Format(a.InvDate, 'MMM yyyy') As PaidMonth, SUm(DueColl) As Collection
	FROM PharSalesLedger a
	Where a.Valid=@IncludePharmacy And a.BranchId=@BranchId
	ANd a.TrDate between @DateFrom and @DateTo
	And a.PtStatus<>'Indoor'
	--and a.TrDate <> a.InvDate
	And a.InvDate < @DateFrom
	--and  a.PrevInvNo='DIA251002953' 
	And DueColl<>0
	Group by Format(a.InvDate, 'MMM yyyy')

	If @Type = 'Summary'
	Begin
		select a.Department, '2025-01-01' As DueMonth, Sum(Due) As Due, Sum(IsnuLL(Collection, 0)) As Collection, Sum(Due-Isnull(Collection, 0)) As Net
		from #z a
		Left Join #zz b On a.Department=b.Department And a.DueMonth=b.PaidMonth
		Where (@Department = '' OR a.Department = @Department)

		Group By a.Department
		Order By a.Department
	End
	Else
	Begin
		select a.Department, DueMonth, Due, IsnuLL(Collection, 0) As Collection, Due-Isnull(Collection, 0) As Net
		from #z a
		Left Join #zz b On a.Department=b.Department And a.DueMonth=b.PaidMonth
		Where Case When @Department = '' Then '' Else a.Department End = @Department
		Order By a.DueMonth, a.Department
	End
End
GO
/****** Object:  StoredProcedure [dbo].[SP_HosptalSalesCollDepartmentWise]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
