CREATE Procedure [dbo].[SP_HP_SalesCollSummarized](@dateFrom date,@dateTo date,@BranchId int)
AS 
drop table tmp 
drop table tmp_TransToTransact

BEGIN -- EXEC SP_HP_SalesCollSummarized '2022-12-13','2022-12-13',1
	select  RefDate,'3101010035' AS AcCode, 'Dental' as Department ,'Indoor' AS PTStatus , sum(Sales) as Sales ,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt , 
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	INTO tmp
	from SalesLedger
	where valid = 1
	and Department = 'Dental' and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101040001' AS AcCode, 'Dental','Outdoor' as ptstatus , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Dental' and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101010030' AS AcCode, 'DIAGNOSTIC' as Department,'Indoor' , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt ,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'DIAGNOSTIC' and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101020001' AS AcCode, 'DIAGNOSTIC' as Department,'Outdoor' as ptstatus , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'DIAGNOSTIC' and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101010031' AS AcCode, 'Dialysis' as Department,'Indoor' AS PTStatus, sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Dialysis' and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101050001' AS AcCode, 'Dialysis' as Department,'Outdoor' as ptstatus , sum(Sales) as Sales ,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque  , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Dialysis' and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101010032' AS AcCode, 'Emergency' as Department,'Indoor' AS PTStatus , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt ,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Emergency' and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101030001' AS AcCode, 'Emergency' as Department,'Outdoor' AS PTStatus, sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt ,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Emergency' and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101010033' AS AcCode, 'Eye' AS Department,'Indoor' AS PTStatus, sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt ,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Eye' and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101080001' AS AcCode, 'Eye' as Department,'Outdoor' AS PTStatus, sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt ,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Eye' and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101010037' AS AcCode, 'OPD' AS Department,'Indoor' AS PTStatus , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt ,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department IN ('OPD','OPD Ticket') and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101070001' AS AcCode, 'OPD' as Department,'Outdoor' AS PTStatus, sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department IN ('OPD','OPD Ticket') and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101010034' AS AcCode, 'Physiotherapy' as Department,'Indoor' AS PTStatus , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department IN ('Physiotherapy') and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101060001' AS AcCode, 'Physiotherapy' as Department,'Outdoor' , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department IN ('Physiotherapy') and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select trdate,'3101010038'  AS AcCode,'Medicine' as Department,'Indoor' AS PTStatus,sum(sales) as sales,
	sum(collection) as coll,SUM(lessAmt) AS Less,SUM(returnAmt) as RtnAmt,
	SUM(CashAmt) as Cash, SUM(CardAmt) as Card, SUM(ChequeAmt) as Cheque,SUM(CashReturn) as CashRtn 
	from PharSalesledger
	where trdate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	and valid = 1 and PtStatus = 'Indoor'
	Group BY trdate
	UNION ALL
	select trdate,'3101100001'  AS AcCode,'Medicine' as Department,'Outdoor' AS PTStatus,sum(sales) as sales,
	sum(collection) as coll,SUM(lessAmt) AS Less,SUM(returnAmt) as RtnAmt,
	SUM(CashAmt) as Cash, SUM(CardAmt) as Card, SUM(ChequeAmt) as Cheque,SUM(CashReturn) as CashRtn 
	from PharSalesledger
	where trdate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	and valid = 1 and PtStatus NOT IN ('Indoor')
	Group BY trdate
	UNION ALL
	select RefDate,'3101090001','Ambulance','OutDoor',SUM(TotalCharge) as Sales,
	SUM(ReceiveAmt) as Coll , SUM(Less) as Less , 0 ,
	SUM(ReceiveAmt) As Cash , 0 as Card , 0 AS Cheque , 0 AS CashReturn
	from AmbulanceLedger  
	where valid  = 1 and PtStatus = 'OutDoor'
	and RefDate  BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select RefDate,'3101010036','Ambulance','Indoor',SUM(TotalCharge) as Sales ,
	SUM(ReceiveAmt) as Coll , SUM(Less) as Less , 0 ,
	SUM(ReceiveAmt) As Cash , 0 as Card , 0 AS Cheque , 0 AS CashReturn
	from AmbulanceLedger  
	where valid  = 1 and PtStatus = 'Indoor'
	and RefDate  BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select a.RefDate,b.AcCode,c.Description AS ACName,'Indoor',SUM(a.totalAmount) AS Sales,
	SUM(a.Collection) as Coll, 
	SUM(a.Less) As Less, 0  as RtnAmt ,
	SUM(a.CashAmt) As Cash , SUM(a.CardAmt) as Card , SUM(a.ChequeAmt) AS Cheque , sum(ReturnAmt) AS CashReturn
	from PatientLedger a , clinicalChart b , tbl_CHART_OF_ACCOUNTS c
	where a.Code=b.PCode and a.BranchId = b.BranchId and b.ACCode = c.code  
	and a.valid = 1
	and a.RefDate BETWEEN @dateFrom AND @dateTo and a.BranchId = @BranchId 
	GROUP BY b.AcCode , c.Description ,a.RefDate
	;

	select 1 as SlNo,a.ACCode,1 as AcType , a.Department as MainDept , b.Description , a.Sales , a.Less , a.RtnAmt as ReturnAmt , 
	a.cash as CashAmt ,a.Card as CardAmt , a.Cheque as ChequeAmt , CashReturn
	INTO tmp_TransToTransact
	from tmp a , tbl_CHART_OF_ACCOUNTS b
	where a.AcCode = b.Code 

	select * from tmp_TransToTransact

	END
GO
/****** Object:  StoredProcedure [dbo].[SP_HP_SalesCollSummarized_Main]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[SP_HP_SalesCollSummarized_Main](@DateFrom date, @DateTo date, @BranchId int)
AS BEGIN
drop table tmp_TransToTransact -- exec SP_HP_SalesCollSummarized '2022-08-31', '2022-08-31', 1
SELECT m.SlNo, m.AcCode, m.AcType, m.MainDept, n.Description, SUM(m.Sales) AS Sales, 0 AS Less, 0 AS ReturnAmt, --SUM(m.Sales) AS Sales,
SUM(m.CashAmt) AS CashAmt, SUM(m.CardAmt) AS CardAmt, SUM(m.ChequeAmt) AS ChequeAmt, SUM(m.CashReturn) AS CashReturn

INTO tmp_TransToTransact /*select * from tmp_TransToTransact order by accode*/
FROM (

/*Sales*/
select 1 AS SlNo, 1 AS AcType, b.AcCode, 'Indoor' AS MainDept,'Indoor Sales' AS Department, SUM(a.CashAmt+a.CardAmt+a.ChequeAmt) AS Sales, 
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
from PatientLedger a
LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.Code = b.PCode
LEFT JOIN PatientAdmission c ON a.BranchId = c.BranchId AND a.PatientId = c.PatientId
WHERE a.Valid = 1 AND a.RefDate BETWEEN @DateFrom AND @DateTo
group by b.AcCode
HAVING SUM(a.CashAmt+a.CardAmt+a.ChequeAmt) != 0

UNION ALL
select 2 AS SlNo, 1 AS AcType, (SELECT DISTINCT AcCode FROM ClinicalChart WHERE DeptName = a.Department and BranchId = a.BranchId) As AcCode, a.Department AS MainDept, a.Department AS Department, sum(a.ByCash+a.ByCard+a.ChequeAmount) AS Sales, 
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
from SalesLedger a
WHERE a.Valid <> 0 AND a.Department <> 'Ambulance' AND a.RefDate BETWEEN @DateFrom AND @DateTo
GROUP BY a.Department, a.BranchId

/*Pharmacy*/
--UNION ALL
--select 3 AS SlNo, 1 AS AcType, '3101010010' As AcCode, 'Medicine' AS MainDept, 'Medicine' AS Department, ISNULL(sum(a.Sales),0) AS Sales, 
--0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
--from PharSalesLedger a
--WHERE a.PtStatus <> 'Indoor' AND a.Valid <> 0 AND a.InvDate BETWEEN @DateFrom AND @DateTo

UNION ALL
SELECT 4 AS SlNo, 1 AS AcType, '3101010004' AS AcCode, 'Ambulance' AS MainDept, 'Ambulance' AS Department, ISNULL(SUM(a.CashAmt+a.CardAmt+a.ChequeAmt),0) AS Sales, 
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
FROM AmbulanceLedger a
WHERE a.Valid = 1 ANd a.RefDate BETWEEN @DateFrom AND @DateTo

UNION ALL
SELECT 5 AS SlNo, 1 AS AcType, '3101010002' AS AcCode, 'OPD' AS MainDept, 'OPD Ticket' AS Department, ISNULL(SUM(a.Amount),0) AS Sales, 
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
FROM OPDTicketMaster a
WHERE a.Valid = 1 ANd a.TrDate BETWEEN @DateFrom AND @DateTo

UNION ALL
SELECT 6 AS SlNo, 1 AS AcType, '3101010002' AS AcCode, 'OPD' AS MainDept, 'Registration' AS Department, ISNULL(SUM(a.Amount),0) AS Sales, 
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
FROM RegistrationFees a
WHERE a.Valid = 1 ANd a.TrDate BETWEEN @DateFrom AND @DateTo

/* Start Account Fees Collection (Sales) */
UNION ALL
SELECT a.SlNo, 1 AS AcType, a.AcCode, a.MainDept, a.Department, SUM(a.Sales) AS Sales,
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
FROM (
SELECT 2 AS SlNo, c.AcCode, a.CollType AS MainDept, a.CollType AS Department, a.ReceiveAmt AS Sales,
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
FROM tbl_AccountsFeesCollection_Master a
LEFT JOIN tbl_AccountsFeesCollection_Dtls b ON a.BranchId = b.BranchId aND a.RefDate = b.RefDate AND a.RefNo = b.RefNo ANd a.Valid = 1
LEFT JOIN StAccFeesCollType c ON a.CollType = c.Name
WHERE a.BranchId = 6 AND a.Valid = 1 AND b.PaidDate BETWEEN @DateFrom AND @DateTo
GROUP BY c.AcCode, a.CollType, a.CollType, a.ReceiveAmt, a.RefNo
) a
GROUP BY a.SlNo, a.AcCode, a.MainDept, a.Department
/* End Account Fees Collection (Sales) */

UNION ALL
/*Start College & Nursing*/
SELECT DISTINCT 6 AS AlNo, 1 AS AcType, b.AcCode, 'College' AS MainDept, 'College Sales' AS Department, SUM(a.ReceiveAmt) AS Sales, 
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
FROM tbl_StudentFeesCollectionDtls a
LEFT JOIN tbl_CodeForTutionFees b ON a.BranchId = b.BranchId AND a.ItemId = b.SlNo
LEFT JOIN tbl_BranchInfo c ON a.BranchId = c.Id
WHERE a.BranchId = 6 AND a.Valid = 1 AND a.PaidDate BETWEEN @DateFrom AND @DateTo 
GROUP BY b.AcCode
UNION ALL
SELECT DISTINCT 6 AS AlNo, 1 AS AcType, b.AcCode, 'Nursing Institue' AS MainDept, 'Nursing Institue Sales' AS Department, SUM(a.ReceiveAmt) AS Sales, 
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
FROM tbl_StudentFeesCollectionDtls a
LEFT JOIN tbl_CodeForTutionFees b ON a.BranchId = b.BranchId AND a.ItemId = b.SlNo
LEFT JOIN tbl_BranchInfo c ON a.BranchId = c.Id
WHERE a.BranchId = 7 AND a.Valid = 1 AND a.PaidDate BETWEEN @DateFrom AND @DateTo 
GROUP BY b.AcCode
/*End College & Nursing*/

--/*Less*/
UNION ALL
select 7 AS SlNo, 1 AS AcType, '4102060001' AS AcCode, 'Indoor' AS MainDept, 'Indoor Less' AS Department, 0 AS Sales, 
ISNULL(SUM(a.Less),0) AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
from PatientLedger a
LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
WHERE a.Valid = 1 AND b.IsRelease = 1 AND b.ReleaseDate BETWEEN @DateFrom AND @DateTo

UNION ALL
select 7 AS SlNo, 1 AS AcType, '4102060002' AS AcCode, a.Department AS MainDept, 'Outdoor Less' AS Department, 0 AS Sales,
SUM(a.Less) AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
from SalesLedger a
WHERE a.Valid <> 0 AND a.PtStatus <> 'Indoor' AND a.Department <> 'Ambulance' AND a.RefDate BETWEEN @DateFrom AND @DateTo
GROUP by a.Department

/*Pharmacy*/
--UNION ALL
--select 7 AS SlNo, '4102060004' AS AcCode, 'Medicine' AS MainDept, 'Medicine Less' AS Department, 0 AS Sales, 
--ISNULL(SUM(a.LessAmt+a.DueLess),0) AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
--from PharSalesLedger a
--WHERE a.Valid = 1 AND a.PtStatus <> 'Indoor' AND a.InvDate BETWEEN @DateFrom AND @DateTo

UNION ALL
select 7 AS SlNo, 1 AS AcType, '4102060002' AS AcCode, 'Ambulance' AS MainDept, 'Ambulance Less' AS Department, 0 AS Sales, 
ISNULL(SUM(a.Less),0) AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn 
from AmbulanceLedger a
WHERE a.Valid = 1 AND a.PtStatus <> 'Indoor' AND a.RefDate BETWEEN @DateFrom AND @DateTo


/*Return*/

--UNION ALL
--SELECT 8 AS SlNo, 1 AS AcType, '3102010001' AS AcCode,'Indoor' AS MainDept, 'Indoor Return' AS Department, 0 AS Sales,
--0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
--FROM PatientLedger a
--LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
--WHERE a.Valid = 1 AND b.IsRelease = 1 AND b.ReleaseDate BETWEEN @DateFrom AND @DateTo

UNION ALL
select 8 AS SlNo, 1 AS AcType, '3102010001' As AcCode, a.Department AS MainDept,  a.Department+' Return' AS Department, 0 AS Sales, 
0 AS Less, ISNULL(SUM(a.ReturnNet),0) as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
from SalesLedger a
WHERE a.PtStatus <> 'Indoor' AND a.Valid <> 0 AND a.Department <> 'Ambulance' ANd a.ReturnAmount != 0 AND a.RefDate BETWEEN @DateFrom AND @DateTo
GROUP BY a.Department, a.BranchId

/*Pharmacy*/
--UNION ALL
--select 8 AS SlNo, '3102010001' As AcCode, 'Medicine' AS MainDept, 'Medicine Return' AS Department, 0 AS Sales, 
--0 AS Less, ISNULL(SUM(a.ReturnAmt),0) as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
--from PharSalesLedger a
--WHERE a.Valid = 1 AND a.Particulars= 'Sales' AND a.InvDate BETWEEN @DateFrom AND @DateTo  --a.PtStatus <> 'Indoor' ANd 

UNION ALL
SELECT 8 AS SlNo, 1 AS AcType, '3102010001' AS AcCode, 'OPD' AS MainDept, 'OPD Ticket Return' AS Department, 0 AS Sales, 
0 AS Less, ISNULL(SUM(a.RtnAmount),0) as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
FROM OPDTicketMaster a
WHERE a.Valid = 1 ANd a.RtnDate BETWEEN @DateFrom AND @DateTo 

UNION ALL
select 8 AS SlNo, 1 AS AcType, '3102010001' AS AcCode, 'OPD' AS MainDept, 'OPD Return' AS Department, 0 AS Sales, 
0 AS Less, ISNULL(SUM(a.Amount),0) as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
from InvRefund a WHERE a.TrDate BETWEEN @DateFrom AND @DateTo AND a.Amount > 0 AND a.Valid=1

/*Collection*/
UNION ALL
SELECT 9 AS SlNo, 1 AS AcType, '2101020001' AS AcCode, 'Indoor' AS MainDept, 'Indoor Advance' AS Department, 0 AS Sales,
0 AS Less, 0 as ReturnAmt, ISNULL(SUM(a.CashAmt),0) AS CashAmt, ISNULL(SUM(a.CardAmt),0) AS CardAmt, ISNULL(SUM(a.ChequeAmt),0) AS ChequeAmt, 0 AS CashReturn
FROM PatientLedger a
WHERE a.Valid = 1 AND a.Status = 'Advance Collection' AND a.RefDate BETWEEN @DateFrom AND @DateTo 

UNION ALL
select 9 AS SlNo, 1 AS AcType, '2101020001' As AcCode, a.Department AS MainDept, a.Department+' Collection' AS Department, 0 AS Sales, 
0 AS Less, 0 as ReturnAmt, ISNULL(SUM(a.ByCash),0) AS CashAmt, ISNULL(SUM(a.ByCard),0) AS CardAmt, ISNULL(SUM(a.ChequeAmount),0) AS ChequeAmt, 0 AS CashReturn
from SalesLedger a
WHERE Valid <> 0 ANd a.CRType = 'Sales' AND a.Department <> 'Ambulance' ANd a.RefDate BETWEEN @DateFrom AND @DateTo 
GROUP BY a.Department, a.BranchId

/*Pharmacy*/
--UNION ALL
--select 9 AS SlNo, 1 AS AcType, '2101020001' As AcCode, 'Medicine' AS MainDept, 'Medicine Collection' AS Department, 0 AS Sales, 
--0 AS Less, 0 as ReturnAmt, ISNULL(SUM(a.CashAmt),0) AS CashAmt, ISNULL(SUM(a.CardAmt),0) AS CardAmt, ISNULL(SUM(a.ChequeAmt),0) AS ChequeAmt, 0 AS CashReturn
--from PharSalesLedger a
--WHERE a.PtStatus <> 'Indoor' ANd a.Valid <> 0 AND a.InvDate BETWEEN @DateFrom AND @DateTo  AND a.Particulars= 'Sales'

UNION ALL
SELECT 9 AS SlNo, 1 AS AcType, '2101020001' AS AcCode, 'Ambulance' AS MainDept, 'Ambulance Collection' AS Department, 0 AS Sales, 
0 AS Less, 0 as ReturnAmt, ISNULL(SUM(a.CashAmt),0) AS CashAmt, ISNULL(SUM(a.CardAmt),0) AS CardAmt, ISNULL(SUM(a.ChequeAmt),0) AS ChequeAmt, 0 AS CashReturn
FROM AmbulanceLedger a
WHERE a.Valid = 1 AND a.RefDate BETWEEN @DateFrom AND @DateTo  AND a.InputFrom= 'Sales'

UNION ALL
SELECT 9 AS SlNo, 1 AS AcType, '2101020001' AS AcCode, 'OPD' AS MainDept, 'OPD Ticket Collection' AS Department, 0 AS Sales, 
0 AS Less, 0 as ReturnAmt, ISNULL(SUM(a.Amount),0) AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
FROM OPDTicketMaster a
WHERE a.Valid = 1 ANd a.TrDate BETWEEN @DateFrom AND @DateTo 

UNION ALL
SELECT 9 AS SlNo, 1 AS AcType, '2101020001' AS AcCode, 'OPD' AS MainDept, 'Registration Collection' AS Department, 0 AS Sales, 
0 AS Less, 0 as ReturnAmt, ISNULL(SUM(a.Amount),0) AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
FROM RegistrationFees a
WHERE a.Valid = 1 and a.TrDate BETWEEN @DateFrom AND @DateTo 

/* Start Account Fess collection */
UNION ALL
SELECT a.SlNo, 5 AS AcType, a.AcCode, a.MainDept, a.Department, 0 AS Sales,
0 AS Less, 0 as ReturnAmt, SUM(CashAmt) AS CashAmt, SUM(CardAmt) AS CardAmt, SUM(ChequeAmt) AS ChequeAmt, 0 AS CashReturn
FROM (
SELECT 9 AS SlNo, c.AcCode, a.CollType AS MainDept, a.CollType AS Department, a.ReceiveAmt AS Sales,
0 AS Less, 0 as ReturnAmt, CashAmt, CardAmt, ChequeAmt, 0 AS CashReturn
FROM tbl_AccountsFeesCollection_Master a
LEFT JOIN tbl_AccountsFeesCollection_Dtls b ON a.BranchId = b.BranchId aND a.RefDate = b.RefDate AND a.RefNo = b.RefNo ANd a.Valid = 1
LEFT JOIN StAccFeesCollType c ON a.CollType = c.Name
WHERE a.BranchId = 6 AND a.Valid = 1 AND b.PaidDate BETWEEN @DateFrom AND @DateTo
GROUP BY c.AcCode, a.CollType, a.CollType, a.ReceiveAmt, a.CashAmt, a.CardAmt, a.ChequeAmt, a.RefNo
) a
GROUP BY a.SlNo, a.AcCode, a.MainDept, a.Department

/* End Account Fess collection */

UNION ALL
/*Start College & Nursing*/
SELECT DISTINCT 13 AS AlNo, (CASE WHEN SUM(FCPaidAmt) != 0 THEN 7 ELSE 5 END) AS AcType, b.AcCode, c.Name AS MainDept, a.Particulars + ' Collection' AS Department, 0 AS Sales, 
SUM(a.LessAmt) AS Less, 0 as ReturnAmt, SUM(a.CashAmt) AS CashAmt, SUM(a.CardAmt) AS CardAmt, SUM(a.ChqAmt) AS ChequeAmt, 0 AS CashReturn
FROM tbl_StudentFeesCollectionDtls a
LEFT JOIN tbl_CodeForTutionFees b ON a.BranchId = b.BranchId AND a.ItemId = b.SlNo
LEFT JOIN tbl_BranchInfo c ON a.BranchId = c.Id
WHERE a.Valid = 1 AND a.PaidDate BETWEEN @DateFrom AND @DateTo 
GROUP BY b.AcCode, c.Name, a.Particulars
/*End College & Nursing*/

/*Due Collection*/
UNION ALL
SELECT 10 AS SlNo, 1 AS AcType, '2101020001' AS AcCode, 'Indoor' AS MainDept,  'Indoor Due Collection' AS Department, 0 AS Sales,
0 AS Less, 0 as ReturnAmt, ISNULL(SUM(a.CashAmt),0) AS CashAmt, ISNULL(SUM(a.CardAmt),0) AS CardAmt, ISNULL(SUM(a.ChequeAmt),0) AS ChequeAmt, 0 AS CashReturn
FROM PatientLedger a
WHERE a.Valid = 1 AND a.Status <> 'Advance Collection' AND a.RefDate BETWEEN @DateFrom AND @DateTo 

UNION ALL
select 10 AS SlNo, 1 AS AcType, '2101020001' As AcCode, a.Department AS MainDept, a.Department+' Due Collection' AS Department, 0 AS Sales, 
0 AS Less, 0 as ReturnAmt, ISNULL(SUM(a.ByCash),0) AS CashAmt, ISNULL(SUM(a.ByCard),0) AS CardAmt, ISNULL(SUM(a.ChequeAmount),0) AS ChequeAmt, 0 AS CashReturn
from SalesLedger a
WHERE a.CRType = 'Collection' ANd a.Valid <> 0 AND a.Department <> 'Ambulance' and RefDate BETWEEN @DateFrom AND @DateTo 
GROUP BY a.Department, a.BranchId

/*Pharmacy*/
--UNION ALL
--select 10 AS SlNo, '2101020001' As AcCode, 'Medicine' AS MainDept, 'Medicine Due Collection' AS Department, 0 AS Sales, 
--0 AS Less, 0 as ReturnAmt, ISNULL(SUM(a.CashAmt),0) AS CashAmt, ISNULL(SUM(a.CardAmt),0) AS CardAmt, ISNULL(SUM(a.ChequeAmt),0) AS ChequeAmt, 0 AS CashReturn
--from PharSalesLedger a
--WHERE a.PtStatus <> 'Indoor' AND a.Valid = 1 AND a.InvDate BETWEEN @DateFrom AND @DateTo  AND a.Particulars = 'Collection'

UNION ALL
SELECT 10 AS SlNo, 1 AS AcType, '2101020001' AS AcCode, 'Ambulance' AS MainDept, 'Ambulance Due Collection' AS Department, 0 AS Sales, 
0 AS Less, 0 as ReturnAmt, ISNULL(SUM(a.CashAmt),0) AS CashAmt, ISNULL(SUM(a.CardAmt),0) AS CardAmt, ISNULL(SUM(a.ChequeAmt),0) AS ChequeAmt, 0 AS CashReturn
FROM AmbulanceLedger a
WHERE a.Valid = 1 AND a.RefDate BETWEEN @DateFrom AND @DateTo  AND a.InputFrom= 'Collection'

/*Cash Return*/
UNION ALL
SELECT 8 AS SlNo, 1 AS AcType, '3102010001' AS AcCode,'Indoor' AS MainDept, 'Indoor Return' AS Department, 0 AS Sales,
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, ISNULL(SUM(a.ReturnAmt),0) AS CashReturn
FROM PatientLedger a
LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
WHERE a.Valid = 1 AND b.IsRelease = 1 AND b.ReleaseDate BETWEEN @DateFrom AND @DateTo

UNION ALL
select 8 AS SlNo, 1 AS AcType, '3102010001' As AcCode, b.Department AS MainDept,  b.Department+' Return' AS Department, 0 AS Sales, 
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, a.ReturnCash AS CashReturn
from InvReturn a
LEFT JOIN SalesLedger b oN a.BranchId = b.BranchId AND a.InvNo = b.PrevInvNo AND a.InvDate = b.PreInvDate
WHERE a.Valid = 1 AND a.Valid <> 0 ANd b.Department <> 'Ambulance' AND a.RtnInvDate BETWEEN @DateFrom AND @DateTo --a.PtStatus <> 'Indoor' AND 
GROUP BY b.Department, b.BranchId, a.ReturnCash

/*Pharmacy*/
--UNION ALL
--select 8 AS SlNo, 1 AS AcType, '3102010001' As AcCode, 'Medicine' AS MainDept, 'Medicine Return' AS Department, 0 AS Sales, 
--0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, ISNULL(SUM(a.CashReturn),0) AS CashReturn
--from PharSalesLedger a
--WHERE a.PtStatus <> 'Indoor' ANd a.Valid = 1 AND a.Particulars= 'Sales' AND a.InvDate BETWEEN @DateFrom AND @DateTo 

UNION ALL
SELECT 8 AS SlNo, 1 AS AcType, '3102010001' AS AcCode, 'OPD' AS MainDept, 'OPD Ticket Return' AS Department, 0 AS Sales, 
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, ISNULL(SUM(a.RtnAmount),0) AS CashReturn
FROM OPDTicketMaster a
WHERE a.Valid = 1 ANd a.RtnDate BETWEEN @DateFrom AND @DateTo 

UNION ALL
select 8 AS SlNo, 1 AS AcType, '3102010001' AS AcCode, 'OPD' AS MainDept, 'OPD Return' AS Department, 0 AS Sales, 
0 AS Less, 0 as ReturnAmt, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, ISNULL(SUM(a.Amount),0) AS CashReturn
from InvRefund a WHERE a.TrDate BETWEEN @DateFrom AND @DateTo AND a.Amount > 0 AND a.Valid=1

UNION ALL
SELECT 8 AS SlNo, 1 AS AcType, '3102010001' AS AcCode, 'Indoor', 'Indoor Refund' AS Department, 0 AS Sales,
0 AS Less, 0 AS ReturnAmt, 0 AS CaahAmt, 0 AS CardAmt, 0 AS ChequeAmt, Amount AS CashReturn
FROM CashReturn WHERE TrDate BETWEEN @DateFrom  AND @DateTo AND Amount>0 AND Valid=1

) m
LEFT JOIN tbl_CHART_OF_ACCOUNTS n ON m.AcCode = n.Code
GROUP BY m.SlNo, m.AcType, m.AcCode, n.Description, m.MainDept
order by m.MainDept
select * from tmp_TransToTransact where Sales+Less+ReturnAmt+CashAmt+CardAmt+ChequeAmt+CashReturn != 0

END

GO
/****** Object:  StoredProcedure [dbo].[SP_HP_SalesCollSummarized_MHL]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE Procedure [dbo].[SP_HP_SalesCollSummarized_MHL](@dateFrom date,@dateTo date,@BranchId int)
AS 
drop table tmp 
drop table tmp_TransToTransact

BEGIN -- EXEC SP_HP_SalesCollSummarized '2023-08-01','2023-08-01',1
	select  RefDate,'3101010035' AS AcCode, 'Dental' as Department ,'Indoor' AS PTStatus , sum(Sales) as Sales ,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt , 
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	INTO tmp
	from SalesLedger
	where valid = 1
	and Department = 'Dental' and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101040001' AS AcCode, 'Dental','Outdoor' as ptstatus , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Dental' and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101010030' AS AcCode, 'DIAGNOSTIC' as Department,'Indoor' , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt ,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'DIAGNOSTIC' and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101020001' AS AcCode, 'DIAGNOSTIC' as Department,'Outdoor' as ptstatus , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'DIAGNOSTIC' and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101010031' AS AcCode, 'Dialysis' as Department,'Indoor' AS PTStatus, sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Dialysis' and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101050001' AS AcCode, 'Dialysis' as Department,'Outdoor' as ptstatus , sum(Sales) as Sales ,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque  , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Dialysis' and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101010032' AS AcCode, 'Emergency' as Department,'Indoor' AS PTStatus , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt ,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Emergency' and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101030001' AS AcCode, 'Emergency' as Department,'Outdoor' AS PTStatus, sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt ,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Emergency' and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101010033' AS AcCode, 'Eye' AS Department,'Indoor' AS PTStatus, sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt ,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Eye' and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101080001' AS AcCode, 'Eye' as Department,'Outdoor' AS PTStatus, sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt ,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department = 'Eye' and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101010037' AS AcCode, 'OPD' AS Department,'Indoor' AS PTStatus , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt ,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department IN ('OPD','OPD Ticket') and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101070001' AS AcCode, 'OPD' as Department,'Outdoor' AS PTStatus, sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department IN ('OPD','OPD Ticket') and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101010034' AS AcCode, 'Physiotherapy' as Department,'Indoor' AS PTStatus , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department IN ('Physiotherapy') and PtStatus = 'Indoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select  RefDate,'3101060001' AS AcCode, 'Physiotherapy' as Department,'Outdoor' , sum(Sales) as Sales,
	SUM(Collection) As Coll , SUM(Less) As Less , SUM(returnAmount) as RtnAmt,
	SUM(ByCash) As Cash , SUM(ByCard) as Card , SUM(ChequeAmount) AS Cheque , sum(returnCash) AS CashReturn
	from SalesLedger
	where valid = 1
	and Department IN ('Physiotherapy') and PtStatus = 'Outdoor'
	and RefDate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by RefDate
	UNION ALL
	select trdate,'3101010038'  AS AcCode,'Medicine' as Department,'Indoor' AS PTStatus,sum(sales) as sales,
	sum(collection) as coll,SUM(lessAmt) AS Less,SUM(returnAmt) as RtnAmt,
	SUM(CashAmt) as Cash, SUM(CardAmt) as Card, SUM(ChequeAmt) as Cheque,SUM(CashReturn) as CashRtn 
	from PharSalesledger
	where trdate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	and valid = 1 and PtStatus = 'Indoor'
	Group BY trdate
	UNION ALL
	select trdate,'3101100001'  AS AcCode,'Medicine' as Department,'Outdoor' AS PTStatus,sum(sales) as sales,
	sum(collection) as coll,SUM(lessAmt) AS Less,SUM(returnAmt) as RtnAmt,
	SUM(CashAmt) as Cash, SUM(CardAmt) as Card, SUM(ChequeAmt) as Cheque,SUM(CashReturn) as CashRtn 
	from PharSalesledger
	where trdate BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	and valid = 1 and PtStatus NOT IN ('Indoor')
	Group BY trdate
	UNION ALL
	select ReceiptDate,'3101090001','Ambulance','OutDoor',SUM(TotalCharge) as Sales,
	SUM(TotalAdvanceAmt) as Coll , SUM(Less) as Less , 0 ,
	SUM(TotalAdvanceAmt) As Cash , 0 as Card , 0 AS Cheque , 0 AS CashReturn
	from AmbulanceMaster  
	where valid  = 1 and PtStatus = 'OutDoor'
	and ReceiptDate  BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by ReceiptDate
	UNION ALL
	select ReceiptDate,'3101010036','Ambulance','Indoor',SUM(TotalCharge) as Sales ,
	SUM(TotalAdvanceAmt) as Coll , SUM(Less) as Less , 0 ,
	SUM(TotalAdvanceAmt) As Cash , 0 as Card , 0 AS Cheque , 0 AS CashReturn
	from AmbulanceMaster  
	where valid  = 1 and PtStatus = 'Indoor'
	and ReceiptDate  BETWEEN @dateFrom AND @dateTo and BranchId = @BranchId 
	group by ReceiptDate
	UNION ALL
	select a.RefDate,b.AcCode,c.Description AS ACName,'Indoor',SUM(a.totalAmount) AS Sales,
	SUM(a.Collection) as Coll, 
	SUM(a.Less) As Less, 0  as RtnAmt ,
	SUM(a.CashAmt) As Cash , SUM(a.CardAmt) as Card , SUM(a.ChequeAmt) AS Cheque , sum(ReturnAmt) AS CashReturn
	from PatientLedger a , clinicalChart b , tbl_CHART_OF_ACCOUNTS c
	where a.Code=b.PCode and a.BranchId = b.BranchId and b.ACCode = c.code  
	and a.valid = 1
	and a.RefDate BETWEEN @dateFrom AND @dateTo and a.BranchId = @BranchId 
	GROUP BY b.AcCode , c.Description ,a.RefDate
	;

	select 1 as SlNo,a.ACCode,1 as AcType , a.Department as MainDept , b.Description , a.Sales , a.Less , a.RtnAmt as ReturnAmt , 
	a.cash as CashAmt ,a.Card as CardAmt , a.Cheque as ChequeAmt , CashReturn
	INTO tmp_TransToTransact
	from tmp a , tbl_CHART_OF_ACCOUNTS b
	where a.AcCode = b.Code 

	select * from tmp_TransToTransact

END
GO
