CREATE PROC [dbo].[SP_HPMisDueList] @DateFrom DATE, @DateTo DATE, @BranchId INT
AS
BEGIN /* SP_HPMisDueList '2023-01-01', '2023-09-10', 1 */
	DECLARE @IncludePharmacy INT, @IsIncludePharmacy INT;
	SELECT @IsIncludePharmacy = PharmacyInclude FROM tbl_ComInfo
	IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END

	SELECT 1 AS SlNo, 'Indoor' AS Department, b.PatientId, b.PatientName, b.PatientTel, '' AS InvNo, '' AS InvDate, 
	SUM(a.HBill+a.DBill+a.MBill-a.Collection-a.LessAmt) AS Due, d.Remarks
	FROM (
		SELECT a.BranchId, a.PatientId, SUM(a.TotalAmount) AS HBill, 0 AS DBill, 0 AS MBill,
		SUM(a.Collection-a.ReturnAmt) AS Collection, 0 AS AdjustAmt , SUM(a.Less) as LessAmt
		FROM PatientLedger a
		WHERE BranchId = @BranchId AND Valid = 1 AND a.PatientId != ''
		GROUP BY a.BranchId, a.PatientId
		UNION
		SELECT a.BranchId, a.PatientId, 0 AS HBill, SUM(a.Sales-a.ReturnAmount) AS DBill, 0 AS MBill,
		SUM(a.Collection-a.ReturnCash) AS Collection, SUM(a.AdjustAmt) AS AdjustAmt , SUM(a.Less) as LessAmt
		FROM SalesLedger a
		WHERE BranchId = @BranchId AND a.Valid = 1 AND a.PatientId != ''
		GROUP BY a.BranchId, a.PatientId
		UNION
		SELECT a.BranchId, a.PatientId, 0 AS HBill, 0 AS DBill, SUM(a.Sales-a.ReturnAmt-a.LessAdjust) AS MBill,
		SUM(a.Collection+a.DueColl-a.CashReturn) AS Collection, SUM(a.AdjustAmt) AS AdjustAmt , SUM(a.DueLess + a.LessAmt) as LessAmt
		FROM PharSalesLedger a
		WHERE BranchId = @BranchId AND a.Valid = @IncludePharmacy AND a.PatientId != ''
		GROUP BY a.BranchId, a.PatientId
	) a
	LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
	LEFT JOIN PatientReleaseMaster d ON a.BranchId = d.BranchId AND b.PatientId = d.PatientID AND d.Valid = 1
	WHERE b.BranchId = @BranchId AND b.IsRelease = 1 AND d.ReleaseDate BETWEEN @DateFrom AND @DateTo
	GROUP BY b.PatientId, b.PatientName, d.Remarks, b.PatientTel
	HAVING SUM(a.HBill+a.DBill+a.MBill-a.Collection-a.LessAmt) NOT BETWEEN -1.00 and 1
	UNION ALL
	SELECT 2 AS SlNo, Department, RegNo, Particulars AS PatientName, PPhone AS PatientTel, PrevInvNo, PreInvDate AS InvDate, SUM(Sales-Less-Collection-ReturnDue) AS Due, '' AS Remarks
	FROM SalesLedger a
	WHERE BranchId = @BranchId AND PtStatus != 'Indoor' AND PreInvDate BETWEEN @DateFrom AND @DateTo
	GROUP BY Department, RegNo, Particulars, PPhone, PrevInvNo, PreInvDate
	HAVING SUM(Sales-Less-Collection-ReturnDue) != 0
	UNION ALL
	SELECT 3 AS SlNo, 'Medicine', RegNo, Particulars AS PatientName, '' AS PatientTel, InvNo, InvDate AS InvDate, SUM(Sales-LessAmt-Collection-DueLess-DueColl-ReturnAmt) AS Due, 
	'' AS Remarks
	FROM PharSalesLedger a
	WHERE BranchId = @BranchId AND PtStatus != 'Indoor' AND InvDate BETWEEN @DateFrom AND @DateTo
	GROUP BY InvNo, InvDate, RegNo, Particulars
	HAVING SUM(Sales-LessAmt-Collection-DueLess-DueColl-ReturnAmt) != 0
	UNION ALL
	SELECT 3 AS SlNo, 'Medicine', RegNo, PatientName, '' AS PatientTel, RefNo, RefDate AS InvDate, SUM(TotalCharge-Less-ReceiveAmt) AS Due, 
	'' AS Remarks
	FROM AmbulanceLedger a
	WHERE BranchId = @BranchId AND PtStatus != 'Indoor' AND RefDate BETWEEN @DateFrom AND @DateTo
	GROUP BY RegNo, PatientName, RefNo, RefDate
	HAVING SUM(TotalCharge-Less-ReceiveAmt) != 0
	ORDER BY 1, 2, 3
END
GO
