CREATE PROC [dbo].[SP_HpPackageDueInsert](@branchId int, @packageCode nvarchar(20), @patientId nvarchar(20))
AS
Begin
SELECT a.PCode, a.Description, SUM(a.PNoU-a.PlNoU) AS NoU, a.Price, SUM(a.PAmount-a.PLAmount) AS TotalAmount FROM(
SELECT a.PCode, a.Description, a.NoU AS PNoU, 0 AS PlNoU, a.Price, a.TotalPrice AS PAmount, 0 AS PLAmount FROM HPIndoorPackage a
WHERE a.PackageCode = @packageCode AND a.Valid = 1 ANd a.BranchId = @branchId
UNION ALL
SELECT a.Code, b.Description, 0 AS PNoU, SUM(a.NoU) AS PlNoU, a.Charge, 0 AS PAmount, SUM(a.NoU*a.Charge) AS PLAmount FROM PatientLedger a
LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.Code = b.PCode
WHERE a.BranchId = @branchId AND PatientId = @patientId AND a.Valid = 1
GROUP BY a.Code, b.Description, a.Charge
) a
GROUP BY a.PCode, a.Description, a.Price
HAVING SUM(a.PAmount-a.PLAmount) > 0
END
GO
