CREATE PROCEDURE [dbo].[SP_HR_AllLeaveInfo] (@BranchId int, @EmpId NVARCHAR(20))
AS
BEGIN
select aa.LeaveType as LeaveType, sum(aa.TotalLeave) as TotalDays, sum(aa.Vaccation) as Vaccation, sum(aa.TotalLeave)-sum(aa.Vaccation) as LeaveAvailable 
FROM (
	Select sum(totaldays) as TotalLeave, Name as LeaveType, 0 as Vaccation
	from LeaveType 
	GROUP BY Name 
	UNION All 
	select 0 as TotalLeave, a.LeaveType AS LeaveType, count(b.TrNo) as Vaccation
	from EmpLeaveInfoMaster a 
	left join EmpLeaveInfoDtls b on b.TrNo=a.TrNo and b.Valid=1 and a.EmpCode=b.EmpCode 
	where a.Status = 2 AND a.BranchId=@BranchId and a.EmpId=@EmpId and a.valid=1 and YEAR(GETDATE())=YEAR(b.LeaveFrom)
	GROUP BY a.EmpCode, a.LeaveType
) aa
GROUP by aa.LeaveType
END
GO
