CREATE PROCEDURE [dbo].[SP_HR_BasicEmployeeInformation] (@WorkingStatus nvarchar(20),@DeptCode 
nvarchar(20),@DesigCode nvarchar(20),@EmpId nvarchar(20), @Scale nvarchar(20) , @BranchId int) 
AS 

SELECT aa.Code ,bb.Name ,bb.DeptCode , bb.Department , bb.DesigCode , bb.Designation ,  
bb.DateOfJoining ,bb.EmpBankAccountNo ,bb.Grade, bb.Project , bb.pno, bb.NID, bb.MobileNo, bb.Email, bb.DateOfBirth, bb.BloodGroup, bb.WorkingStatus, bb.IsGetHoliday, bb.ComBankAccountNo, bb.District, bb.EntryDateTime, bb.UserName, bb.UnitId, bb.BranchId,
SUM(aa.BSalay) as BSalay, SUM(aa.HRent) as HRent, SUM(aa.Conv) as Conv, SUM(aa.Other) as Other, 
SUM(aa.TotalSalary)  AS TSalary
FROM (
select Code , amount as BSalay,0 as HRent, 0 as Conv , 0 as Other , 0 as TotalSalary
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and SalaryTypeId = 1  AND BranchId=@BranchId
UNION ALL 
select Code , 0, amount as HRent,0 as Conv , 0 as Other , 0 as TotalSalary
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and SalaryTypeId = 2  AND BranchId=@BranchId
UNION ALL
select Code , 0, 0 as HRent,amount as Conv , 0 as Other , 0 as TotalSalary
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and SalaryTypeId = 4 AND BranchId=@BranchId
UNION ALL
select Code , 0, 0 as HRent,0 as Conv , amount as Other , 0 as TotalSalary
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and SalaryTypeId NOT IN (1,2,4)  AND BranchId=@BranchId
UNION ALL
select Code , 0, 0 as HRent,0 as Conv , 0 as Other , amount as TotalSalary
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e'  AND BranchId=@BranchId) aa , HREmployeeMaster bb
where aa.Code = bb.Code AND bb.BranchId=@BranchId 
AND (ISNULL(bb.WorkingStatus,'') + ISNULL(bb.DeptCode,'') +ISNULL(bb.DesigCode,'') + ISNULL(bb.Code,'') + ISNULL(bb.Grade,''))  LIKE @WorkingStatus +'%'+@DeptCode +'%'+@DesigCode +'%'+@EmpId +'%'+ @Scale +'%'
group by aa.Code ,bb.Name ,bb.DeptCode , bb.Department , bb.DesigCode , 
bb.Designation, bb.DateOfJoining ,bb.EmpBankAccountNo, bb.Grade, bb.Project , bb.pno, bb.NID, bb.MobileNo, bb.Email, bb.DateOfBirth, bb.BloodGroup, bb.WorkingStatus, bb.IsGetHoliday, bb.ComBankAccountNo, bb.District, bb.EntryDateTime, bb.UserName, bb.UnitId, bb.BranchId
ORDER BY bb.DeptCode

GO
