create PROCEDURE [dbo].[SP_HR_Emp_BasicInformation] (@WorkingStatus nvarchar(20),@DeptCode nvarchar(20),@DesigCode nvarchar(20),@EmpId nvarchar(20),@Scale nvarchar(20),@UnitId int, @BranchId int) 
AS 
SELECT aa.Code ,bb.Name ,bb.DeptCode , bb.Department , bb.DesigCode , bb.Designation ,bb.NID, CONVERT(varchar(20),bb.DateOfJoining,101) as DateOfJoining,
bb.EmpBankAccountNo,bb.Grade,
SUM(aa.BSalay) as BSalay, SUM(aa.HRent) as HRent, SUM(aa.Conv) as Conv, SUM(aa.Other) as Other, 
SUM(aa.TotalSalary)  AS TSalary,aa.UnitId,aa.BranchId
FROM (
select Code , amount as BSalay,0 as HRent, 0 as Conv , 0 as Other , 0 as TotalSalary,UnitId,BranchId
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and SalaryTypeId = 1 
UNION ALL 
select Code , 0, amount as HRent,0 as Conv , 0 as Other , 0 as TotalSalary,UnitId,BranchId
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and SalaryTypeId = 2 
UNION ALL
select Code , 0, 0 as HRent,amount as Conv , 0 as Other , 0 as TotalSalary,UnitId,BranchId
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and SalaryTypeId = 4 
UNION ALL
select Code , 0, 0 as HRent,0 as Conv , amount as Other , 0 as TotalSalary,UnitId,BranchId
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and SalaryTypeId NOT IN (1,2,4)
UNION ALL
select Code , 0, 0 as HRent,0 as Conv , 0 as Other , amount as TotalSalary,UnitId,BranchId
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' ) aa , HREmployeeMaster bb
where aa.Code = bb.Code AND aa.UnitId=bb.UnitId AND aa.BranchId=bb.BranchId AND aa.UnitId=@UnitId And aa.BranchId=@BranchId
AND bb.WorkingStatus LIKE @WorkingStatus+'%' AND bb.DeptCode LIKE @DeptCode+'%' AND bb.DesigCode LIKE @DesigCode+'%' AND bb.Code LIKE @EmpId+'%' AND bb.Grade LIKE @Scale+'%'
group by aa.Code ,bb.Name ,bb.DeptCode , bb.Department , bb.DesigCode , bb.Designation ,bb.NID, bb.DateOfJoining,aa.UnitId,aa.BranchId ,
bb.EmpBankAccountNo,bb.Grade 
ORDER BY bb.DeptCode
GO
