CREATE PROCEDURE [dbo].[SP_HR_LeaveDetails] (@BranchId int, @EmpId NVARCHAR(20))
AS --- EXEC SP_HR_LeaveDetails 1, '0028'
BEGIN
SELECT a.TrNo, a.LeaveType, MIN(b.LeaveFrom) as LeaveFrom, MAX(b.LeaveFrom) as LeaveTo, COUNT(b.TrNo) AS TotalDays
 FROM EmpLeaveInfoMaster a, 
 EmpLeaveInfoDtls b 
WHERE a.TrNo = b.TrNo AND  a.Valid = 1 AND b.Valid = 1 AND a.BranchId =@BranchId AND a.EmpId=@EmpId AND a.Status = 2 and year(b.LeaveFrom)=year(getdate())
GROUP BY a.TrNo, a.LeaveType order by LeaveType
END
