CREATE PROCEDURE [dbo].[SP_HR_LoanReport_Dtls] (@FromDate Date,@ToDate Date, @DeptCode nvarchar(20),@DesigCode nvarchar(20),@EmpCode nvarchar(20), @BranchId int) 
AS 
BEGIN
Select TrDate, EmpCode, EmpName, DeptCode, DeptName, DesigCode, DesigName, LoanDate, LoanId, LoanType, 
LoanAmount, InstallmentAmt, AdjustedAmt, Advance, RefundAmt, Status, TotalSalary
from HRLoanAndAdvance
where Valid=1  AND BranchId=@BranchId
AND LoanDate between @FromDate and @ToDate 
