group by  TrDate, EmpCode, EmpName, DeptCode, DeptName, DesigCode, DesigName, LoanDate, LoanId, LoanType, 
LoanAmount, InstallmentAmt, AdjustedAmt, Advance, RefundAmt, Status, TotalSalary
ORDER BY DeptCode
END

