CREATE PROCEDURE [dbo].[SP_HR_Report_ApproveLeave] (@DateFrom Date,@DateTo Date, @DepartmentCode nvarchar(20),@DesignationCode nvarchar(20),@EmpCode nvarchar(20), @BranchId int) 
AS --- EXEC SP_HR_Report_ApproveLeave '2024-05-01','2024-06-25','','','',1
BEGIN
select a.TrNo, a.TrDate, a.EmpId, a.EmpCode, a.EmpName, b.Department, b.Designation, a.LeaveType, a.TotalDays, a.Note, a.Remarks, a.ApproveRemarks, a.ApprovedTime, a.ApprovedBy
from EmpLeaveInfoMaster a
left join HREmployeeMaster b on a.EmpCode = b.Code
where a.Valid=1 AND a.BranchId=@BranchId AND a.Status = 2
AND a.TrDate between @DateFrom and @DateTo
AND ISNULL(b.DeptCode,'') LIKE '%'+@DepartmentCode+'%' AND  ISNULL(b.DesigCode,'') LIKE '%'+@DesignationCode+'%' AND ISNULL(a.EmpCode,'') LIKE '%'+@EmpCode+'%'
Group By a.TrNo, a.TrDate, a.EmpId, a.EmpCode, a.EmpName, b.Department, b.Designation, a.LeaveType, a.TotalDays, a.Note, a.Remarks, a.ApproveRemarks, a.ApprovedTime, a.ApprovedBy
ORDER BY b.Department
END
