CREATE PROCEDURE [dbo].[sp_HR_Report_DepartmentWiseSalary] (@DateFrom Date,@DateTo Date, @UnitId int, @BranchId int)
AS
BEGIN
	SELECT aa.DeptCode , aa.DeptName , SUM(aa.NoofEmp) As NoOfEmp,  SUM(aa.TotalSalary) AS TSalary , 
	SUM(aa.DeducAmt) AS TDeduct ,
	SUM(aa.TotalSalary-aa.DeducAmt) as NetSalary
	FROM (
	select a.DeptCode , a.DeptName ,0 AS NoofEmp, a.amount as TotalSalary, 0 as DeducAmt
	from Payregister a
	where valid = 1  and a.UnitId=@UnitId AND a.BranchId=@BranchId
	and salaryType='e'
	and a.TRDate BETWEEN @DateFrom AND @DateTo 

	UNION ALL 
	select a.DeptCode , a.DeptName ,0 AS NoofEmp, 0 as TotalSalary,a.amount as DeducAmt
	from Payregister a
	where valid = 1  and a.UnitId=@UnitId AND a.BranchId=@BranchId
	and salaryType='d'
	and a.TRDate BETWEEN @DateFrom AND @DateTo 
	
	UNION ALL 
	select a.DeptCode , a.DeptName ,COUNT(DISTINCT Code) AS NoofEmp, 0 as TotalSalary,0 as DeducAmt
	from Payregister a
	where valid = 1  and a.UnitId=@UnitId AND a.BranchId=@BranchId
	and a.TRDate BETWEEN @DateFrom AND @DateTo 
	GROUP BY a.DeptCode , a.DeptName) aa
	group by aa.DeptCode, aa.DeptName
END

GO
