CREATE PROCEDURE [dbo].[SP_HR_Report_DeptMonthWiseSalary] (@DateFrom Date,@DateTo Date, @Month int, @Year nvarchar(50)
, @UnitId int, @BranchId int)
AS
BEGIN
	SELECT aa.DeptCode , aa.DeptName , SUM(aa.NoofEmp) As NoOfEmp,  SUM(aa.TotalSalary) AS TSalary , 
	SUM(aa.DeducAmt) AS TDeduct ,
	SUM(aa.TotalSalary-aa.DeducAmt) as NetSalary, aa.AttMName, aa.AttMonth, aa.AttYear
	FROM (
	select a.DeptCode , a.DeptName ,0 AS NoofEmp, a.amount as TotalSalary, 0 as DeducAmt, a.AttMName, a.AttMonth, a.AttYear
	from Payregister a
	where valid = 1 
	and salaryType='e' AND a.AttMonth=@Month AND a.AttYear=@Year  and a.UnitId=@UnitId AND a.BranchId=@BranchId
	and a.TRDate BETWEEN @DateFrom AND @DateTo 
		
	UNION ALL 
	select a.DeptCode , a.DeptName ,0 AS NoofEmp, 0 as TotalSalary,a.amount as DeducAmt, a.AttMName, a.AttMonth, a.AttYear
	from Payregister a
	where valid = 1 
	and salaryType='d' AND a.AttMonth=@Month AND a.AttYear=@Year  and a.UnitId=@UnitId AND a.BranchId=@BranchId
	and a.TRDate BETWEEN @DateFrom AND @DateTo 
	
	UNION ALL 
	select a.DeptCode , a.DeptName ,COUNT(DISTINCT Code) AS NoofEmp, 0 as TotalSalary,0 as DeducAmt, a.AttMName, a.AttMonth, a.AttYear
	from Payregister a
	where valid = 1 AND a.AttMonth=@Month AND a.AttYear=@Year and a.UnitId=@UnitId AND a.BranchId=@BranchId
	and a.TRDate BETWEEN @DateFrom AND @DateTo 
	GROUP BY a.DeptCode , a.DeptName, a.AttMName, a.AttMonth, a.AttYear) aa
	group by aa.DeptCode, aa.DeptName, aa.AttMName, aa.AttMonth, aa.AttYear
END


