CREATE Procedure [dbo].[SP_HR_Report_Emp_DepartmentWiseNetSalary_AllEmp] (@DateFrom Date,@DateTo Date,@BranchId int,@DeptCode nvarchar(20),@DesigCode nvarchar(20),@EmpId nvarchar(20),@Scale nvarchar(20))
 AS
 select aa.EmpId, bb.Code, bb.Name, bb.Designation, bb.Department, bb.DeptCode, aa.AttMName, aa.AttYear,
 bb.WorkingStatus, bb.EmpBankAccountNo, aa.Grade, sum (aa.earn) as earn, sum(aa.deduction) as deduction,
 sum(aa.earn-aa.deduction) as NetSalary
  from 
 (select TRDate,EmpId, Amount as earn ,0 as deduction, AttMName, AttYear, UnitId, BranchId,Grade from Payregister a where a.Valid=1 and a.SalaryType='e' and  a.Valid=1   
  union all 
  select TRDate,EmpId, 0 as earn, Amount as deduction, AttMName, AttYear,UnitId, BranchId, Grade from Payregister a where a.Valid=1  and a.SalaryType='d') aa , 
  HREmployeeMaster bb
   where aa.EmpId=bb.EmpId and bb.Valid=1 AND aa.UnitId=bb.UnitId And aa.BranchId=bb.BranchId AND aa.BranchId=@BranchId AND aa.TRDate between @DateFrom AND @DateTo AND
   bb.DeptCode LIKE '%'+ @DeptCode AND bb.DesigCode LIKE '%'+@DesigCode AND bb.EmpId LIKE '%'+@EmpId AND aa.Grade LIKE '%'+ @Scale
    group by aa.EmpId, bb.Name, bb.Designation, bb.NID,
  bb.DateOfJoining, bb.WorkingStatus, bb.EmpBankAccountNo, aa.Grade, bb.Code, bb.DeptCode, bb.Department, aa.AttMName, aa.AttYear 
  ORDER by bb.DeptCode,bb.Department

GO
