CREATE Procedure [dbo].[SP_HR_Report_Emp_DepartmentWiseNetSalarySummarized]@BranchId int, @FromDate Date,@ToDate date,@DeptCode nvarchar(20),@DesigCode  nvarchar(20)
as 
select bb.Department , bb.DeptCode,  COUNT(distinct aa.EmpId) as NoOfEmp, ROUND(sum(aa.earn-aa.deduction)/COUNT(distinct aa.EmpId),2) as Avgsalary,
 sum (aa.earn) as earn, sum(aa.deduction) as deduction, sum(aa.earn-aa.deduction) as 
 TotalSalary,aa.AttMName,aa.AttYear  from (
select TRDate, EmpId, Amount as earn ,0 as deduction, AttMName, AttYear, AttMonth from  Payregister  where Valid=1 AND SalaryType='e'  
union all 
select TRDate, EmpId,0 as earn, Amount as deduction,AttMName,AttYear,AttMonth from Payregister  where Valid=1 AND SalaryType='d') aa ,
HREmployeeMaster bb
 where aa.EmpId=bb.EmpId and bb.WorkingStatus='Working' AND bb.BranchId=@BranchId AND aa.TRDate between @FromDate AND @ToDate AND
(ISNULL(bb.DeptCode,'') + ISNULL(bb.DesigCode,'')) LIKE  '%'+ @DeptCode +'%'+ @DesigCode +'%'
group by  bb.Department, bb.DeptCode , aa.AttMName, aa.AttYear, aa.AttMonth
ORDER by bb.DeptCode

GO
