CREATE Procedure [dbo].[SP_HR_Report_Emp_DeptWiseMonthlySalarySummery] @DateFrom Date, @DateTo Date, @BranchId int
as 
select aa.DeptCode, aa.Department, aa.AttMName, aa.AttMonth, aa.AttYear, SUM(aa.Salary) as Salary, SUM(aa.Deduction) as Deduction, SUM(aa.Salary - aa.Deduction) as NetSalary, aa.UnitId, aa.BranchId from
(
select DeptCode, DeptName AS Department, sum(Amount) as Salary, 0 as Deduction,AttMName,AttMonth,AttYear,UnitId,BranchId
from Payregister a
where SalaryType='e' And Valid=1 AND TRDate between @DateFrom AND @DateTo 
GROUP BY AttMName, AttMonth, AttYear, DeptCode, DeptName, UnitId, BranchId
UNION ALL
select DeptCode, DeptName AS Department, 0 as Salary, sum(Amount) as Deduction,AttMName,AttMonth,AttYear,UnitId,BranchId
from Payregister
where SalaryType='d' And Valid=1 AND TRDate between @DateFrom AND @DateTo
GROUP BY AttMName, AttMonth, AttYear, DeptCode, DeptName, UnitId, BranchId
) aa
where aa.BranchId=@BranchId
GROUP BY aa.DeptCode, aa.Department, aa.AttMName, aa.AttMonth, aa.AttYear, aa.UnitId, aa.BranchId
ORDER By aa.DeptCode,aa.AttMonth

GO
