CREATE Procedure [dbo].[SP_HR_Report_Emp_SalaryBankAdvice] @BranchId int, @FromDate Date, @ToDate Date, @DeptCode nvarchar(20), @DesigCode nvarchar(20), @EmpId nvarchar(20), @Scale nvarchar(20) 
AS
select bb.EmpId, bb.Code, bb.Name, bb.EmpBankAccountNo, aa.AttMName, aa.AttYear, aa.PaymentAmtBank,bb.Grade from 
(select TRDate, EmpId, PaymentAmtBank, AttMonth, AttMName, AttYear, UnitId, BranchId from Payregister where Valid=1 AND PaymentAmtBank>0) aa , HrEmployeeMaster bb
where aa.EmpId=bb.EmpId  AND aa.UnitId=bb.UnitId AND aa.BranchId=bb.BranchId  AND aa.BranchId=@BranchId AND aa.TRDate between @FromDate AND @ToDate AND
 (ISNULL(bb.DeptCode,'') + ISNULL(bb.DesigCode,'') + ISNULL(bb.EmpId,'') + ISNULL(bb.Grade,'')) LIKE @DeptCode +'%'+@DesigCode +'%'+@EmpId +'%'+ @Scale+'%'
group by bb.EmpId ,bb.Code, bb.Name, bb.EmpBankAccountNo, aa.PaymentAmtBank, aa.AttMName, aa.AttYear, bb.Grade
ORDER BY bb.EmpId, AttMName

