CREATE Procedure [dbo].[SP_HR_Report_Emp_SalarySheetDetailsMonthly]  @FromDate Date, @ToDate Date,@DeptCode nvarchar(20),@DesigCode nvarchar(20),@EmpCode nvarchar(20),@Scale nvarchar(20), @BranchId varchar(10)
As /* exec SP_HR_Report_Emp_SalarySheetDetailsMonthly '2023-01-01', '2023-01-31', '3', '0001', '10001', '', 0, 6 */
select bb.Code AS EmpId,bb.Name, bb.DateOfJoining as JoinDate,sum(aa.BSalary) as BSalary ,  sum(aa.HRent) as HouseRent, 
sum(aa.MedicalAllow) as MedicalAllow, sum(aa.Convey) as Convey , sum (aa.MobileAllow) as MobileAllow, SUM(aa.OverTime) as OverTime,
sum(aa.NightAllowence) as NightAllowence, sum(aa.AreaAllowence) as AreaAllowence, sum(aa.Incentive) as Incentive, Sum(aa.OtherAllow) as OtherAllowence,
sum(aa.BSalary+aa.HRent+aa.MedicalAllow+aa.Convey+ aa.MobileAllow+ aa.OverTime+ aa.NightAllowence+ aa.AreaAllowence+ aa.Incentive+ aa.OtherAllow) as TotalSalary,
sum(aa.RevenueStamp) as RevenueStamp, sum(aa.IncomeTax) as IncomeTax, sum(aa.LWP) as LWP, sum(aa.Absent) as Absent, sum(aa.PenaltyDeduction) as PenaltyDeduction,
sum(aa.Loan) as Loan,sum(aa.Advance) as Advance, sum(aa.Transport) as Transport,sum(aa.Meal) as Meal, sum(aa.Others) as Others,
sum(aa.RevenueStamp + aa.IncomeTax + aa.PenaltyDeduction + aa.Loan + aa.Advance + aa.Transport + aa.Meal + aa.Others) as TotalDeduction,
sum(aa.BSalary+aa.HRent+aa.MedicalAllow+aa.Convey+ aa.MobileAllow+ aa.OverTime+ aa.NightAllowence+ aa.AreaAllowence+ aa.Incentive+ aa.OtherAllow) -
sum(aa.RevenueStamp + aa.IncomeTax + aa.LWP + aa.Absent + aa.PenaltyDeduction + aa.Loan + aa.Advance + aa.Transport + aa.Meal + aa.Others) as NetSalary, 
FLOOR((sum(aa.BSalary)*12)/365) AS BasicPerDaySalary, sum(distinct aa.TWorkDays) as TWorkDays, sum(distinct aa.DaysAbsent) as DaysAbsent, 
ISNULL(aa.LateIn,0) as TotalLateInDays, (ISNULL(LateIn, 0)/3) as LateInDays, 
(FLOOR((sum(aa.BSalary)*12)/365))* (ISNULL(LateIn, 0)/3) as  LateInDeductAmount, ISNULL(aa.LeaveWithoutPay,0) as TotalLeaveDays,
Case when sum(distinct aa.DaysAbsent) > 5 then Round((sum(aa.BSalary+aa.HRent+aa.MedicalAllow+aa.Convey+ aa.MobileAllow+ aa.OverTime+ aa.NightAllowence+ aa.AreaAllowence+ 
aa.Incentive+ aa.OtherAllow)/sum(distinct aa.TWorkDays))*sum(distinct aa.DaysAbsent),0) else FLOOR((sum(aa.BSalary)*12)/365)*sum(distinct aa.DaysAbsent) END As DeductAbsAmt,
--CONVERT(varchar(10), (ISNULL(LateIn, 0)/3))+' ' +'Late Days' + ''+' '+ CONVERT(varchar(10), sum(distinct aa.DaysAbsent),0) +' ' + 'Absent Days' as Remarks,

Case when  CONVERT(varchar(10),(ISNULL(LateIn, 0)/3)) =0   And CONVERT(varchar(10),sum(distinct aa.DaysAbsent)) = 0 Then '' Else CONVERT(varchar(10), (ISNULL(LateIn, 0)/3))+' ' +'Late Days' + ''+' '+ CONVERT(varchar(10), sum(distinct aa.DaysAbsent),0) +' ' + 'Absent Days'
End As Remarks,

bb.Department,bb.DeptCode,bb.DesigCode,aa.Grade,aa.UserName 
from
(select EmpId, TRDate, Amount as BSalary,0 as HRent,0 as MedicalAllow,0 as Convey,0 as MobileAllow, 0 as NightAllowence,  0 as AreaAllowence, 0 as Others,0 as DaysAbsent,0 as TWorkDays,0 as OverTime,0 as Incentive,0 as OtherAllow,  0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA,0 as Meal,0 as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade, LateIn, LeaveWithoutPay,UserName from Payregister where   SalaryType='e' AND SalaryTypeId=1 AND Valid = 1
Union All
select EmpId, TRDate, 0 as BSalary,Amount as HRent,0 as MedicalAllow,0 as Convey,0 as MobileAllow, 0 as NightAllowence, 0 as AreaAllowence, 0 as Others,0 as DaysAbsent,0 as TWorkDays,0 as OverTime,0 as Incentive, 0 as OtherAllow,  0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA, 0 as Meal,0 as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade, LateIn, LeaveWithoutPay,UserName  from Payregister where  SalaryType='e' AND SalaryTypeId=2  AND Valid = 1
Union All 
select EmpId, TRDate, 0 as BSalary,0 as HRent,Amount as MedicalAllow,0 as Convey,0 as MobileAllow, 0 as NightAllowence,  0 as AreaAllowence, 0 as Others,0 as DaysAbsent,0 as TWorkDays,0 as OverTime,0 as Incentive, 0 as OtherAllow,  0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent,0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA, 0 as Meal,0 as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade,  LateIn, LeaveWithoutPay,UserName from Payregister  where  SalaryType='e' AND SalaryTypeId=3  AND Valid = 1
Union All
select EmpId, TRDate,0 as BSalary,0 as HRent,0 as MedicalAllow,Amount as Convey,0 as MobileAllow, 0 as NightAllowence, 0 as AreaAllowence, 0 as Others,0 as DaysAbsent,0 as TWorkDays,0 as OverTime,0 as Incentive, 0 as OtherAllow, 0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent,0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA, 0 as Meal,0 as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade, LateIn, LeaveWithoutPay,UserName  from Payregister where  SalaryType='e' AND SalaryTypeId=4  AND Valid = 1
Union All
select EmpId, TRDate,0 as BSalary,0 as HRent,0 as MedicalAllow,0 as Convey, Amount as MobileAllow, 0 as NightAllowence, 0 as AreaAllowence, 0 as Others,0 as DaysAbsent,0 as TWorkDays,0 as OverTime,0 as Incentive,0 as OtherAllow, 0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA, 0 as Meal,0 as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade, LateIn, LeaveWithoutPay,UserName from Payregister where SalaryType='e' AND SalaryTypeId=5  AND Valid = 1
Union All
select EmpId, TRDate,0 as BSalary,0 as HRent,0 as MedicalAllow,0 as Convey, 0 as MobileAllow, 0 as NightAllowence,0 as AreaAllowence, 0 as Others,0 as DaysAbsent, 0 as TWorkDays,Amount as OverTime,0 as Incentive, 0 as OtherAllow , 0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA, 0 as Meal,0 as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade, LateIn, LeaveWithoutPay,UserName from Payregister where SalaryType='e' AND SalaryTypeId=6  AND Valid = 1
Union All
select EmpId, TRDate,0 as BSalary,0 as HRent,0 as MedicalAllow,0 as Convey,0 as MobileAllow, Amount as NightAllowence, 0 as AreaAllowence, 0 as Others,0 as DaysAbsent,0 as TWorkDays,0 as OverTime,0 as Incentive,0 as OtherAllow, 0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA, 0 as Meal,0 as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade, LateIn, LeaveWithoutPay,UserName from Payregister where SalaryType='e' AND SalaryTypeId=8  AND Valid = 1
Union All
