Union All
select EmpId, TRDate,0 as BSalary,0 as HRent,0 as MedicalAllow,0 as Convey,0 as MobileAllow, 0 as NightAllowence,  0 as AreaAllowence, 0 as Others,0 as DaysAbsent, 0 as TWorkDays,0 as OverTime,0 as Incentive, 0 as OtherAllow, 0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction,  Amount as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA, 0 as Mealfrom,0 as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade, LateIn, LeaveWithoutPay,UserName from Payregister where SalaryType='d' AND SalaryTypeId=18 AND Valid = 1
Union All
select EmpId, TRDate,0 as BSalary,0 as HRent,0 as MedicalAllow,0 as Convey,0 as MobileAllow, 0 as NightAllowence,  0 as AreaAllowence, 0 as Others,0 as DaysAbsent, 0 as TWorkDays,0 as OverTime,0 as Incentive, 0 as OtherAllow, 0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction,  0 as Advance,0 as Loan, Amount As Transport, 0 as DeductionCA, 0 as Mealfrom,0 as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade, LateIn, LeaveWithoutPay,UserName from Payregister where SalaryType='d' AND SalaryTypeId=19 AND Valid = 1
Union All
select EmpId, TRDate,0 as BSalary,0 as HRent,0 as MedicalAllow,0 as Convey,0 as MobileAllow, 0 as NightAllowence, 0 as AreaAllowence, 0 as Others,0 as DaysAbsent, 0 as TWorkDays,0 as OverTime,0 as Incentive, 0 as OtherAllow, 0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA, Amount as Meal,0 as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade, LateIn, LeaveWithoutPay ,UserName from Payregister where SalaryType='d' AND SalaryTypeId=20 AND Valid = 1
Union All
select EmpId, TRDate,0 as BSalary,0 as HRent,0 as MedicalAllow,0 as Convey,0 as MobileAllow, 0 as NightAllowence,  0 as AreaAllowence, 0 as Others,0 as DaysAbsent, 0 as TWorkDays,0 as OverTime,0 as Incentive, 0 as OtherAllow, 0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA, 0 as Meal,Amount as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade, LateIn, LeaveWithoutPay ,UserName from Payregister where SalaryType='d' AND SalaryTypeId=21 AND Valid = 1
Union All
select EmpId, TRDate,0 as BSalary,0 as HRent,0 as MedicalAllow,0 as Convey,0 as MobileAllow, 0 as NightAllowence,  0 as AreaAllowence, 0 as Others,0 as DaysAbsent, 0 as TWorkDays,0 as OverTime,0 as Incentive, 0 as OtherAllow,  0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA, 0 as Meal,Amount as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade,LateIn as LateDays, LeaveWithoutPay,UserName   from Payregister where Valid = 1
Union All
select EmpId, TRDate,0 as BSalary,0 as HRent,0 as MedicalAllow,0 as Convey,0 as MobileAllow, 0 as NightAllowence,  0 as AreaAllowence, 0 as Others,0 as DaysAbsent, 0 as TWorkDays,0 as OverTime,0 as Incentive, 0 as OtherAllow,  0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA, 0 as Meal,Amount as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade,LateIn as LateDays, LeaveWithoutPay as LeaveDays,UserName  from Payregister where Valid = 1
Union All
select EmpId, TRDate,0 as BSalary,0 as HRent,0 as MedicalAllow,0 as Convey,0 as MobileAllow, 0 as NightAllowence,  0 as AreaAllowence, 0 as Others,DaysAbsent  as DaysAbsent,0 as TWorkDays,0 as OverTime,0 as Incentive, 0 as OtherAllow, 0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA,0 as Meal,0 as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade, LateIn, LeaveWithoutPay,UserName from Payregister where Valid = 1
Union All
select EmpId, TRDate,0 as BSalary,0 as HRent,0 as MedicalAllow,0 as Convey,0 as MobileAllow, 0 as NightAllowence,  0 as AreaAllowence, 0 as Others,0 as DaysAbsent, TotalWorkDays as TWorkDays,0 as OverTime,0 as Incentive, 0 as OtherAllow , 0 as RevenueStamp, 0 as IncomeTax, 0 as LWP, 0 as Absent, 0 as PenaltyDeduction, 0 as Advance,0 as Loan, 0 As Transport, 0 as DeductionCA, 0 as Meal,0 as DeductionOthers,AttMName,AttYear,AttMonth,UnitId,BranchId,Grade, LateIn, LeaveWithoutPay,UserName from Payregister where Valid = 1
)
 aa, HREmployeeMaster bb 
where aa.EmpId=bb.EmpId AND  aa.TRDate Between @FromDate AND @ToDate AND aa.UnitId=bb.UnitId And aa.BranchId=bb.BranchId And aa.BranchId LIKE (CASE WHEN @BranchId = 0 THEN CONVERT(varchar(10), '%%') ELSE CONVERT(varchar(10), '%'+@BranchId+'%')  END) AND
(ISNULL(bb.DeptCode,'') + ISNULL(bb.DesigCode,'') + ISNULL(bb.EmpId,'') + + ISNULL(aa.Grade,'')) LIKE '%'+ @DeptCode +'%' + @DesigCode +'%'+ @EmpCode +'%' + @Scale
Group By bb.Code, bb.Name, bb.DateOfJoining, bb.Department, bb.Department, bb.DeptCode, bb.DesigCode, aa.Grade, aa.LateIn, aa.LeaveWithoutPay, aa.UserName
Order by bb.Code
GO
