CREATE PROCEDURE [dbo].[SP_HR_Report_LeaveForm] (@DateFrom Date,@DateTo Date, @DepartmentCode nvarchar(20),@DesignationCode nvarchar(20),@EmpCode nvarchar(20), @BranchId int) 
AS --- EXEC SP_HR_Report_LeaveForm '2023-01-01','2024-12-30','','','',1
BEGIN
select a.TrNo, a.TrDate, a.EmpId, a.EmpCode, a.EmpName, b.Department, b.Designation, b.MobileNo, a.Purpose, a.LeaveStartYear, a.LeaveType, a.TotalDays, a.Note, a.Status, a.EntryDateTime, a.UserName from EmpLeaveInfoMaster a
left join HREmployeeMaster b on a.EmpCode = b.Code
where a.Valid=1 AND a.BranchId=@BranchId AND a.Status = 1
AND a.TrDate between @DateFrom and @DateTo
AND ISNULL(b.DeptCode,'') LIKE '%'+@DepartmentCode+'%' AND  ISNULL(b.DesigCode,'') LIKE '%'+@DesignationCode+'%' AND ISNULL(a.EmpCode,'') LIKE '%'+@EmpCode+'%'
Group By a.TrNo, a.TrDate, a.EmpId, a.EmpCode, a.EmpName, b.Department, b.Designation, b.MobileNo, a.Purpose, a.LeaveStartYear, a.LeaveType, a.TotalDays, a.Note, a.Status, a.EntryDateTime, a.UserName
ORDER BY b.Department
END
GO
