CREATE PROCEDURE [dbo].[SP_HR_Report_LeaveInfo] (@FromDate Date,@ToDate Date, @DeptName nvarchar(20),@DesigName nvarchar(20),@EmpCode nvarchar(20), @BranchId int) 
AS 
BEGIN
Select TrDate, TrNo, Department, Designation, EmpCode, EmpName, LeaveStartYear AS LeaveFrom, LeaveType, TotalDays, DATEADD(dd, TotalDays-1, DATEDIFF(dd, 0, LeaveStartYear)) AS LeaveTo
From EmpLeaveInfoMaster
where Valid=1 AND BranchId=@BranchId
AND TrDate between @FromDate and @ToDate 
AND ISNULL(Department,'') + (ISNULL(Designation,'') + ISNULL(EmpCode,'')) 
LIKE '%'+@DeptName +'%'+@DesigName +'%'+@EmpCode +'%'
Group By  TrDate, TrNo, Department, Designation, EmpCode, EmpName, LeaveStartYear, LeaveType, TotalDays
ORDER BY Department
END

GO
