CREATE PROCEDURE [dbo].[SP_HR_Report_MonthWise_LeaveReport] (@DateFrom Date,@DateTo Date, @DepartmentCode nvarchar(20),@DesignationCode nvarchar(20),@EmpCode nvarchar(20), @BranchId int)
AS  --- EXEC SP_HR_Report_MonthWise_LeaveReport '2024-01-01','2024-06-30','147','','',1
BEGIN
select c.Name As EmpName, a.EmpCode, c.Designation, c.DateOfJoining, CAST(Month(LeaveFrom) as Int) As MNo,SUBSTRING(DateName(MM,LeaveFrom),1,3) As MName, 
COUNT(*)  As LeaveDays 
INTO #T1
from EmpLeaveInfoDtls a
left join EmpLeaveInfoMaster b on a.EmpCode = b.EmpCode
left join HREmployeeMaster c on a.EmpCode = c.Code
where a.EmpCode like '%'+@EmpCode +'%' AND c.DeptCode LIKE '%'+@DepartmentCode +'%' AND c.DesigCode LIKE '%'+@DesignationCode+'%'
and c.BranchId = @BranchId AND b.Status = 2
AND a.LeaveFrom BETWEEN @DateFrom AND @DateTo 
Group By c.Name, a.EmpCode, c.Designation, c.DateOfJoining, DateName(mm,LeaveFrom), Month(LeaveFrom)
Order By Month(LeaveFrom)

--drop table T2

select EmpName, EmpCode, Designation, DateOfJoining, MNo, MName, LeaveDays , 1 as MQty
INTO #T2
from #T1
Union All
select EmpName, EmpCode, Designation, DateOfJoining, 14 as MNo, 'Enjoyed' as MName, Sum(LeaveDays) as LeaveDays , (-1) as MQty
from #T1
Group by EmpName, EmpCode, Designation, DateOfJoining
Union All 
select a.EmpName, a.EmpCode, a.Designation, a.DateOfJoining, 15 as MNo, 'T.Leave' as MName, 
(SELECT SUM(TotalDays) FROM LeaveType WHERE id NOT IN (7)) as LeaveDays ,1 as MQty
from #T1 a 
Group by a.EmpName, a.EmpCode, a.Designation, a.DateOfJoining


--INSERT INTO T2 (EmpName , EmpCode , Designation , DateOfJoining , MNo , MName , LeaveDays)

SELECT EmpName, EmpCode, Designation, DateOfJoining, MNo, MName, LeaveDays , MQty
--INTO tmpEmpLeave
FROM #T2
UNION ALL
SELECT EmpName , EmpCode , Designation , DateOfJoining , 16 , 'Balance' , SUM(MQty*LeaveDays),0
from #T2
where MNo in (14,15)
group by EmpName , EmpCode , Designation , DateOfJoining 
ORDER BY EmpCode , Designation ,MNo 
END
GO
