CREATE PROCEDURE [dbo].[SP_HR_Report_NewJoinerEmployeeList] (@DOJFrom Date,@DOJTo Date,@DesigCode nvarchar(20),@DeptCode nvarchar(20),@EmpId nvarchar(20),@Scale nvarchar(20), @BranchId int) 
AS 

SELECT aa.EmpId ,bb.Name ,bb.DeptCode , bb.Department , bb.DesigCode , bb.Designation ,  bb.DateOfJoining ,
bb.EmpBankAccountNo , bb.WorkingStatus , bb.NID , bb.MobileNo , bb.UnitId, bb.BranchId,
SUM(aa.BSalay) as BSalay, SUM(aa.HRent) as HRent, SUM(aa.Conv) as Conv, SUM(aa.Other) as Other, 
SUM(aa.TotalSalary)  AS TSalary
FROM (
select EmpId , amount as BSalay,0 as HRent, 0 as Conv , 0 as Other , 0 as TotalSalary
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and SalaryTypeId = 1  AND BranchId=@BranchId
UNION ALL 
select EmpId , 0, amount as HRent,0 as Conv , 0 as Other , 0 as TotalSalary
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and SalaryTypeId = 2  AND BranchId=@BranchId
UNION ALL
select EmpId , 0, 0 as HRent,amount as Conv , 0 as Other , 0 as TotalSalary
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and SalaryTypeId = 4  AND BranchId=@BranchId
UNION ALL
select EmpId , 0, 0 as HRent,0 as Conv , amount as Other , 0 as TotalSalary
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and SalaryTypeId NOT IN (1,2,4)  AND BranchId=@BranchId
UNION ALL
select EmpId , 0, 0 as HRent,0 as Conv , 0 as Other , amount as TotalSalary 
from HREmployeeDtls 
where valid = 1 and SalaryType = 'e' and UnitId=1 AND BranchId=1) aa , HREmployeeMaster bb
where aa.EmpId = bb.EmpId AND bb.BranchId=@BranchId
AND BB.DateOfJoining between @DOJFrom and @DOJTo 
AND (ISNULL(bb.DesigCode,'') + ISNULL(bb.DeptCode,'') + ISNULL(bb.EmpId,'') + ISNULL(bb.Grade,'')) LIKE '%'+ @DesigCode + '%' + @DeptCode + '%' + @EmpId + '%'+ @Scale
group by aa.EmpId ,bb.Name ,bb.DeptCode , bb.Department , bb.DesigCode , bb.Designation ,  bb.DateOfJoining ,
bb.EmpBankAccountNo , bb.WorkingStatus , bb.NID , bb.MobileNo , bb.userName,bb.EntryDateTime,bb.project, bb.IsGetHoliday, bb.Email, bb.BloodGroup, bb.ComBankAccountNo, bb.DateOfBirth, bb.Grade, bb.ShiftStatus, bb.UnitId, bb.BranchId
ORDER BY bb.DeptCode

GO
/****** Object:  StoredProcedure [dbo].[SP_HR_Report_SalarySheet]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
