GO
 

CREATE PROCEDURE [dbo].[SP_HR_Report_SalarySheet] (@Date nvarchar(50), @UnitId int, @BranchId int, @empCode VARCHAR(50), @deptCode VARCHAR(50), @desigCode VARCHAR(50), @scale VARCHAR(50) ) 
AS
DROP table tmp_Salary_Sheet /* EXEC SP_HR_Report_SalarySheet '2022-10-01', 1, 1,'','','','' */
BEGIN
DECLARE @cols AS NVARCHAR(MAX),
    @query  AS NVARCHAR(MAX),
	@Year as int,
	@MonthNo as int;
DECLARE @branch AS VARCHAR(2)
	SET @Year = YEAR(@Date);
	SET @MonthNo = MONTH(@Date);

IF @BranchId = 0 BEGIN SET @branch = '' END ELSE BEGIN SET @branch = @BranchId END;

SET @cols = STUFF((SELECT distinct ',' + QUOTENAME(c.SalaryFName) 
    FROM Payregister c
	WHERE c.AttYear = @Year AND c.AttMonth = @MonthNo AND c.UnitId=@UnitId AND c.BranchId LIKE '%'+@branch
    FOR XML PATH(''), TYPE
    ).value('.', 'NVARCHAR(MAX)') 
,1,1,'')

set @query = 'SELECT Code, ' + @cols + ' INTO tmp_Salary_Sheet from 
    (
        select Code, amount, SalaryFName from Payregister
	) x
    pivot 
    (
            max(amount)
        for SalaryFName in (' + @cols + ')
	) p'

execute(@query)
--SELECT *  FROM tmp_Salary_Sheet

SELECT b.Project, b.PaymentType, a.Code, b.Name, b.DateOfJoining, b.Department, b.Designation, b.Grade, c.Name AS BranchName, 
DAY(EOMONTH(CAST(@Year AS nvarchar(4))+'-'+CAST(@MonthNo AS nvarchar(2))+'-01')) AS TWorkingDays,
[Basic] AS Basic, [House Rent] AS HouseRent, [Conveyance] AS Conveyance,[Medical Allow] AS Medical,
([Mobile Allow]+[Over Time Allow]+[Salary Per Day]+ 
[Night Allowance]+[Meal Allow]+[Incentive / Pre Due]+[Area Allowance / Other Allow]) AS ExtraAllow,

[Revenue Stamp] , [Income Tax], ([L WP]+[Absent]+[Penalty  Deduction]+[Loan Deduction]+ 
[Advance Deduction]+[Transport]+[Meal Deduction]+[Others]) as OthersDeduction

FROM tmp_Salary_Sheet a, HREmployeeMaster b, tbl_BranchInfo c
WHERE a.Code = b.code and b.WorkingStatus IN ('Working') AND b.Valid = 1 AND b.BranchId = c.Id
AND b.DesigCode LIKE '%'+@desigCode+'%' AND b.DeptCode LIKE '%'+@deptCode+'%'
AND b.Code LIKE '%'+@empCode+'%' AND b.Grade LIKE '%'+@scale+'%' AND b.BranchId LIKE '%'+@branch 
ORDER BY [Basic] DESC
end


GO
/****** Object:  StoredProcedure [dbo].[SP_HR_Report_SalarySheetDetails]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE Procedure [dbo].[SP_HR_Report_SalarySheetDetails] (@DateFrom date,@DateTo date, @UnitId int, @BranchId int)
AS 
BEGIN
	select a.desigCode,a.DesignName,a.DeptCode,a.DeptName, a.Code,a.EmpName,1 as GPNo , SalaryTypeId,a.SalaryFName , a.Amount
	from Payregister a
	where a.Valid = 1 AND a.UnitId=@UnitId AND a.BranchId=@BranchId
	AND a.TRDate BETWEEN @DateFrom AND @DateTo
	and a.SalaryType='e'
	UNION ALL
	select a.desigCode,a.DesignName,a.DeptCode,a.DeptName, a.Code,a.EmpName,2 as GPNo , 88 as SalaryTypeId,'Total Earn' AS SalaryFName ,SUM(a.Amount) AS Amount
	from Payregister a
	where a.Valid = 1 AND a.UnitId=@UnitId AND a.BranchId=@BranchId
	AND a.TRDate BETWEEN @DateFrom AND @DateTo
	and a.SalaryType='e'
	GROUP BY a.desigCode,a.DesignName,a.DeptCode,a.DeptName, a.Code,a.EmpName
	UNION ALL
	select a.desigCode,a.DesignName,a.DeptCode,a.DeptName, a.Code,a.EmpName,5 as GPNo , SalaryTypeId,a.SalaryFName , a.Amount
	from Payregister a
	where a.Valid = 1 AND a.UnitId=@UnitId AND a.BranchId=@BranchId
	AND a.TRDate BETWEEN @DateFrom AND @DateTo
	and a.SalaryType='d'
	UNION ALL
	select a.desigCode,a.DesignName,a.DeptCode,a.DeptName, a.Code,a.EmpName,6 as GPNo , 99 as SalaryTypeId,'Total Deduction' AS SalaryFName ,SUM(a.Amount) AS Amount
	from Payregister a
	where a.Valid = 1 AND a.UnitId=@UnitId AND a.BranchId=@BranchId
	AND a.TRDate BETWEEN @DateFrom AND @DateTo
	and a.SalaryType='d'
	GROUP BY a.desigCode,a.DesignName,a.DeptCode,a.DeptName, a.Code,a.EmpName
	UNION ALL
	SELECT aa.desigCode,aa.DesignName,aa.DeptCode,aa.DeptName, aa.Code,aa.EmpName,10 as GPNo , 100 as SalaryTypeId,'Net Salary' AS SalaryFName ,SUM(aa.Amount) AS Amount
	FROM (
	select a.desigCode,a.DesignName,a.DeptCode,a.DeptName, a.Code,a.EmpName,2 as GPNo , 100 as SalaryTypeId,'Net Salary' AS SalaryFName ,SUM(a.Amount) AS Amount
	from Payregister a
	where a.Valid = 1 AND a.UnitId=@UnitId AND a.BranchId=@BranchId
	 AND a.TRDate BETWEEN @DateFrom AND @DateTo
	and a.SalaryType='e'
	GROUP BY a.desigCode,a.DesignName,a.DeptCode,a.DeptName, a.Code,a.EmpName
	UNION ALL
	select a.desigCode,a.DesignName,a.DeptCode,a.DeptName, a.Code,a.EmpName,6 as GPNo , 100 as SalaryTypeId,'Net Salary' AS SalaryFName ,SUM(a.Amount*(-1)) AS Amount
	from Payregister a
	where a.Valid = 1 AND a.UnitId=@UnitId AND a.BranchId=@BranchId
	AND a.TRDate BETWEEN @DateFrom AND @DateTo
	and a.SalaryType='d'
	GROUP BY a.desigCode,a.DesignName,a.DeptCode,a.DeptName, a.Code,a.EmpName) aa
	GROUP BY aa.desigCode,aa.DesignName,aa.DeptCode,aa.DeptName, aa.Code,aa.EmpName
	ORDER BY a.DeptCode,desigCode,Code
END




GO
