CREATE PROCEDURE [dbo].[SP_HR_Report_VerifyLeaveInfo] (@DateFrom Date,@DateTo Date, @DepartmentCode nvarchar(20),@DesignationCode nvarchar(20),@EmpCode nvarchar(20), @BranchId int) 
AS --- EXEC SP_HR_Report_VerifyLeaveInfo '2024-01-01','2024-12-31','','0193','',1
BEGIN
select a.TrNo, a.TrDate, a.EmpId, a.EmpCode, a.EmpName, b.Department, b.Designation, a.LeaveType, a.TotalDays, a.Note, a.Remarks, a.VerifyTime, a.VerifyBy
from EmpLeaveInfoMaster a
left join HREmployeeMaster b on a.EmpCode = b.Code
where a.Valid=1 AND a.BranchId=@BranchId AND a.Status = 4
AND a.TrDate between @DateFrom and @DateTo
AND ISNULL(b.DeptCode,'') LIKE '%'+@DepartmentCode+'%' AND  ISNULL(b.DesigCode,'') LIKE '%'+@DesignationCode+'%' AND ISNULL(a.EmpCode,'') LIKE '%'+@EmpCode+'%'
Group By a.TrNo, a.TrDate, a.EmpId, a.EmpCode, a.EmpName, b.Department, b.Designation, a.LeaveType, a.TotalDays, a.Note, a.Remarks, a.VerifyTime, a.VerifyBy
ORDER BY b.Department
END
