--27112025
create Proc [dbo].[SP_Hr_RosterReport] @BranchId Int, @StartDate DATE, @EndDate DATE, @Department varchar(150), @Designation Varchar(150), @EmpId Varchar(50)
As
Begin --   SP_Hr_RosterReport 1, '2025-01-01', '2025-01-31', '', '', '1312'
	Select Cast(DateAdd(Day, DateList.Number, @StartDate) As Date) As RosterDate
	Into #z
	From (
		select Top (DATEDIFF(day, @StartDate, @EndDate) +1) Row_Number() Over(Order by (Select Null))-1 As Number From sys.objects
	) As DateList

	select a.EmpId, a.Code, a.Name, a.MobileNo, a.Gender, a.DateOfBirth, a.Religion, a.DateOfJoining, a.Grade, a.Department,
	a.Designation, Isnull(c.GeneralShift, '-----') As GeneralShift, c.DayName, b.RosterDate, c.TimeFrom, c.TimeTo, d.ShortName
	from HREmployeeMaster a
	Cross Join #z b
	Left Join EmployeeRosterDetails c On a.BranchId=c.BranchId And a.EmpId=c.EmpId And b.RosterDate=c.RosterDate And c.Valid=1
	Left Join HRGroupInfo d On c.GeneralShift=d.ShiftName
	Where WorkingStatusId=1 And a.Valid=1 
	And Case When @BranchId = 0 Then 0 Else a.BranchId End = @BranchId
	And Case When @Department = '' Then '' Else a.Department End = @Department
	And Case When @Designation = '' Then '' Else a.Designation End = @Designation
	And Case When @EmpId = '' Then '' Else a.EmpId End = @EmpId
	Order by a.Code, b.RosterDate
End
GO
