CREATE PROC [dbo].[SP_HRAttendenceReport](@DateFrom date, @DateTo date, @BranchId varchar(10),@DeptCode nvarchar(15),@DesigCode nvarchar(15), @EmployeeCode nvarchar(50)) 
AS
Begin --EXEC SP_HRAttendenceReport '2022-06-01', '2022-06-30', 1, 1

SET ANSI_WARNINGS OFF;
Delete From tmp_HRAttendenceReport 

select EmployeeCode, convert(date, CardTime) Rosterdate, CONVERT(time,(MIN(CardTime))) AS InTime, CONVERT(time,(MAX(CardTime))) AS OutTime INTO #tmp_z from HR_CardTime 
WHERE Valid = 1 AND convert(date,CardTime) BETWEEN @DateFrom AND DATEADD(DAY, 1, @DateTo) AND EmployeeCode LIKE '%'+@EmployeeCode+'%' 
GROUP BY EmployeeCode, CONVERT(date,CardTime)

select a.EmpCode, a.InGraceTime AS  InGrace, -a.OutGraceTime AS OutGrace INTO #tmp_zz from HrGraceTime a
LEFT JOIN HREmployeeMaster b ON a.EmpCode = b.Code
WHERE a.Valid = 1 AND a.BranchId = @BranchId
AND b.DeptCode LIKE '%'+@DeptCode +'%'
AND b.DesigCode LIKE '%'+@DesigCode +'%'
AND b.Code LIKE '%'+@EmployeeCode+'%'  

--select * from #tmp_zz

INSERT INTO tmp_HRAttendenceReport(RosterDate,DayName, EmployeeCode, Name, DeptCode, DeptName, DesigCode, Designation,
ShiftStatus, ShiftTime, TimeFrom, TimeTo, InTime, OutTime, Remarks, UnitId,BranchId)

SELECT a.RosterDate, a.DayName, a.Code AS EmployeeCode, b.Name, b.DeptCode, b.Department AS DeptName, b.DesigCode, b.Designation,
a.ShiftStatus, a.GeneralShift as ShiftTime, DATEADD(minute, ISNULL(d.InGrace,19), a.TimeFrom) AS TimeFrom, DATEADD(minute, ISNULL(d.OutGrace,-19), a.TimeTo) AS TimeTo, 
ISNULL((CASE WHEN a.GeneralShift LIKE '%Night%' THEN (SELECT OutTime FROm #tmp_z WHERE EmployeeCode = a.Code AND RosterDate = a.RosterDate AND OutTime BETWEEN DATEADD(HOUR, -3, a.TimeFrom) AND '23:59:59.0000000') ELSE (SELECT InTime FROm #tmp_z WHERE EmployeeCode = a.Code AND RosterDate = a.RosterDate AND InTime BETWEEN DATEADD(HOUR, -3, a.TimeFrom) AND DATEADD(HOUR, 3, a.TimeFrom)) END),'') AS InTime, 

ISNULL((CASE WHEN a.GeneralShift LIKE '%Night%' THEN (SELECT InTime FROm #tmp_z WHERE EmployeeCode = a.Code AND RosterDate = DATEADD(DAY, 1, a.RosterDate) AND InTime BETWEEN DATEADD(HOUR, -3, a.TimeTo) AND DATEADD(HOUR, -1, a.TimeFrom)) ELSE (SELECT OutTime FROm #tmp_z WHERE EmployeeCode = a.Code AND RosterDate = a.RosterDate AND OutTime BETWEEN DATEADD(HOUR, -3, a.TimeTo) AND '23:59:59.0000000') END),'') AS OutTime,

--ISNULL((CASE WHEN a.GeneralShift LIKE '%Night%' THEN (SELECT InTime FROm #tmp_z WHERE EmployeeCode = a.Code AND RosterDate = DATEADD(DAY, 1, a.RosterDate)) ELSE (SELECT OutTime FROm #tmp_z WHERE EmployeeCode = a.Code AND RosterDate = a.RosterDate) END),'') AS OutTime,


'' AS Remarks, a.UnitId, a.BranchId
FROM EmployeeRosterDetails a 
LEFT JOIN HREmployeeMaster b ON a.Code = b.Code AND a.BranchId = b.BranchId
LEFT JOIN #tmp_z AS c ON a.Code = c.EmployeeCode AND a.RosterDate = c.Rosterdate
LEFT JOIN #tmp_zz AS d ON a.Code = d.EmpCode
WHERE a.BranchId LIKE (CASE WHEN @BranchId = 0 THEN CONVERT(varchar(10), '%%') ELSE CONVERT(varchar(10), '%'+@BranchId+'%')  END) 
AND a.Valid = 1 AND b.WorkingStatusId = 1 AND b.Valid = 1
AND a.RosterDate BETWEEN @DateFrom AND @DateTo
AND b.DeptCode LIKE '%'+@DeptCode +'%'
AND b.DesigCode LIKE '%'+@DesigCode +'%'
AND b.Code LIKE '%'+@EmployeeCode+'%' 
 
GROUP BY a.RosterDate, a.DayName, a.Code, b.Name, b.DeptCode, b.Department, b.DesigCode, b.Designation,
a.ShiftStatus, a.GeneralShift, a.TimeFrom, a.TimeTo, a.UnitId, a.BranchId, d.InGrace, d.OutGrace
ORDER BY a.RosterDate

UPdate tmp_HRAttendenceReport Set Remarks= 'Normal'
From tmp_HRAttendenceReport a
Where InTime <= a.TimeFrom AND OutTime >= a.TimeTo AND a.InTime != ''

UPdate tmp_HRAttendenceReport Set Remarks= Remarks+'LateIn'
From tmp_HRAttendenceReport a
Where a.InTime > TimeFrom OR a.InTime = ''

UPdate tmp_HRAttendenceReport Set Remarks= Remarks+ (case when Remarks = '' then  'EarlyOut' else '/EarlyOut' end)
From tmp_HRAttendenceReport a
Where a.TimeTo > a.OutTime

UPdate tmp_HRAttendenceReport Set Remarks= 'MissingOut'
From tmp_HRAttendenceReport a
Where a.InTime > '00:00' AND a.OutTime ='00:00'
--Where DATEADD(minute, 15, a.InTime) <= a.TimeFrom AND a.OutTime ='00:00'

UPdate tmp_HRAttendenceReport Set Remarks= 'Weekend', InTime='00:00', OutTime='00:00'
From tmp_HRAttendenceReport a
LEFT JOIN #tmp_zz b ON a.EmployeeCode = b.EmpCode
Where DATEADD(minute, ISNULL(-b.InGrace, -19), a.TimeFrom) = '' AND DATEADD(minute, ISNULL(-b.OutGrace, 19), a.TimeTo) = ''

--UPdate tmp_HRAttendenceReport Set Remarks= 'MissingIn'
--From tmp_HRAttendenceReport a
--Where a.InTime > '00:00' AND a.OutTime >= a.TimeTo

UPdate tmp_HRAttendenceReport Set Remarks= 'Absent'
From tmp_HRAttendenceReport a
LEFT JOIN #tmp_zz b ON a.EmployeeCode = b.EmpCode
Where DATEADD(minute, ISNULL(-b.InGrace,-19), a.TimeFrom) > '00:00' AND DATEADD(minute, ISNULL(-b.OutGrace,19), a.TimeTo) > '00:00'
AND a.InTime ='00:00' AND a.OutTime ='00:00'

UPdate tmp_HRAttendenceReport Set Remarks= 'Regular' where remarks = ''

UPDATE tmp_HRAttendenceReport SET Remarks = 'Regular' 
from HREmployeeMaster a 
LEFT JOIN tmp_HRAttendenceReport b ON a.BranchId = b.BranchId AND a.Code = b.EmployeeCode
where a.PermissionStatus = 1 AND (b.InTime != '00:00:00.0000000' OR b.OutTime != '00:00:00.0000000')


update tmp_HRAttendenceReport SET Remarks = 'Leave' 
FROM tmp_HRAttendenceReport a , EmpLeaveInfoDtls b
where a.RosterDate = b.LeaveFrom 
and a.EmployeeCode = b.empCode AND a.InTime ='00:00' AND a.OutTime ='00:00'

update tmp_HRAttendenceReport SET Remarks = 'GovHolyDay' 
FROM tmp_HRAttendenceReport a , hrgovtHoliday b
where a.RosterDate = b.Date  

UPDATE tmp_HRAttendenceReport set Remarks = 'Leave Without Pay' 
from tmp_HRAttendenceReport a
LEFT JOIN EmpLeaveInfoMaster b ON a.EmployeeCode = b.EmpCode 
LEFT JOIN EmpLeaveInfoDtls c ON b.TrNo = c.TrNo AND a.RosterDate = c.LeaveFrom
WHERE b.LeaveType = 'Without Pay Leave' AND c.LeaveFrom IS NOT NULL AND a.InTime ='00:00' AND a.OutTime ='00:00'


/*Start Working Status Update*/

/*Start Insert Working stataus in #namedan table*/
SELECT WorkingStatus, FromDate, EmpCode, ISNULL((LEAD(DATEADD(DAY, -1, FromDate), 1) OVER (PARTITION BY EmpCode ORDER BY EmpCode)),GETDATE()) as ToDate,
	ROW_NUMBER() OVER(PARTITION BY EmpCode ORDER BY EmpCode ASC) AS RowNo INTO #namedan
FROM EmpWorkingStatus
WHERE BranchId = @BranchId AND Valid = 1 AND FromDate BETWEEN @DateFrom AND @DateTo AND EmpCode LIKE '%'+@EmployeeCode+'%' 
/*END Insert Working stataus in #namedan table*/

--drop table #namedan
--select * from #namedan

/*Start Declare and set value*/
DECLARE @i INT = 1;
DECLARE @count INT = 0;
SELECT @count=  ROW_NUMBER() OVER(PARTITION BY EmpCode ORDER BY EmpCode ASC) FROM EmpWorkingStatus --WHERE EmpCode = '80203'
/*Start Declare and set value*/

/*Declare @tmp table*/
declare @tmp table(RosterDate date, WorkingStatus nvarchar(50), EmpCode varchar(10), WorkingStatusId int, BranchId int);

/*Start while condition*/
WHILE @i <= @count
	BEGIN  
		/*Start Insert Query for @tmp table*/
		INSERT INTO @tmp (RosterDate, WorkingStatus, EmpCode, WorkingStatusId, BranchId) 
		SELECT a.RosterDate, b.WorkingStatus, b.EmpCode, WorkingStatusId, b.EmpBranchId
		FROM tmp_HRAttendenceReport a, EmpWorkingStatus b
		WHERE a.EmployeeCode = b.EmpCode AND b.WorkingStatusId != 1
		AND a.RosterDate BETWEEN (select FromDate from #namedan WHERE EmpCode = b.EmpCode AND RowNo =@i) 
		AND (select ToDate from #namedan WHERE EmpCode = b.EmpCode AND RowNo =@i) 
		AND b.WorkingStatus = (select WorkingStatus from #namedan WHERE EmpCode = b.EmpCode AND RowNo =@i)
		GROUP BY a.RosterDate, b.WorkingStatus, b.EmpCode, WorkingStatusId, b.EmpBranchId
		ORDER BY RosterDate
		SET @i = @i + 1;
		/*End Insert Query for @tmp table*/
	END
/*END while condition*/

UPDATE tmp_HRAttendenceReport SET Remarks = b.WorkingStatus
from tmp_HRAttendenceReport a, @tmp b
WHERE a.EmployeeCode = b.EmpCode AND a.RosterDate = b.RosterDate and a.BranchId = b.BranchId
/*End Working Status Update*/

UPDATE tmp_HRAttendenceReport SET RemarksSMZ = cc.lcRemarks
FROM tmp_HRAttendenceReport bb ,
(select EmployeeCode,SUBSTRING((SELECT ', ' +Remarks+': '+CONVERT(nvarchar,COUNT(*))+' Days'
FROM tmp_HRAttendenceReport 
where EmployeeCode = a.EmployeeCode group by Remarks, EmployeeCode order by Remarks desc FOR XML PATH('')), 2 , 200) As lcRemarks
from tmp_HRAttendenceReport a
group by EmployeeCode,EmployeeCode) cc
WHERE bb.EmployeeCode = cc.EmployeeCode

------ To Add All Employee As Regular
------- To Create 7 days Roster 
--------insert into EmployeeGroupInfo (EmpId, ShiftStatus, DayName, GeneralShift, SecondShift, ThirdShift, row_Id, 
--------UserLogs, Valid, PNO, UnitId, BranchId, UserName, IPAddress, Code, DeptCode, DeptName)
--------SELECT a.EmpId , b.ShiftStatus, b.DayName, b.GeneralShift, b.SecondShift, b.ThirdShift, b.row_Id, 
--------b.UserLogs, 1, a.PNO, a.UnitId, a.BranchId, 'Auto', b.IPAddress, a.Code, a.DeptCode, a.Department 
--------FROM HREmployeeMaster a , EmployeeGroupInfo b
--------where a.Code NOT IN (SELECT Code FROM EmployeeGroupInfo)

-------- To Create Monthly Roster

--------INSERT INTO EmployeeRosterDetails (EmpId, ShiftStatus, DayName, GeneralShift, RosterDate, TimeFrom, TimeTo, row_Id, UserLogs, Valid, 
--------PNO, UnitId, BranchId, UserName, IPAddress, 
--------Code, DeptCode, DeptName, DesigCode, Designation)
