--------b.PNO, b.UnitId, b.BranchId, 'Auto', a.IPAddress, 
--------b.Code, b.DeptCode, b.Department, b.DesigCode, b.Designation
--------FROM EmployeeRosterDetails a , HREmployeeMaster b
--------where b.Valid = 1 and b.EmpId NOT IN (SELECT distinct empid from EmployeeRosterDetails)

----INSERT INTO HREmployeeDtls (Code, EmpId, SalaryType, SalaryTypeId, Amount, Valid, 
----UserName, PNo, IPAddress, LogDtls, UnitId, BranchId)
----SELECT b.Code, b.EmpId, a.SalaryType, a.SalaryTypeId, a.Amount, 1, 
----'Auto', b.PNo, a.IPAddress, 'Auto', b.UnitId, b.BranchId
----FROM HREmployeeDtls a , HREmployeeMaster b
----WHERE b.Code NOT IN (SELECT Code FROM HREmployeeDtls)




------SELECT aa.employeecode,aa.name,aa.deptcode,aa.deptname,aa.desigcode,aa.designation ,SUM(aa.WorkingDays-aa.HolyDay-aa.GovHolyday-aa.leave) as WorkingDays,
------SUM(aa.HolyDay) as HolyDay , SUM(aa.GovHolyday) as GovHolyday,SUM(aa.leave) as leave , SUM(aa.LateIn) as LateIn, 
------SUM(aa.EarlyOUt) as EarlyOut,SUM(aa.MissingOut) as MissingOut, SUM(aa.Absent) as Absent,SUM(aa.PayableDays) as PayableDays
------FROM (
------select employeecode,name,deptcode,deptname,desigcode,designation ,datediff(day,@DateFrom ,@DateTo)+1 as WorkingDays,
------0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent,0 as PayableDays
------from tmp_HRAttendenceReport
------GROUP BY employeecode,name,deptcode,deptname,desigcode,designation
------UNION ALL
------select employeecode,name,deptcode,deptname,desigcode,designation ,0 as WorkingDays,
------count(*) as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent,0 as PayableDays
------from tmp_HRAttendenceReport
------where remarks LIKE '%'+'Weekend'+'%' 
------GROUP BY employeecode,name,deptcode,deptname,desigcode,designation
------UNION ALL
------select employeecode,name,deptcode,deptname,desigcode,designation ,0 as WorkingDays,
------0 as HolyDay , Count(*) as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent,0 as PayableDays
------from tmp_HRAttendenceReport
------where remarks LIKE '%'+'GovHolyDay'+'%' 
------GROUP BY employeecode,name,deptcode,deptname,desigcode,designation
------UNION ALL
------select employeecode,name,deptcode,deptname,desigcode,designation ,0 as WorkingDays,
------0 as HolyDay , 0 as GovHolyday,COUNT(*) as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent,0 as PayableDays
------from tmp_HRAttendenceReport
------where remarks LIKE '%'+'Leave'+'%' 
------GROUP BY employeecode,name,deptcode,deptname,desigcode,designation
------UNION ALL
------select employeecode,name,deptcode,deptname,desigcode,designation ,0 as WorkingDays,
------0 as HolyDay , 0 as GovHolyday,0 as leave , COUNT(*) as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent,0 as PayableDays
------from tmp_HRAttendenceReport
------where remarks LIKE '%'+'LateIn'+'%' 
------GROUP BY employeecode,name,deptcode,deptname,desigcode,designation
------UNION ALL
------select employeecode,name,deptcode,deptname,desigcode,designation ,0 as WorkingDays,
------0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, count(*) as EarlyOUt, 0 as MissingOut, 0 as Absent,0 as PayableDays
------from tmp_HRAttendenceReport
------where remarks LIKE '%'+'EarlyOut'+'%' 
------GROUP BY employeecode,name,deptcode,deptname,desigcode,designation
------UNION ALL
------select employeecode,name,deptcode,deptname,desigcode,designation ,0 as WorkingDays,
------0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, Count(*) as MissingOut, 0 as Absent,0 as PayableDays
------from tmp_HRAttendenceReport
------where remarks LIKE '%'+'MissingOut'+'%' 
------GROUP BY employeecode,name,deptcode,deptname,desigcode,designation
------UNION ALL
------select employeecode,name,deptcode,deptname,desigcode,designation ,0 as WorkingDays,
------0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, Count(*) as Absent,0 as PayableDays
------from tmp_HRAttendenceReport
------where remarks LIKE '%'+'Absent'+'%' 
------GROUP BY employeecode,name,deptcode,deptname,desigcode,designation) aa
------GROUP BY aa.employeecode,aa.name,aa.deptcode,aa.deptname,aa.desigcode,aa.designation

select * from tmp_HRAttendenceReport  ORDER BY EmployeeCode, RosterDate 

End
