CREATE PROC [dbo].[SP_HRAttendenceReport_SMZ](@DateFrom date, @DateTo date, @BranchId varchar(10),@DeptCode nvarchar(15),@DesigCode nvarchar(15), @EmployeeCode nvarchar(50)) 
AS
Begin --EXEC SP_HRAttendenceReport_SMZ '2022-08-01','2022-08-30',1,6,'','',''

SET ANSI_WARNINGS OFF;
Delete From tmp_HRAttendenceReport 
DROP TABLE tmp_HRAttendenceReportSMZ

--drop table tmp_HRAttendenceReport
