--WHERE a.RosterDate BETWEEN '2022-04-01' AND '2022-04-30'
--GROUP BY a.RosterDate, a.DayName, a.Code, b.Name, b.DeptCode, a.DeptName, b.DesigCode, b.Designation, a.ShiftStatus, a.GeneralShift,
--a.TimeFrom, a.TimeTo, convert(date,CardTime), a.BranchId, a.UnitId
--ORDER BY a.Code, a.RosterDate

--INSERT INTO tmp_HRAttendenceReport(RosterDate,DayName, EmployeeCode, Name, DeptCode, DeptName, DesigCode, Designation,
--ShiftStatus, ShiftTime, TimeFrom, TimeTo, InTime, OutTime, Remarks, UnitId,BranchId)
--select a.RosterDate, a.DayName, a.Code AS EmployeeCode, b.Name, b.DeptCode, a.DeptName, b.DesigCode, b.Designation,
--a.ShiftStatus, a.GeneralShift as ShiftTime, a.TimeFrom, a.TimeTo,
--ISNULL((CASE WHEN a.GeneralShift NOT LIKE '%Night%' 
--THEN (SELECT DISTINCT FORMAT(MIN(CardTime), 'hh:mm tt') FROM HWATT.dbo.KQZ_Card WHERE EmployeeID = d.EmployeeID AND CONVERT(date, CardTime) = CONVERT(DATE, d.CardTime) AND CONVERT(time, CardTime) Between dateadd(HOUR, -3, a.TimeFrom) AND Dateadd(HOUR, 3, a.TimeFrom)) 
--ELSE (SELECT FORMAT(MAX(CardTime), 'hh:mm tt') FROM HWATT.dbo.KQZ_Card WHERE EmployeeID = d.EmployeeID AND CONVERT(date, CardTime+1) = CONVERT(DATE, d.CardTime) AND CONVERT(time, CardTime) Between dateadd(HOUR, -3, a.TimeFrom) AND Dateadd(HOUR, 3, a.TimeFrom)) END),'') as InTime, 

--ISNULL((CASE WHEN a.GeneralShift NOT LIKE '%Night%' 
--THEN (SELECT DISTINCT FORMAT(MAX(CardTime), 'hh:mm tt') FROM HWATT.dbo.KQZ_Card WHERE EmployeeID = d.EmployeeID AND CONVERT(date, CardTime) = CONVERT(DATE, d.CardTime) AND CONVERT(time, CardTime) Between dateadd(HOUR, -3, a.TimeTo) AND Dateadd(HOUR, 3, a.TimeTo)) 
--ELSE (SELECT DISTINCT FORMAT(MIN(CardTime), 'hh:mm tt') FROM HWATT.dbo.KQZ_Card WHERE EmployeeID = d.EmployeeID AND CONVERT(date, CardTime) = CONVERT(DATE, d.CardTime) AND CONVERT(time, CardTime) Between dateadd(HOUR, -3, a.TimeTo) AND Dateadd(HOUR, 3, a.TimeTo)) 
--END),'') AS OutTime,'' AS Remarks, a.UnitId, a.BranchId
--from EmployeeRosterDetails a
--LEFT JOIN HREmployeeMaster b ON a.Code = b.Code AND a.BranchId = b.BranchId
--LEFT JOIN HWATT.dbo.KQZ_Employee c ON b.Code = c.EmployeeCode
