SELECT aa.employeecode,aa.name,aa.deptcode,aa.deptname,aa.desigcode,aa.designation, aa.Branch, SUM(aa.WorkingDays-aa.HolyDay-aa.GovHolyday-aa.leave) as WorkingDays, 
SUM(aa.HolyDay) as HolyDay , SUM(aa.GovHolyday) as GovHolyday,SUM(aa.leave) as leave , SUM(aa.LateIn) as LateIn, SUM(aa.EarlyOUt) as EarlyOut, SUM(aa.MissingOut) as MissingOut, 
SUM(aa.Absent) as Absent, sum(aa.LeaveWithoutPay) AS LeaveWithoutPay, 
(CASE WHEN aa.DeptName = 'Nursing' THEN DAY(EOMONTH(@DateFrom)) ELSE SUM(aa.WorkingDays-aa.Absent-aa.LeaveWithoutPay-floor(aa.LateIn/3)) END) as PayableDays, 
SUM(aa.CasualLeave) as CasualLeave, SUM(aa.EarnLeave) as EarnLeave, SUM(aa.SickLeave) as SickLeave, SUM(aa.MaternityLeave) as MaternityLeave
INTO tmp_HRAttendenceReportSMZ
FROM (
	select a.employeecode, a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name AS Branch,datediff(day, @DateFrom, @DateTo)+1 as WorkingDays,
	0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent, 0 as LeaveWithoutPay, 0 as CasualLeave, 0 as EarnLeave, 
	0 as SickLeave, 0 as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id
	GROUP BY a.employeecode, a.name, a.deptcode, a.deptname, a.desigcode, a.designation, b.Name
	UNION ALL
	select a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name ,0 as WorkingDays,
	count(*) as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent,0 as LeaveWithoutPay, 0 as CasualLeave, 0 as EarnLeave, 
	0 as SickLeave, 0 as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id AND a.remarks LIKE '%'+'Weekend'+'%' 
	GROUP BY a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name
	UNION ALL
	select a.employeecode, a.name, a.deptcode,a.deptname,a.desigcode,a.designation, b.Name, 0 as WorkingDays,
	0 as HolyDay , Count(*) as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent,0 as LeaveWithoutPay, 0 as CasualLeave, 0 as EarnLeave, 
	0 as SickLeave, 0 as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id AND remarks LIKE '%'+'GovHolyDay'+'%' 
	GROUP BY a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name
	UNION ALL
	select a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name ,0 as WorkingDays,
	0 as HolyDay , 0 as GovHolyday,COUNT(*) as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent,0 as LeaveWithoutPay, 0 as CasualLeave, 0 as EarnLeave, 
	0 as SickLeave, 0 as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id AND remarks LIKE '%'+'Leave'+'%' 
	GROUP BY a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name
	UNION ALL
	select a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name ,0 as WorkingDays,
	0 as HolyDay , 0 as GovHolyday,0 as leave , COUNT(*) as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent,0 as LeaveWithoutPay, 0 as CasualLeave, 0 as EarnLeave, 
	0 as SickLeave, 0 as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id AND remarks LIKE '%'+'LateIn'+'%' 
	GROUP BY a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name
	UNION ALL
	select a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name,0 as WorkingDays,
	0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, count(*) as EarlyOUt, 0 as MissingOut, 0 as Absent,0 as LeaveWithoutPay, 0 as CasualLeave, 0 as EarnLeave, 
	0 as SickLeave, 0 as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id AND remarks LIKE '%'+'EarlyOut'+'%' 
	GROUP BY a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name
	UNION ALL
	select a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name,0 as WorkingDays,
	0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, Count(*) as MissingOut, 0 as Absent,0 as LeaveWithoutPay, 0 as CasualLeave, 0 as EarnLeave, 
	0 as SickLeave, 0 as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id AND remarks LIKE '%'+'MissingOut'+'%' 
	GROUP BY a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name
	UNION ALL
	select a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name,0 as WorkingDays,
	0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, Count(*) as Absent,0 as LeaveWithoutPay, 0 as CasualLeave, 0 as EarnLeave, 
	0 as SickLeave, 0 as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id AND remarks LIKE '%'+'Absent'+'%' 
	GROUP BY a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name
	UNION ALL
	select a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name,0 as WorkingDays,
	0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent, Count(*) as LeaveWithoutPay, 0 as CasualLeave, 0 as EarnLeave, 
	0 as SickLeave, 0 as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id AND remarks LIKE '%'+'Leave Without Pay'+'%' 
	GROUP BY a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name
	UNION ALL
	select a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name,0 as WorkingDays,
	0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent, 0 as LeaveWithoutPay, Count(*) as CasualLeave, 0 as EarnLeave, 
	0 as SickLeave, 0 as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id AND remarks LIKE '%'+'Casual Leave'+'%' 
	GROUP BY a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name
	UNION ALL
	select a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name,0 as WorkingDays,
	0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent, 0 as LeaveWithoutPay, 0 as CasualLeave,  Count(*) as EarnLeave, 
	0 as SickLeave, 0 as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id AND remarks LIKE '%'+'Earn Leave'+'%' 
	GROUP BY a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name
	UNION ALL
	select a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name,0 as WorkingDays,
	0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent, 0 as LeaveWithoutPay, 0 as CasualLeave, 0 as EarnLeave,  
	Count(*) as SickLeave, 0 as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id AND remarks IN ('Sick Leave', 'Station Leave', 'Study Leave')
	GROUP BY a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name
	UNION ALL
	select a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name,0 as WorkingDays,
	0 as HolyDay , 0 as GovHolyday,0 as leave , 0 as LateIn, 0 as EarlyOUt, 0 as MissingOut, 0 as Absent, 0 as LeaveWithoutPay, 0 as CasualLeave,  0 as EarnLeave, 
	0 as SickLeave, Count(*) as MaternityLeave
	from tmp_HRAttendenceReport a, tbl_BranchInfo b
	WHERE a.BranchId = b.Id AND remarks LIKE '%'+'Maternity Leave'+'%' 
	GROUP BY a.employeecode,a.name,a.deptcode,a.deptname,a.desigcode,a.designation, b.Name
) aa
GROUP BY aa.employeecode,aa.name,aa.deptcode,aa.deptname,aa.desigcode,aa.designation, aa.Branch

select * from tmp_HRAttendenceReportSMZ

End
