CREATE PROC [dbo].[SP_HREmpFamilyMemberSetup] @Code nvarchar(50)
AS
-- EXEC SP_HREmpFamilyMemberSetup '21003'
BEGIN	 
	SELECT a.Code, a.EmpId, a.Name,a.Department, a.Designation, a.MobileNo, a.Gender, a.DateOfJoining, a.EmpImage, b.FamilyMemberName, b.Relation, b.DoB, b.Age, b.Sex, b.BGName,
	b.Contact, b.MairtalStatus, b.Remarks, b.PatientImage 
	FROM HREmployeeMaster a 
	INNER JOIN EmpRelativesInfo b ON a.Code = b.EmployeeCode AND a.Valid = b.Valid AND a.BranchId = b.BranchId
	WHERE b.Valid = 1 AND a.Code = @Code	
END
