Create proc [dbo].[SP_HrEmpInformation] @BranchId int, @EmpId nvarchar(50)
as 
begin
select em.EmpId, em.Code, em.Name , em.NID ,em.MobileNo, em.District, em.Gender, em.DateOfBirth, em.PresentAddress, em.PermanentAddress, em.Nationality,em.TAXNumber, em.ProtithanikCode,em.JibonBimaNumber, em.Tahabil,  em.Religion, em.DateOfJoining, em.WorkingStatus, em.Designation, em.Department, em.BloodGroup, ISNULL( em.UserName ,'') as UserName, em.passportNo, em.BMDCRegNo, em.EmergencyContact, em.PresentStatus, ad.MaritalStatus, ad.ExtraCurricularActivities, ad.ComputerSkills, ad.OtherSkills, ad.AccommodationType, ad.LivingWith,ad.MembershipDetails from HREmployeeMaster em left join tbl_Hr_AdditionalInformation ad on em.EmpId=ad.EmpId and em.BranchId=ad.BranchId WHERE em.EmpId = @empId AND em.BranchId = @branchId
end
