CREATE PROC [dbo].[SP_HrEmployeeInfo] @branchId int, @empId VARCHAR(50)
AS
SELECT zz.EmpId, zz.Code, zz.Name, zz.NID, zz.MobileNo, zz.Email, zz.District, zz.Gender, zz.DateOfBirth, zz.PresentAddress, zz.PermanentAddress, zz.Nationality, zz.TAXNumber, zz.ProtithanikCode, zz.JibonBimaNumber, zz.Tahabil, zz.Religion, zz.DateOfJoining, zz.DateOfConfirmation, zz.WorkingStatus, zz.Project, zz.Grade, zz.DeptCode, zz.Department, zz.DesigCode, zz.Designation, zz.EmpBankAccountNo, zz.EmpBankName, zz.EmpBankBrName, zz.PaymentType, zz.PaymentAmtCash, zz.PaymentAmtBank, zz.ComBankAccountNo, zz.ComBankBrName, zz.ComBankName, zz.ShiftStatus, ISNULL(zz.EmpCardNo,'') AS EmpCardNo, zz.IsGetHoliday, zz.BloodGroup, ISNULL(zz.UserName,'') AS UserName, zz.PrimarySalary, aa.BranchId, aa.RowNo, aa.AddType, aa.AddAmt, bb.DeductType, bb.DeductAmt FROM (
(
SELECT ROW_NUMBER() OVER(partition by m.EmpId order by m.EmpId) AS RowNo, m.BranchId, m.EmpId, n.SalaryName AS AddType, m.Amount AS AddAmt FROM HREmployeeDtls m
LEFT JOIN HRSalaryType n ON m.SalaryTypeId = n.SlNo and n.Validity = 1
WHERE m.Valid = 1 AND m.SalaryType = 'e') aa
LEFT JOIN
(SELECT ROW_NUMBER() OVER(partition by m.EmpId order by m.EmpId) AS RowNo, m.BranchId, m.EmpId, n.SalaryName AS DeductType, m.Amount AS DeductAmt FROM HREmployeeDtls m
LEFT JOIN HRSalaryType n ON m.SalaryTypeId = n.SlNo and n.Validity = 1
WHERE m.Valid = 1 AND m.SalaryType = 'd'
) bb ON aa.RowNo = bb.RowNo AND aa.EmpId = bb.EmpId
LEFT JOIN HREmployeeMaster zz ON zz.BranchId = aa.BranchId ANd zz.EmpId = aa.EmpId
)
WHERE aa.EmpId = @empId AND zz.BranchId = @branchId


