AS --- EXEC SP_HrEmployeeProfile 1, '0292'
BEGIN
SELECT zz.EmpId, zz.Code, zz.Name, zz.NID, zz.MobileNo, zz.Email, zz.District, zz.Gender, zz.DateOfBirth, zz.PresentAddress, zz.PermanentAddress, zz.Nationality, (zz.TAXNumber) AS TINNo, (zz.Tahabil) AS TreasuryNo, zz.Religion, zz.DateOfJoining, zz.DateOfConfirmation, zz.WorkingStatus, zz.Grade, zz.DeptCode, zz.Department, zz.DesigCode, zz.Designation, zz.FathersName, zz.MothersName, zz.Emergencycontact, zz.Passportno, zz.Fileno, zz.PermissionStatus, zz.EmpImage, zz.Signature,   zz.EmpBankAccountNo, zz.EmpBankName, zz.EmpBankBrName, zz.PaymentType, zz.BloodGroup, ISNULL(zz.UserName,'') AS UserName, zz.PrimarySalary, zz.DeductedSalary, zz.GrossSalary, ISNULL(cc.NameOfExam,'') as NameOfExam, ISNULL(cc.RollNo,'') as RollNo, ISNULL(cc.Board,'') as Board, ISNULL(cc.InstituteName,'') as InstituteName, ISNULL(cc.PassingYear,'') as PassingYear, ISNULL(cc.GPA,'') as GPA
FROM HREmployeeMaster zz
