CREATE PROC [dbo].[Sp_HrInOutRpt] @BranchId INT, @dateFrom DATE, @dateTo DATE, @empId VARCHAR(50), @DeptCode NVARCHAR(50), @DesigCode VARCHAR(50)
AS
BEGIN /* EXEC Sp_HrInOutRpt 1, '2023-07-01', '2023-07-31', '', '4', '' */

select a.EmpId, a.Code, a.Name, a.Department, a.Designation, a.MobileNo,
convert(date,b.CardTime) as Rosterdate, FORMAT(MIN(b.cardtime),'hh:mm tt') AS InTime, FORMAT(MAX(b.cardtime),'hh:mm tt') AS OutTime
INTO #Z
from HREmployeeMaster a
Left join HR_CardTime b ON a.Code = b.EmployeeCode and b.Valid=1
Where a.Valid=1 AND a.BranchId = @BranchId AND convert(date,b.CardTime) Between @dateFrom AND @dateTo
AND EmpId LIKE '%'+@empId+'%'
AND 
(
	(CASE WHEN @DeptCode != '' THEN DeptCode END = @DeptCode) OR (CASE WHEN @DeptCode = '' THEN DeptCode END LIKE '%'+@DeptCode+'%')
)
AND 
(
	(CASE WHEN @DesigCode != '' THEN DesigCode END = @DesigCode) OR (CASE WHEN @DesigCode = '' THEN DesigCode END LIKE '%'+@DesigCode+'%')
)

Group By a.EmpId, a.Code, a.Name, a.Department, a.Designation, a.MobileNo,convert(date,b.CardTime)

SELECT EmpId , Code , name,Department ,Designation , MobileNo , Rosterdate ,
1 as SlNo, 'IN TIME' as INOutStatus , InTime AS INOutTime 
FROM #Z
UNION ALL
SELECT EmpId , Code , name,Department ,Designation , MobileNo , Rosterdate ,
2 as SlNo, 'OUT TIME' as INOutStatus , OutTime AS INOutTime 
FROM #Z
ORDER BY EmpId, code, Rosterdate

END 
GO
