CREATE PROC [dbo].[SP_HRReplaceGrossSalary](@EmpCode nvarchar(50), @PrimarySalary float, @DeductedSalary float, @AfterIncrement float, @UpdatedBy nvarchar(250))
AS

 
UPDATE HREmployeeMaster SET PrimarySalary =@PrimarySalary, DeductedSalary=@DeductedSalary, GrossSalary=@AfterIncrement, LogDtls=@UpdatedBy,
PaymentAmtBank=@AfterIncrement 
WHERE Valid=1 AND Code=@EmpCode AND PaymentType='Bank'


UPDATE HREmployeeMaster SET PrimarySalary =@PrimarySalary, DeductedSalary=@DeductedSalary, GrossSalary=@AfterIncrement, LogDtls=@UpdatedBy,
PaymentAmtCash=@AfterIncrement 
WHERE Valid=1 AND Code=@EmpCode AND PaymentType='Cash'


