CREATE PROC [dbo].[SP_HRReplaceIncrement](@EmpCode nvarchar(50), @BasicSalary float,  @HouseRent float, @Conveyance float, @Medical float, @UpdatedBy nvarchar(250))
AS

UPDATE HREmployeeDtls SET Amount=@BasicSalary, LogDtls=@UpdatedBy 
FROM HREmployeeDtls a, HRSalaryType b
WHERE a.Valid=1 AND a.SalaryType = b.SalaryType AND a.SalaryTypeId=b.SlNo and b.Validity=1 and b.ShowInBasic=1
AND a.Code=@EmpCode AND a.SalaryTypeId=1 AND b.SalaryName='Allow Basic'

UPDATE HREmployeeDtls SET Amount=@HouseRent, LogDtls=@UpdatedBy 
FROM HREmployeeDtls a, HRSalaryType b
WHERE a.Valid=1 AND a.SalaryType = b.SalaryType AND a.SalaryTypeId=b.SlNo and b.Validity=1 and b.ShowInBasic=1
AND a.Code=@EmpCode AND a.SalaryTypeId=2 AND b.SalaryName='Allow House Rent'

UPDATE HREmployeeDtls SET Amount=@Medical, LogDtls=@UpdatedBy 
FROM HREmployeeDtls a, HRSalaryType b
WHERE a.Valid=1 AND a.SalaryType = b.SalaryType AND a.SalaryTypeId=b.SlNo and b.Validity=1 and b.ShowInBasic=1
AND a.Code=@EmpCode AND a.SalaryTypeId=3 AND b.SalaryName='Allow Medical'

UPDATE HREmployeeDtls SET Amount=@Conveyance, LogDtls=@UpdatedBy 
FROM HREmployeeDtls a, HRSalaryType b
WHERE a.Valid=1 AND a.SalaryType = b.SalaryType AND a.SalaryTypeId=b.SlNo and b.Validity=1 and b.ShowInBasic=1
AND a.Code=@EmpCode AND a.SalaryTypeId=4 AND b.SalaryName='Allow Conveyance'


GO
