CREATE PROC [dbo].[SP_HRRestLeave] @BranchId INT, @EmpId varchar(20)
as
begin -- exec SP_HRRestLeave 1, '0449'
	select sum(aa.TotalLeaveDays - aa.TotalDays) as RestLeave, sum(aa.CasualLeave - aa.tCasualLeave) as RestCL, sum(aa.EarnLeave -aa.tEarnLeave) as RestEL 
	from(
		select sum(totaldays) as TotalLeaveDays, 0 as CasualLeave, 0 as  tCasualLeave,0 as EarnLeave, 0 as tEarnLeave, 0 as TotalDays 
		from LeaveType 
		union all 
		select 0 as TotalLeaveDays, sum(totaldays) as CasualLeave, 0 as  tCasualLeave, 0 as EarnLeave, 0 as tEarnLeave, 0 as TotalDays 
		from LeaveType 
		where Name = 'Casual Leave' 
		union all 
		select  0 as TotalLeaveDays, 0 as CasualLeave, count(*) as tCasualLeave ,0 as EarnLeave, 0 as tEarnLeave, 0 as TotalDays 
		from EmpLeaveInfoMaster a 
		left join EmpLeaveInfoDtls b on b.TrNo = a.TrNo and b.Valid = 1 and a.EmpCode = b.EmpCode
		where a.BranchId = @BranchId and a.EmpId = @EmpId and a.LeaveType = 'Casual Leave' and a.valid = 1 and YEAR(GETDATE())=YEAR(b.LeaveFrom) AND Status = '2' 
		union all 
		select 0 as TotalLeaveDays, 0 as CasualLeave, 0 as  tCasualLeave, sum(totaldays) as EarnLeave, 0 as tEarnLeave, 0 as TotalDays 
		from LeaveType where Name = 'Earn Leave' 
		union all 
		select  0 as TotalLeaveDays, 0 as CasualLeave, 0 as tCasualLeave ,0 as EarnLeave, count(*) as tEarnLeave, 0 as TotalDays 
		from EmpLeaveInfoMaster a 
		left join EmpLeaveInfoDtls b on b.TrNo = a.TrNo and b.Valid = 1 and a.EmpCode = b.EmpCode
		where a.BranchId = @BranchId and a.EmpId = @EmpId and a.LeaveType = 'Earn Leave' and a.valid = 1 and YEAR(GETDATE())=YEAR(b.LeaveFrom) AND Status = '2' 
		union all 
		select  0 as TotalLeaveDays, 0 as CasualLeave, 0 as tCasualLeave ,0 as EarnLeave, 0 as tEarnLeave, count(*) as TotalDays 
		from EmpLeaveInfoMaster a 
		left join EmpLeaveInfoDtls b on b.TrNo = a.TrNo and b.Valid = 1 and a.EmpCode = b.EmpCode
		where a.BranchId = @BranchId and a.EmpId = @EmpId and a.valid = 1 and YEAR(GETDATE())=YEAR(b.LeaveFrom) AND Status = '2' and a.LeaveType in ('Casual Leave', 'Earn Leave', 'Sick Leave')
	) aa
END


GO
