CREATE PROC [dbo].[SP_HrRosterReportDetailsDeptwise] @BranchId INT, @DeptCode VARCHAR(50), @DesigCode VARCHAR(50), @DateFrom DATE, @DateTo DATE
AS
BEGIn -- SP_HrRosterReportDetailsDeptwise 1, '3', '', '2024-07-01', '2024-07-10'
	SELECT a.EmpId, a.Code, Name, a.NID, a.MobileNo, a.Gender, DeptName, a.Designation, b.RosterDate, b.DayName, b.GeneralShift, b.TimeFrom, b.TimeTo
