CREATE PROC [dbo].[SP_HrRosterReportDetailsDeptwiseNew] @BranchId INT, @DeptCode VARCHAR(50), @DesigCode VARCHAR(50), @DateFrom DATE, @DateTo DATE
AS
BEGIn -- SP_HrRosterReportDetailsDeptwiseNew 1, '', '', '2025-04-01', '2025-05-21'
	SELECT a.EmpId, a.Code, Name, a.NID, a.MobileNo, a.Gender, DeptName, a.Designation, b.RosterDate, 
	b.DayName, b.GeneralShift, b.TimeFrom, b.TimeTo,a.DeptCode, a.DesigCode
	INTO #z
	FROM HREmployeeMaster a
	INNER JOIN EmployeeRosterDetails b oN b.BranchId = a.BranchId AND b.EmpId = a.EmpId AND b.Valid = 1
	WHERE a.BranchId = @BranchId AND b.RosterDate BETWEEN @DateFrom AND @DateTo AND a.WorkingStatusId = 1
	AND (CASE WHEN @DeptCode = '' THEN '' ELSE a.DeptCode END) = @deptCode 
	AND (CASE WHEN @DesigCode = '' THEN '' ELSE a.DesigCode END) = @DesigCode
	--ORDER BY a.DeptCode, a.DesigCode

	ALTER TABLE #z ADD ShortName NVARCHAR(150),ShiftList NVARCHAR(350)

	ALTER TABLE #z ALTER COLUMN ShortName VARCHAR(100) COLLATE SQL_Latin1_General_CP1_CI_AS


	UPDATE #z SET ShortName=b.ShortName
	FROM #z a,HRGroupInfo  b
	WHERE a.GeneralShift=b.ShiftName

	declare @ShiftList NVARCHAR(350)
	
	SELECT @ShiftList=ISNULL(SUBSTRING((SELECT DISTINCT GeneralShift+'='+ShortName +SPACE(10)
		From #z FOR XML PATH('')), 1 , 1000),'') 
	from #z a

	update #z SET ShiftList=@ShiftList

	select * from #z ORDER BY DeptCode, DesigCode
END
