CREATE Procedure [dbo].[SP_ICUDischargeCertificate] @branchId int, @dischargeNo nvarchar(20), @dischargedate varchar(20)
AS -- EXEC SP_ICUDischargeCertificate 1, 'IDC241200005', '2024-12-10'
BEGIN
SELECT a.DischargeType,a.DischargeNo,a.DischargeDate,a.DischargeTime,a.PatientId,a.PatientName,a.Age,a.BedNo,a.Address,a.BloodGroup,
a.Admission,a.Transfer,a.PresentingComplain,a.FinalDiagnosis,a.PresentIllness,a.HoldDRUG,a.Note,a.UserName,a.EntryDateTime,
Consultant.ConsultantList,Medicine.MedicineList,
( SELECT STUFF((SELECT CHAR(10) + b.InvestigationName + ' : ' + b.Result FROM BedSideInvestigation b
WHERE b.DischargeNo = a.DischargeNo AND b.PatientId = a.PatientId AND b.Valid = 1
FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, '')) AS BedSideInvestigations,
(SELECT STUFF((SELECT CHAR(10) + c.InvestigationName + ' : ' + c.Result FROM FirstDayInvestigation c
WHERE c.DischargeNo = a.DischargeNo AND c.PatientId = a.PatientId AND c.Valid = 1
FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, '')) AS FirstDayInvestigations,
(SELECT STUFF((SELECT CHAR(10) + d.ExaminationName + ' : ' + d.Result FROM ExaminationDuringAdmission d
WHERE d.DischargeNo = a.DischargeNo AND d.PatientId = a.PatientId AND d.Valid = 1
FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, '')) AS ExaminationResults,
(SELECT STUFF((SELECT CHAR(10) + e.ClinicalParamName + ' : ' + e.Result FROM ClinicalParameters e
WHERE e.DischargeNo = a.DischargeNo AND e.PatientId = a.PatientId AND e.Valid = 1
FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, '')) AS ClinicalParameters
FROM ICUDischargeCertificateHistory a
CROSS APPLY    
(SELECT STUFF((SELECT CHAR(10) + c.DrName FROM ICUDischargeConsultantDetails AS c   
WHERE c.DischargeNo = a.DischargeNo AND c.PatientId = a.PatientId AND c.Valid = 1   
FOR XML PATH('')), 1, 0, '')) AS Consultant (ConsultantList)
CROSS APPLY    
(SELECT STUFF((SELECT CHAR(10) + m.MedicineName + ', ' + m.DoseInfo + ', ' + m.Days 
FROM ICUPatientDischargeTreatment AS m   
WHERE m.DischargeNo = a.DischargeNo AND m.PatientId = a.PatientId AND m.Valid = 1   
FOR XML PATH('')), 1, 1, '')) AS Medicine (MedicineList)
WHERE Valid=1 AND BranchId=@branchId AND DischargeNo=@dischargeNo AND DischargeDate=@dischargedate
END
GO
/****** Object:  StoredProcedure [dbo].[SP_ImagingDoctorLedgerReport]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
--09092025 Add @PaymentStatus Parameter which one use for Due/Paid Condition
CREATE Procedure [dbo].[SP_ImagingDoctorLedgerReport] @BranchId int, @DateFrom date, @DateTo date, @DeptName nvarchar(20), @DrCode nvarchar(20), @PtStatus nvarchar(30), @PaymentStatus Varchar(20)
AS  ---  Exec SP_ImagingDoctorLedgerReport 1, '2026-01-18', '2026-01-18' , 'H019', '', '', 'Paid'

BEGIN
	BEGIN TRY
		BEGIN TRANSACTION;

		--drop table #DueCollLess and LessAdjust
		SELECT a.PrevInvNo AS InvNo, a.PaidDate, SUM(CASE WHEN a.CRType='Sales' THEN 0 ELSE a.Less END) AS DueCollLess, SUM(a.ReturnLess) AS LessAdjust,
		SUM(Sales-Less-Collection-ReturnDue-AdjustAmt) AS Due 
		INTO #lessDueCollRtn
		FROM SalesLedger a
		WHERE a.BranchId=@BranchId AND a.Valid=1 AND a.PaidDate BETWEEN @DateFrom AND @DateTo
		GROUP BY a.BranchId, a.PrevInvNo, a.PaidDate

		--DROP TABle #sales for DueCollLess/LessAdjust ratio
		SELECT InvNo, SUM(TotalAmount) AS TotalSales
		INTO #sales
		FROM InvDetails a 
		INNER JOIN ClinicalChart c on a.BranchId=c.BranchId AND a.PCode=c.PCode AND c.CanGiveLess=1
		WHERE a.BranchId=@BranchId AND a.Valid=1 AND a.PaidDate BETWEEN @DateFrom AND @DateTo
		GROUP BY a.InvNo
		HAVING SUM(TotalAmount) > 0

		--drop table #salesPcode for DueCollLess/LessAdjust ratio
		SELECT InvNo, a.PCode, a.GLessAmt, TotalAmount AS Charge
		INTO #salesPcode
		FROM InvDetails a 
		INNER JOIN ClinicalChart c on a.BranchId=c.BranchId AND a.PCode=c.PCode AND c.CanGiveLess=1
		WHERE a.BranchId=@BranchId AND a.Valid=1 AND a.PaidDate BETWEEN @DateFrom AND @DateTo

		--drop table #chargeForPayable

		SELECT a.InvNo, PCode, b.Due, ((c.GLessAmt+ISNULL(((b.DueCollLess*c.Charge)/a.TotalSales), 0)) - ISNULL(((b.LessAdjust*c.Charge)/a.TotalSales), 0)) AS Less
		INTO #chargeForPayable
		FROM #sales a
		LEFT JOIN #lessDueCollRtn b on a.InvNo=b.InvNo
		INNER JOIN #salesPcode c on a.InvNo=c.InvNo

		SELECT a.InvNo, e.PaidDate, b.BedNo, b.PatientId, '' AS MobNo, b.PtStatus, Isnull(d.Due,0) As Due, a.PCode, b.TotalAmount,
		(CASE WHEN c.CanGiveLess=0 THEN (b.FixedLess+b.SpecialLess) ELSE 0 END)+ISNULL(d.Less, 0) AS Less,
		(b.TotalAmount-(CASE WHEN c.CanGiveLess=0 THEN (b.FixedLess+b.SpecialLess) ELSE 0 END))-ISNULL(d.Less, 0) AS ChargeWithoutLess, a.DrCode
		INTO #z
		FROM ImagingDoctorLedger a
		Inner Join InvDetails b On a.BranchId=b.BranchId And a.InvNo=b.InvNo And a.PCode=b.PCode
		Inner JOIN ClinicalChart c On a.BranchId=c.BranchId And a.PCode=c.PCode
		LEFT JOIN #chargeForPayable d ON a.InvNo=d.InvNo AND a.PCode=d.PCode
		LEFT JOIN #lessDueCollRtn e ON a.InvNo=e.InvNo
		where a.BranchId=@BranchId AND a.Valid=1 AND b.PaidDate BETWEEN @DateFrom AND @DateTo

		SELECT a.PtStatus, a.BedNo, a.PatientId, a.MobNo, b.InvNo, b.InvDate, a.PaidDate, b.DateofExam, b.DrCode, b.Drname, b.PatientRegNo, b.PatientName, b.DeptName,
		b.PCode, b.Description, a.TotalAmount, a.Less, a.ChargeWithoutLess AS NetAmount, 
		b.PcOrTk, a.ChargeWithoutLess*c.RefFees/100 AS PayBeforeTax, (a.ChargeWithoutLess*c.RefFees/100)*.10 AS Tax, 
		(a.ChargeWithoutLess*c.RefFees/100)-(a.ChargeWithoutLess*c.RefFees/100)*.10 AS PayAfterTax, b.UserName, b.EntryDateTime, a.Due
		FROM #z a
		LEFT JOIN ImagingDoctorLedger b ON a.InvNo=b.InvNo AND a.PCode=b.PCode and a.DrCode=b.DrCode
		LEFT JOIN ReportFeesRegistration c ON b.BranchId=c.BranchId AND b.DrCode=c.DrCode AND b.DeptName=c.RptDepartment aND c.Valid=1
		WHERE b.BranchId=@BranchId AND b.DeptName LIKE '%'+@DeptName+'%' AND b.DrCode LIKE '%'+@DrCode+'%'
		And ((@PaymentStatus = 'Due' And a.Due>0) Or (@PaymentStatus='Paid' And a.Due=0))
		AND CASE WHEN @PtStatus = '' THEN '' ELSE a.PtStatus END = @PtStatus

		--select  InvNo, InvDate, DateofExam ,  DrCode, Drname, PatientRegNo,  PatientName,  DeptName, PCode, Description,TotalAmount , PcOrTk,
		--ROUND(Payable,0) as PayBeforeTax, ROUND(((Payable * 10)/100),0) AS TAX ,
		--ROUND((Payable- ((Payable * 10)/100)),0) as PayAfterTAX ,
		--UserName, EntryDateTime  
		--From ImagingDoctorLedger
		--WHERE Valid=1 AND BranchId=@BranchId AND DateofExam Between @DateFrom AND  @DateTo AND DeptName + DrCode  LIKE '%'+@DeptName+'%' + @DrCode 

		COMMIT TRANSACTION;
	END TRY

	BEGIN CATCH
		IF @@TRANCOUNT > 0
				ROLLBACK TRANSACTION;
		DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
		DECLARE @ErrorSeverity INT = ERROR_SEVERITY();
		DECLARE @ErrorState INT = ERROR_STATE();
        
		RAISERROR(@ErrorMessage, @ErrorSeverity, @ErrorState);
	END CATCH
End
GO
