CREATE Procedure [dbo].[SP_ImagingDoctorLedgerReportSMZ] (@BranchId int, @DateFrom date, @DateTo date, @Deptname nvarchar(20), @DrCode nvarchar(20), @PtStatus VARCHAR(30))
AS --- Exec SP_ImagingDoctorLedgerReportSMZ 1,  '2024-10-01' ,  '2024-10-05', '' , '', ''


------- By Zahid
--select DeptName, DrCode, Drname, ROUND(sum(TotalAmount),0) as TotalAmount, ROUND(sum(Payable),0) as BeforeTaxPayableAmt ,  ROUND(sum(Payable) * 10 /100,0) as TaxAmt,
-- ROUND(ROUND(sum(Payable),0) - (ROUND(sum(Payable) * 10,0) / 100),0) as  afterTaxPayableAmt  from ImagingDoctorLedger
--WHERE valid=1 AND BranchId=1 AND DateofExam Between @DateFrom AND @DateTo AND (DeptName + DrCode) LIKE '%'+@Deptname+'%' + @DrCode
--GROUP BY DeptName, DrCode, Drname


-------- Change BY Arif 12/12/2024
--drop table #DueCollLess and LessAdjust
SELECT a.PrevInvNo AS InvNo, SUM(CASE WHEN a.CRType='Sales' THEN 0 ELSE a.Less END) AS DueCollLess, SUM(a.ReturnLess) AS LessAdjust,
SUM(Sales-Less-Collection-ReturnDue-AdjustAmt) AS Due 
INTO #lessDueCollRtn
FROM SalesLedger a
WHERE a.BranchId=@BranchId AND a.Valid=1 AND a.PaidDate BETWEEN @DateFrom AND @DateTo
GROUP BY a.BranchId, a.PrevInvNo

--DROP TABle #sales for DueCollLess/LessAdjust ratio
SELECT InvNo, SUM(TotalAmount) AS TotalSales
INTO #sales
FROM InvDetails a 
INNER JOIN ClinicalChart c on a.BranchId=c.BranchId AND a.PCode=c.PCode AND c.CanGiveLess=1
WHERE a.BranchId=@BranchId AND a.Valid=1 AND a.PaidDate BETWEEN @DateFrom AND @DateTo
GROUP BY a.InvNo
HAVING SUM(TotalAmount) > 0

--drop table #salesPcode for DueCollLess/LessAdjust ratio
SELECT InvNo, a.PCode, a.GLessAmt, TotalAmount AS Charge
INTO #salesPcode
FROM InvDetails a 
INNER JOIN ClinicalChart c on a.BranchId=c.BranchId AND a.PCode=c.PCode AND c.CanGiveLess=1
WHERE a.BranchId=@BranchId AND a.Valid=1 AND a.PaidDate BETWEEN @DateFrom AND @DateTo

--drop table #chargeForPayable

SELECT a.InvNo, PCode, b.Due, ((c.GLessAmt+ISNULL(((b.DueCollLess*c.Charge)/a.TotalSales), 0)) - ISNULL(((b.LessAdjust*c.Charge)/a.TotalSales), 0)) AS Less
INTO #chargeForPayable
FROM #sales a
LEFT JOIN #lessDueCollRtn b on a.InvNo=b.InvNo
INNER JOIN #salesPcode c on a.InvNo=c.InvNo

SELECT b.PtStatus, a.InvNo, d.Due, a.PCode, b.TotalAmount,
(CASE WHEN cc.CanGiveLess=0 THEN (b.FixedLess+b.SpecialLess) ELSE 0 END)+ISNULL(c.Less, 0) AS Less,
(b.TotalAmount-(CASE WHEN cc.CanGiveLess=0 THEN (b.FixedLess+b.SpecialLess) ELSE 0 END))-ISNULL(c.Less, 0) AS ChargeWithoutLess
INTO #z
FROM ImagingDoctorLedger a
INNER JOIN InvDetails b ON a.BranchId=b.BranchId AND a.InvNo=b.InvNo AND a.PCode=b.PCode
INNER JOIN ClinicalChart cc ON b.BranchId=cc.BranchId AND b.PCode=cc.PCode
LEFT JOIN #chargeForPayable c ON a.InvNo=c.InvNo AND a.PCode=c.PCode
LEFT JOIN #lessDueCollRtn d ON a.InvNo=d.InvNo
WHERE a.BranchId=@BranchId AND a.Valid=1 AND b.PaidDate BETWEEN @DateFrom AND @DateTo


SELECT a.PtStatus, b.DeptName,b.DrCode,b.Drname, SUM(a.TotalAmount) AS TotalAmount, SUM(a.Less) AS Less,SUM(a.ChargeWithoutLess) AS NetAmount, 
SUM(a.ChargeWithoutLess*c.RefFees/100) AS BeforeTaxPayableAmt, 
SUM((a.ChargeWithoutLess*c.RefFees/100)*0.10) AS TaxAmt, 
SUM((a.ChargeWithoutLess*c.RefFees/100)-(a.ChargeWithoutLess*c.RefFees/100)*.10) AS afterTaxPayableAmt
FROM #z a
LEFT JOIN ImagingDoctorLedger b ON a.InvNo=b.InvNo AND a.PCode=b.PCode
LEFT JOIN ReportFeesRegistration c ON b.BranchId=c.BranchId AND b.DrCode=c.DrCode AND b.DeptName=c.RptDepartment aND c.Valid=1
WHERE b.BranchId=@BranchId AND b.DeptName LIKE '%'+@DeptName+'%' AND b.DrCode LIKE '%'+@DrCode+'%' and a.Due=0
AND CASE WHEN @PtStatus = '' THEN '' ELSE a.PtStatus END = @PtStatus
GROUP BY b.DeptName,b.DrCode,b.Drname, a.PtStatus


GO
