CREATE PROC [dbo].[Sp_ImagingPtnInfo] @BranchId INT, @InvNo VARCHAR(50)
AS
BEGIN /* EXEC Sp_ImagingPtnInfo 1, 'DIA231200002' */
	select a.RegNo, a.InvNo, a.InvDate, a.PatientName, a.MobNo, a.Sex, a.DOB, a.ConsultantCode, a.ConsultantName, a.PtStatus, b.PCode, b.ShortDesc, c.SubDeptName AS GroupName, a.LabNo AS LabNo,
	0 as PrintStatus, 0 AS SMSSend
	from InvMaster a
	left join InvDetails b on b.BranchId = a.BranchId and b.InvNo = a.InvNo
