CREATE PROCEDURE [dbo].[SP_IN_ProductIssuingReport] (@BranchId int, @UnitId int, @datefrom date, @dateto date, @StoreName nvarchar(20), @Category nvarchar(50), @IssueDeptName nvarchar(50), @ProductCode nvarchar(20), @inventoryType NVARCHAR(50)) 
AS
BEGIN /* SP_IN_ProductIssuingReport 1, 1, '2023-07-01', '2025-08-01', '', '',  '', '', ''  */
	SELECT a.storeName,a.TrDate, a.TrNo, a.InvoiceNo, a.InvoiceDate, a.ProductCode, b.ProductName, a.Unit, b.InventoryType,
	a.BatchNo,  ISNULL(a.ExpDate, '1990-01-01') AS ExpDate, a.PPrice, a.OutQty,(a.PPrice*a.OutQty) AS TotalAmt, 
	a.ReqFrom AS IssueTo, a.IssueDeptName AS Department, a.IssueToDtls, b.ProductCategory, a.UserName, a.EntryDateTime
	FROM InvStockLedger a
	LEFT JOIN InvItemRegistration b ON a.ProductCode = b.ProductCode
	WHERE a.Valid=1 AND b.Valid = 1 AND a.UnitId = @UnitId AND a.BranchId = @BranchId AND a.OutQty <> 0 
	AND a.StoreName LIKE '%'+@StoreName+'%' AND  b.ProductCategory LIKE '%'+@Category+'%' 
	AND ISNULL (a.IssueDeptName,'') LIKE  '%'+@IssueDeptName+'%' AND a.ProductCode LIKE '%'+ @ProductCode +'%'
	AND CASE WHEN @inventoryType = '' THEN '' ELSE b.InventoryType END = @inventoryType
	AND TrDate BETWEEN @datefrom AND @dateto
	ORDER BY a.TrNo, a.TrDate
END
GO
