CREATE PROCEDURE [dbo].[SP_IN_ProductIssuingReportAurroraDtls] 
(@BranchId int, @UnitId int, @datefrom date, @dateto date, @StoreName nvarchar(20), @Category nvarchar(50), @IssueDeptName nvarchar(50), @ProductCode nvarchar(20) ) 
AS
BEGIN /* SP_IN_ProductIssuingReportAurroraDtls 1, 1, '2023-09-01', '2023-09-07', '', '', '', ''  */
	SELECT a.storeName,  a.ProductCode, b.ProductName, a.Unit, a.IssueDeptName AS Department,
	 sum(a.OutQty) as OutQty, sum(a.PPrice*a.OutQty) AS TotalAmt
	FROM InvStockLedger a
	LEFT JOIN InvItemRegistration b ON a.ProductCode = b.ProductCode
	WHERE a.Valid=1 AND b.Valid = 1 AND a.UnitId = @UnitId AND a.BranchId = @BranchId AND TrDate BETWEEN @datefrom AND @dateto AND a.OutQty <> 0 
	AND a.StoreName LIKE '%'+@StoreName+'%' AND b.ProductCategory  LIKE '%'+@Category+'%' AND  ISNULL(a.IssueDeptName,'') LIKE '%'+@IssueDeptName+'%' AND a.ProductCode LIKE '%'+ @ProductCode +'%'	
	GROUP BY  a.storeName,  a.ProductCode, b.ProductName, a.Unit,  a.IssueDeptName
	ORDER BY ProductCode
END
GO
