	BEGIN /* SP_IN_ProductReceivingReport  1, 1, '2024-10-01', '2024-10-01','', '', '' ,''  */
		--SELECT a.storeName, a.TrDate, a.TrNo, a.InvoiceNo, a.InvoiceDate, a.supplierid, a.SupplierName, a.ProductCode, b.ProductName, 
		--a.Unit, a.BatchNo, ISNULL(a.ExpDate, '1990-01-01') AS ExpDate, a.PPrice, a.InQty, (a.PPrice * a.InQty) as TotalAmt, b.ProductCategory
		--FROM InvStockLedger a
		--LEFT JOIN InvItemRegistration b ON a.ProductCode = b.ProductCode
		--WHERE a.Valid=1 AND b.Valid = 1 AND a.UnitId = @UnitId AND a.BranchId = @BranchId AND a.InQty <> 0 
		--AND a.StoreName LIKE '%'+@StoreName +'%' AND b.ProductCategory LIKE '%'+@Category +'%' AND 
