CREATE PROCEDURE [dbo].[SP_IN_ProductReceivingReportForARRORADetails] (@BranchId int, @UnitId int, @datefrom date, @dateto date, @StoreName nvarchar(20), @Category nvarchar(50), @SupplierCode nvarchar(10), @ProductCode nvarchar(20) ) AS
	BEGIN /* EXEC SP_IN_ProductReceivingReportForARRORADetails 1, 1, '2023-12-31', '2023-12-31', '', '', '' ,'' */
		SELECT a.storeName, a.ProductCode, b.ProductName, a.SupplierId, a.SupplierName,
		a.Unit, (case when SUM(a.InQty) <> 0 then (SUM(a.PPrice * a.InQty)/SUM(a.InQty)) end ) as PPrice, SUM(a.InQty) AS InQty, 
		SUM(a.PPrice * a.InQty) as TotalAmt, b.ProductCategory, a.UserName, a.EntryDateTime
		FROM InvStockLedger a
		LEFT JOIN InvItemRegistration b ON a.ProductCode = b.ProductCode
		WHERE a.Valid=1 AND b.Valid = 1 AND a.BranchId = @BranchId AND a.UnitId = @UnitId  
	    AND TrDate BETWEEN @datefrom AND @dateto
		AND a.InQty <> 0 
		AND a.StoreName LIKE '%'+@StoreName+'%' AND b.ProductCategory LIKE '%'+@Category+'%' AND  a.SupplierId LIKE '%'+@SupplierCode+'%' AND a.ProductCode LIKE '%'+@ProductCode +'%'		
		GROUP BY a.storeName, a.ProductCode, b.ProductName,  a.SupplierId, a.SupplierName, a.Unit,b.ProductCategory, a.UserName, a.EntryDateTime
		ORDER BY b.ProductCategory,a.ProductCode
	END
GO
