CREATE PROCEDURE [dbo].[SP_IN_ProductReceivingReportSupplierSMZ] (@BranchId int, @UnitId int, @datefrom date, @dateto date, @StoreName nvarchar(20),  @SupplierCode nvarchar(10)) AS
	BEGIN /* EXEC SP_IN_ProductReceivingReportSupplierSMZ 1, 1, '2024-01-01', '2024-02-29', '', '' */
		SELECT a.storeName, a.SupplierId, a.SupplierName,
		ROUND((case when SUM(a.InQty) <> 0 then (SUM(a.PPrice * a.InQty)/SUM(a.InQty)) end),2) as PPrice, SUM(a.InQty) AS InQty, 
		SUM(a.PPrice * a.InQty) as TotalAmt
