		AND a.StoreName LIKE '%'+@StoreName+'%' AND a.SupplierId LIKE '%'+@SupplierCode+'%'
		GROUP BY a.storeName, a.SupplierId,  a.SupplierName 
		ORDER BY a.SupplierId
END
