CREATE PROCEDURE [dbo].[SP_InCurrentStock](@StoreName nvarchar(50), @StoreUnit nvarchar(20), @Param nvarchar(50), @ReqNo nvarchar(20), @ReqDate date)
AS 

if @ReqNo = '' 
	BEGIN
		select a.ProductCode, a.ProductName, a.Unit, a.BatchNo, a.ExpDate, SUM(a.InQty-a.OutQty+a.PRtnQty-a.RtnQty) as CurrQty, 0.0 as IssueQty
		from InvStockLedger a
		WHERE a.Valid = 1 AND a.storeName = @StoreName AND a.Pno = @StoreUnit AND a.ProductCode+a.ProductName like N'%'+@Param+'%'
		GROUP BY a.ProductCode, a.ProductName, a.Unit, a.BatchNo, a.ExpDate
		HAVING SUM(a.InQty-a.OutQty+a.PRtnQty-a.RtnQty) > 0
	END
ELSE
	BEGIN
		select a.ProductCode, a.ProductName, a.Unit, a.BatchNo, a.ExpDate, SUM(a.InQty-a.OutQty+a.PRtnQty-a.RtnQty) as CurrQty, 0.0 as IssueQty
		from InvStockLedger a
		WHERE a.Valid = 1 AND a.storeName = @StoreName AND a.Pno = @StoreUnit AND a.ProductCode+a.ProductName like N'%'+@Param+'%'
		GROUP BY a.ProductCode, a.ProductName, a.Unit, a.BatchNo, a.ExpDate
		HAVING SUM(a.InQty-a.OutQty+a.PRtnQty-a.RtnQty) > 0
	END


GO
