CREATE PROC [dbo].[SP_INDOOR_BILL_PREVIEW_PHARMACY](@PatientId nvarchar(20), @BranchId int, @UnitId int)
AS
BEGIN
select a.PatientId, 'Pharmacy Bill' as ServiceName, 'Medicine' as Service, SUM(a.Sales) as MSales, SUM(a.Collection+a.DueColl) as MColl, SUM(a.LessAmt+a.DueLess) as MLess, SUM(a.Sales-a.Collection-a.DueColl-a.DueLess-a.ReturnAmt-a.LessAmt) AS Due
from PharSalesLedger a
WHERE a.PatientId = @PatientId and a.Valid <> 0 AND a.BranchId = @BranchId AND a.CostCenterName = @UnitId AND a.PatientId != ''
GROUP BY a.PatientId

END
GO
