CREATE PROC [dbo].[SP_Indoor_Collection] @BranchId int, @PatientId VARCHAR(20), @IsIncludePharmacy INT
AS
BEGIN /* EXEC SP_Indoor_Collection 1, 'PA231200197', 1 */

/*Condition for IsInclude Pharmacy bill*/
DECLARE @IncludePharmacy INT;
IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END

select SUM(Collection) as Collection, SUM(a.Due) AS Due from (
select SUM(Collection-ReturnAmt-Adjust) as Collection, SUM((a.NoU*a.Charge)+a.ServiceCharge-a.Less+a.ReturnAmt-a.Collection) AS Due
from PatientLedger a where BranchId = @BranchId AND PatientId=@PatientId AND Valid=1
UNION AlL
select SUM(Collection-ReturnCash) as Collection, ISNULL(sum(Sales+ProcServiceCharge-Less-Collection-ReturnDue), 0) AS Due
from SalesLedger where BranchId = @BranchId AND PatientId=@PatientId AND Valid = 1 AND Department != 'Ambulance'
UNION AlL
select SUM(Collection+DueColl-CashReturn) as Collection, ISNULL(SUM(Sales-LessAmt-DueLess-Collection-DueColl-ReturnAmt), 0) AS Due
from PharSalesLedger where BranchId = @BranchId AND PatientId=@PatientId AND Valid = @IncludePharmacy
UNION AlL 
SELECT SUM(ReceiveAmt) AS Collection, ISNULL(SUM(TotalCharge-Less-ReceiveAmt), 0) AS Due
FROM AmbulanceLedger WHERE BranchId = @BranchId AND PatientId=@PatientId AND Valid = 1 
) a 
END
GO
