CREATE PROCEDURE [dbo].[SP_INDOOR_PATIENT_LIST](@dateFrom date, @dateTo date, @branchId int, @unitId int, @isRelease int)
AS
BEGIN	
	SELECT a.DrCode AS RefDrCode, a.DrName AS RefDrName, a.UnderDrCode AS ConsultantDrCode, a.UnderDrName AS ConsultantDrName, a.BedNo, a.PatientId, a.PatientName,
	a.PatientAge, a.PatientSex, a.AdmissionDate, ISNULL(a.ReleaseDate,'0001-01-01') as ReleaseDate, a.PatientAddress, a.BedCharge, a.UserName FROM PatientAdmission a
	WHERE a.Valid = 1 AND a.IsRelease = @isRelease AND a.BranchId = @branchId AND a.AdmissionDate BETWEEN @dateFrom AND @dateTo

END

