/****** Object:  StoredProcedure [dbo].[SP_Indoor_PatientLedgerDeptWise]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

--16092025 For Arora, Due Re-Calculate
CREATE PROC [dbo].[SP_Indoor_PatientLedgerDeptWise] @BranchId int, @PatientId VARCHAR(20), @IsIncludePharmacy INT, @CardTypeId INT
AS
BEGIN /* EXEC SP_Indoor_PatientLedgerDeptWise 1, 'PA250800079', 1, 0 */

/*Condition for IsInclude Pharmacy bill*/
DECLARE @IncludePharmacy INT;
IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END

select a.PatientId, a.Bedno, ISNULL(b.SubDeptName, 'LabTest') AS Description, SUM(a.Amount) AS DueAmount
into #z
from InvDetails a
left join ClinicalChart b on a.PCode=b.PCode
where a.PatientId=@PatientId and b.CanGiveLess=1 and a.Valid<>0
group by a.PatientId, a.Bedno, ISNULL(b.SubDeptName, 'LabTest')

/*Indoor Bill*/
SELECT (CASE WHEN a.Status = 'Procedure Entry For Dr' OR a.Status = 'OT' THEN 2 ELSE 1 END) AS SlNo, a.BedNo, b.SubSubPno AS BedDept, 'Indoor' AS Department, a.Code, a.Particulars, a.DrCode,
a.Charge, a.Unit, SUM(a.NoU) AS NoU, SUM(a.Charge*a.NoU) AS TotalCharge, SUM(a.Less) AS Less, --+a.ServiceCharge
ISNULL((CASE WHEN @CardTypeId != 0 THEN SUM(CASE WHEN c.PcOrTk = '%' THEN a.TotalAmount*c.DiscountAmt*0.01 ELSE a.NoU*c.DiscountAmt END) END),0) AS FixedLess,
/*SUM(a.ServiceCharge)*/0 AS ServiceCharge, (SUM(a.Charge*a.NoU+a.ReturnAmt)-/*+a.ServiceCharge*/ISNULL((CASE WHEN @CardTypeId = 0 THEN SUM(a.Less) ELSE SUM(CASE WHEN c.PcOrTk = '%' THEN a.TotalAmount*c.DiscountAmt*0.01 ELSE a.NoU*c.DiscountAmt END) END),0)/**/) AS Due
FROM PatientLedger a
LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
LEFT JOIN VW_DiscCardRegNoWise c ON a.BranchId = c.BranchId AND a.RegNo = c.RegNo AND a.Code = c.PCode
WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.PatientId = @PatientId AND a.Status != 'Advance Collection'
GROUP BY a.BedNo, b.SubSubPno, a.Code, a.Particulars, a.DrCode, a.Charge, a.Unit, (CASE WHEN a.Status = 'Procedure Entry For Dr' OR a.Status = 'OT' THEN 2 ELSE 1 END)
HAVING SUM(a.Charge*a.NoU+a.ServiceCharge-a.Less+a.ReturnAmt) != 0

/*Start Indoor Service Charge*/
UNION ALL
SELECT 3 AS SlNo, a.BedNo, c.SubSubPno AS BedDept, 'Indoor' AS Department, '0015' AS Code, 'Service Charge' AS Particulars, '' AS DrCode,
SUM(b.ServiceCharge) AS Charge, 1 AS Unit, 1 AS NoU, SUM(b.ServiceCharge) AS TotalCharge, 0 AS Less, 0 AS FixedLess, 0 AS ServiceCharge, SUM(b.ServiceCharge) AS Due
FROM PatientAdmission a
LEFT JOIN PatientLedger b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId AND b.Valid = 1
LEFT JOIN BedInformation c ON a.BranchId = c.BranchId AND a.BedNo = c.BedNo
WHERE a.BranchId = @BranchId AND a.PatientId = @PatientId 
GROUP BY a.BedNo, c.SubSubPno
/*End Indoor Service Charge*/

/*End Indoor Bill*/

/*Test Bill*/
UNION ALL
--SELECT 5 AS SlNo, a.BedNo, b.SubSubPno AS BedDept, '0011' AS Code, a.Department AS Particulars, '' AS DrCode, SUM(a.Sales-a.ReturnAmount) AS Charge, '1' AS Unit,
--1 AS NoU, SUM(a.Sales-a.ReturnAmount) AS TotalCharge, SUM(a.Less-a.ReturnLess) AS Less,
--0 AS ServiceCharge, SUM(a.Sales-a.Less-a.Collection-(a.ReturnAmount-a.ReturnCash-a.ReturnLess)) AS Due
--FROM SalesLedger a
--LEFT JOIN PatientAdmission c ON a.BranchId = c.BranchId AND a.PatientId = c.PatientId
--LEFT JOIN BedInformation b on a.BranchId = b.BranchId AND c.BedNo = b.BedNo
--WHERE a.BranchId = @BranchId AND a.PatientId = @PatientId AND a.Valid = 1 AND a.Department != 'Ambulance'
--GROUP BY a.BedNo, b.SubSubPno, a.Department

SELECT 5 AS SlNo, a.Bedno, BedDept, Department, '0011' AS Code, Particulars, '' AS DrCode, 
SUM(Charge) AS Charge, '1' AS Unit, 1 AS NoU, SUM(TotalCharge) AS TotalCharge, SUM(Less) AS Less, 
SUM(FixedLess) AS FixedLess, 0 AS ServiceCharge, ISNULL(b.DueAmount, 0) AS DueAmount--, SUM(Due) AS Due
FROM (
	SELECT a.BedNo, e.SubSubPno AS BedDept, a.DeptName AS Department, ISNULL(b.SubDeptName, 'LabTest') AS Particulars, SUM(a.Amount*a.Quantity) AS Charge,
	SUM(a.TotalAmount) AS TotalCharge, SUM(a.GLessAmt+a.GDueLess) AS Less,
	ISNULL((CASE WHEN @CardTypeId != 0 THEN SUM(CASE WHEN f.PcOrTk = '%' THEN a.TotalAmount*f.DiscountAmt*0.01 ELSE a.Quantity*f.DiscountAmt END) END), 0) AS FixedLess, 
	(SUM(a.TotalAmount)-(SUM(a.TotalAmount)*c.Collection)/c.Sales/**/-ISNULL((CASE WHEN @CardTypeId = 0 THEN SUM(a.GLessAmt) ELSE SUM(CASE WHEN f.PcOrTk = '%' THEN a.TotalAmount*f.DiscountAmt*0.01 ELSE a.Quantity*f.DiscountAmt END) END), 0)/**/) as due
	FROM InvDetails a
	left join ClinicalChart b on a.BranchId = b.BranchId ANd a.PCode = b.PCode
	LEFT join (
		SELECT BranchId, SUM(Sales-ReturnAmount) as Sales, sum(Collection-ReturnCash) as Collection 
		FROM SalesLedger where BranchId = @BranchId ANd Valid = 1 AND PatientId = @PatientId GROUP BY BranchId HAVING SUM(Sales-ReturnAmount) > 0
	) c ON a.BranchId = c.BranchId
	LEFT JOIN BedInformation e on a.BranchId = e.BranchId AND a.BedNo = e.BedNo
	LEFT JOIN VW_DiscCardRegNoWise f ON a.BranchId = f.BranchId AND a.RegNo = f.RegNo AND a.PCode = f.PCode
	where a.Valid = 1 AND a.BranchId = @BranchId AND a.PatientId = @PatientId AND c.BranchId IS NOT NULL
	group by a.Bedno, e.SubSubPno, a.DeptName, b.SubDeptName, c.Collection, c.Sales
) a
left join #z b on a.Bedno=b.Bedno and a.Particulars=b.Description
GROUP BY a.Bedno, BedDept, Department, a.Particulars, b.DueAmount
/*End Test Bill*/

/*Medicine Bill*/
UNION ALL
SELECT 6 AS SlNo, a.BedNo, b.SubSubPno AS BedDept, 'Medicine' AS Department, '0009' AS Code, 'Medicine Bill' as Particulars, '' as DrCode,
SUM(a.Sales-a.ReturnAmt-a.LessAdjust) AS Charge, '1' AS Unit, 1 AS NoU, SUM(a.Sales-a.ReturnAmt-a.LessAdjust) AS TotalCharge, SUM(a.LessAmt+a.DueLess) AS Less, 
ISNULL((CASE WHEN @CardTypeId != 0 THEN (CASE WHEN c.PcOrTk = '%' THEN SUM((a.Sales-a.ReturnAmt)*c.DiscountAmt*0.01) ELSE SUM(c.DiscountAmt) END) END), 0) AS FixedLess,
0 AS ServiceCharge, (SUM(a.Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt)-/**/ISNULL((CASE WHEN @CardTypeId = 0 THEN SUM(c.DiscountAmt) ELSE (CASE WHEN c.PcOrTk = '%' THEN SUM((a.Sales-a.ReturnAmt)*c.DiscountAmt*0.01) ELSE SUM(c.DiscountAmt) END) END), 0)/**/) AS Due
FROM PharSalesLedger a
LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
LEFT JOIN VW_DiscCardRegNoWise c ON a.BranchId = c.BranchId AND a.RegNo = c.RegNo AND c.PCode = '0009'
where a.BranchId = @BranchId  AND a.PatientId = @PatientId AND a.Valid = @IncludePharmacy
GROUP BY b.SubSubPno, a.BedNo, c.PcOrTk
/*End Medicine Bill*/

/*Ambulance Bill*/
UNION ALL
SELECT 7 AS SlNo, a.BedNo, b.SubSubPno AS BedDept, 'Ambulance' AS Department, '0016' AS Code, 'Ambulance' AS Particulars, '' AS DrCode,
SUM(a.TotalCharge) AS Charge, '1' AS Unti, 1 AS NoU, SUM(a.TotalCharge) AS TotalCharge, SUM(a.Less) AS Less, 
ISNULL((CASE WHEN @CardTypeId != 0 THEN (CASE WHEN c.PcOrTk = '%' THEN SUM(a.TotalCharge*c.DiscountAmt*0.01) ELSE SUM(c.DiscountAmt) END) END), 0) AS Less,
0 AS ServiceCharge, (SUM(a.TotalCharge-a.Less-a.ReceiveAmt)-/**/ISNULL((CASE WHEN @CardTypeId = 0 THEN SUM(a.Less) ELSE (CASE WHEN c.PcOrTk = '%' THEN SUM(a.TotalCharge*c.DiscountAmt*0.01) ELSE SUM(c.DiscountAmt) END) END), 0)/**/) AS Due
FROM AmbulanceLedger a
LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
LEFT JOIN VW_DiscCardRegNoWise c ON a.BranchId = c.BranchId AND a.RegNo = c.RegNo AND c.PCode = '0016'
WHERE a.BranchId = @BranchId AND a.PatientId = @PatientId AND a.Valid = 1
GROUP BY b.SubSubPno, a.BedNo, c.PcOrTk
HAVING SUM(a.TotalCharge) > 0
/*End Ambulance Bill*/

ORDER BY SlNo, SubSubPno, a.BedNo
END
GO
/****** Object:  StoredProcedure [dbo].[SP_Indoor_PatientLedgerDueColl]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[SP_Indoor_PatientLedgerDueColl] @BranchId int, @PatientId VARCHAR(20), @IsIncludePharmacy INT
AS
BEGIN /* EXEC SP_Indoor_PatientLedgerDueColl 1, 'PA240100115', 1 */
DECLARE @IncludePharmacy INT;
IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END

/* Start SalesLedger into #z table*/
SELECT BranchId, PrevInvNo AS InvNo, SUM(Sales) AS Sales, SUM(Less) AS Less, SUM(Collection-ReturnCash) AS Collection, SUM(AdjustAmt) AS AdjustAmt
INTO #z --drop table #z
FROM SalesLedger a 
WHERE BranchId = @BranchId AND PatientId = @PatientId AND Valid = 1 AND Department != 'Ambulance'
GROUP BY BranchId, PrevInvNo
--HAVING SUM(Sales-Less-Collection-AdjustAmt) != 0
/* End SalesLedger into #z table*/

/*Start Indoor Due Bill*/
SELECT SlNo, BedNo, BedDept, 'Indoor' AS DeptName, Code, Particulars, DrCode, SUM(NoU) AS NoU,
SUM(TotalCharge) AS TotalCharge, SUM(Less) AS Less, SUM(TotalCharge-Less) AS Due
FROM (
	SELECT (CASE WHEN a.Status = 'Procedure Entry For Dr' THEN 2 ELSE 1 END) AS SlNo, a.BedNo, b.SubSubPno AS BedDept, a.Code, a.Particulars, a.DrCode, SUM(a.NoU) AS NoU,
	SUM(a.Charge*a.NoU+a.ServiceCharge) AS TotalCharge, 0 AS Less, SUM(a.Charge*a.NoU+a.ServiceCharge-Less) AS Due
	FROM PatientLedger a
	LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.PatientId = @PatientId 
	AND a.Status NOT IN ('Advance Collection', 'Patient Release', 'Indoor Due Collection')
	GROUP BY a.Status, a.Code, a.Particulars, b.SubSubPno, a.BedNo, a.DrCode
	UNION ALL
	select (CASE WHEN a.Status = 'Procedure Entry For Dr' THEN 2 ELSE 1 END) AS SlNo, a.BedNo, b.SubSubPno AS BedDept, a.Code, a.Particulars, a.DrCode, 0 AS NoU,
	0 AS TotalCharge, SUM(a.Less) AS Less, 0 AS Due 
	from PatientLedger a
LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.PatientId = @PatientId 
	AND a.Status IN ('Patient Release', 'Indoor Due Collection')
	GROUP BY a.Status, a.Code, a.Particulars, b.SubSubPno, a.BedNo, a.DrCode


) a
GROUP BY SlNo, BedNo, BedDept, Code, Particulars, DrCode
HAVING SUM(TotalCharge-Less) != 0
/*End Indoor Due Bill*/

/*Start Investigation Due Bill*/
UNION ALL
SELECT 5 AS SlNo, BedNo, BedDept, DeptName, '0011' AS Code, Particulars, '' AS DrCode, 1 AS NoU, 
SUM(TotalCharge) AS TotalCharge, SUM(Less) AS Less, SUM(Due) AS Due
FROM (
	SELECT a.Bedno AS BedNo, d.SubSubPno AS BedDept, a.DeptName, ISNULL(b.SubDeptName, 'LabTest') AS Particulars,
	SUM(a.TotalAmount) AS TotalCharge, ISNULL((c.Less*SUM(a.TotalAmount))/c.Sales, 0) AS Less,
	--ISNULL((c.AdjustAmt*SUM(a.TotalAmount))/c.Due, 0) as adjust, ISNULL((c.Collection*SUM(a.TotalAmount))/c.Due, 0) as coll,
	ISNULL(SUM(a.TotalAmount)-(ISNULL((c.Less*SUM(a.TotalAmount))/c.Sales, 0)/*Less*/)-(ISNULL((c.AdjustAmt*SUM(a.TotalAmount))/c.Sales, 0)/*Adjust*/)-(ISNULL((c.Collection*SUM(a.TotalAmount))/c.Sales, 0) /*Collection*/), 0) AS Due
	FROM InvDetails a
	LEFT JOIN ClinicalChart b on a.BranchId = b.BranchId ANd a.PCode = b.PCode
	LEFT JOIN #z c ON a.BranchId = c.BranchId AND a.InvNo = c.InvNo
	LEFT JOIN BedInformation d ON a.BranchId = d.BranchId AND a.Bedno = d.BedNo
	WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.PatientId = @PatientId AND c.BranchId IS NOT NULL
	GROUP BY a.Bedno, d.SubSubPno, a.DeptName, b.SubDeptName, c.Less, c.Sales, c.AdjustAmt, c.Collection
) aa
GROUP BY BedNo, BedDept, DeptName, Particulars
/*End Investigation Due Bill*/

/*Start Medicine Due Bill*/
UNION ALL
SELECT 6 AS SlNo, a.BedNo, b.SubSubPno AS BedDept, 'Medicine' AS DeptName, '0009' AS Code, 'Medicine Bill' as Particulars, '' as DrCode,1 AS NoU,
SUM(a.Sales-a.ReturnAmt-a.CashReturn) AS TotalCharge, SUM(a.LessAmt+a.DueLess) AS Less, SUM(a.Sales-a.Collection-a.DueColl-a.DueLess-a.LessAmt-a.ReturnAmt-a.AdjustAmt) AS Due
FROM PharSalesLedger a
LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
where a.BranchId = @BranchId  AND PatientId = @PatientId AND a.Valid = 1
GROUP BY b.SubSubPno, a.BedNo
HAVING SUM(a.Sales-a.Collection-a.DueColl-a.DueLess-a.LessAmt-a.ReturnAmt-a.AdjustAmt) != 0
/*End Medicine Due Bill*/

/*Start Ambulance Due Bill*/
UNION ALL
SELECT 7 AS SlNo, a.BedNo, b.SubSubPno AS BedDept, 'Ambulance' AS DeptName, '0016' AS Code, 'Ambulance' AS Particulars, '' AS DrCode, 1 AS NoU,
SUM(a.TotalCharge) AS TotalCharge, SUM(a.Less) AS Less, SUM(a.TotalCharge-a.Less-a.ReceiveAmt-a.AdjustAmt) AS Due
FROM AmbulanceLedger a
LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
WHERE a.BranchId = @BranchId AND a.PatientId = @PatientId AND a.Valid = 1
GROUP BY b.SubSubPno, a.BedNo
HAVING SUM(a.TotalCharge-a.Less-a.ReceiveAmt-a.AdjustAmt) != 0
ORDER BY BedDept, SlNo, a.BedNo
/*End Ambulance Due Bill*/

END
GO
/****** Object:  StoredProcedure [dbo].[SP_Indoor_PatientListAfterRelease]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[SP_Indoor_PatientListAfterRelease] @branchId INT, @param VARCHAR(50)
as
BEGIN /* EXEC SP_Indoor_PatientListAfterRelease 1, 'PA250100001' */
	SELECT TOP 100 b.RegNo, b.PatientId, b.PatientName, b.AdmissionDate, b.AdmissionTime, b.PatientSex, b.PatientAge, b.BedNo, b.PatientTel, b.PatientAddress, b.ContractAmount,
	c.SubSubPno, b.DrCode, b.DrName, b.UnderDrCode, b.UnderDrName, DATEDIFF(day, b.AdmissionDate, d.ReleaseDate)+1 AS TotalDays, b.PackCode, d.ReleaseDate AS ReleaseDate, d.EntryDateTime AS ReleaseDateTime,
	SUM(a.AdjustAmt) AS AdjustAmt, SUM(a.HBill+a.DBill+a.MBill-a.Collection) AS Due
	FROM (
	SELECT a.BranchId, a.PatientId, SUM(a.TotalAmount-a.Less) AS HBill, 0 AS DBill, 0 AS MBill, SUM(a.Collection-a.ReturnAmt) AS Collection, 
	0 AS AdjustAmt
	FROM PatientLedger a
	WHERE Valid = 1 AND a.PatientId != ''
	GROUP BY a.BranchId, a.PatientId
	UNION
	SELECT a.BranchId, a.PatientId, 0 AS HBill, SUM(a.Sales-a.Less-a.ReturnNet) AS DBill, 0 AS MBill, SUM(a.Collection-a.ReturnCash) AS Collection, 
	SUM(a.AdjustAmt) AS AdjustAmt
	FROM SalesLedger a
	WHERE a.Valid = 1 AND a.PatientId != ''
	GROUP BY a.BranchId, a.PatientId
	UNION
	SELECT a.BranchId, a.PatientId, 0 AS HBill, 0 AS DBill, SUM(a.Sales-a.LessAmt-a.DueLess-a.ReturnAmt-a.LessAdjust) AS MBill, SUM(a.Collection+a.DueColl-a.CashReturn) AS Collection, 
	SUM(a.AdjustAmt) AS AdjustAmt
	FROM PharSalesLedger a
	WHERE a.Valid = 1 AND a.PatientId != ''
	GROUP BY a.BranchId, a.PatientId
	) a
	LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
	LEFT JOIN BedInformation c ON a.BranchId = c.BranchId AND b.BedNo = c.BedNo
	LEFT JOIN PatientReleaseMaster d ON a.BranchId = d.BranchId AND b.PatientId = d.PatientID AND d.Valid = 1
	where a.BranchId = @branchId AND b.IsRelease = 1 AND (b.PatientId+b.RegNo+b.PatientName+b.PatientTel) Like '%'+@param+'%'
	GROUP BY b.RegNo, b.PatientId, b.PatientName, b.AdmissionDate, b.AdmissionTime, b.PatientSex, b.PatientAge, b.BedNo, b.PatientTel, b.PatientAddress, b.ContractAmount,
	c.SubSubPno, b.DrCode, b.DrName, b.UnderDrCode, b.UnderDrName, DATEDIFF(day, b.AdmissionDate, d.ReleaseDate)+1, b.PackCode, d.ReleaseDate, d.EntryDateTime
	HAVING SUM(a.HBill+a.DBill+a.MBill+a.Collection) != 0
END
GO
