SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[SP_Indoor_PtnLedgerDueColl_Oasis] @BranchId INT, @PatientId VARCHAR(50)
AS
BEGIN /* EXEC SP_Indoor_PtnLedgerDueColl_Oasis 1, 'PA231200038' */
	select 1 AS SlNo, a.Code, a.Particulars, a.ChangedBedId, SUM(a.NoU*a.Charge-a.Less) AS DueAmt, sum(a.ServiceCharge-a.ServiceChargeLess) AS ServiceCharge
	from PatientLedger a
	where a.BranchId = @BranchId and a.Valid = 1 and a.PatientId = @PatientId
	GROUP BY a.Code, a.Particulars, a.ChangedBedId
	having SUM(a.NoU*a.Charge+a.ServiceCharge-a.Less) != 0
	UNION ALL
	SELEct 5 AS SlNo, '0011' aS Code, a.Department AS Particulars, a.ChangedBedId, sum(a.Sales-a.Less-a.Collection) aS DueAmt, sum(a.ProcServiceCharge) AS ServiceCharge
	from SalesLedger a
	where a.BranchId = @BranchId and a.Valid = 1 and a.PatientId = @PatientId
	GROUP BY a.Department, a.ChangedBedId
	Having sum(a.Sales+a.ProcServiceCharge-a.Less-a.Collection) != 0
END
GO
