CREATE PROC [dbo].[SP_Indoor_RemainingPtnWithoutProbablyRelease] @BranchId INT, @UnitId INT
AS 
BEGIN /* EXEC SP_Indoor_RemainingPtnWithoutProbablyRelease 1, 1 */
	SELECT a.RegNo, a.PatientId, a.AdmissionDate, a.PatientName, a.PatientSex AS Gender, a.PatientAge, a.UnderDrCode, 
	a.UnderDrName, a.DrCode, a.DrName, a.BedNo, a.PatientTel, c.SubSubPno AS Department, a.PatientType
	FROM PatientAdmission a
	LEFT JOIN ProbablyPatientRelease b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId AND a.RegNo = b.RegNo
	LEFT JOIN BedInformation c ON a.BranchId = c.BranchId AND a.BedNo = c.BedNo
	WHERE a.IsRelease = 0 AND b.Id IS NULL
END
