CREATE PROC [dbo].[SP_IndoorAmbulanceBillDtls] @PatientId VARCHAR(20), @BranchId INT
AS
BEGIN /* EXEC SP_IndoorAmbulanceBillDtls 'PA221200004', 1 */
SELECT c.SubSubPno AS Department, a.PatientId, a.RegNo, a.PatientName, a.BedNo, a.Gender, a.Age, d.UnderDrCode AS DrCode, d.UnderDrName AS DrName,
a.ReceiptNo, a.ReceiptDate, a.EntryDateTime AS InvDatetime, d.PatientAddress, b.Mobile, a.DriverName, a.AmbulanceNo, a.DestinationFrom, a.DestinationTo,
a.MeterFrom, a.MeterTo, a.UserName, SUM(b.TotalCharge) AS TotalAmt, SUM(b.Less) AS Less, SUM(b.ReceiveAmt) AS Advance,
SUM(b.TotalCharge-b.Less-b.ReceiveAmt) AS Due
FROM AmbulanceMaster a
LEFT JOIN AmbulanceLedger b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId AND b.Valid = 1
LEFT JOIN BedInformation c oN a.BranchId = c.BranchId AND a.BedNo = c.BedNo
LEFT JOIN PatientAdmission d ON a.BranchId = d.BranchId AND a.PatientId = d.PatientId
WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.PatientId = @PatientId
GROUP BY c.SubSubPno, a.PatientId, a.RegNo, a.PatientName, a.BedNo, a.Gender, a.Age, d.UnderDrCode, d.UnderDrName, a.ReceiptNo, a.ReceiptDate, a.EntryDateTime, d.PatientAddress, b.Mobile, a.DriverName, a.AmbulanceNo, a.DestinationFrom, a.DestinationTo, a.MeterFrom, a.MeterTo, a.UserName
END
GO
