CREATE Procedure [dbo].[SP_IndoorBirth_Certificate] @BranchId int ,@CertNo nvarchar(50),@CertDate nvarchar(50)
AS
	BEGIN
	Select BirthCertificateNo, BirthCertificateDate, PatientId, BedNo, BabyName, BabySex, BirthDate, 
	LTRIM(RIGHT(BirthTime, 11)) AS BirthTime, Weight,Religion, FathersName, FathersOccupation, FatherNIDNo, 
	MothersName, MothersOccupation, MotherNIDNo, PresentAddress, PermanentAddress, 
	NameOfConsultant+' '+ISNULL(b.Degree,'') AS NameOfConsultant, ModeOfDelivery, EntryDateTime, a.UserName
	from HospitalBirthCertificate a
	LEFT JOIN DrInfo b ON a.BranchId = b.BranchId aND a.ConsultantCode = b.DrCode
	WHERE Valid=1 AND a.BranchId=@BranchId AND Valid=1 AND BirthCertificateNo=@CertNo AND BirthCertificateDate=@CertDate
	END
