/****** Object:  StoredProcedure [dbo].[SP_IndoorCurrPtnDrDeptWise]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



--23042025 MrId, Name Add
create PROC [dbo].[SP_IndoorCurrPtnDrDeptWise] @BranchId INT, @fromDate VARCHAR(20), @toDate VARCHAR(20), @drCode varchar(50), @status VARCHAR(30), @floorNo VARCHAR(50)
AS 
BEGIN	/* EXEC SP_IndoorCurrPtnDrDeptWise 1, '2025-01-01', '2025-02-01', '', 'All', '' */

	--- Written BY Zahid
	DECLARE @isRelease INT = 0;
	If @fromDate = '' BEGIN SET @fromDate = '2020-01-01' END;
	If @toDate = '' BEGIN SET @toDate = FORMAT(GETDATE(), 'yyyy-MM-dd') END;
	IF @status = 'All' BEGIN SET @isRelease = 1 END;

	SELECT c.SubSubPno, b.RegNo, b.PatientId, b.AdmissionDate, b.AdmissionTime, b.PatientName, b.PatientSex, b.PatientAge,
	b.PatientAddress, b.DrCode, b.DrName, b.UnderDrCode, b.UnderDrName, b.BedNo, b.Remarks, b.PatientTel, b.AdmittedDept, d.MrId, d.MrName, b.CorporateId, b.CorporateName,
	b.PatientType, c.FloorNo, SUM(a.HBill) AS HBill, SUM(a.DBill) AS DBill, SUM(a.MBill) AS MBill, SUM(a.Collection) AS Advance,
	SUM(a.AdjustAmt) AS AdjustAmt
	FROM (
		SELECT a.BranchId, a.PatientId, SUM(a.TotalAmount-a.Less) AS HBill, 0 AS DBill, 0 AS MBill, 
		SUM(a.Collection-a.ReturnAmt) AS Collection, 0 AS AdjustAmt
		FROM PatientLedger a
		WHERE Valid = 1 AND a.PatientId != '' AND a.BranchId = @BranchId
		GROUP BY a.BranchId, a.PatientId
		UNION
		SELECT a.BranchId, a.PatientId, 0 AS HBill, SUM(a.Sales-a.Less-a.ReturnNet) AS DBill, 0 AS MBill, 
		SUM(a.Collection-a.ReturnCash) AS Collection, SUM(a.AdjustAmt) AS AdjustAmt
		FROM SalesLedger a
		WHERE a.Valid = 1 AND a.PatientId != '' AND a.BranchId = @BranchId
		GROUP BY a.BranchId, a.PatientId
		UNION
		SELECT a.BranchId, a.PatientId, 0 AS HBill, 0 AS DBill, SUM(a.Sales-a.LessAmt-a.DueLess-a.ReturnAmt-a.CashReturn) AS MBill,
		SUM(a.Collection+a.DueColl-a.CashReturn) AS Collection, SUM(a.AdjustAmt) AS AdjustAmt
		FROM PharSalesLedger a
		WHERE a.Valid = 1 AND a.PatientId != '' AND a.BranchId = @BranchId
		GROUP BY a.BranchId, a.PatientId
	) a
	RIGHT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
	RIGHT JOIN BedInformation c ON a.BranchId = c.BranchId AND b.BedNo = c.BedNo
	RIGHT Join CorporateStaff d ON b.CorporateId=d.Id AND a.BranchId=d.BranchId AND d.Valid=1
	WHERE b.BranchId = @BranchId and b.Valid=1 AND b.AdmissionDate BETWEEN @fromDate AND @toDate
	AND c.FloorNo LIKE '%'+@floorNo+'%' AND b.IsRelease IN (0, @isRelease)
	AND case when @drCode='' then '' else b.UnderDrCode end = @drCode
	GROUP BY c.SubSubPno, b.RegNo, b.PatientId, b.AdmissionDate, b.AdmissionTime, b.PatientName, b.PatientSex,
	b.PatientAge, b.PatientAddress, b.DrCode, b.DrName, b.UnderDrCode, b.UnderDrName, b.BedNo, b.Remarks,
	b.PatientTel, b.AdmittedDept, b.PatientType, c.FloorNo, d.MrId, d.MrName, b.CorporateId, b.CorporateName
	ORDER BY b.PatientId

END
GO
