CREATE Procedure [dbo].[SP_IndoorDeath_Certificate] @BranchId int,@DeathCertNo nvarchar(50),@DeathCertDate nvarchar(50)
AS
SELECT a.DeathCertificateNo,a.DeathCertificateDate,a.EntryDateTime,a.PatientId,a.PatientName,a.SpouseName,a.CabinBedNo,a.Sex,a.Age,
a.Address,a.DateOfAdmission,a.TimeOfAdmission,b.ReleaseDate as ReleaseDateTime ,a.DateOfDeath,a.TimeOfDeath,a.NextTokin,a.RelationOfDeceased,a.ImmediateCauseDeath,a.PrimaryCauseDeath,
a.AssociateConditionDeath,a.a,a.b,a.c,a.No1,a.No1Relationship,a.No1Address,a.NIDNo1,
No2,No2Relationship,No2Address,NIDNo2,No3,No3Relationship,No3Address,NIDNo3,a.UserName
FROM HospitalDeathCertificate a, PatientAdmission b--, PatientReleaseMaster b
Where a.PatientId=b.PatientID AND a.Valid=1 AND b.BranchId = @BranchId AND a.DeathCertificateNo=@DeathCertNo AND a.DeathCertificateDate=@DeathCertDate
