CREATE PROC [dbo].[SP_IndoorDiagnosticBillDtls] @PatientId VARCHAR(20), @BranchId INT, @Depertment VARCHAR(20)
AS 
BEGIN /* EXEC SP_IndoorDiagnosticBillDtls 'PA231200281', 1, 'DIAGNOSTIC' */
	SELECT aa.DeptName, aa.InvNo, aa.InvDate, aa.RegNo, aa.PatientId, aa.PatientName, aa.Address, aa.Age, aa.Sex, aa.MobNo, aa.ConsultantCode, aa.ConsultantName, 
	aa.RefDrCode, aa.RefDrName, aa.UserName, aa.EntryTime AS InvDateTime, SUM(cc.Sales) AS Sales, SUM(cc.Less) AS Less, SUM(cc.Collection) AS Collection, 
	aa.ReturnAmt AS ReturnAmount, aa.ReturnLess AS ReturnLess, aa.ReturnDue AS ReturnDue, aa.ReturnCash AS ReturnCash, 
	SUM(cc.Sales-cc.Less-cc.Collection)-aa.ReturnAmt+aa.ReturnCash+aa.ReturnLess AS Due, bb.Department AS BedDepartment, bb.BranchId, bb.Bedno, bb.PatientId, bb.PCode, 
	bb.ShortDesc, bb.Amount, bb.IsReturn, bb.Quantity AS NoU, bb.TotalAmt AS TotalAmt, aa.ProcServiceCharge
	FROM (
	SELECT b.SubSubPno AS Department, a.InvNo, a.InvDate, a.BranchId, a.Bedno, a.PatientId, a.PCode, a.ShortDesc, a.Amount, a.Valid AS IsReturn,
	a.Quantity AS Quantity, SUM(a.Amount*a.Quantity) AS TotalAmt
	FROM InvDetails a
	LEFT JOIN BedInformation b ON a.Bedno = b.BedNo AND a.BranchId = b.BranchId
	WHERE a.BranchId = @BranchId AND a.PatientId = @PatientId AND Valid <> 0 AND a.DeptName = @Depertment
	GROUP BY b.SubSubPno, a.InvNo, a.InvDate, a.BranchId, a.Bedno, a.PatientId, a.PCode, a.ShortDesc, a.Amount, a.Valid, a.Quantity
	) bb
	LEFT JOIN InvMaster aa ON bb.BranchId = aa.BranchId AND bb.InvDate = aa.InvDate AND bb.InvNo = aa.InvNo AND aa.Valid = 1 AND aa.PatientId = bb.PatientId
	LEFT JOIN SalesLedger cc ON bb.BranchId = cc.BranchId AND bb.InvDate = cc.PreInvDate AND bb.InvNo = cc.PrevInvNo AND cc.Valid = 1 AND aa.PatientId = cc.PatientId
	WHERE aa.BranchId = @BranchId AND aa.PatientId = @PatientId AND aa.DeptName = @Depertment
	GROUP BY aa.DeptName, aa.InvNo, aa.InvDate, aa.RegNo, aa.PatientId, aa.PatientName, aa.Address, aa.Age, aa.Sex, aa.MobNo, aa.ConsultantCode, aa.ConsultantName, 
	aa.RefDrCode, aa.RefDrName, aa.UserName, aa.EntryTime, bb.Department, bb.BranchId, bb.Bedno, bb.PatientId, bb.PCode, bb.ShortDesc, bb.Amount, bb.IsReturn, 
	aa.ReturnAmt, aa.ReturnLess, aa.ReturnDue, aa.ReturnCash, bb.Quantity, bb.TotalAmt, aa.ProcServiceCharge
	ORDER by invno, PCode
END
GO
