CREATE Procedure [dbo].[SP_IndoorDischarge_Medicine] @BranchId int, @DiscertNo nvarchar(50), @DiscertDate nvarchar(50)
AS  ---  Exec SP_IndoorDischarge_Medicine 1,'NDC241100003','2024-11-18'

SELECT MedicineName, b.ProductNameFull AS Generic, DoseInfo, Days, c.Name AS ProductGroup
FROM HospitalDischargeMedicine a
LEFT JOIN PharProductInfo b on a.MedicineName=b.ProductName
LEFT JOIN PharPdGroup c on b.ProductGroup=c.Id
WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.DischargeNo =  @DiscertNo AND a.DischargeDate = @DiscertDate
UNION ALL
SELECT MedicineName, b.ProductNameFull AS Generic, DoseInfo, Days, c.Name AS ProductGroup
FROM PatientDischargeTreatment a
LEFT JOIN PharProductInfo b on a.MedicineName=b.ProductName
LEFT JOIN PharPdGroup c on b.ProductGroup=c.Id
WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.DischargeNo =  @DiscertNo AND a.DischargeDate = @DiscertDate
UNION ALL
SELECT MedicineName, b.ProductNameFull AS Generic, DoseInfo, Days, c.Name AS ProductGroup 
FROM NICUPatientDischargeTreatment a
LEFT JOIN PharProductInfo b on a.MedicineName=b.ProductName
LEFT JOIN PharPdGroup c on b.ProductGroup=c.Id
WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.DischargeNo =  @DiscertNo AND a.DischargeDate = @DiscertDate
GO
