CREATE PROC [dbo].[Sp_IndoorDiscountRpt] @BranchId INT, @DateFrom VARCHAR(20), @DateTo VARCHAR(20)
AS
BEGIN /* EXEC Sp_IndoorDiscountRpt 1, '2023-12-05', '2023-12-25' */

select aa.RegNo, aa.PatientId, aa.PatientName, aa.BedNo, aa.Remarks, SUM(aa.ReleaseLess) AS ReleaseLess, SUM(aa.DueLess) AS DueLess, aa.UserName from(
SELECT a.RegNo, a.PatientId, b.PatientName, b.BedNo, a.Remarks, SUM(a.Less) AS ReleaseLess, 0 AS DueLess, a.UserName
FROM PatientLedger a, PatientAdmission b
WHERE a.BranchId  = @BranchId AND a.Valid = 1 AND a.Less != 0 AND a.Status = 'Patient Release' and a.PatientId=b.PatientId
AND a.RefDate BETWEEN @DateFrom AND @DateTo
group by a.RegNo, a.PatientId, b.PatientName, b.BedNo, a.Remarks, a.UserName
UNION ALL
SELECT a.RegNo, a.PatientId, b.PatientName, b.BedNo, a.Remarks,  0 AS ReleaseLess, SUM(a.Less) AS DueLess, a.UserName
FROM PatientLedger a, PatientAdmission b
WHERE a.BranchId  = @BranchId AND a.Valid = 1 AND a.Less != 0 AND a.Status = 'Indoor Due Collection' and a.PatientId=b.PatientId
AND a.RefDate BETWEEN @DateFrom AND @DateTo
group by a.RegNo, a.PatientId, b.PatientName, b.BedNo, a.Remarks, a.UserName
UNION ALL
SELECT a.RegNo, a.PatientId, b.PatientName, b.BedNo, a.Remarks,  SUM(a.Less) AS ReleaseLess, 0 AS DueLess, a.UserName
FROM SalesLedger a, PatientAdmission b
WHERE a.BranchId  = @BranchId AND a.Valid = 1 AND a.Less != 0 and a.PatientId=b.PatientId
AND a.RefDate BETWEEN @DateFrom AND @DateTo
group by a.RegNo, a.PatientId, b.PatientName, b.BedNo, a.Remarks, a.UserName) aa
group by  aa.RegNo, aa.PatientId, aa.PatientName, aa.BedNo, aa.Remarks, aa.UserName
END

GO
