CREATE PROC [dbo].[SP_IndoorDrPaymentBill] @BranchId INT, @RefNo VARCHAR(20)
AS /* EXEC SP_IndoorDrPaymentBill 1, 'DP221100003' */
SELECT a.EntryDateTime AS RefDate, a.RefNo, a.PatientId, a.PatientName, a.BedNo, a.DrCode, b.DrName,
a.PCode, a.Particulars, a.PaidAmt, a.CashAmt, a.ChequeAmt, a.ChequeNo, a.ChequeDate, a.ChequeBank, a.UserName
FROM IndoorDrLedger a
LEFT JOIN DrInfo b ON a.BranchId = b.BranchId ANd a.DrCode = b.DrCode
where a.BranchId = @BranchId AND a.Valid = 1 AND RefNo = @RefNo

GO
