create PROC [dbo].[SP_IndoorDrPaymentPtnList] @BranchId INT, @DrCode VARCHAR(50), @DateFrom DATE, @DateTo DATE
AS /* EXEC SP_IndoorDrPaymentPtnList 1, 'DR', '2022-11-05','2022-11-05' */
SELECT TOP 50 b.DrCode, b.DrName, b.DeptName, b.Degree, SUM(a.DrAmt) AS DrAmt, SUM(a.PaidAmt) AS PaidAmt, SUM(a.LessAmt) AS LessAmt, SUM(a.DrAmt-a.PaidAmt-a.LessAmt) AS Due
FROM DrInfo b
LEFT JOIN IndoorDrLedger a ON a.BranchId = b.BranchId AND a.DrCode = b.DrCode AND b.Status = 1 
WHERE a.BranchId = @BranchId AND a.Valid = 1 AND b.DrCode+b.DrName+b.Degree LIKE '%'+@DrCode+'%' --AND a.RefDate BETWEEN @DateFrom AND @DateTo 
GROUP BY b.DrCode, b.DrName, b.DeptName, b.Degree
HAVING SUM(a.DrAmt-a.PaidAmt-a.LessAmt) != 0
GO
