CREATE PROC [dbo].[Sp_IndoorDrPaymentReportDtls] @BranchId INT, @FromDate DATE, @ToDate DATE, @DrCode VARCHAR(10), @PCode nvarchar(50)
AS /* EXEC Sp_IndoorDrPaymentReportDtls 1, '2024-09-10', '2024-09-18', '','' */
BEGIN
	SELECT '' AS RefNo, b.ReleaseDate AS RefDate, a.PatientId, b.PatientName, b.PatientSex, b.PatientTel, b.BedNo, a.DrCode, c.DrName, c.DrName+''+c.Degree AS DrFullName,
	a.PCode, d.Description, SUBSTRING((SELECT DISTINCT ', ' + UserName  FROM IndoorDrLedger where PatientId = a.PatientId FOR XML PATH('')), 2 , 100) As UserName,
	(CASE WHEN b.IsApplicableDrPayment = 0 THEN 'Due' ELSE 'Paid' END) AS IsApplicableDrPayment,
	GETDATE() AS PaidDate, SUM(a.DrAmt) AS DrAmt, SUM(a.LessAmt) AS LessAmt, (CASE WHEN SUM(a.DrAmt) > 0 THEN SUM(a.DrAmt) - sum(a.LessAmt) ELSE '0' END) AS CutLessDrAmt,
	(CASE WHEN  SUM(a.DrAmt) > 0 THEN ((SUM(a.DrAmt) - SUM(a.LessAmt)) * 10/100) ELSE '0' END) as TaxAmt, 
	CASE WHEN SUM(a.DrAmt) > 0 THEN  SUM(a.DrAmt) - sum(a.LessAmt) - (SUM(a.DrAmt) - SUM(a.LessAmt))* 10/100 ELSE '0' END as AfterTaxDrAmt,
	SUM(a.PaidAmt) AS PaidAmt, 
	CASE WHEN SUM(a.DrAmt) > 0 THEN (SUM(a.DrAmt) - sum(a.LessAmt) - (SUM(a.DrAmt) - SUM(a.LessAmt))* 10/100) - sum(a.PaidAmt) ELSE '0' END as Due
	FROM IndoorDrLedger a
	LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId=b.PatientId
	LEFT JOIN DrInfo c ON a.BranchId = c.BranchId AND a.DrCode=c.DrCode
	LEFT JOIN ClinicalChart d On a.BranchId = d.BranchId AND a.PCode=d.PCode
	WHERE a.valid=1 AND a.BranchId = @BranchId AND a.DrCode LIKE '%'+@DrCode+'%' AND a.PCode LIKE '%'+@PCode+'%' AND
	--b.IsApplicableDrPayment=1 AND 
	(CASE WHEN b.IsApplicableDrPayment = 1 THEN b.ApplicableDateDrPayment ELSE b.ReleaseDate END)  BETWEEN @FromDate AND @ToDate
	GROUP BY b.ReleaseDate, a.PatientId, b.PatientName, b.PatientSex, b.PatientTel, b.BedNo, a.DrCode, c.DrName, c.Degree,
	a.PCode, d.Description, b.IsApplicableDrPayment
END
GO
