CREATE PROCEDURE [dbo].[Sp_IndoorDrPaymentReportDtlsSMZ] @BranchId int , @FromDate Date, @ToDate date, @DrCode VARCHAR(10), @PCode nvarchar(10)
AS ----   EXEC Sp_IndoorDrPaymentReportDtlsSMZ 1, '2024-01-01', '2024-01-31', '0066','0258'
BEGIN


select  a.DrCode, c.DrName, c.DrName + '' + c.Degree as DrFullName,
a.PCode, d.Description, SUM(a.DrAmt) AS DrAmt, sum(a.LessAmt) as LessAmt, SUM(a.DrAmt) - SUM(a.LessAmt) as CutLessDrAmt, 
(SUM(a.DrAmt) - SUM(a.LessAmt))* 10/100 as Tax, 
 SUM(a.DrAmt) - sum(a.LessAmt) - (SUM(a.DrAmt) - SUM(a.LessAmt))* 10/100  as AfterTaxDrAmt,
 SUM(a.PaidAmt) AS PaidAmt, 
(SUM(a.DrAmt) - sum(a.LessAmt) - (SUM(a.DrAmt) - SUM(a.LessAmt))* 10/100) - sum(a.PaidAmt) as Due
from IndoorDrLedger a
LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
LEFT JOIN DrInfo c ON a.BranchId = b.BranchId AND a.DrCode = c.DrCode
LEFT JOIN ClinicalChart d On a.PCode=d.PCode AND a.Valid=d.Status
where a.Valid = 1   AND a.BranchId = @BranchId  AND b.IsRelease =1  AND  b.ReleaseDate between @FromDate AND @ToDate AND a.DrCode + a.PCode LIKE '%'+@DrCode+'%'+ @PCode
 --a.PaidDate BETWEEN @FromDate AND @ToDate
GROUP BY  a.DrCode, c.DrName, c.Degree, a.PCode, d.Description
HAVING SUM(DrAmt) > 0 OR SUM(LessAmt) > 0 OR SUM(PaidAmt) > 0 
ORDER BY DrCode , PCode
END
GO
