CREATE PROCEDURE [dbo].[SP_IndoorDrUnpaidPtnList] @BranchId INT, @DrCode VARCHAR(50)
AS /* EXEC SP_IndoorDrUnpaidPtnList 1, 'DR0022' */
SELECT PatientId, PatientName, BedNo, DrCode, PCode, Particulars, SUM(DrAmt) AS DrAmt, SUM(PaidAmt) AS PaidAmt, SUM(LessAmt) AS LessAmt, SUM(DrAmt-PaidAmt-LessAmt) AS Due
FROM IndoorDrLedger
WHERE BranchId = @BranchId AND DrCode = @DrCode
GROUP BY PatientId, PatientName, BedNo, DrCode, PCode, Particulars
HAVING SUM(DrAmt-PaidAmt-LessAmt) != 0
