CREATE PROC [dbo].[SP_IndoorDrVisitBillDtls] @PatientId VARCHAR(20), @BranchId INT
AS /* EXEC SP_IndoorDrVisitBillDtls 'PA221200006', 1 */

/* GET Dr Paid Amount*/
SELECT RefDate, BranchId, DrCode, PCode, SUM(PaidAmt) AS PaidAmt INTO #z
FROM IndoorDrLedger WHERE
BranchId = @BranchId AND PatientId = @PatientId AND Valid = 1
group by RefDate, BranchId, DrCode, PCode
having SUM(PaidAmt) != 0
/* END Dr Paid Amount*/

SELECT c.Description AS Department, a.RefNo, a.RefDate, a.RegNo, b.BedNo, a.PatientId, a.PatientName, b.DrCode AS RefDrCode, b.DrName AS RefDrName,
b.UnderDrCode, b.UnderDrName, b.PatientAge, b.PatientSex, b.PatientAddress, b.PatientTel,
a.UserName, FORMAT(a.EntryDateTime, 'yyyy-MM-dd hh:mm:ss') AS EntryDateTime, a.Code, c.Description AS Particulars, a.DrCode,
a.DrName, a.Charge, SUM(a.NoU) AS NoU, SUM(a.NoU*a.Charge) AS TotalAmount, SUM(a.ServiceCharge) AS ServiceCharge,
SUM(a.NoU*a.Charge+a.ServiceCharge) AS TotalAmt, ISNULL(d.PaidAmt,0) AS DrPaidAmt
FROM PatientLedger a
LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
LEFT JOIN ClinicalChart c ON a.BranchId = c.BranchId AND a.Code = c.PCode
LEFT JOIN #z d ON a.BranchId = d.BranchId AND a.DrCode = d.DrCode AND a.Code = d.PCode AND a.RefDate = d.RefDate
WHERE a.BranchId = @BranchId AND a.PatientId = @PatientId AND a.Valid = 1 AND a.Status = 'Procedure Entry For Dr'
GROUP BY a.Status, a.RefNo, a.RefDate, a.RegNo, b.BedNo, a.PatientId, a.PatientName, a.UserName, FORMAT(a.EntryDateTime, 'yyyy-MM-dd hh:mm:ss'),
a.Code, c.Description, a.DrCode, a.DrName, a.Charge, b.DrCode, b.DrName, b.UnderDrCode, b.UnderDrName,
b.PatientAge, b.PatientSex, b.PatientAddress, b.PatientTel, d.PaidAmt
ORDER BY a.RefDate


GO
