CREATE PROCEDURE [dbo].[SP_IndoorDueCollBillDeptWise] @BranchId INT, @PatientId VARCHAR(20), @ReceiptNo VARCHAR(20), @ReceiptDate DATE
AS /* EXEC SP_IndoorDueCollBillDeptWise 1, 'PA2209904730', 'DC2210000017','2022-10-22' */
	SELECT d.SubSubPno AS DeptName, a.RefDate, a.RefNo, a.PatientId, a.RegNo, a.PatientName, a.BedNo, a.PrevDues, a.Less AS TotalLess,
	a.Collection, a.RestDue, a.CashAmt, a.CardAmt, a.ChequeAmt, a.CardNo, a.CardBank, a.ChequeNo, a.ChequeBank, a.ChequeDate,
	a.UserName, a.EntryDateTime AS PaymentDateTime, c.EntryDateTime AS AdmissionDate, c.PatientSex, c.PatientAge,
	c.PatientAddress, c.DrCode, c.DrName, c.UnderDrCode, c.UnderDrName, e.EntryDateTime AS ReleaseDate, c.Religion, a.Remarks, b.Code, b.Particulars, b.NoU, b.Sales, b.PrevLess, b.Less, b.NetSales,
	ISNULL(SUBSTRING(( SELECT OperationName + CHAR(10) FROM OTScheduleMaster WHERE PatientId = a.PatientID AND BranchId = a.BranchId and Valid = 1 FOR XML PATH('')), 0 , 1000),'') As OtName,
	ISNULL(SUBSTRING(( SELECT OperationType + CHAR(10) FROM OTScheduleMaster WHERE PatientId = a.PatientID AND BranchId = a.BranchId and Valid = 1 FOR XML PATH('')), 0 , 1000),'') As OtType
	FROM IndoorDueCollMaster a
	LEFT JOIN IndoorDueCollDetails b ON a.BranchId = b.BranchId AND a.RefDate = b.RefDate AND a.RefNo = b.RefNo AND a.PatientId = b.PatientId
	LEFT JOIN PatientAdmission c ON a.BranchId = c.BranchId AND a.PatientId = c.PatientId AND c.IsRelease = 1
	LEFT JOIN BedInformation d ON b.BranchId = d.BranchId AND b.BedNo = d.BedNo
	LEFT JOIN PatientReleaseMaster e ON a.BranchId = e.BranchId AND a.PatientId = e.PatientID AND e.Valid = 1
	WHERE a.BranchId = 1 AND a.Valid = 1 AND a.RefDate = @ReceiptDate AND a.RefNo = @ReceiptNo AND a.PatientId = @PatientId
GO
