CREATE PROC [dbo].[Sp_IndoorDueCollBillOasis] @BranchId INT, @RefNo VARCHAR(50)
AS
	BEGIN /* Sp_IndoorDueCollBillOasis 1, 'DC231200010' */
		select a.RefDate, a.RefNo, a.PatientId, a.PatientName, a.BedNo, a.PrevDues, a.Less, a.Collection, a.RestDue, a.ChequeAmt, a.CardAmt, a.ChequeAmt, 
		a.CardNo, a.CardBank, a.ChequeNo, a.ChequeDate, a.ChequeBank, a.UserName, a.Remarks, a.EntryDateTime, b.SubSubPno AS Department, c.PatientTel, 
		c.EntryDateTime as AdmissionDateTime, c.PatientAddress, c.PatientSex, c.PatientAge, c.DrCode, c.DrName+''+d.Degree AS DrName, c.UnderDrCode, c.UnderDrName+''+e.Degree AS UnderDrName
		from IndoorDueCollMaster a
		left join BedInformation b on a.BranchId = b.BranchId and a.BedNo = b.BedNo
		left join PatientAdmission c on c.BranchId = a.BranchId and c.PatientId = a.PatientId
		left join DrInfo d on d.BranchId = c.BranchId and d.DrCode = c.DrCode
		left join DrInfo e on e.BranchId = c.BranchId and e.DrCode = c.DrCode
		where a.BranchId = @BranchId AND a.Valid = 1 AND a.RefNo = @RefNo
	END
GO
