CREATE Proc [dbo].[Sp_IndoorGetPtnLedgerOasis] @BranchId int, @PatientId VARCHar(50)
AS
BEGIN /* Sp_IndoorGetPtnLedgerOasis 1, 'PA231200292' */
	SELECT 1 AS SlNo, a.Code, a.Particulars, a.DrCode, a.Charge, SUM(a.NoU) AS NoU, SUM(a.NoU*a.Charge) as TotalCharge, SUM(a.ServiceCharge) AS ServiceCharge, 
	SUM(a.NoU*a.Charge+a.ServiceCharge) AS Due, SUM(a.Less) AS PrevLess, a.BedNo, a.ChangedBedId,
	(CASE WHEN a.Status = 'Procedure Entry For Dr' THEN 2 ELSE 1 END) AS Sl
	from PatientLedger a 
	where a.BranchId = @BranchId and a.Valid = 1 and a.PatientId = @PatientId
	GROUP BY a.Code, a.Particulars, a.DrCode, a.Charge, a.BedNo, a.ChangedBedId, a.Status
	UNION ALL
	select 2 AS SlNo, '0011' AS Code, a.Department AS Particulars, '' AS DrCode, SUM(a.Sales-a.ReturnAmount) AS Charge, 1 AS NoU, 
	SUM(a.Sales-a.ReturnAmount) AS TotalAmt, SUM(a.ProcServiceCharge) aS ServiceCharge, 
	SUM(a.Sales+a.ProcServiceCharge-a.Less-Collection-ReturnDue) AS Due, SUM(a.Less-a.ReturnLess) AS PrevLess, a.BedNo, a.ChangedBedId, 5 AS Sl
	from SalesLedger a
	where a.BranchId = @BranchId and a.Valid = 1 and PatientId = @PatientId and Department != 'ambulance'
	group by a.Department, a.BedNo, a.ChangedBedId
	UNION alL
	select 3 aS SlNo, '0011' AS Code, 'Ambulance', '' AS DrCode, a.TotalCharge AS Charge, 1 AS NoU, a.TotalCharge AS TotalAmt,  a.ProcServiceCharge AS ServiceCharge,
	(a.TotalCharge+a.ProcServiceCharge-a.ReceiveAmt-a.Less) AS Due, a.Less AS PrevLess, a.BedNo, b.Id ChangedBedId, 7 AS Sl
	from AmbulanceLedger a
	left join ChangeBedInfo b on b.BranchId = a.BranchId and b.PatientId = a.PatientId and b.BedNo = a.BedNo
	where a.BranchId = @BranchId and a.Valid = 1 and a.PatientId = @PatientId
	UNION ALL
	select 8 AS SlNo, '0014' AS Code, 'Meal Charge' AS Particulars, '' AS DrCode, SUM(a.GrandTotal) AS Charge, 1 AS NoU, SUM(a.GrandTotal) AS TotalAmt, SUM(ProcServiceCharge) AS ServiceCharge,
	SUM(a.GrandTotal-a.FixedLessAmt-a.GeneralLessAmt-a.TotalCollection) AS Due, 0 AS PrevLess, a.BedNo, a.ChangedBedId, 8 AS Sl
	from CanteenSalesLedger a
	WHERE a.BranchId = @BranchId and a.Valid = 1 and a.PatientId = @PatientId
	GROUP BY a.BedNo, a.ChangedBedId
END
GO
