create PROC [dbo].[Sp_IndoorHistory] @BranchId INT, @DateFrom DATE, @DateTo DATE, @Param VARCHAR(20)
AS
BEGIN /* EXEC Sp_IndoorHistory 1, '2022-01-01', '2023-01-20', 'RefDr' */
/* Start Pharmacy */
SELECT DISTINCT a.BranchId, a.PatientId, 'Medicine' AS Particulars 
INTO #z
FROM PatientAdmission a
LEFT JOIN PharSalesLedger b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId AND b.Valid = 1
WHERE a.BranchId = @BranchId AND a.AdmissionDate BETWEEN @DateFrom AND @DateTo AND b.PatientId IS NOT NULL
/* End Pharmacy */

/* Start Outdoor */
UNION ALL
SELECT DISTINCT a.BranchId, a.PatientId, b.Department AS Particulars 
FROM PatientAdmission a
LEFT JOIN SalesLedger b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId AND b.Valid = 1
WHERE a.BranchId = @BranchId AND a.AdmissionDate BETWEEN @DateFrom AND @DateTo AND b.PatientId IS NOT NULL
/* End Outdoor */

/* Start Indoor */
UNION ALL
SELECT DISTINCT a.BranchId, a.PatientId, (CASE WHEN b.Status = 'Procedure Entry For Dr' THEN 'Doctor Visit' ELSE b.Status END) AS Particulars 
FROM PatientAdmission a
LEFT JOIN PatientLedger b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId AND b.Valid = 1
WHERE a.BranchId = @BranchId AND a.AdmissionDate BETWEEN @DateFrom AND '2023-01-15' 
AND b.Status NOT IN ('Auto Generate', 'Advance Collection','Patient Release', 'Indoor Due Collection') 
AND b.PatientId IS NOT NULL
/* End Indoor */

/* Start Indoor History */
SELECT (CASE WHEN @Param = 'RefDr' THEN a.DrCode ELSE a.UnderDrCode END) AS DrCode, (CASE WHEN @Param = 'RefDr' THEN a.DrName ELSE a.UnderDrName END) AS DrName,
a.RegNo, a.PatientId, a.EntryDateTime AS AdmissionDate, a.PatientName, a.PatientSex AS Gender,a.BedNo, a.UserName AS AdmittedBy, c.UserName AS ReleasedBy,
a.PatientTel AS MobileNo, a.PatientAddress, a.Remarks AS AdmissionRemarks, b.SubSubPno AS Department, c.ReleaseDate, c.EntryDateTime AS ReleaseDateTime,
SUBSTRING((SELECT Particulars+','+SPACE(3) FROM #z where BranchId = a.BranchId AND PatientId = a.PatientId FOR XML PATH('')), 1, 1000) As Particulars
FROM PatientAdmission a
LEFT JOIN BedInformation b ON a.FirstBedNo = b.BedNo
LEFT JOIN PatientReleaseMaster c ON a.BranchId = b.BranchId AND a.PatientId = c.PatientID AND c.Valid = 1
WHERE a.BranchId = @BranchId AND a.AdmissionDate BETWEEN @DateFrom AND @DateTo
/* End Indoor History */

END
GO
