CREATE PROC [dbo].[Sp_IndoorIncomeRptUserWise] @BranchId int, @DateFrom varchar(20), @DateTo VARCHAR(20), @UserName VARCHAR(20)
AS
BEGIN /* EXEC Sp_IndoorIncomeRptUserWise 1, '2022-12-01', '2022-12-31', 'MAHAFUJA' */
select a.RefDate, a.RefNo, a.PatientId, a.RegNo, a.PatientName, a.BedNo, a.Collection AS Advance,
0 AS RColl, 0 AS DueColl, a.ReturnAmt, a.CashAmt, a.CardAmt, a.ChequeAmt, a.UserName
from PatientLedger a
WHERE a.BranchId = @BranchId ANd a.Valid = 1 AND a.RefDate BETWEEN @DateFrom AND @DateTo
AND a.Collection+a.ReturnAmt != 0 AND a.Status = 'Advance Collection' AND a.UserName like '%'+@UserName+'%'
UNION ALL
select a.RefDate, a.RefNo, a.PatientId, a.RegNo, a.PatientName, a.BedNo, 0 AS Advance,
a.Collection AS RColl, 0 AS DueColl, a.ReturnAmt, a.CashAmt, a.CardAmt, a.ChequeAmt, a.UserName
from PatientLedger a
WHERE a.BranchId = @BranchId ANd a.Valid = 1 AND a.RefDate BETWEEN @DateFrom AND @DateTo
AND a.Collection+a.ReturnAmt != 0 AND a.Status = 'Patient Release' AND a.UserName like '%'+@UserName+'%'
UNION ALL
select a.RefDate, a.RefNo, a.PatientId, a.RegNo, a.PatientName, a.BedNo, 0 AS Advance,
0 AS RColl, a.Collection AS DueColl, a.ReturnAmt, a.CashAmt, a.CardAmt, a.ChequeAmt, a.UserName
from PatientLedger a
WHERE a.BranchId = @BranchId ANd a.Valid = 1 AND a.RefDate BETWEEN @DateFrom AND @DateTo
AND a.Collection+a.ReturnAmt != 0 AND a.Status = 'Indoor Due Collection' AND a.UserName like '%'+@UserName+'%'

END
  
GO
