CREATE PROCEDURE [dbo].[Sp_IndoorIndentMedicineList] @BranchId INT, @RefNo VARCHAR(30), @RefDate DATE, @RegNo VARCHAR(30), @StoredId INT
AS
BEGIN
	SELECT a.RefDate, a.RefNo, b.PatientId, a.UserName, a.BranchId, a.RegNo, b.BedNo, e.Department,  b.PatientAge, b.PatientSex, 
	b.PatientName, d.Id, d.ProductName, (CASE WHEN SUM(ISNULL(c.CurrentStock, 0)) < a.Qty THEN 0 ELSE SUM(ISNULL(c.CurrentStock,0))-a.Qty END) AS AvailableStock, 
	a.Qty AS ReqQty, d.SalePrice, b.AdmissionDate, b.PatientTel, a.Qty*d.SalePrice AS SubTotal, d.CompanyId, 
	d.TP AS PPrice, c.StoreId, d.ReminderStock, MAX(a.EntryDateTime) AS EntryDateTime,
	SUM(ISNULL(c.CurrentStock,0)) AS CurrentStock, d.ProductNameFull Generic, b.UnderDrCode, b.UnderDrName
	FROM CommonMedicine a
	LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.RegNo = b.RegNo AND b.Valid = 1 AND b.IsRelease = 0
	LEFT JOIN PharProductInfo d ON a.ProductId=d.Id
	LEFT JOIN VW_PharCurrentStock c ON a.BranchId = c.BranchId AND d.Id = c.Id AND c.StoreId=@StoredId 
	LEFT JOIN IndoorMedicineReqMaster e On a.RefNo=e.RequistionNo AND a.BranchId=e.BranchId
	WHERE a.BranchId=@BranchId and a.RefNo=@RefNo AND a.RegNo=@RegNo AND a.RefDate=@RefDate AND a.IsDone = 0 AND e.Valid=1 AND a.Status = 'Indoor Medicine Requsition' 
	AND a.DoneBy IS NULL AND b.PatientId IS NOT NULL
	GROUP BY a.RefDate, a.RefNo, b.PatientId, a.UserName, a.BranchId, a.RegNo, b.BedNo, e.Department, b.PatientAge, b.PatientSex, b.PatientName, 
	d.Id, d.ProductName, a.Qty, d.SalePrice, a.Qty*d.SalePrice, d.CompanyId, d.TP, c.StoreId, d.ReminderStock, d.ProductNameFull, b.AdmissionDate, b.PatientTel,
	b.UnderDrCode, b.UnderDrName
END
GO
