CREATE PROC [dbo].[Sp_IndoorItemWiseSales] @BranchId INT, @DateFrom DATE, @DateTo DATE, @pCode VARCHAR(20)
AS
BEGIN /* EXEC Sp_IndoorItemWiseSales 1, '2020-01-05','2025-12-11', 'Oxygen' */
	SELECT a.Code, b.Description, b.DeptName, b.ReportGroupName SubDeptName, b.SubSubDeptName, a.Charge, SUM(a.TotalAmount) AS TotalSales, 
	SUM(a.NoU) AS Qty, SUM(a.ServiceCharge) AS ServiceCharge
	FROM PatientLedger a
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.Code = b.PCode
	WHERE a.BranchId = @BranchId AND a.RefDate BETWEEN @DateFrom AND @DateTo and NoU != 0 AND ReportGroupName LIKE '%'+@pCode+'%'
	GROUP BY a.Code, a.Charge, b.Description, b.DeptName, b.ReportGroupName, b.SubSubDeptName
	HAVING SUM(a.TotalAmount) != 0
END

