CREATE PROC [dbo].[Sp_IndoorItemWiseSalesPatientwise] @BranchId INT, @DateFrom DATE, @DateTo DATE, @pCode VARCHAR(20)
AS
BEGIN /* EXEC [Sp_IndoorItemWiseSalesPatientwise] 1, '2020-01-05','2025-12-11', '' */
	SELECT a.PatientId, a.PatientName, c.AdmissionDate, a.BedNo, a.DrCode, a.DrName, a.Code, b.Description, 
	b.DeptName, b.ReportGroupName SubDeptName, b.SubSubDeptName, a.Charge, SUM(a.NoU) AS Qty, SUM(a.TotalAmount) AS TotalSales, 
	SUM(a.Less) AS Less, SUM(a.ServiceCharge) AS ServiceCharge, a.DrAmount
	FROM PatientLedger a
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.Code = b.PCode
	LEFT JOIN PatientAdmission c ON a.BranchId = c.BranchId ANd a.PatientId=c.PatientId
	WHERE a.BranchId = @BranchId AND a.RefDate BETWEEN @DateFrom AND @DateTo and NoU != 0 AND ReportGroupName LIKE '%'+@pCode+'%'
	GROUP BY a.PatientId, a.PatientName, c.AdmissionDate, a.BedNo, a.DrCode, a.DrName, a.Code, b.Description, 
	b.DeptName, b.ReportGroupName, b.SubSubDeptName, a.Charge, a.Less, a.DrAmount
	HAVING SUM(a.TotalAmount) != 0
END
