CREATE PROCEDURE [dbo].[SP_IndoorLabReqReport](@BranchId int, @ReqNo nvarchar(20), @ReqDate varchar(20)) 
AS 
Begin  ---  EXEC SP_IndoorLabReqReport 1, 'LR230700001', '2023-07-06'
Select a.RequistionNo, a.RequsitionDate, a.RequsitionTime, a.PatientId, a.EntryDateTime, a.DepartmentName, a.UserName, a.Remarks, a.Department,
b.PCode, b.Description, c.PatientName, c.BedNo, c.UnderDrCode, c.UnderDrName+' '+d.Degree as UnderDrName, c.DrCode, c.DrName+' '+e.Degree AS DrName
From IndoorLabReqMaster a 
