left join PatientAdmission c On a.PatientId=c.PatientId AND a.BranchId=c.BranchId AND c.Valid=1
left join DrInfo d on d.BranchId = a.BranchId and c.UnderDrCode = d.DrCode
left join DrInfo e on e.BranchId = a.BranchId and c.UnderDrCode = e.DrCode
WHERE  a.Valid=1 AND a.BranchId= @BranchId AND a.RequistionNo= @ReqNo AND a.RequsitionDate=@ReqDate
END
