----a.TotalAmt, a.LessAmt+a.ExtraLess, a.AdvanceAmt, a.EntryDateTime, c.PatientAddress, a.RegNo, c.AgeDetail, a.DrCode, e.DrName,
----b.ProductName

----UNION ALL
-- Change By MD Sir 16/08/2023 3:03pm
--SELECT d.SubSubPno AS Department, a.PatientId, a.RegNo, a.PatientName, c.Gender, c.AgeDetail, '' AS DrCode, '' AS DrName, c.TelephoneNo as MobNo,
--a.ReturnNo, a.ReturnDate,
---a.TotalRtn/*+SUM(-b.ItemLess)*/ AS Total, -SUM(b.ItemLess) AS Less, 0 AS AdvanceAmt, a.EntryDateTime as InvDateTime, c.PatientAddress as Address,
--b.ProductName, SUM(-b.ProductQty) AS ProductQty, SUM(-b.SalePrice) AS Price,SUM(-ProductQty*b.SalePrice) AS ttl 
--FROM PharSalesReturnMaster a
--LEFT JOIN PharSalesReturnDetails b ON a.ReturnNo = b.ReturnNo AND a.ReturnDate = b.ReturnDate
--LEFT join PatientRegistration c on a.RegNo = c.RegNo
--LEFT JOIN BedInformation d ON a.BedNo = d.BedNo
--WHERE a.PatientId = @PatientId
--GROUP BY d.SubSubPno, a.PatientId, a.RegNo, a.PatientName, c.Gender, c.AgeDetail, c.TelephoneNo, a.ReturnNo, a.ReturnDate,
--a.TotalRtn, a.LessAmt, a.EntryDateTime, c.PatientAddress, b.ProductName


select a.DeptName AS Department, a.PatientId, a.RegNo, c.PatientName PatientName, c.Gender, c.AgeDetail, a.DrCode, e.DrName, c.TelephoneNo as MobNo, a.SaleNo, a.SaleDate,
a.TotalAmt, SUM(b.ItemLess) AS LessAmt, a.AdvanceAmt, 
a.EntryDateTime as InvDateTime, c.PatientAddress as Address,
b.ProductName, SUM(b.ProductQty) AS ProductQty, SUM(b.SalePrice) AS Price, SUM(ProductQty*b.SalePrice) AS ttl , 0 as ReturnAmt , 0 as RtnQty
from PharSalesMaster a
left join PharSalesDetails b on a.BranchId = b.BranchId AND a.SaleNo = b.SaleNo ANd a.SaleDate = b.SaleDate AND b.Valid = 1
LEFT join PatientRegistration c on a.BranchId = c.BranchId and a.RegNo = c.RegNo
LEFT JOIN BedInformation d ON a.BranchId = d.BranchId AND a.BedNo = d.BedNo
LEFT JOIN DrInfo e ON a.BranchId = e.BranchId AND a.DrCode = e.DrCode
where a.BranchId = 1 AND a.PatientId = @PatientId ANd a.Valid = 1
GROUP BY a.DeptName, a.PatientId, c.PatientName, c.Gender, c.TelephoneNo, a.SaleNo, a.SaleDate,
a.TotalAmt, a.LessAmt+a.ExtraLess, a.AdvanceAmt, a.EntryDateTime, c.PatientAddress, a.RegNo, c.AgeDetail, a.DrCode, e.DrName,
b.ProductName

UNION ALL


