a.ReturnNo, a.ReturnDate,
-a.TotalRtn/*+SUM(-b.ItemLess)*/ AS Total, -SUM(b.ItemLess) AS Less, 0 AS AdvanceAmt, a.EntryDateTime as InvDateTime, c.PatientAddress as Address,
b.ProductName, 0 AS ProductQty, SUM(b.SalePrice) AS Price, 0 AS ttl, SUM(ProductQty*b.SalePrice) as ReturnAmt , SUM(b.ProductQty) as RtnQty
FROM PharSalesReturnMaster a
LEFT JOIN PharSalesReturnDetails b ON a.ReturnNo = b.ReturnNo AND a.ReturnDate = b.ReturnDate and b.valid = 1
LEFT join PatientRegistration c on a.RegNo = c.RegNo
LEFT JOIN BedInformation d ON a.BedNo = d.BedNo
WHERE a.PatientId = @PatientId
GROUP BY d.SubSubPno, a.PatientId, a.RegNo, c.PatientName, c.Gender, c.AgeDetail, c.TelephoneNo, a.ReturnNo, a.ReturnDate,
a.TotalRtn, a.LessAmt, a.EntryDateTime, c.PatientAddress, b.ProductName

UNION ALL
SELECT c.SubSubPno AS Department, a.PatientId, b.RegNo, b.PatientName, b.PatientSex, b.PatientAge, '' AS DrCode, '' AS DrName, b.PatientTel, a.TrNo, a.TrDate, 0 AS Total, SUM(DueLess) AS LEss, SUM(DueColl) AS AdvanceAmt, TrDate, b.PatientAddress, 'Due Collection' AS ProductName, 0 AS ProductQty, 0 AS Price, 0 Ttl, 0 AS ReturnAmt, 0 AS RtnQty
FROM PharSalesLedger a
LEFT JOIN PatientAdmission b ON a.BranchId=b.BranchId and a.PatientId=b.PatientId
LEFT JOIN BedInformation c ON a.BranchId=c.BranchId AND b.BedNo=c.BedNo
WHERE a.BranchId = @BranchId AND a.PatientId = @PatientId and DueLess+DueColl != 0
GROUP BY c.SubSubPno, a.PatientId, b.RegNo, b.PatientName, b.PatientSex, b.PatientAge, b.PatientTel, a.TrNo, a.TrDate, TrDate, b.PatientAddress


END
