CREATE Procedure [dbo].[SP_IndoorMedicineReqReport] @BranchId int, @RequistionNo nvarchar(20), @RequsitionDate varchar(20)
AS
BEGIN
/* exec SP_IndoorMedicineReqReport 1, 'MR2312030001', '2023-12-03' */
	Select a.RequistionNo, a.RequsitionDate, a.RequsitionTime, a.PatientId, c.PatientName, c.BedNo, a.Department , b.ProductId, b.ProductName, b.ProductQty, 
	a.UserName, a.Remarks, a.ProjectName, a.EntryDateTime, c.patientaddress, c.UnderDrCode, c.UnderDrName+''+d.Degree aS UnderDrName
	From IndoorMedicineReqMaster a 
	left join IndoorMedicineReqDetails b On a.RequistionNo=b.RequistionNo AND a.BranchId=b.BranchId AND b.Valid=1
	left join PatientAdmission c On a.PatientId=c.PatientId AND a.BranchId=c.BranchId
	left join DrInfo d on d.drcode = c.UnderDrCode and d.BranchId = a.BranchId
