CREATE PROC [dbo].[SP_IndoorProcedureBillDtls] @PatientId VARCHAR(20), @BranchId INT
AS /* EXEC SP_IndoorProcedureBillDtls 'PA221106337', 1 */
SELECT a.Status AS Department, a.RefNo, a.RefDate, a.RegNo, b.BedNo, a.PatientId, a.PatientName, b.DrCode AS RefDrCode, b.DrName AS RefDrName,
b.UnderDrCode, b.UnderDrName, b.PatientAge, b.PatientSex, b.PatientAddress, b.PatientTel,
a.UserName, FORMAT(a.EntryDateTime, 'yyyy-MM-dd hh:mm:ss') AS EntryDateTime, a.Code, a.Particulars, a.DrCode,
a.DrName, a.Charge, SUM(a.NoU) AS NoU, SUM(a.NoU*a.Charge) AS TotalAmount, SUM(a.ServiceCharge) AS ServiceCharge,
SUM(a.NoU*a.Charge+a.ServiceCharge) AS TotalAmt, SUM(a.Collection) AS Advance, SUM(a.ReturnAmt) AS ReturnAmt
FROM PatientLedger a
LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
WHERE a.BranchId = @BranchId AND a.PatientId = @PatientId AND a.Valid = 1 AND a.Status != 'Procedure Entry For Dr'
GROUP BY a.Status, a.RefNo, a.RefDate, a.RegNo, b.BedNo, a.PatientId, a.PatientName, a.UserName, FORMAT(a.EntryDateTime, 'yyyy-MM-dd hh:mm:ss'),
a.Code, a.Particulars, a.DrCode, a.DrName, a.Charge, b.DrCode, b.DrName, b.UnderDrCode, b.UnderDrName,
b.PatientAge, b.PatientSex, b.PatientAddress, b.PatientTel
ORDER BY a.RefDate

GO
