/****** Object:  StoredProcedure [dbo].[Sp_IndoorPtnDueListForReleaseTimeColl]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[Sp_IndoorPtnDueListForReleaseTimeColl] @BranchId INT, @param VARCHAR(50)
AS
BEGIN /* Sp_IndoorPtnDueListForReleaseTimeColl 1, 'PA220301353' */

	/*Condition for IsInclude Pharmacy bill*/
	DECLARE @IncludePharmacy INT, @IsIncludePharmacy INT;
	SELECT @IncludePharmacy = PharmacyInclude FROM tbl_ComInfo
	IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END;

	WITH ptns AS
	(
		SELECT aa.PatientId, ISNULL(SUM(Due), 0) AS Due FROM
		(
			SELECT 1 AS SlNo, a.PatientId, SUM(a.TotalAmount-a.Less-a.Collection) AS Due
			FROM PatientLedger a
			WHERE a.BranchId = @BranchId AND Valid = 1 AND a.PatientId != '' AND a.Code NOT IN ('0011', '0009')
			GROUP BY a.PatientId
			HAVING SUM(a.TotalAmount-a.Less-a.Collection) != 0
			UNION
			SELECT 2 AS SlNo, a.PatientId, ISNULL(SUM(a.Sales-a.Less-a.Collection-a.ReturnDue-a.AdjustAmt), 0) AS Due
			FROM SalesLedger a
			WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.PatientId != ''
			GROUP BY a.PatientId
			HAVING ISNULL(SUM(a.Sales-a.Less-a.Collection-a.ReturnDue-a.AdjustAmt), 0) != 0
			UNION
			SELECT 3 AS SlNo, a.PatientId, ISNULL(SUM(a.Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt-a.AdjustAmt), 0) AS Due
			FROM PharSalesLedger a
			WHERE a.BranchId = @BranchId AND a.Valid = @IncludePharmacy AND a.PatientId != ''
			GROUP BY a.PatientId
			HAVING ISNULL(SUM(a.Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt-a.AdjustAmt), 0) != 0
		) aa
		GROUP BY aa.PatientId
	)
	SELECT TOP 1000 a.RegNo, a.PatientId, a.PatientName, a.AdmissionDate, a.AdmissionTime, a.PatientSex, a.PatientAge, a.BedNo, a.PatientTel, a.PatientAddress, c.SubSubPno, a.DrCode, a.DrName, 
	a.UnderDrCode, a.UnderDrName, DATEDIFF(day, a.AdmissionDate, d.ReleaseDate)+1 AS TotalDays, a.PackCode, d.ReleaseDate AS ReleaseDate, d.EntryDateTime AS ReleaseDateTime, b.Due AS Due 
	FROM PatientAdmission a
	LEFT JOIN ptns b ON b.PatientId = a.PatientId
	LEFT JOIN BedInformation c ON c.BranchId = a.BranchId AND c.BedNo = a.BedNo
	LEFT JOIN PatientReleaseMaster d ON a.BranchId = d.BranchId AND a.PatientId = d.PatientID AND d.Valid = 1
	WHERE a.IsRelease = 1 AND a.BranchId = 1 AND b.Due > 0 AND (a.PatientId+a.RegNo+a.PatientName+a.PatientTel) Like '%'+@param+'%'
	ORDER BY a.PatientId
END
GO
/****** Object:  StoredProcedure [dbo].[SP_IndoorPtnProfile]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROC [dbo].[SP_IndoorPtnProfile] @BranchId int, @PatientId VARCHAR(20), @IsIncludePharmacy INT
AS
BEGIN /* EXEC SP_IndoorPtnProfile 1, 'PA230100112', 1 */

	/*Start Condition for IsInclude Pharmacy bill*/
	DECLARE @IncludePharmacy INT;
	IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END
	/*End Condition for IsInclude Pharmacy bill*/

	/*Start Indoor Bill*/
	SELECT SlNo, BedDept, Code, Description, '' AS DrCode, Charge AS Charge, SUM(NoU) AS NoU, SUM(ServiceCharge) AS ServiceCharge,
	SUM((Charge*NoU)+ServiceCharge) AS TotalCharge, SUM(Less) AS Less
	FROM (
		SELECT (CASE WHEN a.Status = 'Procedure Entry For Dr' THEN 2 ELSE 1 END) AS SlNo, b.SubSubPno AS BedDept, a.Code, 
		a.Particulars AS Description, (CASE WHEN a.DrCode = 'N/A' OR a.DrCode = '' THEN '' ELSE a.DrCode END) AS DrCode, 
		a.Charge, a.NoU AS NoU, a.ServiceCharge AS ServiceCharge, a.Less AS Less
		FROM PatientLedger a 
		LEFT JOIN BedInformation b On a.BranchId = b.BranchId AND a.BedNo = b.BedNo
		WHERE a.BranchId = @BranchId AND PatientId = @PatientId AND Valid = 1
	) a
	GROUP BY SlNo, BedDept, Code, Description, Charge
	HAVING SUM(Charge*NoU+ServiceCharge) > 0
	/*End Indoor Bill*/

	/*Start Test Bill*/
	UNION ALL
	SELECT 5 AS SlNo, b.SubSubPno AS BedDept, '0011' AS Code, 
	a.Department AS Description, '' AS DrCode, SUM(a.Sales) AS Charge, 1 AS NoU, 0 AS ServiceCharge, 
	SUM(a.Sales) AS TotalCharge, SUM(a.Less) AS Less
	FROM SalesLedger a
	LEFT JOIN BedInformation b On a.BranchId = b.BranchId AND a.BedNo = b.BedNo
	WHERE a.BranchId = @BranchId AND PatientId = @PatientId AND Valid = 1 AND a.Department != 'Ambulance'
	GROUP BY b.SubSubPno, a.Department
	/*End Test Bill*/

	/*Start Medicine Bill*/
	UNION ALL
	SELECT 6 AS SlNo, b.SubSubPno AS BedDept, '0009' AS Code,
	'Medicine' AS Description, '' AS DrCode, SUM(a.Sales-a.ReturnAmt-a.CashReturn) AS Charge, 1 AS NoU, 0 AS ServiceCharge, 
	SUM(a.Sales-a.ReturnAmt-a.CashReturn) AS TotalCharge, SUM(a.LessAmt+a.DueLess-a.LessAdjust) AS Less
	FROM PharSalesLedger a
	LEFT JOIN BedInformation b On a.BranchId = b.BranchId AND a.BedNo = b.BedNo
	WHERE a.BranchId = @BranchId AND PatientId = @PatientId AND a.Valid = @IncludePharmacy
	GROUP BY b.SubSubPno
	/*End Medicine Bill*/

	/*Start Ambulance Bill*/
	UNION ALL
	SELECT 7 AS SlNo, b.SubSubPno AS BedDept, '0016' AS Code,
	'Ambulance' AS Description, '' AS DrCode, SUM(TotalCharge) AS Charge, 1 AS NoU, 0 AS ServiceCharge, SUM(TotalCharge) AS TotalCharge, SUM(a.Less) AS Less
	FROM AmbulanceLedger a
	LEFT JOIN BedInformation b On a.BranchId = b.BranchId AND a.BedNo = b.BedNo
	WHERE a.BranchId = @BranchId AND PatientId = @PatientId AND Valid = 1
	GROUP BY b.SubSubPno
	/*End Ambulance Bill*/
END
GO
