CREATE PROC [dbo].[SP_IndoorReleaseBill_Oasis] @BranchId INT, @PatientId VARCHAR(20)
AS
BEGIN /* EXEC SP_IndoorReleaseBill_Oasis 1, 'pa231200110' */
	select a.PatientID, a.PatientName, b.PatientAge, b.RegNo, b.PatientTel, b.PatientAddress, b.EntryDateTime AS AdmissionDateTime, b.BedNo, b.PatientSex,
	b.UnderDrCode, b.UnderDrName+' '+d.Degree AS UnderDrName, b.DrCode AS RefDrCode, b.DrName+''+e.Degree AS RefDrName, a.AdmitDepartment,
	Datediff(day, a.AdmissionDate, a.ReleaseDate)+1 AS TotalDay, a.EntryDateTime AS ReleaseDateTime, b.Religion, b.Occupation, b.IsStaff, b.PackCode, b.PackName, 
	b.PatientType, a.PatientStatus, a.AdvanceAmt, a.PrevLessAmt AS PrevLess, a.NetPaymentAmt as ReleaseColl, a.LessAmt AS ReleaseLess, a.ReturnAmt, a.Remarks, a.UserName,
	c.EntryDateTime AS TransferDate, c.UserName AS TransferBy, ISNULL(c.ReleaseDate, a.ReleaseDate) AS TransferReleaseDate, c.BedNo AS TransferBed,	aa.* 
	from (
		select a.BranchId, a.ChangedBedId, a.PatientId, a.BedNo, c.SubSubPno, a.Code, a.Particulars, 
		MAX(a.Charge) AS Charge, SUM(NoU) AS NoU, SUM(a.ServiceCharge) AS ServiceCharge, SUM(a.NoU*a.Charge) AS TotalAmount, 
		SUM(a.Less) AS Less, SUM(a.Collection) AS Collection 
		from PatientLedger a
		left join BedInformation c on c.BranchId = a.BranchId and c.BedNo = a.BedNo
		where a.BranchId = @BranchId and a.PatientId = @PatientId and a.Valid = 1 and a.NoU != 0
		GROUP By a.BranchId, a.ChangedBedId, a.PatientId, a.BedNo, c.SubSubPno, a.Code, a.Particulars--, a.Charge
		union all
		select a.BranchId, a.ChangedBedId, a.PatientId, a.BedNo, b.SubSubPno, '0011' AS Code, a.Department AS Particulars, 
		SUM(a.Sales-a.ReturnAmount) AS Sales, 1 AS NoU, SUM(a.ProcServiceCharge) AS ServiceCharge, SUM(a.Sales-a.ReturnAmount) AS TotalAmount,
		SUM(a.Less) AS Less, SUM(a.Collection-a.ReturnCash) AS Collection
		from SalesLedger a
		left join BedInformation b on b.BranchId = a.BranchId and b.BedNo = a.BedNo
		where a.BranchId = @BranchId and a.PatientId = @PatientId and a.valid = 1 and a.Department != 'Ambulance'
		group by a.BranchId, a.ChangedBedId, a.PatientId, a.BedNo, b.SubSubPno, a.Department
		UnioN ALl
		select a.BranchId, 0 as ChangedBedId, a.PatientId, a.BedNo, b.SubSubPno, '0011' AS Code, 'Ambulance' AS Particulars, 
		a.TotalCharge, 1 AS NoU, a.ProcServiceCharge AS ServiceCharge, a.TotalCharge, a.Less, a.ReceiveAmt Collection 
		from AmbulanceLedger a
		left join BedInformation b on b.BranchId = a.BranchId and b.BedNo = a.BedNo
		where a.BranchId = @BranchId and a.PatientId = @PatientId and valid = 1
	) aa
	left join PatientReleaseMaster a on a.BranchId = aa.BranchId and a.PatientID = aa.PatientId
	left join PatientAdmission b on b.BranchId = a.BranchId and b.PatientId = a.PatientID
	left join ChangeBedInfo c on c.BranchId = a.BranchId and c.id = aa.ChangedBedId
	left join DrInfo d on d.BranchId = a.BranchId and d.DrCode = b.UnderDrCode 
	left join DrInfo e on e.BranchId = a.BranchId and e.DrCode = b.DrCode 
	where a.BranchId = @BranchId AND a.PatientID = @PatientId and a.Valid  =1
	order by aa.ChangedBedId
END
GO
