CREATE PROC [dbo].[SP_IndoorReleaseBillDeptWise] @BranchId int, @PatientId VARCHAR(20)
AS
BEGIN /* EXEC SP_IndoorReleaseBillDeptWise 1, 'PA240700368' */
	select a.PatientID, a.PatientName, b.PatientAge, a.RegNo, b.PatientTel, b.PatientAddress, b.AdmissionDate, b.AdmissionTime, b.BedNo, b.PatientSex,
	b.UnderDrCode, b.UnderDrName+''+d.Degree AS UnderDrName, b.DrCode AS RefDrCode, b.DrName+''+e.Degree AS RefDrName, a.TotalDay, c.MainDeptName AS Department,
	a.EntryDateTime AS ReleaseDateTime, b.Religion, b.Occupation, b.IsStaff, b.PackCode, b.PackName, b.PatientType, c.InvestigationCode AS Code,
	c.SortDescription AS Particulars, c.Charge, c.NoOfUnit AS Unit, c.TotCharge AS TotalAmt, c.LessAmt, c.ServiceCharge, c.NetTotal+c.ServiceCharge AS NetTotal, a.AdvanceAmt, a.PatientStatus,
	a.PrevLessAmt AS PrevLess, a.NetPaymentAmt as ReleaseColl, a.LessAmt AS ReleaseLess, a.ReturnAmt, a.Remarks, a.UserName,

	ISNULL(SUBSTRING(( SELECT OperationName + CHAR(10) FROM OTScheduleMaster WHERE PatientId = a.PatientID AND BranchId = a.BranchId and Valid = 1 FOR XML PATH('')), 0 , 1000),'') As OtName,
	ISNULL(SUBSTRING(( SELECT OperationType + CHAR(10) FROM OTScheduleMaster WHERE PatientId = a.PatientID AND BranchId = a.BranchId and Valid = 1 FOR XML PATH('')), 0 , 1000),'') As OtType

	from PatientReleaseMaster a 
	LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientID = b.PatientId ANd b.Valid = 1 AND b.IsRelease = 1
	LEFT JOIN PatientReleaseDetails c ON a.BranchId = c.BranchId ANd a.PatientID = c.PatientID AND c.Valid = 1
	LEFT JOIN DrInfo d ON a.BranchId = d.BranchId AND b.UnderDrCode = d.DrCode
	LEFT JOIN DrInfo e ON a.BranchId = e.BranchId AND b.DrCode = e.DrCode
	WHERE a.PatientID = @PatientId AND a.Valid = 1 AND a.BranchId = @BranchId

END
GO
