SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[Sp_IndoorReleaseTimeColl] @Id INT
AS
	BEGIN /* EXEC Sp_IndoorReleaseTimeColl 1 */
		SELECT a.RefNo, a.RefDate, a.ReceiveAmount, a.CashAmount, a.CardAmount, a.ChequeAmount, a.CardNo, c.Name AS CardBank, a.ChequeNo, 
		a.ChequeDate, d.Name AS ChequeBank, a.UserName, a.CreatedAt, a.LogDetails, b.RegNo, b.PatientId, b.EntryDateTime AS AdmissionDateTime, 
		b.PatientName, b.PatientSex, b.PatientAge, b.PatientAddress, b.DrCode, b.DrName, b.BedNo, b.PatientTel, b.AdmittedDept, 
		b.UnderDrCode, b.UnderDrName, e.EntryDateTime AS ReleaseDateTime, e.UserName AS ReleaseBy, dbo.fn_IndoorDueAmount(a.BranchId, b.PatientId) AS Due
		FROM ReleaseTimeColl a
		LEFT JOIN PatientAdmission b ON b.id = a.MasterId
		LEFT JOIN BankInfo c ON c.Id = a.CardBankId
		LEFT JOIN BankInfo d ON d.Id = a.ChequeBankId
		LEFT JOIN PatientReleaseMaster e ON e.BranchId = a.BranchId AND e.PatientID = b.PatientId AND e.Valid = 1
		WHERE a.Valid = 1 AND a.Id = @Id
	END
GO
/****** Object:  StoredProcedure [dbo].[SP_IndoorScChargeBillDtls]    Script Date: 3/12/2026 6:25:16 AM ******/
