create PROC [dbo].[SP_IndoorScChargeBillDtls] @PatientId VARCHAR(20), @BranchId INT
AS /* EXEC SP_IndoorScChargeBillDtls 'PA230700094', 1 */
BEGIN
	SELECT c.SubSubPno AS Department, a.RefNo, a.RefDate, a.PatientId, a.RegNo, a.BedNo, a.PatientName, b.DrCode AS RefDrCode, b.DrName AS RefDrName,
	b.UnderDrCode, b.UnderDrName, b.PatientAge, b.PatientSex, b.PatientAddress, b.PatientTel,
	a.UserName, FORMAT(a.EntryDateTime, 'yyyy-MM-dd hh:mm:ss') AS EntryDateTime, a.Code, a.Particulars, a.DrCode,
	a.DrName, a.Charge, SUM(a.NoU) AS NoU, SUM(a.NoU*a.Charge) AS TotalAmount, SUM(a.ServiceCharge) AS ServiceCharge
	FROM PatientLedger a
	LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId and b.Valid = 1
	LEFT JOIN BedInformation c ON a.BranchId = c.BranchId AND a.BedNo = c.BedNo
	WHERE a.BranchId = @BranchId AND a.PatientId = @PatientId AND a.Valid = 1
	GROUP BY c.SubSubPno, a.Status, a.RefNo, a.RefDate, a.RegNo, a.BedNo, a.PatientId, a.PatientName, a.UserName, FORMAT(a.EntryDateTime, 'yyyy-MM-dd hh:mm:ss'),
	a.Code, a.Particulars, a.DrCode, a.DrName, a.Charge, b.DrCode, b.DrName, b.UnderDrCode, b.UnderDrName,
	b.PatientAge, b.PatientSex, b.PatientAddress, b.PatientTel
	HAVING SUM(a.ServiceCharge) != 0
	ORDER BY a.RefDate
END
GO
