CREATE PROC [dbo].[Sp_IndoorTopContribur] @BranchId INT, @DateFrom DATE, @DateTO DATE, @Param VARCHAR(50)
AS
/* EXEC Sp_IndoorTopContribur 1, '2023-02-01', '2023-02-10', 'RefDr' */
IF @Param = 'RefDr'
	BEGIN
		SELECT a.DrCode, a.DrName, count(DISTINCT a.PatientId) AS NoOfPtn, SUM(b.TotalAmount) AS Sales,
		SUM(b.Less) AS Less, SUM(b.TotalAmount-b.Less) AS Net
		FROM PatientAdmission a
		LEFT JOIN PatientLedger b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
		WHERE a.BranchId = @BranchId AND b.Valid = 1 AND a.IsRelease = 1 AND a.ReleaseDate BETWEEN @DateFrom AND @DateTO
		GROUP BY a.DrCode, a.DrName
		ORDER BY SUM(b.TotalAmount-b.Less) DESC
	END
ELSE
	BEGIN
		SELECT a.UnderDrCode AS DrCode, a.UnderDrName AS DrName, count(DISTINCT a.PatientId) AS NoOfPtn, SUM(b.TotalAmount) AS Sales,
		SUM(b.Less) AS Less, SUM(b.TotalAmount-b.Less) AS Net
		FROM PatientAdmission a
		LEFT JOIN PatientLedger b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId AND b.Valid = 1
		WHERE a.BranchId = @BranchId AND b.Valid = 1 AND a.IsRelease = 1 AND a.ReleaseDate BETWEEN @DateFrom AND @DateTO
		GROUP BY a.UnderDrCode, a.UnderDrName
		ORDER BY SUM(b.TotalAmount-b.Less) DESC
	END
GO
