--14102025
CREATE Proc [dbo].[SP_InGetDataForPurchaseOrderIn] @BranchId Int, @ReqNo Varchar(50), @LastIssuedFor Int, @IssueFor Int
AS
BEGIN --SP_InGetDataForPurchaseOrderIn 1, 'R260103967', 2, 1
	Select aa.ProductCode, LTRIM(Rtrim(bb.ProductName)) AS ProductName, bb.Unit,
	Sum(aa.EstimatedPrice) As EstimatedPrice, Sum(aa.ReqQty) As ReqQty, Isnull(SUm(aa.CurrStock), 0) As CurrentQty,
	SUm(aa.OutQty) As IssuedQty,
	Case WHen @LastIssuedFor=0 And @IssueFor=0 Then Sum(aa.OutQty) Else Isnull(SUm(aa.OutQty/Nullif(@LastIssuedFor, 0)*@IssueFor), 0) End As EstimatedQty
	From (
		Select a.ProductCode, a.ReqQty, a.EstimatedPrice, Sum(b.InQty-b.OutQty) As CurrStock, 0 As OutQty
		From InvPurchaseRequisitionDetails a
		Left Join InvStockLedger b On a.BranchId=b.BranchId And a.ProductCode=b.ProductCode And b.Valid=1
		Where a.BranchId=@BranchId And a.Valid=1 And a.ReqNo=@ReqNo
		Group By a.ProductCode, a.ReqQty, a.EstimatedPrice
		Union All
		Select a.ProductCode, 0 ReqQty, 0 As EstimatedPrice, 0 As CurrStock, SUM(b.OutQty) As OutQty
		From InvPurchaseRequisitionDetails a
		Left Join InvStockLedger b On a.BranchId=b.BranchId And a.ProductCode=b.ProductCode And b.Valid=1
		Where a.BranchId=@BranchId And a.Valid=1 And a.ReqNo=@ReqNo
		And b.TrDate Between DatEADD(MONTH, -@LastIssuedFor, Getdate()) And Getdate()
		Group By a.ProductCode
	) aa
	Left Join InvItemRegistration bb on aa.ProductCode=bb.ProductCode
	Group by aa.ProductCode, bb.ProductName, bb.Unit
End
GO
