CREATE PROC [dbo].[SP_InIssueAgainstRequisition](@GINNo nvarchar(20),@GINDate Date,@ReqNo nvarchar(50), @ReqDate date, @UnitId int, @BranchId int)
AS ---- exec [SP_InIssueAgainstRequisition] 'GI240100126', '2024-01-21','R240100137','	2024-01-21', 1, 1 
BEGIN

SELECT aa.PrevReqNo AS ReqNo,aa.PrevReqDate AS ReqDate,
@GINNo as GiNo,@GINDate as Gidate,
aa.ProductCode,aa.BranchId,
bb.ProductName , bb.Unit ,
SUM(aa.ReqInQty) as ReqInQty , SUM(aa.PrevIssue) AS PrevIssue, SUM(aa.IssueQty) as CurrentIssueQty ,
SUM(aa.ReqInQty-aa.PrevIssue-aa.IssueQty) as BalanceQty , aa.Department, aa.UserName, aa.EntryDateTime
FROM (
SELECT PrevReqNo,PrevReqDate,ProductCode , BranchId , ReqInQty , 0 as IssueQty , 0 as PrevIssue , Department, UserName, EntryDateTime
FROM InvReqLedger 
WHERE PrevReqNo = @ReqNo AND PrevReqDate = @ReqDate and ReqInQty <> 0 and UnitId = @UnitId AND BranchId = @BranchId 
and Valid = 1
GROUP BY PrevReqNo,PrevReqDate,ProductCode , BranchId , ReqInQty,Department, UserName, EntryDateTime
UNION ALL
SELECT PrevReqNo,PrevReqDate,ProductCode , BranchId , 0 as ReqInQty , SUM(ReqOutQty) AS  IssueQty , 0 as PrevIssue,Department, UserName, EntryDateTime
FROM InvReqLedger 
WHERE TrNO = @GINNo  AND TrDate = @GINDate and ReqOutQty <> 0 and UnitId = @UnitId AND BranchId = @BranchId 
and Valid = 1
GROUP BY PrevReqNo,PrevReqDate,ProductCode , BranchId ,Department, UserName, EntryDateTime
UNION ALL
SELECT PrevReqNo,PrevReqDate,ProductCode , BranchId , 0 as ReqInQty , 0 , SUM(ReqOutQty) AS  PrevIssue, Department, UserName, EntryDateTime
FROM InvReqLedger 
WHERE PrevReqNo = @ReqNo AND PrevReqDate = @ReqDate and ReqOutQty <> 0 
AND EntryDateTime < (SELECT MAX(entryDateTime) from InvReqLedger where TrNO = @GINNo  AND TrDate = @GINDate and ReqOutQty <> 0 and UnitId = @UnitId AND BranchId = @BranchId 
and Valid = 1)
and UnitId = @UnitId AND BranchId = @BranchId 
and Valid = 1
GROUP BY ProductCode , BranchId,PrevReqNo,PrevReqDate,Department, UserName, EntryDateTime) aa , InvItemRegistration bb
where aa.ProductCode = bb.ProductCode
GROUP BY aa.ProductCode,aa.BranchId,bb.ProductName , bb.Unit,aa.PrevReqNo,aa.PrevReqDate,aa.Department, aa.UserName, aa.EntryDateTime
HAVING SUM(aa.IssueQty) <> 0
END
GO
