CREATE PROCEDURE [dbo].[Sp_InPendingApprovedListForIssue] @BranchId INT, @ApproveNo VARCHAR(50)
AS -- Sp_InPendingApprovedListForIssue 1, ''
begin
	Select TOP 50 TrNo as ApproveTrNo, TrDate as ApproveDate, PrevReqNo, PrevReqDate, Department, ReqFrom, UserName as ApprovedBy
	From InvRequisitionApprovalMain WHERE Valid=1 AND BranchId=@BranchId AND (TrNo + Department) LIKE '%'+@ApproveNo+'%' 
	AND PrevReqNo IN (
		SELECT PrevReqNo FROM InvReqLedger WHere BranchId=@BranchId and Valid=1 GROUP BY PrevReqNo HAVING SUM(ReqApprovedQty-ReqOutQty) > 0
	)
	ORDER BY TrNo DESC
