--02022025
CREATE PROC [dbo].[SP_InPendingProductListForIssue] @BranchId INT, @ApproveNo varchar(50)
AS
BEGIN -- SP_InPendingProductListForIssue 1, 'RA250100278'
	SELECT b.ProductCode, b.ProductName, b.Unit, SUM(b.ReqInQty) AS ReqInQty, SUM(b.ReqApprovedQty) AS ReqApprovedQty, SUM(b.ReqOutQty) AS IssueQty, 
	SUM(b.ReqApprovedQty-ReqOutQty) AS HaveToIsue, ISNULL(c.ExpiryDate, GETDATE()) AS ExpiryDate, ISNULL(c.CurrQty, 0 ) AS CurrQty
	FROM InvRequisitionApprovalMain a
	LEFT JOIN InvReqLedger b ON a.BranchId=b.BranchId AND a.PrevReqNo=b.PrevReqNo AND b.Valid=1
	LEFT JOIN (
		SELECT ISNULL(sum(InQty + RtnQty - OutQty- PRtnQty), 0) as CurrQty, MaX(ExpDate) AS ExpiryDate, ProductCode, BranchId
		FROM InvStockLedger 
		WHERE Valid=1 ANd BranchId=@BranchId
		group by ProductCode, BranchId
		) c ON b.ProductCode=c.ProductCode and a.BranchId=c.BranchId
	WHERE a.TrNo=@ApproveNo AND b.Valid=1 AND a.BranchId=@BranchId
	GROUP BY b.ProductCode, b.ProductName, b.Unit, c.ExpiryDate, c.CurrQty
	HAVING SUM(b.ReqApprovedQty-ReqOutQty) > 0
END
GO
