CREATE PROC [dbo].[SP_InProductIssueWithoutRequisition](@TrNo nvarchar(50), @TrDate date, @UnitId int, @BranchId int)
AS
BEGIN /* EXEC SP_InProductIssueWithoutRequisition 'WR230700136', '2023-07-31', 1, 1 */
	Select a.TrNo, a.TrDate, a.FromUnit, a.FromStore, a.ToUnit, a.ToStore, a.ProductCode, a.ProductName, a.Unit, '' AS BatchNo, ('1900-01-01') AS ExpDate, a.IssueQty, 
	a.Note, b.InventoryType, MAX(a.Price) AS Price, a.TotalAmt, a.ReqNo, ISNULL(a.ReqDate, '') AS ReqDate, a.UserName
