--26012025
CREATE PROC [dbo].[SP_InProductListForRequisitionApprove] @BranchId INT, @UnitId INT, @ReqNo varchar(50)
AS
BEGIN --  EXEC SP_InProductListForRequisitionApprove 1, 1, 'R250100295'
	DECLARE @DeptName nvarchar(100); 
	SELECT @DeptName = Department FROM InvRequisitionMain WHERE Valid=1 AND BranchId=@BranchId AND UnitId=@UnitId AND ReqNo=@ReqNo;

	WITH AB as 
	(
		Select ProductCode, MAX(TrDate) as LastIssueDate 
		From InvStockLedger 
		WHERE Valid=1 AND BranchId=@BranchId AND UnitId=@UnitId AND IssueDeptName= @DeptName AND OutQty > 0
		AND ProductCode IN (
			Select ProductCode FROM InvRequisitionDetails WHERE Valid=1 AND BranchId=@BranchId AND UnitId=@UnitId AND ReqNo=@ReqNo
		) 
		GROUP BY ProductCode
	) 
	SELECT a.ProductCode, a.ProductName, a.Details, a.Unit, a.ReqQty, ISNULL(SUM((b.InQty+b.RtnQty+b.BonusQty)-(b.PRtnQty+b.OutQty)),0) AS OurStock, 
	ISNULL(c.LastIssueDate, GETDATE()) as  LastIssueDate 
	from InvRequisitionDetails a 
	LEFT JOIN InvStockLedger b on a.BranchId=b.BranchId AND a.ProductCode = b.ProductCode AND b.Valid=1
	LEFT JOIN AB c on a.ProductCode=c.ProductCode
	where a.Valid=1 AND a.BranchId=@BranchId AND a.UnitId=@UnitId AND a.ReqNo=@ReqNo
	GROUP BY a.ProductCode, a.ProductName, a.Details, a.Unit, a.ReqQty, c.LastIssueDate
END
GO
