CREATE PROCEDURE [dbo].[SP_InPurchaseRequisition] (@ReqNo nvarchar(50) , @ReqDate date , @UnitId int, @BranchId int)
AS	-- This Procedure Created By Arif 05/03/2024
BEGIN
select ee.ReqNo, ee.ReqDate, dd.Department , dd.ReqFrom ,dd.TotalQty ,dd.Note, ee.UserName ,dd.EntryDateTime ,
cc.ProductCode ,CC.ProductName , ee.Details,CC.Unit, cc.ProductCategory, CC.ApproverPrice as UnitPrice,  0 as OurStock , 
0 as BatchNo ,ee.ReqQty, ee.EDD, ee.EstimatedPrice, Isnull(ee.LastPPrice, 0) as LastPP, cc.lastPurchaseDate as LastPDate ,ISNULL(aa.CurBaance,0) as CurrQty 
from InvPurchaseRequisitionMain dd
LEFT JOIN InvPurchaseRequisitionDetails ee ON dd.BranchId = ee.BranchId and dd.ReqNo=ee.ReqNo and ee.Valid = 1
LEFT JOIN InvItemRegistration cc ON cc.ProductCode = ee.ProductCode
LEFT JOIN (
	select BranchId, ProductCode,SUM(InQty+RtnQty+BonusQty-OutQty-PRtnQty) as CurBaance 
	from InvStockLedger
	WHERE Valid = 1 AND ProductCode IN (
		SELECT ProductCode FROM InvPurchaseRequisitionDetails where ReqNo = @ReqNo 
		AND ReqDate = @ReqDate and BranchId = BranchId --AND UnitId = @UnitId
	)
	and TrDate < = @ReqDate and BranchId = BranchId --AND UnitId = @UnitId
	group by BranchId, ProductCode
) aa ON aa.BranchId = dd.BranchId and aa.ProductCode=ee.ProductCode
where dd.ReqNo = @ReqNo AND dd.ReqDate=@ReqDate and dd.BranchId = @BranchId AND dd.UnitId = @UnitId
END
GO
