--22102025
Create Procedure [dbo].[SP_InReOrderList] @BranchId Int, @DateFrom Date, @DateTo Date
AS
Begin --      SP_InReOrderList 1, '2025-10-01', '2025-10-20'
	With sales AS
	(
		Select a.ProductCode, b.ProductName, b.ReminderStock, b.Unit, b.ProductCategory, SUM(a.InQty+a.RtnQty+a.BonusQty-a.OutQty-a.PRtnQty) As CurrentStock
		from InvStockLedger a
		Left Join InvItemRegistration b On a.ProductCode=b.ProductCode
		Where a.Valid=1 And a.BranchId=@BranchId
		Group by a.ProductCode, b.ProductName, b.ReminderStock, b.ProductCategory, b.Unit
		Having SUM(a.InQty+a.RtnQty+a.BonusQty-a.OutQty-a.PRtnQty) <= b.ReminderStock
	)
	Select aa.ProductCode, bb.ProductName, bb.ReminderStock, bb.ProductCategory, bb.Unit,
	SUm(aa.OpenQty) As OpenQty, SUm(InQty) as InQty, Sum(OutQty) As OutQty, SUm(ClosingQty) As ClosingQty
	from (
		Select a.ProductCode, SUM(a.InQty+a.RtnQty+a.BonusQty-a.OutQty-a.PRtnQty) As OpenQty, 0 As InQty, 0 As OutQty, 0 As ClosingQty
		from InvStockLedger a
		Where a.Valid=1 And a.BranchId=@BranchId And a.TrDate < @DateFrom
		Group by a.ProductCode

		Union All
		Select a.ProductCode, 0 As OpenQty, SUM(a.InQty+a.RtnQty+a.BonusQty) As InQty, SUM(a.OutQty+a.PRtnQty) As OutQty, 0 As ClosingQty
		from InvStockLedger a
		Where a.Valid=1 And a.BranchId=@BranchId And a.TrDate Between @DateFrom And @DateTo
		Group by a.ProductCode
		Union All
		Select a.ProductCode, 0 As OpenQty, 0 As InQty, 0 As OutQty, SUM(a.InQty+a.RtnQty+a.BonusQty-a.OutQty-a.PRtnQty) As ClosingQty
		from InvStockLedger a
		Where a.Valid=1 And a.BranchId=@BranchId And a.TrDate <= @DateTo --and ProductCode='0010'
		Group by a.ProductCode
	) aa
	Inner Join sales bb on aa.ProductCode=bb.ProductCode
	Group by aa.ProductCode, bb.ProductName, bb.ReminderStock, bb.ProductCategory, bb.Unit
	order by 6 desc
End
GO
