CREATE PROC [dbo].[SP_InReqListForManagementApprove] @BranchId INT, @UserName varchar(50), @Param varchar(50)
AS
BEGIN --- SP_InReqListForManagementApprove 1, 'Asha@123', ''
DECLaRe @IsIncludeInvDeptWiseUserAccess int;
select @IsIncludeInvDeptWiseUserAccess=ActiveIndividualUserDeptInInventory from tbl_ComInfo;

IF @IsIncludeInvDeptWiseUserAccess = 1
	begin
		SELECT DISTINCT TOP 50 a.ReqNo, a.ReqDate, a.ReqFrom AS ReqBy, a.Department 
		FROM InvRequisitionMain a 
		WHERE a.BranchId=@BranchId AND a.Valid=1
		AND (a.ReqNo + a.Department) LIKE '%'+@Param+'%'
		AND Department IN (SELECT DISTINCT DeptName FROM InvUserConfig WHERE BranchId=@BranchId AND UserName=@UserName)
		AND a.ReqNo NOT IN (
				Select PrevReqNo 
				FROM InvRequisitionApprovalMain 
				WHERE Valid=1 AND BranchId=@BranchId
		)
		ORDER BY a.Department, a.ReqNo DESC
	end
	else
	begin
		Select TOP 50 a.ReqNo, a.ReqDate, a.ReqFrom as ReqBy, a.Department From InvRequisitionMain a
		WHERE a.BranchId=@BranchId AND a.Valid=1 AND (a.ReqNo+a.Department) LIKE '%'+@Param+'%'
		AND a.ReqNo NOT IN (
				Select PrevReqNo 
				FROM InvRequisitionApprovalMain 
				WHERE Valid=1 AND BranchId=@BranchId
		)
		GROUP BY a.ReqNo, a.ReqDate, a.ReqFrom, a.Department 
		ORDER BY a.Department, a.ReqNo DESC
	end
end
GO
