CREATE Proc [dbo].[Sp_InReqRptDatewise] @BranchId INT, @DateFrom DATE, @DateTo DATE, @DeptName VARCHAR(50), @ProductCode VARCHAR(50)
AS
BEGIN /* Sp_InReqRptDatewise 1, '2023-12-01', '2023-12-04' */
	select a.ReqNo, a.ReqDate, a.Department, a.UserName, a.EntryDateTime, b.ProductCode, b.ProductName, b.Details, b.UnitId, b.BatchNo, b.ReqQty, 
	c.GinNo, c.GinDate, c.EntryDateTime AS GinDateTime, c.IssueQty, c.UserName
	from InvRequisitionMain a
	left join InvRequisitionDetails b on b.BranchId = a.BranchId and b.ReqNo = a.ReqNo AND b.Valid = 1
	LEFT join InvProductIssueFormDetails c on c.BranchId = a.BranchId and c.ProductCode = b.ProductCode AND c.Valid = 1
	where a.BranchId = @BranchId AND a.Valid = 1 AND a.ReqDate BetWeen @DateFrom and @DateTo 
	AND a.Department LIKE '%'+@DeptName+'%' and b.ProductCode LIKE '%'+@ProductCode+'%'
	ORDER BY a.ReqNo, b.ProductCode
END
