CREATE PROC [dbo].[SP_InRequisition](@ReqNo nvarchar(50), @ReqDate date, @UnitId int, @BranchId int)
AS
BEGIN
select a.ReqNo, a.ReqDate, a.Department, a.ReqFrom, a.Note, a.UserName, b.ProductCode, b.ProductName, b.Details, b.Unit, 
b.ReqQty, b.BatchNo, a.EntryDateTime as EntryTime, b.EntryDateTime as IssueDate, c.Quantity AS LastIssueQuantity, c.IssueDate AS LastIssueDate
from InvRequisitionMain a 
LEFT JOIN InvRequisitionDetails b On a.ReqNo = b.ReqNo AND a.ReqDate = b.ReqDate AND b.Valid = 1
OUTER APPLY(SELECT IssueDate, Quantity FROM [dbo].[fnc_InPreviousIssueQty] (a.Department, b.ProductCode, @BranchId)) c
WHERE a.Valid = 1  AND a.ReqNo = @ReqNo AND a.ReqDate = @ReqDate
AND a.UnitId = b.UnitId AND a.BranchId = b.BranchId AND a.UnitId = @UnitId AND a.BranchId = @BranchId
end
