CREATE PROC [dbo].[SP_InRequisitionApproval](@TrNo nvarchar(50), @TrDate date, @UnitId int, @BranchId int)
AS   --- EXEC SP_InRequisitionApproval 'RA250100277', '2025-01-26', 1, 1
BEGIN
	select a.TrNo,a.TrDate,a.ReqFrom,a.Department, a.PrevReqNo,a.PrevReqDate,a.UserName, b.ProductCode,b.ProductName, b.IssueToDtls, 
	b.Unit, b.ReqQty as ReqInQty, b.ApprovedQty as ReqApprovedQty, ISNULL(SUM((c.InQty+c.RtnQty+c.BonusQty)-(c.PRtnQty+C.OutQty)),0) AS CurrentStock, 
	LastIssueDate 
	from InvRequisitionApprovalMain a
	LEFT JOIN InvRequisitionApprovalDetails b on a.BranchId=b.BranchId AND a.TrNo=b.ReqNo AND b.Valid=1
	LEFT JOIN InvStockLedger c ON a.BranchId=c.BranchId AND b.ProductCode=c.ProductCode AND c.Valid=1
	WHERE a.Valid = 1 AND a.TrNo = @TrNo AND a.TrDate = @TrDate AND a.UnitId = @UnitId AND a.BranchId = @BranchId
	GROUP BY a.TrNo,a.TrDate,a.ReqFrom,a.Department, a.PrevReqNo,a.PrevReqDate,a.UserName, b.ProductCode,b.ProductName, b.IssueToDtls,
	b.Unit, b.ReqQty, b.ApprovedQty, LastIssueDate
END
