CREATE PROC [dbo].[Sp_InsertRosterDeptwise] @BranchId INT, @Code VARCHAR(10), @RosterDate DATE, @ShiftId INT, @UserName VARCHAR(50)
AS
BEGIN -- EXEC Sp_InsertRosterDeptwise 1, '80320', '2024-04-01', 48, 'as'

	DELETE FROM EmployeeRosterDetails WHERE Code = @Code and RosterDate = @RosterDate;

	/* Variable Declare */
	DECLARE @shiftName VARCHAR(100), @timeFrom VARCHAR(50), @timeTo VARCHAR(50), @empId VARCHAR(10), @deptCode VARCHAR(50), @department VARCHAR(100), 
	@desigCode VARCHAR(50), @designation VARCHAR(100);

	/* start data from shift info */
	SELECT @shiftName = ShiftName, @timeFrom = TimeFrom, @timeTo = TimeTo FROM HRGroupInfo WHERE Id = @ShiftId;
	/* end data from shift info */

	/* start data from employe info */
	SELECT @empId = EmpId, @deptCode = DeptCode, @department = Department, @desigCode = DesigCode, @designation = Designation 
	FROM HREmployeeMaster WHERE Code = @Code AND Valid = 1;

	--select @shiftName ShiftName, @timeFrom TimeFrom, @timeTo TimeTo, @empId EmpId, @deptCode DeptCode, @desigCode DesigCode

	/* end data from employe info */

	INSERT INTO EmployeeRosterDetails (EmpId, ShiftStatus, DayName, GeneralShift, RosterDate, TimeFrom, TimeTo, UserLogs, PNO, UnitId, BranchId, UserName,
	IPAddress, Code, DeptCode, DeptName, DesigCode, Designation, ShiftId) 

	VALUES(@empId, 'Yes', DATENAME(DW, @RosterDate), @shiftName, @RosterDate, @timeFrom, @timeTo, 'Insert by '+@userName, 1, 1, @BranchId, @UserName, 
	'' , @Code, @deptCode, @department, @desigCode, @designation, @ShiftId);

END
