CREATE procedure [dbo].[SP_Inventory_LedgerDetails] (@StoreName nvarchar(50), @DateFrom date , @DateTo date, @UnitId int, @BranchId int ,@ProductCategory nvarchar(50),@productId nvarchar(20))
AS
BEGIN  --EXEC SP_Inventory_LedgerDetails '','2004-01-01','2023-12-31',1,1,'',''
SELECT aa.StoreName,aa.ProductCode,bb.ProductName , bb.Unit,   aa.TrDate,aa.TrNo,aa.InvoiceNo , aa.InvoiceDate ,aa.PPrice as Price, aa.Particular,aa.IssueDeptName,aa.PostedBy,aa.OPBal,aa.InQty , aa.OutQty 
FROM (
	select ProductCode, TrDate,TrNo,InvoiceNo , InvoiceDate ,PPrice, UserName AS PostedBy,reqFrom AS Particular,StoreName,IssueDeptName , 0 as OPBal,InQty , OutQty 
	from InvStockLedger 
	where ProductCode LIKE '%'+@productId+'%' and valid  = 1
	and TrDate between @DateFrom and @DateTo and StoreName LIKE '%'+@StoreName+'%' AND UnitId = @unitid and BranchId = @BranchId 
	UNION ALL
	select ProductCode, null As TrDate,'' as TrNo, '' as InvoiceNo , null as InvoiceDate ,0 as PPrice, '' AS PostedBy,'Opening Stock' as reqFrom,StoreName,'' as IssueDeptName , SUM(InQty-OutQty ) AS OB , 0 as InQty , 0 as OutQty 
	from InvStockLedger 
	where ProductCode LIKE '%'+@productId+'%' and valid  = 1
	and TrDate < @DateFrom  and StoreName LIKE '%'+@StoreName+'%' AND UnitId = @unitid and BranchId = @BranchId 
	GROUP BY ProductCode,StoreName) aa , InvItemRegistration bb
	where aa.ProductCode = bb.ProductCode and bb.ProductCategory LIKE '%'+@ProductCategory +'%'
	ORDER BY storeName , ProductName , TrDate , trno 
END
GO
