CREATE PROCEDURE [dbo].[SP_Inventory_ProductLedgerSummarized] (@StoreName nvarchar(50), @DateFrom date , @DateTo date, @UnitId int, @BranchId int ,@ProductCategory nvarchar(50), @ProductCode nvarchar(20))
AS 
BEGIN  --- exec SP_Inventory_ProductLedgerSummarized 'Central Store','2024-07-01' , '2024-07-30' , 1 , 1, '',''
	if @StoreName <> '' 
		BEGIN
			SELECT aa.storeName , bb.ProductCategory,  aa.ProductCode , bb.ProductName , bb.Unit , 
			SUM(aa.OB) AS OB , SUM(aa.OBAmt) AS OBAmt , SUM(aa.InQty) As InQty , SUM(aa.InAmt) AS InAmt , 
			SUM(aa.OutQty) AS OutQty , SUM(aa.OutAmt) OutAmt ,
			SUM(aa.CB) AS CB , SUM(aa.CBamt) AS CBAmt , AVG(PPrice) As TP
			into #stock1
			FROM (
				select StoreName,ProductCode ,0 as OB, 0 as OBAmt,  (ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0)) as InQty,
				((ISNULL(InQty,0)*PPrice)+(ISNULL(RtnQty,0)*PPrice)+(ISNULL(BonusQty,0)*PPrice)) as InAmt  , 
				(ISNULL(OutQty,0)+ISNULL(PRtnQty,0)) as OutQty ,
				((ISNULL(OutQty,0)*PPrice)+(ISNULL(PRtnQty,0)*PPrice)) as OutAmt ,
				0 as CB , 0 as CBamt,PPrice
				from InvStockLedger 
				where valid = 1 AND UnitId = @UnitId AND BranchId = @BranchId AND ReqFrom != 'Stock Adjust'
				AND TrDate BETWEEN @DateFrom AND @DateTo 
				AND StoreName = @StoreName
				UNION ALL
				select StoreName,ProductCode ,((ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0))-(ISNULL(OutQty,0)+ISNULL(PRtnQty,0))) as OB,
				(((ISNULL(InQty,0)*PPrice)+(ISNULL(RtnQty,0)*PPrice)+(ISNULL(BonusQty,0)*PPrice))-((ISNULL(OutQty,0)*PPrice)+
				(ISNULL(PRtnQty,0)*PPrice))) as OBAmt,  
				0 as InQty,
				0 as InAmt  , 
				0 as OutQty ,
				0 as OutAmt ,
				0 as CB , 0 as CBamt,PPrice
				from InvStockLedger 
				where valid = 1 AND UnitId = @UnitId AND BranchId = @BranchId
				AND TrDate < @DateFrom
				AND StoreName = @StoreName
				UNION ALL
				select StoreName,ProductCode , 0 as OB, 
				0 as OBAmt,  
				0 as InQty,
				0 as InAmt  , 
				0 as OutQty ,
				0 as OutAmt ,
				((ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0))-(ISNULL(OutQty,0)+ISNULL(PRtnQty,0))) as CB , 
				(((ISNULL(InQty,0)*PPrice)+(ISNULL(RtnQty,0)*PPrice)+(ISNULL(BonusQty,0)*PPrice))-
				((ISNULL(OutQty,0)*PPrice)+(ISNULL(PRtnQty,0)*PPrice))) as CBamt,PPrice
				from InvStockLedger 
				where valid = 1 AND UnitId = @UnitId AND BranchId = @BranchId
				AND TrDate <= @DateTo
				AND StoreName = @StoreName
			) aa , InvItemRegistration bb
			WHERE aa.ProductCode = bb.ProductCode And bb.Valid=1 and bb.InventoryType!='pharmacy'
			AND bb.ProductCategory LIKE '%'+@ProductCategory + '%' AND bb.ProductCode LIKE '%'+@ProductCode+'%'
			GROUP BY aa.storeName , bb.ProductCategory,  aa.ProductCode , bb.ProductName , bb.Unit 
			--HAVING SUM(aa.CB) <> 0
			order by ProductCode

			delete from #stock1 where (InQty+OutQty+OB+CB) = 0
			select * from #stock1
		END
	ELSE
		BEGIN
			SELECT aa.storeName , bb.ProductCategory, aa.ProductCode, bb.ProductName, bb.Unit , 
			SUM(aa.OB) AS OB, SUM(aa.OBAmt) AS OBAmt, SUM(aa.InQty) As InQty, SUM(aa.InAmt) AS InAmt , 
			SUM(aa.OutQty) AS OutQty , SUM(aa.OutAmt) OutAmt ,
			SUM(aa.CB) AS CB , SUM(aa.CBamt) AS CBAmt , 
			AVG(PPrice) As TP
			into #stock
			FROM (
				select StoreName,ProductCode ,0 as OB, 0 as OBAmt,  (ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0)) as InQty,
				((ISNULL(InQty,0)*PPrice)+(ISNULL(RtnQty,0)*PPrice)+(ISNULL(BonusQty,0)*PPrice)) as InAmt  , 
				(ISNULL(OutQty,0)+ISNULL(PRtnQty,0)) as OutQty ,
				((ISNULL(OutQty,0)*PPrice)+(ISNULL(PRtnQty,0)*PPrice)) as OutAmt ,
				0 as CB , 0 as CBamt,PPrice
				from InvStockLedger 
				where valid = 1 AND UnitId = @UnitId AND BranchId = @BranchId AND ReqFrom != 'Stock Adjust'
				AND TrDate BETWEEN @DateFrom AND @DateTo 
				UNION ALL
				select StoreName,ProductCode ,((ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0))-(ISNULL(OutQty,0)+ISNULL(PRtnQty,0))) as OB, 			(((ISNULL(InQty,0)*PPrice)+(ISNULL(RtnQty,0)*PPrice)+(ISNULL(BonusQty,0)*PPrice))-((ISNULL(OutQty,0)*PPrice)+
				(ISNULL(PRtnQty,0)*PPrice))) as OBAmt,  
				0 as InQty,
				0 as InAmt  , 
				0 as OutQty ,
				0 as OutAmt ,
				0 as CB , 0 as CBamt,PPrice
				from InvStockLedger 
				where valid = 1 AND UnitId = @UnitId AND BranchId = @BranchId
				AND TrDate < @DateFrom
				UNION ALL
				select StoreName,ProductCode , 0 as OB, 
				0 as OBAmt,  
				0 as InQty,
				0 as InAmt  , 
				0 as OutQty ,
				0 as OutAmt ,
				((ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0))-(ISNULL(OutQty,0)+ISNULL(PRtnQty,0))) as CB , 
				(((ISNULL(InQty,0)*PPrice)+(ISNULL(RtnQty,0)*PPrice)+(ISNULL(BonusQty,0)*PPrice))-
				((ISNULL(OutQty,0)*PPrice)+(ISNULL(PRtnQty,0)*PPrice))) as CBamt,PPrice
				from InvStockLedger 
				where valid = 1 AND UnitId = @UnitId AND BranchId = @BranchId
				AND TrDate <= @DateTo
			) aa , InvItemRegistration bb
			WHERE aa.ProductCode = bb.ProductCode And bb.Valid=1 and bb.InventoryType!='pharmacy'
			AND bb.ProductCategory LIKE '%'+@ProductCategory + '%' AND bb.ProductCode LIKE '%'+@ProductCode+'%'
			GROUP BY aa.storeName , bb.ProductCategory,  aa.ProductCode , bb.ProductName , bb.Unit 
			--HAVING SUM(aa.CB) <> 0
			order by ProductCode

			delete from #stock where (InQty+OutQty+OB+CB) = 0
			select * from #stock
		END
	END


GO
