CREATE PROCEDURE [dbo].[SP_InvoiceRegisterAllDept] (@DateFrom datetime, @DateTo datetime, @BranchId int, @UnitId int, @DeptName VARCHAR(50), @PtStatus VARCHAR(20))
AS 
BEGIN /* EXEC SP_InvoiceRegisterAllDept '2022-09-01', '2022-09-01', 1, 1, 'Diagnostic' */
	SELECT a.PtStatus, a.DeptName, a.InvDate, a.InvNo, a.RegNo, a.PatientName, a.MobNo, [dbo].[fnc_DiagInvName](a.InvNo, a.InvDate, a.BranchId) AS InvstName,
	a.RefDrCode, a.RefDrName, a.ConsultantCode, a.ConsultantName, SUM(a.TotalAmt) AS Sales, SUM(b.Less) AS Less, SUM(b.Collection) AS Collection,
	SUM(b.ReturnAmount) AS ReturnAmt, SUM(b.ReturnCash) AS CashReturn, SUM(b.ReturnDue) AS DueAdjust, SUM(b.ReturnLess) As LessAdjust,
	SUM(b.Sales-b.Less-b.Collection-b.ReturnDue) AS Due
	FROM InvMaster a
	LEFT JOIN SalesLedger b ON a.BranchId = b.BranchId AND a.InvDate = b.PreInvDate AND a.InvNo = b.PrevInvNo AND b.Valid = 1
	WHERE a.BranchId = @BranchId AND a.InvDate BETWEEN @DateFrom AND @DateTo AND a.DeptName = @DeptName AND a.PtStatus LIKE '%'+@PtStatus+'%'
	GROUP BY a.PtStatus, a.DeptName, a.InvDate, a.InvNo, a.RegNo, a.PatientName, a.MobNo, a.RefDrCode, a.RefDrName, a.ConsultantCode, a.ConsultantName, a.BranchId
END
GO
