CREATE Procedure [dbo].[SP_InvProductIsseuRtnReq] @BranchId int, @UnitId int, @Param nvarchar(20)
AS  -- Exec SP_InvProductIsseuRtnReq 1, 1, 'GI240300334'
BEGIN
SELECT ROW_NUMBER() OVER (ORDER BY a.GinNo) SL,  a.GinNo as IssueNo, a.GinDate as IssueDate, a.IssueTo as IssueDept, a.storeName, b.ProductCode, c.ProductName, c.ApproverPrice, b.IssueQty, b.Unit, b.BatchNo, b.ExpDate, b.ExpDate as MfgDate
From InvProductIssueFormMain a 
Left Join InvProductIssueFormDetails b On a.GinNo=b.GinNo AND a.BranchId=b.BranchId AND a.Valid=b.Valid AND a.UnitId=b.UnitId
LEFT JOIN InvItemRegistration c On b.ProductCode=c.ProductCode AND b.BranchId=c.BranchId AND b.Valid=c.Valid
WHERE a.Valid=1  AND b.IssueQty > 0 AND a.BranchId=@BranchId AND a.UnitId=@UnitId AND a.GinNo=@Param
END
GO
