CREATE PROCEDURE [dbo].[SP_InvProductPurchaseReq] @BranchId int, @UnitId int, @Param nvarchar(20)
AS ---EXEC SP_InvProductPurchaseReq 1, 1, 'GR231100373'
BEGIN
select ROW_NUMBER() OVER (ORDER BY a.GrnNo) AS SL, a.GrnNo, a.GrnDate, a.storeName, b.ProductCode, b.ProductName, b.Price,
b.Qty as RecQty, SUM(ISNULL(c.RtnQty,0)) as PRtnQty,  b.Unit, ISNULL((b.Qty) - SUM(ISNULL(c.RtnQty,0)), 0) as RemainQty,  b.BatchNo, b.ExpDate, b.ExpDate as MfgDate
from InvPurchaseReceivingMain a
LEFT JOIN InvPurchaseReceivingDetails b on a.GrnNo = b.GrnNo and a.BranchId = b.BranchId and a.Valid = b.Valid and a.UnitId=b.UnitId
LEFT JOIN InvProductPurchaseReturnDetails c ON b.ProductCode=c.ProductCode AND b.GrnNo = c.GinNo and b.GrnDate = c.GinDate and b.BranchId = c.BranchId and b.Valid = c.Valid and b.UnitId = c.UnitId
WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.UnitId=@UnitId AND a.GrnNo=@Param
GROUP BY  a.GrnNo, a.GrnDate, a.storeName, b.ProductCode, b.ProductName, b.Price,
b.Qty, b.Unit,  b.BatchNo, b.ExpDate, b.ExpDate
ORDER BY b.ProductCode
END
GO
