create Procedure [dbo].[SP_InvPurchasePaymentInvoice] @BranchId int , @refNo nvarchar(20), @refDate date
AS ----- EXEC SP_InvPurchasePaymentInvoice 1, 'GR250703096', '2025-07-15'
BEGIN 
	select a.GrnNo RefNo, a.GrnDate AS RefDate, a.SupplierId, b.Name AS SupplierName, a.PrevInvNo, a.PrevInvDate, 
	sum(a.TotalPrice) as TotalPrice, sum(a.TotalCollection) as PaymentAmt, a.UserName, a.EntryDateTime AS EntryTime, 
	SUM(a.LessAmt) AS LessAmt, Sum(a.VatAmt) As VatAmt, Sum(a.AITAmt) As AITAmt, Sum(a.AdjustAmt) As AdjustAmt
	From InvPurchaseReceivingLedger a 
	left join InvSupplierInfo b On a.SupplierId=b.SupplierId AND b.Valid=1
	WHERE a.Valid=1 AND a.BranchId=@BranchId AND GrnNo=@refNo AND GrnDate=@refDate
	GROUP BY a.GrnNo, a.GrnDate, a.SupplierId, b.Name, a.PrevInvNo, a.PrevInvDate, a.UserName, a.EntryDateTime
END
