create PROC [dbo].[sp_InvPurchaseRequisitionShortList]
@BranchId int,
@DateFrom DATETIME,
@DateTo DATETIME
AS
BEGIN
SELECT a.ProductCode,a.ProductName,a.Unit,a.Department,
SUM(a.ReqApprovedQty-a.ReqOutQty) as BalanceQty,ISNULL(SUM(b.CurrQty),0) AS CurrQty
INTO #invShortList
FROM InvReqLedger a
LEFT JOIN (SELECT BranchId,ProductCode,sum(CurrQty) as CurrQty FROM VW_InCurrentStock GROUP BY BranchId,ProductCode) b ON a.ProductCode=b.ProductCode AND a.BranchId=b.BranchId
WHERE a.Valid=1 AND a.BranchId=@BranchId
AND a.ReqApproveDate BETWEEN @DateFrom AND @DateTo
GROUP BY a.ProductCode,a.ProductName,a.Unit,a.Department
HAVING SUM(a.ReqApprovedQty-a.ReqOutQty)>0
select * from #invShortList where BalanceQty>CurrQty
END
GO
