CREATE PROCEDURE  [dbo].[SP_InvReport_ExpectedPurReqReport] (@UserName nvarchar(50),  @dateFrom date , @dateto date, @UnitId int, @BranchId int) 
AS  --- Exec SP_InvReport_ExpectedPurReqReport 'Bijon24002', '2024-10-01','2024-11-10',1,1
BEGIN
	BEGIN
		SELECT a.ReqDate, a.ReqNo, b.EDD, b.ProductCode, b.ProductName, b.ReqQty, b.Details, b.EstimatedPrice, b.LastPPrice,
		a.ReqFrom, a.EntryDateTime, a.UserName AS PostedBy, c.ProductCategory, c.InventoryType, c.RegistrationGroup
		FROM InvPurchaseRequisitionMain a 
