CREATE Procedure [dbo].[SP_InvReqStoreVerifyReport] @BranchId int, @UnitId int, @StoreVerifyNo nvarchar(20), @StoreVerifyDate nvarchar(20)
AS  --- EXEC SP_InvReqStoreVerifyReport 1, 1, 'RSV241100072', '2024-11-16'
BEGIN
     Select a.VerifiedNo, a.VerifiedDate,  a.PrevReqNo, a.PrevReqDate, a.Department, a.ReqFrom, a.VerifiedBy, a.Note, b.ProductCode,
     b.ProductName, b.Details, b.LastIssueDate, b.LastIssueQty, b.Unit, ISNULL(SUM(c.CurrQty),0) as CurrQty, b.ReqQty, b.VerifyQty, a.UserName, a.EntryDateTime
     From InvReqStoreVerifyMain a
     Left Join InvReqStoreVerifyDetails b On a.VerifiedNo=b.VerifiedNo AND a.BranchId=b.BranchId AND a.Valid=b.Valid AND a.UnitId=b.UnitId
     Left Join VW_InCurrentStock c On b.ProductCode=c.ProductCode AND b.BranchId=c.BranchId AND b.UnitId=c.UnitId
