CREATE PROCEDURE [dbo].[SP_InvReturnReportDtls] (@BranchId int, @UnitId int, @DateFrom date , @DateTo date, @PtStatus nvarchar(20), @DrType nvarchar(25), @DrCode nvarchar(20), @DeptName NVARCHAR(50))
AS ---EXEC SP_InvReturnReportDtls 1, 1, '2022-01-01', '2024-05-30', 'Outdoor', 'Referred', '', 'DIAGNOSTIC'
IF @DrType = 'Consultant'
BEGIN
SELECT b.RefDrCode, b.RefDrName, b.ConsultantCode, b.ConsultantName, a.RtnInvNo, a.RtnInvDate, a.InvNo, a.InvDate, b.RegNo, b.PatientId, b.PatientName, b.Age, b.Sex as Gender, b.PtStatus, c.Sales , c.Less, c.Collection, (c.Sales - c.Less - c.Collection) as Due, c.ReturnLess , c.ReturnDue , c.ReturnCash , c.ReturnAmount, b.UserName as InvoiceBy, a.UserName as ReturnBy
FROM InvReturn a
LEFT JOIN InvMaster b On a.InvNo=b.InvNo AND a.BranchId=b.BranchId AND a.Valid=b.Valid 
LEFT JOIN SalesLedger c On a.InvNo = c.RefNo AND a.BranchId=c.BranchId AND a.Valid=c.Valid
where a.Valid = 1 and a.RtnInvDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @branchId ANd b.DeptName = @deptName
AND b.PtStatus LIKE '%'+@PtStatus+'%' AND b.ConsultantCode  LIKE '%'+@DrCode+'%'
GROUP BY b.RefDrCode, b.RefDrName, b.ConsultantCode, b.ConsultantName, a.RtnInvNo, a.RtnInvDate, a.InvNo, a.InvDate, b.RegNo, b.PatientId, b.PatientName, b.Age, b.Sex, b.PtStatus, c.Sales , c.Less, c.Collection, c.ReturnLess , c.ReturnDue , c.ReturnCash , c.ReturnAmount, b.UserName , a.UserName
END
ELSE
BEGIN
SELECT b.RefDrCode, b.RefDrName, b.ConsultantCode, b.ConsultantName, a.RtnInvNo, a.RtnInvDate, a.InvNo, a.InvDate, b.RegNo, b.PatientId, b.PatientName, b.Age, b.Sex as Gender, b.PtStatus, c.Sales , c.Less, c.Collection, (c.Sales - c.Less - c.Collection) as Due, c.ReturnLess , c.ReturnDue , c.ReturnCash , c.ReturnAmount, b.UserName as InvoiceBy, a.UserName as ReturnBy
FROM InvReturn a
LEFT JOIN InvMaster b On a.InvNo=b.InvNo AND a.BranchId=b.BranchId AND a.Valid=b.Valid 
LEFT JOIN SalesLedger c On a.InvNo = c.RefNo AND a.BranchId=c.BranchId AND a.Valid=c.Valid
where a.Valid = 1 and a.RtnInvDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @branchId ANd b.DeptName = @deptName
AND b.PtStatus LIKE '%'+@PtStatus+'%' AND b.RefDrCode LIKE '%'+@DrCode+'%'
GROUP BY b.RefDrCode, b.RefDrName, b.ConsultantCode, b.ConsultantName, a.RtnInvNo, a.RtnInvDate, a.InvNo, a.InvDate, b.RegNo, b.PatientId, b.PatientName, b.Age, b.Sex, b.PtStatus, c.Sales , c.Less, c.Collection, c.ReturnLess , c.ReturnDue , c.ReturnCash , c.ReturnAmount, b.UserName , a.UserName
END
GO
