CREATE PROCEDURE [dbo].[SP_InvReturnReportSMZ] (@BranchId int, @UnitId int, @DateFrom date , @DateTo date, @PtStatus nvarchar(20), @DrType nvarchar(25), @DrCode nvarchar(20), @DeptName NVARCHAR(50))
AS --- EXEC SP_InvReturnReportSMZ 1, 1, '2022-01-01', '2024-05-30', 'Outdoor', 'Consultant', '', 'DIAGNOSTIC'
IF @DrType = 'Consultant'
BEGIN
SELECT b.ConsultantCode as DrCode , d.DrName AS DrName, SUM(c.Sales) AS Sales, SUM(c.Less) AS Less, SUM(c.Collection) AS Collection, SUM(c.ReturnCash) AS ReturnCash, SUM(c.ReturnAmount) AS ReturnAmount
FROM InvReturn a
LEFT JOIN InvMaster b On a.InvNo=b.InvNo AND a.BranchId=b.BranchId AND a.Valid=b.Valid 
LEFT JOIN SalesLedger c On a.InvNo = c.RefNo AND a.BranchId=c.BranchId AND a.Valid=c.Valid
LEFT JOIN DrInfo d On b.ConsultantCode = d.DrCode 
where a.Valid = 1 and a.RtnInvDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @branchId ANd b.DeptName = @deptName
AND b.PtStatus LIKE '%'+@PtStatus+'%' AND b.ConsultantCode  LIKE '%'+@DrCode+'%'
GROUP BY  b.ConsultantCode, d.DrName, b.PtStatus
ORDER BY  b.ConsultantCode
END
ELSE
BEGIN
SELECT b.RefDrCode as DrCode, d.DrName AS DrName, SUM(c.Sales) AS Sales, SUM(c.Less) AS Less, SUM(c.Collection) AS Collection, SUM(c.ReturnCash) AS ReturnCash, SUM(c.ReturnAmount) AS ReturnAmount
FROM InvReturn a
LEFT JOIN InvMaster b On a.InvNo=b.InvNo AND a.BranchId=b.BranchId AND a.Valid=b.Valid 
LEFT JOIN SalesLedger c On a.InvNo = c.RefNo AND a.BranchId=c.BranchId AND a.Valid=c.Valid
LEFT JOIN DrInfo d On b.RefDrCode = d.DrCode
where a.Valid = 1 and a.RtnInvDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @branchId ANd b.DeptName = @deptName
AND b.PtStatus LIKE '%'+@PtStatus+'%' AND b.RefDrCode  LIKE '%'+@DrCode+'%'
GROUP BY b.RefDrCode, d.DrName, b.PtStatus
ORDER BY b.RefDrCode
END
GO
