CREATE PROCEDURE [dbo].[SP_InvStockAdjustRpt] (@BranchId int, @UnitId int, @trNo nvarchar(20), @trDate date)
AS --- EXEC SP_InvStockAdjustRpt 1, 1, 'SA240300001', '2024-03-11'
BEGIN
SELECT  a.TrNo, a.TrDate, a.UserName, c.Name, b.storeName, b.ProductCode, b.ProductName, b.Unit, b.BatchNo,(b.BalancedQty + b.OutQty) AS CurrentQty, b.BalancedQty, b.InQty, b.OutQty, a.Note, a.EntryDateTime 
FROM  InvStockUpdate  a 
LEFT JOIN InvStockLedger b  ON a.TrNo = b.TrNo AND a.TrDate = b.TrDate AND a.Valid=b.Valid AND a.BranchId=b.BranchId AND a.ProductCode=b.ProductCode
LEFT JOIN tbl_COMPANY_INFORMATION c ON a.BranchId = c.BranchId
WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.UnitId = @UnitId AND a.TrNo = @trNo AND a.TrDate = @trDate
END
GO
