CREATE PROCEDURE [dbo].[SP_InvStockAdjustRptDtls] (@BranchId INT, @UnitId INT, @datefrom date, @dateto date, @StoreName nvarchar(20), @ProductCode nvarchar(20))
AS -- EXEC SP_InvStockAdjustRptDtls 1, 1, '2024-01-01', '2025-05-28', '', ''
BEGIN
SELECT a.TrNo, a.TrDate, b.storeName, b.ProductCode, b.ProductName, (b.BalancedQty + b.OutQty) AS CurrentQty,
(b.BalancedQty) AS CorrectQty, (b.BalancedQty + b.OutQty - b.BalancedQty) AS AdjustQty,
a.UserName, a.Note, a.EntryDateTime ,b.InQty,b.OutQty,b.BalancedQty
FROM InvStockUpdate a
LEFT JOIN InvStockLedger b ON a.TrNo = b.TrNo AND a.TrDate = b.TrDate AND a.Valid=b.Valid AND a.BranchId=b.BranchId AND a.ProductCode=b.ProductCode
WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.UnitId = @UnitId
AND a.TrDate BETWEEN @datefrom AND @dateto
AND b.storeName  LIKE '%'+@StoreName+'%'  AND b.ProductCode LIKE '%'+@ProductCode+'%'
ORDER BY a.TrNo
END

GO
