CREATE PROCEDURE [dbo].[SP_InvStockAdjustRptSMZ] (@BranchId INT, @UnitId INT, @datefrom date, @dateto date, @StoreName nvarchar(20), @ProductCode nvarchar(20))
AS -- EXEC SP_InvStockAdjustRptSMZ 1, 1, '2024-01-01', '2025-05-28', '', ''
BEGIN
SELECT ProductCode, ProductName, (BalancedQty + OutQty) AS CurrentQty, (BalancedQty) AS CorrectQty, (BalancedQty + OutQty - BalancedQty) AS AdjustQty,
(PPrice) AS UnitPrice, ((BalancedQty + OutQty - BalancedQty) * PPrice) AS AdjustPrice, InQty, OutQty, BalancedQty
FROM InvStockLedger
WHERE Valid = 1 AND BranchId = @BranchId AND UnitId = @UnitId 
AND TrDate BETWEEN @datefrom AND @dateto
AND (storeName + ProductCode) LIKE '%'+@StoreName+'%'+'%'+@ProductCode+'%'
order by ProductCode
END
GO
