CREATE PROC [dbo].[SP_ITEMWISE_BALANCE] (@pno int,@itemId int,@dateFrom dateTime,@dateTo dateTime)
AS
IF @itemId=0
BEGIN

SELECT 0 as Sl,'-' AS TrNo,@dateTo AS TrDate,a.ItemId,b.Name AS ItemName,b.Model, 0 AS InQty,0 AS OutQty,SUM(a.InQty-a.OutQty+a.RtnQty)-SUM(a.PRtnQty) AS OpBal,a.Pno,'Opening' AS Description
FROM tbl_STOCK_LEDGER a LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id
WHERE a.TrDate < @dateFrom AND a.Pno=@pno
GROUP BY a.ItemId,b.Name,b.Model,a.Pno
UNION ALL
SELECT 2 as Sl,a.InvoiceNo AS TrNo,a.InvoiceDate AS TrDate,a.ItemId,b.Name AS ItemName,b.Model, 0 AS InQty,a.Quantity AS OutQty,0 AS OpBal,a.Pno,'Sales to '+c.Name AS Description
FROM tbl_SALES_DETAIL a LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id LEFT JOIN tbl_CUSTOMER c ON a.CustId=c.Id
WHERE a.InvoiceDate BETWEEN @dateFrom AND @dateTo AND a.Pno=@pno
UNION ALL
SELECT 1 as Sl,a.InvoiceNo AS TrNo,a.InvoiceDate AS TrDate,a.ItemId,b.Name AS ItemName,b.Model, a.Quantity AS InQty,0 AS OutQty,0 AS OpBal,a.Pno,'Purchase From '+c.Name AS Description
FROM tbl_STOCK_IN_DETAIL a LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id LEFT JOIN tbl_SUPPLIER_INFO_MASTER c ON a.SuppId=c.Id
WHERE a.InvoiceDate BETWEEN @dateFrom AND @dateTo AND a.Pno=@pno
UNION ALL
SELECT 3 as Sl,a.InvoiceNo AS TrNo,a.InvoiceDate AS TrDate,a.ItemId,b.Name AS ItemName,b.Model, Quantity AS InQty,0 AS OutQty,0 AS OpBal,a.Pno,'Return From '+c.Name AS Description
FROM tbl_SALES_RETURN_DETAIL a LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id LEFT JOIN tbl_CUSTOMER c ON a.CustId=c.Id
WHERE a.InvoiceDate BETWEEN @dateFrom AND @dateTo AND a.Pno=@pno
UNION ALL 
SELECT 4 as Sl,a.InvoiceNo AS TrNo,a.InvoiceDate AS TrDate,a.ItemId,b.Name AS ItemName,b.Model, Quantity AS InQty,0 AS OutQty,0 AS OpBal,a.Pno,'Return To '+c.Name AS Description
FROM tbl_STOCK_RETURN_DETAIL a LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id LEFT JOIN tbl_SUPPLIER_INFO_MASTER c ON a.SuppId=c.Id
WHERE a.InvoiceDate BETWEEN @dateFrom AND @dateTo AND a.Pno=@pno

END
ELSE

BEGIN
SELECT 0 as Sl,'-' AS TrNo,@dateTo AS TrDate,a.ItemId,b.Name AS ItemName,b.Model, 0 AS InQty,0 AS OutQty,SUM(a.InQty-a.OutQty+a.RtnQty)-SUM(a.PRtnQty) AS OpBal,a.Pno,'Opening' AS Description
FROM tbl_STOCK_LEDGER a LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id
WHERE a.TrDate < @dateFrom AND a.ItemId=@itemId AND a.Pno=@pno
GROUP BY a.ItemId,b.Name,b.Model,a.Pno
UNION ALL
SELECT 2 as Sl,a.InvoiceNo AS TrNo,a.InvoiceDate AS TrDate,a.ItemId,b.Name AS ItemName,b.Model, 0 AS InQty,a.Quantity AS OutQty,0 AS OpBal,a.Pno,'Sales to '+c.Name AS Description
FROM tbl_SALES_DETAIL a LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id LEFT JOIN tbl_CUSTOMER c ON a.CustId=c.Id
WHERE a.InvoiceDate BETWEEN @dateFrom AND @dateTo AND a.ItemId=@itemId AND a.Pno=@pno
UNION ALL
SELECT 1 as Sl,a.InvoiceNo AS TrNo,a.InvoiceDate AS TrDate,a.ItemId,b.Name AS ItemName,b.Model, a.Quantity AS InQty,0 AS OutQty,0 AS OpBal,a.Pno,'Purchase From '+c.Name AS Description
FROM tbl_STOCK_IN_DETAIL a LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id LEFT JOIN tbl_SUPPLIER_INFO_MASTER c ON a.SuppId=c.Id
WHERE a.InvoiceDate BETWEEN @dateFrom AND @dateTo AND a.ItemId=@itemId AND a.Pno=@pno
UNION ALL
SELECT 3 as Sl,a.InvoiceNo AS TrNo,a.InvoiceDate AS TrDate,a.ItemId,b.Name AS ItemName,b.Model, Quantity AS InQty,0 AS OutQty,0 AS OpBal,a.Pno,'Return From '+c.Name AS Description
FROM tbl_SALES_RETURN_DETAIL a LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id LEFT JOIN tbl_CUSTOMER c ON a.CustId=c.Id
WHERE a.InvoiceDate BETWEEN @dateFrom AND @dateTo AND a.ItemId=@itemId AND a.Pno=@pno
UNION ALL
SELECT 4 as Sl,a.InvoiceNo AS TrNo,a.InvoiceDate AS TrDate,a.ItemId,b.Name AS ItemName,b.Model, Quantity AS InQty,0 AS OutQty,0 AS OpBal,a.Pno,'Return To '+c.Name AS Description
FROM tbl_STOCK_RETURN_DETAIL a LEFT JOIN tbl_ITEM b ON a.ItemId=b.Id LEFT JOIN tbl_SUPPLIER_INFO_MASTER c ON a.SuppId=c.Id
WHERE a.InvoiceDate BETWEEN @dateFrom AND @dateTo AND a.ItemId=@itemId AND a.Pno=@pno
 
END





