/****** Object:  StoredProcedure [dbo].[SP_ItemWiseCollRatio]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

--25032025 Alamin
CREATE PROCEDURE [dbo].[SP_ItemWiseCollRatio] (@dateFrom date,@dateTo date ,@BranchId int,@DeptName NVARCHAR(50),@PatientStatus NVARCHAR(50))
AS 
BEGIN --EXEC SP_ItemWiseCollRatio '2025-03-01','2025-03-19',1,'',''
select PrevINvNO,PreInvDate , SUM(Sales) as Sales , SUM(Collection) as Coll, SUM(Less) as Less, 
SUM(ReturnAmount) as rtnAmt,SUM(AdjustAmt) AS AdjustAmt,SUM(ReturnLess) AS ReturnLess,
SUM(ReturnNet) AS ReturnNet,SUM(ReturnCash) AS ReturnCash,SUM(ReturnDue) AS ReturnDue,BranchId ,
SUM(Sales-Less-Collection-(ReturnAmount-ReturnCash-ReturnLess)) AS DueAmt
INTO #z
from SalesLedger
where valid <> 0 AND Department='DIAGNOSTIC'
and refdate BETWEEN @dateFrom AND @dateTo AND BranchId = @BranchId 
AND PtStatus LIKE '%'+@PatientStatus+'%'
GROUP BY PrevINvNO,PreInvDate,BranchId 
ORDER BY PrevINvNO,PreInvDate


select PrevINvNO,PreInvDate ,BranchId,
SUM(Sales-Less-Collection-(ReturnAmount-ReturnCash-ReturnLess)) AS DueAmt
INTO #zz
from SalesLedger
where valid <> 0 AND Department='DIAGNOSTIC'
and PrevInvNo IN (SELECT PrevINvNO FROM #z)
AND PtStatus LIKE '%'+@PatientStatus+'%'
GROUP BY PrevINvNO,PreInvDate,BranchId 
ORDER BY PrevINvNO,PreInvDate

UPDATE #z SET DueAmt= b.DueAmt
FROM #z a,#zz b
WHERE a.PrevInvNo=b.PrevInvNo AND a.PreInvDate=b.PreInvDate AND a.BranchId=b.BranchId

select a.DeptName , a.InvNo,a.InvDate,a.PCode,b.Description, a.Amount , a.Quantity AS Sales,c.Coll,c.Less,c.rtnAmt,
CASE WHEN c.Sales>0 THEN ROUND(((c.Coll/c.Sales)*a.Amount),0) ELSE 0 END as CollRatio , CASE WHEN c.Sales>0 THEN ROUND(((c.Less/c.Sales)*a.Amount),0) ELSE 0 END as LessRatio  , 
CASE WHEN c.Sales>0 THEN ROUND(((c.AdjustAmt/c.Sales)*a.Amount),0) ELSE 0 END as AdjustRatio,CASE WHEN c.Sales>0 THEN ROUND(((c.ReturnLess/c.Sales)*a.Amount),0) ELSE 0 END as ReturnLessRatio ,
CASE WHEN c.Sales>0 THEN ROUND(((c.rtnAmt/c.Sales)*a.Amount),0) ELSE 0 END as ReturnNetRatio ,CASE WHEN c.Sales>0 THEN ROUND(((c.ReturnCash/c.Sales)*a.Amount),0) ELSE 0 END as ReturnCashRatio ,
CASE WHEN c.Sales>0 THEN ROUND(((c.ReturnDue/c.Sales)*a.Amount),0) ELSE 0 END as ReturnDueRatio ,b.SubDeptName,b.SubSubDeptName,
CASE WHEN c.Sales>0 THEN ROUND(((c.DueAmt/c.Sales)*a.Amount),0) ELSE 0 END AS DueAmt,
ISNULL(d.Valid,0) as OutSampleTest,ISNULL(d.InstituteName,'') AS InstituteName,a.PtStatus
from InvDetails a 
LEFT JOIN #z c ON a.INvNo = c.PrevINvNO AND a.InvDate = c.PreInvDate AND a.BranchId = c.BranchId  
LEFT JOIN OutSample d ON a.InvNo=d.InvoiceNo AND a.InvDate=d.InvoiceDate AND a.PCode=d.PCode AND d.Valid=1,
ClinicalChart b
where a.PCode = b.PCode AND a.BranchId = b.BranchId AND a.DeptName='DIAGNOSTIC'
AND b.SubDeptName LIKE '%'+@DeptName+'%'
AND ISNUMERIC(a.PCode)=1
AND a.InvDate BETWEEN @dateFrom AND @dateTo AND a.BranchId = @BranchId 
AND a.PtStatus LIKE '%'+@PatientStatus+'%'
UNION ALL
select a.DeptName,a.InvNo,a.InvDate,'0001',a.ShortDesc as Description, a.Amount , a.Quantity AS Sales,c.Coll,c.Less,c.rtnAmt,
CASE WHEN c.Sales>0 THEN ROUND(((c.Coll/c.Sales)*a.Amount),0) ELSE 0 END as CollRatio , CASE WHEN c.Sales>0 THEN ROUND(((c.Less/c.Sales)*a.Amount),0) ELSE 0 END  as LessRatio,
CASE WHEN c.Sales>0 THEN ROUND(((c.AdjustAmt/c.Sales)*a.Amount),0) ELSE 0 END  as AdjustRatio,CASE WHEN c.Sales>0 THEN ROUND(((c.ReturnLess/c.Sales)*a.Amount),0) ELSE 0 END as ReturnLessRatio ,
CASE WHEN c.Sales>0 THEN ROUND(((c.rtnAmt/c.Sales)*a.Amount),0) ELSE 0 END as ReturnNetRatio ,CASE WHEN c.Sales>0 THEN ROUND(((c.ReturnCash/c.Sales)*a.Amount),0) ELSE 0 END  as ReturnCashRatio ,
CASE WHEN c.Sales>0 THEN ROUND(((c.ReturnDue/c.Sales)*a.Amount),0) ELSE 0 END  as ReturnDueRatio ,b.SubDeptName,b.SubSubDeptName,
CASE WHEN c.Sales>0 THEN ROUND(((c.DueAmt/c.Sales)*a.Amount),0) ELSE 0 END AS DueAmt,
ISNULL(d.Valid,0) as OutSampleTest,ISNULL(d.InstituteName,'') AS InstituteName,a.PtStatus
from InvDetails a 
LEFT JOIN #z c ON a.INvNo = c.PrevINvNO AND a.InvDate = c.PreInvDate AND a.BranchId = c.BranchId
LEFT JOIN OutSample d ON a.InvNo=d.InvoiceNo AND a.InvDate=d.InvoiceDate AND a.PCode=d.PCode AND d.Valid=1,
	(select distinct VaqGroup AS PCode,'LabTest' AS SubDeptName,'Vacutainer' as SubSubDeptName 
	from VacutainerSetup ) b
where a.PCode = b.PCode AND a.SubDeptName = '' AND ISNUMERIC(a.PCode)=0
AND a.DeptName='DIAGNOSTIC'
AND b.SubDeptName LIKE '%'+@DeptName+'%'
AND a.InvDate BETWEEN @dateFrom AND @dateTo AND a.BranchId = @BranchId 
AND a.PtStatus LIKE '%'+@PatientStatus+'%'
ORDER BY a.DeptName,a.InvDate, a.InvNo 

END
GO
