CREATE PROCEDURE [dbo].[SP_ItemWiseTotalSales](@DateFrom DateTime,@DateTo DateTime)
AS 
BEGIN
	SELECT 'OUTDOOR' AS MainDept,2 as SlNo,UPPER(a.DeptName) AS DeptName,UPPER(b.SubDeptName) AS SubDeptName,a.PCode,b.Description ,count(*) as NOU, SUM(Amount*Quantity)  as Totalamt
	FROM InvDetails a , ClinicalChart b
	WHERE a.Valid = 1 --and a.PtStatus = 'Outdoor'
	and a.pcode = b.pcode 
	and a.InvDate BETWEEN @DateFrom and @DateTo
	GROUP BY a.PCode,b.Description,a.DeptName,b.SubDeptName
	UNION ALL
	select 'OUTDOOR',1 as SlNo,'AMBULANCE','AMBULANCE','-','Ambulance No' as ProductName , COUNT(*), ISNULL(SUM(TotalCharge),0)
	from AmbulanceLedger 
	where valid = 1 --and PtStatus='OUTDOOR'
	and RefDate  BETWEEN @DateFrom and @DateTo
	UNION ALL
	select 'OUTDOOR',3 as SlNo,'MEDICINE','MEDICINE','-',ProductName , SUM(ProductQty),SUM(ProductQty*SalePrice)
	from PharSalesDetails 
	where valid = 1 --and PtStatus = 'Outdoor'
	and SaleDate BETWEEN @DateFrom and @DateTo
	GROUP BY ProductName
	ORDER BY slno,DeptName,SubDeptName,PCode
END





GO
