CREATE PROC [dbo].[SP_LabGrowthPtnList] @branchId int, @invNo varchar(50), @groupName VARCHAR(50)
AS
BEGIN
	SELECT a.InvDate, a.InvNo, a.PatientName, a.MobNo, a.Sex, a.DOB, a.PtStatus, b.PCode, b.ShortDesc, a.ConsultantCode as DrCode,
	a.ConsultantName AS DrName, b.SubDeptName AS GroupName, b.rptPrintNo, b.LabNo AS SampleNo, c.Email
	FROM InvMaster a
	LEFT JOIN InvDetails b ON a.BranchId = b.BranchId ANd a.InvNo = b.InvNo AND a.InvDate = b.InvDate ANd a.Valid = 1
	LEFT JOIN PatientRegistration c ON b.BranchId = c.BranchId AND c.RegNo = a.RegNo
	WHERE a.BranchId = @branchId AND a.InvNo = @invNo AND b.SubSubDeptName = @groupName
