CREATE PROC [dbo].[SP_LabGrowthRptPrint](@branchId int, @id int, @invNo VARCHAR(20), @pcode VARCHAR(30), @reportNo VARCHAR(50), @dept VARCHAR(30))
AS
/* EXEC SP_LabGrowthRptPrint 1, 19, 'DIA240200259', '1453', '24200000000006', 'GdROWTH' */
IF @dept = 'GROWTH'
	BEGIN
		select c.DeptName, a.InvNo, a.InvDate, c.RegNo, c.PatientName, c.Address, c.Age, c.Sex AS Gender, c.RefDrCode, c.RefDrName, c.ConsultantCode AS ConstDrCode,
		c.ConsultantName AS ConstDrName, c.PtStatus, c.BedNo, c.MobNo, a.LabNo, a.ReportNo, a.Code, a.TestName, a.Organism, a.ColonyCount, a.Incubation, a.SpecificTest, 
		c.CollTime AS InvCollTime,		
		e.Name AS PreparedBy, e.Designation AS PreparedByDegree, e.SignImg AS PreparedByImg,
		f.Name AS CheckedBy, f.Designation AS CheckedByDegree, f.SignImg AS CheckedByImg,
		g.Name AS Consultant, g.Designation AS ConsultantDegree, g.SignImg AS ConsultantImg,
		h.Name AS LabIncharge, h.Designation AS LabInchargeDegree, h.SignImg AS LabInchargeImg,

		a.Specimen, a.Comments, a.Advise, a.UserName, a.EntryDateTime, d.Id AS DrugId, d.Name AS DrugName, d.ShortName, ISNULL(b.Interpretation,'') AS Interpretation,
		ISNULL(b.ZoneSize, 0) AS ZoneSize, a.EntryDateTime AS RptDeliveryDate, i.CollTime, i.CollUser, i.ReceiveInLabTime, i.ReceiveInLabUser, c.EntryTime as InvoiceTime, 
		c.CollTime AS InvCollTime

		from Lab_ParameterDefinitionMicrobiology d
		LEFT JOIN Lab_MachineDataMicroMaster a ON d.BranchId = a.BranchId
		LEFT JOIN Lab_MachineDataMicroDetails b ON a.Id = b.MachineMasterId AND a.BranchId = b.BranchId AND d.Id = b.DrugId
		LEFT JOIN InvMaster c ON a.BranchId = c.BranchId AND a.InvNo = c.InvNo AND a.InvDate = c.InvDate AND c.Valid = 1
		LEFT JOIN LabSignatureDrInfo e ON a.PreparedId = e.Id AND a.ESPrepared = 1
		LEFT JOIN LabSignatureDrInfo f ON a.CheckedId = f.Id AND a.ESChecked = 1
		LEFT JOIN LabSignatureDrInfo g ON a.ConsultantId = g.Id AND a.ESConsultant = 1
		LEFT JOIN LabSignatureDrInfo h ON a.LabInchargeId = h.Id AND a.ESLabIncharge = 1
		LEFT JOIN Lab_SampleStatusInfo i ON i.BranchId = a.BranchId AND i.InvNo = a.InvNo AND i.TestCode = a.Code

		WHERE a.BranchId = @branchId AND a.Id = @id AND a.Valid = 1 AND a.InvNo = @invNo AND a.ReportNo = @reportNo
	END
ELSE
	BEGIN
		select c.DeptName, a.InvNo, a.InvDate, c.RegNo, c.PatientName, c.Address, c.Age, c.Sex AS Gender, c.RefDrCode, c.RefDrName,	c.ConsultantCode AS ConstDrCode,
		c.ConsultantName AS ConstDrName, c.PtStatus, c.BedNo, c.MobNo, a.LabNo, a.ReportNo, a.Code,	a.TestName, a.Organism, a.ColonyCount, a.Incubation, a.SpecificTest, 
		c.CollTime AS InvCollTime,

		e.Name AS PreparedBy, e.Designation AS PreparedByDegree, e.SignImg AS PreparedByImg,
		f.Name AS CheckedBy, f.Designation AS CheckedByDegree, f.SignImg AS CheckedByImg,
		g.Name AS Consultant, g.Designation AS ConsultantDegree, g.SignImg AS ConsultantImg,
		h.Name AS LabIncharge, h.Designation AS LabInchargeDegree, h.SignImg AS LabInchargeImg,

		a.Specimen, a.Comments, a.Advise, a.UserName, a.EntryDateTime, d.Id AS DrugId, d.Name AS DrugName, d.ShortName, d.Result AS Interpretation, 
		0 AS ZoneSize, a.EntryDateTime AS RptDeliveryDate, i.CollTime, i.CollUser, i.ReceiveInLabTime, i.ReceiveInLabUser, c.EntryTime as InvoiceTime, 
		c.CollTime AS InvCollTime

		from Lab_ParameterDefinitionMicrobiology d
		LEFT JOIN Lab_MachineDataMicroMaster a ON d.BranchId = a.BranchId
		LEFT JOIN InvMaster c ON a.BranchId = c.BranchId AND a.InvNo = c.InvNo AND a.InvDate = c.InvDate AND c.Valid = 1
		LEFT JOIN LabSignatureDrInfo e ON a.PreparedId = e.Id AND a.ESPrepared = 1
		LEFT JOIN LabSignatureDrInfo f ON a.CheckedId = f.Id AND a.ESChecked = 1
		LEFT JOIN LabSignatureDrInfo g ON a.ConsultantId = g.Id AND a.ESConsultant = 1
		LEFT JOIN LabSignatureDrInfo h ON a.LabInchargeId = h.Id AND a.ESLabIncharge = 1
		LEFT JOIN Lab_SampleStatusInfo i ON i.BranchId = a.BranchId AND i.InvNo = a.InvNo AND i.TestCode = a.Code

		WHERE a.BranchId = @branchId AND a.Id = @id AND a.Valid = 1 AND a.InvNo = @invNo AND a.ReportNo = @reportNo
	END
GO
