CREATE PROC [dbo].[Sp_LabSampleHandler] @BranchId INT, @InvNo VARCHAR(50), @Status VARCHAR(50)
AS
BEGIN -- EXEC sp_LabSampleHandler 1, 'DIA240100009', 'Lab Receive'
	WITH z AS
	(
		SELECT ISNULL(MAX(CASE WHEN @Status = 'Sample Collection' THEN StickerPrintTime WHEN @Status = 'Sample Send' THEN CollTime ELSE SendTime END), GETDATE()) AS Time,
		(CASE WHEN @Status = 'Sample Collection' THEN StickerPrintBy WHEN @Status = 'Sample Send' THEN CollUser ELSE SendUser END) AS UserName,
		(CASE WHEN FinalStatus = 'Invoice' THEN 1 WHEN FinalStatus = 'Sticker Print' THEN 2 WHEN FinalStatus = 'Sample Collection' THEN 3 WHEN FinalStatus = 'Sample Send' THEN 4 ELSE 5 END) AS SlNo,
		FinalStatus, SampleNo
		FROM Lab_SampleStatusInfo 
		WHERE BranchId = @BranchId AND InvNo = @InvNo
		GROUP BY StickerPrintBy, FinalStatus, SampleNo, CollUser, SendUser
	)
	SELECT DISTINCT a.PatientName, a.MobNo, a.Age, a.Sex, a.InvNo, a.InvDate, a.PtStatus, b.LabNo, c.Time, c.UserName, c.FinalStatus, c.SlNo,
	SUBSTRING((SELECT ','+ShortDesc FROM InvDetails where InvNo = a.InvNo AND IsSampleCollected = 1 AND LabNo = b.LabNo ORDER BY ShortDesc FOR XML PATH('')), 2 , 500) As TestName
	FROM InvMaster a
	LEFT JOIN InvDetails b On b.BranchId = a.BranchId AND b.InvNo = a.InvNo AND b.Valid = 1 AND b.SubDeptName = 'LabTest'
	LEFT JOIN z c On c.SampleNo = b.LabNo
	WHERE a.BranchId = @BranchId AND a.InvNo = @InvNo AND c.FinalStatus IS NOT NULL --AND c.FinalStatus = 'Sticker Print'
END
GO
