CREATE PROC [dbo].[Sp_LabStickerPrint] @BranchId INT, @InvNo VARCHAR(50), @SampleNo VARCHAR(50)
AS
BEGIN --EXEC Sp_LabStickerPrint 1, 'DIA240100006', ''
	SELECT a.DeptName AS Department, a.InvNo, a.InvDate, a.RegNo, a.PatientName, a.Address, a.Age, a.Sex, a.PtStatus, a.PatientId, a.BedNo, a.MobNo, a.ConsultantName+' '+c.Degree AS Consultant, b.SubDeptName AS DeptName, b.StickerName, b.ReportGroupName, b.LabNo, MAX(d.StickerPrintTime) AS StickerPrintTime, d.StickerPrintBy, SUBSTRING((SELECT ','+ShortDesc FROM InvDetails where InvNo = a.InvNo AND StickerName = b.StickerName AND IsSampleCollected = 1 AND StickerName = b.StickerName AND LabNo = b.LabNo ORDER BY ShortDesc FOR XML PATH('')), 2 , 200) As TestName
	FROM InvMaster a
	LEFT JOIN InvDetails b ON b.BranchId = a.BranchId AND b.InvNo = a.InvNo AND b.SubDeptName = 'LabTest' AND b.Valid = 1
	LEFT JOIN DrInfo c ON c.BranchId = a.BranchId AND c.DrCode = a.ConsultantCode
	LEFT JOIN Lab_SampleStatusInfo d ON d.BranchId = a.BranchId AND d.InvNo = a.InvNo AND d.TestCode = b.PCode and d.SampleNo = b.LabNo
	where a.BranchId = @BranchId AND a.InvNo = @InvNo AND a.Valid = 1 AND d.StickerPrintStatus = 'Done' AND b.LabNo LIKE '%'+@SampleNo+'%'
	GROUP BY a.DeptName, a.InvNo, a.InvDate, a.RegNo, a.PatientName, a.Address, a.Age, a.Sex, a.PtStatus, a.PatientId, a.BedNo, a.MobNo, a.ConsultantName+' '+c.Degree, b.SubDeptName, b.StickerName, b.ReportGroupName, b.LabNo, d.StickerPrintBy
END
GO
