CREATE PROC [dbo].[Sp_LabStickerPrintInvDetails] @BranchId INT, @InvNo VARCHAR(50)
AS
BEGIN -- EXEC Sp_LabStickerPrintInvDetails 1, 'DIA240100003'
	SELECT DISTINCT a.InvNo, a.InvDate, a.RegNo, a.PatientName, a.Age, a.Sex, a.PtStatus, a.MobNo, a.BedNo, 0 AS IsSampleCollected, a.ConsultantName+' '+c.Degree AS Consultant,	
	SUBSTRING((SELECT ','+ShortDesc FROM InvDetails where BranchId = a.BranchId AND InvNo = a.InvNo AND StickerName = b.StickerName AND LabNo = b.LabNo AND IsSampleCollected = 1 AND SubDeptName = 'LabTest' ORDER BY ShortDesc FOR XML PATH('')), 2 , 200) As Description,	
	b.StickerName, b.LabNo
	FROM InvMaster a
	left join InvDetails b on b.BranchId = a.BranchId and b.InvNo = a.InvNo
	left join DrInfo c on c.BranchId = a.BranchId and c.DrCode = a.ConsultantCode
	left join ClinicalChart d on d.BranchId = a.BranchId and d.PCode = b.PCode
	WHERE a.BranchId = @BranchId and a.InvNo = @InvNo and d.SubDeptName = 'LabTest'
	ORDER by b.LabNo
END
GO
