CREATE PROC [dbo].[SP_ListOfServicesPtnReport](@pno nvarchar(50), @dateFrom date, @dateTo date)
AS
BEGIN

select 1 AS SlNo, 1 AS RowId, 'Special Clinic' AS Department, COUNT(RoomNo) AS Total from OPDTicketMaster where Amount = 400 AND CostCenterName = @pno AND TrDate BETWEEN @dateFrom AND @dateTo
UNION ALL
select 2 AS SlNo, 2 AS RowId, 'Outdoor' AS Department , COUNT(RoomNo) AS Total from OPDTicketMaster where Amount = 200 AND CostCenterName = @pno AND TrDate BETWEEN @dateFrom AND @dateTo
UNION ALL
select 3 AS SlNo, 2+ROW_NUMBER() OVER(ORDER BY b.SubDeptName ASC) AS RowId, b.SubDeptName, COUNT(a.InvNo) as Total from InvDetails a, ClinicalChart b WHERE a.PCode = b.PCode AND a.Valid = @pno AND b.SubDeptName != 'Radiology' AND a.InvDate BETWEEN @dateFrom AND @dateTo GROUP BY b.SubDeptName
UNION ALL
select 4 AS SlNo, ROW_NUMBER() OVER(ORDER BY b.SubSubDeptName ASC) AS RowId, b.SubSubDeptName, COUNT(a.InvNo) as Total from InvDetails a, ClinicalChart b WHERE a.PCode = b.PCode AND a.Valid = @pno AND b.SubDeptName = 'Radiology' AND a.InvDate BETWEEN @dateFrom AND @dateTo GROUP BY b.SubSubDeptName

end

