CREATE PROCEDURE [dbo].[SP_LocationWiseAssetRptDtls] (@BranchId INT, @DateFrom NVARCHAR(20), @DateTo NVARCHAR(20), @Department NVARCHAR(50), @AssetCode NVARCHAR(20))
AS --- EXEC SP_LocationWiseAssetRptDtls 1, '2023-01-01', '2024-06-01', '', ''
BEGIN
SELECT AssetCount, AssetClass, AssetMainCode, AssetName, MRRNo, MRRDate, InvoiceNo, InvoiceDate, UnitType, UnitPrice, Department AS Location, FloorNo, RoomNumber, StoreName, AnyNote, OfficeNote AS Remarks, UserName, EntryDateTime  FROM FixedAssetRegisterDetails
WHERE Valid = 1 AND BranchId = @BranchId AND MRRDate BETWEEN @DateFrom AND @DateTo AND Department LIKE '%'+@Department+'%' AND
AssetMainCode LIKE '%'+@AssetCode+'%'
END
