CREATE PROCEDURE [dbo].[SP_LocationWiseAssetRptSMZ] (@BranchId INT, @DateFrom NVARCHAR(20), @DateTo NVARCHAR(20), @Department NVARCHAR(50), @AssetCode NVARCHAR(20))
AS --- EXEC SP_LocationWiseAssetRptSMZ 1, '2023-01-01', '2024-06-01', '', ''
BEGIN
SELECT Department AS Location, FloorNo, RoomNumber, Sum(UnitPrice) AS TotalPrice FROM FixedAssetRegisterDetails
WHERE Valid = 1 AND BranchId = @BranchId AND MRRDate BETWEEN @DateFrom AND @DateTo AND Department LIKE '%'+@Department+'%' AND
