/****** Object:  StoredProcedure [dbo].[SP_MainDepartmentWiseSalesColl]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SP_MainDepartmentWiseSalesColl] (@DateFrom DateTime , @DateTo DateTime, @BranchId int, @UnitId int)
AS 
BEGIN

	UPDATE PatientReleaseMaster
	SET DueCollectionAmt=b.DueCollection,DueCollectionLessAmt=b.DueCollLess
	from PatientReleaseMaster a,
	(SELECT PatientId,SUM(Collection) AS DueCollection,SUM(Less) as DueCollLess 
	FROM IndoorDueCollMaster
	WHERE Valid=1
	GROUP BY PatientId
	) b
	WHERE a.PatientID=b.PatientId
	AND a.Valid=1


	--   EXEC SP_MainDepartmentWiseSalesColl '2025-11-05','2025-11-05',1,1

	SELECT aa.slno,aa.MainDept, UPPER(aa.DeptName) AS DeptName, ROUND(ISNULL(SUM(aa.Sales),0),0) as Sales, ROUND(ISNULL(SUM(aa.Less),0),0) AS Less,
	ROUND(ISNULL(SUM(aa.RtnAmt),0),0) AS RtnAmt, ROUND(ISNULL(SUM(aa.Sales -aa.Less - aa.RtnAmt),0),0) AS NetSales, 
	ROUND(ISNULL(SUM(aa.ByCash),0),0) AS ByCash, ROUND(ISNULL(SUM(aa.ByCard),0),0) AS ByCard, 
	ROUND(ISNULL(SUM(aa.ByCheque),0),0) AS ByCheque, ROUND(ISNULL(SUM(aa.TotalColl),0),0) AS TotalCall, 
	ROUND(ISNULL(SUM(aa.CashReturn),0),0) AS CashReturn ,SUM(TotalPt) AS TotalPt,SUM(aa.DueCollection) AS DueCollection,
	SUM(aa.Due) AS Due, SUM(aa.DueCollLess) As DueCollLess,SUM(aa.AdvanceAmt) AS AdvanceAmt,SUM(aa.AdvanceAdjust) AS AdvanceAdjust
	FROM (
	--------START INDOOR---------
	--Sales/Less
	SELECT 1 AS SlNo, 'INDOOR' AS MainDept, a.MainDeptName AS DeptName, 
	SUM(TotalAmt+ServiceChargeAmt) AS Sales,SUM(LessAmt+PrevLessAmt) AS Less, 0 as RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,COUNT(a.PatientID) AS TotalPt,
	SUM(NetPaymentAmt) AS TotalColl,0 AS DueCollection,
	SUM(CASE WHEN a.NetTotalAmt-a.AdvanceAmt-a.NetPaymentAmt+a.ReturnAmt-a.DueCollectionAmt-a.DueCollectionLessAmt>1 THEN
		 a.NetTotalAmt-a.AdvanceAmt-a.NetPaymentAmt+a.ReturnAmt-a.DueCollectionAmt-a.DueCollectionLessAmt ELSE 0 END ) AS Due, 
	0 As DueCollLess,0 AS AdvanceAmt,SUM(AdvanceAmt-ReturnAmt) AS AdvanceAdjust
	FROM PatientReleaseMaster a 
	WHERE a.Valid=1
	AND a.BranchId = @BranchId 
	and a.ReleaseDate BETWEEN @DateFrom and @DateTo 
	GROUP BY a.MainDeptName

	UNION ALL
	--Cash Return
	SELECT 1 AS SlNo, 'INDOOR' AS MainDept, c.SubSubPno AS DeptName, 
	0 AS Sales, 0 AS Less, 0 as RtnAmt,SUM(b.CashAmt) AS ByCash, SUM(b.CardAmt) AS ByCard, SUM(b.ChequeAmt) AS ByCheque, 
	sum(b.ReturnAmt) AS CashReturn,0 AS TotalPt,0 AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,
	0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PatientLedger b LEFT JOIN BedInformation c ON b.BedNo=c.BedNo AND b.BranchId = c.BranchId 
	WHERE b.valid = 1 
	AND b.BranchId = @BranchId 
	and b.RefDate BETWEEN @DateFrom and @DateTo 
	GROUP BY c.SubSubPno
	HAVING SUM(b.CashAmt+b.CardAmt+b.ChequeAmt)>0
	
	UNION ALL
	--Advance
	SELECT 1 AS SlNo, 'INDOOR' AS MainDept, c.SubSubPno AS DeptName, 0 AS Sales, 0 AS Less, 0 as RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	0 AS DueCollection,0 AS Due, 0 As DueCollLess,SUM(b.Collection) AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PatientLedger b LEFT JOIN BedInformation c ON b.BedNo=c.BedNo AND b.BranchId = c.BranchId  
	WHERE b.valid = 1 
	AND b.BranchId = @BranchId 
	and b.RefDate BETWEEN @DateFrom and @DateTo 
	AND b.Status='Advance Collection'
	GROUP BY c.SubSubPno	
	
	--UNION ALL
	----Collection
	--SELECT 1 AS SlNo, 'INDOOR' AS MainDept, c.SubSubPno AS DeptName, 
	--0 AS Sales, 0 AS Less, 0 as RtnAmt,0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	--0 AS CashReturn,0 AS TotalPt,sum(b.Collection) AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,
	--0 AS AdvanceAmt,0 AS AdvanceAdjust
	--FROM PatientLedger b LEFT JOIN BedInformation c ON b.BedNo=c.BedNo AND b.BranchId = c.BranchId 
	--WHERE b.valid = 1 
	--AND b.BranchId = @BranchId 
	--and b.RefDate BETWEEN @DateFrom and @DateTo 
	--and b.PatientId IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)
	--AND b.Status<>'Advance Collection'
	--GROUP BY c.SubSubPno
	
	--UNION ALL
	----Due Collection
	--SELECT 1 AS SlNo, 'INDOOR' AS MainDept, c.SubSubPno AS DeptName, 0 AS Sales, 0 AS Less, 0 as RtnAmt,
	--0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	--SUM(b.Collection) AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	--FROM PatientLedger b LEFT JOIN BedInformation c ON b.BedNo=c.BedNo AND b.BranchId = c.BranchId 
	--WHERE b.valid = 1 
	--AND b.BranchId = @BranchId 
	--and b.RefDate BETWEEN @DateFrom and @DateTo 
	--and b.PatientId NOT IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)
	--AND b.Status<>'Advance Collection'
	--GROUP BY c.SubSubPno
	

	UNION ALL
	--Due Collection/Less
	SELECT 1 AS SlNo, 'INDOOR' AS MainDept, c.SubSubPno AS DeptName, 
	0 AS Sales, SUM(b.Less) AS Less, 0 as RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,
	SUM(b.Collection) AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM IndoorDueCollMaster b,BedInformation c
	WHERE b.Valid=1 AND b.BedNo=c.BedNo
	AND b.BranchId = @BranchId 
	AND b.RefDate BETWEEN @DateFrom and @DateTo
	and b.PatientId IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)	
	GROUP BY c.SubSubPno

	UNION ALL
	--Due Coll Less
	SELECT 1 AS SlNo, 'INDOOR' AS MainDept, c.SubSubPno AS DeptName, 
	0 AS Sales, 0 AS Less, 0 as RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,
	0 AS TotalColl,SUM(b.Collection) AS DueCollection,0 AS Due, SUM(b.Less) As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM IndoorDueCollMaster b,BedInformation c
	WHERE b.Valid=1 
	AND b.BedNo=c.BedNo
	AND b.RefDate BETWEEN @DateFrom and @DateTo
	AND b.BranchId = @BranchId 
	and b.PatientId NOT IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)	
	GROUP BY c.SubSubPno
	
	UNION ALL
	--Diagnostic Advance
	select 1 as slno, 'INDOOR' AS MainDept, c.SubSubPno AS DeptName, 0 AS Sales,0 AS Less,0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	0 AS DueCollection,0 AS Due, 0 As DueCollLess,sum(a.Collection) AS AdvanceAmt,0 AS AdvanceAdjust
	from SalesLedger a INNER JOIN PatientAdmission b ON a.PatientId=b.PatientId AND b.Valid=1 
	LEFT JOIN BedInformation c
	on a.BedNo=c.BedNo
	where a.Valid = 1 AND a.Department <> 'Ambulance' and a.PtStatus = 'Indoor' and InputFrom NOT IN('Indoor Due Collection','Patient Release') AND Collection>0
	And a.RefDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	GROUP BY c.SubSubPno

		
	UNION ALL
	--Ambulance Advance
	select 1 as slno, 'INDOOR' AS MainDept, c.SubSubPno AS DeptName, 0 AS Sales,0 AS Less,0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	0 AS DueCollection,0 AS Due, 0 As DueCollLess,sum(a.ReceiveAmt) AS AdvanceAmt,0 AS AdvanceAdjust
	from AmbulanceLedger a INNER JOIN PatientAdmission b ON a.PatientId=b.PatientId AND b.Valid=1 
	LEFT JOIN BedInformation c
	on a.BedNo=c.BedNo
	where a.Valid = 1 and a.PtStatus = 'Indoor' AND a.ReceiveAmt>0
	And a.RefDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	GROUP BY c.SubSubPno



	--UNION ALL
	----Medicine Cash Return
	--SELECT 1 as slno,'INDOOR' AS MainDept, 'MEDICINE', 0 AS Sales, 0 AS Less, 0 AS RtnAmt,
	--SUM(a.CashAmt) AS ByCash, SUM(a.CardAmt) AS ByCard, SUM(a.ChequeAmt) AS ByCheque, 
	--SUM(a.CashReturn) AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	--0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	--FROM PharSalesLedger a LEFT JOIN BedInformation b
	--on a.BedNo=b.BedNo
	--where a.Valid = 1 and a.PtStatus = 'Indoor'
	--and a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	--group by b.SubSubPno


	UNION ALL
	--Medicine Advance
	SELECT 1 as slno,'INDOOR' AS MainDept, c.SubSubPno, 0 AS Sales, 0 AS Less, 0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,0 AS TotalPt,sum(a.Collection) AS TotalColl,
	0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PharSalesLedger a INNER JOIN PatientAdmission b ON a.PatientId=b.PatientId AND b.Valid=1 
	LEFT JOIN BedInformation c
	on a.BedNo=c.BedNo
	where a.Valid = 1 and a.PtStatus = 'Indoor' AND a.Sales>0 AND a.Collection>0
	and a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	group by c.SubSubPno

	--UNION ALL
	----Medicine Due Collection
	--SELECT 1 as slno,'INDOOR' AS MainDept, 'MEDICINE', 0 AS Sales, 0 AS Less, 0 AS RtnAmt,
	--0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	--0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	--sum(a.Collection+a.DueColl) AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	--FROM PharSalesLedger a LEFT JOIN BedInformation b
	--on a.BedNo=b.BedNo
	--where a.Valid = 1 and a.PtStatus = 'Indoor'
	--and a.TrDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	--and a.PatientId NOT IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)
	--group by b.SubSubPno

	--UNION ALL
	----Diagnostic 
	--select 1 as slno, 'INDOOR' AS MainDept, a.Department AS DeptName, 0 AS Sales,0 AS Less,0 AS RtnAmt,
	--SUM(ByCash) AS ByCash, SUM(ByCard) AS ByCard, SUM(ChequeAmount) AS ByCheque, 
	--0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	--0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	--from SalesLedger a LEFT JOIN BedInformation b
	--on a.BedNo=b.BedNo
	--where valid <> 0 AND a.Department <> 'Ambulance' and a.PtStatus = 'Indoor' 
	--And a.RefDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	--GROUP BY b.SubSubPno,a.Department

	--UNION ALL
	----Diagnostic Due Coll/Advance
	--select 1 as slno, 'INDOOR' AS MainDept, a.Department AS DeptName, 0 AS Sales,0 AS Less,0 AS RtnAmt,
	--0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	--0 AS CashReturn,0 AS TotalPt,0 AS TotalColl,
	--sum(case when Sales=0 then Collection else 0 end)  AS DueCollection,0 AS Due, 0 As DueCollLess,
	--sum(case when Sales>0 then Collection else 0 end) AS AdvanceAmt,0 AS AdvanceAdjust
	--from SalesLedger a LEFT JOIN BedInformation b
	--on a.BedNo=b.BedNo
	--where valid <> 0 AND a.Department <> 'Ambulance' and a.PtStatus = 'Indoor' 
	--And a.RefDate BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId
	--and a.PatientId not IN(select PatientId from PatientReleaseMaster WHERE Valid=1 AND ReleaseDate BETWEEN @DateFrom AND @DateTo)
	--GROUP BY b.SubSubPno,a.Department

	-----------------------------------------------------------------------------------------------------------------
	UNION ALL

	select 3 as slno, 'OUTDOOR' AS MainDept, Department AS DeptName, SUM(Sales) AS Sales, 0 AS Less,0 AS RtnAmt,
	SUM(ByCash) AS ByCash, SUM(ByCard) AS ByCard, SUM(ChequeAmount) AS ByCheque, 
	0 AS CashReturn,SUM(CASE WHEN Sales>0 THEN 1 ELSE 0 END) AS TotalPt,sum(case when CRType='Sales' THEN Collection ELSE 0 END) AS TotalColl,
	0 AS DueCollection,0 AS Due, 
	0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	from SalesLedger 
	where valid = 1 AND Department <> 'Ambulance' and PtStatus <> 'Indoor' 
	and RefDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId
	GROUP BY Department	

	UNION ALL

	select 3 as slno, 'OUTDOOR' AS MainDept, Department AS DeptName,0 AS Sales, SUM(Less) AS Less, 0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,SUM(CASE WHEN Sales>0 THEN 1 ELSE 0 END) AS TotalPt,sum(case when CRType='Collection' THEN Collection ELSE 0 END) AS TotalColl,
	0 AS DueCollection,0 AS Due, 
	sum(case when CRType='Collection' THEN Less  ELSE 0 END) As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	from SalesLedger 
	where valid <> 0 AND Department <> 'Ambulance' and PtStatus <> 'Indoor' 
	and RefDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId
	and PrevInvNo IN(select InvNo from InvMaster WHERE Valid=1 AND InvDate BETWEEN @DateFrom AND @DateTo)
	GROUP BY Department	

	UNION ALL

	select 3 as slno, 'OUTDOOR' AS MainDept, Department AS DeptName, 0 AS Sales, 0 AS Less, 0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,SUM(CASE WHEN Sales>0 THEN 1 ELSE 0 END) AS TotalPt,0,
	sum(case when CRType='Collection' THEN Collection ELSE 0 END) AS DueCollection,0 AS Due, 
	sum(case when CRType='Collection' THEN Less  ELSE 0 END) As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	from SalesLedger 
	where valid <> 0 AND Department <> 'Ambulance' and PtStatus <> 'Indoor' 
	and RefDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId
	and PrevInvNo NOT IN(select InvNo from InvMaster WHERE Valid=1 AND InvDate BETWEEN @DateFrom AND @DateTo)
	GROUP BY Department	

	UNION ALL
	
	SELECT 3 AS SlNo, 'OUTDOOR' AS MainDept, a.Department AS DeptName, 
	0 AS Sales,0 AS Less, 0 as RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 
	0 AS CashReturn,COUNT(a.PatientID) AS TotalPt,
	0 AS TotalColl,0 AS DueCollection,
	SUM(Sales-a.Less-a.Collection-(a.ReturnAmount-a.ReturnCash-a.ReturnLess)) AS Due, 
	0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM SalesLedger a
	WHERE a.Valid = 1 AND CONVERT(DATE,a.PreInvDate) BETWEEN @dateFrom AND @dateTo 
	AND a.PtStatus != 'Indoor' AND a.BranchId=@branchId
	GROUP BY PrevInvNo, PreInvDate, a.Department, a.Particulars, a.PPhone, a.BranchId,a.PatientId
	HAVING SUM(Sales-a.Less-a.Collection-(a.ReturnAmount-a.ReturnCash-a.ReturnLess)) > 0

	UNION ALL

	SELECT 3 AS SlNo, 'OUTDOOR' AS MainDept, b.DeptName AS Department, 0 AS Sales, 0 AS Less, MAX(a.ReturnAmt-a.ReturnLess) AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, 0 AS CashReturn,0 AS TotalPt,
	-MAX(a.ReturnCash) AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM InvReturn a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
	WHERE a.BranchId =@branchId AND a.RtnInvDate BETWEEN @DateFrom AND @DateTo 
	and a.InvNo IN(select InvNo from InvMaster WHERE Valid=1 AND InvDate BETWEEN @DateFrom AND @DateTo AND PtStatus != 'Indoor' )
	GROUP BY b.DeptName, b.InvNo, a.RtnInvNo

	UNION ALL

	SELECT 3 AS SlNo, 'OUTDOOR' AS MainDept, b.DeptName AS Department, 0 AS Sales, 0 AS Less, 0 AS RtnAmt,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque, MAX(a.ReturnCash) AS CashReturn,0 AS TotalPt,
	0 AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM InvReturn a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
	WHERE a.BranchId =@branchId AND a.RtnInvDate BETWEEN @DateFrom AND @DateTo 
	and a.InvNo NOT IN(select InvNo from InvMaster WHERE Valid=1 AND InvDate BETWEEN @DateFrom AND @DateTo AND PtStatus != 'Indoor')
	GROUP BY b.DeptName, b.InvNo, a.RtnInvNo

	UNION ALL

	SELECT 5 as slno,'OUTDOOR' AS MainDept, 'MEDICINE' AS DeptName, SUM(SALES) AS Sales, SUM(LessAmt) AS Less, 
	SUM(ReturnAmt) AS RtnAmt,
	SUM(CashAmt) AS ByCash, SUM(CardAmt) AS ByCard, SUM(ChequeAmt) AS ByCheque, 
	SUM(CashReturn) AS CashReturn,SUM(CASE WHEN SALES>0 THEN 1 ELSE 0 END) AS TotalPt,sum(Collection) AS TotalColl,
	SUM(DueColl) AS DueCollection,0 AS Due, SUM(DueLess) As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM PharSalesLedger 
	where valid = 1 and PtStatus <> 'Indoor'
	and TrDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId

	

	UNION ALL 

	SELECT 2 as slno, 'OUTDOOR' AS MainDept, 'OPD TICKET' AS DeptName, SUM(Amount) AS Sales, 0 as Less, 0 AS RtnAmt,
	SUM(Amount) as CashAmt, 0 as CardAmt, 0 as ChequeAmt, 
	SUM(a.RtnAmount) as CashReturn,COUNT(TrNo) AS TotalPt,sum(a.Received) AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM OPDTicketMaster a
	where a.valid = 1 and a.TrDate BETWEEN @DateFrom and @DateTo AND BranchId = @BranchId

	UNION ALL
	SELECT 6 as slno, PtStatus As MainDept, 'Ambulance' AS DeptName, SUM(TotalCharge) AS Sales, SUM(Less), 0 AS RtnAmt,
	SUM(CashAmt) as ByCash, SUM(CardAmt) as ByCard, SUM(ChequeAmt) as ByCheque, 0 AS CashReturn,
	SUM(CASE WHEN TotalCharge>0 THEN 1 ELSE 0 END) AS TotalPt,sum(ReceiveAmt) AS TotalColl,0 AS DueCollection,0 AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM AmbulanceLedger
	where valid = 1 AND PtStatus='OUTDOOR'
	and RefDate BETWEEN @DateFrom and @DateTo
	GROUP BY PtStatus

	UNION ALL
	SELECT 6 as slno, a.PtStatus As MainDept, 'Ambulance' AS DeptName, 0 AS Sales, 0, 0 AS RtnAmt,
	0 as ByCash, 0 as ByCard, 0 as ByCheque, 0 AS CashReturn,
	0 AS TotalPt,0 AS TotalColl,0 AS DueCollection,SUM(a.TotalCharge - a.Less - a.ReceiveAmt) AS Due, 0 As DueCollLess,0 AS AdvanceAmt,0 AS AdvanceAdjust
	FROM AmbulanceLedger a,AmbulanceMaster b
	where a.Valid = 1 AND a.PtStatus='OUTDOOR'
	AND a.PrevReceiptNo=b.ReceiptNo  AND a.RegNo = b.RegNo AND a.Valid = b.Valid AND a.BranchId = b.BranchId
	and b.ReceiptDate BETWEEN @DateFrom and @DateTo
	GROUP BY a.PtStatus

	) aa
	GROUP BY aa.MainDept , aa.DeptName,aa.slno
	HAVING SUM(aa.Sales+aa.Less+aa.RtnAmt+aa.ByCash+aa.ByCard+aa.ByCheque+aa.CashReturn) <> 0
	ORDER BY aa.MainDept,aa.DeptName 
END
GO
/****** Object:  StoredProcedure [dbo].[SP_ManufacturingAccount]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROC [dbo].[SP_ManufacturingAccount] (@Pno AS Int,@dateFrom AS date,@dateTo AS date)AS
BEGIN
DELETE FROM tmp_MA
INSERT INTO tmp_MA
SELECT 1 as SlNO,'' AS Code, 'O/B' AS Particulars,Isnull(SUM(InQty*PurchasePrice-OutQty*PurchasePrice+RtnQty*PurchasePrice-PRtnQty*PurchasePrice),0) AS Bal ,
1 AS Bal1 
FROM tbl_STOCK_LEDGER WHERE TrDate< @dateFrom AND Valid=1 AND Pno=@Pno
UNION ALL
SELECT 2,a.Code,('Add '+ b.Description) AS Particulars,Isnull(SUM(a.Debit-a.Credit),0) AS Bal ,1 AS Bal1 
FROM tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
WHERE a.Code = b.Code and b.Type= 'Manufacturing A/C' 
and a.Trans_dt BETWEEN @dateFrom AND @dateTo AND a.Valid=1 AND a.Pno=@Pno
GROUP BY a.Code,b.Description
UNION ALL
SELECT 3,'','Less C/S' AS Particulars,Isnull(SUM(InQty*PurchasePrice-OutQty*PurchasePrice+RtnQty*PurchasePrice-PRtnQty*PurchasePrice),0) AS Bal,
(-1) AS Bal1 
FROM tbl_STOCK_LEDGER WHERE TrDate<=@dateTo AND Valid=1 AND Pno=@Pno
select slno,code,Particulars,Bal from tmp_MA
UNION ALL
select 4,'','Cost Of Goods Sold' , SUM(Bal*Bal1)
from tmp_MA
END










GO
/****** Object:  StoredProcedure [dbo].[sp_MarketingDrCommissionForSmamc]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE proc [dbo].[sp_MarketingDrCommissionForSmamc] @BranchId int, @DrCode varchar(150), @DateFrom date, @DateTo date
AS
BEGIN --   sp_MarketingDrCommissionForSmamc 1, 'DR0CH2', '2024-05-01', '2024-05-20'

	select aa.SlNo, aa.Description, aa.BedNo, aa.PatientId, aa.DrCode, aa.DrName, aa.TotalAmount, aa.Commission, aa.Commission*.10 AS PayableCommission, b.PatientName, b.PatientSex, b.PatientAge, b.UnderDrCode, b.UnderDrName
	from 
	(
		-- Start Bed Charge Calculation
		select 1 AS SlNo, 'Bed Charge' AS Description, c.BedNo, a.BranchId, a.PatientId, b.DrCode, b.DrName+' '+b.Degree AS DrName, c.TotalAmount, 
		case when d.BedType = 'Ward' then c.Charge-200 when d.BedType = 'Cabin' then Charge-500 when d.BedType = 'ICU' then Charge-500 when d.BedType = 'HDU' then Charge-500 end AS Commission
		from PatientAdmission a
		inner join DrInfo b on b.BranchId = a.BranchId and b.DrCode = a.MediDrCode and b.DrType = 'Marketing'
		inner join PatientLedger c ON c.BranchId = a.BranchId and c.PatientId = a.PatientId and c.Code = '0002'
		inner join BedInformation d on d.BranchId = a.BranchId and d.BedNo = c.BedNo
		WHERE a.BranchId = @BranchId and c.RefDate BETWEEN @DateFrom AND @DateTo AND (CASE WHEN @DrCode != '' THEN a.MediDrCode Else '' END) = @DrCode
		-- END Bed Charge Calculation

		-- Start Surgery Calculation
		UNION ALL
		select 2 AS SlNo, 'Surgery Charge' AS Description, c.BedNo, a.BranchId, a.PatientId, b.DrCode, b.DrName+' '+b.Degree AS DrName, c.TotalAmount, 
		c.Charge Commission
		from PatientAdmission a
		inner join DrInfo b on b.BranchId = a.BranchId and b.DrCode = a.MediDrCode and b.DrType = 'Marketing'
		inner join PatientLedger c ON c.BranchId = a.BranchId and c.PatientId = a.PatientId and c.Code IN ('0004', '5752', '5753')
		WHERE a.BranchId = @BranchId and c.RefDate BETWEEN @DateFrom AND @DateTo AND (CASE WHEN @DrCode != '' THEN a.MediDrCode Else '' END) = @DrCode
		-- END Surgery Calculation

		-- Start Test Calculation
		UNION ALL
		select 3 AS SlNo, 'Test Charge' AS Description, c.BedNo, a.BranchId, a.PatientId, b.DrCode, b.DrName+' '+b.Degree AS DrName, c.Sales, 
		c.Sales Commission
		from PatientAdmission a
		inner join DrInfo b on b.BranchId = a.BranchId and b.DrCode = a.MediDrCode and b.DrType = 'Marketing'
		inner join SalesLedger c ON c.BranchId = a.BranchId and c.PatientId = a.PatientId
		WHERE a.BranchId = @BranchId and c.RefDate BETWEEN @DateFrom AND @DateTo AND (CASE WHEN @DrCode != '' THEN a.MediDrCode Else '' END) = @DrCode
		-- END Test Calculation
	) aa
	left join PatientAdmission b on b.BranchId = aa.BranchId and b.PatientId = aa.PatientId
	order by b.MediDrCode, b.PatientId, aa.SlNo
END

GO
