CREATE PROCEDURE[dbo].[SP_MarketingExeutivePayment] @BranchId Int, @Unit Int, @InvNo nvarchar(20), @InvDate date
AS --- EXEC SP_MarketingExeutivePayment 1, 1, '001', 'MRP240200001', '0001-01-01'
BEGIN
Select a.InvNo, a.InvDate, a.DateFrom, a.DateTo, a.MrId, b.MRName, a.DrCode, a.DrName, a.Amount, a.Paid, a.Less, a.Due, a.SalesAmt, a.Payment, a.PcOrTk, a.PayableAmt, a.CashAmt, a.ReceiveAmt, a.PreviousDue, a.RestDue, a.TotalDue, a.CardAmt, a.CardNo, a.CardBank, a.ChequeAmt, a.ChequeNo, a.ChequeBank, a.ChequeDate, 
a.Remarks, a.UserName, a.EntryDateTime From MRPayment a
Left Join tbl_MRInfo b On a.Valid = b.Valid And a.BranchId = b.BranchId And a.MrId = b.MRId
Where a.Valid = 1 And a.BranchId = @BranchId And a.UnitId = @Unit And a.InvNo = @InvNo 
And a.InvDate = @InvDate And a.DrCode = ''
END
