CREATE PROCEDURE [dbo].[SP_MedicineListwithExpireDate] (@BranchId INT, @UnitId INT, @CompanyId NVARCHAR(20), @DateFrom NVARCHAR(20), @DateTo NVARCHAR(20), @Store NVARCHAR(50))
AS --- EXEC SP_MedicineListwithExpireDate 1, 1, 'A001', '2020-01-01', '2026-12-31', '72'
BEGIN
	SELECT ISNULL(a.CompanyId,'') as CompanyId, a.ProductName, a.CurrentStock as CurrentQty, a.TP, a.ExpiryDate, c.SubSubPno AS StoreName
	FROM VW_PharCurrentStock a 
	--LEFT JOIN PharProductInfo b ON a.Id = b.Id
	LEFT JOIN ProjectInformations c ON a.StoreId = c.PnoCode
	WHERE a.BranchId=@BranchId AND a.UnitId=@UnitId AND a.CompanyId LIKE '%'+@CompanyId+'%' AND a.ExpiryDate BETWEEN @DateFrom AND @DateTo AND a.StoreId LIKE '%'+@Store+'%' AND a.CurrentStock > 0 
	GROUP BY a.CompanyId, a.CompanyName, a.ProductName,  a.CurrentStock, a.TP, a.ExpiryDate, c.SubSubPno
	ORDER BY a.CompanyId
END
