CREATE PROC [dbo].[SP_MedicineSalesDiscount] (@fromDate date, @toDate date, @unitId int, @branchId int, @ptStatus nvarchar(20), @storeId nvarchar(10)) 
AS   --- EXEC SP_MedicineSalesDiscount '2024-06-01', '2024-06-30', 1, 1, '', '166'
BEGIN
SELECT a.TrNo, a.TrDate, a.DeptName, a.RegNo, a.PatientId, a.PatientName, a.BedNo, a.PtStatus, a.UserName, a.EntryDateTime , a.LessAmt, a.DueLess, b.Remarks, a.StoreId, c.SubSubPno as StoreName
FROM PharSalesLedger a
LEFT JOIN PharSalesMaster b ON a.TrNo = b.SaleNo AND a.TrDate = b.SaleDate AND a.StoreId=b.StoreId
INNER JOIN ProjectInformations c On a.StoreId=c.PnoCode AND b.StoreId=c.PnoCode
WHERE a.Valid = 1 AND b.Valid = 1 AND a.BranchId = @branchId AND a.UnitId = @unitId AND a.PtStatus LIKE '%'+@ptStatus+'%' AND a.TrDate BETWEEN @fromDate AND @toDate AND 
a.StoreId LIKE '%'+@storeId+'%' AND a.LessAmt > 0 OR a.DueLess > 0 
END
GO
