CREATE Procedure [dbo].[SP_MedicineSalesProductWiseSMZ] @fromDate date, @toDate date, @unitId int, @branchId int, @ptStatus nvarchar(20),  @storeId nvarchar(10)
AS  --- EXEC SP_MedicineSalesProductWiseSMZ '2024-05-01', '2024-06-12', 1, 1, '', ''
BEGIN
Select a.PtStatus, a.ProductId, b.ProductName, sum(a.ProductQty) as ProductQty, sum(a.ProductQty* a.SalePrice) as TotalSalesPrice, sum(a.ProductQty* a.TP) as TotalPurchase,
 sum(a.ItemLess) as ItemLess, sum((a.ProductQty* a.SalePrice) - (a.ProductQty* a.TP) - a.ItemLess) as Profit, a.UserName, c.SubSubPno as StoreName
From PharSalesDetails a
INNER JOIN PharProductInfo b On a.ProductId=b.Id
INNER JOIN ProjectInformations c On a.StoreId=c.PnoCode
WHERE a.Valid=1 AND a.SaleDate BETWEEN @fromDate AND @toDate AND  a.UnitId=@unitId AND a.BranchId=@branchId AND a.PtStatus LIKE '%'+@ptStatus+'%' 
AND a.StoreId LIKE  '%'+@storeId+'%'
GROUP BY a.PtStatus, a.ProductId, b.ProductName, a.UserName, c.SubSubPno
END
GO
