CREATE PROC [dbo].[SP_MedicineSalesRegisterDetails] (@fromDate date, @toDate date, @unitId int, @branchId int, @ptStatus nvarchar(20),  @storeId nvarchar(10))
AS  ---  EXEC SP_MedicineSalesRegisterDetails '2024-05-01', '2024-06-12', 1,1,'','72'
BEGIN
SELECT a.SaleNo AS TrNo, a.SaleDate AS TrDate, a.DeptName, a.PtStatus, a.RegNo, a.PatientId, a.PatientName, b.ProductId, b.ProductName, b.ProductQty, b.SalePrice, b.TP, b.ItemLess, SUM((b.ProductQty * b.SalePrice)- (b.ProductQty * b.TP) -b.ItemLess) AS Profit, b.UserName, b.StoreId, b.UnitId, b.BranchId, c.TotalProduct, d.SubSubPno as StoreName ,c.TotalSale
FROM (SELECT c.SaleNo, c.SaleDate, SUM(c.ProductQty) AS TotalProduct, SUM(c.ProductQty * c.SalePrice) AS TotalSale
FROM PharSalesDetails c
WHERE c.Valid = 1
GROUP BY c.SaleNo, c.SaleDate) c
LEFT JOIN PharSalesMaster a ON a.SaleNo = c.SaleNo AND a.SaleDate = c.SaleDate
LEFT JOIN PharSalesDetails b ON a.SaleNo = b.SaleNo AND a.SaleDate = b.SaleDate
LEFT JOIN ProjectInformations d On a.StoreId=d.PnoCode
WHERE a.Valid = 1 AND b.Valid = 1 AND a.BranchId = @branchId AND a.UnitId = @unitId AND a.PtStatus LIKE '%'+@ptStatus+'%' AND a.SaleDate BETWEEN @fromDate AND @toDate 
 AND a.StoreId LIKE  '%'+@storeId+'%'
GROUP BY a.SaleNo, a.SaleDate, a.DeptName, a.PtStatus, a.RegNo, a.PatientId, a.PatientName, b.ProductId, b.ProductName, b.ProductQty, b.SalePrice, b.TP, b.ItemLess, b.UserName, b.StoreId, b.UnitId, b.BranchId, c.TotalProduct, d.SubSubPno, c.TotalSale
ORDER BY a.SaleNo
END
GO
