CREATE PROC [dbo].[SP_MIS_DrSalesLedger] @BranchId INT, @DateFrom DATE, @DateTo DATE, @DrCode VARCHAR(20)
AS
BEGIN /* EXEC SP_MIS_DrSalesLedger 1, '2023-08-01', '2023-08-05', '' */
select 1 AS SlNo, b.DeptName, '' AS PtStatus, b.ConsultantCode AS DrCode, b.ConsultantName AS DrName, 0 AS Count, 
SUM(a.Sales-a.ReturnAmount) AS TotalSales, SUM(a.Less-a.ReturnLess) AS TotalLess, SUM(a.Sales-a.Less-a.ReturnNet) AS NetTotal
from SalesLedger a
LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.PreInvDate = b.InvDate AND a.PrevInvNo = b.InvNo AND b.Valid = 1
where a.BranchId = @BranchId AND a.Valid = 1 AND a.PreInvDate BETWEEN @DateFrom and @DateTo AND b.ConsultantCode LIKE '%'+@DrCode+'%'
group by b.DeptName, b.ConsultantCode, b.ConsultantName
UNION ALL
SELECT 2 AS SlNo, 'Indoor' AS DeptName, 'Indoor' AS PtStatus, a.UnderDrCode AS DrCode, a.UnderDrName AS DrName, count(DISTINCT a.PatientId) AS NoOfPtn, 
SUM(b.TotalAmount) AS Sales, SUM(b.Less) AS Less, SUM(b.TotalAmount-b.Less) AS Net
FROM PatientAdmission a
LEFT JOIN PatientLedger b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId AND b.Valid = 1
WHERE a.BranchId = @BranchId AND b.Valid = 1 AND a.IsRelease = 1 AND a.UnderDrCode LIKE '%'+@DrCode+'%'
AND a.ReleaseDate BETWEEN @DateFrom and @DateTo AND b.Code NOT IN ('0011')
GROUP BY a.UnderDrCode, a.UnderDrName

UNION ALL
SELECT 3 AS SlNo,'OPD Ticket' AS DeptName, 'Outdoor' AS PtStatus, a.DrCode, b.DrName AS DrName, SUM(SQty) AS NoOfPtn,
SUM(Sales-ReturnAmt) AS Sales, 0 AS Less, SUM(Sales-ReturnAmt) AS Net
FROM(
SELECT a.BranchId, DrCode, Amount AS Sales, 0 AS ReturnAmt, 1 AS SQty
FROM OPDTicketMaster a
WHERE a.Valid = 1 AND BranchId = @BranchId AND TrDate BETWEEN @DateFrom AND @DateTo
UNION ALL
SELECT b.BranchId, DrCode, 0 AS Sales, b.RtnAmount AS ReturnAmt, -1 AS SQty
FROM OPDTicketReturn a
LEFT JOIN OPDTicketMaster b ON a.OpdId = b.Id AND b.Valid = 1
WHERE a.Valid = 1 AND b.BranchId = @BranchId AND a.TrDate BETWEEN @DateFrom AND @DateTo
) a
LEFT JOIN DrInfo b ON a.DrCode = b.DrCode AND a.BranchId = b.BranchId
WHERE a.BranchId = @BranchId AND a.DrCode LIKE '%'+@DrCode+'%'
GROUP BY a.DrCode, b.DrName



SELECT * FROM OPDTicketMaster

ORDER BY 4, 3
END
GO
