CREATE PROC [dbo].[Sp_MisCollReportSummarized] @BranchId INT, @DateFrom DATE, @DateTo DATE
AS
BEGIN /* EXEC Sp_MisCollReportSummarized 1, '2022-10-01', '2022-10-01' */

/*Condition for IsInclude Pharmacy bill*/
DECLARE @IncludePharmacy INT, @IsIncludePharmacy INT;
SELECT @IncludePharmacy = PharmacyInclude FROM tbl_ComInfo
IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END

/* Sales Ledger Collection */
SELECT a.Department, SUM(a.Collection) AS Collection, SUM(a.CashReturn) AS CashReturn FROM (
SELECT a.Department, a.PrevInvNo, SUM(a.Collection) AS Collection, 0 AS CashReturn
FROM SalesLedger a
WHERE BranchId = @BranchId AND RefDate BETWEEN @DateFrom AND @DateTo AND a.Valid = 1
GROUP BY a.Department, a.PrevInvNo
UNION ALL
select distinct b.DeptName AS Department, a.InvNo, 0 AS Collection, a.ReturnCash
from InvReturn a
LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
where a.BranchId = @BranchId AND a.Valid = 1 AND a.RtnInvDate between @DateFrom and @DateTo
UNION ALL
select b.DeptName AS Department, b.InvNo, 0 AS Collection, SUM(Amount) from InvRefund a
LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.TrDate BETWEEN @DateFrom AND @DateTo
group by b.DeptName, b.InvNo
) a
GROUP BY a.Department
/* End Sales Ledger Collection */

/* Start Indoor Collection */
UNION ALL
SELECT 'Indoor' AS Department, SUM(Collection) AS Collection, SUM(CashReturn) AS CashReturn 
FROM (
SELECT SUM(Collection) AS Collection, SUM(a.ReturnAmt) AS CashReturn 
FROM PatientLedger a 
WHERE BranchId = @BranchId AND a.RefDate BETWEEN @DateFrom AND @DateTo AND a.Valid = 1
UNION ALL
SELECT 0 AS Collection, SUM(Amount) AS CashReturn
FROM CashReturn WHERE Valid = 1 ANd TrDate BETWEEN @DateFrom AND @DateTo
) a
/* End Indoor Collection */


UNION ALL
SELECT 'Medicine' AS Department, SUM(Collection+DueColl) AS Collection, SUM(CashReturn) AS CashReturn
FROM PharSalesLedger a
WHERE a.BranchId = @BranchId AND Valid = @IncludePharmacy AND a.TrDate BETWEEN @DateFrom AND @DateTo
HAVING SUM(Collection+DueColl+CashReturn) != 0
/* Start Opd Ticket */
UNION ALL
SELECT 'OPD Ticket', SUM(Collection) AS Collection, SUM(CashReturn) AS CashReturn
FROM(
SELECT SUM(Amount) AS Collection, 0 AS CashReturn
FROM OPDTicketMaster a
WHERE a.Valid = 1 AND BranchId = @BranchId AND TrDate BETWEEN @DateFrom AND @DateTo
UNION ALL
SELECT 0 AS Collection, SUM(b.RtnAmount) AS CashReturn FROM OPDTicketReturn a
LEFT JOIN OPDTicketMaster b ON a.OpdId = b.Id AND b.Valid = 1
WHERE a.Valid = 1 AND b.BranchId = @BranchId AND a.TrDate BETWEEN @DateFrom AND @DateTo
) a
HAVING SUM(Collection+CashReturn) != 0
/* End Opd Ticket */
UNION ALL
SELECT 'Registration Card', SUM(Amount) AS Collection, 0 AS CashReturn FROM RegistrationFees a
WHERE a.BranchId = @BranchId AND a.Valid =  1 AND a.TrDate BETWEEN @DateFrom AND @DateTo
HAVING SUM(Amount) != 0
END
GO
/****** Object:  StoredProcedure [dbo].[Sp_MISCollReportSummarized_DateWise]    Script Date: 3/12/2026 6:25:16 AM ******/
