CREATE PROC [dbo].[Sp_MISCollReportSummarized_DateWise] @BranchId INT, @DateFrom DATE, @DateTo DATE
AS
BEGIN /* EXEC Sp_MISCollReportSummarized_DateWise 1, '2023-01-01','2023-01-31' */

/* Sales Ledger Collection */
SELECT a.TrDate ,a.Department, SUM(a.Collection) AS Collection, SUM(a.CashReturn) AS CashReturn , SUM(a.Collection-a.CashReturn) AS NetColl
INTO #Z
FROM (
	SELECT a.RefDate as TrDate, a.Department, a.PrevInvNo, SUM(a.Collection) AS Collection, 0 AS CashReturn
	FROM SalesLedger a
	WHERE BranchId = @BranchId
	AND RefDate BETWEEN @DateFrom AND @DateTo
	AND a.Valid = 1
	GROUP BY a.Department, a.PrevInvNo , a.RefDate
	UNION ALL
	select a.RtnInvDate, b.DeptName AS Department, a.InvNo, 0 AS Collection, a.ReturnCash
	from InvReturn a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
	where a.BranchId = @BranchId AND a.Valid = 1 AND a.RtnInvDate between @DateFrom AND @DateTo
	group by a.RtnInvDate, b.DeptName, a.InvNo,  a.ReturnCash
	UNION ALL
	select a.TrDate,b.DeptName AS Department, b.InvNo, 0 AS Collection, SUM(Amount) from InvRefund a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
	WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.TrDate BETWEEN @DateFrom AND @DateTo
	group by b.DeptName, b.InvNo ,a.TrDate
) a
GROUP BY a.Department , a.TrDate 
/* End Sales Ledger Collection */

/* Start Indoor Collection */
UNION ALL
SELECT a.TrDate,'Indoor' AS Department, SUM(Collection) AS Collection, SUM(CashReturn) AS CashReturn ,
SUM(Collection-CashReturn) AS NetColl 
FROM (
SELECT RefDate as TrDate,Collection, a.ReturnAmt AS CashReturn  
FROM PatientLedger a 
WHERE BranchId = @BranchId AND a.RefDate BETWEEN @DateFrom AND @DateTo AND a.Valid = 1
UNION ALL
SELECT TrDate,0 AS Collection, Amount AS CashReturn
FROM CashReturn WHERE Valid = 1 ANd TrDate BETWEEN @DateFrom AND @DateTo
) a
GROUP BY a.TrDate
/* End Indoor Collection */

/* Start Opd Ticket */
UNION ALL
SELECT TRDate,'OPD Ticket', SUM(Collection) AS Collection, SUM(CashReturn) AS CashReturn ,
SUM(Collection-CashReturn) as NetColl
FROM(
	SELECT TrDate,Amount AS Collection, 0 AS CashReturn
	FROM OPDTicketMaster a
	WHERE a.Valid = 1 AND BranchId = @BranchId AND TrDate BETWEEN @DateFrom AND @DateTo
	UNION ALL
	SELECT a.TrDate,0 AS Collection, b.RtnAmount AS CashReturn 
	FROM OPDTicketReturn a
	LEFT JOIN OPDTicketMaster b ON a.OpdId = b.Id AND b.Valid = 1
	WHERE a.Valid = 1 AND b.BranchId = @BranchId AND a.TrDate BETWEEN @DateFrom AND @DateTo
) a
GROUP BY TrDate 
/* End Opd Ticket */
UNION ALL
SELECT a.TrDate,'Registration Card', SUM(a.Amount) AS Collection, 0 AS CashReturn , SUM(a.Amount) AS NetColl
FROM RegistrationFees a
WHERE a.BranchId = 1 AND a.Valid =  1 AND a.TrDate BETWEEN @DateFrom AND @DateTo
GROUP BY a.TrDate
HAVING SUM(a.Amount) <> 0

select TrDate , Department as Department, ISNULL(NetColl,0) AS NetColl  
INTO #Z1
from #Z 
--UNION ALL
--select TrDate, ('Total') AS Department , SUM(IsNull(NetColl,0)) AS Netcoll
--from #Z  
--GROUP BY TrDate
order by TrDate , department

select TrDate, Department, NetColl from #z1 

--DECLARE @cols AS NVARCHAR(MAX),
--    @query  AS NVARCHAR(MAX);

--SET @cols = STUFF((SELECT distinct ',' + QUOTENAME(c.department) 
--            FROM #Z1 c
--            FOR XML PATH(''), TYPE
--            ).value('.', 'NVARCHAR(MAX)') 
--        ,1,1,'')    
--set @query = 'SELECT TrDate, ' + @cols + ' from 
--            (
--                select TrDate
--                    , department
--					, netColl
--                from #Z1 
--           ) x
--            pivot 
--            (
--                 SUM(NetColl)
--                for department in (' + @cols + ')
--            ) p '
--execute(@query);

END
GO
/****** Object:  StoredProcedure [dbo].[Sp_MisCollReportTypewiseSummary]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
