create PROC [dbo].[Sp_MisCollReportTypewiseSummary] @DateFrom DATE, @DateTo DATE, @BranchId INT, @UserName VARCHAR(50)
AS
BEGIN ---     Sp_MisCollReportTypewiseSummary '2025-06-01', '2025-06-01', 1,''

/*Condition for IsInclude Pharmacy bill*/
DECLARE @IncludePharmacy INT, @IsIncludePharmacy INT;		
SELECT @IncludePharmacy = PharmacyInclude FROM tbl_ComInfo;
IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END;

WITH zz AS(
	SELECT a.UserName, SUM(a.Collection) AS Collection, SUM(CashReturn) AS CashReturn, SUM(a.Collection-a.CashReturn) AS NetAmt, 
	SUM(a.Cash-a.CashReturn) AS Cash, SUM(a.Card) AS Card, a.CardBank, SUM(a.Cheque) AS Cheque, a.ChequeBank
	FROM (
		
		/* -- OUTDOOER -- */
		--Collection
		SELECT 'Outdoor' AS Dept, a.UserName, a.Collection, 0 AS CashReturn,
		a.ByCash AS Cash, a.ByCard AS Card, a.CardBank, a.ChequeAmount AS Cheque, a.ChequeBank
		FROM SalesLedger a
		WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.RefDate BETWEEN @DateFrom AND @DateTo AND a.Department!='Dialysis'
		AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName
		--and a.Collection > 0

		--Return
		UNION ALL
		SELECT 'Outdoor' AS Dept, a.UserName, 0 AS Collection, MAX(a.ReturnCash) AS CashReturn,
		0 AS Cash, 0 AS Card, '' AS CardBank, 0 AS Cheque, '' AS ChequeBank
		FROM InvReturn a INNER JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
		WHERE a.BranchId = @BranchId AND a.Valid=1 AND a.BranchId=@BranchId AND a.RtnInvDate BETWEEN @DateFrom AND @DateTo
		AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName AND b.DeptName!='Dialysis'
		GROUP BY a.UserName, a.RtnInvNo
		HAVING MAX(a.ReturnCash) > 0

		--select 'Outdoor' AS Dept, a.UserName, 0 AS Collection, a.ReturnCash,
		--0 AS Cash, 0 AS Card, '' AS CardBank, 0 AS Cheque, '' AS ChequeBank
		--from InvReturn a
		--LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
		--where a.BranchId = @branchId AND a.Valid = 1 AND a.RtnInvDate between @dateFrom AND @dateTo AND a.ReturnCash != 0

		--Refund
		UNION ALL		
		SELECT 'Outdoor' AS Dept, a.UserName, 0 AS Collection, Amount AS CashReturn,
		0 AS Cash, 0 AS Card, '' AS CardBank, 0 AS Cheque, '' AS ChequeBank
		FROM InvRefund a INNER JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo 
		WHERE a.Valid=1  AND a.BranchId = @BranchId AND a.BranchId=@BranchId AND a.TrDate BETWEEN @DateFrom AND @DateTo AND b.DeptName!='Dialysis'
		AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName
		--and a.Amount>0

		/* -- INDOOR -- */
		--Collection, Return
		UNION ALL
		SELECT 'Indoor' AS Dept, a.UserName, a.Collection, a.ReturnAmt,
		a.CashAmt AS Cash, a.CardAmt AS Card, CASE WHEN a.CardAmt >  0 THEN a.CardBank ELSE '' END AS CardBank,
		a.ChequeAmt AS Cheque, CASE WHEN a.ChequeAmt > 0 THEN a.ChequeBank ELSE '' END AS ChequeBank
		FROM PatientLedger a
		WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.Collection+a.ReturnAmt > 0
		AND a.RefDate BETWEEN @DateFrom AND @DateTo
		AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName

		--Return
		UNION ALL
		SELECT 'Retun' AS Dept, a.UserName, 0 AS Collection, a.Amount AS ReturnAmt,
		0 AS Cash, 0 AS Card, '' AS CardBank,
		0 AS Cheque, '' AS ChequeBank
		FROM CashReturn a
		WHERE a.Valid=1 AND a.TrDate BETWEEN @DateFrom AND @DateTo
		AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName

		/* -- PHARMACY -- */
		--Collection With Return
		UNION ALL
		SELECT 'Pharmacy' AS Dept, a.UserName, a.Collection+a.DueColl AS Collection, a.CashReturn,
		a.CashAmt AS Cash, a.CardAmt AS Card, CASE WHEN a.CardAmt >  0 THEN a.CardBank ELSE '' END AS CardBank,
		a.ChequeAmt AS Cheque, CASE WHEN a.ChequeAmt > 0 THEN a.ChequeBank ELSE '' END AS ChequeBank
		FROM PharSalesLedger a
		WHERE a.BranchId=1 AND a.Valid=@IncludePharmacy AND a.TrDate BETWEEN @DateFrom AND @DateTo
		AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName

		/* -- OPD TICKET -- */
		--Collection

		UNION ALL		
		SELECT 'OpdTicket' AS Dept, a.UserName, a.Received AS Collection,  a.CashReturn AS CashReturn,
		CashAmount AS Cash, CardAmount AS Card, CardBank AS CardBank, ChequeAmount AS Cheque, ChequeBank AS ChequeBank
		FROM OPDTicketLedger a
		WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.RefDate BETWEEN @DateFrom AND @DateTo 
		AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName --AND a.Received!=0



		--UNION ALL		
		--SELECT 'OpdTicket' AS Dept, a.UserName, a.Received AS Collection,  a.CashReturn AS CashReturn,
		--a.Received AS Cash, 0 AS Card, '' AS CardBank, 0 AS Cheque, '' AS ChequeBank
		--FROM OPDTicketLedger a
		--WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.RefDate BETWEEN @DateFrom AND @DateTo 
		--AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName --AND a.Received!=0

		--Return
		--UNION ALL
		--SELECT 'OpdTicket' AS Dept, a.UserName, 0 AS Collection, b.RtnAmount AS CashReturn,
		--0 AS Cash, 0 AS Card, '' AS CardBank, 0 AS Cheque, '' AS ChequeBank
		--FROM OPDTicketReturn a
		--LEFT JOIN OPDTicketMaster b on a.OpdId=b.Id
		--WHERE a.Valid=1 AND b.BranchId=@BranchId AND a.TrDate BETWEEN @DateFrom AND @DateTo
		UNION ALL

		/* -- Ambulance -- */
		SELECT 'Ambulance' AS Dept, a.UserName, a.ReceiveAmt AS Collection, 0 AS CashReturn,
		a.CashAmt AS Cash, a.CardAmt AS Card, CASE WHEN a.CardAmt >  0 THEN a.CardBank ELSE '' END AS CardBank,
		a.ChequeAmt AS Cheque, CASE WHEN a.ChequeAmt > 0 THEN a.ChequeBank ELSE '' END AS ChequeBank
		FROM AmbulanceLedger a
		WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.RefDate BETWEEN @DateFrom AND @DateTo
		AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName

		/* -- Registration -- */
		UNION ALL
		SELECT 'Registration' AS Dept, a.UserName, a.Amount AS Collection, 0 AS CashReturn,
		a.Amount AS Cash, 0 AS Card, '' AS CardBank,
		0 AS Cheque, '' AS ChequeBank
		FROM RegistrationFees a
		WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.TrDate BETWEEN @DateFrom AND @DateTo
		AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName

	) a
	GROUP BY a.UserName, a.CardBank, a.ChequeBank
)
SELECT a.UserName, a.Collection, a.CashReturn, a.NetAmt, a.Cash, a.Card, a.CardBank, a.Cheque, a.ChequeBank
INTO #z
--  drop table #z
FROM zz a

UPDATE #z SET CardBank='POS' WHERE Card>0 AND CardBank NOT IN ('Bkash', 'Nagad')
UPDATE #z SET CardBank='Cheque' WHERE Cheque>0 

SELECT a.UserName, SUM(a.Collection) AS Collection, SUM(a.CashReturn) AS CashReturn, SUM(NetAmt) AS NetAmt, 
SUM(a.Cash) AS Cash, SUM(a.Bkash) AS Bkash, SUM(a.Nagad) AS Nagad, SUM(a.POS) AS POS,SUM(a.Cheque) as Cheque 
FROM (
	SELECT a.UserName, a.Collection, a.CashReturn, a.NetAmt, a.Cash, 0 AS Bkash, 0 AS Nagad, 0 AS POS,0 AS Cheque
	FROM #z a
	UNION ALL
	SELECT a.UserName, 0 as Collection, 0 AS CashReturn, 0 AS NetAmt, 0 AS Cash, a.Card AS Bkash, 0 AS Nagad, 0 AS POS,0 AS Cheque
	FROM #z a
	WHERE a.CardBank='BKash'
	UNION ALL
	SELECT a.UserName, 0 as Collection, 0 AS CashReturn, 0 AS NetAmt, 0 AS Cash, 0 AS Bkash, a.Card AS Nagad, 0 AS POS,0 AS Cheque
	FROM #z a
	WHERE a.CardBank='Nagad'
	UNION ALL
	SELECT a.UserName, 0 as Collection, 0 AS CashReturn, 0 AS NetAmt, 0 AS Cash, 0 AS Bkash, 0 AS Nagad, a.Card AS POS,0 AS Cheque
	FROM #z a
	WHERE a.CardBank='POS'
	UNION ALL
	SELECT a.UserName, 0 as Collection, 0 AS CashReturn, 0 AS NetAmt, 0 AS Cash, 0 AS Bkash, 0 AS Nagad, 0 AS POS,a.Cheque AS Cheque
	FROM #z a
	WHERE a.CardBank='Cheque'
) a
GROUP BY a.UserName

END
GO
/****** Object:  StoredProcedure [dbo].[Sp_MisCollRptCollTypeWise]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
