GO

CREATE PROC [dbo].[Sp_MisCollRptCollTypeWise] @branchId INT, @dateFrom DATE, @dateTo DATE
AS
BEGIN /* EXEC Sp_MisCollRptCollTypeWise 1, '2023-07-01', '2023-07-21' */

/*Condition for IsInclude Pharmacy bill*/
DECLARE @IncludePharmacy INT, @IsIncludePharmacy INT;
SELECT @IsIncludePharmacy = PharmacyInclude FROM tbl_ComInfo
IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END

SELECT a.SlNo, a.UserName, a.Department, a.PtStatus, (CASE WHEN a.CardBank = '' THEN 'Cash' ELSE a.CardBank END) AS CardBank, a.ChequeBank,
SUM(a.Collection) AS Collection, SUM(a.CashReturn) AS CashReturn, SUM(a.Collection-a.CashReturn) AS NetColl,
SUM(a.ByCash) AS ByCash, SUM(a.ByCard) AS ByCard, SUM(a.ByCheque) AS ByCheque
INTO #z
FROM(
	/*Start Indoor Ledger*/
	SELECT 1 AS SlNo, a.PatientId, a.UserName, 'IPD' AS Department, 'Indoor' AS PtStatus, a.CardBank, a.ChequeBank, 
	SUM(Collection) AS Collection,SUM(a.ReturnAmt) AS CashReturn, 
	SUM(a.CashAmt) AS ByCash, SUM(a.CardAmt) AS ByCard, SUM(a.ChequeAmt) AS ByCheque 
	FROM PatientLedger a
	WHERE a.BranchId = @branchId AND a.Valid = 1 AND a.RefDate BETWEEN @dateFrom AND @dateTo
	GROUP BY a.UserName, a.PatientId, a.CardBank, a.ChequeBank
	UNION ALL
	SELECT 1 AS SlNo, a.PatientId, a.UserName, 'IPD' AS Department, 'Indoor' AS PtStatus, '' AS CardBank, '' AS ChequeBank, 
	0 AS Collection, SUM(a.Amount) AS CashReturn, 
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque 
	FROM CashReturn a
	WHERE Valid = 1 ANd TrDate BETWEEN @dateFrom AND @dateTo
	GROUP BY a.UserName, a.PatientId
	/*End Indoor Ledger*/

	/*Start Sales Ledger*/
	UNION ALL
	SELECT 5 AS SlNo, a.PrevInvNo, a.UserName, a.Department, a.PtStatus, a.CardBank, a.ChequeBank,
	SUM(a.Collection) AS Collection, 0 AS CashReturn,
	SUM(a.ByCash) AS ByCash, SUM(a.ByCard) AS ByCard, SUM(a.ChequeAmount) AS ByCheque
	FROM SalesLedger a
	WHERE BranchId = @branchId AND RefDate BETWEEN @dateFrom AND @dateTo AND a.Valid = 1
	GROUP BY a.PrevInvNo, a.Department, a.PrevInvNo, a.PtStatus, a.UserName, a.CardBank, a.ChequeBank
	UNION ALL
	select distinct 5 AS SlNo, RtnInvNo, a.UserName, b.DeptName AS Department, b.PtStatus, '' AS CardBank, '' AS ChequeBank,
	0 AS Collection, a.ReturnCash,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque
	from InvReturn a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
	where a.BranchId = @branchId AND a.Valid = 1 AND a.RtnInvDate between @dateFrom AND @dateTo AND a.ReturnCash != 0
	UNION ALL
	select 5 AS SlNo, '' InvNo, a.UserName, b.DeptName AS Department, b.PtStatus,  '' AS CardBank, '' AS ChequeBank,
	0 AS Collection, SUM(Amount) AS CashReturn,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque
	from InvRefund a
	LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
	WHERE a.Valid = 1 AND a.BranchId = @branchId AND a.TrDate BETWEEN @dateFrom AND @dateTo
	group by b.InvNo, b.DeptName, b.PtStatus, a.UserName

	/*End Sales Ledger*/

	/* Start Medicine Collection */
	UNION ALL
	SELECT 10 AS SlNo, '', a.UserName, 'Medicine' AS Department, a.PtStatus,  '' AS CardBank, '' AS ChequeBank,
	SUM(a.Collection+a.DueColl) AS Collection, SUM(a.CashReturn) AS CashReturn,
	SUM(CashAmt) AS ByCash, SUM(a.CardAmt) AS ByCard, SUM(a.ChequeAmt) AS ByCheque
	FROM PharSalesLedger a 
	WHERE a.BranchId = @branchId AND a.Valid = @IncludePharmacy AND TrDate BETWEEN @dateFrom AND @dateTo
	GROUP BY a.PtStatus, a.UserName
	/* End Medicine Collection */

	/*Start Registration*/
	UNION ALL
	SELECT 5 AS SlNo, '', a.UserName, 'OPD' AS Department, 'Registration' AS PtStatus,  '' AS CardBank, '' AS ChequeBank, 
	SUM(Amount) AS Collection, 0 AS CashReturn,
	SUM(Amount) AS ByCash, 0 AS ByCard, 0 AS ByCheque
	FROM RegistrationFees a
	WHERE a.BranchId = @branchId AND a.Valid =  1 AND a.TrDate BETWEEN @dateFrom AND @dateTo
	GROUP BY a.UserName
	/*End Registration*/

	/*Start OPD Ticket*/
	UNION ALL
	SELECT 7 AS SlNo, '', a.UserName, 'OPD' AS Department, 'OPD Ticket' AS PtStatus,  '' AS CardBank, '' AS ChequeBank,
	SUM(Amount) AS Collection, 0 AS CashReturn,
	SUM(Amount) AS ByCash, 0 AS ByCard, 0 AS ByCheque
	FROM OPDTicketMaster a
	WHERE a.Valid = 1 AND BranchId = @branchId AND TrDate BETWEEN @dateFrom AND @dateTo
	GROUP BY a.UserName
	UNION ALL
	SELECT 7 AS SlNo, '', a.UserName, 'OPD' AS Department, 'OPD Ticket' AS PtStatus,  '' AS CardBank, '' AS ChequeBank,
	0 AS Collection, SUM(b.RtnAmount) AS CashReturn,
	0 AS ByCash, 0 AS ByCard, 0 AS ByCheque
	FROM OPDTicketReturn a
	LEFT JOIN OPDTicketMaster b ON a.OpdId = b.Id AND b.Valid = 1
	WHERE a.Valid = 1 AND b.BranchId = @branchId AND a.TrDate BETWEEN @dateFrom AND @dateTo
	GROUP BY a.UserName
	/*End OPD Ticket*/
) a
GROUP BY a.SlNo, a.UserName, a.Department, a.PtStatus, a.CardBank, a.ChequeBank
HAVING SUM(a.Collection+a.CashReturn) != 0
ORDER BY a.UserName, a.SlNo


select 1 AS SlNo, UserName, Department, PtStatus, 'Cash' AS PaymentType, (ByCash-CashReturn) AS Collection 
FROM #z WHERE (ByCash+CashReturn) != 0
UNION ALL
select 1 AS SlNo, UserName, Department, PtStatus, CardBank AS PaymentType, ByCard AS Collection 
FROM #z WHERE ByCard != 0
UNION ALL
select 1 AS SlNo, UserName, Department, PtStatus, ChequeBank AS PaymentType, ByCheque AS Collection 
FROM #z WHERE ByCheque != 0
UNION ALL
select 2 AS SlNo, UserName, 'Total' AS Department, '' AS PtStatus, 'Cash' AS PaymentType, (ByCash-CashReturn) AS Collection 
FROM #z WHERE (ByCash+CashReturn) != 0
UNION ALL
select 2 AS SlNo, UserName, 'Total' AS Department, '' AS PtStatus, 'Card' AS PaymentType, ByCard AS Collection 
FROM #z WHERE ByCard != 0
UNION ALL
select 2 AS SlNo, UserName, 'Total' AS Department, '' AS PtStatus, 'Cheque' AS PaymentType, ByCard AS Collection 
FROM #z WHERE ByCheque != 0
UNION ALL
select 2 AS SlNo, UserName, 'Total' AS Department, '' AS PtStatus, 'G.Total' AS PaymentType, NetColl AS Collection 
FROM #z WHERE NetColl != 0

END
GO
