CREATE PROC [dbo].[SP_MisCollRptProjectWise] @branchId INT, @fromDate DATE, @toDate DATE, @UserName VARCHAR(20)
AS /* EXEC SP_MisCollRptProjectWise 1, '2024-12-18', '2024-12-18', '' */
BEGIN

SELECT 3 AS SlNo, a.Department AS MainDept, a.Department, a.UserName, SUM(a.Collection) AS Collection, 0 AS CashReturn
INTO #Z
FROM SalesLedger a
WHERE a.Valid = 1 ANd a.BranchId = @branchId AND a.RefDate BETWEEN @fromDate AND @toDate
AND a.UserName LIKE '%'+@UserName+'%' and a.Department <> 'Ambulance'
GROUP BY a.Department, a.UserName
HAVING SUM(a.Collection) != 0
UNION ALL
SELECT 3 AS SlNo, b.DeptName AS MainDept, b.DeptName AS Department, a.UserName, 0 AS Collection, MAX(a.ReturnCash) AS CashReturn
FROM InvReturn a
LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
WHERE a.Valid=1 And a.BranchId =@branchId AND a.RtnInvDate BETWEEN @fromDate AND @toDate AND a.UserName LIKE '%'+@UserName+'%'
GROUP BY b.DeptName, a.UserName, b.InvNo, a.RtnInvNo

UNION ALL
SELECT 2 AS SlNo, 'Pharmacy' AS MainDept, a.PtStatus AS Department, a.UserName, SUM(a.Collection+a.DueColl) AS Collection, SUM(a.CashReturn) AS CashReturn
FROM PharSalesLedger a
WHERE a.Valid = 1 ANd a.BranchId = @branchId AND a.TrDate BETWEEN @fromDate AND @toDate
AND a.UserName LIKE '%'+@UserName+'%'
GROUP BY a.UserName, a.PtStatus
HAVING SUM(a.Collection+a.DueColl+a.CashReturn) != 0

UNION ALL
SELECT 2 AS SlNo, 'Pharmacy' AS MainDept, a.PtStatus AS Department, a.UserName, SUM(a.AdjustAmt) AS Collection, 0 AS CashReturn
FROM PharSalesLedger a
WHERE a.Valid = 1 ANd a.BranchId = @branchId AND a.TrDate BETWEEN @fromDate AND @toDate
AND a.UserName LIKE '%'+@UserName+'%'
GROUP BY a.UserName, a.PtStatus
HAVING SUM(a.AdjustAmt) != 0
Union All
SELECT 3 AS SlNo, 'Ambulance' AS MainDept, 'Ambulance' Department, a.UserName, SUM(a.ReceiveAmt) AS Collection, 0 AS CashReturn
FROM AmbulanceLedger a
WHERE a.Valid = 1 ANd a.BranchId = @branchId AND a.RefDate BETWEEN @fromDate AND @toDate
AND a.UserName LIKE '%'+@UserName+'%' 
GROUP BY a.UserName
HAVING SUM(a.ReceiveAmt) != 0

--UNION ALL
--SELECT 2 AS SlNo, 'Pharmacy' AS MainDept, 'Pharmacy Outdoor' AS Department, a.UserName, SUM(a.Collection+a.DueColl) AS Collection, SUM(a.CashReturn) AS CashReturn
--FROM PharSalesLedger a
--WHERE a.Valid = 1 ANd a.BranchId = @branchId AND a.PtStatus != 'Indoor' AND a.TrDate BETWEEN @fromDate AND @toDate
--AND a.UserName LIKE '%'+@UserName+'%'
--GROUP BY a.UserName
--HAVING SUM(a.Collection+a.DueColl+a.CashReturn) != 0

UNION ALL
SELECT 1 AS SlNo, 'IPD' AS MainDept, b.BedType AS Department, a.UserName, SUM(a.Collection) AS Collection, SUM(a.ReturnAmt) AS CashReturn
FROM PatientLedger a
LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
WHERE a.Valid = 1 AND a.BranchId = @branchId AND a.RefDate BETWEEN @fromDate AND @toDate
AND a.UserName LIKE '%'+@UserName+'%'
group by a.UserName, b.BedType
having SUM(a.Collection-a.ReturnAmt) != 0
UNION ALL
SELECT 2 AS SlNo, 'IPD' AS MainDept, 'Pharmacy Adjust' AS Department, a.UserName, -SUM(a.AdjustAmt) AS Collection, 0 AS CashReturn
FROM PharSalesLedger a
WHERE a.Valid = 1 ANd a.BranchId = @branchId AND a.TrDate BETWEEN @fromDate AND @toDate
AND a.UserName LIKE '%'+@UserName+'%'
GROUP BY a.UserName, a.PtStatus
HAVING SUM(a.AdjustAmt) != 0
order by SlNo, a.UserName

--UNION ALL
--SELECT 1 AS SlNo, 'IP' AS MainDept, 'ZTotal IPD' AS Department, a.UserName, SUM(a.Collection) AS Collection, SUM(a.ReturnAmt) AS CashReturn
--FROM PatientLedger a
--LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
--WHERE a.Valid = 1 AND a.BranchId = @branchId AND a.RefDate BETWEEN @fromDate AND @toDate
--AND a.UserName LIKE '%'+@UserName+'%'
--group by a.UserName, b.BedType
--having SUM(a.Collection-a.ReturnAmt) != 0
--order by SlNo, a.UserName



INSERT INTO #Z (slno,MainDept,Department,UserName,Collection ,CashReturn )
SELECT 9999,'TOTAL','TOTAL',UserName,SUM(Collection),SUM(CashReturn)
FROM #Z
--WHERE Department != 'Indoor Adjust'
GROUP BY UserName

INSERT INTO #Z (slno,MainDept,Department,UserName,Collection ,CashReturn )
SELECT slno,'IPD','Z-TOTAL',UserName,SUM(Collection),SUM(CashReturn)
FROM #Z
WHERE MainDept ='IPD' 
GROUP BY SlNo , UserName

select * INTO #ZZ from #Z ORDER BY SlNo,MainDept , Department 


declare @TotalLabAmount float;
declare @TotalRediologyAmount float;
declare @TotalAmount float;

SET @TotalLabAmount = (
select SUM(a.TotalAmount) AS Amount 
from InvDetails a , ClinicalChart b
where a.PCode =b.PCode and a.valid <> 0 
AND b.subDeptName = 'LabTest'
AND a.invno IN (select PrevInvNo from SalesLedger
where BranchId = @branchId AND RefDate BETWEEN @fromDate AND @toDate
and Department = 'DIAGNOSTIC'
and valid <> 0)
GROUP BY b.subDeptName)

SET @TotalRediologyAmount = (
select SUM(a.TotalAmount) AS Amount 
from InvDetails a , ClinicalChart b
where a.PCode =b.PCode and a.valid <> 0 
AND b.subDeptName <> 'LabTest'
AND a.invno IN (select PrevInvNo from SalesLedger
where BranchId = @branchId AND RefDate BETWEEN @fromDate AND @toDate
and Department = 'DIAGNOSTIC'
and valid <> 0))


SET @TotalAmount = (
select SUM(a.TotalAmount) AS Amount 
from InvDetails a , ClinicalChart b
where a.PCode =b.PCode and a.valid <> 0 
AND a.invno IN (select PrevInvNo from SalesLedger
where BranchId = @branchId AND RefDate BETWEEN @fromDate AND @toDate
and Department = 'DIAGNOSTIC'
and valid <> 0))


INSERT INTO #Z (slno,MainDept,Department,UserName , Collection , CashReturn)
SELECT slno,MainDept,'RADIOLOGY' as Department,UserName , ((Collection*@TotalRediologyAmount)/@TotalAmount)-((CashReturn*@TotalRediologyAmount)/@TotalAmount), 0
FROM #ZZ 
where MainDept = 'DIAGNOSTIC'

INSERT INTO #Z (slno,MainDept,Department,UserName , Collection , CashReturn)
SELECT slno,MainDept,'LAB TEST' as Department,UserName , ((Collection*@TotalLabAmount)/@TotalAmount)-((CashReturn*@TotalLabAmount)/@TotalAmount),0
FROM #ZZ
where MainDept = 'DIAGNOSTIC'

delete from #Z where Department = 'DIAGNOSTIC'

select * from #Z ORDER BY SlNo,MainDept , Department 


END
GO
