CREATE PROCEDURE [dbo].[SP_MisCollRptProjectWise_DtlsUserWise] @branchId INT, @fromDate DATE, @toDate DATE, @UserName VARCHAR(20)
AS -- EXEC SP_MisCollRptProjectWise_DtlsUserWise 1,'2023-07-25','2023-07-25',''
BEGIN
	
	SELECT aa.UserName , aa.RefNo , aa.RefDate , aa.Department , aa.Particulars , aa.Sales , aa.Collection,
	aa.Less , aa.ReturnAmount , aa.ByCash , aa.ByCard , aa.ChequeAmount , (aa.ByCash + aa.ByCard + aa.ChequeAmount) as TotalCASHCardChq ,
	(aa.Collection-aa.ByCash-aa.ByCard-aa.ChequeAmount ) AS Diff,aa.Comments 
	FROM ( 
	select username, RefNo , RefDate , Department , Particulars , Sales , Collection , Less , 
	ReturnNet as ReturnAmount, ByCash , ByCard , ChequeAmount , Comments 
	from SalesLedger
	where Valid = 1
	ANd BranchId = @branchId AND RefDate BETWEEN @fromDate AND @toDate
	AND UserName LIKE '%'+@UserName+'%'
	UNION ALL
	select UserName , InvNo , InvDate ,DeptName ,PatientName ,TotalAmt , AdvanceAmt , lessAmount,  
	ReturnAmt , CashAmt , CardAmt , ChequeAmt , Remarks 
	from InvMaster
	where Valid = 1
	AND BranchId =@branchId AND InvDate BETWEEN @fromDate AND @toDate AND UserName LIKE '%'+@UserName+'%'
	UNION ALL
	select UserName , RtnInvNo , RtnInvDate , '','',0,0,0,ReturnCash , ReturnCash,0,0,'Cash Return' 
	from InvReturn
	where Valid = 1
	AND BranchId =@branchId AND RtnInvDate BETWEEN @fromDate AND @toDate AND UserName LIKE '%'+@UserName+'%'
	UNION ALL
	SELECT UserName , TrNo , PaidDate , DeptName , '',0,PaidAmt , Less , 
	0,CashAmt , CardAmt , ChequeAmt , ''
	from InvPaid 
	where Valid = 1
	ANd BranchId = @branchId AND PaidDate BETWEEN @fromDate AND @toDate
	AND UserName LIKE '%'+@UserName+'%'
	UNION ALL
	select UserName,trno,TrDate ,deptname,PatientName,Sales , Collection+DueColl , LessAmt , 
	ReturnAmt , CashAmt , CardAmt , ChequeAmt , ''
	from PharSalesLedger
	where Valid = 1
	ANd BranchId = @branchId AND TrDate BETWEEN @fromDate AND @toDate
	AND UserName LIKE '%'+@UserName+'%'
	UNION ALL
	select UserName , RefNo ,RefDate , 'IPD','',TotalAmount,Collection,Less , 
	ReturnAmt , CashAmt , CardAmt , ChequeAmt , Remarks  
	from PatientLedger
	where Valid = 1
	AND BranchId = @branchId AND RefDate BETWEEN @fromDate AND @toDate
	AND UserName LIKE '%'+@UserName+'%')  aa
	order by UserName  , RefDate , Department 
END

GO
