CREATE PROC [dbo].[SP_MisDueReport](@branchId int, @dateFrom nvarchar(50), @dateTo nvarchar(50))
AS
BEGIN /* EXEC SP_MisDueReport 1, '2022-01-01', '2023-12-10' */
/* Start Outdoor Bill */
SELECT PrevInvNo AS InvNo, PreInvDate AS InvDate, a.Department, a.Particulars AS PatietnName, a.PPhone, '' AS PackCode,
SUM(a.Sales-a.ReturnAmount) AS Sales, SUM(a.Less-a.ReturnLess) AS Less, SUM(a.Collection-a.ReturnCash) As Collection,
SUM(Sales-a.Less-a.Collection-(a.ReturnAmount-a.ReturnCash-a.ReturnLess)) AS Due,
SUBSTRING((SELECT DISTINCT ',' + Replace(Remarks, 'N/A','') FROM SalesLedger where PrevInvNo = a.PrevInvNo AND BranchId = a.BranchId GROUP BY PrevInvNo, BranchId, Remarks FOR XML PATH('')), 2 , 300) As Remarks
FROM SalesLedger a
WHERE a.Valid = 1 AND CONVERT(DATE,a.PreInvDate) BETWEEN @dateFrom AND @dateTo AND a.PtStatus != 'Indoor' AND a.BranchId=@branchId
GROUP BY PrevInvNo, PreInvDate, a.Department, a.Particulars, a.PPhone, a.BranchId,a.PatientId
HAVING SUM(Sales-a.Less-a.Collection-(a.ReturnAmount-a.ReturnCash-a.ReturnLess)) > 0
/* End Outdoor Bill */

/* Start Indoor Bill*/
UNION ALL
SELECT bb.PatientId, bb.AdmissionDate, 'Indoor' AS Department, bb.PatientName, bb.PatientTel AS PPhone, bb.PackCode,
SUM(aa.Sales) AS Sales, SUM(aa.Less) AS Less, SUM(aa.Collection) AS Collection, SUM(aa.Sales-aa.Less-aa.Collection) AS Due,
SUBSTRING((SELECT distinct ',' + REPLACE(Replace(Remarks, 'N/A',''),'.','') FROM PatientLedger where PatientId = aa.PatientId AND BranchId = aa.BranchId FOR XML PATH('')), 2 , 300) As Remarks
 FROM (
	 /* Start Indoor Data */
	SELECT a.BranchId, a.PatientId, 0 AS Sales, SUM(-b.ReturnAmt) AS Collection, 0 AS Less
	FROM PatientAdmission a 
	INNER JOIN PatientLedger b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId AND b.Valid = 1
	WHERE a.Valid = 1 AND a.IsRelease = 1
	GROUP BY a.BranchId, a.PatientId
	UNION ALL
	SELECT a.BranchId, a.PatientId, SUM(a.TotalAmt+a.ServiceChargeAmt) AS Sales, SUM(AdvanceAmt+NetPaymentAmt) AS Collection,SUM(LessAmt+PrevLessAmt) AS Less
	FROM PatientReleaseMaster a 
	WHERE a.Valid = 1 
	GROUP BY a.BranchId, a.PatientId
	UNION ALL
	SELECT a.BranchId, a.PatientId, 0 AS Sales, SUM(a.Collection) AS Collection, SUM(a.Less) AS Less
	FROM IndoorDueCollMaster a 
	WHERE a.Valid = 1 
	GROUP BY a.BranchId, a.PatientId

	/* Ende Indoor Data */
	/* Start SalesLedger Data */
	--UNION ALL
	--SELECT a.BranchId, a.PatientId, 0, SUM(a.Collection-a.ReturnCash) AS Collection, 0 AS Less
	--FROM SalesLedger a
	--INNER JOIN PatientAdmission b  ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
	--WHERE a.Valid = 1 AND b.IsRelease = 1 AND a.PtStatus = 'Indoor'
	--GROUP BY a.BranchId, a.PatientId
	/* End SalesLedger Data */
	--UNION
	--SELECT a.BranchId, a.PatientId, 0 AS MBill,
	--SUM(a.Collection+a.DueColl-a.CashReturn) AS Collection,0 as LessAmt
	--FROM PharSalesLedger a INNER JOIN PatientAdmission b  ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
	--WHERE a.Valid = 1 AND a.PatientId != ''  AND b.IsRelease = 1 AND a.PtStatus = 'Indoor'
	--GROUP BY a.BranchId, a.PatientId
	

	/* Start Ambulance Data */
	UNION ALL
	SELECT a.BranchId, a.PatientId, 0 AS Sales, SUM(a.ReceiveAmt) AS Collection, 0 AS Less
	FROM AmbulanceLedger a
	INNER JOIN PatientAdmission b  ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
	WHERE a.Valid <> 0 AND b.IsRelease = 1 AND a.PtStatus = 'Indoor'
	GROUP BY a.BranchId, a.PatientId
	/* End Ambulance Data */
) aa
LEFT JOIN PatientAdmission bb ON aa.BranchId = bb.BranchId AND aa.PatientId = bb.PatientId
WHERE bb.BranchId = @branchId AND bb.AdmissionDate BETWEEN @dateFrom AND @dateTo AND bb.IsRelease = 1
GROUP BY bb.PatientId, bb.AdmissionDate, bb.PatientName, bb.PatientTel, aa.PatientId, aa.BranchId, bb.PackCode
HAVING SUM(aa.Sales-aa.Less-aa.Collection) > 3
/* End Indoor Bill*/

ORDER BY 3, InvDate, InvNo
END

GO
