CREATE PROCEDURE [dbo].[SP_MISIncomeRptUserwise] @DateFrom DateTime, @DateTo DateTime, @UserName nvarchar(20), @branchId int

AS /* EXEC SP_MISIncomeRptUserwise '2023-12-01', '2023-12-05', 'MAMUN FDE', 1 */

/*Condition for IsInclude Pharmacy bill*/
DECLARE @IncludePharmacy INT, @IsIncludePharmacy INT;
SELECT @IncludePharmacy = PharmacyInclude FROM tbl_ComInfo;
IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END;

BEGIN
	SELECT aa.Department, aa.RefNo, aa.RefDate, aa.PatientId, aa.PatientName, aa.UserName, SUM(AdvanceColl) AS AdvanceColl,
	SUM(aa.ReturnAmt) AS ReturnAmt, SUM(aa.DueColl) AS DueColl, sum(aa.CashAmt) as CashAmt, sum(aa.CardAmt) as CardAmt, sum(aa.ChequeAmt) as ChequeAmt
	FROM (

		SELECT 'Indoor' as Department, RefNo, RefDate, PatientID, PatientName, UserName,
		Collection AS AdvanceColl, ReturnAmt, 0 as DueColl, CashAmt, CardAmt, ChequeAmt
		FROM PatientLedger Where Valid = 1 AND UserName lIKe '%'+ @UserName +'%'
		And BranchId = @branchId AND EntryDateTime Between @DateFrom and @DateTo 
		and Status = 'Advance Collection' and Collection != 0
		--GROUP BY RefNo, RefDate, PatientID, PatientName, UserName, Collection, ReturnAmt
		--HAVING Collection > 0
		UNION ALL
		SELECT 'Indoor' as Department, RefNo, RefDate, PatientID, PatientName, UserName, 
		0 AS AdvanceColl, ReturnAmt, Collection as DueColl, CashAmt, CardAmt, ChequeAmt
		FROM PatientLedger Where BranchId = @branchId AND UserName lIKe '%'+ @UserName +'%' AND Valid = 1 And EntryDateTime Between @DateFrom and @DateTo 
		and Status != 'Advance Collection' and Collection+ReturnAmt != 0
		--GROUP BY RefNo, RefDate, PatientID, PatientName, UserName, ReturnAmt, Collection
		--HAVING Collection+ReturnAmt != 0
		UNION ALL
		SELECT a.Department, a.RefNo AS RefNo, a.RefDate AS Invdate, a.PatientId, a.Particulars AS PatientName, a.UserName,
		a.Collection, 0 ReturnNet, 0 as DueColl, ByCash AS CashAmt, ByCard AS CardAmt, ChequeAmount AS ChequeAmt
		FROM SalesLedger a WHERE BranchId = @branchId AND UserName lIKe '%'+ @UserName +'%' AND a.Valid = 1 AND a.CRType = 'Sales' 
		AND a.PostingDateTime BETWEEN @DateFrom AND @DateTo AND a.Department != 'Ambulance' --AND Collection+ReturnNet != 0	
		--GROUP BY a.Department, a.RefNo, a.RefDate, a.PatientId, a.Particulars, a.UserName, a.Collection, a.ReturnNet
		--HAVING Collection+ReturnNet != 0	
		UNION ALL
		SELECT a.Department, a.RefNo AS RefNo, a.RefDate AS Invdate, a.PatientId, a.Particulars AS PatientName, a.UserName,
		0 AS Collection, 0 ReturnNet, Collection as DueColl , ByCash AS CashAmt, ByCard AS CardAmt, ChequeAmount AS ChequeAmt
		FROM SalesLedger a WHERE a.Valid != 0 AND a.BranchId = @branchId AND a.UserName lIKe '%'+ @UserName +'%' AND a.CRType = 'Collection' 
		AND a.PostingDateTime BETWEEN @DateFrom AND @DateTo AND a.Department != 'Ambulance'
		--GROUP BY a.Department, a.RefNo, a.RefDate, a.PatientId, a.Particulars, a.UserName, a.ReturnNet, a.Collection
		--HAVING Collection+a.ReturnNet != 0
		
		--Start Ambulance
		UNION ALL
		select 'Ambulance' AS Department, a.RefNo, a.RefDate, a.PatientId, a.PatientName, a.UserName, a.ReceiveAmt AS Collection, 
		0 AS ReturnNet, 0 AS DueColl, a.CashAmt, a.CardAmt, a.ChequeAmt
		from AmbulanceLedger  a
		WHERE a.Valid=1 AND a.BranchId=@branchId AND a.InputFrom = 'Sales' AND a.UserName LIKE '%'+@UserName+'%'
		AND a.EntryDateTime BETWEEN @DateFrom AND @DateTo
		UNION ALL
		select 'Ambulance' AS Department, a.RefNo, a.RefDate, a.PatientId, a.PatientName, a.UserName, 0 AS Collection, 
		0 AS ReturnNet, a.ReceiveAmt AS DueColl, a.CashAmt, a.CardAmt, a.ChequeAmt
		from AmbulanceLedger  a
		WHERE a.Valid=1 AND a.BranchId=@branchId AND a.InputFrom = 'Collection' AND a.UserName LIKE '%'+@UserName+'%'
		AND a.EntryDateTime BETWEEN @DateFrom AND @DateTo
		--End Ambulance

		/* Start Outdoor Return */
		UNION ALL
		SELECT b.DeptName AS Department, a.RtnInvNo AS RefNo, a.RtnInvDate AS InvDate, b.PatientId, b.PatientName, a.UserName,
		0 AS Collection, MAX(a.ReturnCash) AS CashReturn, 0 AS DueColl, 0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt
		FROM InvReturn a
		LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
		WHERE a.BranchId =@branchId AND a.EntryDateTime BETWEEN @DateFrom AND @DateTo AND a.UserName lIKe '%'+ @UserName +'%'
		GROUP BY b.DeptName, a.RtnInvNo, a.RtnInvDate, b.PatientId, b.PatientName, a.UserName
		/* End Outdoor Return */

		--------==Medicine==--------
		UNION ALL
		SELECT 'Medicine' AS Department, a.InvNo, a.InvDate, a.PatientId, a.PatientName, a.UserName, 
		a.Collection AS AdvanceColl, a.CashReturn AS ReturnAmt, a.DueColl, CashAmt AS CashAmt, CardAmt AS CardAmt, ChequeAmt AS ChequeAmt
		FROM PharSalesLedger a WHERE BranchId = @branchId AND a.Valid = @IncludePharmacy AND a.UserName lIKe '%'+ @UserName +'%'
		AND a.EntryDateTime BETWEEN @DateFrom AND @DateTo
		AND a.Collection+a.DueColl+a.CashReturn != 0
	) aa
	GROUP BY aa.Department, aa.RefNo, aa.RefDate, aa.PatientId, aa.PatientName, aa.UserName
END
GO
