CREATE PROCEDURE [dbo].[SP_ModuleWisePatientRegDtls] (@BranchId INT, @DateFrom NVARCHAR(10), @DateTo NVARCHAR(10), @Module NVARCHAR(50), @RefCode NVARCHAR(50))
AS  -- EXEC SP_ModuleWisePatientRegDtls 1, '2023-07-11', '2024-10-20', '', ''
BEGIN
SELECT a.PatientType, a.TelephoneNo, a.RegNo, a.PatientName, a.DOB, a.Gender, a.FatherName, a.MotherName, a.SpouseName, a.PatientAddress as PresentAddress, a.PermanentAddress, a.BloodGroup, a.Email, b.DrCode as RefCode, b.DrName as RefName, a.Religion, a.Occupation, a.Nationality, a.IntroduceBy, a.NationalId, a.PassportNo, a.BirthCertificateNo, a.EntryDateTime, a.UserName
FROM PatientRegistration a
LEFT JOIN DrInfo b on a.RefBy = b.DrCode AND a.BranchId = b.BranchId
WHERE a.Valid = 1 AND a.BranchId = @BranchId  AND a.RegDate between @DateFrom and @DateTo and a.RegFrom LIKE '%' + @Module + '%' AND b.DrCode LIKE '%' + @RefCode + '%'
END
GO
