CREATE PROCEDURE [dbo].[SP_ModuleWisePatientRegSMZ] (@BranchId INT, @DateFrom NVARCHAR(10), @DateTo NVARCHAR(10), @Module NVARCHAR(50), @RefCode NVARCHAR(50))
AS  -- EXEC SP_ModuleWisePatientRegSMZ 1, '2024-08-01', '2024-10-20', '', ''
BEGIN
SELECT b.DrCode as RefCode, b.DrName as RefName, a.RegFrom AS ModuleName, COUNT(*) AS ModuleCount FROM PatientRegistration a
LEFT JOIN DrInfo b on a.RefBy = b.DrCode AND a.BranchId = b.BranchId
WHERE a.RegFrom <> '' and a.Valid = 1 AND a.BranchId = @BranchId  AND a.RegDate between @DateFrom and @DateTo and a.RegFrom LIKE '%' + @Module + '%' AND b.DrCode LIKE '%' + @RefCode + '%'
GROUP BY a.RegFrom, b.DrCode, b.DrName
END
