CREATE PROC [dbo].[sp_MothlyComparativeSalesReport]
@BranchId INT,
@DateFrom DATETIME,
@DateTo DATETIME
AS
BEGIN
SELECT convert(nvarchar(20),RIGHT(CONCAT('00', convert(nvarchar(20),MONTH(InvDate))), 2))+'-'+convert(varchar(20),DATENAME(M,InvDate))+'-'+CONVERT(VARCHAR(10),YEAR(InvDate)) As MonthNo,SUM(TotalAmt) AS TotalAmount,DeptName,COUNT(InvNo) AS TotalInvoice
FROM InvMaster
WHERE DeptName='DIAGNOSTIC' AND BranchId=@BranchId
AND InvDate BETWEEN @DateFrom AND @DateTo
GROUP BY convert(nvarchar(20),RIGHT(CONCAT('00', convert(nvarchar(20),MONTH(InvDate))), 2))+'-'+convert(varchar(20),DATENAME(M,InvDate))+'-'+CONVERT(VARCHAR(10),YEAR(InvDate)),DeptName
END
GO
