CREATE PROCEDURE [dbo].[SP_MRAfterPaymentDetails] @BranchId int , @UnitId int, @DateFrom date , @DateTo date, @MrId nvarchar(50)
AS  --- Exec SP_MRAfterPaymentDetails 1, 1, '2024-05-01', '2024-05-31', '003' 
BEGIN
Select a.InvNo, a.DateFrom, a.DateTo , a.MrId, b.MRName, a.DrCode, a.DrName, (a.Amount) as Amount, (a.Paid) as Paid, (a.Less) as Less, (a.Due) as Due,
 (SalesAmt) as SalesAmt, (Payment) as Payment, PcOrTk, (PayableAmt) as PayableAmt, (CashAmt) as CashAmt, (ReceiveAmt) as ReceiveAmt, 
(PreviousDue) as PreviousDue, (RestDue + PreviousDue) as RestDue, (TotalDue) as TotalDue From MRPayment a 
LEFT JOIN tbl_MRInfo b On a.MrId=b.MRId AND a.Valid=b.Valid AND a.BranchId=b.BranchId
WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.InvDate Between @DateFrom AND @DateTo AND a.MrId LIKE '%'+@MrId+'%'
ORDER BY a.MrId, DrCode
END
GO
