CREATE PROCEDURE [dbo].[SP_MRAfterPaymentSMZ] @BranchId int , @UnitId int, @DateFrom date , @DateTo date, @MrId nvarchar(50)
AS  --- Exec SP_MRAfterPaymentSMZ 1, 1, '2024-05-01', '2024-05-31', '' 
BEGIN
Select a.MrId, b.MRName, sum(SalesAmt) as SalesAmt, sum(PayableAmt) as PayableAmt, sum(ReceiveAmt) as PaymentAmt, sum(PayableAmt  - ReceiveAmt) as CurrentDue, sum(CashAmt) as CashAmt, 
  sum(CardAmt) as CardAmt, sum(ChequeAmt) as ChequeAmt
 From MRPayment a 
LEFT JOIN tbl_MRInfo b On a.MrId=b.MRId AND a.Valid=b.Valid AND a.BranchId=b.BranchId
WHERE a.Valid=1 AND a.BranchId=@BranchId AND DrCode='' AND a.InvDate Between @DateFrom AND @DateTo AND a.MrId LIKE '%'+@MrId+'%'
GROUP BY a.MrId, b.MRName
END
