CREATE PROCEDURE [dbo].[SP_MrBeforePaymentDtls]
    @BranchId INT, @UnitId INT, @MRId NVARCHAR(20), @InvDateFrom NVARCHAR(20), @InvDateTo NVARCHAR(20)
AS --- EXEC SP_MrBeforePaymentDtls   1, 1, '005', '2024-01-01', '2024-01-31' 
BEGIN
	SELECT c.MRId, c.MRName, a.RefDrCode, c.DrName, SUM(b.Sales) AS TotalAmt,
	SUM(b.Less-b.ReturnLess) AS TotalLess, SUM(b.Sales-b.ReturnNet-b.Less) AS NetAmt, SUM(b.Collection-b.ReturnCash) AS AdvanceAmt,
	SUM(b.Sales-b.Less-b.Collection-b.ReturnDue) AS Due
	FROM InvMaster a
	INNER JOIN SalesLedger b oN a.BranchId=b.BranchId AND a.InvNo=b.PrevInvNo
	LEFT JOIN DrInfo c ON a.BranchId=c.BranchId AND a.RefDrCode=c.DrCode
	where a.Valid=1 and a.BranchId=@BranchId
	AND c.MRId LIKE '%'+@MRId+'%'
	and a.InvDate between @InvDateFrom AND  @InvDateTo
	AND a.RefDrCode NOT IN (Select DrCode FROM MRPayment WHERE Valid=1 and MrId LIKE '%'+@MRId+'%' 
	AND @InvDateFrom BETWEEN DateFrom AND DateTo)				
	GROUP BY c.MRId, c.MRName, a.RefDrCode, c.DrName

 --   SELECT  b.MRId,b.MRName, a.RefDrCode, b.DrName,
 --  SUM(a.TotalAmt) AS TotalAmt, SUM(a.TotalLess) AS TotalLess, SUM(a.TotalAmt - a.TotalLess) AS NetAmt,  SUM(a.AdvanceAmt) + ISNULL(sum(d.PaidAmt),0) AS AdvanceAmt, 
 --  (SUM(a.TotalAmt) - SUM(a.TotalLess) - SUM(a.AdvanceAmt) - ISNULL(sum(d.PaidAmt),0)) AS Due
 --   FROM InvMaster a
 --   LEFT  JOIN  DrInfo b ON a.BranchId = b.BranchId AND a.RefDrCode = b.DrCode  
	--LEFT JOIN InvPaid d On a.InvNo=d.InvNo AND a.BranchId=d.BranchId 	
 --   WHERE 
 --   a.Valid = 1
