CREATE PROCEDURE [dbo].[SP_MrBeforePaymentSMZ]
    @BranchId INT,
	@UnitId INT,
    @MRId NVARCHAR(20),
    @InvDateFrom NVARCHAR(20),
    @InvDateTo NVARCHAR(20),
	@DeptName NVARCHAR(50),
	@SubDeptName NVARCHAR(50),
	@SubSubDeptName NVARCHAR(50)
    --@RefDrCode NVARCHAR(20)
AS --- EXEC SP_MrBeforePaymentSMZ   1, 1, '', '2023-12-01', '2024-01-12', '', '', ''
BEGIN
    SELECT 
        b.MRId,
        c.MRName,
        a.InvDate,
        a.InvNo,
		d.DeptName,
		d.SubDeptName,
		d.SubSubDeptName,
        a.PatientId,
        a.PatientName,
        a.RefDrCode,
        b.DrName,
        a.MobNo,
        SUM(a.TotalAmt) AS TotalAmt,
        SUM(a.TotalLess) AS TotalLess,
        SUM(a.TotalAmt - a.TotalLess) AS NetAmt,
        SUM(a.AdvanceAmt) AS AdvanceAmt,
        (SUM(a.TotalAmt) - SUM(a.TotalLess) - SUM(a.AdvanceAmt)) AS Due,
        a.Comments,
        a.Remarks
    FROM 
        InvMaster a
    INNER JOIN 
        DrInfo b ON a.BranchId = b.BranchId AND a.RefDrCode = b.DrCode
    INNER JOIN 
        tbl_MRInfo c ON b.MRId = c.MRId
	INNER JOIN 
		InvDetails d ON a.BranchId = d.BranchId AND a.RegNo = d.RegNo
    WHERE 
         a.Valid = 1
        AND a.BranchId = @BranchId
		AND a.CostCenterName=@UnitId
        AND b.MRId LIKE '%'+@MRId+'%'
        AND a.InvDate BETWEEN @InvDateFrom AND  @InvDateTo
		AND d.DeptName LIKE '%'+@DeptName+'%'
		AND d.SubDeptName LIKE '%'+@SubDeptName+'%'
		AND d.SubSubDeptName LIKE '%'+@SubSubDeptName+'%'
        --AND a.RefDrCode = @RefDrCode
    GROUP BY 
        b.MRId,
        c.MRName,
        a.InvDate,
        a.InvNo,
		d.DeptName,
		d.SubDeptName,
		d.SubSubDeptName,
        a.PatientId,
        a.PatientName,
        a.RefDrCode,
        b.DrName,
        a.MobNo,
		a.Comments,
        a.Remarks
    ORDER BY 
        b.MRId,
		a.RefDrCode
END
GO
