--17052025 New Report
CREATE PROCEDURE [dbo].[SP_MrPerformanceReportDepartmentWiseNew] @BranchId INT, @MRId NVARCHAR(20), @InvDateFrom NVARCHAR(20), @InvDateTo NVARCHAR(20)
AS --- EXEC SP_MrPerformanceReportDepartmentWiseNew   1, '', '2025-05-01', '2025-05-31'
BEGIN
	SELECT c.MRId, c.MRName, SUM(b.Sales) AS DiagnosticOpdSalesAmt,
	SUM(b.Less-b.ReturnLess) AS DiagnosticOpdTotalLess, SUM(b.Sales-b.ReturnNet-b.Less) AS DiagnosticOpdNetAmt,
	0 AS DiagnosticIPDSalesAmt,0 AS DiagnosticIPDTotalLess,0 AS DiagnosticIPDNetAmt,
	0 as GeneralBedSales,0 AS IcuHduSales,0 AS NicuPicuSales,0 AS HospitalDiscountAmt,
	a.RefDrCode, c.DrName,a.DeptName,a.InvDate,a.InvNo,a.PatientId,a.PatientName
	FROM InvMaster a
	INNER JOIN SalesLedger b ON a.BranchId=b.BranchId AND a.InvNo=b.PrevInvNo
	LEFT JOIN DrInfo c ON a.BranchId=c.BranchId AND a.RefDrCode=c.DrCode
	where a.Valid=1 and a.BranchId=@BranchId
	AND c.MRId LIKE '%'+@MRId+'%' AND a.PtStatus='Outdoor'
	and b.PaidDate between @InvDateFrom AND  @InvDateTo AND c.MRId<>''
	GROUP BY c.MRId, c.MRName, a.RefDrCode, c.DrName,a.DeptName,a.InvDate,a.InvNo,a.PatientId,a.PatientName
	HAVING SUM(b.Sales-b.Less-b.Collection-b.ReturnDue)<=0
	UNION ALL
	SELECT d.MRId, d.MRName, 0 AS DiagnosticOpdSalesAmt,
	0 AS DiagnosticOpdTotalLess, 0 AS DiagnosticOpdNetAmt,
	SUM(b.Sales) AS DiagnosticIPDSalesAmt,SUM(b.Less-b.ReturnLess) AS DiagnosticIPDTotalLess,
	SUM(b.Sales-b.ReturnNet-b.Less) AS DiagnosticIPDNetAmt,
	0 as GeneralBedSales,0 AS IcuHduSales,0 AS NicuPicuSales,0 AS HospitalDiscountAmt,
	a.RefDrCode, c.DrName,a.DeptName,a.InvDate,a.InvNo,a.PatientId,a.PatientName
	FROM InvMaster a
	INNER JOIN SalesLedger b ON a.BranchId=b.BranchId AND a.InvNo=b.PrevInvNo
	INNER JOIN PatientAdmission c ON a.PatientId=c.PatientId AND b.PatientId=c.PatientId
	LEFT JOIN DrInfo d ON a.BranchId=d.BranchId AND a.RefDrCode=d.DrCode
	where a.Valid=1 and a.BranchId=@BranchId
	AND d.MRId LIKE '%'+@MRId+'%' AND a.PtStatus='Indoor'
	and c.ReleaseDate between @InvDateFrom AND  @InvDateTo AND d.MRId<>''
	GROUP BY d.MRId, d.MRName, a.RefDrCode, c.DrName,a.DeptName,a.InvDate,a.InvNo,a.PatientName,a.PatientId
	HAVING SUM(b.Sales-b.Less-b.Collection-b.ReturnDue)<=0
	UNION ALL
	SELECT d.MRId, d.MRName, 0 AS DiagnosticOpdSalesAmt,
	0 AS DiagnosticOpdTotalLess, 0 AS DiagnosticOpdNetAmt,
	0 AS DiagnosticIPDSalesAmt,0 AS DiagnosticIPDTotalLess,
	0 AS DiagnosticIPDNetAmt,
	CASE WHEN a.MainDeptName not in('ICU','PICU','NICU','HDU') then a.TotalAmt else 0 END as GeneralBedSales,
	CASE WHEN a.MainDeptName in('ICU','HDU') then a.TotalAmt else 0 END AS IcuHduSales,
	CASE WHEN a.MainDeptName in('NICU','PICU') then a.TotalAmt else 0 END AS NicuPicuSales,
	a.LessAmt+ISNULL(e.Less,0) AS HospitalDiscountAmt,
	a.RefDrCode, b.DrName,a.MainDeptName,a.ReleaseDate,a.ReceiptNo,a.PatientId,a.PatientName
	FROM PatientReleaseMaster a
	INNER JOIN PatientAdmission b ON a.PatientId=b.PatientId AND a.PatientId=b.PatientId
	LEFT JOIN DrInfo d ON a.BranchId=d.BranchId AND a.RefDrCode=d.DrCode
	LEFT JOIN (SELECT PatientId,BranchId,SUM(Collection) AS Collection,SUM(Less) AS Less ,MAX(RefDate) AS DueCollectionDate
			from IndoorDueCollMaster WHERE Valid=1 GROUP BY PatientId,BranchId) e ON a.PatientID=e.PatientId
	where a.Valid=1 and a.BranchId=@BranchId
	AND d.MRId LIKE '%'+@MRId+'%' 
	and ISNULL(e.DueCollectionDate,a.ReleaseDate) between @InvDateFrom AND  @InvDateTo AND d.MRId<>''
	AND a.NetDueAmt-ISNULL(e.Collection,0)-ISNULL(e.Less,0)=0
END
GO
