CREATE PROCEDURE [dbo].[SP_MRTargetProfileReportSMZ] @BranchId INT, @UnitId INT, @MRId NVARCHAR(20), @DateFrom NVARCHAR(20),
@DateTo NVARCHAR(20), @DeptName NVARCHAR(50), @SubDeptName NVARCHAR(50), @SubSubDeptName NVARCHAR(50)
AS --- EXEC SP_MRTargetProfileReportSMZ 1, 1, '', '2023-07-01', '2023-07-31', '', '', ''
BEGIN
SELECT c.MRId, d.MRName, d.DailyTarget AS [Target], d.DailyPcOrTk AS PcOrTk, 
CASE WHEN d.DailyPcOrTk = 'TK' THEN SUM(a.TotalAmt)
WHEN d.DailyPcOrTk = '%' THEN (SUM(a.TotalAmt) * d.DailyTarget / 100)
ELSE SUM(a.TotalAmt) END AS GainTarget
FROM InvMaster a
LEFT JOIN InvDetails b ON  a.BranchId = b.BranchId AND a.RegNo = b.RegNo
LEFT JOIN DrInfo c ON a.BranchId = c.BranchId and a.RefDrCode = c.DrCode
LEFT JOIN tbl_MRInfo d ON a.BranchId = c.BranchId AND c.MRId = d.MRId
WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.CostCenterName= @UnitId AND c.MRId LIKE '%'+@MRId+'%'
AND a.InvDate BETWEEN @DateFrom AND  @DateTo AND b.DeptName LIKE '%'+@DeptName+'%'
AND b.SubDeptName LIKE '%'+@SubDeptName+'%' AND b.SubSubDeptName LIKE '%'+@SubSubDeptName+'%'
GROUP BY c.MRId, d.MRName, d.DailyTarget, d.DailyPcOrTk
ORDER BY c.MRId
END
