CREATE PROC [dbo].[SP_NEW_ITEM_STOCK_LEDGER] (@dateFrom AS dateTime,@dateTo AS DateTime,@suppId AS Int,@itemId AS Int) AS
If @suppId!=0 AND @itemId!=0
BEGIN
Select 0 As Id,'-' AS InvoiceNo,GETDATE() AS  InvoiceDate,a.SuppId,b.Name AS SuppName, AVG(a.PurchasePrice) AS PurchasePrice,a.ItemId,a.BarcodeId,c.Name AS ItemName,c.Model,  SUM(a.InQty-a.OutQty-a.RtnQty) AS OpQty,0 AS InQty,0 AS OutQty,0 AS RtnQty,0 As SlNo
FROM tbl_STOCK_LEDGER a
LEFT JOIN tbl_SUPPLIER_INFO_MASTER b  ON a.SuppId=b.Id
LEFT JOIN tbl_ITEM  c  ON a.ItemId=c.Id WHERE a.TrDate < @dateFrom  AND a.SuppId=@suppId AND a.ItemId=@itemId
GROUP BY a.SuppId,a.BarcodeId,a.ItemId,b.Name,c.Name,c.Model
UNION ALL
Select a.Id, InvoiceNo AS InvoiceNo,InvoiceDate AS  InvoiceDate,a.SuppId,b.Name AS SuppName, a.PurchasePrice AS PurchasePrice,a.ItemId,a.BarcodeId,c.Name AS ItemName,c.Model,  0 AS OpQty,0 AS InQty,SUM(a.OutQty) AS OutQty,0 AS RtnQty,0 As SlNo
FROM tbl_STOCK_LEDGER a
LEFT JOIN tbl_SUPPLIER_INFO_MASTER b  ON a.SuppId=b.Id
LEFT JOIN tbl_ITEM  c  ON a.ItemId=c.Id WHERE a.TrDate BETWEEN @dateFrom AND @dateTo AND a.OutQty>0 AND a.SuppId=@suppId AND a.ItemId=@itemId
GROUP BY a.Id,a.SuppId,a.BarcodeId,a.ItemId,b.Name,c.Name,c.Model,a.InvoiceDate,a.InvoiceNo,a.PurchasePrice

UNION ALL
Select a.Id, InvoiceNo AS InvoiceNo,InvoiceDate AS  InvoiceDate,a.SuppId,b.Name AS SuppName, a.PurchasePrice AS PurchasePrice,a.ItemId,a.BarcodeId,c.Name AS ItemName,c.Model,  0 AS OpQty,SUM(a.InQty) AS InQty,0 AS OutQty,0 AS RtnQty,0 As SlNo
FROM tbl_STOCK_LEDGER a
LEFT JOIN tbl_SUPPLIER_INFO_MASTER b  ON a.SuppId=b.Id
LEFT JOIN tbl_ITEM  c  ON a.ItemId=c.Id WHERE a.TrDate BETWEEN  @dateFrom AND @dateTo  AND a.InQty>0 AND a.SuppId=@suppId AND a.ItemId=@itemId
GROUP BY a.Id, a.SuppId,a.BarcodeId,a.ItemId,b.Name,c.Name,c.Model,a.InvoiceDate,a.InvoiceNo,a.PurchasePrice
UNION ALL
Select a.Id, InvoiceNo AS InvoiceNo,InvoiceDate AS  InvoiceDate,a.SuppId,b.Name AS SuppName, a.PurchasePrice AS PurchasePrice,a.ItemId,a.BarcodeId,c.Name AS ItemName,c.Model,  0 AS OpQty,0 AS InQty,0 AS OutQty,SUM(a.RtnQty) AS RtnQty,0 As SlNo
FROM tbl_STOCK_LEDGER a
LEFT JOIN tbl_SUPPLIER_INFO_MASTER b  ON a.SuppId=b.Id
LEFT JOIN tbl_ITEM  c  ON a.ItemId=c.Id WHERE a.TrDate BETWEEN @dateFrom AND @dateTo  AND a.RtnQty>0 AND a.SuppId=@suppId AND a.ItemId=@itemId
GROUP BY a.Id, a.SuppId,a.BarcodeId,a.ItemId,b.Name,c.Name,c.Model,a.InvoiceDate,a.InvoiceNo,a.PurchasePrice
ORDER BY Id
END

If @suppId=0 AND @itemId=0
BEGIN
Select 0 As Id, '-' AS InvoiceNo,GETDATE() AS  InvoiceDate,a.SuppId,b.Name AS SuppName, AVG(a.PurchasePrice) AS PurchasePrice,a.ItemId,a.BarcodeId,c.Name AS ItemName,c.Model,  SUM(a.InQty-a.OutQty-a.RtnQty) AS OpQty,0 AS InQty,0 AS OutQty,0 AS RtnQty,0 As SlNo
FROM tbl_STOCK_LEDGER a
LEFT JOIN tbl_SUPPLIER_INFO_MASTER b  ON a.SuppId=b.Id
LEFT JOIN tbl_ITEM  c  ON a.ItemId=c.Id WHERE a.TrDate < @dateFrom  
GROUP BY  a.SuppId,a.BarcodeId,a.ItemId,b.Name,c.Name,c.Model
UNION ALL
Select a.Id, InvoiceNo AS InvoiceNo,InvoiceDate AS  InvoiceDate,a.SuppId,b.Name AS SuppName, a.PurchasePrice AS PurchasePrice,a.ItemId,a.BarcodeId,c.Name AS ItemName,c.Model,  0 AS OpQty,0 AS InQty,SUM(a.OutQty) AS OutQty,0 AS RtnQty,0 As SlNo
FROM tbl_STOCK_LEDGER a
LEFT JOIN tbl_SUPPLIER_INFO_MASTER b  ON a.SuppId=b.Id
LEFT JOIN tbl_ITEM  c  ON a.ItemId=c.Id WHERE a.TrDate BETWEEN @dateFrom AND @dateTo AND a.OutQty>0 
GROUP BY a.Id,a.SuppId,a.BarcodeId,a.ItemId,b.Name,c.Name,c.Model,a.InvoiceDate,a.InvoiceNo,a.PurchasePrice
UNION ALL
Select a.Id,InvoiceNo AS InvoiceNo,InvoiceDate AS  InvoiceDate,a.SuppId,b.Name AS SuppName, a.PurchasePrice AS PurchasePrice,a.ItemId,a.BarcodeId,c.Name AS ItemName,c.Model,  0 AS OpQty,SUM(a.InQty) AS InQty,0 AS OutQty,0 AS RtnQty,0 As SlNo
FROM tbl_STOCK_LEDGER a
LEFT JOIN tbl_SUPPLIER_INFO_MASTER b  ON a.SuppId=b.Id
LEFT JOIN tbl_ITEM  c  ON a.ItemId=c.Id WHERE a.TrDate BETWEEN  @dateFrom AND @dateTo  AND a.InQty>0 
GROUP BY a.Id,a.SuppId,a.BarcodeId,a.ItemId,b.Name,c.Name,c.Model,a.InvoiceDate,a.InvoiceNo,a.PurchasePrice
UNION ALL
Select a.Id,InvoiceNo AS InvoiceNo,InvoiceDate AS  InvoiceDate,a.SuppId,b.Name AS SuppName, a.PurchasePrice AS PurchasePrice,a.ItemId,a.BarcodeId,c.Name AS ItemName,c.Model,  0 AS OpQty,0 AS InQty,0 AS OutQty,SUM(a.RtnQty) AS RtnQty,0 As SlNo
FROM tbl_STOCK_LEDGER a
LEFT JOIN tbl_SUPPLIER_INFO_MASTER b  ON a.SuppId=b.Id
LEFT JOIN tbl_ITEM  c  ON a.ItemId=c.Id WHERE a.TrDate BETWEEN @dateFrom AND @dateTo  AND a.RtnQty>0 
GROUP BY a.Id,a.SuppId,a.BarcodeId,a.ItemId,b.Name,c.Name,c.Model,a.InvoiceDate,a.InvoiceNo,a.PurchasePrice
ORDER BY Id

END


If @suppId!=0 AND @itemId=0
BEGIN
Select 0 As Id,'-' AS InvoiceNo,GETDATE() AS  InvoiceDate,a.SuppId,b.Name AS SuppName, AVG(a.PurchasePrice) AS PurchasePrice,a.ItemId,a.BarcodeId,c.Name AS ItemName,c.Model,  SUM(a.InQty-a.OutQty-a.RtnQty) AS OpQty,0 AS InQty,0 AS OutQty,0 AS RtnQty,0 As SlNo
FROM tbl_STOCK_LEDGER a
LEFT JOIN tbl_SUPPLIER_INFO_MASTER b  ON a.SuppId=b.Id
