GROUP BY a.SuppId,a.BarcodeId,a.ItemId,b.Name,c.Name,c.Model
UNION ALL
Select a.Id,InvoiceNo AS InvoiceNo,InvoiceDate AS  InvoiceDate,a.SuppId,b.Name AS SuppName, a.PurchasePrice AS PurchasePrice,a.ItemId,a.BarcodeId,c.Name AS ItemName,c.Model,  0 AS OpQty,0 AS InQty,SUM(a.OutQty) AS OutQty,0 AS RtnQty,0 As SlNo
FROM tbl_STOCK_LEDGER a
LEFT JOIN tbl_SUPPLIER_INFO_MASTER b  ON a.SuppId=b.Id
