Select 0 As Id,'-' AS InvoiceNo,GETDATE() AS  InvoiceDate,a.SuppId,b.Name AS SuppName, AVG(a.PurchasePrice) AS PurchasePrice,a.ItemId,a.BarcodeId,c.Name AS ItemName,c.Model,  SUM(a.InQty-a.OutQty-a.RtnQty) AS OpQty,0 AS InQty,0 AS OutQty,0 AS RtnQty,0 As SlNo
