CREATE Procedure [dbo].[SP_NewDischargeCertificate] @branchId int, @dischargeNo nvarchar(20), @dischargedate varchar(20)
AS 
BEGIN --Exec SP_NewDischargeCertificate 1, 'DIS240902903', '2024-09-22' 
SELECT a.DischargeNo, a.DischargeDate, a.PatientId, b.PatientName, b.PatientAge, b.PatientSex, b.AdmissionDate,	b.AdmissionTime, a.DischargeTime, a.RefferdTo, 
 b.PatientAddress, b.PatientTel, b.BedNo, TypeOfDischarge, a.DignosisName, a.ComplainOnAdmission, a.CaseHistory, a.Investigation, a.ManagementType, 
a.OperationDate, a.OperationTime, LEFT(a.OperationName, 100) AS OperationName, a.TypeOfAneasthesia, a.IndicationOfOperation, a.Findings, a.AneasthesiaCode, a.Lmp, a.Edd, a.BloodGroup, a.TreatmentGiven, 

ISNULL(SUBSTRING((
	SELECT n.DrName+' '+n.Degree + CHAR(10) FROM PatientDischargeAnesthetists m, DrInfo n 
	WHERE m.BranchId = n.BranchId AND m.DrCode = n.DrCode AND DischargeNo = a.DischargeNo AND m.BranchId = a.BranchId and m.Valid = 1 
	ORDER BY m.Id 
FOR XML PATH('')), 0 , 1000),'') As AneasthesiaName,

ISNULL(SUBSTRING((
	SELECT DISTINCT n.DrName+' '+n.Degree + CHAR(10) FROM PatientDischargSurgeonDetails m, DrInfo n 
	WHERE m.BranchId = n.BranchId AND m.DrCode = n.DrCode AND DischargeNo = a.DischargeNo AND m.BranchId = a.BranchId and m.Valid = 1 
	ORDER BY n.DrName+' '+n.Degree + CHAR(10) 
FOR XML PATH('')), 0 , 1000),'') As SurgeonList,

 a.BabyNote, a.Histopathology, a.SpecialMedication, a.StatusOnDischarge, a.FollowUp, a.AdviceOnDepartment, a.AdviceOnDischarge, a.Weight,
b.UnderDrName+''+dr.degree AS UnderDrName, Consultant.ConsultantList, Medicine.MedicineList --,  Surgeon.SurgeonList, Consultant.ConsultantList
From  PatientDischargeHistory a   
Left join PatientAdmission b On a.PatientId=b.PatientId AND a.BranchId=b.BranchId AND a.Valid=b.Valid
left join DrInfo AS dr oN a.BranchId = dr.BranchId and b.UnderDrCode = dr.DrCode
CROSS APPLY    
(    
SELECT DISTINCT STUFF    
            (    
                (    
                    SELECT DISTINCT ',' +'DrCode: '+ DrCode +', '+ 'Dr Name:'+ a.DrName+'  ' FROM PatientDischargSurgeonDetails AS a   
                    INNER JOIN PatientDischargeHistory AS b ON a.DischargeNo=b.DischargeNo AND a.PatientId=b.PatientId AND a.Valid=b.Valid   
                    WHERE a.DischargeNo=b.DischargeNo AND a.Valid=1 AND a.BranchId=@branchId AND a.DischargeNo=@dischargeNo --AND a.DischargeDate=@dischargedate
                    FOR XML PATH('')    
                )                      
            ,1,1,'') as SurgeonList    
) as Surgeon

CROSS APPLY    
(    
SELECT DISTINCT STUFF    
            (    
                (    
                    SELECT DISTINCT a.DrName +CHAR(10) FROM PatientDischargeConsultantDetails AS a   
                    INNER JOIN PatientDischargeHistory AS b ON a.DischargeNo=b.DischargeNo AND a.PatientId=b.PatientId AND a.Valid=b.Valid   
                    WHERE a.DischargeNo=b.DischargeNo AND a.Valid=1 AND a.BranchId=@branchId AND a.DischargeNo=@dischargeNo --AND a.DischargeDate=@dischargedate
                    FOR XML PATH('')    
                )                      
            , 1, 0,'') as ConsultantList    
) as Consultant 

CROSS APPLY    
(    
SELECT STUFF    
            (    
                (    
                    SELECT  ','+ LTRIM(RTRIM(a.MedicineName)) +', '+LTRIM(RTRIM(a.DoseInfo))+', ' +LTRIM(RTRIM(a.Days))+ CHAR(10) FROM PatientDischargeTreatment AS a   
                    INNER JOIN PatientDischargeHistory AS b ON a.DischargeNo=b.DischargeNo AND a.PatientId=b.PatientId AND a.Valid=b.Valid   
                    WHERE a.DischargeNo=b.DischargeNo AND a.Valid=1 AND a.BranchId=@branchId AND a.DischargeNo=@dischargeNo --AND a.DischargeDate=@dischargedate 
					--order by a.RowId
					ORDER BY a.MedicineType
                    FOR XML PATH('')    
                )                      
            ,1,1,'') as MedicineList    
) as Medicine 
WHERE a.Valid=1 AND a.BranchId=@branchId AND a.DischargeNo=@dischargeNo --AND a.DischargeDate=@dischargedate
END
GO
