Create PROCEDURE [dbo].[SP_NICUcallListReport] @BranchId int, @PatientId NVARCHAR(20)
AS --- EXEC SP_NICUcallListReport 1, 'PA230800082'
BEGIN
SELECT d.RegNo, d.PatientId, a.PatientName, a.PatientAge, a.PatientSex, d.BloodGroup, a.PatientTel, b.KindsofBed as Department, a.PatientAddress, a.AdmissionDate, a.AdmissionTime, e.OTDate, (e.StartTime) AS OTTime, a.BedNo, b.FloorNo, a.DrCode, a.DrName, a.UnderDrCode, a.UnderDrName, d.LUCS, d.Comorbidities, d.History, d.Officer, d.MedicalOfficer, d.PostedBy, d.UserName, d.EntryDateTime 
FROM PatientAdmission a
LEFT JOIN BedInformation b ON a.BedNo = b.BedNo
LEFT JOIN NICUcallList d ON a.PatientId = d.PatientId AND a.RegNo = d.RegNo
LEFT JOIN OTScheduleMaster e ON a.PatientId = e.PatientId AND a.RegNo = e.RegNo
WHERE a.Valid = 1 AND a.BranchId = @BranchId AND d.PatientId = @PatientId
END
GO
