CREATE Procedure [dbo].[SP_NICUcallListReportDetails] @BranchId int, @UnitId int, @DateFrom varchar(20), @DateTo varchar(20)
 AS
 BEGIN
 Select a.TrNo, a.TrDate, a.PatientId, a.RegNo, b.PatientName, b.PatientAge, b.PatientSex, a.BloodGroup, b.PatientTel, b.PatientAddress,
 b.AdmissionDate, b.AdmissionTime, c.OTDate, c.StartTime as OTTime, b.BedNo , b.DrCode, b.DrName , b.UnderDrCode, b.UnderDrName, a.LUCS, a.Comorbidities, 
 a.History,  a.Officer, a.MedicalOfficer, a.PostedBy, a.UserName, a.EntryDateTime, d.FloorNo, d.KindsofBed as Department
  From NICUcallList a 
 INNER JOIN PatientAdmission b On a.PatientId=b.PatientId AND a.RegNo=b.RegNo AND a.BranchId=b.BranchId AND a.UnitId=b.CostCenterName
 INNER JOIN OTScheduleMaster c On a.PatientId=c.PatientId AND a.RegNo=c.RegNo AND a.BranchId=c.BranchId
 INNER JOIN BedInformation d On b.BedNo=d.BedNo
 WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.UnitId=@UnitId AND a.TrDate Between @DateFrom AND @DateTo
 END
GO
