CREATE Procedure [dbo].[SP_NICUcallListReportSummarized] @BranchId int, @UnitId int, @DateFrom varchar(20), @DateTo varchar(20)
 AS -- EXEC SP_NICUcallListReportSummarized 1,1, '2024-04-01','2024-04-30'
 BEGIN
 Select  b.UnderDrCode, b.UnderDrName, COUNT(TrNo) as TotalPatient
 From NICUcallList a 
 INNER JOIN PatientAdmission b On a.PatientId=b.PatientId AND a.RegNo=b.RegNo AND a.BranchId=b.BranchId AND a.UnitId=b.CostCenterName
 WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.UnitId=@UnitId AND a.TrDate Between @DateFrom AND @DateTo
 GROUP BY  b.UnderDrCode, b.UnderDrName
 END
