CREATE PROCEDURE [dbo].[SP_NICUDischargeCertificate] 
    @branchId INT, 
    @dischargeNo NVARCHAR(20), 
    @dischargedate VARCHAR(20)
AS 
BEGIN
    -- Exec SP_NICUDischargeCertificate 1, 'NDC241100001', '2024-11-27'
	SELECT  h.DischargeNo, h.DischargeType, h.DischargeDate, h.DischargeTime, h.PatientId, h.PatientName, h.GuardianName, h.Age, h.BedNo, h.Address,
	h.BloodGroup, h.Admission, h.Gender, h.Weight, h.PresentingComplain, h.FinalDiagnosis, h.HeartRate, h.RespiratoryRate, h.SpO2, h.Investigation, h.BirthHistory, h.SpecialMedication, h.NonMedicationOrder, h.Advice,
		(SELECT STUFF(
            (SELECT CHAR(10) + a.DrName FROM NICUDischargeConsultantDetails AS a WHERE a.DischargeNo = h.DischargeNo 
			AND a.PatientId = h.PatientId AND a.Valid = 1 AND a.BranchId = @branchId AND a.DischargeNo = @dischargeNo
             FOR XML PATH('')), 1, 1, ''
         )) AS ConsultantList
    FROM NICUDischargeCertificateHistory AS h
    WHERE h.Valid = 1 AND h.BranchId = @branchId AND h.DischargeNo = @dischargeNo;
END
GO
