CREATE Procedure [dbo].[SP_NICUTransferNote] @branchId int, @dischargeNo nvarchar(20), @dischargedate varchar(20)
AS 
BEGIN -- Exec SP_NICUTransferNote 1, 'TN241100001', '2024-11-28'
select a.DischargeType, TransferNo, TransferDate, TransferTime, PatientId, PatientName, Age, BloodGroup, Admission, Weight, PresentingComplain, FinalDiagnosis, S_Electrolyte, CBC,  S_Creatinine, CRP, CXR, S_Calcium, S_Bilirubin, Others, Note, Advice, UserName, EntryDateTime, Consultant.ConsultantList 
from NICUTransferNote a
    CROSS APPLY    
    (    
        SELECT 
            STUFF(
                (    
                    SELECT '' + a.DrName + CHAR(13)+CHAR(10)
                    FROM NICUTransferNoteConsultants AS a   
                    INNER JOIN NICUTransferNote AS b 
                        ON a.TransferNo = b.TransferNo 
                        AND a.PatientId = b.PatientId 
                        AND a.Valid = b.Valid   
                    WHERE 
                        a.TransferNo = b.TransferNo 
                        AND a.Valid = 1 
                        AND a.BranchId = @branchId 
                        AND a.TransferNo = @dischargeNo 
                    FOR XML PATH(''), TYPE
                ).value('.', 'NVARCHAR(MAX)'), 1, 1, ''
            ) AS ConsultantList
    ) AS Consultant 
WHERE Valid=1 AND BranchId=@branchId AND TransferNo=@dischargeNo
END
GO
