CREATE PROC [dbo].[SP_OccupiedBedInfo](@BranchId int, @UnitId int)
AS
BEGIN

select a.BedNo, a.FirstBedNo, b.FloorNo, b.CabinNo, b.KindsofBed, b.ChargePerDay, a.PatientId, a.PatientName, a.PatientSex, a.PatientAge, a.DrCode, a.DrName, a.UnderDrCode, a.UnderDrName
from PatientAdmission a, BedInformation b
where a.BranchId = b.BranchId AND a.BedNo = b.BedNo and a.IsRelease = 0 and b.IsBooked = 1 AND a.BranchId = @BranchId
UNION ALL
select a.BedNo, c.FirstBedNo, b.FloorNo, b.CabinNo, b.KindsofBed, b.ChargePerDay, a.PatientId, c.PatientName+' [ Extra Bed ]', c.PatientSex, c.PatientAge, c.DrCode, c.DrName, c.UnderDrCode, c.UnderDrName
from PatientExtraBed a, BedInformation b, PatientAdmission c
where a.BedNo = b.BedNo and a.PatientId = c.PatientId and c.IsRelease = 0 and b.isBooked = 1 AND a.BranchId = @BranchId

END
