CREATE PROC [dbo].[SP_OpdFess] (@FromDate date, @ToDate date, @UserName nvarchar(50))
AS
BEGIN
	select a.TrDate, a.TrNo, a.TokenNo, a.Name, a.RegNo, a.PhoneNo, a.Age, a.Dob, a.Gender, a.DrCode, b.DrName, b.DrType, a.Department, 
	a.Amount-ISNULL(a.RtnAmount,0) as Amount, a.UserName, a.EntryDateTime as EntryTime from OPDTicketMaster a, DrInfo b where a.DrCode = b.DrCode and a.Valid = 1 and a.Amount <> 0
	and a.TrDate BETWEEN @FromDate and @ToDate and a.UserName LIKE '%'+@UserName+'%' order by a.TrNo 
END
