create PROC [dbo].[SP_OPDTicket_DrWise](@DateFrom date, @DateTo date, @BranchId int, @DrCode NVARCHAR(20))
AS BEGIN /* EXEC SP_OPDTicket_DrWise '2022-06-01','2022-06-25', 1,'' */
select a.TrDate, a.TrNo, a.TokenNo, a.Name, a.RegNo, a.PhoneNo, a.Age, a.Gender, a.DrCode, b.DrName, a.Department,
