CREATE Procedure [dbo].[SP_OperationCallListReportDetails] @BranchId int, @UnitId int, @DateFrom varchar(20), @DateTo varchar(20), @Department nvarchar(50), @OperationName nvarchar(250)
AS ---- EXEC SP_OperationCallListReportDetails 1, 1, '2024-01-01', '2024-02-29','', ''
BEGIN
SELECT a.TrNo, a.TrDate, a.RegNo, a.PatientId, a.OperationDate, CONVERT(varchar(15),a.OTTime,100) AS  OTTime, b.PatientName, b.PatientAge, b.PatientSex, a.Diagnosis, a.Procedure1 ,
 a.EntryDateTime, a.UserName, a.Operation, a.Anesthesia, a.OTNumber, a.SeniorNurse, b.BedNo,
SUBSTRING((SELECT DISTINCT ', ' + SurgeonName FROM OperationListSurgeonInfo where TrNo=a.TrNo AND PatientId = a.PatientId AND BranchId=a.BranchId AND Valid=1 FOR XML PATH('')), 2 , 100) As SurgeonName,
SUBSTRING((SELECT DISTINCT ', ' + AnaesthesiologistName FROM OperationListAnaesthesiologistInfo where TrNo=a.TrNo AND PatientId = a.PatientId AND BranchId=a.BranchId AND Valid=1 FOR XML PATH('')), 2 , 100) As Anaesthesiologist,
SUBSTRING((SELECT DISTINCT ', ' + PaediatricianName FROM OperationListPaediatricianInfo where TrNo=a.TrNo AND PatientId = a.PatientId AND BranchId=a.BranchId AND Valid=1 FOR XML PATH('')), 2 , 100) As Paediatrician,
SUBSTRING((SELECT DISTINCT ', ' + FirstAsstDrName FROM OperationListFirstAsstDrInfo where TrNo=a.TrNo AND PatientId = a.PatientId AND BranchId=a.BranchId AND Valid=1 FOR XML PATH('')), 2 , 100) As FirstAssistantDoctor,
SUBSTRING((SELECT DISTINCT ', ' + SecondAsstDrName FROM OperationListSecondAsstDrInfo where TrNo=a.TrNo AND PatientId = a.PatientId AND BranchId=a.BranchId AND Valid=1 FOR XML PATH('')), 2 , 100) As  SecondAssistantDoctor,
SUBSTRING((SELECT DISTINCT ', ' + ThirdAsstDrName FROM OperationListThirdAsstDrInfo where TrNo=a.TrNo AND PatientId = a.PatientId AND BranchId=a.BranchId AND Valid=1 FOR XML PATH('')), 2 , 100) As  ThirdAssistantDoctor
 --c.SurgeonCode, c.SurgeonName
 From OperationList a 
LEFT JOIN PatientAdmission b On a.PatientId=b.PatientId AND a.BranchId=b.BranchId AND A.UnitId=b.CostCenterName AND a.Valid=b.Valid
LEFT JOIN BedInformation c On b.BedNo=c.BedNo
WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.UnitId=@UnitId AND a.OperationDate BETWEEN @DateFrom AND @DateTo AND
c.BedType LIKE '%'+@Department+'%' AND
a.Operation LIKE '%'+@OperationName+'%'
END
GO
