SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE Procedure [dbo].[SP_OperationCallListReportSummarized] @BranchId int, @UnitId int, @DateFrom varchar(20), @DateTo varchar(20), @Department nvarchar(50), 
@OperationName nvarchar(250)
AS ---- EXEC SP_OperationCallListReportSummarized 1, 1, '2024-01-01', '2024-02-29','Cabin', ''
BEGIN
SELECT b.SurgeonName, COUNT(a.Operation) AS TotalOperations
FROM OperationList a
LEFT JOIN OperationListSurgeonInfo b ON a.PatientId = b.PatientId
LEFT JOIN PatientAdmission c On a.PatientId=c.PatientId AND a.BranchId=c.BranchId AND A.UnitId=c.CostCenterName AND a.Valid=b.Valid
LEFT JOIN BedInformation d On c.BedNo=d.BedNo
WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.UnitId=@UnitId AND a.OperationDate BETWEEN @DateFrom AND @DateTo AND
d.BedType LIKE '%'+@Department+'%' AND
a.Operation LIKE '%'+@OperationName+'%'
GROUP BY b.SurgeonName
END
GO
