CREATE Procedure [dbo].[Sp_OperationComplianceReport] @BranchId int, @UnitId int, @TrNo nvarchar(20), @TrDate varchar(20), @patientId nvarchar(20)
AS  --- EXEC Sp_OperationComplianceReport 1, 1, 'OC240200001', '2024-02-01','PR240103356'
BEGIN
SELECT d.TrNo, d.TrDate, d.RegNo, d.PatientId, a.PatientName, a.AgeYear, a.AgeMon, a.AgeDay, a.PatientAge, a.PatientSex, a.PatientTel,
c.Name AS Department, a.PatientAddress, a.AdmissionDate, a.AdmissionTime, a.BedNo, b.FloorNo, a.DrCode, a.DrName, a.UnderDrCode, a.UnderDrName, 
d.GuardianName, d.Relation, d.Address, d.Phone, d.PostedBy, e.SurgeonCode, e.SurgeonName, d.Operation, d.Anesthesia, d.Conditions, d.UserName, d.EntryDateTime
FROM PatientAdmission a
LEFT JOIN BedInformation b ON a.BedNo = b.BedNo LEFT JOIN BedBaseTable c ON b.KindsofBed = c.Name AND c.Department = 'Department'
LEFT JOIN OperationComTable d On a.PatientId=d.PatientId AND a.RegNo=d.RegNo AND a.BranchId=d.BranchId AND a.Valid=d.Valid
LEFT JOIN OpComplianceSurgeonInfo e On a.PatientId=e.PatientId AND a.BranchId=d.BranchId AND d.TrNo=e.TrNo AND d.Valid=e.Valid AND a.Valid=d.Valid
WHERE d.Valid = 1 AND d.BranchId =@BranchId AND d.UnitId=@UnitId AND d.TrNo=@TrNo AND d.TrDate=@TrDate AND d.PatientId = @patientId 
END
GO
