CREATE Procedure [dbo].[SP_OperationNoteReport] @branchId int, @trNo nvarchar(20), @trDate varchar(20), @patientId nvarchar(20)
AS --- Exec SP_OperationNoteReport 1, 'OTN240200001', '2024-02-03' ,'PA230900015'
BEGIN
SELECT d.TrNo, d.TrDate, d.RegNo, d.PatientId, a.PatientName, a.AgeYear, a.AgeMon, a.AgeDay, a.PatientAge, a.PatientSex, a.PatientTel,
c.Name AS Department, a.PatientAddress, a.AdmissionDate, a.AdmissionTime, a.BedNo, b.FloorNo, a.DrCode, a.DrName, a.UnderDrCode, a.UnderDrName, d.PostedBy,  d.OperationDate, d.OTTime, d.Operation, d.Anesthesia, d.Incision, d.ProcedureFinding, d.UserName, d.EntryDateTime, Surgeon.SurgeonList, 
Anaesthesiologist.AnaesthesiologistList, Paediatrician.PaediatricianList, FirstAsstDr.FirstAsstDrList, SecondAsstDr.SecondAsstDrList, ThirdAsstDr.ThirdAsstDrList
FROM PatientAdmission a
LEFT JOIN BedInformation b ON a.BedNo = b.BedNo 
LEFT JOIN BedBaseTable c ON b.KindsofBed = c.Name AND c.Department = 'Department'
LEFT JOIN OperationNote d On a.PatientId=d.PatientId AND a.RegNo=d.RegNo AND a.BranchId=d.BranchId AND a.Valid=d.Valid  
CROSS APPLY    
(    
SELECT STUFF    
            (    
                (    
                    SELECT ',' +'DrCode: '+ a.SurgeonCode +', '+ 'Dr Name:'+ a.SurgeonName+'  ' FROM OperationListSurgeonInfo AS a 
                    INNER JOIN OperationNote AS b ON a.TrNo=b.TrNo AND a.PatientId=b.PatientId AND a.BranchId=b.BranchId AND a.Valid=b.Valid 
		    WHERE a.TrNo=b.TrNo AND a.Valid=1 AND a.BranchId=@branchId AND a.TrNo=@trNo AND a.TrDate=@trDate AND a.PatientId=@patientId
                    FOR XML PATH('')    
                )                      
            ,1,1,'') as SurgeonList    
) as Surgeon

CROSS APPLY    
(    
SELECT STUFF    
            (    
                (    
                    SELECT ',' + 'DrCode: '+ a.AnaesthesiologistCode +', '+ 'Dr Name:'+ a.AnaesthesiologistName +'  ' FROM OperationListAnaesthesiologistInfo AS a
                    INNER JOIN OperationNote AS b ON a.TrNo=b.TrNo AND a.PatientId=b.PatientId AND a.BranchId=b.BranchId AND a.Valid=b.Valid 
		    WHERE a.TrNo=b.TrNo AND a.Valid=1 AND a.BranchId=@branchId AND a.TrNo=@trNo AND a.TrDate=@trDate AND a.PatientId=@patientId
                    FOR XML PATH('')    
                )                      
            ,1,1,'') as AnaesthesiologistList    
) as Anaesthesiologist

CROSS APPLY    
(    
SELECT STUFF    
            (    
                (    
                     SELECT ',' + 'DrCode: '+ a.PaediatricianCode +', '+ 'Dr Name:'+ a.PaediatricianName +'  ' FROM OperationListPaediatricianInfo AS a 
                     INNER JOIN OperationNote AS b ON a.TrNo=b.TrNo AND a.PatientId=b.PatientId AND a.BranchId=b.BranchId AND a.Valid=b.Valid 
			WHERE a.TrNo=b.TrNo AND a.Valid=1 AND a.BranchId=@branchId AND a.TrNo=@trNo AND a.TrDate=@trDate AND a.PatientId=@patientId
                    FOR XML PATH('')    
                )                      
            ,1,1,'') as PaediatricianList    
) as Paediatrician 

CROSS APPLY    
(    
SELECT STUFF    
            (    
                (    
                     SELECT ',' + 'DrCode: '+ a.FirstAsstDrCode +', '+ 'Dr Name:'+ a.FirstAsstDrName +'  ' FROM OperationListFirstAsstDrInfo AS a 
                     INNER JOIN OperationNote AS b ON a.TrNo=b.TrNo AND a.PatientId=b.PatientId AND a.BranchId=b.BranchId AND a.Valid=b.Valid 
			WHERE a.TrNo=b.TrNo AND a.Valid=1 AND a.BranchId=@branchId AND a.TrNo=@trNo AND a.TrDate=@trDate AND a.PatientId=@patientId
                     FOR XML PATH('')    
                )                      
            ,1,1,'') as FirstAsstDrList    
) as FirstAsstDr

CROSS APPLY    
(    
SELECT STUFF    
            (    
                (    
                     SELECT ',' + 'DrCode: '+ a.SecondAsstDrCode +', '+ 'Dr Name:'+ a.SecondAsstDrName +'  ' FROM OperationListSecondAsstDrInfo AS a 
                     INNER JOIN OperationNote AS b ON a.TrNo=b.TrNo AND a.PatientId=b.PatientId AND a.BranchId=b.BranchId AND a.Valid=b.Valid 
			WHERE a.TrNo=b.TrNo AND a.Valid=1 AND a.BranchId=@branchId AND a.TrNo=@trNo AND a.TrDate=@trDate AND a.PatientId=@patientId
                     FOR XML PATH('')    
                )                      
            ,1,1,'') as SecondAsstDrList    
) as SecondAsstDr

CROSS APPLY    
(    
SELECT STUFF    
            (    
                (    
                     SELECT ',' + 'DrCode: '+ a.ThirdAsstDrCode +', '+ 'Dr Name:'+ a.ThirdAsstDrName +'  'FROM OperationListThirdAsstDrInfo AS a 
                     INNER JOIN OperationNote AS b ON a.TrNo=b.TrNo AND a.PatientId=b.PatientId AND a.BranchId=b.BranchId AND a.Valid=b.Valid 
		     WHERE a.TrNo=b.TrNo AND a.Valid=1 AND a.BranchId=@branchId AND a.TrNo=@trNo AND a.TrDate=@trDate AND a.PatientId=@patientId
                     FOR XML PATH('')    
                )                      
            ,1,1,'') as ThirdAsstDrList    
) as ThirdAsstDr

WHERE d.Valid=1 AND d.BranchId=@branchId AND d.TrNo=@trNo AND d.TrDate=@trDate AND a.PatientId=@patientId
END
