CREATE Procedure [dbo].[SP_OTCountedListDetails] @branchId int , @dateFrom date, @dateTo date, @OpCode nvarchar(10), @drCode nvarchar(10)
AS ---- EXEC SP_OTCountedListDetails 1, '2023-08-01', '2023-08-31', '0103',''
BEGIN
Select  RefDate , a.SurgeonCode, b.DrName, a.OperationName, count(a.OperationCode) as TotalOT
From OTScheduleMaster a left join DrInfo b On a.UnderDrCode=b.DrCode AND a.SurgeonCode=b.DrCode AND a.BranchId=b.BranchId
WHERE a.Valid=1 AND a.BranchId=@branchId  AND a.RefDate Between @dateFrom AND @dateTo AND (a.OperationCode + a.SurgeonCode) LIKE '%'+@OpCode+'%'+ @drCode 
GROUP BY  a.RefDate, a.UnderDrCode,  b.DrName, a.SurgeonCode, b.DrName, a.OperationName
ORDER BY SurgeonCode
END
GO
