CREATE Procedure [dbo].[SP_OTCountedListSMZ] @branchId int , @dateFrom date, @dateTo date, @OpCode nvarchar(10)
AS -------- EXEC SP_OTCountedListSMZ 1, '2023-08-01', '2023-08-31',''
BEGIN
Select OperationCode, OperationName, Count(OperationCode) as TotalOT From OTScheduleMaster
WHERE Valid=1 AND BranchId=@branchId  AND RefDate Between @dateFrom AND @dateTo AND OperationCode LIKE '%'+@OpCode+'%' 
GROUP BY OperationCode, OperationName
ORDER BY OperationCode
END
