CREATE Procedure [dbo].[SP_OTDoctorLedgerDetails] @branchId int, @dateFrom date, @dateTo date, @opCode nvarchar(10), @pCode nvarchar(10), @drCode nvarchar(10)
AS ---- EXEC SP_OTDoctorLedgerDetails 1, '2023-08-01' , '2023-08-31' , '', '',''
BEGIN
select a.RefNo, a.RefDate, a.PatientId, a.RegNo, a.Name, a.BedNo , a.OTDate, a.OTRoomNo, b.DrCode, c.DrName,
a.OTSlNo, a.StartTime, a.FinishingTime, a.TotalOTTime, a.OperationCode, a.OperationName, a.OperationType,
b.Code, b.Description, b.Charge, b.ServiceCharge,  b.TotalAmount, a.UserName, a.EntryDateTime
From OTScheduleMaster a left join OTScheduleDtls b On a.RefNo=b.RefNo AND a.BranchId=b.BranchId AND a.Valid=b.Valid
left join DrInfo c On b.DrCode=c.DrCode AND b.BranchId=c.BranchId
WHERE a.Valid=1 AND a.BranchId=@branchId AND a.RefDate BETWEEN @dateFrom AND @dateTo AND (a.OperationCode + b.Code + b.DrCode) LIKE '%'+@opCode+'%'+ @pCode +'%'+ @drCode
GROUP BY a.RefNo, a.RefDate, a.PatientId, a.RegNo, a.Name, a.BedNo, a.OTDate, a.OTRoomNo, b.DrCode, c.DrName,
a.OTSlNo, a.StartTime, a.FinishingTime, a.TotalOTTime, a.OperationCode, a.OperationName, a.OperationType, 
b.Code, b.Description, b.Charge, b.ServiceCharge,  b.TotalAmount, a.UserName,  a.EntryDateTime
HAVING b.DrCode !=''
END
GO
