CREATE Procedure [dbo].[SP_OTDoctorLedgerSMZ] @branchId int, @dateFrom date, @dateTo date, @opCode nvarchar(10), @pCode nvarchar(10), @drCode nvarchar(10)
AS ----  EXEC SP_OTDoctorLedgerSMZ 1, '2023-08-01' , '2023-08-31' , '', '0004', ''
BEGIN
select a.OperationCode, a.OperationName, b.DrCode, c.DrName , b.Code, b.Description, sum(b.Charge) as Charge
From OTScheduleMaster a left join OTScheduleDtls b On a.RefNo=b.RefNo AND a.BranchId=b.BranchId AND a.Valid=b.Valid
left join DrInfo c On b.DrCode=c.DrCode AND a.BranchId=b.BranchId  
WHERE a.Valid=1 AND a.BranchId=@branchId AND a.RefDate BETWEEN @dateFrom AND @dateTo AND (a.OperationCode + b.Code + b.DrCode) LIKE '%'+@opCode+'%'+ @pCode+'%'+  @drCode+'%'
GROUP BY  a.OperationCode, a.OperationName, b.DrCode , c.DrName, b.Code, b.Description
HAVING b.DrCode !=''
END
GO
