CREATE Procedure [dbo].[SP_OtPostOperativeReport] @BranchId int, @UnitId int, @TrNo nvarchar(20), @TrDate nvarchar(20), @PatientId nvarchar(20)
AS  ---  EXEC SP_OtPostOperativeReport 1, 1, 'POO240100001', '2024-01-31', 'PA240100206' 
BEGIN
SELECT a.TrNo, a.TrDate, a.OrderTime, a.RegNo, a.PatientId, c.PatientName, c.PatientTel, d.KindsofBed as Department, c.PatientAddress, c.AdmissionDate, c.AdmissionTime, c.AgeYear, c.AgeMon, c.AgeDay, c.PatientAge, c.PatientSex, c.BedNo, d.FloorNo, c.DrCode, c.DrName, c.UnderDrCode, c.UnderDrName, a.Note, a.BloodGroup, a.HOAllergy, b.MedicineName, b.Doses, b.Days, b.Root, b.Frequency, b.MedicineType, a.UserName, a.EntryDateTime
FROM OTPostOperativeOrders a 
LEFT JOIN OTPostOperativeMedicineInfo b On a.TrNo=b.TrNo AND a.PatientId=b.PatientId AND a.BranchId=b.BranchId AND a.UnitId=b.UnitId AND a.Valid=b.Valid
LEFT JOIN PatientAdmission c On a.PatientId=c.PatientId AND a.RegNo=c.RegNo AND a.BranchId=c.BranchId AND a.Valid=c.Valid
LEFT JOIN BedInformation d On c.BedNo=d.BedNo
WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.UnitId=@UnitId AND a.TrNo=@TrNo AND a.TrDate=@TrDate AND a.PatientId=@PatientId
END
GO
