CREATE PROC [dbo].[SP_OTSchedule] @BranchId INT, @RefDate DATE, @RefNo VARCHAR(20)
AS
BEGIN
SELECT a.Id, a.RefNo, a.RefDate, a.PatientId, a.RegNo, a.Name, a.Age, a.Sex, a.BedNo, a.UnderDrCode, UnderDrName, 
a.OTDate, a.OTRoomNo, a.OTSlNo, a.StartTime, a.FinishingTime, a.TotalOTTime, a.UserName, a.OperationCode, a.OperationName,
a.OperationType, a.SurgeonCode, a.SurgeonName, a.Remarks, b.Code, b.Description, b.Unit, b.NoU, b.Charge, b.ServiceCharge, 
b.TotalAmount, b.DrCode, b.DrName, b.DrAmount
FROM OTScheduleMaster a
LEFT JOIN OTScheduleDtls b ON a.Id = b.MasterId AND a.BranchId = b.BranchId AND b.Valid = 1
WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.RefDate = @RefDate AND a.RefNo = @RefNo
END
