CREATE PROC [dbo].[Sp_OutdoorChamberVisitCollectionReport] @BranchId INT, @DrCode VARCHAR(60), @DateFrom DATE, @DateTo DATE
AS
	BEGIN --EXEC Sp_OutdoorChamberVisitCollectionReport 1, '', '2024-03-19', '2024-03-19'
		SELECT a.RefNo, a.RefDate, a.PtStatus, a.RegNo, a.PatientId, a.PatientName, a.MobNo, a.Gender, a.Age, a.BedNo, a.TotalTk,
		a.Collection, a.CashAmt, a.CardAmt, a.ChequeAmt, a.Remarks, a.UserName,	b.Code, b.Description, 
		b.DrCode, b.DrName, b.Charge, b.NoU, b.Total
		FROM OutdoorChamberVisitMaster a
		LEFT JOIN OutdoorChamberVisitDtls b on b.RefDate = a.RefDate and b.RefNo = a.RefNo and b.Valid = 1
		WHERE a.Valid = 1 AND a.BranchId = 1 AND a.RefDate BETWEEN @DateFrom AND @DateTo and (CASE when @DrCode = '' THEN '' ELSE b.DrCode END) = @DrCode

		UNION ALL
		SELECT a.TrNo, a.TrDate, 'Chamber' AS PtStatus, a.RegNo, '' AS PatientId, a.Name AS PatientName, a.PhoneNo AS MobNo, a.Gender, a.Age, '' AS BedNo, a.Amount AS TotalTk,
		a.Amount AS Collection, a.Amount AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, a.Remarks, a.UserName, '' AS Code, 'Chamber Ticket' AS Description,
		a.DrCode, b.DrName+' '+b.Degree AS DrName, a.Amount AS Charge, 1 AS Nou, a.Amount AS Total
		FROM OPDTicketChamber a
		LEFT JOIN DrInfo b on b.BranchId = a.BranchId and b.DrCode = a.DrCode
		WHERE a.Valid = 1 AND a.BranchId = 1 AND a.TrDate BETWEEN @DateFrom AND @DateTo and (CASE when @DrCode = '' THEN '' ELSE a.DrCode END) = @DrCode

	END
GO
