/****** Object:  StoredProcedure [dbo].[SP_PATIENT_BILL_DETAILS]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[SP_PATIENT_BILL_DETAILS](@PatientId AS varchar(20))
AS
select a.RegNo, a.PatientName, a.PatientTel, a.PatientAddress, a.AdmissionDate, a.AdmissionTime, a.BedNo, aa.* from
(
select a.RefDate, a.RefNo, a.PatientId, a.Status, b.SubSubPno, a.Particulars, a.Charge, a.NoU, 
a.ServiceCharge, (a.Charge*a.NoU)+a.ServiceCharge as TotalAmount, a.Less,
(a.Charge*a.NoU)+a.ServiceCharge-a.Less as NetTotalAmount
from PatientLedger a, BedInformation b, PatientRegistration c
where a.BedNo = b.BedNo and a.RegNo = c.RegNo and a.Charge != 0 and a.PatientId = @PatientId
group by a.RefDate, a.RefNo, a.PatientId, a.Status, b.SubSubPno, a.Particulars, a.Charge, a.NoU, 
a.ServiceCharge, a.Less
UNION ALL
select a.InvDate, 'Diagnosis', a.PatientId, a.DeptName, b.SubSubPno, a.ShortDesc, a.Amount, a.Quantity, 
a.ServiceCharge, (a.Amount*a.Quantity)+a.ServiceCharge, a.Less1,
((a.Amount*a.Quantity)+a.ServiceCharge-a.Less1) as NetTotalAmount
from InvDetails a, BedInformation b
where a.Bedno = b.BedNo and a.Amount != 0 and a.PatientId = @PatientId
--group by  a.InvDate, a.PatientId, UPPER(a.DeptName), a.ShortDesc, b.SubSubPno, a.Amount, a.Quantity, 
--a.ServiceCharge, a.Less1
UNION ALL
select a.SaleDate, 'Medicine' ,a.PatientId,'Medicine', b.SubSubPno, a.ProductName, a.SalePrice, a.ProductQty,
0, a.SalePrice*a.ProductQty TotalAmount, 0, 
a.SalePrice*a.ProductQty NetTotalAmount 
from PharSalesDetails a, BedInformation b
where a.BedNo = b.BedNo and a.PatientId =@PatientId
--group by a.PatientId, a.RegNo, b.SubSubPno
UNION ALL
select a.RefDate, 'Ambulance' ,a.PatientId, 'Ambulance', b.SubSubPno, a.AmbulanceNo, a.TotalCharge, 1,
0, a.TotalCharge-a.Less, 0,
a.TotalCharge-a.Less
from AmbulanceLedger a, BedInformation b
where a.BedNo = b.BedNo and a.PatientId = @PatientId
) aa,
PatientAdmission a
where a.Valid = 1 and a.PatientId =@PatientId






GO
/****** Object:  StoredProcedure [dbo].[SP_PATIENT_DISCHARGE_AFTER_SETTLEMENT]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE proc [dbo].[SP_PATIENT_DISCHARGE_AFTER_SETTLEMENT](@PatientId nvarchar(20), @BranchId int)
AS
BEGIN

SELECT cc.ReceiptNo, cc.RefDate, bb.UnderDrCode, bb.UnderDrName, bb.AdmissionDate, bb.AdmissionTime, cc.ReleaseDate, cc.EntryDateTime as ReleaseDateTime, 
bb.PatientName , bb.BedNo, bb.PatientAddress, bb.PatientAge, bb.RegNo, bb.PatientSex, bb.PatientTel, cc.UserName, DATEDIFF(DAY, bb.AdmissionDate,cc.ReleaseDate) as TotalDays,
ISNULL(SUBSTRING((SELECT DISTINCT Remarks+',' FROM PatientLedger where PatientId = @PatientId and Valid = 1  FOR XML PATH('')), 1 , 1000),'') as Remarks,  aa.PatientId, aa.Status, aa.SubSubPno, aa.NoU, SUM(aa.ServiceCharge) as ServiceCharge, SUM(aa.TotalAmount) as TotalAmount, SUM(aa.FirstLess) as FirstLess, SUM(aa.NetTotalAmount) as NetTotalAmount, SUM(aa.FirstColl) as FirstColl, SUM(aa.SecondLess) as SecondLess, SUM(aa.DueCollection) as DueCollection, SUM(aa.ReturnAmt) as ReturnAmt, sum(aa.Charge) as Charge
FROM (
select a.PatientId, a.Particulars Status, b.SubSubPno, a.Charge, SUM(a.NoU) NoU, SUM(a.ServiceCharge) ServiceCharge, 
Sum(a.Charge*a.NoU+a.ServiceCharge) as TotalAmount, SUM(a.Less) FirstLess,
SUM(a.Charge*a.NoU+a.ServiceCharge-a.Less) as NetTotalAmount, sum(a.Collection) AS FirstColl, 0 as SecondLess, 
0 as DueCollection, a.ReturnAmt AS ReturnAmt
from PatientLedger a, BedInformation b, PatientRegistration c
where a.BranchId = b.BranchId AND a.BranchId = c.BranchId AND b.BranchId = c.BranchId AND a.BedNo = b.BedNo and a.RegNo = c.RegNo
and a.Status NOT IN ('Patient Settlement', 'Patient Release') and a.Valid = 1 and a.PatientId = @PatientId AND a.BranchId = @BranchId
group by a.PatientId, a.Particulars, b.SubSubPno, a.Charge, a.ReturnAmt
UNION ALL
select a.PatientId, 'Settlement', '', 0, 1, 0, 
0, 0, 0, 0, SUM(a.Less) as Less, 
SUM(a.Collection) as SecondColl, a.ReturnAmt AS ReturnAmt
from PatientLedger a
where a.PatientId = @PatientId and a.Status IN ('Patient Settlement') and a.Valid = 1 AND a.BranchId = @BranchId
group by a.PatientId, a.ReturnAmt
UNION ALL
select  a.PatientId, 'Diagnosis Bill' Status, b.SubSubPno, SUM(a.Sales-a.ReturnAmount) as Charge, 1 as NoU, 0 ServiceCharge, 
SUM(a.Sales-a.ReturnAmount) as TotalAmount, SUM(a.Less) FirstLess, SUM(a.Sales-a.ReturnAmount-a.Less) as NetTotalAmount, sum(a.Collection) AS FirstColl, 0 as SecondLess, 
0 as DueCollection, 0 AS ReturnAmt
from SalesLedger a, BedInformation b, PatientRegistration c
where a.BranchId = b.BranchId AND a.BranchId = c.BranchId AND b.BranchId = c.BranchId AND a.BedNo = b.BedNo and a.RegNo = c.RegNo
 and a.Valid = 1 and a.PatientId = @PatientId AND a.BranchId = @BranchId
group by a.PatientId, a.Particulars, b.SubSubPno
UNION ALL
select  a.PatientId, 'Medicine Bill' Status, b.SubSubPno, SUM(a.Sales) as Charge, 1 as NoU, 0 ServiceCharge, 
SUM(a.Sales) as TotalAmount, SUM(a.LessAmt) AS FirstLess, SUM(a.Sales-a.LessAmt-a.CashReturn) as NetTotalAmount, SUM(a.Collection) AS FirstColl, SUM(a.DueLess) as SecondLess, 
SUM(a.DueColl) as DueCollection, SUM(a.CashReturn) AS ReturnAmt
from PharSalesLedger a, BedInformation b
where a.BranchId = b.BranchId AND a.BedNo = b.BedNo
 and a.Valid = 1 and a.PatientId = @PatientId AND a.BranchId = @BranchId
group by a.PatientId, a.Particulars, b.SubSubPno
) aa , PatientAdmission bb, PatientReleaseMaster cc--, PatientLedger dd
where aa.PatientId = bb.PatientId and aa.PatientId = cc.PatientID --and bb.PatientId = dd.PatientId and dd.Valid = 1 
and cc.Valid = 1 and bb.Valid = 1 
group by cc.ReceiptNo, cc.RefDate, bb.UnderDrCode, bb.UnderDrName, bb.AdmissionDate, bb.AdmissionTime, cc.ReleaseDate, cc.EntryDateTime, 
bb.PatientName , bb.BedNo, bb.PatientAddress, bb.PatientAge, bb.RegNo, bb.PatientSex, bb.PatientTel, aa.PatientId, aa.Status, cc.UserName, aa.SubSubPno,
aa.NoU

END
GO
