where a.PatientID = b.PatientId and a.RegNo = b.RegNo and a.PatientID = c.PatientId and a.RegNo = c.RegNo and a.Valid = 1 and b.Valid = 1 and a.PatientID = @PatientId and a.RegNo = @RegNo

