/****** Object:  StoredProcedure [dbo].[SP_Patient_Discharge_Package]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[SP_Patient_Discharge_Package](@PatientId nvarchar(20), @PackageCode nvarchar(20))
AS
BEGIN

select PCode, Description, 0 as Charge, 0 as PackageCost,  Charge as ExtraAmount from ClinicalChart where PCode = @PackageCode
UNION ALL
select aaa.Code, 'Extra Charge of '+ aaa.Description, SUM(aaa.Charge) as Charge, SUM(aaa.PackageCost) as PackageCost, (CASE WHEN sum(aaa.charge-aaa.PackageCost) < 0 THEN 0 else sum(aaa.charge-aaa.PackageCost) END) as ExtraAmount from(
select aa.code, aa.Description, aa.Charge, 0 as PackageCost
from (
select '0001' as Code, b.Description as Description, a.Charge*a.NoU as Charge from PatientLedger a, ClinicalChart b where a.Code = b.PCode and PatientId = @PatientId and a.Code = '0001'
UNION ALL 
select '0002' as Code, b.Description as Description, a.Charge*a.NoU as Charge from PatientLedger a, ClinicalChart b where a.Code = b.PCode and PatientId = @PatientId and a.Code = '0002'
UNION ALL
select '0003' as Code, b.Description as Description, a.Charge*a.NoU as Charge from PatientLedger a, ClinicalChart b where a.Code = b.PCode and PatientId = @PatientId and a.Code = '0003'
UNION ALL
select a.Code, b.Description as Description, a.DrAmount*a.NoU as Charge from PatientLedger a, ClinicalChart b where a.Code = b.PCode and PatientId = @PatientId and a.Code IN ('0004','0005','0006','0007')  and NOT Exists (select * from HPIndoorPackage where PCode = '0008' and PackageCode = @PackageCode and Valid = 1)
UNION ALL
select a.Code, b.Description as Description, a.Charge*a.NoU as Charge from PatientLedger a, ClinicalChart b where a.Code = b.PCode And a.Charge > 0 and PatientId = @PatientId and a.Code IN ('0008') and NOT Exists (select * from HPIndoorPackage where PCode = '0004' and PackageCode = @PackageCode and Valid = 1)
UNION ALL
select '0009' as Code, 'Medicine Bill' as Description, SUM(a.Sales-a.ReturnAmt) from PharSalesLedger a where PatientId = @PatientId and Valid = 1
UNION ALL
select '0011' as Code, 'Diagnosis Bill' as Description, SUM(a.Sales-a.ReturnAmount) from SalesLedger a where a.PatientId = @PatientId and a.Valid = 1
UNION ALL
select '0012' as Code, 'Procedure charge' as Description, SUM((a.Charge*a.NoU)+a.ServiceCharge) as Charge from PatientLedger a where PatientId = @PatientId and a.Code NOT IN('0003','0001','0002','0008','0004','0005','0006','0007')
) aa
UNION ALL
select PCode, Description, 0 as Charge, TotalPrice from HPIndoorPackage where PackageCode = @PackageCode
) aaa
group by aaa.Code, aaa.Description
having sum(aaa.charge-aaa.PackageCost) > 0

END



GO
