Begin
SELECT a.TreatmentTime, a.RegNo, a.BedNo, a.PatientName, a.PatientAge, a.BedRest, a.Position, a.Diet, a.Fluid, 
a.FluidLDay, a.Oxygen, a.Reflow, a.PatientCondition, a.BPSystolic, a.BPDistolic, a.Pulse, a.BloodSugar, 
a.Weight, a.Temp, a.Heart, a.Lung, a.UserName,
a.PatientId , a.TreatmentDate, a.OrderNo ,
ISNULL(dbo.fnc_IndoorPressInvName(PatientId,OrderNo),'') InvstName ,
ISNULL(dbo.fnc_IndoorPressMedicine(PatientId,OrderNo),'') AS MedicineName,
ISNULL(dbo.fnc_IndoorPressComplain(PatientId,OrderNo),'') AS Complain,
ISNULL(dbo.fnc_IndoorPressPD(PatientId,OrderNo),'') AS PD 
FROM IndoorPrescriptionMaster a 
where a.Valid = 1  AND a.PatientId = @patientId --AND a.BranchId = @BranchId
end


