/****** Object:  StoredProcedure [dbo].[SP_PatientBillPreview]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[SP_PatientBillPreview](@PatientId AS varchar(20), @BranchId int, @IsIncludePharmacy INT)
AS
BEGIN /* EXEC SP_PatientBillPreview 'PA231100182', 1, 1 */
	DECLARE @IncludePharmacy INT;
	IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END

	SELECT TOP 1 BranchId, PatientId, OperationName, OperationType, StartTime, FinishingTime, OTDate, OTRoomNo, OTSlNo
	into #z 
	FROM OTScheduleMaster 
	WHERE BranchId = @BranchId and Valid = 1 and PatientId = @PatientId order by id desc

	select a.RegNo, a.PatientName, a.PatientTel, a.PatientAddress, a.AdmissionDate, a.AdmissionTime, a.BedNo, a.PatientSex, ISNULL(a.DrCode, '') AS DrCode,
	ISNULL(a.DrName+''+c.Degree, '') AS DrName, ISNULL(a.UnderDrCode,'') AS UnderDrCode, ISNULL(a.UnderDrName+''+b.Degree, '') AS UnderDrName, a.PatientAge, 
	a.EntryDateTime as AdmissionDateTime, DATEDIFF(DAY, a.AdmissionDate, GETDATE())+1 as TotalDays, ISNULL(d.OperationName, '') AS OperationName, 
	ISNULL(d.OperationType, '') AS OperationType, ISNULL(d.StartTime, '') AS StartTime, ISNULL(d.FinishingTime, '') AS FinishingTime, 
	ISNULL(d.OTDate, '') AS OTDate, ISNULL(d.OTRoomNo, '') AS OTRoomNo, ISNULL(d.OTSlNo, '') AS OTSlNo, aa.* 
	from
	(
	--select a.PatientId, b.SubSubPno, a.Particulars, a.Charge, SUM(a.NoU) AS NoU, 
	--SUM(a.ServiceCharge) AS ServiceCharge, sum((a.Charge*a.NoU)+a.ServiceCharge) as TotalAmount, SUM(a.Less) AS Less,
	--SUM((a.Charge*a.NoU)+a.ServiceCharge-a.Less) as NetTotalAmount, 0 as Collection
	--from PatientLedger a, BedInformation b, PatientRegistration c
	--where a.BranchId = b.BranchId AND a.BranchId = c.BranchId AND b.BranchId = c.BranchId AND a.BedNo = b.BedNo and a.RegNo = c.RegNo and a.Valid = 1
	--and a.PatientId = @PatientId AND a.BranchId = @BranchId
	--group by a.PatientId, b.SubSubPno, a.Particulars, a.Charge

	select a.PatientId, b.SubSubPno, a.Particulars, a.Charge, SUM(a.NoU) AS NoU, 
	0 AS ServiceCharge, sum((a.Charge*a.NoU)) as TotalAmount, SUM(a.Less) AS Less,
	SUM((a.Charge*a.NoU)-a.Less) as NetTotalAmount, 0 as Collection
	from PatientLedger a, BedInformation b, PatientRegistration c
	where a.BranchId = b.BranchId AND a.BranchId = c.BranchId AND b.BranchId = c.BranchId AND a.BedNo = b.BedNo and a.RegNo = c.RegNo 
	and a.Valid = 1 and a.PatientId = @PatientId AND a.BranchId = @BranchId
	group by a.PatientId, b.SubSubPno, a.Particulars, a.Charge

	UNION ALL
	select a.PatientId, b.SubSubPno, a.Particulars, a.Charge, SUM(a.NoU) AS NoU, 
	SUM(a.ServiceCharge) AS ServiceCharge, sum((a.Charge*a.NoU)+a.ServiceCharge) as TotalAmount, SUM(a.Less) AS Less,
	SUM((a.Charge*a.NoU)+a.ServiceCharge-a.Less) as NetTotalAmount, SUM(a.Collection) as Collection
	from PatientLedger a, BedInformation b, PatientRegistration c
	where a.BranchId = b.BranchId AND a.BranchId = c.BranchId AND b.BranchId = c.BranchId AND a.BedNo = b.BedNo and a.RegNo = c.RegNo and a.Collection != 0 
	and a.Valid = 1 and a.PatientId = @PatientId AND a.BranchId = @BranchId
	group by a.PatientId, b.SubSubPno, a.Particulars, a.Charge

	/*Start Indoor Service Charge*/
	UNION ALL
	SELECT a.PatientId, c.SubSubPno AS BedDept,  'Service Charge' AS Particulars, SUM(b.ServiceCharge) AS Charge, 1 AS NoU,
	0 AS ServiceCharge, SUM(b.ServiceCharge) AS TotalAmount, 0 AS  Less, SUM(b.ServiceCharge) AS NetTotalAmount, 0 AS Collection
	FROM PatientAdmission a
	LEFT JOIN PatientLedger b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId AND b.Valid = 1
	LEFT JOIN BedInformation c ON a.BranchId = c.BranchId AND a.BedNo = c.BedNo
	WHERE a.BranchId = @BranchId AND a.PatientId = @PatientId 
	GROUP BY a.PatientId, c.SubSubPno
	/*End Indoor Service Charge*/

	/*End Indoor Charge*/


	/*Start SalesLedger */
	UNION ALL
	/*Sales From SalesLedger */
	SELECT PatientId, SubSubPno, Particulars, SUM(Charge) AS Charge, 1 AS NoU, 
	0 AS ServiceCharge, SUM(TotalAmount) AS TotalAmount, SUM(Less) AS Less,
	SUM(NetTotalAmount) AS NetTotalAmount, 0 as Collection FROM (
		SELECT a.PatientId, d.SubSubPno, ISNULL(b.SubDeptName, 'LabTest') AS Particulars, SUM(a.Amount*a.Quantity) AS Charge, 
		SUM(a.Amount*a.Quantity) AS TotalAmount, SUM(a.GLessAmt) AS Less, SUM(a.Amount*a.Quantity-a.GLessAmt) AS NetTotalAmount
		FROM InvDetails a
		LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.PCode = b.PCode
		LEFT JOIN BedInformation d ON a.BranchId=d.BranchId AND a.Bedno = d.BedNo
		LEFT JOIN (
			SELECT BranchId, sum(Collection-ReturnCash) as Collection, SUM(Less) AS Less
			FROM SalesLedger where BranchId = @BranchId ANd Valid = 1 AND Department != 'Ambulance' AND PatientId = @PatientId GROUP BY BranchId
		) f ON a.BranchId = f.BranchId
		WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.DeptName != 'Ambulance' AND a.PatientId = @PatientId
		GROUP BY a.PatientId, d.SubSubPno, b.SubDeptName, a.GLessAmt, f.Collection
	) m
	GROUP BY PatientId, SubSubPno, Particulars

	/*Collection From SalesLedger */
	UNION ALL
	select a.PatientId, b.SubSubPno, 'Outdoor Collection' as Particulars, 0 as Charge, 1 As NoU, 
	0 as ServiceCharge, 0 AS TotalAmount, 0 as Less,
	0 as NetTotalAmount, SUM(a.Collection-a.ReturnCash) as Collection
	from SalesLedger a
	LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
	WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.Department != 'Ambulance' AND a.PatientId = @PatientId
	GROUP BY a.PatientId, b.SubSubPno, a.Department
	HAVING SUM(a.Collection-a.ReturnCash) > 0
	/*End SalesLedger */

	UNION ALL
	SELECT a.PatientId, b.SubSubPno, 'Abmulance' AS Particulars, SUM(TotalCharge) AS Charge, 1 AS NoU,
	0 AS ServiceCharge, SUM(TotalCharge) AS TotalAmount, SUM(a.Less) AS Less, SUM(a.TotalCharge-a.Less) AS NetTotalAmount, SUM(a.ReceiveAmt) AS Collection
	FROM AmbulanceLedger a
	LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.PatientId = @PatientId
	GROUP BY a.PatientId, b.SubSubPno

	--select  a.PatientId, b.SubSubPno, a.Department as Particulars, sum(a.Sales-a.ReturnAmount) as Charge, 1 As NoU, 
	--0 as ServiceCharge, SUM(a.Sales-a.ReturnAmount) AS TotalAmount, SUM(a.Less) as Less,
	--SUM(a.Sales-a.Less-a.ReturnAmount) as NetTotalAmount, SUM(a.Collection-a.ReturnAmount) as Collection
	--from SalesLedger a, BedInformation b
	--where a.BranchId = b.BranchId AND a.Bedno = b.BedNo and a.Valid <> 0 and a.PatientId = @PatientId AND a.BranchId = @BranchId
	--group by  a.PatientId, b.SubSubPno, a.Department
	--------a.ServiceCharge, a.Less1

	UNION ALL
	select a.PatientId, b.SubSubPno, 'Medicine Bill' AS Particulars, SUM(a.Sales-a.ReturnAmt-a.LessAdjust) AS Charge, 1 AS NoU,
	0 as ServiceCharge, SUM(a.Sales-a.ReturnAmt-a.LessAdjust) AS TotalAmount, SUM(a.LessAmt+a.DueLess) as Less, 
	SUM(a.Sales-a.LessAmt-a.DueLess-a.ReturnAmt-a.LessAdjust) AS NetTotalAmount, SUM(a.Collection+a.DueColl-a.CashReturn) as Collection
	from PharSalesLedger a, BedInformation b
	where a.BranchId = b.BranchId AND a.BedNo = b.BedNo and a.Valid = @IsIncludePharmacy and a.PatientId = @PatientId and a.Valid = 1 AND a.BranchId = @BranchId 
	group by a.PatientId, b.SubSubPno


	) aa
	LEFT JOIN PatientAdmission a ON aa.PatientId = a.PatientId
	LEFT JOIN DrInfo b ON a.BranchId = b.BranchId AND a.UnderDrCode = b.DrCode
	LEFT JOIN DrInfo c ON a.BranchId = c.BranchId AND a.DrCode = c.DrCode
	LEFT JOIN #z d ON a.BranchId = d.BranchId AND a.PatientId=d.PatientId
	where a.Valid = 1 and a.PatientId = @PatientId and IsRelease = 0 aND a.BranchId = @BranchId
	--------
END
GO
/****** Object:  StoredProcedure [dbo].[SP_PatientBillPreview_Oasis]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[SP_PatientBillPreview_Oasis](@PatientId AS varchar(20), @BranchId int, @IsIncludePharmacy INT)
AS
BEGIN /* EXEC SP_PatientBillPreview_Oasis 'PA231200115', 1, 1 */
	DECLARE @IncludePharmacy INT;
	IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END;

	SELECT TOP 1 BranchId, PatientId, OperationName, OperationType, StartTime, FinishingTime, OTDate, OTRoomNo, OTSlNo
	into #z 
	FROM OTScheduleMaster 
	WHERE BranchId = @BranchId and Valid = 1 and PatientId = @PatientId order by id desc

	select a.BedNo, a.RegNo, a.PatientName, a.PatientTel, a.PatientAddress, a.AdmissionDate, a.AdmissionTime, aa.BedNo AS TransferBed, 
	aa.EntryDateTime AS TransferDate, aa.ReleaseDate AS TransferReleaseDate, aa.UserName AS TrasferBy, a.PatientSex, ISNULL(a.DrCode, '') AS DrCode, 
	ISNULL(a.DrName+''+c.Degree, '') AS DrName, ISNULL(a.UnderDrCode,'') AS UnderDrCode, ISNULL(a.UnderDrName+''+b.Degree, '') AS UnderDrName, a.PatientAge, 
	a.EntryDateTime as AdmissionDateTime, DATEDIFF(DAY, a.AdmissionDate, GETDATE())+1 as TotalDays, ISNULL(d.OperationName, '') AS OperationName, 
	ISNULL(d.OperationType, '') AS OperationType, ISNULL(d.StartTime, '') AS StartTime, ISNULL(d.FinishingTime, '') AS FinishingTime, 
	ISNULL(d.OTDate, '') AS OTDate, ISNULL(d.OTRoomNo, '') AS OTRoomNo, ISNULL(d.OTSlNo, '') AS OTSlNo, aa.* 
	from
	(
		/*Start Indoor Charge */
		select c.id AS ChangedBedId, c.Status, a.BedNo, c.EntryDateTime, ISNULL(c.ReleaseDate, GETDATE()) AS ReleaseDate, c.UserName, a.PatientId, b.SubSubPno, a.Particulars, 
		a.Charge, SUM(a.NoU) AS NoU, 
		SUM(a.ServiceCharge) AS ServiceCharge, sum((a.Charge*a.NoU)) as TotalAmount, SUM(a.Less) AS Less,
		SUM((a.Charge*a.NoU)-a.Less+a.ServiceCharge) as NetTotalAmount, SUM(a.Collection) as Collection
		from PatientLedger a
		left join BedInformation b on b.BranchId = a.BranchId and b.BedNo = a.BedNo
		left join ChangeBedInfo c on c.BranchId = a.BranchId AND c.Id = a.ChangedBedId AND c.Valid = 1
		where a.Valid = 1 and a.PatientId = @PatientId AND a.BranchId = @BranchId
		group by c.id, c.Status, c.EntryDateTime, c.ReleaseDate, c.UserName, a.BedNo, a.PatientId, b.SubSubPno, a.Particulars, a.Charge

		/*End Indoor Charge*/

		/*Start SalesLedger */
		UNION ALL
		select c.id, c.Status, a.BedNo, c.EntryDateTime, ISNULL(c.ReleaseDate, GETDATE()) AS ReleaseDate, c.UserName, a.PatientId, b.SubSubPno AS SubSubPno, a.Department, 
		SUM(a.Sales-a.ReturnAmount) AS Charge, 1 as NoU, 
		SUM(a.ProcServiceCharge) AS ServiceCharge, SUM(a.Sales-a.ReturnAmount) AS TotalAmount, SUM(a.Less) AS Less, 
		SUM(a.Sales+a.ProcServiceCharge-a.ReturnAmount) AS NetTotalamount, SUM(a.Collection) AS Collection
		from SalesLedger a
		LEFT JOIN BedInformation b on b.BranchId = a.BranchId and b.BedNo = a.BedNo
		left join ChangeBedInfo c on c.Id = a.ChangedBedId and c.Valid = 1
		where a.BranchId = @BranchId and a.Valid = 1 and a.PatientId = @PatientId and Department != 'ambulance'
		GROUP BY c.id, c.Status, a.BedNo, c.EntryDateTime, c.ReleaseDate, c.UserName, a.PatientId, b.SubSubPno, a.Department, b.BedNo

		/*End SalesLedger */
		UNION ALL
		SELECT c.id, c.Status, a.BedNo, c.EntryDateTime, ISNULL(c.ReleaseDate, GETDATE()) AS ReleaseDate, c.UserName, a.PatientId, b.SubSubPno, 'Abmulance' AS Particulars, 
		SUM(a.TotalCharge) AS Charge, 1 AS NoU,
		sum(a.ProcServiceCharge) AS ServiceCharge, SUM(a.TotalCharge) AS TotalAmount, SUM(a.Less) AS Less, SUM(a.TotalCharge-a.Less) AS NetTotalAmount, SUM(a.ReceiveAmt) AS Collection
		FROM AmbulanceLedger a
		LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
		left join ChangeBedInfo c on c.BranchId = a.BranchId and c.BedNo = b.BedNo and c.Valid = 1 and c.EntryDateTime > a.EntryDateTime
		WHERE a.BranchId = @BranchId AND a.Valid = 1 AND a.PatientId = @PatientId
		GROUP BY c.id, c.Status, a.BedNo, c.EntryDateTime, c.ReleaseDate, c.UserName, a.PatientId, b.SubSubPno

		UNION ALL
		select c.id, c.Status, a.BedNo, c.EntryDateTime, ISNULL(c.ReleaseDate, GETDATE()) AS ReleaseDate, c.UserName, a.PatientId, b.SubSubPno, 'Medicine Bill' AS Particulars, 
		SUM(a.Sales-a.ReturnAmt-a.LessAdjust) AS Charge, 1 AS NoU,
		0 as ServiceCharge, SUM(a.Sales-a.ReturnAmt-a.LessAdjust) AS TotalAmount, SUM(a.LessAmt+a.DueLess) as Less, 
		SUM(a.Sales-a.LessAmt-a.DueLess-a.ReturnAmt-a.LessAdjust) AS NetTotalAmount, SUM(a.Collection+a.DueColl-a.CashReturn) as Collection
		from PharSalesLedger a 
		left join BedInformation b on a.BranchId = b.BranchId and a.BedNo = b.BedNo
		left join ChangeBedInfo c on c.BranchId = a.BranchId and c.BedNo = b.BedNo and c.Valid = 1 and c.EntryDateTime > a.EntryDateTime
		where a.BranchId = b.BranchId AND a.BedNo = b.BedNo and a.Valid = @IsIncludePharmacy and a.PatientId = @PatientId and a.Valid = 1 AND a.BranchId = @BranchId 
		group by c.id, c.Status, a.BedNo, c.EntryDateTime, c.ReleaseDate, c.UserName, a.PatientId, b.SubSubPno
		union all
		select b.id, b.Status, b.BedNo, b.EntryDateTime, b.ReleaseDate, b.UserName, b.PatientId, c.SubSubPno AS SubSubPno, 'Canteen' AS Particulars, 
		SuM(a.GrandTotal) as Charge, 1 AS NoU, SUM(a.ProcServiceCharge) AS ServiceCharge, SUM(a.GrandTotal) AS TotalAmount, sum(a.FixedLessAmt+a.GeneralLessAmt) AS Less, 
		SUM(a.GrandTotal+a.ProcServiceCharge-a.FixedLessAmt-a.GeneralLessAmt-a.TotalCollection) AS NetTotalAmount, SUM(a.TotalCollection) AS Collection 
		from CanteenSalesLedger a
		left join ChangeBedInfo b on a.ChangedBedId = b.Id
		left join BedInformation c on c.BranchId = a.BranchId and c.BedNo = b.bedno
		where a.BranchId = @BranchId and a.patientid = @PatientId and a.valid = 1
		GROUP BY b.id, b.Status, b.BedNo, b.EntryDateTime, b.ReleaseDate, b.UserName, b.PatientId, c.SubSubPno

	) aa
	LEFT JOIN PatientAdmission a ON aa.PatientId = a.PatientId
	LEFT JOIN DrInfo b ON a.BranchId = b.BranchId AND a.UnderDrCode = b.DrCode
	LEFT JOIN DrInfo c ON a.BranchId = c.BranchId AND a.DrCode = c.DrCode
	LEFT JOIN #z d ON a.BranchId = d.BranchId AND a.PatientId=d.PatientId
	where a.Valid = 1 and a.PatientId = @PatientId and IsRelease = 0 aND a.BranchId = @BranchId
	ORDER BY aa.EntryDateTime
	--------
END
GO
