CREATE PROC [dbo].[SP_PatientBillPreview_Temp](@PatientId AS varchar(20), @BranchId int, @IsIncludePharmacy INT)
AS
/* EXEC SP_PatientBillPreview_Temp 'PA221200001', 1, 1 */
DECLARE @IncludePharmacy INT;
IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END

select a.RegNo, a.PatientName, a.PatientTel, a.PatientAddress, a.AdmissionDate, a.AdmissionTime, a.BedNo, a.PatientSex,
a.DrCode, a.DrName+''+c.Degree AS DrName, a.UnderDrCode, a.UnderDrName+''+b.Degree AS UnderDrName, a.PatientAge, a.EntryDateTime as AdmissionDateTime,
DATEDIFF(DAY, a.AdmissionDate, GETDATE())+1 as TotalDays, aa.* from
(
select a.PatientId, b.SubSubPno, a.Particulars, a.Charge, SUM(a.NoU) AS NoU, 
SUM(a.ServiceCharge) AS ServiceCharge, sum((a.Charge*a.NoU)+a.ServiceCharge) as TotalAmount, SUM(a.Less) AS Less,
SUM((a.Charge*a.NoU)+a.ServiceCharge-a.Less) as NetTotalAmount, 0 as Collection
from PatientLedgerForPreview a, BedInformation b, PatientRegistration c
where a.BranchId = b.BranchId AND a.BranchId = c.BranchId AND b.BranchId = c.BranchId AND a.BedNo = b.BedNo and a.RegNo = c.RegNo and a.Valid = 1 and a.PatientId = @PatientId AND a.BranchId = @BranchId
group by a.PatientId, b.SubSubPno, a.Particulars, a.Charge--, a.ServiceCharge, a.Less, a.NoU
UNION ALL
select a.PatientId, b.SubSubPno, a.Particulars, a.Charge, SUM(a.NoU) AS NoU, 
SUM(a.ServiceCharge) AS ServiceCharge, sum((a.Charge*a.NoU)+a.ServiceCharge) as TotalAmount, SUM(a.Less) AS Less,
SUM((a.Charge*a.NoU)+a.ServiceCharge-a.Less) as NetTotalAmount, SUM(a.Collection) as Collection
from PatientLedgerForPreview a, BedInformation b, PatientRegistration c
where a.BranchId = b.BranchId AND a.BranchId = c.BranchId AND b.BranchId = c.BranchId AND a.BedNo = b.BedNo and a.RegNo = c.RegNo and a.Collection != 0 and a.Valid = 1 and a.PatientId = @PatientId AND a.BranchId = @BranchId
group by a.PatientId, b.SubSubPno, a.Particulars, a.Charge--, a.ServiceCharge, a.Less, a.NoU
UNION ALL
select  a.PatientId, b.SubSubPno, a.Department as Particulars, sum(a.Sales-a.ReturnAmount) as Charge, 1 As NoU, 
0 as ServiceCharge, SUM(a.Sales-a.ReturnAmount) AS TotalAmount, SUM(a.Less) as Less,
SUM(a.Sales-a.Less-a.ReturnAmount) as NetTotalAmount, SUM(a.Collection-a.ReturnAmount) as Collection
from SalesLedger a, BedInformation b
where a.BranchId = b.BranchId AND a.Bedno = b.BedNo and a.Valid <> 0 and a.PatientId = @PatientId AND a.BranchId = @BranchId
group by  a.PatientId, b.SubSubPno, a.Department
--------a.ServiceCharge, a.Less1
UNION ALL
select a.PatientId, b.SubSubPno, 'Medicine Bill' AS Particulars, SUM(a.Sales-a.ReturnAmt-a.CashReturn) AS Charge, 1 AS NoU,
0 as ServiceCharge, SUM(a.Sales-a.ReturnAmt-a.CashReturn) AS TotalAmount, SUM(a.LessAmt+a.DueLess) as Less, 
SUM(a.Sales-a.LessAmt-a.DueLess-a.ReturnAmt-a.CashReturn) AS NetTotalAmount, SUM(a.Collection+a.DueColl-a.CashReturn) as Collection
from PharSalesLedger a, BedInformation b
where a.BranchId = b.BranchId AND a.BedNo = b.BedNo and a.Valid = @IsIncludePharmacy and a.PatientId = @PatientId AND a.BranchId = @BranchId 
group by a.PatientId, b.SubSubPno
--UNION ALL
--select a.PatientId, b.SubSubPno, a.AmbulanceNo, a.TotalCharge as Charge, 1 AS Nou,
--0 as ServiceCharge, SUM(a.TotalCharge) AS TotalAmount, SUM(a.Less) as Less,
--SUM(a.TotalCharge-a.Less) AS NetTotalAmout, SUM(a.ReceiveAmt) as Collection
--from AmbulanceLedger a, BedInformation b
--where a.BranchId = b.BranchId AND a.BedNo = b.BedNo and a.Valid = 1 and a.PatientId = @PatientId AND a.BranchId = @BranchId
--group by a.PatientId, b.SubSubPno, a.AmbulanceNo, a.TotalCharge
) aa,
PatientAdmission a, DrInfo b, DrInfo c
where  a.BranchId = b.BranchId AND a.UnderDrCode = b.DrCode AND a.BranchId = c.BranchId AND a.DrCode = c.DrCode AND a.Valid = 1 
and a.PatientId = @PatientId and IsRelease = 0 aND a.BranchId = @BranchId

--------


GO
