CREATE PROC [dbo].[SP_PatientEMR](@RegNo nvarchar(20), @BranchId INT)
AS
BEGIN
select a.InvDate, a.InvNo, a.PCode, a.ShortDesc, a.PtStatus, (Case when a.PatientId = '0' then '' else a.PatientId end) as PatientId, b.SubDeptName 
from InvDetails a, ClinicalChart b 
WHERE a.PCode = b.PCode AND Valid=1 and b.SubDeptName NOT IN ('Neddle') AND RegNo =@RegNo
UNION ALL
select DISTINCT TreatmentDate as InvDate, '' AS OrderNo, '' as PCode, 'Pulse Chart' AS ShortDesc, 'Indoor' as PtStatus, a.PatientId, 'Pulse Chart' AS SubDeptName from IndoorPrescriptionMaster a
where a.RegNo = @RegNo
UNION ALL
select DISTINCT TreatmentDate as InvDate, '' AS OrderNo, '' as PCode, 'BP Chart' AS ShortDesc, 'Indoor' as PtStatus, a.PatientId, 'BP Chart' AS SubDeptName from IndoorPrescriptionMaster a
where a.RegNo = @RegNo
UNION ALL
select DISTINCT TreatmentDate as InvDate, '' AS OrderNo, '' as PCode, 'Temperature Chart' AS ShortDesc, 'Indoor' as PtStatus, a.PatientId, 'Temperature Chart' AS SubDeptName from IndoorPrescriptionMaster a
where a.RegNo = @RegNo
UNION ALL
select DISTINCT TreatmentDate as InvDate, '' AS OrderNo, '' as PCode, 'Order Sheet' AS ShortDesc, 'Indoor' as PtStatus, a.PatientId, 'Order Sheet' AS SubDeptName from IndoorPrescriptionMaster a
where a.RegNo = @RegNo
UNION ALL
select a.DischargeDate, a.DischargeNo, '' as PCode, 'Dishcarge Certificate' as ShortDesc, 'Indoor' as PtStatus, a.PatientId, 'Discharge Certificate' as SubDeptName from HospitalDischargeMaster a, PatientAdmission b where a.PatientId=b.PatientId and b.RegNo = @RegNo
UNION ALL
select ReceiptDate as InvDate, ReceiptNo as InvNo, '' as PCode, 'Prescription' as ShortDesc, 'Outdoor' as PtStatus, '' as PatientId, 'Prescription' as SubDeptName from PrescriptionMaster where RegNo = @RegNo

END
GO
