CREATE PROCEDURE [dbo].[SP_PatientReleaseDtls](@PatientId nvarchar(50), @BranchId int)
AS BEGIN /* EXEC SP_PatientReleaseDtls 'PA230600469', 1*/
SELECT aa.SlNo, aa.PatientId, bb.PatientName, bb.RegNo, bb.EntryDateTime as AdmissionDate, cc.EntryDateTime as ReleaseDate, bb.UnderDrName, bb.PatientTel, bb.PatientAddress, bb.BedNo, bb.PatientAge, bb.PatientSex, DATEDIFF(DAY, bb.AdmissionDate, cc.ReleaseDate)+1 as TotalDays, aa.ServiceName, aa.Service as SubSubPno, cc.UserName, aa.Service as Particulars, 0 as TotalAmount, SUM(aa.HTotalAmount) as HTotalAmount, SUM(aa.HAdvanceColl) as HAdvanceColl, SUM(aa.HLess) as HLess, SUM(aa.HSettlementColl) as HSettlementColl, SUM(aa.HAdvanceColl+aa.HSettlementColl) as HTotalPaid, SUM(aa.HTotalAmount-aa.HAdvanceColl-aa.HSettlementColl-HLess) as HDue, SUM(aa.DSales) as DSales, SUM(aa.DColl) as DColl, SUM(aa.DLess) as DLess, SUM(aa.DSales-aa.DColl-aa.DLess) as DDue, SUM(aa.MSales) as MSales, SUM(aa.MColl) as MColl, SUM(aa.MLess) as MLess, SUM(aa.MSales-aa.MColl-aa.MLess) as MDue, SUM(aa.HTotalAmount+aa.DSales+aa.MSales) as GTotal, SUM(aa.HLess+aa.DLess+aa.MLess) as GLess, SUM(aa.HAdvanceColl+aa.DColl+aa.MColl) as GAdvance, SUM(aa.HSettlementColl) as GSettlementColl, SUM(aa.HAdvanceColl+aa.HSettlementColl+aa.DColl+aa.MColl) AS GTotalPaid, SUM((aa.HTotalAmount+aa.DSales+aa.MSales)-(aa.HAdvanceColl+aa.HSettlementColl+aa.DColl+aa.MColl+aa.HLess+aa.DLess+aa.MLess)) as Due 
FROM (

	select 2 as SlNo, a.BranchId, a.PatientId, 'Hospital Bill' as ServiceName, 'Services' as Service, SUM(a.NoU*a.Charge+a.ServiceCharge-a.Less) as HTotalAmount,
	SUM(a.Collection) as HAdvanceColl, SUM(a.Less) as HLess, 0 as HSettlementColl, 0 as DSales, 0 as DColl, 0 as DLess, 0 as MSales, 0 as MColl, 0 as MLess
	from PatientLedger a

	WHERE a.BranchId = @BranchId and a.PatientId = @PatientId 
	AND a.Status NOT IN ('Patient Release') and a.Valid = 1 AND a.Code NOT IN ('0009','0011')
	GROUP BY a.BranchId, a.PatientId

	UNION ALL
	select 2 as SlNo, a.BranchId, a.PatientId, 'Hospital Bill' as ServiceName, 'Services' as Service, 0 as HTotalAmount,
	0 as HAdvanceColl, SUM(a.Less) as HLess, SUM(a.Collection) as HSettlementColl, 0 as DSales, 0 as DColl, 0 as DLess, 
	0 as MSales, 0 as MColl, 0 as MLess
	from PatientLedger a
	WHERE a.PatientId = @PatientId AND a.BranchId = @BranchId AND a.Status IN ('Patient Release') and a.Valid = 1 AND a.Code NOT IN ('0009','0011')
	GROUP BY a.BranchId, a.PatientId
	----------Ambulance
	UNION ALL
	select 2 as SlNo, a.BranchId, a.PatientId, 'Hospital Bill' as ServiceName, 'Services' as Service, ISNULL(SUM(a.TotalCharge),0) as HTotalAmount,
	ISNULL(SUM(a.ReceiveAmt),0) as HAdvanceColl, 0 as HLess, 0 as HSettlementColl, 0 as DSales, 0 as DColl, 0 as DLess, 
	0 as MSales, 0 as MColl, 0 as MLess
	from AmbulanceLedger a, BedInformation b 
	WHERE a.BedNo = b.BedNo and a.PatientId = @PatientId and a.Valid = 1 ANd a.BranchId = @BranchId
	GROUP BY a.BranchId, a.PatientId
	HAVING ISNULL(SUM(a.ReceiveAmt),0) > 0
	-------END
	UNION ALL
	select 3 as SlNo, a.BranchId, a.PatientId, 'Diagnostic Bill' as ServiceName, 'Investigation' as Service, 0 as HTotalAmount,
	0 as HAdvanceColl, 0 as HLess, 0 as HSettlementColl, SUM(a.Sales-a.ReturnAmount) as DSales, SUM(a.Collection-a.ReturnCash) as DColl, SUM(a.Less-a.ReturnLess) as DLess, 
	0 as MSales, 0 as MColl, 0 as MLess
	from SalesLedger a
	WHERE a.PatientId = @PatientId AND a.BranchId = @BranchId and a.Valid <> 0
	GROUP BY a.BranchId, a.PatientId

	UNION ALL
	select 3 as SlNo, a.BranchId, a.PatientId, 'OPD Bill' as ServiceName, 'OPD Bill' as Service, 0 as HTotalAmount,
	0 as HAdvanceColl, 0 as HLess, 0 as HSettlementColl, 0 as DSales, 0 as DColl, 0 as DLess, 
	SUM(a.TotalTk) as MSales, SUM(a.Collection) as MColl, 0 as DLess
	from OutdoorChamberVisitMaster a
	WHERE a.PatientId = @PatientId AND a.BranchId = @BranchId and a.Valid <> 0
	GROUP BY a.BranchId, a.PatientId

	--UNION ALL
	--select 4 as SlNo, a.BranchId, a.PatientId, 'Pharmacy Bill' as ServiceName, 'Medicine' as Service, 0 as HTotalAmount, 0 as HAdvanceColl, 0 as HLess, 0 as HSettlementColl, 0 as DSales, 0 as DColl, 0 as DLess, SUM(a.Sales) as MSales, SUM(a.Collection+a.DueColl) as MColl, SUM(a.LessAmt) as MLess
	--from PharSalesLedger a
	--WHERE a.PatientId = @PatientId AND a.BranchId = @BranchId and a.Valid <> 0
	--GROUP BY a.PatientId, a.BranchId

) aa, PatientAdmission bb, PatientReleaseMaster cc
where aa.BranchId = bb.BranchId AND aa.BranchId = cc.BranchId AND aa.PatientId = bb.PatientId and aa.PatientId = cc.PatientID AND bb.PatientId = cc.PatientID AND cc.Valid = 1 AND bb.Valid = 1
GROUP BY aa.SlNo, aa.PatientId, bb.PatientName, bb.RegNo, bb.EntryDateTime, cc.EntryDateTime, bb.UnderDrName, bb.PatientTel, bb.PatientAddress, bb.BedNo, aa.ServiceName, cc.UserName, aa.Service, bb.PatientAge, bb.PatientSex, bb.AdmissionDate, cc.ReleaseDate
UNION ALL
select 1 aS SLNO, a.PatientId, bb.PatientName, bb.RegNo, bb.EntryDateTime as AdmissionDate, cc.EntryDateTime as ReleaseDate, bb.UnderDrName, bb.PatientTel, bb.PatientAddress, bb.BedNo, 
bb.PatientAge, bb.PatientSex, DATEDIFF(DAY, bb.AdmissionDate, cc.ReleaseDate)+1 as TotalDays, 'Hospital Bill' as ServiceName, b.SubSubPno, cc.UserName, 
(CASE WHEN c.SubSubDeptName = 'General OT' THEN a.Particulars+' - '+a.DrName+' ('+a.DrCode+')' ELSE a.Particulars END) AS Particulars, 
SUM(a.NoU*a.Charge+a.ServiceCharge-a.Less) as TotalAmount , 0 as HTotalAmount,0 as HAdvanceColl, 0 as HLess, 0 as HSettlementColl, 0 as HTotalPaid, 0 as HDue, 0 as DSales, 0 as DColl, 
0 as DLess, 0 AS DDue, 0 as MSales, 0 as MColl, 0 as MLess, 0 AS MDue, 0 as GTotal, 0 as GLess, 0 as GAdvance, 0 as GSettlementColl, 0 AS GTotalPaid, 0 as Due-- INTO #ptn
from PatientLedger a 
LEFT JOIN BedInformation b ON a.BranchId = b.BranchId AND a.BedNo = b.BedNo
LEFT JOIN PatientAdmission bb ON a.BranchId = bb.BranchId AND a.PatientId = bb.PatientId AND bb.Valid = 1
LEFT JOIN PatientReleaseMaster cc ON a.BranchId = cc.BranchId AND a.PatientId = cc.PatientID AND cc.Valid = 1
LEFT JOIN ClinicalChart c ON a.BranchId = c.BranchId AND a.Code = c.PCode
WHERE a.BranchId = @BranchId AND a.PatientId = @PatientId AND a.Status NOT IN ('Patient Release') and a.Valid = 1
group by a.PatientId, bb.PatientName, bb.RegNo, bb.EntryDateTime, cc.EntryDateTime , bb.UnderDrName, bb.PatientTel, bb.PatientAddress, bb.BedNo, b.SubSubPno, cc.UserName, a.Particulars, bb.PatientAge, bb.PatientSex, bb.AdmissionDate, cc.ReleaseDate, c.SubSubDeptName, a.DrCode, a.DrName

UNION ALL
select 1 aS SLNO, a.PatientId, bb.PatientName, bb.RegNo, bb.EntryDateTime as AdmissionDate, cc.EntryDateTime as ReleaseDate, bb.UnderDrName, bb.PatientTel, bb.PatientAddress, bb.BedNo, bb.PatientAge, bb.PatientSex, DATEDIFF(DAY, bb.AdmissionDate, cc.ReleaseDate)+1 as TotalDays, 'Hospital Bill' as ServiceName, b.SubSubPno, cc.UserName, 'Ambulance Bill' AS Particulars, SUM(a.TotalCharge) as TotalAmount , 0 as HTotalAmount,0 as HAdvanceColl, 0 as HLess, 0 as HSettlementColl, 0 as HTotalPaid, 0 as HDue, 0 as DSales, 0 as DColl, 0 as DLess, 0 AS DDue, 0 as MSales, 0 as MColl, 0 as MLess, 0 AS MDue, 0 as GTotal, 0 as GLess, 0 as GAdvance, 0 as GSettlementColl, 0 AS GTotalPaid, 0 as Due
from AmbulanceLedger a, BedInformation b, PatientAdmission bb, PatientReleaseMaster cc
WHERE a.BranchId = b.BranchId AND a.BranchId = bb.BranchId AND a.BranchId = cc.BranchId AND b.BranchId = bb.BranchId AND b.BranchId = cc.BranchId AND bb.BranchId = cc.BranchId AND a.BedNo = b.BedNo AND a.PatientId = bb.PatientId AND a.PatientId = cc.PatientID and bb.PatientId = cc.PatientID and a.PatientId = @PatientId AND a.BranchId = @BranchId and a.Valid = 1 AND bb.Valid = 1 AND cc.Valid = 1
group by a.PatientId, bb.PatientName, bb.RegNo, bb.EntryDateTime, cc.EntryDateTime , bb.UnderDrName, bb.PatientTel, bb.PatientAddress, bb.BedNo, b.SubSubPno, cc.UserName, bb.PatientAge, bb.PatientSex, bb.AdmissionDate, cc.ReleaseDate
order by SlNo
END
GO
/****** Object:  StoredProcedure [dbo].[SP_PatientReleaseDtls_Pharmacy]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
