CREATE PROC [dbo].[SP_PatientReleaseDtls_Pharmacy](@PatientId nvarchar(20), @BranchId int)
AS
BEGIN

select a.BranchId, a.PatientId, 'Pharmacy Bill' as ServiceName, 'Medicine' as Service, SUM(a.Sales) as MSales, SUM(a.Collection+a.DueColl) as MColl, SUM(a.LessAmt) as MLess, SUM(a.Sales-a.Collection-a.DueColl-a.DueLess-a.ReturnAmt-a.LessAmt) AS Due
from PharSalesLedger a
WHERE a.PatientId = @PatientId AND a.BranchId = @BranchId and a.Valid <> 0
GROUP BY a.PatientId, a.BranchId

END
GO
/****** Object:  StoredProcedure [dbo].[SP_PatientReleaseInfo]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

--10082025 CorporateId, CorporateName Add
--19082025 CorporateId, MrId Parameter Pass
CREATE PROC [dbo].[SP_PatientReleaseInfo] (@dateFrom datetime,@dateTo dateTime, @branchId int, @type VARCHAR(20), @drCode VARChAR(50), @corporateId varchar(50), @mrId varchar(60))
AS
BEGIN /* EXEC SP_PatientReleaseInfo '2026-01-01', '2026-01-02', 1, '', '', '', '' */

	DECLARE @IncludePharmacy INT, @IsIncludePharmacy INT;
	SELECT @IsIncludePharmacy = PharmacyInclude FROM tbl_ComInfo
	IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END

	SELECT c.SubSubPno, b.RegNo, b.PatientId, b.AdmissionDate, b.AdmissionTime, b.PatientName, b.PatientSex, b.PatientAge, b.PatientAddress, 
	b.DrCode, b.DrName, b.UnderDrCode, b.UnderDrName, b.BedNo, d.Remarks, b.PatientTel, b.AdmittedDept, d.EntryDateTime AS ReleaseDateTime, d.ReleaseDate, d.UserName,
	b.PatientType, ISNULL(e.MrId,'') AS MrId, ISNULL(e.MrName,'') AS MrName, b.CorporateId, ISNULL(e.Name,'') As CorporateName, SUM(a.HBill) AS HBill, SUM(a.DBill) AS DBill, SUM(a.MBill) AS MBill, SUM(a.Collection) AS Advance,
	SUM(a.AdjustAmt) AS AdjustAmt, SUM(a.HBill+a.DBill+a.MBill-a.Collection-a.LessAmt) AS Due , SUM(a.LessAmt) as LessAmt, 
	SUM(isnull(a.HBill,0)+ISNULL(a.DBill,0)+ISNULL(a.MBill,0)) AS TotalBill
	FROM (
		SELECT a.BranchId, a.PatientId, SUM(a.TotalAmount) AS HBill, 0 AS DBill, 0 AS MBill,
		SUM(a.Collection-a.ReturnAmt) AS Collection, 0 AS AdjustAmt , SUM(a.Less) as LessAmt
		FROM PatientLedger a
		WHERE Valid = 1 AND a.PatientId != ''
		GROUP BY a.BranchId, a.PatientId
		UNION
		SELECT a.BranchId, a.PatientId, 0 AS HBill, SUM(a.Sales-a.ReturnNet) AS DBill, 0 AS MBill,
		SUM(a.Collection-a.ReturnCash) AS Collection, SUM(a.AdjustAmt) AS AdjustAmt , SUM(a.Less) as LessAmt
		FROM SalesLedger a
		WHERE a.Valid = 1 AND a.PatientId != ''
		GROUP BY a.BranchId, a.PatientId
		UNION
		SELECT a.BranchId, a.PatientId, 0 AS HBill, 0 AS DBill, SUM(a.Sales-a.ReturnAmt-a.LessAdjust) AS MBill,
		SUM(a.Collection+a.DueColl-a.CashReturn) AS Collection, SUM(a.AdjustAmt) AS AdjustAmt , SUM(a.DueLess + a.LessAmt) as LessAmt
		FROM PharSalesLedger a
		WHERE a.Valid = @IncludePharmacy AND a.PatientId != ''
		GROUP BY a.BranchId, a.PatientId
	) a
	LEFT JOIN PatientAdmission b ON a.BranchId = b.BranchId AND a.PatientId = b.PatientId
	LEFT JOIN BedInformation c ON a.BranchId = c.BranchId AND b.BedNo = c.BedNo
	LEFT JOIN PatientReleaseMaster d ON a.BranchId = d.BranchId AND b.PatientId = d.PatientID
	Left Join CorporateStaff e ON b.BranchId=e.BranchId AND b.CorporateId=e.Id
	WHERE b.BranchId = @BranchId AND b.IsRelease = 1 AND d.ReleaseDate BETWEEN @DateFrom AND @DateTo
	AND d.Valid = 1
	AND CASE when @type = 'RefDr' THEN b.DrCode ELSE b.UnderDrCode END LIKE '%'+@drCode+'%'
	And Case WHEN @corporateId = '' THen '' ELse b.CorporateId end = @corporateId
	And Case WHEN @mrId = '' THen '' ELse e.MrId end = @mrId
	GROUP BY c.SubSubPno, b.RegNo, b.PatientId, b.AdmissionDate, b.AdmissionTime, b.PatientName, b.PatientSex,
	b.PatientAge, b.PatientAddress, b.DrCode, b.DrName, b.UnderDrCode, b.UnderDrName, b.BedNo, d.Remarks,
	b.PatientTel, b.AdmittedDept, b.PatientType, d.EntryDateTime, d.ReleaseDate, d.UserName, 
	e.MrId, e.MrName, b.CorporateId, e.Name--b.CorporateName
	--HAVING SUM(a.HBill+a.DBill+a.MBill-a.Collection-a.LessAmt) != 0	
END
GO
/****** Object:  StoredProcedure [dbo].[SP_PatientReleasePackge]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[SP_PatientReleasePackge](@branchId int, @patientId nvarchar(20), @PackageCode nvarchar(20), @isRelease int)
AS BEGIN
/*exec SP_PatientReleasePackge 1, 'PA2209004647','P002',0*/
/*Start Insert #tmp_z table package date*/
select PCode, Description, 0 as Charge, 0 as PackageCost, Charge as ExtraAmount, 0 as Id,
0 AS Collection, 0 AS Less
INTO #tmp_z from ClinicalChart where BranchId = @branchId AND PCode = @PackageCode
UNION ALL
select aa.Code, 'Extra Charge of '+ aa.Description, SUM(aa.Charge) as Charge, SUM(aa.PackageCharge) as PackageCost,
(CASE WHEN sum(aa.charge-aa.PackageCharge) < 0 THEN 0 else sum(aa.charge-aa.PackageCharge) END) as ExtraAmount, Id,
SUM(aa.Collection) AS Collection, SUM(aa.Less) AS Less
from(
	select a.Code, b.Description, SUM(a.NoU*a.Charge) AS Charge, 0 AS PackageCharge, (CASE WHEN ISNULL(c.Id, 0) = 0  then 0 ELSE 1 END) AS Id, 
	0 AS Collection, 0 AS Less
	from PatientLedger a
	LEFT JOIN ClinicalChart b ON a.BranchId = b.BranchId AND a.Code = b.PCode
	LEFT JOIN HPIndoorPackage c ON a.BranchId = c.BranchId AND a.Code = c.PCode AND b.PCode = c.PCode ANd b.BranchId = c.BranchId AND c.PackageCode = @PackageCode
	WHERE a.BranchId = @branchId AND a.Valid = 1 AND a.PatientId = @patientId
	GROUP BY a.Code, b.Description, c.Id, a.BedNo
	UNION ALL
	SELECT a.PCode, a.ShortDesc AS Description, SUM(a.Quantity*a.Amount) AS Charge, 0 AS PackageCharge, 1 AS Id,
	0 AS Collection, SUM(GLessAmt) AS Less
	FROM InvDetails a
	WHERE a.BranchId = @branchId AND a.PatientId = @patientId
	GROUP BY a.PCode, a.ShortDesc
	--UNION ALL
	--select '0009' as Code, 'Medicine Bill' as Description, SUM(a.Sales-a.ReturnAmt-a.CashReturn) AS Charge, 0 AS PackageCharge, 1 AS Id,
	--0 AS Collection, 0 AS Less
	--from PharSalesLedger a where a.BranchId = @branchId AND a.PatientId = @patientId and a.Valid = 1
	UNION ALL
	select PCode, Description, 0 as Charge, TotalPrice, 1 AS Id, 0 AS Collection, 0 AS Less
	from HPIndoorPackage where BranchId = @branchId AND PackageCode = @PackageCode

	/*Collection*/
	UNION ALL
	select '9999' AS Code, a.Department+' Collection' AS Description, 0 as Charge, 0 AS TotalPrice, 1 AS Id,
	SUM(a.Collection-a.ReturnCash) AS Collection, 0 AS Less
	from SalesLedger a
	where a.BranchId = @branchId AND a.Valid <> 0 AND a.PatientId = @patientId AND @isRelease = 1
	GROUP BY a.Department
	UNION ALL
	select '9999' AS Code, 'Indoor Collection' AS Description, 0 as Charge, 0 AS TotalPrice, 1 AS Id,
	SUM(a.Collection) AS Collection, 0 AS Less
	from PatientLedger a
	where a.BranchId = @branchId AND a.Valid = 1 AND a.PatientId = @patientId AND @isRelease = 1
	/*End Collection*/
) aa
GROUP BY aa.Code, aa.Description, aa.Id
having sum(aa.charge-aa.PackageCharge+aa.Collection) > 0
/*Start Insert #tmp_z table package date*/

/*START If Bill Preview Then @isRelease = 0 ELSE @isRelease = 1*/
if ( @isRelease = 0)
	/*START GET RELEASE DATE */
	BEGIN
		SELECT PCode, Description, Charge, PackageCost, ExtraAmount, Id, Collection, Less FROM #tmp_z;
	END
	/*END GET RELEASE DATE */
ELSE
	/*START BILL PREVIEW DATE*/
	BEGIN
		select a.RegNo, a.PatientId, a.AdmissionDate, a.AdmissionTime, a.PatientName, a.PatientSex AS Gender, a.PatientAge, a.BedNo, 
		DATEDIFF(DAY, AdmissionDate, GETDATE())+1 AS TotalDays, a.UnderDrName, a.BedNo, a.PatientTel AS PhoneNo, a.PatientAddress AS Address, a.UserName AS AdmittedBy,
		b.PCode, b.Description, b.ExtraAmount AS Charge, b.Collection, b.Less AS Less
		from PatientAdmission a
		CROSS JOIN #tmp_z b
		where a.BranchId = @branchId AND a.IsRelease = 0 AND PatientId = @patientId
	END
	/*END BILL PREVIEW DATE*/
/*END If Bill Preview Then @isRelease = 0 ELSE @isRelease = 1*/

END

GO
