CREATE PROC [dbo].[SP_PatientService]
@BranchId INT,
@RefDateFrom NVARCHAR(20),
@RefDateTo NVARCHAR(20)
AS
BEGIN
SELECT a.MainDeptName,COUNT(a.PatientId) AS TotalPatient
FROM
	(SELECT b.SubSubPno AS MainDeptName,a.PatientId,a.PatientName
    FROM PatientLedger a,BedInformation b
	WHERE a.BedNo=b.BedNo AND a.RefDate BETWEEN @RefDateFrom AND @RefDateTo AND a.BranchId=@BranchId
	GROUP BY b.SubSubPno,a.PatientId,a.PatientName) a
GROUP BY a.MainDeptName
END
GO
