CREATE PROC [dbo].[SP_PaymentDrHonorarium](@DateFrom nvarchar(20), @DateTo nvarchar(20), @DrCode nvarchar(20), @InvNo nvarchar(30), @InvDate date, @UserName nvarchar(200))
AS
if @DrCode = '' and @InvNo = '' and @InvDate = ''
	BEGIN
	INSERT INTO DrHonorariumPayment(DrCode, Payment, PayDate, Remarks, InvNo, InvDate, MaxDrCom, LessAmt, isTransferForSMS, Valid, UserName, EntryDateTime)
	select aa.DrCode, sum(aa.MaxDrCom-aa.Less) as Payment, GETDATE(), 'Automatic Payment' as Remarks, aa.InvNo, aa.InvDate, SUM(aa.MaxDrCom) as MaxDrCom,
	SUM(aa.Less) AS Less, 0 IsTransferForSMS, 1 as Valid, @UserName as UserName, GETDATE() as EntryDateTime from (
	select a.PrevInvNo as InvNo, a.PreInvDate as InvDate, b.RefDrCode AS DrCode, ISNULL((select sum(MaxDrCom) from InvDetails where InvNo = a.PrevInvNo 
	and InvDate = a.PreInvDate and isPaidDrComm = 0 ),0) as MaxDrCom , sum(a.LessByDr) as Less from SalesLedger a
	left join InvMaster b on a.PrevInvNo = b.InvNo and a.PreInvDate = b.InvDate
	where a.IsPaid  = 0 and a.Valid = 1 and a.PtStatus = 'OutDoor' and a.Department = 'DIAGNOSTIC' and a.PaidDate BETWEEN @DateFrom and @DateTo
	group by a.PrevInvNo, a.PreInvDate, b.RefDrCode
	having SUM(a.Sales-a.Collection-a.Less) = 0
	) aa
	group by aa.InvNo, aa.InvDate, aa.DrCode
	having sum(aa.MaxDrCom) <> 0

	END
else if @DrCode <> '' and @InvNo = '' and @InvDate = ''
	BEGIN
	INSERT INTO DrHonorariumPayment(DrCode, Payment, PayDate, Remarks, InvNo, InvDate, MaxDrCom, LessAmt, isTransferForSMS, Valid, UserName, EntryDateTime)
	select aa.DrCode, sum(aa.MaxDrCom-aa.Less) as Payment, GETDATE(), 'Automatic Payment' as Remarks, aa.InvNo, aa.InvDate, SUM(aa.MaxDrCom) as MaxDrCom,
	SUM(aa.Less) AS Less, 0 IsTransferForSMS, 1 as Valid, @UserName as UserName, GETDATE() as EntryDateTime from (
	select a.PrevInvNo as InvNo, a.PreInvDate as InvDate, b.RefDrCode AS DrCode, ISNULL((select sum(MaxDrCom) from InvDetails where InvNo = a.PrevInvNo 
	and InvDate = a.PreInvDate and isPaidDrComm = 0 ),0) as MaxDrCom , sum(a.LessByDr) as Less from SalesLedger a
	left join InvMaster b on a.PrevInvNo = b.InvNo and a.PreInvDate = b.InvDate
	where a.IsPaid  = 0 and a.Valid = 1 and a.PtStatus = 'OutDoor' and a.Department = 'DIAGNOSTIC' and a.PaidDate BETWEEN @DateFrom and @DateTo and b.RefDrCode = @DrCode
	group by a.PrevInvNo, a.PreInvDate, b.RefDrCode
	having SUM(a.Sales-a.Collection-a.Less) = 0
	) aa
	group by aa.InvNo, aa.InvDate, aa.DrCode
	having sum(aa.MaxDrCom) <> 0

	END
else
	BEGIN
	INSERT INTO DrHonorariumPayment(DrCode, Payment, PayDate, Remarks, InvNo, InvDate, MaxDrCom, LessAmt, isTransferForSMS, Valid, UserName, EntryDateTime)
	select aa.DrCode, sum(aa.MaxDrCom-aa.Less) as Payment, GETDATE(), 'Automatic Payment' as Remarks, aa.InvNo, aa.InvDate, SUM(aa.MaxDrCom) as MaxDrCom,
	SUM(aa.Less) AS Less, 0 IsTransferForSMS, 1 as Valid, @UserName as UserName, GETDATE() as EntryDateTime from (
	select a.PrevInvNo as InvNo, a.PreInvDate as InvDate, b.RefDrCode AS DrCode, ISNULL((select sum(MaxDrCom) from InvDetails where InvNo = a.PrevInvNo 
	and InvDate = a.PreInvDate and isPaidDrComm = 0 ),0) as MaxDrCom , sum(a.LessByDr) as Less from SalesLedger a
	left join InvMaster b on a.PrevInvNo = b.InvNo and a.PreInvDate = b.InvDate
	where a.IsPaid  = 0 and a.Valid = 1 and a.PtStatus = 'OutDoor' and a.Department = 'DIAGNOSTIC' and a.PaidDate BETWEEN @DateFrom and @DateTo and b.RefDrCode = @DrCode and a.PrevInvNo = @InvNo and a.PreInvDate = @InvDate
	group by a.PrevInvNo, a.PreInvDate, b.RefDrCode
	having SUM(a.Sales-a.Collection-a.Less) = 0
	) aa
	group by aa.InvNo, aa.InvDate, aa.DrCode
	having sum(aa.MaxDrCom) <> 0

	END
	




GO
