--03062025 Abu Bakkar
CREATE PROCEDURE [dbo].[SP_Phar_ProductLedgerSummarized] (@StoreId nvarchar(50), @DateFrom date , @DateTo date, @UnitId int, @BranchId int ,@ProductCategory nvarchar(50), @ProductCode nvarchar(20))
AS 
BEGIN  --- exec SP_Phar_ProductLedgerSummarized '','2025-05-01' , '2024-05-30' , 1 , 1, '',''
	if @StoreId <> '' 
		BEGIN
			SELECT aa.StoreId, dd.SubSubPno AS storeName , cc.Name AS ProductCategory,  aa.ProductCode , bb.ProductName , bb.ProductUnit as Unit , 
			SUM(aa.OB) AS OB , SUM(aa.OBAmt) AS OBAmt , SUM(aa.InQty) As InQty , SUM(aa.InAmt) AS InAmt , 
			SUM(aa.OutQty) AS OutQty , SUM(aa.OutAmt) OutAmt ,
			SUM(aa.CB) AS CB , SUM(aa.CBamt) AS CBAmt , 
			ROUND(isnull((Case when SUM(aa.CB) <> 0 then SUM(aa.CBamt) / SUM(aa.CB) end),0),2) As TP
			into #stock1
			FROM (
				select StoreId,ProductId AS ProductCode ,0 as OB, 0 as OBAmt,  (ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0)) as InQty,
				((ISNULL(InQty,0)*TP)+(ISNULL(RtnQty,0)*TP)+(ISNULL(BonusQty,0)*TP)) as InAmt  , 
				(ISNULL(OutQty,0)+ISNULL(RtnQty,0)) as OutQty ,
				((ISNULL(OutQty,0)*TP)+(ISNULL(RtnQty,0)*TP)) as OutAmt ,
				0 as CB , 0 as CBamt
				from PharStockLedger 
				where valid = 1 AND UnitId = @UnitId AND BranchId = @BranchId 
				AND TranDate BETWEEN @DateFrom AND @DateTo 
				AND StoreId = @StoreId
				UNION ALL
				select StoreId, ProductId ,((ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0))-(ISNULL(OutQty,0)+ISNULL(RtnQty,0))) as OB,
				(((ISNULL(InQty,0)*TP)+(ISNULL(RtnQty,0)*TP)+(ISNULL(BonusQty,0)*TP))-((ISNULL(OutQty,0)*TP)+
				(ISNULL(RtnQty,0)*TP))) as OBAmt,  
				0 as InQty,
				0 as InAmt  , 
				0 as OutQty ,
				0 as OutAmt ,
				0 as CB , 0 as CBamt
				from PharStockLedger 
				where valid = 1 AND UnitId = @UnitId AND BranchId = @BranchId
				AND TranDate < @DateFrom
				AND StoreId = @StoreId
				UNION ALL
				select StoreId,ProductId , 0 as OB, 
				0 as OBAmt,  
				0 as InQty,
				0 as InAmt  , 
				0 as OutQty ,
				0 as OutAmt ,
				((ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0))-(ISNULL(OutQty,0)+ISNULL(RtnQty,0))) as CB , 
				(((ISNULL(InQty,0)*TP)+(ISNULL(RtnQty,0)*TP)+(ISNULL(BonusQty,0)*TP))-
				((ISNULL(OutQty,0)*TP)+(ISNULL(RtnQty,0)*TP))) as CBamt
				from PharStockLedger 
				where valid = 1 AND UnitId = @UnitId AND BranchId = @BranchId
				AND TranDate <= @DateTo
				AND StoreId = @StoreId
			) aa , PharProductInfo bb,PharPdGroup cc,ProjectInformations dd
			WHERE aa.ProductCode = bb.Id
			AND bb.ProductGroup=cc.Id
			AND aa.StoreId=dd.PnoCode
			AND bb.ProductGroup LIKE '%'+@ProductCategory + '%' AND bb.Id LIKE '%'+@ProductCode+'%'
			GROUP BY aa.StoreId,dd.SubSubPno , cc.Name,  aa.ProductCode , bb.ProductName , bb.ProductUnit 
			--HAVING SUM(aa.CB) <> 0
			order by ProductCode

			delete from #stock1 where (InQty+OutQty+OB+CB) = 0
			select * from #stock1
		END
	ELSE
		BEGIN
			SELECT aa.StoreId,dd.SubSubPno AS storeName , cc.Name AS ProductCategory, aa.ProductCode, bb.ProductName, bb.ProductUnit , 
			SUM(aa.OB) AS OB, SUM(aa.OBAmt) AS OBAmt, SUM(aa.InQty) As InQty, SUM(aa.InAmt) AS InAmt , 
			SUM(aa.OutQty) AS OutQty , SUM(aa.OutAmt) OutAmt ,
			SUM(aa.CB) AS CB , SUM(aa.CBamt) AS CBAmt , 
			ROUND(isnull((Case when SUM(aa.CB) <> 0 then SUM(aa.CBamt) / SUM(aa.CB) end),0),2) As TP
			into #stock
			FROM (
				select StoreId,ProductId AS ProductCode ,0 as OB, 0 as OBAmt,  
				(ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0)) as InQty,
				((ISNULL(InQty,0)*TP)+(ISNULL(RtnQty,0)*TP)+(ISNULL(BonusQty,0)*TP)) as InAmt  , 
				(ISNULL(OutQty,0)+ISNULL(RtnQty,0)) as OutQty ,
				((ISNULL(OutQty,0)*TP)+(ISNULL(RtnQty,0)*TP)) as OutAmt ,
				0 as CB , 0 as CBamt
				from PharStockLedger 
				where valid = 1 AND UnitId = @UnitId AND BranchId = @BranchId 
				AND TranDate BETWEEN @DateFrom AND @DateTo 
				UNION ALL
				select StoreId,ProductId ,((ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0))-(ISNULL(OutQty,0)+ISNULL(RtnQty,0))) as OB, 			(((ISNULL(InQty,0)*TP)+(ISNULL(RtnQty,0)*TP)+(ISNULL(BonusQty,0)*TP))-((ISNULL(OutQty,0)*TP)+
				(ISNULL(RtnQty,0)*TP))) as OBAmt,  
				0 as InQty,
				0 as InAmt  , 
				0 as OutQty ,
				0 as OutAmt ,
				0 as CB , 0 as CBamt
				from PharStockLedger 
				where valid = 1 AND UnitId = @UnitId AND BranchId = @BranchId
				AND TranDate < @DateFrom
				UNION ALL
				select StoreId,ProductId , 0 as OB, 
				0 as OBAmt,  
				0 as InQty,
				0 as InAmt  , 
				0 as OutQty ,
				0 as OutAmt ,
				((ISNULL(InQty,0)+ISNULL(RtnQty,0)+ISNULL(BonusQty,0))-(ISNULL(OutQty,0)+ISNULL(RtnQty,0))) as CB , 
				(((ISNULL(InQty,0)*TP)+(ISNULL(RtnQty,0)*TP)+(ISNULL(BonusQty,0)*TP))-
				((ISNULL(OutQty,0)*TP)+(ISNULL(RtnQty,0)*TP))) as CBamt
				from PharStockLedger 
				where valid = 1 AND UnitId = @UnitId AND BranchId = @BranchId
				AND TranDate <= @DateTo
			) aa , PharProductInfo bb,PharPdGroup cc,ProjectInformations dd
			WHERE aa.ProductCode = bb.Id
			AND bb.ProductGroup=cc.Id
			AND aa.StoreId=dd.PnoCode
			AND bb.ProductGroup LIKE '%'+@ProductCategory + '%' 
			AND bb.Id LIKE '%'+@ProductCode+'%'
			GROUP BY aa.StoreId,dd.SubSubPno , cc.Name,  aa.ProductCode , bb.ProductName , bb.ProductUnit 
			--HAVING SUM(aa.CB) <> 0
			order by ProductCode

			delete from #stock where (InQty+OutQty+OB+CB) = 0
			select * from #stock
		END
	END
GO
/****** Object:  StoredProcedure [dbo].[SP_PHAR_SALES_COLL_SMZ_DateTimeWise]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
