GO

CREATE PROCEDURE [dbo].[SP_PHAR_SALES_COLL_SMZ_DateTimeWise] @branchId int, @unitId int,  @dateFrom nvarchar(25), @dateTo nvarchar(25), @ptStatus nvarchar(20), @storeId nvarchar(10)
AS ---  EXEC SP_PHAR_SALES_COLL_SMZ_DateTimeWise 1,1, '2024-06-01 00:00:00.000', '2024-06-30 11:59:59.000', '', ''
BEGIN
select a.TrDate, SUM(a.Sales) as TotalAmt, SUM(a.Collection) as AdvanceAmt, SUM(a.LessAmt) As LessAmt, SUM(a.Sales- a.LessAmt -a.Collection) as DueAmt, SUM(a.DueColl) as DueColl,
SUM(a.DueLess) as DueLess, SUM(a.CashReturn) as CashReturn, sum(a.CashAmt) as CashAmt, sum(a.CardAmt) as CardAmt, sum(a.ChequeAmt) as ChequeAmt, a.PtStatus, 
a.CostCenterName, a.BranchId, a.Valid, a.UnitId, a.StoreId, b.SubSubPno as StoreName
from PharSalesLedger a
INNER JOIN ProjectInformations b On a.StoreId=b.PnoCode
WHERE a.Valid=1 AND a.BranchId=@branchId AND a.UnitId=@unitId AND a.EntryDateTime BETWEEN @dateFrom AND @dateTo AND a.PtStatus LIKE '%'+@ptStatus+'%' AND a.StoreId LIKE '%'+@storeId+'%'
group by a.TrDate, a.PtStatus, a.CostCenterName, BranchId, a.Valid, a.UnitId, a.StoreId, b.SubSubPno
END
GO
/****** Object:  StoredProcedure [dbo].[SP_PHAR_SALES_RETURN_DETAILS]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROC [dbo].[SP_PHAR_SALES_RETURN_DETAILS] (@ptStatus nvarchar(50), @dateFrom date, @dateTo date, @branchId int, @unitId int, @patientId nvarchar(20), @regNo nvarchar(20), @invNo nvarchar(20), @storeId nvarchar(10))   
AS
BEGIN --- EXEC SP_PHAR_SALES_RETURN_DETAILS '', '2024-06-01', '2024-06-30', 1, 1, '', '','', '72'

if  @dateFrom = '' AND @dateTo =  ''	
	SELECT a.ReturnNo, a.ReturnDate, a.ProductName, a.ProductQty, a.SalePrice, a.TP, a.ItemLess, ((a.ProductQty * a.SalePrice)-b.LessAmt) as NetReturnAmt, b.PatientId, b.RegNo, b.BedNo, b.PatientName, b.PtStatus, b.TotalRtn AS TotalAmt, b.LessAmt, b.Remarks, b.UserName, a.ExpireDate, a.CompanyId, b.CostCenterName, 
        b.BranchId, b.EntryDateTime, b.StoreId, c.SubSubPno as StoreName
	FROM PharSalesReturnDetails a
	LEFT JOIN PharSalesReturnMaster b ON a.BranchId = b.BranchId AND a.ReturnNo = b.ReturnNo
	LEFT JOIN ProjectInformations c On b.StoreId=c.PnoCode
	WHERE a.valid=1 AND a.BranchId = @branchId AND  b.PtStatus LIKE '%'+@ptStatus+'%' AND b.PatientId LIKE '%'+@patientId+'%' AND b.RegNo LIKE '%'+@regNo+'%' AND b.ReturnNo LIKE '%'+@invNo+'%' AND b.StoreId LIKE '%'+@storeId+'%'
  
ELSE  
        SELECT a.ReturnNo, a.ReturnDate, a.ProductName, a.ProductQty, a.SalePrice, a.TP, a.ItemLess, ((a.ProductQty * a.SalePrice)-              b.LessAmt) as NetReturnAmt, b.PatientId, b.RegNo, b.BedNo, b.PatientName, b.PtStatus,
        b.TotalRtn AS TotalAmt, b.LessAmt, b.Remarks, b.UserName, a.ExpireDate, a.CompanyId, b.CostCenterName, b.BranchId,             b.EntryDateTime, b.StoreId, c.SubSubPno as StoreName
	FROM PharSalesReturnDetails a
	LEFT JOIN PharSalesReturnMaster b ON a.BranchId = b.BranchId AND a.ReturnNo = b.ReturnNo
	LEFT JOIN ProjectInformations c On b.StoreId=c.PnoCode
	WHERE a.valid=1 AND a.BranchId = @branchId AND b.PtStatus LIKE '%'+@ptStatus+'%' AND b.PatientId LIKE '%'+@patientId+'%' AND b.RegNo LIKE '%'+@regNo+'%' AND b.ReturnNo LIKE '%'+@invNo+'%' and a.ReturnDate BETWEEN @dateFrom AND @dateTo AND 
	b.StoreId LIKE '%'+@storeId+'%'
END
