CREATE PROC [dbo].[Sp_PharCollReportTypewiseSummary] @DateFrom DATE, @DateTo DATE, @BranchId INT, @UserName VARCHAR(150)
AS
BEGIN ---     Sp_PharCollReportTypewiseSummary '2024-11-02', '2024-11-02', 1, ''
	WITH zz AS(
		SELECT a.UserName, SUM(a.Collection) AS Collection, SUM(CashReturn) AS CashReturn, SUM(a.Collection-a.CashReturn) AS NetAmt, 
		SUM(a.Cash-a.CashReturn) AS Cash, SUM(a.Card) AS Card, a.CardBank, SUM(a.Cheque) AS Cheque, a.ChequeBank
		FROM 
		(
		
			/*Start Indoor Ledger*/
			SELECT 'Pharmacy' AS Dept, a.UserName, a.Collection+a.DueColl AS Collection, a.CashReturn,
			a.CashAmt AS Cash, a.CardAmt AS Card, CASE WHEN a.CardAmt >  0 THEN a.CardBank ELSE '' END AS CardBank,
			a.ChequeAmt AS Cheque, CASE WHEN a.ChequeAmt > 0 THEN a.ChequeBank ELSE '' END AS ChequeBank
			FROM PharSalesLedger a
			WHERE a.BranchId=@BranchId AND a.Valid=1 AND a.TrDate BETWEEN @DateFrom AND @DateTo
			AND CASE WHEN @UserName = '' THEN '' ELSE a.UserName END = @UserName
			/*End Indoor Ledger*/
		) a
		group by a.UserName, a.CardBank, a.ChequeBank
	)
	SELECT * 
	INTO #z
	--  drop table #z
	FROM zz a
	WHERE a.Collection > 1

	UPDATE #z SET CardBank='POS' WHERE Card>0 AND CardBank NOT IN ('Bkash', 'Nagad')

	SELECT a.UserName, SUM(a.Collection) AS Collection, SUM(a.CashReturn) AS CashReturn, SUM(NetAmt) AS NetAmt, 
	SUM(a.Cash) AS Cash, SUM(a.Bkash) AS Bkash, SUM(a.Nagad) AS Nagad, SUM(a.POS) AS POS FROM (
		SELECT a.UserName, a.Collection, a.CashReturn, a.NetAmt, a.Cash, 0 AS Bkash, 0 AS Nagad, 0 AS POS
		FROM #z a
		UNION ALL
		SELECT a.UserName, 0 as Collection, 0 AS CashReturn, 0 AS NetAmt, 0 AS Cash, a.Card AS Bkash, 0 AS Nagad, 0 AS POS
		FROM #z a
		WHERE a.CardBank='BKash'
		UNION ALL
		SELECT a.UserName, 0 as Collection, 0 AS CashReturn, 0 AS NetAmt, 0 AS Cash, 0 AS Bkash, a.Card AS Nagad, 0 AS POS
		FROM #z a
		WHERE a.CardBank='Nagad'
		UNION ALL
		SELECT a.UserName, 0 as Collection, 0 AS CashReturn, 0 AS NetAmt, 0 AS Cash, 0 AS Bkash, 0 AS Nagad, a.Card AS POS
		FROM #z a
		WHERE a.CardBank='POS'
	) a
	GROUP BY a.UserName
	END
GO
