CREATE PROC [dbo].[SP_PharDueCollectionIndoor](@TrNo nvarchar(50), @TrDate date, @branchId int)
AS
BEGIN -- EXEC SP_PharDueCollectionIndoor 'DC240300048','2024-03-07', 1

DECLARE @PatientId VARCHAR(50);
DECLARE @EntryTime DATETIME;
SELECT @PatientId = PatientId FROM PharSalesLedger WHERE BranchId=@branchId  AND  Valid = 1 AND TrNo = @TrNo;
SELECT @EntryTime = MIN(EntryDateTime) FROM PharSalesLedger WHERE BranchId=@branchId AND Valid = 1 AND TrNo = @TrNo;

WITH z AS
(
	SELECT BranchId, InvNo, SUM(Sales) AS Sales, SUM(LessAmt+DueLess) AS Less, SUM(Collection+DueColl) AS Collection,
	SUM(Sales-LessAmt-Collection-DueLess-DueColl-ReturnAmt) AS Due 
	FROM PharSalesLedger WHERE Valid = 1 AND BranchId=@branchId AND PatientId = @PatientId AND EntryDateTime < @EntryTime
	GROUP BY BranchId, InvNo
),
due AS
(
	SELECT BranchId, InvNo, SUM(Sales-LessAmt-Collection-DueLess-DueColl-ReturnAmt) AS Due 
	FROM PharSalesLedger a
	 WHERE Valid = 1 AND BranchId=@branchId AND PatientId = @PatientId
	GROUP BY BranchId, InvNo
)
select a.InvNo, a.InvDate, a.TrNo, a.EntryDateTime AS TrDate, a.PatientId, a.RegNo, a.BedNo, a.PatientName,
b.Sales, b.Less, b.Collection AS PrevColl, a.DueColl as Collection,
a.DueLess as Less, a.CashAmt, a.CardAmt, a.ChequeAmt, a.CardNo, a.CardBank, a.ChequeNo, a.ChequeBank, a.ChequeDate,
a.UserName, ISNULL((SELECT top 1 Remarks from PharDueCollection where TrNo = a.TrNo),'') AS Remarks,
c.Due as Due, d.DueAmt as totalDue, d.LessAmt as totalLess,  D.Collection as totalCollection, (d.DueAmt - d.LessAmt - d.Collection) as restDue
from PharSalesLedger a
LEFT JOIN z b on a.BranchId = b.BranchId AND a.InvNo = b.InvNo
LEFT JOIN due c on c.BranchId = a.BranchId and c.InvNo = a.InvNo
LEFT JOIN PharDueCollectionMaster d on a.BranchId=d.BranchId AND a.PatientId = d.PatientId AND a.TrNo=d.TrNo
where a.BranchId = @branchId AND a.TrNo = @TrNo AND a.TrDate = @TrDate ANd a.Valid = 1
end
GO
