CREATE Procedure [dbo].[SP_PharDueCollectionSMZ] @BranchId int, @UnitId int, @DateFrom date, @DateTo date, @PtStatus nvarchar(20), @storeId nvarchar(10), @staffRegNo varchar(20)
AS -- EXEC SP_PharDueCollectionSMZ 1, 1, '2024-06-01', '2024-06-30', '', '166'
BEGIN
	SELECT  a.PtStatus, a.InvDate, sum(a.Collection) as DueCollection, Sum(a.Less) as Less, sum(a.CashAmt) as Cash, sum(a.CardAmt) as CardAmt, 
	sum(a.ChequeAmt) as ChequeAmt, sum(a.MediLess) as MediLess, sum(a.SurgLess) as SurgLess, sum(a.InhLess) as InhLess,
	sum(DeptLess) as DeptLess, a.StoreId, b.SubSubPno as StoreName
	FROM PharDueCollection a
	INNER JOIN ProjectInformations b On a.StoreId=b.PnoCode
	WHERE a.Valid=1  AND a.BranchId =@BranchId AND a.UnitId= @UnitId AND a.TrDate BETWEEN @DateFrom AND @DateTo AND  a.PtStatus LIKE '%'+@PtStatus+'%' 
	AND a.RegNo LIKE '%'+@staffRegNo+'%'
	AND a.StoreId LIKE '%'+@storeId+'%'
	GROUP BY a.PtStatus, a.InvDate, a.StoreId, b.SubSubPno
END
GO
