CREATE PROC [dbo].[SP_PharDueList] (@branchId int, @dateFrom date, @dateTo date, @ptStatus nvarchar(20), @storeId nvarchar(10), @staffRegNo varchar(20))
AS ----- SP_PharDueList  1, '2024-08-01','2024-08-01', '', '', ''
BEGIN -- SP_PharDueList  1, '2024-11-14','2024-11-14', 'Staff', '', 'PR231200405' 

		
	select a.PtStatus, ''AS InvNo, d.AdmissionDate AS InvDate, a.RegNo, a.PatientId, 
	d.PatientName, d.BedNo, 
	SUM(a.Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt-a.AdjustAmt) as Due , 
	0 AS StoreId, '' as StoreName, a.BranchId, a.UnitId
	from PharSalesLedger a
	INNER JOIN PatientAdmission d on a.PatientId=d.PatientId 
	where a.Valid=1 AND a.BranchId = @branchId AND a.InvDate <= @dateTo 
	AND a.PtStatus LIKE '%'+@ptStatus+'%'
	AND d.IsRelease=0
	AND a.RegNo LIKE '%'+@staffRegNo+'%'
	AND a.PtStatus='Indoor'
	group by a.PtStatus, a.RegNo,a.PatientId, d.PatientName, a.BranchId, a.UnitId, d.BedNo, a.PtStatus,d.AdmissionDate
	having SUM(a.Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt-a.AdjustAmt) >3

	UNION 
	select a.PtStatus, a.InvNo, a.InvDate, a.RegNo, a.PatientId, a.PatientName, '', 
	SUM(a.Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt-a.AdjustAmt) as Due , 
	0 AS StoreId, '' as StoreName, a.BranchId, a.UnitId
	from PharSalesLedger a
	where a.Valid=1 AND a.BranchId = @branchId AND a.InvDate <= @dateTo AND a.PtStatus LIKE '%'+@ptStatus+'%'
	AND a.RegNo LIKE '%'+@staffRegNo+'%'
	AND a.PtStatus<>'Indoor'
	group by a.PtStatus, a.RegNo,a.PatientId, a.PatientName, a.BranchId, a.UnitId,
	a.InvNo , a.InvDate
	having SUM(a.Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt-a.AdjustAmt) >3



END
GO
