--23062025
create PROC [dbo].[SP_PharDueListByDateRange] (@branchId int, @dateFrom date, @dateTo date, @ptStatus nvarchar(20), @storeId nvarchar(10), @staffRegNo varchar(20))
AS ----- SP_PharDueListByDateRange  1, '2025-05-01','2025-06-01', '', '', ''
BEGIN -- SP_PharDueListByDateRange  1, '2025-11-14','2025-11-24', 'Staff', '', '' 		
	select a.PtStatus, CASE WHEN a.PtStatus = 'Indoor' THEN '' ELSE a.InvNo END AS InvNo, 
	CASE WHEN a.PtStatus = 'Indoor' THEN NULL ELSE a.InvDate END AS InvDate, a.RegNo, a.PatientId, 
	CASE WHEN a.PtStatus = 'Indoor' THEN d.PatientName ELSE a.PatientName END AS PatientName, d.BedNo, 
	SUM(a.Sales-a.Collection-a.DueColl-a.DueLess-a.ReturnAmt-a.LessAmt) as Due , 
	a.StoreId AS StoreId, '' as StoreName, a.BranchId, a.UnitId
	from PharSalesLedger a
	LEFT JOIN PatientAdmission d on a.PatientId=d.PatientId
	where a.Valid=1 AND a.BranchId = @branchId AND a.InvDate between @dateFrom and @dateTo 
	AND a.PtStatus LIKE '%'+@ptStatus+'%'
	AND a.RegNo LIKE '%'+@staffRegNo+'%'
	--and a.PatientId = 'PA240700457'
	group by a.PtStatus, a.RegNo,a.PatientId, d.PatientName, a.BranchId, a.UnitId, d.BedNo, a.StoreId, 
	CASE WHEN a.PtStatus = 'Indoor' THEN '' ELSE a.InvNo END, 
	CASE WHEN a.PtStatus = 'Indoor' THEN NULL ELSE a.InvDate END, CASE WHEN a.PtStatus = 'Indoor' THEN d.PatientName ELSE a.PatientName END
	having SUM(a.Sales-a.Collection-a.DueColl-a.DueLess-a.ReturnAmt-a.LessAmt)>2
END
GO
