CREATE Procedure [dbo].[SP_PharDueListSMZ] @BranchId int, @UnitId int, @DateFrom date, @DateTo date, @ptStatus nvarchar(20), @storeId nvarchar(10), @staffRegNo varchar(20)
AS --- exec SP_PharDueListSMZ 1, 1, '2024-08-01','2024-08-01', '', '', ''
BEGIN
	select a.PtStatus, a.InvDate,
	SUM(a.Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt-a.AdjustAmt) as Due, a.StoreId, b.SubSubPno as StoreName
	from PharSalesLedger a
	LEFT JOIN ProjectInformations b On a.StoreId=b.PnoCode
	where a.Valid=1 AND a.BranchId = @BranchId AND a.UnitId=@UnitId 
	AND a.InvDate BETWEEN @DateFrom AND @DateTo AND a.PtStatus LIKE '%'+@ptStatus+'%'
	AND a.RegNo LIKE '%'+@staffRegNo+'%' AND a.StoreId LIKE '%'+@storeId+'%'
	group by PtStatus, InvDate, a.StoreId, b.SubSubPno
	having SUM(a.Sales-a.LessAmt-a.Collection-a.DueLess-a.DueColl-a.ReturnAmt-a.AdjustAmt)>1
	ORDER BY InvDate, PtStatus
END
GO
