	SELECT SUM(Sales) AS Sales, SUM(Collection+DueColl) AS Collection, SUM(LessAmt+DueLess) AS LessAmt, SUM(CashReturn) AS ReturnAmt, 
	SUM(Sales-LessAmt-Collection-DueLess-DueColl-ReturnAmt) AS DueAmt, PatientId, BranchId 
	INTO #z
	FROM PharSalesLedger 
	WHERE Valid = 1 AND BranchId = @BranchId AND (InvNo+PatientId) LIKE '%'+@PatientId+'%'
	GROUP BY PatientId, BranchId 
	HAVING SUM(Sales-Collection-DueColl-DueLess-ReturnAmt-LessAmt) != 0

	SELECT a.ProductId, b.ProductName, SUM(a.OutQty-a.RtnQty) AS ProductQty, a.Price AS SalePrice, a.TP, ISNULL(b.PharDeptId, 0) AS PharDeptId, a.BedNo, 
	SUM(a.ItemLess-a.LessAdjust) AS ItemLess, c.Sales, c.Collection, c.LessAmt, 0 AS ReturnAmt, c.DueAmt
	FROM PharStockLedger a
	LEFT JOIN PharProductInfo b ON a.ProductId = b.Id
	LEFT JOIN #z c ON a.PatientId = c.PatientId AND a.BranchId = c.BranchId
	WHERE a.BranchId = @BranchId AND a.Valid = 1 AND (InvNo+a.PatientId) LIKE '%'+@PatientId+'%'
	GROUP BY a.ProductId, b.ProductName, a.Price, a.TP, b.PharDeptId, a.BedNo, c.Sales, c.Collection, c.LessAmt, c.ReturnAmt, c.DueAmt
