--		WHERE Valid= 1 AND BranchId = @BranchId AND PatientId = @PatientId AND ProductId NOT IN (
--			SELECT ProductId 
--			FROM PharDueCollectionDtls 
--			WHERE Valid = 1 AND BranchId = @BranchId AND PatientId = @PatientId) 
--			UNION ALL 
--			SELECT ISNULL(ProductId, '') AS ProductId, SUM(0-ISNULL(ProductQty, 0)) AS ProductQty 
--			FROM PharSalesReturnDetails 
--			WHERE Valid= 1 AND BranchId = @BranchId AND PatientId = @PatientId 
