CREATE PROC [dbo].[Sp_PharIndoorPaymentList] @BranchId INT, @FromDate DATE, @ToDate DATE
AS
BEGIN /* EXEC Sp_PharIndoorPaymentList 1, '2023-06-12', '2023-12-12' */
	select a.PatientId, a.AdmissionDate, a.BedNo, a.PatientName, a.ReceiptNo, a.PaymentDate, 0 as Sales, 0 AS Less, 0 AS NetSales,
	a.ReceiveAmt AS AdvanceAmt, 0 AS Payment, 0 AS DueColl, a.CashAmt, a.CardAmt, a.ChequeAmt, 
	a.UserName, a.EntryDateTime
	from PharAdavnceCollection a
	Where a.BranchId = @BranchId AND a.Valid = 1 and PaymentDate between @FromDate and @ToDate
	UNION ALL
	select a.PatientId, b.AdmissionDate, b.BedNo, b.PatientName, a.RefNo, a.RefDate, a.TotalSales, 0 AS Less, a.TotalSales AS NetSales,
	0 AS AdvanceAmt, a.ReceiveAmt AS Payment, 0 AS DueColl, a.CashAmt as CashAmt, a.CardAmt as CardAmt, a.ChequeAmt as ChequeAmt, 
	a.UserName, a.CreatedAt
	from PharPtnReleaseMaster a
	left join PatientAdmission b on b.BranchId = a.BranchId and b.PatientId = a.PatientId
	WHERE a.BranchId = @BranchId and a.Valid = 1 AND a.RefDate between @FromDate and @ToDate
	UNION ALL
	select a.PatientId, b.AdmissionDate, b.BedNo, a.PatientName, a.TrNo AS InvNo, a.TrDate, 0 AS Sales, Less, 0 as NetSales,
	0 AS ReceiveAmt, 0 as Payment, Collection AS DueColl, a.CashAmt, a.CardAmt, a.ChequeAmt, 
	a.UserName, a.EntryTime
	from PharDueCollection a
	left join PatientAdmission b on b.BranchId = a.BranchId and b.PatientId = a.PatientId
	where a.BranchId = @BranchId and a.Valid = 1 AND a.TrDate between @FromDate and @ToDate and a.PtStatus = 'Indoor'
	order by a.PatientId
END
GO
