CREATE PROCEDURE [dbo].[SP_Pharma_Balance_Item_Wise](@DateFrom date, @DateTo date, @BranchId int, @UnitId int, @ProductId int)
AS
BEGIN
select 2 AS SlNo, 'Product Receive' AS Description, a.TrNo, a.TrDate, a.ProductId, a.ProductName, a.InQty AS Qty 
from PharmaCurrentStock a
WHERE a.TrDate BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId AND a.UnitId = @UnitId AND ProductId = @ProductId AND a.InQty > 0
UNION ALL
SELECT 3 AS SlNo, 'Product Out' AS Description, a.TrNo, a.TrDate, a.ProductId, a.ProductName, (ISNULL(OutQty,0)) as Qty
from PharmaCurrentStock a 
WHERE TrDate BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId AND a.UnitId = @UnitId AND ProductId = @ProductId AND a.OutQty > 0
UNION ALL
SELECT 1 AS SlNo, 'Product Opening Balance' AS Description, '' AS TrNo, '' AS TrDate, a.ProductId, a.ProductName, SUM(ISNULL(InQty,0)-ISNULL(OutQty,0)) as Qty
from PharmaCurrentStock a 
WHERE TrDate < @DateFrom AND a.BranchId = @BranchId AND a.UnitId = @UnitId AND ProductId = @ProductId
GROUP BY a.ProductId, a.ProductName
UNION ALL
SELECT 4 AS SlNo, 'Product Closing Balance' AS Description, '' AS TrNo, '' AS TrDate, a.ProductId, a.ProductName, SUM(ISNULL(InQty,0)-ISNULL(OutQty,0)) as Qty
from PharmaCurrentStock a 
WHERE TrDate <= @DateTo AND a.BranchId = @BranchId AND a.UnitId = @UnitId AND ProductId = @ProductId
GROUP BY a.ProductId, a.ProductName
ORDER BY SlNo
END
-------------
GO
