CREATE procedure [dbo].[SP_PharmacyProduct_LedgerDetails] (@BranchId int, @UnitId nvarchar(5), @DateFrom date , @DateTo date, @productName nvarchar(50),@StoreId integer)
AS
BEGIN --- EXEC SP_PharmacyProduct_LedgerDetails 1, '1' ,'2023-01-01','2023-12-31','Napa 500' ,72
SELECT aa.StoreId, cc.SubSubPno as StoreName , bb.CompanyId, bb.CompanyName, aa.ProductId, bb.ProductName , bb.ProductNameFull , bb.UnitType,  aa.TranDate, aa.RefNo, aa.InvNo , aa.InvDate ,aa.TP as Price , aa.PostedBy,aa.reqFrom, aa.OPBal, aa.InQty , aa.RtnQty , aa.OutQty 
FROM (
	select StoreId, ProductId, TranDate, RefNo, InvNo , InvDate ,TP, UserName AS PostedBy,inputfrom as reqFrom,0 as OPBal,InQty ,RtnQty, OutQty 
	from PharStockLedger 
	where valid  = 1 AND BranchId =@BranchId AND UnitId = @UnitId and StoreId like @StoreId
	AND TranDate between @DateFrom and @DateTo AND ProductName LIKE '%'+@productName+'%' 
	UNION ALL
	select Storeid,ProductId, null As TranDate,'' as TrNo, '' as InvoiceNo , null as InvoiceDate ,0 as PPrice, '' AS PostedBy,'Opening Stock' as reqFrom, SUM(InQty + RtnQty-    OutQty ) AS OB , 0 as InQty , 0 as RtnQty, 0 as OutQty 
	from PharStockLedger 
	where valid  = 1 AND BranchId = @BranchId  
	and StoreId like @StoreId
	AND UnitId = @UnitId AND TranDate < @DateFrom AND ProductName LIKE '%'+@productName+'%'	
	GROUP BY ProductId, StoreId) aa , PharProductInfo bb , ProjectInformations cc
	where aa.ProductId = bb.Id and aa.StoreId = cc.PnoCode 
	ORDER BY  ProductName , TranDate , RefNo 
END
GO
