AS 
BEGIN --EXEC SP_PharmaPurchaseLedgerSMZ '','2023-08-10','2023-08-31',1,72
SELECT aa.CompanyID , bb.Name , bb.Address, SUM(aa.OB) AS OB,SUM(aa.PurchaseAmt) as PurchaseAmt , SUM(aa.Less) AS Less , 
SUM(aa.ReturnAmt) As ReturnAmt, SUM(aa.PurchaseAmt - aa.Less - aa.ReturnAmt) as NetSales , SUM(aa.PaymentAmt) AS PaymentAmt  , 
SUM(aa.PurchaseAmt - aa.Less - aa.ReturnAmt-aa.PaymentAmt) as CB
FROM (
select CompanyID,Refdate,RefNo ,Particulars, 0 as  OB, purchaseAmt,PaymentAmt,Less,ReturnAmt 
from pharmapurchaseledger a
where valid = 1
AND a.RefDate BETWEEN @dateFrom AND @dateTo AND a.BranchId  = @BranchId AND a.CompanyID LIKE '%'+@companyId +'%' AND StoreId = @storeId
UNION ALL
select CompanyID,DateAdd(day,-1,@dateFrom) as Refdate,'-' as RefNo ,'Opening Balance' AS Particulars, 
(purchaseAmt-PaymentAmt-Less-ReturnAmt) AS OB,  
0 as purchaseAmt, 0 as PaymentAmt, 0 as Less,0 as ReturnAmt  
from pharmapurchaseledger a
where valid = 1
AND a.RefDate < @dateFrom  AND a.BranchId  = @BranchId AND a.CompanyID LIKE '%'+@companyId +'%' AND StoreId = @storeId
) aa , pharCompanyInfo bb
where aa.CompanyID = bb.Company_Id 
