--27102024

CREATE PROCEDURE [dbo].[Sp_PharPdWiseCurrStock] @branchId INT, @companyId VARCHaR(60), @storeId INT, @groupId InT, @UnitId INT, @upToDate DATE
AS
BEGIN --   Sp_PharPdWiseCurrStock 1, '', 166, 0, 0, '2024-01-01'
	SELECT a.CompanyId, a.CompanyName, a.Id, a.ProductName, a.ProductUnit, d.Name AS ProductGroup, a.WholeSalePrice, 
	SUM(b.InQty-b.OutQty) as CurrentStock, a.TP AS TP, a.SalePrice, b.UnitId, b.StoreId, b.BranchId, c.Pno AS StoreName
	FROM PharProductInfo a
	INNER JOIN PharmaCurrentStock b ON a.Id=b.ProductId
	LEFT JOIN ProjectInformations c on b.StoreId=c.PnoCode
	INNER JOIN PharPdGroup d ON a.ProductGroup=d.Id
	WHERE b.BranchId=@branchId AND b.TrDate<=@upToDate AND b.StoreId!=0
	AND (CASE WHEN 1=0 THEN StoreId ELSE 1 END) = 1
	AND (CASE WHEN @companyId='' THEN 0 ELSE a.CompanyId END) = @companyId
	AND (CASE WHEN @storeId=0 THEN 0 ELSE b.StoreId END) = @storeId
	AND (CASE WHEN @groupId=0 THEN 0 ELSE a.ProductGroup END) = @groupId
	GROUP BY a.CompanyId, a.CompanyName, a.Id, a.ProductName, a.ProductUnit, d.Name, a.WholeSalePrice, a.TP, a.SalePrice, b.UnitId, b.StoreId, b.BranchId, c.Pno
	ORDER BY 1, 3
END
GO
