--28012026
Create Procedure [dbo].[Sp_PharProductListForPurchaseRequisition] @StoredId Int, @CompanyCode varchar(50), @BranchId Int
AS
Begin
	SELECT ROW_NUMBER() Over(Order BY a.Id) as SLNo,  a.CompanyId, a.CompanyName, a.Id AS ProductId, a.ProductName,
	ISNULL(a.OpenQty,0) as OpenQty , ISNULL(SUM(b.InQty),0) AS InQty, ISNULL(SUM(b.OutQty),0) as SoldQty,
	sum(ISNULL(b.InQty,0) - ISNULL(b.OutQty,0)) AS CurrQty, a.ReminderStock, ISNULL(a.TP,0) as TP, 
	ISNULL(MAX(TrDate),'') AS LastPurchaseDate, 
	(
		SELECT ISNULL (sum(InQty),0) 
		FROM PharmaCurrentStock 
		WHERE ProductId = a.Id AND StoreId=@StoredId  And BranchId=@BranchId
		AND TrDate BETWEEN DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE ())-1, 0) AND DATEADD(MONTH, DATEDIFF(MONTH, -1, GETDATE())-1, -1)
	) as LastPurQty
	FROM PharProductInfo a
	LEFT JOIN PharmaCurrentStock b ON a.Id = b.ProductId AND b.BranchId=@BranchId AND b.StoreId=@StoredId
	WHERE a.Valid=1 AND a.IsActive=1  AND a.CompanyId=@CompanyCode
	GROUP BY a.CompanyId, a.CompanyName, a.Id, a.ProductName, a.OpenQty, a.TP, a.ReminderStock
	ORDER BY a.Id
End
GO
