CREATE Procedure [dbo].[SP_PharProductSlowSell_SMZ] @BranchId int, @FromDate Date, @ToDate date, 
@CompanyId nvarchar(20), @StoreId nvarchar(10), @ProductGroup nvarchar(50)
AS
BEGIN /* EXEC SP_PharProductSlowSell_SMZ 1, '2024-01-01', '2024-06-26', '', 72, '' */
select c.Company_Id,c.Name, a.ProductId, b.ProductName,b.Tp, b.SalePrice, MAX(a.ExpireDate) as ExpDate,  (SELECT SUM(InQty-OutQty) FROM PharmaCurrentStock WHERE ProductId = a.ProductId) AS CurrQty, SUM(OutQty) as SlowSales, a.StoreId, d.SubSubPno as StoreName
from PharmaCurrentStock a
LEFT JOIN PharProductInfo b ON a.ProductId = b.Id
LEFT JOIN PharCompanyInfo c ON b.CompanyId = c.Company_Id
LEFT JOIN ProjectInformations d On a.StoreId=d.PnoCode
WHERE  b.Id IS NOT NULL AND a.BranchId = 1 AND  a.TrDate between @FromDate AND @ToDate AND c.Company_Id LIKE '%'+ @CompanyId+'%' 
AND a.StoreId LIKE '%'+@StoreId+'%' AND b.ProductGroup LIKE '%'+@ProductGroup+'%'
GROUP BY a.ProductId, b.ProductName, c.Company_Id, c.Name, b.Tp, b.SalePrice, a.StoreId, d.SubSubPno
Having SUM(OutQty)= 0
order by sum(OutQty),c.Company_Id, a.ProductId ASC
END
GO
