CREATE PROC [dbo].[Sp_PharPtnRelease] @PatientId VARCHAR(20), @BranchId INT
AS
BEGIN /* EXEC Sp_PharPtnRelease 'PA241000009', 1 */
	WITH sales AS
	(
		SeleCT a.BranchId, a.ProductId, a.ProductName, a.SalePrice, SUM(a.ProductQty) AS Issue, CASE when SUM(ItemLess) > 0 then sum(a.ItemLess/ProductQty) ELSE 0 End AS ItemLess
		FRoM PharSalesDetails a
		WHERE a.BranchId = @BranchId And a.Valid = 1 AnD a.PatientId = @PatientId
		GROUP BY a.BranchId, a.ProductId, a.ProductName, a.SalePrice
	),
	rtn AS
	(
		SeLeCt a.BranchId, a.ProductId, SUM(a.ProductQty) AS Rtn, CASE when sum(ItemLess) > 0 then sum(ItemLess/a.ProductQty) else 0 end LessAdjust
		FRoM PharSalesReturnDetails a 
		WHERE a.BranchId = @BranchId And a.Valid = 1 AnD a.PatientId = @PatientId
		group by a.BranchId, a.ProductId
	),
	salescoll  as
	(
		select BranchId, sum(Sales) AS Sales, sum(LessAmt+DueLess-LessAdjust) as Less, SUM(Collection) AS Collection, sum(DueColl) AS DueColl, sum(ReturnAmt+LessAdjust+CashReturn) AS ReturnTotal, sum(sales-LessAmt-Collection-DueLess-DueColl-ReturnAmt-LessAdjust) AS Due
		from PharSalesLedger
		where BranchId = @BranchId And Valid = 1 AnD PatientId = @PatientId
		group by BranchId
	)
	SELECT DISTINCT b.RegNo, b.PatientId, b.AdmissionDate, b.AdmissionTime, b.PatientName, b.PatientSex, b.PatientAge, b.PatientAddress, b.DrCode, b.DrName, 
	b.UnderDrCode, b.UnderDrName, b.BedNo, g.CabinNo, g.FloorNo, b.PatientTel, c.ProductId, c.ProductName, 'Pcs' AS Unit, c.SalePrice, c.Issue, c.ItemLess, 
	ISNULL(d.Rtn, 0) AS Rtn, ISNULL(d.LessAdjust, 0) AS LessAdjust, e.Sales, e.Less, e.Collection, e.DueColl, e.ReturnTotal, e.Due
	FROM PharSalesMaster a 
	left join PatientAdmission b on b.BranchId = a.BranchId and b.PatientId = a.PatientId
	Left join sales c on c.BranchId = a.BranchId --and c.ProductId = b.ProductId
	Left join rtn d on d.BranchId = a.BranchId and d.ProductId = c.ProductId
	left join salescoll e on e.BranchId = a.BranchId
	left join PharSalesDetails f on f.BranchId = a.BranchId ANd f.SaleNo = a.SaleNo AND f.ProductId = c.ProductId
	LEFT joiN BedInformation g on a.BranchId = g.BranchId And b.BedNo = g.BedNo
	WHERE a.BranchId = @BranchId And a.Valid = 1 AnD a.PatientId = @PatientId
	order by ProductId
END
GO
