CREATE PROC [dbo].[Sp_PharPtnReleaseBill] @Id INT, @BranchId INT
AS
BEGIN /* EXEC Sp_PharPtnReleaseBill 44, 1 */
	
	DECLARE @PatientId VARCHAR(20), @EntryDate DATETIME;
	SELECT @PatientId = PatientId, @EntryDate = CreatedAt FROM PharPtnReleaseMaster WHERE Id = @Id;

	WITH salescoll as
	(
		select BranchId, sum(Sales) AS Sales, sum(LessAmt+DueLess) as Less, SUM(Collection+DueColl) AS Collection, sum(ReturnAmt+LessAdjust+CashReturn) AS ReturnTotal, 
		sum(sales-LessAmt-Collection-DueLess-DueColl-ReturnAmt) AS Due
		from PharSalesLedger
		where BranchId = @BranchId And Valid = 1 AnD PatientId = @PatientId AND EntryDateTime < @EntryDate
		group by BranchId
	)
	SELECT a.RefNo, a.RefDate, a.ReceiveAmt, a.CashAmt, a.CardAmt, a.ChequeAmt, a.CardNo, d.Name AS CardBank, a.ChequeNo, a.ChequeDate, e.name AS ChequeBank, a.RegNo, 
	a.UserName, a.CreatedAt, a.Remarks, c.PatientId, c.AdmissionDate, c.AdmissionTime, c.PatientName, c.PatientSex, c.PatientAge, c.PatientAddress, c.DrCode, c.DrName, 
	c.UnderDrCode, c.UnderDrName, c.BedNo, c.PatientTel, g.CabinNo, g.FloorNo, b.ProductId, b.SalePrice, b.Issue, b.IssueLess AS ItemLess, b.[Return] AS Rtn, 
	b.ReturnLess AS LessAdjust, h.ProductName, h.UnitType AS Unit, f.Sales, /*f.Less*/ a.TotalLess AS Less, f.Collection, f.ReturnTotal, 
	ISNULL((SELECT sum(Sales-LessAmt-Collection-DueLess-DueColl-ReturnAmt) FROM PharSalesLedger WHERE BranchId=a.BranchId AND valid=1 and PatientId=a.PatientId), 0) AS Due
	FROM PharPtnReleaseMaster a
	LEFT JOIN PharPtnReleaseDtls b ON b.MasterId = a.Id
	LEFT JOIN PatientAdmission c ON c.BranchId = a.BranchId AND c.PatientId = a.PatientId
	left join BankInfo d on d.Id = a.CardBankId
	left join BankInfo e on e.Id = a.ChequeBankId
	LeFT JOIN salescoll f ON f.BranchId = a.BranchId
	LEFT joiN BedInformation g on g.BranchId = a.BranchId And g.BedNo = c.BedNo
	Left Join PharProductInfo h ON h.Id = b.ProductId
	WHERE a.BranchId = @BranchId And a.Valid = 1 AnD a.Id = @Id
	order by b.ProductId
END
GO
