CREATE Proc [dbo].[sp_PharPurchaseInvoiceRegister]
@BranchId INT,
@DateFrom DATETIME,
@DateTo DATETIME,
@CompanyId NVARCHAR(20)
AS -- EXEC sp_PharPurchaseInvoiceRegister 1,'2024-01-01','2025-02-11','A001'
BEGIN
	SELECT a.CompanyID,b.Name AS CompanyName,a.PINo AS InvoiceNo,a.PIDate AS InvoiceDate,
	SUM(a.PurchaseAmt) AS PurchaseAmt,SUM(a.PaymentAmt) AS PaymentAmt,SUM(a.Less) AS Less,
	SUM(a.ReturnAmt) AS ReturnAmt
	FROM PharmaPurchaseLedger a,PharCompanyInfo b
	WHERE a.Valid=1 and b.Valid=1
	AND a.CompanyID=b.Company_Id
	AND BranchId=@BranchId AND PIDate BETWEEN @DateFrom AND @DateTo
	AND a.CompanyID LIKE '%'+@CompanyId+'%'
	GROUP BY a.CompanyID,b.Name,a.PINo,a.PIDate
	HAVING SUM(PurchaseAmt)>0
END
