CREATE Procedure [dbo].[SP_PharReqPurchaseStockIn] @BranchId varchar(5), @InvoiceNo  varchar(20), @InvoiceDate varchar(20)
AS  --- EXEC SP_PharReqPurchaseStockIn 1, 'PS250300004', '2025-03-24'
BEGIN
 select a.InvoiceNo, a.InvoiceDate, a.EntryDateTime ,a.CompanySlipNo, a.StoreId, d.SubSubPno as StoreName, a.CompanyId, c.Name,
 a.TotalAmount, a.TotalVat, a.GrandTotal, a.TotalDiscount, a.TotalLess, a.TotalPayableAmt, a.TotalPayment, a.CashAmt,
 a.CardAmt, a.ChequeAmt, a.CardNo, a.CardBank, e.Name as CardBankName, a.ChequeNo, ChequeBank, e.Name as ChqBankName, 
 b.ProductCode, b.ProductName, b.ApproveQty, b.PurchaseQty, b.BonusQty, b.UnitTp, b.TotalTp, b.Vat, b.TotalTpVAT, b.Discount,
 b.TotalPurchaseAmt, b.NewTP, b.MRP, b.ExpDate, a.Remarks, a.UserName, a.BranchId, b.TotalDiscount AS TotalDiscountAmt, b.TotalVat AS TotalVatAmt
 from PharReqPurStockInMain a left join PharReqPurStockInDetails b On a.InvoiceNo=b.InvoiceNo 
 left join PharCompanyInfo c on a.CompanyId=c.Company_Id 
 left join ProjectInformations d On a.StoreId=d.PnoCode
 left join BankInfo e On a.CardBank=e.Id 
 where a.Valid=1 AND a.BranchId=@BranchId AND a.InvoiceNo=@InvoiceNo AND a.InvoiceDate=@InvoiceDate
 END
