CREATE PROC [dbo].[SP_PharSaleRptProductWise](@DateFrom date, @DateTo date, @ProductId nvarchar(20), @BranchId int, @companyId nvarchar(20), @storeId nvarchar(10))
AS --- EXEC SP_PharSaleRptProductWise '2024-06-01', '2024-06-26', '', 1, '', ''
IF @ProductId <> '0' OR @companyId <>'0'
BEGIN
select b.CompanyName, a.ProductId, a.ProductName, c.Name as ProductGroup, SUM(a.OutQty) AS SaleQty, a.Tp, a.Mrp, a.StoreId, d.SubSubPno as StoreName
from PharmaCurrentStock a
LEFT JOIN PharProductInfo b ON a.ProductId = b.Id
LEFT JOIN PharPdGroup c On b.ProductGroup = c.Id
LEFT JOIN ProjectInformations d On a.StoreId = d.PnoCode
WHERE a.TrDate BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId AND Status = 'Out' and a.ProductId LIKE '%'+@ProductId+'%' AND b.CompanyId LIKE '%'+@companyId+'%' AND
a.StoreId LIKE '%'+@storeId+'%'
GROUP BY b.CompanyName, a.ProductId, a.ProductName, c.Name, a.Tp, a.Mrp, a.StoreId, d.SubSubPno
order by b.CompanyName, a.ProductId
END
else
BEGIN
select b.CompanyName, a.ProductId, a.ProductName, c.Name as ProductGroup, SUM(a.OutQty) AS SaleQty, a.Tp, a.Mrp, a.StoreId, d.SubSubPno as StoreName
 from PharmaCurrentStock a
LEFT JOIN PharProductInfo b ON a.ProductId = b.Id
LEFT JOIN PharPdGroup c On b.ProductGroup = c.Id
LEFT JOIN ProjectInformations d On a.StoreId = d.PnoCode
WHERE a.TrDate BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId AND a.StoreId LIKE '%'+@storeId+'%' AND Status = 'Out' 
GROUP BY b.CompanyName, a.ProductId, a.ProductName, c.Name, a.Tp, a.Mrp, a.StoreId, d.SubSubPno
order by b.CompanyName, a.ProductId
END
GO
