--17012026
Create Procedure [dbo].[SP_PharSalesAndCollection] @DateFrom Date, @DateTo Date, @BranchId Int, @PtStatus Varchar(50), @PatientId Varchar(50), @StaffId Varchar(50), @InvNo Varchar(50), @StoreId Int
AS
Begin -- exec SP_PharSalesAndCollection '2025-01-01', '2025-01-10', 1, '', '', '', '', 72
	Select a.TrNo, a.TrDate, a.Particulars, a.PatientId, a.RegNo, a.BedNo, a.PatientName, a.Sales, a.LessAmt, a.Collection,
	a.DueLess, a.DueColl, a.ReturnAmt+a.LessAdjust+a.CashReturn As TotalReturn, a.ReturnAmt As DueAdjust, a.LessAdjust,
	a.CashReturn, a.InvNo, a.InvDate, a.CashAmt, a.CardAmt, a.ChequeAmt, a.AdjustAmt, a.PtStatus, a.UserName, a.EntryDateTime,
	b.SubSubPno As StoreName, Case When a.Sales <= 0 Then 0 Else a.Sales-a.LessAmt-a.Collection End As Due
	From PharSalesLedger a
	Inner Join ProjectInformations b On a.StoreId=b.PnoCode
	Where a.Valid=1 And Case when @BranchId=0 then 0 Else a.BranchId End = @BranchId
	And Case when @PtStatus='' then '' Else a.PtStatus End = @PtStatus
	And Case when @PatientId='' then '' Else a.PatientId End = @PatientId
	And Case when @StaffId='' then '' Else a.RegNo End = @StaffId
	And Case when @InvNo='' then '' Else a.InvNo End = @InvNo
	And Case when @StoreId=0 then 0 Else a.StoreId End = @StoreId
	And a.TrDate Between @DateFrom And @DateTo
End
GO
