--22092025
create Procedure [dbo].[Sp_PharSalesReportForDashboard] @BranchId Int, @DateFrom Date, @DateTo Date, @PtStatus Varchar(150)
AS
BEGIN -- Sp_PharSalesReportForDashboard 1, '2025-04-01', '2025-04-01', ''
Select Sum(TotalInvoice) as TotalInvoice, IsnuLl(Sum(Sales),0 ) as Sales, Sum(Less) As Less,
SUm(Collection) As Collection, SUm(DueColl) As DueColl, Sum(CashReturn) As CashReturn, Isnull(Sum(Due), 0) As Due
From
(
	Select Count(SaleNo) As TotalInvoice, Sum(TotalAmt) As Sales,
	0 As Less, 0 As Collection, 0 As DueColl, 0 AS CashReturn, 0 As Due
	From PharSalesMaster
	Where BranchId=@BranchId And Valid=1 And SaleDate Between @DateFrom and @DateTo
	And Case when @PtStatus = '' Then '' Else PtStatus End = @PtStatus
	Union All
	Select 0 As TotalInvoice, 0 As Sales,
	LessAmt+DueLess As Less, Collection, DueColl As DueColl, CashReturn As CashReturn, 0 As Due
	from PharSalesLedger
	Where BranchId=@BranchId And Valid=1 And TrDate Between @DateFrom and @DateTo
	And Case when @PtStatus = '' Then '' Else PtStatus End = @PtStatus
	Union All
	Select 0 As TotalInvoice, 0 As Sales,
	0 As Less, 0 As Collection, 0 As DueColl, 0 As CashReturn, Sum(Sales-LessAmt-DueLess-ReturnAmt) As Due
	from PharSalesLedger a
	Left Join PatientAdmission b On a.PatientId=b.PatientId And b.IsRelease=0
	Where a.BranchId=@BranchId And a.Valid=1 And a.InvDate Between @DateFrom and @DateTo
	and PtStatus <> 'Outdoor'
) aa
End

GO
