CREATE PROC [dbo].[SP_PharSalesRptUserWiseDtls](@FromDate date, @ToDate date, @branchId nvarchar(10), @unitId nvarchar(10), @userName nvarchar(50), 
@DeptName VARCHaR(40), @storeId nvarchar(10))
AS
/******
  EXEC SP_PharSalesRptUserWiseDtls '2023-12-23', '2023-12-23', 1, 1, '', '', ''
******/
BEGIN
SELECT a.TrNo, a.EntryDateTime AS TrDate, a.PatientId, a.RegNo, a.BedNo, a.PatientName, a.Sales, a.Collection AS AdvColl, 
a.LessAmt AS Less, (a.CashReturn) AS ReturnAmt, a.DueColl AS SecondColl, a.DueLess AS SecondLess,a.CashAmt, a.CardAmt, 
a.ChequeAmt, a.CashReturn, a.InvNo, a.InvDate, a.PtStatus, a.UserName, a.StoreId, b.SubSubPno as StoreName
FROM PharSalesLedger a
LEFT JOIN ProjectInformations b On a.StoreId=b.PnoCode
WHERE a.Valid=1 and a.TrDate BETWEEN @FromDate AND @ToDate AND a.UserName like '%'+@userName+'%' AND a.BranchId LIKE '%'+@branchId+'%'
AND a.PtStatus LIKE '%'+@DeptName+'%' AND a.StoreId LIKE '%'+@storeId+'%'
AND a.InputFrom NOT IN('Patient Release','Indoor Due Collection')
GROUP BY a.TrNo, a.EntryDateTime, a.PatientId, a.RegNo, a.BedNo, a.PatientName, a.InvNo, a.InvDate, a.PtStatus, a.UserName, a.Sales, a.Collection, a.LessAmt, a.CashReturn, a.DueColl, a.DueLess, a.CashAmt, a.CardAmt,  a.ChequeAmt, a.CashReturn, a.StoreId, b.SubSubPno
HAVING SUM(a.Sales + a.Collection + a.LessAmt + a.CashReturn + a.DueColl + a.DueLess) <> 0
ORDER BY a.UserName, a.EntryDateTime DESC
End
GO
