CREATE PROC [dbo].[SP_PharSalesRptUserWiseSummarized](@dateFrom nvarchar(50), @dateTo nvarchar(50), @unitId nvarchar(50), @branchId nvarchar(50), 
@userName nvarchar(50), @ptStatus nvarchar(50), @storeId nvarchar(10))
AS ---  Exec SP_PharSalesRptUserWiseSummarized '2023-12-23', '2023-12-23', 1, 1, '', '', ''
BEGIN
select SUM(a.Sales) AS Sales, SUM(a.Collection+a.DueColl) AS Collection, SUM(a.CashReturn) AS ReturnAmt, SUM(a.LessAmt+a.DueLess) AS LessAmt, SUM(a.Collection+a.DueColl-a.CashReturn) AS NetColl, sum(a.CashAmt) as CashAmt, sum(a.CardAmt) as CardAmt, sum(a.ChequeAmt) as ChequeAmt,
a.PtStatus, a.UserName, a.StoreId, b.SubSubPno as StoreName
from PharSalesLedger a
LEFT JOIN ProjectInformations b On a.StoreId=b.PnoCode
WHERE a.Valid = 1  AND a.TrDate BETWEEN @dateFrom AND @dateTo And a.BranchId=@branchId AND a.UnitId=@unitId AND a.UserName LIKE '%'+@userName+'%' AND 
a.PtStatus LIKE '%'+@ptStatus+'%' AND a.StoreId LIKE '%'+@storeId+'%'
AND a.InputFrom NOT IN('Patient Release','Indoor Due Collection')
GROUP BY a.PtStatus, a.UserName, a.StoreId, b.SubSubPno
END
GO
