	SELECT a.RefNo, a.RefDate, a.PatientId, a.RegNo, a.ProductId, a.ProductName, a.SalePrice, a.TP, a.RtnItemLess, 
	a.RtnQuantity, a.RtnTotal, a.ExpiredDate, a.Remarks, a.UserName, b.EntryDateTime AS AdmissionDate, b.PatientName, 
