CREATE PROC [dbo].[Sp_PharSalesRtnIpdNurseApp] @branchId INT, @returnNo VARCHAR(30), @returnDate DATE
AS
BEGIN /* EXEC Sp_PharSalesRtnIpdNurseApp 1, 'RA231200091', '2023-12-09' */
	
	DECLARE @RefNo VARCHAR(20);
	SELECT @RefNo = RefNo FROM PharSalesRtnIpdAppMaster WHERE Valid = 1 AND BranchId = @branchId AND ReturnNo = @returnNo AND ReturnDate = @returnDate;

	select r.BranchId, r.UserName AS RtnIndentUserName, MAX(r.EntryDateTime) AS RtnIndentTime, r.Department AS RtnIndentDept 
	INTO #z
	from PharSalesRtnIPD r 
	WHERE r.Valid =1 AND r.RefNo = @RefNo 
	GROUP BY r.BranchId, r.UserName, r.Department

	SELECT a.ReturnNo, a.ReturnDate, a.RefNo, a.RefDate, a.DeptName, a.PatientId, a.PatientName, a.RegNo, a.BedNo, a.TotalRtn, 
	a.LessAdjust, a.NetReturn, a.DueAdjust, a.CashReturn, a.Remarks, a.UserName, b.ProductId, b.ProductName, b.SalePrice, b.TP, 
	b.RtnQuantity, b.RtnItemLess, b.ExpiredDate, c.RtnIndentUserName, c.RtnIndentTime, c.RtnIndentDept
	FROM PharSalesRtnIpdAppMaster a
	LEFT JOIN PharSalesRtnIpdAppDtls b ON a.BranchId = b.BranchId AND a.Id = b.MasterId and b.Valid= 1
	left join #z c on c.BranchId = a.BranchId
	WHERE a.Valid = 1 AND a.BranchId = @branchId AND a.ReturnNo = @returnNo AND a.ReturnDate = @returnDate
END
GO
