CREATE PROC [dbo].[SP_PharSalesRtnSummary](@FromDate date, @ToDate date, @branchId nvarchar(50), @unitId nvarchar(50), @ptStatus nvarchar(20), @storeId nvarchar(10))
AS --- EXEC SP_PharSalesRtnSummary '2024-06-01', '2024-06-30', 1 , 1 , '', ''
BEGIN
select a.PtStatus+' Sales' AS SalesStatus, SUM(a.Sales) AS Sales, SUM(a.Collection+a.DueColl) AS Collection, SUM(a.LessAmt+a.DueLess) LessAmt, SUM(a.CashReturn + ReturnAmt) as ReturnAmt, SUM((a.Collection+a.DueColl)-(a.CashReturn)) AS NetAmount, a.StoreId, b.SubSubPno as StoreName
from PharSalesLedger a 
LEFT JOIN ProjectInformations b On a.StoreId=b.PnoCode
WHERE a.Valid = 1 AND a.BranchId=@branchId AND a.UnitId=@unitId AND TrDate BETWEEN @FromDate AND @ToDate AND a.PtStatus like '%'+@ptStatus+'%' AND a.StoreId LIKE '%'+@storeId+'%'
GROUP BY a.PtStatus, a.StoreId, b.SubSubPno
END
