CREATE PROCEDURE [dbo].[SP_PharStockTransfer](@TrNo nvarchar(50), @TrDate date, @BranchId int, @UnitId int)
AS
BEGIN
----SELECT TrNo, TrDate, b.Name as FromBranch, c.Name AS FromUnit, g.SubSubPno AS FromStore,
----d.Name AS ToBranch, e.Name as ToUnit, h.SubSubPno AS Tostore, a.CompanyId, f.Name AS CompanyName,
----a.ProductName, a.StockOutQty, a.TP, a.TotalTp, a.Remarks, a.UserName, a.EntryDateTime
----FROM PharStockTransfer a
----LEFT JOIN tbl_BranchInfo b ON a.FromBranchId = b.Id
----LEFT JOIN tbl_COMPANY_INFORMATION c ON a.FromUnitId = c.Id and a.BranchId = c.BranchId
----LEFT JOIN tbl_BranchInfo d ON a.ToBranchId = d.Id
----LEFT JOIN tbl_COMPANY_INFORMATION e ON a.ToUnitId = e.Id
----LEFT JOIN PharCompanyInfo f ON a.CompanyId = f.Company_Id
----LEFT JOIN ProjectInformations g ON a.FromStoreId = g.PnoCode
----LEFT JOIN ProjectInformations h ON a.ToStoreId = h.PnoCode
----WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.TrNo = @TrNo AND a.TrDate = @TrDate

SELECT TrNo, TrDate, b.Name as FromBranch, c.Name AS FromUnit, g.SubSubPno AS FromStore,
d.Name AS ToBranch, e.Name as ToUnit, h.SubSubPno AS Tostore, a.CompanyId, f.Name AS CompanyName,
a.ProductName, sum(a.StockOutQty) as StockOutQty, 0 as TP, sum(a.TotalTp) as TotalTp, a.Remarks, a.UserName,  MAX(EntryDateTime) as EntryDateTime
FROM PharStockTransfer a
LEFT JOIN tbl_BranchInfo b ON a.FromBranchId = b.Id
LEFT JOIN tbl_COMPANY_INFORMATION c ON a.FromUnitId = c.Id and a.BranchId = c.BranchId
LEFT JOIN tbl_BranchInfo d ON a.ToBranchId = d.Id
LEFT JOIN tbl_COMPANY_INFORMATION e ON a.ToUnitId = e.Id
LEFT JOIN PharCompanyInfo f ON a.CompanyId = f.Company_Id
LEFT JOIN ProjectInformations g ON a.FromStoreId = g.PnoCode
LEFT JOIN ProjectInformations h ON a.ToStoreId = h.PnoCode
WHERE a.Valid = 1 AND a.BranchId = @BranchId AND a.TrNo = @TrNo AND a.TrDate = @TrDate
GROUP BY  TrNo, TrDate, b.Name,  c.Name , g.SubSubPno ,
d.Name , e.Name, h.SubSubPno, a.CompanyId, f.Name,
a.ProductName,  a.Remarks, a.UserName
END 
