CREATE PROC [dbo].[SP_PLAccount] (@Pno AS Int,@dateFrom AS date,@dateTo AS date)AS
BEGIN
--------Before Update Please Call EXEC SP_ManufacturingAccount 1,'2019-11-19','2019-11-20'
DELETE FROM tmp_PL
INSERT INTO tmp_PL
select 1 as SlNo,a.Code ,b.Description,SUM(a.Credit-a.Debit) as Bal , 1 as Bal1
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.Code=b.Code and b.Type='Profit And Loss A/C'
and SUBSTRING(a.code,1,1) IN ('3') and a.Trans_dt BETWEEN @dateFrom AND @dateTo AND a.Valid=1 AND a.Pno=1
group by a.Code ,b.Description
UNION ALL
select 2 as SlNo,a.Code ,b.Description,SUM(a.Debit-a.Credit) as Bal , (-1) as Bal1
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.Code=b.Code and b.Type='Profit And Loss A/C'
and SUBSTRING(a.code,1,1) IN ('4') and a.Trans_dt BETWEEN @dateFrom AND @dateTo AND a.Valid=1 AND a.Pno=1
group by a.Code ,b.Description
UNION ALL
select 4,'','LESS Cost Of Goods Sold' , SUM(Bal*Bal1) , (-1)
from tmp_MA

DELETE FROM tmpPLFinal
INSERT INTO tmpPLFinal
select slno,code,description,Bal 
from tmp_PL
UNION ALL
select 5,'','NET PROFIT/LOSS' , SUM(Bal*Bal1) 
from tmp_PL

select * from tmpPLFinal

END








GO
