CREATE PROCEDURE [dbo].[SP_PreOperativeOrderReport] @BranchId int, @PatientId NVARCHAR(20)
AS ---EXEC SP_PreOperativeOrderReport 1 , 'PA230900028'
BEGIN
SELECT d.RegNo, d.PatientId, a.PatientName, a.AgeYear, a.AgeMon, a.AgeDay, a.PatientAge, a.PatientSex, a.PatientTel, c.Name AS Department, a.PatientAddress, a.AdmissionDate, a.AdmissionTime, a.BedNo, b.FloorNo, a.DrCode, a.DrName, a.UnderDrCode, a.UnderDrName, d.OrderDate, d.OrderTime, d.Weight, d.BloodGroup, d.Rx, d.PostedBy FROM PatientAdmission a
LEFT JOIN BedInformation b ON a.BedNo = b.BedNo
LEFT JOIN BedBaseTable c ON b.KindsofBed = c.Name AND c.Department = 'Department' 
LEFT JOIN PreOpeOrdersTable d ON a.PatientId = d.PatientId AND a.RegNo = d.RegNo
WHERE a.Valid = 1 AND a.BranchId = @BranchId AND c.Department = 'Department' AND a.IsRelease = 0 
AND d.PatientId IS NOT NULL AND d.PatientId = @PatientId
END
