CREATE PROC [dbo].[SP_PRESCRIPTION] (@ReceiptNo as nvarchar(20), @ReceiptDate as nvarchar(20), @RegNo as nvarchar(20))
AS
Begin

select a.ReceiptNo, a.ReceiptDate, a.TicketNo, a.VisitNo, a.RegNo, a.PatientName, a.Gender, a.Age, a.DrCode, a.DrName, b.DesignationInEnglish as DegreeEng, b.DrNameInBangla AS DrNameBng, b.DesignationInBangla as DegreeBng, a.NextFollowUp, a.NextFollowUpDate, a.RefDrCode, a.RefDrName, ISNULL((a.HeightFeet+'''' + a.HeightInch+'"'),'') as Height, ISNULL(a.Weight,'') as Weight, ISNULL(a.BpDiastolic,'') as BpDiastolic, ISNULL(a.BpSystolic,'') as BpSystolic,
ISNULL(SUBSTRING((SELECT DISTINCT Investigation+char(10) FROM PresInvestigationDtls where ReceiptNo = a.ReceiptNo and ReceiptDate = a.ReceiptDate and RegNo = a.RegNo and Valid = 1  FOR XML PATH('')), 1 , 1000),'') As InvsName,
ISNULL(SUBSTRING((SELECT DISTINCT CompDescription+char(10) FROM PresComplainDtls where ReceiptNo = a.ReceiptNo and ReceiptDate = a.ReceiptDate and RegNo = a.RegNo and Valid = 1  FOR XML PATH('')), 1, 1000),'') As Complain,

ISNULL(SUBSTRING((SELECT DISTINCT CompDescription+char(10) FROM PresPreComplainsDtls where ReceiptNo = a.ReceiptNo and ReceiptDate = a.ReceiptDate and RegNo = a.RegNo and Valid = 1  FOR XML PATH('')), 1, 1000),'') As PrevComplain,

ISNULL(SUBSTRING((SELECT DISTINCT ExamName+':'+space(2)+ExamResult+char(10) FROM PresTestParameter where LTRIM(ExamResult) <>'' AND ReceiptNo = a.ReceiptNo and ReceiptDate = a.ReceiptDate and RegNo = a.RegNo and Valid = 1  FOR XML PATH('')), 1 , 1000),'') As TestParameter,
ISNULL(SUBSTRING((SELECT DISTINCT PdDescription+char(10) From PresDdDtls where ReceiptNo = a.ReceiptNo and ReceiptDate = a.ReceiptDate and RegNo = a.RegNo and Valid = 1  FOR XML PATH('')), 1 , 1000),'') As PdDescription,
ISNULL(SUBSTRING((SELECT DISTINCT PdDescription+char(10) From PresDdDtls where ReceiptNo = a.ReceiptNo and ReceiptDate = a.ReceiptDate and RegNo = a.RegNo and Valid = 1  FOR XML PATH('')), 1 , 1000),'') As DdDescription,
ISNULL(SUBSTRING((SELECT distinct  dbo.LPAD(ROW_NUMBER() OVER(ORDER BY MedicineName ASC),2,'0')+'.' +  MedicineName+char(10)+SPACE(10)+Doses+SPACE(5)+Days+char(10) From PresMedicineDtls where ReceiptNo = a.ReceiptNo and ReceiptDate = a.ReceiptDate and RegNo = a.RegNo and Valid = 1  FOR XML PATH('')), 1 , 1000),'') As Medicine,
ISNULL(SUBSTRING((SELECT DISTINCT dbo.LPAD(ROW_NUMBER() OVER(ORDER BY Advice ASC),2,'0')+'.' +Advice+char(10) From PresAdviceDtls where ReceiptNo = a.ReceiptNo and ReceiptDate = a.ReceiptDate and RegNo = a.RegNo and Valid = 1  FOR XML PATH('')), 1 , 1000),'') AS Advice,

ISNULL(SUBSTRING((SELECT DISTINCT Name+char(10) From PresMedicalHistory where ReceiptNo = a.ReceiptNo and ReceiptDate = a.ReceiptDate and RegNo = a.RegNo and Valid = 1  FOR XML PATH('')), 1 , 1000),'') AS MedicalHistory,
ISNULL(SUBSTRING((SELECT DISTINCT MedicineName+char(10) From PresDrugHistory where ReceiptNo = a.ReceiptNo and ReceiptDate = a.ReceiptDate and RegNo = a.RegNo and Valid = 1  FOR XML PATH('')), 1 , 1000),'') As DrugHistory,
ISNULL(SUBSTRING((SELECT DISTINCT Name+char(10) From PresAllergy where ReceiptNo = a.ReceiptNo and ReceiptDate = a.ReceiptDate and RegNo = a.RegNo and Valid = 1  FOR XML PATH('')), 1 , 1000),'') AS Allergy,
a.Comments
from PrescriptionMaster a, DrInfo b
where a.DrCode = b.DrCode AND a.BranchId = b.BranchId and a.ReceiptNo = @ReceiptNo AND a.ReceiptDate= @ReceiptDate AND a.RegNo= @RegNo

end
GO
