--select * from CommonMedicine
--select * from PresAdviceDtls
--select * from PresDrugHistory
--select * from PresMedicalHistory
--select * from PresAllergy


SELECT CompRecordFor AS RecordFor,
CASE 
    WHEN CHARINDEX('(', CompDescription) > 0 THEN LEFT(CompDescription, CHARINDEX('(', CompDescription) - 2)
    ELSE CompDescription END AS FirstPart
	INTO #Z
from PresComplainDtls


select count(*) As RankIndx,FirstPart,RecordFor INTO #zz from #z GROUp BY FirstPart,RecordFor Order by FirstPart


UPDATE PresComplain SET RankSl = b.RankIndx
FROM PresComplain a , #zz b
WHERE a.Description = b.FirstPart and a.RecordFor = b.RecordFor 

---- PD List Update

SELECT PDRecordFor AS RecordFor,
CASE 
    WHEN CHARINDEX('(', PdDescription) > 0 THEN LEFT(PdDescription, CHARINDEX('(', PdDescription) - 2)
    ELSE PdDescription END AS FirstPart
	INTO #Z1
from PresPdDtls

select count(*) As RankIndx,FirstPart,RecordFor INTO #ZZ1 from #Z1 GROUp BY FirstPart,RecordFor Order by FirstPart


UPDATE PressPDList SET RankSl = b.RankIndx
FROM PressPDList a , #ZZ1 b
WHERE a.Description = b.FirstPart 
AND a.RecordFor = b.RecordFor 


---- DD List Update

SELECT PDRecordFor AS RecordFor,
CASE 
    WHEN CHARINDEX('(', PdDescription) > 0 THEN LEFT(PdDescription, CHARINDEX('(', PdDescription) - 2)
    ELSE PdDescription END AS FirstPart
	INTO #Z2
from PresDdDtls 

select count(*) As RankIndx,FirstPart,RecordFor INTO #ZZ2 from #Z2 GROUp BY FirstPart,RecordFor Order by FirstPart


UPDATE PressDDList SET RankSl = b.RankIndx
FROM PressDDList a , #ZZ2 b
WHERE a.Description = b.FirstPart 
and a.RecordFor = b.RecordFor 

--------- Medicine Details


SELECT 
CASE 
    WHEN CHARINDEX('(', MedicineName) > 0 THEN LEFT(MedicineName, CHARINDEX('(', MedicineName) - 2)
    ELSE MedicineName END AS FirstPart
	INTO #Z3
from PresMedicineDtls 

select count(*) As RankIndx,FirstPart INTO #ZZ3 from #Z3 GROUp BY FirstPart Order by FirstPart


UPDATE PharProductInfo SET RankSl = b.RankIndx
FROM PharProductInfo a , #ZZ3 b
WHERE a.ProductName = b.FirstPart 

-------- Press Exam Parameter

SELECT 
CASE 
    WHEN CHARINDEX('(', ExamName ) > 0 THEN LEFT(ExamName, CHARINDEX('(', ExamName) - 2)
    ELSE ExamName END AS FirstPart
	INTO #Z4
from PresTestParameter  

select count(*) As RankIndx,FirstPart INTO #ZZ4 from #Z4 GROUp BY FirstPart Order by FirstPart


UPDATE PresExamParameter SET RankSl = b.RankIndx
FROM PresExamParameter a , #ZZ4 b
WHERE a.Particulars = b.FirstPart 


------------- Investigation Details

SELECT 
CASE 
    WHEN CHARINDEX('(', Investigation ) > 0 THEN LEFT(Investigation, CHARINDEX('(', Investigation) - 2)
    ELSE Investigation END AS FirstPart
	INTO #Z5
from PresInvestigationDtls  

select count(*) As RankIndx,FirstPart INTO #ZZ5 from #Z5 GROUp BY FirstPart Order by FirstPart


UPDATE ClinicalChart SET RankSl = b.RankIndx
FROM ClinicalChart a , #ZZ5 b
WHERE a.Description = b.FirstPart 

END


GO
