CREATE PROCEDURE [dbo].[SP_ProductApproveByStoreDtls] @BranchId int, @DateFrom date, @DateTo date, @StoreId nvarchar(10), @CompanyId nvarchar(20)
AS --- EXEC SP_ProductApproveByStoreDtls 1, '2024-05-01', '2024-06-30', '', ''
BEGIN
Select a.ReqNo, a.ReqDate, a.ReqBy, a.TransferNo, a.TransferDate, a.TransferBy, a.ApproveNo, a.ApproveDate, a.UserName as ApprovedBy,
c.SubSubPno as ApproveStoreName, d.CompanyId, d.CompanyName, b.ProductCode, d.ProductName, b.ReqQty , e.TotalTp as ReqAmt , 
b.ApproveQty , (e.Tp* b.ApproveQty) as ApproveAmt, a.EntryDateTime
From ProductApprovedMaster a
INNER JOIN ProductApprovedDetails b On a.ApproveNo=b.ApproveNo AND A.BranchId=b.BranchId AND a.Valid=b.Valid
INNER JOIN ProjectInformations c On a.ApproveStoreId = c.PnoCode
INNER JOIN PharProductInfo d On b.ProductCode = d.Id
INNER JOIN PharProductReqCentralStoreDetails e On a.ReqNo = e.TrNo AND a.BranchId=e.BranchId AND a.Valid=b.Valid AND b.ProductCode=e.ProductCode
WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.ApproveDate BETWEEN @DateFrom AND @DateTo AND a.ApproveStoreId LIKE '%'+@StoreId+'%' AND d.CompanyId LIKE '%'+@CompanyId+'%'
END
GO
