CREATE PROCEDURE [dbo].[SP_ProductApproveByStoreSMZ] @BranchId int, @DateFrom date, @DateTo date, @StoreId nvarchar(10), @CompanyId nvarchar(20)
AS  --- EXEC SP_ProductApproveByStoreSMZ 1, '2024-05-01', '2024-06-30', '', ''
BEGIN
Select f.SubSubPno as FromStore ,c.SubSubPno as ToStore, d.CompanyId, d.CompanyName, b.ProductCode, d.ProductName,
 sum(b.ReqQty) as ReqQty, sum(g.TotalTp) as ReqAmt, sum(b.ApproveQty) as ApproveQty, sum(b.ApproveQty * g.Tp) as ApproveAmt
From ProductApprovedMaster a 
INNER JOIN ProductApprovedDetails b On a.ApproveNo=b.ApproveNo AND A.BranchId=b.BranchId AND a.Valid=b.Valid
INNER JOIN ProjectInformations c On a.ApproveStoreId=c.PnoCode
INNER JOIN PharProductInfo d On b.ProductCode=d.Id
INNER JOIN PharProductReqCentralStoreMaster e On a.ReqNo=e.TrNo AND a.BranchId=e.BranchId AND a.Valid=e.Valid
INNER JOIN ProjectInformations f On e.ToStoreId=f.PnoCode
INNER JOIN PharProductReqCentralStoreDetails g On a.ReqNo = g.TrNo AND a.BranchId=g.BranchId AND a.Valid=g.Valid AND b.ProductCode=g.ProductCode
WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.ApproveDate BETWEEN @DateFrom AND @DateTo AND a.ApproveStoreId LIKE '%'+@StoreId+'%' AND d.CompanyId LIKE '%'+@CompanyId+'%'
GROUP BY a.ApproveStoreId,  f.SubSubPno, c.SubSubPno, d.CompanyId, d.CompanyName, b.ProductCode, d.ProductName
ORDER BY a.ApproveStoreId, d.CompanyName, b.ProductCode
END
GO
