CREATE Procedure [dbo].[SP_ProductApprovedByStoreReport] @BranchId int, @unitId int, @approveNo nvarchar(20), @approveDate date
AS  --- Exec SP_ProductApprovedByStoreReport 1, 1, '240300001', '2024-03-21'
BEGIN
Select a.ApproveNo, a.ApproveDate, c.SubSubPno as ApproveStore, a.TransferNo, a.TransferDate, a.TransferBy,
a.ReqNo, a.ReqDate, a.ReqBy ,  a.TotalReqQty, a.TotalApproveQty, b.ProductCode, d.ProductName, b.ReqQty, b.ApproveQty,
a.UserName as ApprovedBy , a.EntryDateTime
From ProductApprovedMaster a
Inner Join ProductApprovedDetails b On a.ApproveNo=b.ApproveNo AND a.ApproveDate=b.ApproveDate AND a.Valid=b.Valid AND a.BranchId=b.BranchId AND a.UnitId=b.UnitId
Inner Join ProjectInformations c On a.ApproveStoreId=c.PnoCode
Inner join PharProductInfo d On b.ProductCode=d.Id
WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.UnitId=@UnitId AND a.ApproveNo=@ApproveNo AND a.ApproveDate=@ApproveDate
END
GO
