CREATE PROCEDURE [dbo].[SP_ProductReqToCentralStoreDtls] @BranchId int, @DateFrom date, @DateTo date, @StoreId nvarchar(10), @CompanyId nvarchar(20)
AS  --- EXEC SP_ProductReqToCentralStoreDtls 1, '2024-06-01', '2024-06-09', '', ''
BEGIN
Select a.TrNo, a.TrDate, c.SubSubPno as FromStoreName, d.SubSubPno as ToStoreName, e.CompanyId, e.CompanyName, b.ProductCode, e.ProductName, 
b.Tp, b.CurrentQty, b.ReqQty, b.TotalTp as ReqAmt, a.Note, a.UserName, a.EnryDateTime
From PharProductReqCentralStoreMaster a
INNER JOIN PharProductReqCentralStoreDetails b On a.TrNo=b.TrNo AND a.TrDate=b.TrDate AND a.BranchId=b.BranchId AND a.Valid=b.Valid
INNER JOIN ProjectInformations c On a.FromStoreId=c.PnoCode
INNER JOIN ProjectInformations d On a.ToStoreId=d.PnoCode
INNER JOIN PharProductInfo e On b.ProductCode=e.Id
WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.TrDate BETWEEN @DateFrom AND @DateTo AND a.FromStoreId LIKE '%'+@StoreId+'%' AND e.CompanyId LIKE '%'+@CompanyId+'%'
END
