CREATE PROCEDURE [dbo].[SP_ProductReqToCentralStoreSMZ] @BranchId int, @DateFrom date, @DateTo date, @StoreId nvarchar(10), @CompanyId nvarchar(20)
AS  --- EXEC SP_ProductReqToCentralStoreSMZ 1, '2024-05-01', '2024-06-09', '', ''
BEGIN
Select a.FromStoreId, b.SubSubPno as FromStoreName, c.SubSubPno as ToStoreName, d.CompanyId, d.CompanyName, a.ProductCode, d.ProductName, 
sum(a.ReqQty) as ReqQty, sum(a.TotalTp)  as ReqAmt
From PharProductReqCentralStoreDetails a
INNER JOIN ProjectInformations b On a.FromStoreId=b.PnoCode
INNER JOIN ProjectInformations c On a.ToStoreId=c.PnoCode
INNER JOIN PharProductInfo d On a.ProductCode=d.Id
WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.TrDate BETWEEN @DateFrom AND @DateTo AND a.FromStoreId LIKE '%'+@StoreId+'%' AND d.CompanyId LIKE '%'+@CompanyId+'%'
GROUP BY a.FromStoreId, b.SubSubPno,  c.SubSubPno, d.CompanyId, d.CompanyName, a.ProductCode, d.ProductName
ORDER BY  a.FromStoreId, d.CompanyName, a.ProductCode
END
