CREATE Procedure [dbo].[SP_ProductSlowTransfer] @BranchId int, @FromDate Date, @ToDate date, @StoreId int, @CompanyId nvarchar(20), @ProductGroup nvarchar(50)
AS ----  EXEC SP_ProductSlowTransfer 1, '2023-10-16', '2023-10-16', 139, '', ''
BEGIN
select c.Company_Id,c.Name, a.ProductId, b.ProductName,b.Tp, b.SalePrice, MAX(a.ExpireDate) as ExpDate,  (SELECT SUM(InQty-OutQty) FROM PharStockLedger WHERE ProductId = a.ProductId) AS CurrQty, SUM(a.OutQty) as SlowSales
from PharStockLedger a
LEFT JOIN PharProductInfo b ON a.ProductId = b.Id
LEFT JOIN PharCompanyInfo c ON b.CompanyId = c.Company_Id
LEFT JOIN PharStockTransfer d On a.ProductId=d.ProductId AND a.BranchId=d.BranchId AND a.Valid=d.Valid
WHERE  b.Id IS NOT NULL AND a.BranchId =@BranchId  AND  a.TranDate between  @FromDate AND @ToDate AND a.StoreId=139 AND c.Company_Id LIKE '%'+ @CompanyId +'%' AND b.ProductGroup LIKE '%'+@ProductGroup+'%' 
GROUP BY a.ProductId, b.ProductName, c.Company_Id, c.Name, b.Tp, b.SalePrice
Having SUM(a.OutQty) = 0
order by sum (a.OutQty),c.Company_Id, a.ProductId ASC
END
GO
