CREATE PROC [dbo].[SP_PurchaseDuePaidReport](@fromDate date, @toDate date, @branchId int, @unitId int, @type nvarchar(10))
AS
BEGIN --- EXEC SP_PurchaseDuePaidReport '2023-04-10','2023-04-30', 1, 1, ''

IF(@type = 'Paid')
	SELECT a.RefNo, a.RefDate, a.PINo, a.PIDate, a.Particulars, a.PurchaseAmt, a.PaymentAmt, a.CompanyID, a.UserName, a.EntryTime,	b.CompanyName,
	CASE
	    WHEN a.PurchaseAmt <= a.PaymentAmt THEN 'Paid'
	    WHEN SUM(a.PurchaseAmt - a.PaymentAmt) > 0 THEN 'Due'
	END AS PaymentStatus
	FROM PharmaPurchaseLedger a
	LEFT JOIN PharStockInMain b ON a.PINo = b.InvoiceNo AND a.PIDate = b.InvoiceDate
	WHERE a.Valid = 1 AND b.Valid = 1 AND a.BranchId = @branchId AND a.UnitId = @unitId AND a.PIDate BETWEEN @fromDate AND @toDate 
	GROUP BY a.RefNo, a.RefDate, a.PINo, a.PIDate, a.Particulars, a.PurchaseAmt, a.PaymentAmt, a.CompanyID, a.UserName, a.EntryTime, b.CompanyName
	HAVING SUM(a.PurchaseAmt - a.PaymentAmt) <= 0
IF(@type = 'Due')
	SELECT a.RefNo, a.RefDate, a.PINo, a.PIDate, a.Particulars, a.PurchaseAmt, a.PaymentAmt, a.CompanyID, a.UserName, a.EntryTime,	b.CompanyName,
	CASE
	    WHEN a.PurchaseAmt <= a.PaymentAmt THEN 'Paid'
	    WHEN SUM(a.PurchaseAmt - a.PaymentAmt) > 0 THEN 'Due'
	END AS PaymentStatus
	FROM PharmaPurchaseLedger a
	LEFT JOIN PharStockInMain b ON a.PINo = b.InvoiceNo AND a.PIDate = b.InvoiceDate
	WHERE a.Valid = 1 AND b.Valid = 1 AND a.BranchId = @branchId AND a.UnitId = @unitId AND a.PIDate BETWEEN @fromDate AND @toDate 
	GROUP BY a.RefNo, a.RefDate, a.PINo, a.PIDate, a.Particulars, a.PurchaseAmt, a.PaymentAmt, a.CompanyID, a.UserName, a.EntryTime, b.CompanyName
	HAVING SUM(a.PurchaseAmt - a.PaymentAmt) > 0
ELSE
	SELECT a.RefNo, a.RefDate, a.PINo, a.PIDate, a.Particulars, a.PurchaseAmt, a.PaymentAmt, a.CompanyID, a.UserName, a.EntryTime,	b.CompanyName,
	CASE
	    WHEN a.PurchaseAmt <= a.PaymentAmt THEN 'Paid'
	    WHEN SUM(a.PurchaseAmt - a.PaymentAmt) > 0 THEN 'Due'
	END AS PaymentStatus
	FROM PharmaPurchaseLedger a
	LEFT JOIN PharStockInMain b ON a.PINo = b.InvoiceNo AND a.PIDate = b.InvoiceDate
	WHERE a.Valid = 1 AND b.Valid = 1 AND a.BranchId = @branchId AND a.UnitId = @unitId AND a.PIDate BETWEEN @fromDate AND @toDate 
	GROUP BY a.RefNo, a.RefDate, a.PINo, a.PIDate, a.Particulars, a.PurchaseAmt, a.PaymentAmt, a.CompanyID, a.UserName, a.EntryTime, b.CompanyName

END




GO
