Create Procedure [dbo].[SP_PurchaseReqApprovedDetails] @BranchId int, @DateFrom Date, @DateTo Date, @CompanyId nvarchar(20)
As  ----  EXec SP_PurchaseReqApprovedDetails 1, '2023-01-01', '2023-12-01', ''
Begin
select a.TrNo, a.TrDate, a.PurchaseReqNo, a.PurchaseReqDate,  a.CompanyId, c.Name, b.ProductCode, d.ProductName,  sum(b.RequiredQty) as ReqQty ,
b.LastTP, sum( b.ApproveQty) as AppQty, sum(b.TotalAmount) as TotalAmt, a.EntryDateTime, a.UserName
 From PharPurchaseReqApproveMaster a 
left join PharPurchaseReqApproveDetails b on a.TrNo=b.TrNo and a.BranchId=b.BranchId and a.Valid=b.Valid
left join PharCompanyInfo c on a.CompanyId=c.Company_Id
left join PharProductInfo d on b.ProductCode=d.Id
Where a.Valid=1 and a.BranchId=@BranchId and a.TrDate between @DateFrom and @DateTo and a.CompanyId like '%'+@CompanyId+'%'
Group by a.TrNo, a.PurchaseReqNo,a.TrDate, a.PurchaseReqDate,  a.CompanyId, c.Name, b.ProductCode, d.ProductName, b.LastTP, a.EntryDateTime, a.UserName
order by a.CompanyId, c.Name
End
GO
