Create Procedure [dbo].[SP_PurchaseReqApprovedSMZ] @BranchId int, @DateFrom Date, @DateTo Date, @CompanyId nvarchar(20)
As  ----  Exec SP_PurchaseReqApprovedSMZ 1, '2023-01-01', '2023-12-01', ''
Begin
select a.CompanyId, c.Name, sum(b.RequiredQty) as ReqQty ,sum( b.ApproveQty) as AppQty, sum(b.TotalAmount) as TotalAmt From PharPurchaseReqApproveMaster a 
left join PharPurchaseReqApproveDetails b on a.TrNo=b.TrNo and a.BranchId=b.BranchId and a.Valid=b.Valid
left join PharCompanyInfo c on a.CompanyId=c.Company_Id
left join PharProductInfo d on b.ProductCode=d.Id
Where a.Valid=1 and a.BranchId=@BranchId and a.TrDate between @DateFrom and @DateTo and a.CompanyId like '%'+@CompanyId+'%'
Group by a.CompanyId, c.Name 
order by a.CompanyId, c.Name
End
GO
