CREATE PROC [dbo].[SP_RECEIVE_PAYMENT] (@dateFrom date,@dateTo date,@pno int)   AS
BEGIN
SELECT 0 AS RowId,'-' As TrNo,GETDATE() AS TrDate, '21010101' AS Code,b.Description As HeadDescription, SUM(a.Debit-a.Credit) AS Debit,0 AS Credit,'Previous Balance'  AS Description
from tbl_TRANSACT a LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code=b.Code
WHERE a.Trans_dt < @dateFrom AND a.Code='21010101' AND a.Pno=@pno
Group by b.Description
UNION ALL
SELECT a.Id as RowId,a.TrNo,a.Trans_dt As TrDate, a.Code,b.Description as HeadDescription, SUM(Credit)AS Debit,Sum(Debit) AS Credit,
a.Naration as  Description
FROm tbl_TRANSACT a LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code=b.Code
WHERE a.Trans_dt BETWEEN @dateFrom  AND @dateTo AND a.Code<>'21010101' AND a.VoucherType IN ('Payment','Receive') AND a.Pno=@pno
group by a.Code,a.TrNo,a.Id,b.Description,a.Naration,a.Trans_dt
END






GO
