--26082025
CREATE PROC [dbo].[SP_RegFees] (@FromDate date, @ToDate date, @UserName nvarchar(50))
AS
if @UserName <> ''
BEGIN
	SELECT a.RegNo, a.PatientName, a.TrNo, a.TrDate, a.TrType, a.Amount, a.UserName, a.EntryDateTime as EntryTime, a.CashAmount, a.CardAmount, a.CardNo, b.Name AS CardBank
	FROM RegistrationFees a
	LEFT JOIN BankInfo b On a.CardBank=b.Id
	where a.Valid = 1 and a.TrDate BETWEEN @FromDate AND @ToDate AND a.UserName = @UserName 
	ORDER BY TrNo
end
Else
BEGIN
	SELECT a.RegNo, a.PatientName, a.TrNo, a.TrDate, a.TrType, a.Amount, a.UserName, a.EntryDateTime as EntryTime, a.CashAmount, a.CardAmount, a.CardNo, b.Name AS CardBank
	FROM RegistrationFees a
	LEFT JOIN BankInfo b On a.CardBank=b.Id
	where a.Valid = 1 and a.TrDate BETWEEN @FromDate AND @ToDate
	ORDER BY TrNo
end
GO
