CREATE PROC [dbo].[SP_ReleaseBill_Package](@branchId int, @patientId nvarchar(20), @packCode nvarchar(20))
AS
BEGIN /*EXEC SP_ReleaseBill_Package 1, 'PA220804116', 'P001' */



select a.RegNo, a.PatientId, a.AdmissionDate, c.AdmissionTime, a.PatientName, c.PatientSex AS Gender, c.PatientAge, a.BedNo, 
DATEDIFF(DAY, c.AdmissionDate, GETDATE())+1 AS TotalDays, c.UnderDrName, a.BedNo, c.PatientTel AS PhoneNo, c.PatientAddress AS Address, a.UserName AS AdmittedBy,
b.InvestigationCode AS PCode, b.SortDescription AS Description, b.Charge*b.Unit AS Charge, a.AdvanceAmt AS Collection, 0 AS Less, a.NetPaymentAmt ReleaseTimeColl,  a.LessAmt AS ReleaseTimeLess, a.ReturnAmt, a.EntryDateTime AS ReleaseDate, a.PackCode, c.PackName from PatientReleaseMaster a
LEFT JOIN PatientReleaseDetails b ON a.BranchId = b.BranchId ANd a.PatientID = b.PatientId AND a.ReceiptNo = b.ReceiptNo AND b.Valid = 1
LEFT JOIN PatientAdmission c ON a.BranchId = c.BranchId ANd a.PatientID = b.PatientId ANd b.BranchId = c.BranchId ANd b.PatientId = c.PatientId
where a.BranchId = @branchId AND a.Valid = 1 AND c.IsRelease = 1 AND a.PatientId = @patientId and a.PackCode = @packCode ANd b.NoOfUnit = 0





END

GO
