create PROCEDURE [dbo].[SP_RollBackACTransfer] (@DateFrom Date, @DateTo Date, @BranchId integer, @UserName nvarchar(100))
AS
BEGIN
	update tbl_TRANSACT set valid = 0 , LogDtls = SUBSTRING(LogDtls + 'Cancel By ' + @UserName + space(2) + convert(varchar,getdate(),121),1,149)
	where FrNo = 'AutoFromSP' and valid = 1 
	and Trans_dt BETWEEN @dateFrom and @DateTo AND BranchId = @BranchId 
END
GO
