SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SP_SaleCollSummarized](@FromDate date, @ToDate date, @BranchId int)
AS
BEGIN        --EXEC SP_SaleCollSummarized '2022-06-15','2022-06-15',1

SELECT m.SlNo, m.AcCode, n.Description,  m.Status, SUM(m.Sales) AS Sales, SUM(m.Less) AS Less, SUM(m.ReturnAmt) AS ReturnAmt, SUM(m.CashAmt) AS CashAmt, SUM(m.CardAmt) AS CardAmt, SUM(m.ChequeAmt) AS ChequeAmt, SUM(m.CashReturn) AS CashReturn FROM (

select 1 AS SlNo,b.AcCode, 'Indoor Sales' as Status, SUM(a.Charge*a.NoOfUnit) as Sales, SUM(a.LessAmt) AS Less, 0 AS ReturnAmt,
0 As CashAmt, 0 as CardAmt, 0 AS ChequeAmt, 0 AS CashReturn
from PatientReleaseDetails a, ClinicalChart b
WHERE a.BranchId = b.BranchId AND a.InvestigationCode = b.PCode 
AND ReleaseDate BETWEEN @FromDate AND @ToDate AND Valid = 1 AND a.BranchId = @BranchId
group by b.AcCode
UNION
SELECT 5 AS SlNo, '3101010018' AcCode, 'Indoor Collection' AS Status, 0 as Sales, 0 AS Less, 0 AS ReturnAmt,
SUM(a.CashAmt+ISNULL(b.CashAmt,0)) AS CashAmt, SUM(a.CardAmt+ISNULL(b.CardAmt,0)) AS CardAmt, SUM(a.ChequeAmt+ISNULL(b.ChequeAmt,0)) AS ChequeAmt, 0 AS CashReturn
FROM PatientReleaseMaster a
LEFT JOIN PatientSettlementDetails b ON a.BranchId = b.BranchId AND a.PatientID = b.PatientId
WHERE a.ReleaseDate BETWEEN @FromDate AND @ToDate AND a.Valid = 1
AND a.BranchId = @BranchId
HAVING SUM(a.CashAmt+a.CardAmt+a.ChequeAmt) > 0
UNION
SELECT 6 AS SlNo, '3101010018' AcCode, 'Indoor Advance Collection' AS Status, 0 as Sales, 0 AS Less, 0 AS ReturnAmt,
SUM(a.CashAmt) AS CashAmt, SUM(a.CardAmt) AS CardAmt, SUM(a.ChequeAmt) AS ChequeAmt, 0 AS CashReturn
FROM TimeToTimeDuePayment a
WHERE a.BranchId = @BranchId AND a.PaymentDate BETWEEN @FromDate AND @ToDate AND a.Valid = 1
AND a.BranchId = 1
HAVING SUM(a.CashAmt+a.CardAmt+a.ChequeAmt) > 0
UNION
SELECT 4 AS SlNo, '3101010019' AcCode, 'Indoor Return' AS Status, 0 as Sales, 0 AS Less, SUM(ReturnAmt) AS ReturnAmt,
0 AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, SUM(ReturnAmt) AS CashReturn
FROM PatientReleaseMaster a WHERE a.ReleaseDate BETWEEN @FromDate AND @ToDate AND Valid = 1
AND a.BranchId = @BranchId
HAVING SUM(ReturnAmt) > 0
UNION
select 2 AS SlNo, (SELECT DISTINCT AcCode FROM ClinicalChart WHERE DeptName = a.Department and BranchId = a.BranchId) As AcCode, 'Diagnostic' AS Status, 
SUM(a.Sales-a.ReturnAmount) AS Sales, SUM(a.Less-a.ReturnLess) AS Less, sum(a.ReturnNet) as ReturnAmt,
SUM(a.ByCash) AS CashAmt, SUM(a.ByCard) AS CardAmt, SUM(a.ChequeAmount) AS ChequeAmt, sum(a.ReturnCash) as CashReturn
from SalesLedger a
WHERE BranchId = @BranchId AND a.Valid <> 0 AND a.PreInvDate BETWEEN @FromDate AND @ToDate
GROUP BY a.BranchId, a.Department
UNION ALL
SELECT 3 AS SlNo, '3101010020' AS AcCode, 'OPDTicket' AS Status, SUM(a.Amount) AS Sales, 0 AS Less, SUM(ISNULL(a.RtnAmount, 0)) AS ReturnAmt, 
SUM(a.Amount) AS CashAmt, 0 AS CardAmt, 0 AS ChequeAmt, SUM(ISNULL(a.RtnAmount, 0)) as CashReturn
FROM OPDTicketMaster a
WHERE a.BranchId = @BranchId AND a.TrDate BETWEEN @FromDate AND @ToDate
UNION ALL
/* Start Pharmacy Section */
--select 2 AS SlNo, '3101010010' As AcCode, 'Medicine' AS Status, SUM(a.Sales) AS Sales, SUM(a.LessAmt-a.DueLess) AS Less, sum(a.CashReturn+a.ReturnAmt) as ReturnAmt,
--SUM(a.CashAmt) AS CashAmt, SUM(a.CardAmt) AS CardAmt, SUM(a.ChequeAmt) AS ChequeAmt, sum(a.CashReturn) as CashReturn
--from PharSalesLedger a
--WHERE BranchId = @BranchId AND a.Valid <> 0 AND a.PtStatus <> 'INDOOR' AND a.InvDate BETWEEN @FromDate AND @ToDate
--UNION ALL
/* End Pharmacy Section */
select 2 AS SlNo, '3101010004' As AcCode, 'Ambulance' AS Status, SUM(a.TotalCharge) AS Sales, SUM(a.Less) AS Less, 0 as ReturnAmt,
SUM(a.CashAmt) AS CashAmt, SUM(a.CardAmt) AS CardAmt, SUM(a.ChequeAmt) AS ChequeAmt, 0 as CashReturn
from AmbulanceLedger a
WHERE BranchId = @BranchId AND a.Valid <> 0 AND a.PtStatus <> 'INDOOR' AND a.RefDate BETWEEN @FromDate AND @ToDate
HAVING SUM(a.TotalCharge) > 0

) m
LEFT JOIN tbl_CHART_OF_ACCOUNTS n ON m.AcCode = n.Code
GROUP BY m.SlNo, m.AcCode, m.Status, n.Description
ORDER BY m.SlNo
END
GO
