--27012026 -- item less = itemless/qty
CREATE PROC [dbo].[SP_SalesRtnIndoorPtnWise] @BranchId INT, @Param VARCHAR(30), @StoreId Int
AS /* If you want to change this 'SP_SalesRtnIndoorPtnWise' PROCEDURE you must change this 'SP_SalesRtnStaffWise' PROCEDURE too */
BEGIN /* EXEC SP_SalesRtnIndoorPtnWise 1, 'PA251000308', 72 */
	SELECT DISTINCT c.RegNo, a.PatientId, c.PatientName, a.BedNo, a.ProductId, b.ProductName, a.SalePrice, a.ItemLess/a.ProductQty As ItemLess, 
	a.ExpireDate, a.TP, a.DeptName, b.CompanyId,UnitId, StoreId, 
	(
		SELECT SUM(OutQty-RtnQty) FROM PharStockLedger m WHERE m.Valid=1 And m.StoreId=@StoreId AND m.BranchId = a.BranchId AND m.PatientId = a.PatientId 
		AND m.ProductId = a.ProductId AND m.ExpireDate=a.ExpireDate
	) AS BalQty
	INTO #z
	FROM PharSalesDetails a
	LEFT JOIN PharProductInfo b ON a.ProductId = b.Id
	LEFT JOIN PatientRegistration c ON a.BranchId = c.BranchId AND a.RegNo = c.RegNo
	Left Join PatientAdmission d on a.PatientId=d.PatientId
	WHERE a.Valid=1 And a.StoreId=@StoreId AND a.BranchId = @BranchId AND a.PatientId = @Param and d.IsRelease=0
	SELECT * FROM #z WHERE BalQty != 0 ORDER BY ProductName
END
GO
