--27012026 -- item less = itemless/qty
CREATE PROC [dbo].[SP_SalesRtnStaffWise] @BranchId INT, @Param VARCHAR(30), @StoreId Int 
AS /* If you want to change this 'SP_SalesRtnStaffWise' PROCEDURE you must change this 'SP_SalesRtnIndoorPtnWise' PROCEDURE too */
BEGIN /* EXEC SP_SalesRtnStaffWise 1, 'PR230900798', 72 */
	SELECT DISTINCT c.RegNo, '' AS PatientId, c.PatientName, '' AS BedNo, a.ProductId, b.ProductName, a.SalePrice, 
	a.ItemLess/a.ProductQty As ItemLess, a.ExpireDate, a.TP, a.DeptName, b.CompanyId,UnitId, StoreId,  
	(
		SELECT SUM(OutQty-RtnQty) FROM PharStockLedger m WHERE m.Valid=1 And m.StoreId=@StoreId AND m.BranchId = a.BranchId AND m.RegNo = a.RegNo 
		AND m.ProductId = a.ProductId AND m.ExpireDate=a.ExpireDate
	) AS BalQty
	INTO #z
	FROM PharSalesDetails a
	LEFT JOIN PharProductInfo b ON a.ProductId = b.Id
	LEFT JOIN PatientRegistration c ON a.BranchId = c.BranchId AND a.RegNo = c.RegNo
	WHERE a.Valid=1 And a.StoreId=@StoreId AND a.BranchId = @BranchId AND a.RegNo = @Param AND a.ExpireDate > DATEADD(YEAR, -1, (FORMAT(GETDATE(), 'yyyy-MM-dd')))	
	SELECT * FROM #z WHERE BalQty > 0 ORDER BY ProductName
END
GO
