Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, Valid, RefNo, ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, LogDtls, IpAddress, BranchId, PartyName, PartyCode, ChequeDate)
VALUES (@ExpCode,@Amount,0,@naration,'',@trno ,@trDate,1,@trno,'Journal',@username,1,@RefNo
,@APCode,1,'',@RefDate,'','','D','','','Inventory',@userName,'',@branchId,@partyName ,@partycode , null);


INSERT INTO tbl_TRANSACT (
