VALUES (@APCode,0,@Amount,@naration,'',@trno ,@trDate,1,@trno,'Journal',@username,1,@RefNo
,@ExpCode,1,'',null,'','','C','','','Inventory',@userName,'',@branchId,@partyName ,@partycode , null);
