SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE  [dbo].[sp_ShowChartOfAcc] 
AS 
BEGIN
select 5 as SlNo, (space(20)+Code) AS AcCode,(space(20)+Description) AS ACName,Type , Code, Id
from tbl_CHART_OF_ACCOUNTS where right(Code,4)<>'0000'
UNION ALL
select 4 as SlNo, (space(15)+Code) AS Code,(space(15)+Description) AS ACName,Type , Code, Id 
from tbl_CHART_OF_ACCOUNTS where right(Code,4)='0000' and substring(Code,5,2) <> '00'
UNION ALL
select 3 as SlNo, (space(10)+Code) AS Code,(space(10)+Description) AS ACName,Type , Code, Id 
from tbl_CHART_OF_ACCOUNTS where right(Code,6)='000000' and substring(Code,3,2) <> '00'
UNION ALL
select 2 as SlNo, (space(5)+Code) AS Code,(space(5)+Description) AS ACName,Type , Code, Id 
from tbl_CHART_OF_ACCOUNTS where right(Code,8)='00000000' and substring(Code,2,2) <> '00'
UNION ALL
select 1 as SlNo, Code,Description AS ACName,Type , Code, Id 
from tbl_CHART_OF_ACCOUNTS where right(Code,9)='000000000' and substring(Code,1,1) <> '0'
ORDER BY Code 
END


GO
