CREATE procedure [dbo].[sp_ShowStudentDueCrossTab] (@dateUpto date,@Session nvarchar(20),@BatchNo nvarchar(20),@RollNo nvarchar(20),@BranchId integer, @isUpTo INT)
AS --- EXEC sp_ShowStudentDueCrossTab '2024-01-01','','','',6, 0 --- Writen By Arif
BEGIN

DECLARE @uptoDate DATE;
IF @isUpTo = 0 SET @uptoDate=@dateUpto ELSE SET @uptoDAte = DATEADD(YEAR, 10, GETDATE())

drop table tmpStudentDueReport
select 1 as SlNo , a.Quota,a.Session , a.BatchNo , a.RollNo ,a.ItemId , b.name as ItemName,  count(*) AS NoofMonth,
sum(a.DueAmt-a.ReceiveAmt-a.LessAmt) as due ,
SUBSTRING(datename(month,Min(ArDate)),1,3)+'-'+datename(year,Min(ArDate)) + ' To '+SUBSTRING(datename(month,MAX(ArDate)),1,3)+'-'+datename(year,MAX(ArDate)) as Particulars  ,'(Tk)' as CurType , a.BranchId 
INTO #tmpStudentDueSpecial
from tbl_StudentLedger a , tbl_CodeForTutionFees b
where a.valid = 1 and ltrim(rtrim(a.ItemId)) = LTRIM(RTRIM(b.SlNo))  
and a.BranchId = b.BranchId and b.SlNO = 4 and a.Quota IN ('General' , 'Poor & Merit')
and a.ARDate <= @uptoDate
--and a.ARDate <= @dateUpto 
and a.Session like '%'+@Session +'%' and a.BatchNo like '%'+@BatchNo + '%' and a.RollNo LIKE '%'+@RollNo +'%' and a.BranchId = @BranchId 
group by a.Quota,a.Session , a.BatchNo , a.RollNo ,  a.ItemId , b.name , a.BranchId 
having SUM(a.DueAmt-a.ReceiveAmt-a.LessAmt) <> 0
UNION ALL
select 2 as SlNo ,a.Quota,a.Session , a.BatchNo , a.RollNo ,a.ItemId , b.name as ItemName,  count(*) AS NoofMonth,
sum(a.DueAmt-a.ReceiveAmt-a.LessAmt) as due ,
SUBSTRING(datename(month,Min(ArDate)),1,3)+'-'+datename(year,Min(ArDate)) + ' To '+SUBSTRING(datename(month,MAX(ArDate)),1,3)+'-'+datename(year,MAX(ArDate)) as Particulars  ,'(Tk)' as CurType , a.BranchId 
from tbl_StudentLedger a , tbl_CodeForTutionFees b
where a.valid = 1 and ltrim(rtrim(a.ItemId)) = LTRIM(RTRIM(b.SlNo))  
and a.BranchId = b.BranchId and b.SlNO = 10 and a.Quota IN ('General' , 'Poor & Merit')
and a.ARDate <= @uptoDate
--and a.ARDate <= @dateUpto 
and a.Session like '%'+@Session +'%' and a.BatchNo like '%'+@BatchNo + '%' and a.RollNo LIKE '%'+@RollNo +'%' and a.BranchId = @BranchId 
group by a.Quota,a.Session , a.BatchNo , a.RollNo ,  a.ItemId , b.name , a.BranchId 
having SUM(a.DueAmt-a.ReceiveAmt-a.LessAmt) <> 0
UNION ALL
select 3 as SlNo ,a.Quota,a.Session , a.BatchNo , a.RollNo ,a.ItemId , b.name as ItemName,  0 AS NoofMonth,
sum(a.DueAmt-a.ReceiveAmt-a.LessAmt) as due ,
'' as Particulars  ,'(Tk)' as CurType , a.BranchId 
from tbl_StudentLedger a , tbl_CodeForTutionFees b
where a.valid = 1 and ltrim(rtrim(a.ItemId)) = LTRIM(RTRIM(b.SlNo))  
and a.BranchId = b.BranchId and b.slno NOT IN (4,10,6,11,17,18,26,30)
and a.ARDate <= @uptoDate
--and a.ARDate <= @dateUpto 
and a.Session like '%'+@Session +'%' and a.BatchNo like '%'+@BatchNo + '%' and a.RollNo LIKE '%'+@RollNo +'%' and a.BranchId = @BranchId and a.Quota IN ('General' , 'Poor & Merit')
group by a.Quota,a.Session , a.BatchNo , a.RollNo ,  a.ItemId , b.name , a.BranchId 
having SUM(a.DueAmt-a.ReceiveAmt-a.LessAmt) <> 0
UNION ALL
select 4 as SlNo ,a.Quota,a.Session , a.BatchNo , a.RollNo ,99 as ItemId , 'Others' as ItemName,  0 AS NoofMonth,
sum(a.DueAmt-a.ReceiveAmt-a.LessAmt) as due ,
'' as Particulars ,'(Tk)' as CurType , a.BranchId 
from tbl_StudentLedger a , tbl_CodeForTutionFees b
where a.valid = 1 and ltrim(rtrim(a.ItemId)) = LTRIM(RTRIM(b.SlNo))  
and b.slno IN (6,11,17,18,26,30) and a.Quota IN ('General' , 'Poor & Merit')
and a.BranchId = b.BranchId and a.ARDate <= @uptoDate
--and a.ARDate <= @dateUpto 
and a.Session like '%'+@Session +'%' and a.BatchNo like '%'+@BatchNo + '%' and a.RollNo LIKE '%'+@RollNo +'%' and a.BranchId = @BranchId 
group by a.Session , a.BatchNo , a.RollNo ,a.Quota  , a.BranchId 
having SUM(a.DueAmt-a.ReceiveAmt-a.LessAmt) <> 0

UNION ALL ----------For Foreign  select * from tbl_StudentLedger

select 1 as SlNo ,a.Quota,a.Session , a.BatchNo , a.RollNo ,a.ItemId , b.name as ItemName,  count(*) AS NoofMonth,
sum(a.FCDueAmt-a.FCPaidAmt) as due ,
SUBSTRING(datename(month,Min(ArDate)),1,3)+'-'+datename(year,Min(ArDate)) + ' To '+SUBSTRING(datename(month,MAX(ArDate)),1,3)+'-'+datename(year,MAX(ArDate)) as Particulars  ,'(FC)' as CurType, a.BranchId 
from tbl_StudentLedger a , tbl_CodeForTutionFees b
where a.valid = 1 and ltrim(rtrim(a.ItemId)) = LTRIM(RTRIM(b.SlNo))  
and a.BranchId = b.BranchId and b.SlNO = 4
and a.Quota IN ('Foreign') and a.ARDate <= @uptoDate
--and a.ARDate <= @dateUpto 
and a.Session like '%'+@Session +'%' and a.BatchNo like '%'+@BatchNo + '%' and a.RollNo LIKE '%'+@RollNo +'%' and a.BranchId = @BranchId 
group by a.Quota,a.Session , a.BatchNo , a.RollNo ,  a.ItemId , b.name , a.BranchId 
having SUM(a.FCDueAmt-a.FCPaidAmt) <> 0
UNION ALL
select 2 as SlNo ,a.Quota,a.Session , a.BatchNo , a.RollNo ,a.ItemId , b.name as ItemName,  count(*) AS NoofMonth,
sum(a.FCDueAmt-a.FCPaidAmt) as due ,
SUBSTRING(datename(month,Min(ArDate)),1,3)+'-'+datename(year,Min(ArDate)) + ' To '+SUBSTRING(datename(month,MAX(ArDate)),1,3)+'-'+datename(year,MAX(ArDate)) as Particulars  ,'(FC)' as CurType, a.BranchId 
from tbl_StudentLedger a , tbl_CodeForTutionFees b
where a.valid = 1 and ltrim(rtrim(a.ItemId)) = LTRIM(RTRIM(b.SlNo))  
and a.BranchId = b.BranchId and b.SlNO = 10 
and a.Quota IN ('Foreign') and a.ARDate <= @uptoDate
--and a.ARDate <= @dateUpto 
and a.Session like '%'+@Session +'%' and a.BatchNo like '%'+@BatchNo + '%' and a.RollNo LIKE '%'+@RollNo +'%' and a.BranchId = @BranchId 
group by a.Quota,a.Session , a.BatchNo , a.RollNo ,  a.ItemId , b.name , a.BranchId 
having SUM(a.FCDueAmt-a.FCPaidAmt) <> 0
UNION ALL
select 3 as SlNo ,a.Quota,a.Session , a.BatchNo , a.RollNo ,a.ItemId , b.name as ItemName,  0 AS NoofMonth,
sum(a.FCDueAmt-a.FCPaidAmt) as due ,
'' as Particulars  ,'(FC)' as CurType , a.BranchId 
from tbl_StudentLedger a , tbl_CodeForTutionFees b
where a.valid = 1 and ltrim(rtrim(a.ItemId)) = LTRIM(RTRIM(b.SlNo))  
and a.BranchId = b.BranchId and b.slno NOT IN (4,10,6,11,17,18,26,30)
and a.Quota IN ('Foreign') and a.ARDate <= @uptoDate
--and a.ARDate <= @dateUpto 
and a.Session like '%'+@Session +'%' and a.BatchNo like '%'+@BatchNo + '%' and a.RollNo LIKE '%'+@RollNo +'%' and a.BranchId = @BranchId 
group by a.Quota,a.Session , a.BatchNo , a.RollNo ,  a.ItemId , b.name , a.BranchId 
having SUM(a.FCDueAmt-a.FCPaidAmt) <> 0
UNION ALL
select 4 as SlNo ,a.Quota,a.Session , a.BatchNo , a.RollNo ,99 as ItemId , 'Others' as ItemName,  0 AS NoofMonth,
sum(a.FCDueAmt-a.FCPaidAmt) as due ,
'' as Particulars  ,'(FC)' as CurType , a.BranchId 
from tbl_StudentLedger a , tbl_CodeForTutionFees b
where a.valid = 1 and ltrim(rtrim(a.ItemId)) = LTRIM(RTRIM(b.SlNo))  
and b.slno IN (6,11,17,18,26,30)
and a.BranchId = b.BranchId 
and a.Quota IN ('Foreign') and a.ARDate <= @uptoDate
--and a.ARDate <= @dateUpto 
and a.Session like '%'+@Session +'%' and a.BatchNo like '%'+@BatchNo + '%' and a.RollNo LIKE '%'+@RollNo +'%' and a.BranchId = @BranchId 
group by a.Session , a.BatchNo , a.RollNo ,a.Quota  , a.BranchId 
having SUM(a.FCDueAmt-a.FCPaidAmt) <> 0
order by Session , BatchNo , Quota desc,RollNo 

--drop table tmpStudentDueSpecial
--select * INTO tmpStudentDueSpecial from #tmpStudentDueSpecial


--select * from tmpStudentDueSpecial

SELECT aa.SlNo,aa.quota,aa.session,aa.batchNo,aa.RollNo , 
bb.Name,bb.ContactNo,
aa.ItemId , aa.ItemName ,aa.SndSlno, aa.ColName , aa.ColValue , aa.BranchId 
into tmpStudentDueReport
FROM (
select SlNo,quota,session,batchNo,RollNo , ItemId , ItemName ,1 as SndSlno, 'Spell' as ColName , Particulars as ColValue , BranchId 
from #tmpStudentDueSpecial
where Particulars <> ''
UNION ALL
select SlNo,quota,session,batchNo,RollNo , ItemId , ItemName ,2 as SndSlno, 'Month' as ColName , convert(nvarchar(20),NoofMonth) as ColValue , BranchId 
from #tmpStudentDueSpecial
where NoofMonth <> 0
UNION ALL
select SlNo,quota,session,batchNo,RollNo , ItemId , ItemName , 3 as SndSlno,'Dues' as ColName , ltrim(rtrim(STR(Due)))+space(1)+CurType as ColValue , BranchId 
from #tmpStudentDueSpecial
where Due <> 0
UNION ALL
select 98 as SlNo,quota,session,batchNo,RollNo , 90 as ItemId , 'Total' as ItemName ,9 as SndSlno,'Total' as ColName , ltrim(rtrim(STR(SUM(Due))))+space(1)+CurType as ColValue , BranchId 
from #tmpStudentDueSpecial
where Due <> 0
group by quota,session,batchNo,RollNo,CurType , BranchId) aa , tbl_StudentAdmission bb
WHERE aa.branchId = bb.BranchId 
and  aa.Session = bb.Session 
and aa.BatchNo = bb.BatchNo 
and aa.RollNo = bb.RollNo 
UNION ALL
select 99 as SlNo,'Grand Total' as quota,'Grand Total' as session,'Grand Total' as batchNo,'Grand Total' as RollNo, '' as Name, '' as ContactNo, 99 as ItemId , 'Grand Total' as ItemName,9 as SndSlno,'Total' as ColName , ltrim(rtrim(STR(SUM(Due))))+ ' (Tk & FC)' as ColValue , BranchId 
from #tmpStudentDueSpecial
where Due <> 0 GROUP BY BranchId
order by  aa.SlNo,aa.quota,aa.session,aa.batchNo,aa.RollNo


select * from tmpStudentDueReport
END
GO
