CREATE PROC [dbo].[SP_SINGLE_ITEM_LEDGER] (@mainCatId AS Int,@dateFrom date,@dateto date,@itemId int)
AS
IF @itemId!=0 
BEGIN
SELECT 0 AS Id, a.ItemId, '-' AS TrNo,@dateFrom AS TrDate,'Opening' AS Description,b.BrandName,b.MainCatName,b.ColorName,Isnull(SUM(a.InQty-a.OutQty-a.PRtnQty+a.RtnQty),0) AS OpBalQty,0 AS InQty,0 AS OutQty,0 AS PrtnQty,0 AS RtnQty
FROM tbl_STOCK_LEDGER  a LEFT JOIN VW_GET_ITEM_DETAILS  b ON a.ItemId=b.Id
WHERE a.TrDate < @dateFrom AND b.MainCatId=@mainCatId AND a.ItemId=@itemId
Group by a.ItemId,b.BrandName,b.MainCatName,b.ColorName
UNION ALL
SELECT a.Id, a.ItemId, a.TrNo,a.TrDate,
case 
when Left(a.TrNo,2)='PI' Then 'Purchase From : '+c.Name  
when Left(a.TrNo,2)='PR' Then 'Return To : '+c.Name  
when Left(a.TrNo,2)='SR' Then 'Return From : '+c.Name  
when Left(a.TrNo,2)='SI' Then 'Sales To : '+e.Name  
when Left(a.TrNo,2)='OB' Then ' Opening '
END AS Description,b.BrandName ,b.MainCatName,b.ColorName,0 AS OpBalQty,a.InQty,a.OutQty,a.PrtnQty,a.RtnQty
FROM tbl_STOCK_LEDGER  a LEFT JOIN VW_GET_ITEM_DETAILS b ON a.ItemId=b.Id LEFT JOIN tbl_SUPPLIER_INFO_MASTER c ON a.SuppId=c.Id  LEFT JOIN tbl_CUSTOMER e ON a.SuppId=e.Id
WHERE a.TrDate Between  @dateFrom AND @dateto  AND a.ItemId=@itemId
Order by id
end






GO
