create PROC [dbo].[SP_SMS_DrHonorarium](@invDate date, @invNo nvarchar(50), @drCode nvarchar(50))
AS

BEGIN

SELECT sum(aa.CurrentHonorarium) as Honorarium, SUM(aa.PrevHonorium) AS PrevHonorarium FROM(
select SUM(PathCom+ElisaCom+USGCom+CTScanCom+XRayCom+BMDCom+ECGCom+ECHOCom+EEGCom
+ETTCom+MRICom+OTHERSCom-LessByDr) as PrevHonorium, 0 as CurrentHonorarium from tmpDrCommForWeb
WHERE InvNo != @invNo AND DueAmt = 0
UNION ALL
select 0 as PrevHonorium, SUM(PathCom+ElisaCom+USGCom+CTScanCom+XRayCom+BMDCom+ECGCom+ECHOCom+EEGCom
+ETTCom+MRICom+OTHERSCom-LessByDr) as CurrentHonorarium from tmpDrCommForWeb
WHERE InvNo = @invNo AND DueAmt = 0
) aa

----SELECT SUM(aa.Honorarium-aa.DrLess) AS Honorarium, SUM(aa.DrLess) AS DrLess, SUM(aa.PrevHonorarium-aa.PrevDrLess) as PrevHonorarium, SUM(aa.PrevDrLess) AS PrevDrLess FROM (
----select SUM((CASE WHEN RefFeePcOrTk = 'Tk.' then b.RefFee ELSE a.TotalAmount * 0.01 * b.RefFee end)) as Honorarium, 0 as DrLess,
----0 as PrevHonorarium, 0 as PrevDrLess
----from InvDetails a , ClinicalChart b
----where a.Pcode=b.pcode AND  a.isPaidDrComm = 0 AND a.PaidDate <= @invDate AND a.RefDrCode = @drCode AND a.InvNo = @invNo
----and a.valid =1 AND a.isHide = 1 and InvNo IN (SELECT PrevInvNo FROM SalesLedger WHERE Valid = 1 GROUP BY PrevInvNo HAVING SUM(Sales - Collection - Less - ReturnAmount) = 0)
----GROUP BY a.PaidDate
----UNION ALL
----select 0 as Honorarium, SUM(a.LessByDr) as DrLess, 0 as PrevHonorarium, 0 as PrevDrLess 
----from SalesLedger a, InvMaster b
----where a.PrevInvNo = b.InvNo AND a.isPaid= 0 AND a.PaidDate <= @invDate AND b.RefDrCode = @drCode AND a.PrevInvNo = @invNo
----and a.valid =1
----HAVING SUM(Sales - Collection - Less - ReturnAmount) = 0
----UNION ALL
----select 0 as Honorarium, 0 as DrLess,
----SUM((CASE WHEN RefFeePcOrTk = 'Tk.' then b.RefFee ELSE a.TotalAmount * 0.01 * b.RefFee end)) as PrevHonorarium, 0 as PrevDrLess
----from InvDetails a , ClinicalChart b
----where a.Pcode=b.pcode and a.isPaidDrComm = 0 
----AND a.PaidDate <= @invDate AND a.RefDrCode = @drCode AND a.InvNo <> @invNo
----and a.valid =1 AND a.isHide = 1 AND InvNo IN (SELECT PrevInvNo FROM SalesLedger WHERE Valid = 1 GROUP BY PrevInvNo HAVING SUM(Sales - Collection - Less - ReturnAmount) = 0)
----UNION ALL
----select 0 as Honorarium, 0 as DrLess, 0 as PrevHonorarium, SUM(a.LessByDr) as PrevDrLess
----from SalesLedger a, InvMaster b
----where a.PrevInvNo = b.InvNo AND a.isPaid= 0 AND a.PaidDate <= @invDate AND b.RefDrCode = @drCode AND a.PrevInvNo <> @invNo
----and a.valid =1
----HAVING SUM(Sales - Collection - Less - ReturnAmount) = 0
----) aa


end

