CREATE procedure [dbo].[sp_SMSGenerateForWishes] (@lcMessageFor nvarchar(100),@dateFrom date , @dateTo date , @Message nvarchar(1000))
as
Begin
	if @lcMessageFor = 'Confirmation SMS'
	begin
		select mobileNo,Name,Code,designation,department,Email,'Y' as YesNo,
		Replace(@Message,'XXXName',Name) as Msg from HREmployeeMaster
	end
	if @lcMessageFor = 'Birthday wishing SMS/Card'
	begin
		select mobileNo,Name,Code,designation,department,Email,'Y' as YesNo,
		Replace(@Message,'XXXName',Name) as Msg 
		--, convert(nvarchar(20),datediff(Year,DateofBirth,getdate()))+'Yrs.' as Age,DateofBirth
		from HREmployeeMaster
		WHERE MONTH(DateofBirth) BETWEEN month(@dateFrom) and Month(@DateTo) 
	end
end
