CREATE proc [dbo].[SP_StDuesDtlsReport_Foreign] (@DeptName nvarchar(50), 
 @Session nvarchar(50), @BatchNo nvarchar(50),@RollNo nvarchar(50), @Particulars nvarchar(50))
As
Select a.SlNo, a.ItemId, a.ItemName, a.FeesType, SUM(a.FCDueAmt -a.FCPaidAmt-a.LessAmt) FCDueAmt, SUM(a.FCPaidAmt) AS FCPaidAmt, SUM(a.LessAmt) As LessAmt, SUM(a.FCDueAmt) As TotalAmt, a.Particulars,
b.DeptName, b.Session, b.BatchNo, b.Name, b.RollNo, a.PaidDate  
From tbl_StudentLedger a, tbl_StudentAdmission b
 Where a.Valid = 1 AND a.isYearClosed=0 AND a.Quota='Foreign'  
 AND b.Valid=1 AND a.RollNo=b.RollNo AND a.DeptName=b.DeptName AND a.Session=b.Session AND a.BatchNo=b.BatchNo
and a.DeptName=@DeptName and a.Session=@Session and a.BatchNo=@BatchNo and a.RollNo=@RollNo AND a.Particulars=@Particulars
Group By a.SlNo, a.ItemId, a.ItemName, a.FeesType, a.Particulars, b.DeptName, b.Session, b.BatchNo, b.Name, b.RollNo, a.PaidDate 
 Order By a.SlNo
GO
