CREATE PROC [dbo].[SP_STICKER_PRINT] (@invNo nvarchar(50), @branchId INT, @department VARCHAR(50))
AS
BEGIN
	/* EXEC SP_STICKER_PRINT 'DIA230700954', 1, 'X-RAY' */
	select a.InvNo, a.InvDate, b.PatientId, b.RegNo, b.BedNo, b.Address, b.DOB, b.PatientName, b.Age, b.Sex, b.PtStatus, b.MobNo, b.RefDrCode, b.RefDrName, 
	b.ConsultantName, b.ConsultantCode, b.BranchId,
	SUBSTRING(
		(SELECT ', ' + d.ShortDesc 
		FROM InvDetails d 
		left join ClinicalChart c on d.BranchId = c.BranchId AND d.PCode=c.PCode 
		where d.InvNo=@invNo AND d.BranchId = @branchId and c.SubSubDeptName = @department ORDER BY d.ShortDesc
		FOR XML PATH('')), 2 , 300
	) As ShortDesc

	from InvDetails a
	left join InvMaster b on a.BranchId = b.BranchId AND a.InvNo=b.InvNo and a.InvDate=b.invDate
	left join ClinicalChart c on  a.BranchId = c.BranchId AND a.PCode=c.PCode
	where c.SubSubDeptName = @department and a.InvNo=@invNo and a.Valid=1 AND a.BranchId = @branchId
	group by a.InvNo, a.InvDate, b.RegNo, b.Address, b.DOB, b.PatientName, b.Age, b.Sex, b.PtStatus, 
	b.MobNo, b.RefDrCode, b.RefDrName, b.ConsultantName, b.ConsultantCode, b.BranchId, b.BedNo, b.PatientId
END
