CREATE Procedure [dbo].[SP_StockAdjustReportDetails] @BranchId int, @UnitId int, @DateFrom date, @DateTo date, @companyId nvarchar(20), @StoreId nvarchar(20) 
AS --- EXEC SP_StockAdjustReportDetails 1, 1, '2024-09-30', '2024-09-30', '', ''
BEGIN
SELECT c.Company_Id, c.Name AS CompanyName, a.InvoiceDate, a.InvoiceNo, a.ProductId, a.ProductName, a.InQty, a.TpPrice, a.InQty*a.TpPrice AS InTotalTp, 
a.OutQty, a.OutQty*a.TpPrice AS OutTotalTp, a.ExpireDate, a.EntryDate, a.UserName, d.SubSubPno
FROM PharStockAdjustDetails a
LEFT JOIN PharProductInfo b ON a.ProductId=b.Id
LEFT JOIN PharCompanyInfo c ON b.CompanyId=c.Company_Id
LEFT JOIN ProjectInformations d On a.StoreId = d.PnoCode
WHERE a.Valid=1 AND a.BranchId=@BranchId AND InvoiceDate Between @DateFrom AND @DateTo 
AND c.Company_Id LIKE '%'+@companyId+'%' AND a.StoreId LIKE '%'+@StoreId+'%'
END
