CREATE Procedure [dbo].[SP_StockAdjustReportSMZ] @BranchId int, @UnitId int, @DateFrom date, @DateTo date, @CompanyId nvarchar(20),
@StoreId nvarchar(20)
AS --- EXEC SP_StockAdjustReportSMZ 1, 1, '2023-01-01', '2023-10-16', '', ''
BEGIN
select a.CompanyId, b.Name, sum(a.TotalTP) as AdjustAmt, sum(a.ProductQty) as AdjustQty, c.SubSubPno
From  PharStockAdjustDetails a
Left join PharCompanyInfo b On a.CompanyId=b.Company_Id
LEFT Join ProjectInformations c On a.StoreId=c.PnoCode
WHERE a.Valid=1 AND a.BranchId=@BranchId AND a.UnitId=@UnitId AND a.InvoiceDate Between @DateFrom AND @DateTo AND  a.CompanyId LIKE '%'+@CompanyId+'%' AND a.StoreId LIKE '%'+@StoreId+'%'
GROUP BY b.Name, a.CompanyId, c.SubSubPno
ORDER BY a.CompanyId
END
