CREATE Procedure [dbo].[SP_StockTransferSMZ] @BranchId int , @UnitId int, @DateFrom date , @DateTo date , @FromStoreId int
AS ---- SP_StockTransferSMZ 1, 1, '2023-10-01', '2023-10-31', 139
BEGIN
select a.FromStoreId, a.FromStore, a.ToStoreId, a.ToStore, a.CompanyId, b.Name as CompanyName, sum(a.StockOutQty) as TransferQty, sum(a.TotalTp) as TotalTp From PHAR_STOCK_TRANSFER a
Left join PharCompanyInfo b On a.CompanyId=b.Company_Id
WHERE FromBranchId = @BranchId AND FromUnitId = @UnitId AND TrDate Between @DateFrom AND @DateTo AND FromStoreId = @FromStoreId
GROUP BY  FromStoreId, FromStore, ToStoreId, ToStore, CompanyId, b.Name
ORDER BY a.FromStoreId
END
