CREATE PROCEDURE [dbo].[sp_Student_Collection] (@DateFrom Date , @DateTo Date) 
AS
DROP TABLE tmp_StudentSalary_BBCL
BEGIN

DECLARE @cols AS NVARCHAR(MAX),
    @query  AS NVARCHAR(MAX);

SET @cols = STUFF((SELECT distinct ',' + QUOTENAME(c.Particulars) 
            FROM tbl_StudentFeesCollectionDtls c
            FOR XML PATH(''), TYPE
            ).value('.', 'NVARCHAR(MAX)') 
        ,1,1,'')

set @query = 'SELECT PaidTrDate, PaidTrNo, MrNo, Name, BatchNo, RollNo, AccountNo, BankName, BankBrName, CollectionType, InstituteName, ' + @cols + ' INTO tmp_StudentSalary_BBCL from 
            (
                select a.PaidTrDate, a.PaidTrNo, a.MrNo, a.Name,a.BatchNo,a.RollNo, b.AccountNo, b.BankName, b.BankBrName, b.CollectionType, b.NameOfInstitute as InstituteName
                    , Particulars
					, receiveAmt
                from tbl_StudentFeesCollectionDtls a
				LEFT JOIN tbl_StudentFeesCollection b ON a.MrNo=b.MrNo AND a.PaidTrNo=b.PaidTrNo AND a.PaidTrDate=b.PaidTrDate AND a.RollNo=b.RollNo AND a.BatchNo=b.BatchNo
           ) x
            pivot 
            (
                 SUM(receiveAmt)
                for Particulars in (' + @cols + ')
            ) p '


execute(@query)

select PaidTrDate, PaidTrNo, MrNo, Name, BatchNo, RollNo, AccountNo, BankName, BankBrName, CollectionType, InstituteName, ISNULL([Admission Fee],0) AS AdmissionFee, ISNULL([For Internship Allowance],0) AS ForInternshipAllowance, ISNULL([Tution Fee],0) AS TutionFee, ISNULL([Tution Late Fee],0) AS TutionLateFee, ISNULL([Session Charge],0) AS SessionCharge, ISNULL([Hostel Seat Rent],0) AS HostelSeatRent, ISNULL([Hostel Placement Fee],0) AS HostelPlacementFee, ISNULL([Exam Fee],0) AS ExamFee,  ISNULL([Session Fee],0) AS SessionFee, ISNULL([Admission Form Fee],0) AS AdmissionFormFee, ISNULL([BM&DC Registration Fee],0) AS BMDCRegistrationFee, ISNULL(Miscellaneous,0) AS Miscellaneous, ISNULL([BNMC Registration Fees]+[Supplementary Exam Fee]+[Re-admission Fee]+[Form fill up Charge],0) AS Others
from tmp_StudentSalary_BBCL 
where PaidTrDate BETWEEN @DateFrom AND @DateTo 

--BEGIN
--	SELECT a.PaidTrDate,a.PaidTrNo, a.MrNo , a.Name,a.BatchNo,a.RollNo , a.Particulars , SUM(a.receiveAmt) AS Coll
--	INTO tmp_StudentSalary_BBCL
--	FROM tbl_StudentFeesCollectionDtls a
--	WHERE a.Valid = 1
--	and a.PaidTrDate BETWEEN @DateFrom AND @DateTo 
--	GROUP BY a.PaidTrDate,a.PaidTrNo, a.MrNo , a.Name,a.BatchNo,a.RollNo , a.Particulars
END



