CREATE Proc [dbo].[SP_StudentDuesDescWise](@DeptName nvarchar(50), @Session nvarchar(50),
 @BatchNo nvarchar(50), @RollNo nvarchar(50), @Particulars nvarchar(50))
AS
Begin
with data as ( 
		SELECT Id, ARDate,DeptName, Session, BatchNo, RollNo, StudentName, Particulars, ItemId, ItemName, DueAmt, 0 As ReceiveAmt,
		 '' As MrNo, null AS PaidDate , (DueAmt - ReceiveAmt) as CTotal
		FROM tbl_StudentLedger WHERE Valid=1	
		AND DueAmt <> 0 
		AND isYearClosed = 0 AND Quota <> 'Foreign' 
		and DeptName=@DeptName and Session=@Session and BatchNo=@BatchNo and RollNo=@RollNo and Particulars=@Particulars
		UNION ALL 
		SELECT Id, ARDate,DeptName, Session, BatchNo, RollNo, StudentName, Particulars, ItemId, ItemName,
		 0 AS DueAmt, ReceiveAmt, MrNo, PaidDate, (DueAmt - ReceiveAmt) as CTotal
		FROM tbl_StudentLedger WHERE Valid=1		
		AND isYearClosed = 0 AND Quota <> 'Foreign' AND ReceiveAmt <> 0
		and DeptName=@DeptName and Session=@Session and BatchNo=@BatchNo and RollNo=@RollNo and Particulars=@Particulars
)
select
 ARDate, DeptName, Session, BatchNo, RollNo, StudentName, ItemId, ItemName, MrNo, PaidDate, DueAmt, ReceiveAmt,
  sum(CTotal) over (order by ItemId, Ardate, Id asc rows between unbounded preceding and current row) as CumTotal
from data;

End



GO
