CREATE PROCEDURE [dbo].[SP_TF_StudentLedger] (@SessionStart date, @SessionEnd date, @DeptName nvarchar(50), @RollNo nvarchar(50),
 @Session nvarchar(50), @BatchNo nvarchar(50), @Quota nvarchar(50), @UserName nvarchar(50), @branchId int)
AS 
BEGIN
DECLARE @SessionInit date
DECLARE @Year int
DECLARE @MonthName nvarchar(50) 
DECLARE @count INT;
DECLARE @Duration INT;
DECLARE @SlNo INT
SET @SessionInit = @SessionStart

Select @Duration = Duration from tbl_Session_TutionFees 
WHERE Valid=1 AND SessionDeptName = @DeptName AND SessionName= @Session

SET @count = 0;
SET @SlNo = 1;
SET @SlNo = @SlNo + @count
WHILE @count < 1
BEGIN
 	SET @MonthName = DATENAME(month, @SessionStart) + '/' + CONVERT(varchar(50), Cast(YEAR(DATEADD(year, @count, @SessionStart)) AS varchar(4)));
    INSERT INTO tbl_StudentLedger (SessionStart, SessionEnd, Session, DeptName, BatchNo, ItemId, ItemName, FeesType, DueAmt,  
    DeptId, Duration, StudentId, RollNo, StudentName, TrNo, TrDate, AdmissionMName, AdmissionMonth,ARYear, ARMonth, ARMName, YearCode, UserName, ARDate, Particulars, SlNo, RegNo, NameOfInstitute, Quota, BranchId)
	SELECT @SessionStart, @SessionEnd, a.Session, a.DeptName, a.BatchNo, a.ItemId,a.ItemName +' - '+@MonthName, a.FeesType, a.Amount, 
    c.Id, b.Duration, b.RollNo, b.RollNo, b.Name, b.TrNo, b.TrDate, datename(mm, getdate()) AS MonthName, month(getdate()) AS Month,  cast(Year(@SessionStart) as varchar), cast(Month(@SessionStart) as varchar), DATENAME(mm, @SessionStart), cast(Year(@SessionStart) as varchar), @UserName, @SessionStart, a.Particulars
	 ,@SlNo, b.RegNo, b.NameOfInstitute, @Quota, @branchId
	FROM tbl_StudentFeesRegDtls a, tbl_StudentAdmission b, tbl_Department_TutionFees c 
	WHERE a.BranchId = b.BranchId AND a.BranchId = @branchId AND a.Valid=1 AND b.Valid=1 AND c.Valid=1 AND a.DeptName = b.DeptName AND a.Session = b.Session AND a.BatchNo = b.BatchNo AND a.DeptName = c.DeptName
	AND a.FeesType =  'OneTime' AND a.Amount > 0 AND b.RollNo = @RollNo AND b.DeptName = @DeptName AND b.Session = @Session AND b.BatchNo = @BatchNo AND a.StudentType=@Quota 
    Group By a.Session, a.DeptName, a.BatchNo, a.ItemId, a.ItemName, a.FeesType, a.Amount, c.Id,
	b.Duration, b.RollNo, b.Name, b.TrNo, b.TrDate, a.Particulars, b.RegNo, b.NameOfInstitute
	SET @count = @count + 1;
	SET @SlNo = @SlNo + @count
END

SET @SessionStart = @SessionInit 
SET @count = 0;
SET @SlNo = @SlNo + @count
WHILE @count < (@Duration * 1)
BEGIN
 SET @MonthName = DATENAME(mm, @SessionStart)  + '/' + cast(Year(@SessionStart) as varchar);
    INSERT INTO tbl_StudentLedger (SessionStart, SessionEnd, Session, DeptName, BatchNo, ItemId, ItemName, FeesType, DueAmt,  
    DeptId, Duration, StudentId, RollNo, StudentName, TrNo, TrDate, AdmissionMName, AdmissionMonth, ARYear, ARMonth, ARMName, YearCode, UserName, ARDate, Particulars, SlNo, RegNo, NameOfInstitute, Quota, BranchId)
	SELECT @SessionStart, @SessionEnd, a.Session, a.DeptName, a.BatchNo, a.ItemId, a.ItemName +' - '+@MonthName, a.FeesType, a.Amount,  
    c.Id,b.Duration, b.RollNo, b.RollNo, b.Name, b.TrNo, b.TrDate, datename(mm, getdate()) AS MonthName, month(getdate()) AS Month,  cast(Year(@SessionStart) as varchar), cast(Month(@SessionStart) as varchar), DATENAME(mm, @SessionStart), cast(Year(@SessionStart) as varchar), @UserName, @SessionStart, a.Particulars	 
	, @SlNo, b.RegNo, b.NameOfInstitute, @Quota, @branchId	
	FROM tbl_StudentFeesRegDtls a, tbl_StudentAdmission b, tbl_Department_TutionFees c 
	WHERE a.BranchId = b.BranchId AND a.BranchId = @branchId AND a.Valid=1 AND b.Valid=1 AND c.Valid=1 AND a.DeptName = b.DeptName AND a.Session = b.Session AND a.BatchNo = b.BatchNo AND a.DeptName = c.DeptName
	AND a.FeesType =  'Yearly' AND a.Amount > 0 AND b.RollNo = @RollNo AND b.DeptName = @DeptName AND b.Session = @Session AND b.BatchNo = @BatchNo AND a.StudentType=@Quota  
    Group By a.Session, a.DeptName, a.BatchNo, a.ItemId, a.ItemName, a.FeesType, a.Amount, c.Id,
	b.Duration, b.RollNo, b.Name, b.TrNo, b.TrDate, a.Particulars, b.RegNo, b.NameOfInstitute 			 
SET @count = @count + 1;
SET @SessionStart = DATEADD(YEAR, 1, @SessionStart);	
SET @SlNo = @SlNo + @count
END

SET @SessionStart = @SessionInit 
SET @count = 0;
SET @SlNo = @SlNo + @count
 WHILE @count < (@Duration * 2)
BEGIN
SET @MonthName = DATENAME(mm, @SessionStart)  + '/' + cast(Year(@SessionStart) as varchar);
    INSERT INTO tbl_StudentLedger (SessionStart, SessionEnd, Session, DeptName, BatchNo, ItemId, ItemName, FeesType, DueAmt,  
