SET @SessionStart = DATEADD(MONTH, 6, @SessionStart);
SET @count = @count + 1;
SET @SlNo = @SlNo + @count
 END

 SET @SessionStart = @SessionInit 
 SET @count = 0; 
 SET @SlNo = @SlNo + @count
 WHILE @count < (@Duration * 4)
BEGIN
 SET @MonthName = DATENAME(mm, @SessionStart)  + '/' + cast(Year(@SessionStart) as varchar);
    INSERT INTO tbl_StudentLedger (SessionStart, SessionEnd, Session, DeptName, BatchNo, ItemId, ItemName, FeesType, FCDueAmt,  
