/****** Object:  StoredProcedure [dbo].[sp_TotalSalesCollItemWiseForAurora]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


create PROCEDURE [dbo].[sp_TotalSalesCollItemWiseForAurora] (@DateFrom date ,@DateTo date ,@BranchId int)
AS 

---drop table tmpForCheck

BEGIN

	select SUM(Sales) as Sales, SUM(Collection) as Coll,SUM(Less) as Less , 
	SUM(ReturnAmount)  as RtnAmt , ROUND((SUM(Collection)/SUM(Sales)),6) as CollRatio , 
	ROUND((SUM(Less)/SUM(Sales)),6) as LessRatio,ROUND((SUM(ReturnAmount)/sum(Sales)),6) as RtnRatio
	INTO #z
	from SalesLedger where refdate BETWEEN @DateFrom and @DateTo and BranchId = @BranchId
	and valid <> 0

--	drop table tmpRatio1

	select SUM(TotalAmount) as Sales, SUM(Collection) as Coll,SUM(Less) as Less , 
	SUM(ReturnAmt)  as RtnAmt , ROUND((SUM(Collection)/SUM(TotalAmount)),6) as CollRatio , 
	ROUND((SUM(Less)/SUM(TotalAmount)),6) as LessRatio,ROUND((SUM(ReturnAmt)/sum(TotalAmount)),6) as RtnRatio
	INTO #z1
	from PatientLedger where refdate BETWEEN @DateFrom and @DateTo and BranchId = @BranchId
	and valid <> 0

	select SUM(Sales) as Sales, SUM(Collection) as Coll,SUM(LessAmt) as Less , 
	SUM(ReturnAmt)  as RtnAmt , ROUND((SUM(Collection)/SUM(Sales)),6) as CollRatio , 
	ROUND((SUM(LessAmt)/SUM(Sales)),6) as LessRatio,ROUND((SUM(ReturnAmt)/sum(Sales)),6) as RtnRatio
	INTO #z2
	from PharSalesLedger where TrDate BETWEEN @DateFrom and @DateTo and BranchId = @BranchId
	and valid <> 0

	select 2 as SlNo,b.PCode,b.ShortDesc,SUM(b.TotalAmount)/count(*) as Amount , count(*) as NoofQty , 
	SUM(b.TotalAmount) as Sales ,
	(SUM(b.TotalAmount * c.CollRatio)) as Coll ,  (SUM(b.TotalAmount * c.LessRatio)) as Less , 
	(SUM(b.TotalAmount * c.RtnRatio)) as RtnAmt , 'Ourdoor' as DeptName
	--INTO #tmpCheck
	from InvMaster a
	LEFT JOIN invDetails b ON a.BranchId = b.BranchId AND a.InvNo=b.InvNo and a.InvDate=b.InvDate
	CROSS JOIN #z c 
	LEFT JOIN ClinicalChart d ON b.branchId=d.BranchId AND b.PCode=d.PCode
	where --a.invNo=b.InvNo and a.InvDate = b.InvDate and b.pCode=d.PCode and b.branchId=d.BranchId and 
	a.InvDate BETWEEN @DateFrom and @DateTo and a.BranchId = @BranchId 
	and a.Valid <> 0 and b.Valid <> 0
	GROUP BY b.PCode,b.ShortDesc
	


	UNION ALL
	select 1 as SlNo ,b.PCode,b.Description as ShortDesc,SUM(a.TotalAmount)/count(*) as Amount , count(*) as NoofQty , 
	SUM(a.TotalAmount) as Sales ,
	(SUM(a.TotalAmount * c.CollRatio)) as Coll ,  (SUM(a.TotalAmount * c.LessRatio)) as Less , 
	(SUM(a.TotalAmount * c.RtnRatio)) as RtnAmt , 'Indoor' as DeptName
	from PatientLedger a , ClinicalChart b , #z1 c
	where a.Code=b.PCode and a.BranchId = b.BranchId 
	and a.RefDate BETWEEN @DateFrom and @DateTo and a.BranchId = @BranchId 
	and a.Valid <> 0 
	GROUP BY b.PCode,b.Description
	UNION ALL
	select 3 as SlNo, CONVERT(nvarchar(20), a.storeId ) as PCode,b.SubsubPNo as ShortDesc,SUM(a.Sales) as Amount , 1 as NoofQty , 
	SUM(a.Sales) as Sales ,
	(SUM(a.Sales * c.CollRatio)) as Coll ,  (SUM(a.Sales * c.LessRatio)) as Less , 
	(SUM(a.Sales * c.RtnRatio)) as RtnAmt , 'Medicine' as DeptName
	from PharSalesLedger a , ProjectInformations b, #z2 c
	where a.storeId=b.PNoCode 
	and a.TrDate BETWEEN @DateFrom and @DateTo and a.BranchId = @BranchId 
	and a.Valid <> 0 
	GROUP BY a.storeId,b.SubsubPNo
	UNION ALL
	SELECT 4,'-','Grand Total',SUM(cc.Sales) As Sales,1 as NoofQty,SUM(cc.Sales) As Sales,
	SUM(cc.Coll) As Coll,SUM(cc.Less) As Less,SUM(cc.RtnAmt) As RtnAmt,'GTotal' as DeptName
	FROM 
	(
	select Sales,Coll,Less,RtnAmt from #z
	UNION ALL
	select Sales,Coll,Less,RtnAmt from #z1
	UNION ALL
	select Sales,Coll,Less,RtnAmt from #z2) cc

	--SELECT SUM(Sales) AS Sales, SUM(Coll) Coll, SUM(Less) less, SUM(RtnAmt) AS RtnAmt FROM #tmpCheck where SlNo!=4
	--SELECT SUM(Sales) AS Sales, SUM(Coll) Coll, SUM(Less) less, SUM(RtnAmt) AS RtnAmt FROM #tmpCheck where SlNo=4

----------For Check Purpose
--------	DROP TABLE #z 
--------	DROP TABLE #z1
--------	DROP TABLE #z2
--------	DROP TABLE tmpForCheck


--------	select SUM(Sales) as Sales, SUM(Collection) as Coll,SUM(Less) as Less , 
--------	SUM(ReturnAmount)  as RtnAmt , ROUND((SUM(Collection)/SUM(Sales)),6) as CollRatio , 
--------	ROUND((SUM(Less)/SUM(Sales)),6) as LessRatio,ROUND((SUM(ReturnAmount)/sum(Sales)),6) as RtnRatio
--------	INTO #z
--------	from SalesLedger where refdate BETWEEN '2024-04-01' and '2024-04-01' and BranchId = 1
--------	and valid <> 0

--------	select * from #z
----------	drop table tmpRatio1

--------	select SUM(TotalAmount) as Sales, SUM(Collection) as Coll,SUM(Less) as Less , 
--------	SUM(ReturnAmt)  as RtnAmt , ROUND((SUM(Collection)/SUM(TotalAmount)),6) as CollRatio , 
--------	ROUND((SUM(Less)/SUM(TotalAmount)),6) as LessRatio,ROUND((SUM(ReturnAmt)/sum(TotalAmount)),6) as RtnRatio
--------	INTO #z1
--------	from PatientLedger where refdate BETWEEN '2024-04-01' and '2024-04-01' and BranchId = 1
--------	and valid <> 0

--------	select * from #z1

--------	select SUM(Sales) as Sales, SUM(Collection) as Coll,SUM(LessAmt) as Less , 
--------	SUM(ReturnAmt)  as RtnAmt , ROUND((SUM(Collection)/SUM(Sales)),6) as CollRatio , 
--------	ROUND((SUM(LessAmt)/SUM(Sales)),6) as LessRatio,ROUND((SUM(ReturnAmt)/sum(Sales)),6) as RtnRatio
--------	INTO #z2
--------	from PharSalesLedger where TrDate BETWEEN '2024-04-01' and '2024-04-01' and BranchId = 1
--------	and valid <> 0

--------	select * from #z2 


--------	select 2 as SlNo,b.PCode,b.ShortDesc,SUM(b.TotalAmount)/count(*) as Amount , count(*) as NoofQty , 
--------	SUM(b.TotalAmount) as Sales ,
--------	(SUM(b.TotalAmount * c.CollRatio)) as Coll ,  (SUM(b.TotalAmount * c.LessRatio)) as Less , 
--------	(SUM(b.TotalAmount * c.RtnRatio)) as RtnAmt , 'Ourdoor' as DeptName
----------	INTO tmpForCheck
--------	from InvMaster a , invDetails b , #z c , ClinicalChart d
--------	where a.invNo=b.InvNo and a.InvDate = b.InvDate and b.pCode=d.PCode and b.branchId=d.BranchId
--------	and a.InvDate BETWEEN '2024-04-01' and '2024-04-01' and a.BranchId = 1
--------	and a.Valid <> 0 and b.Valid <> 0
--------	GROUP BY b.PCode,b.ShortDesc


--------	UNION ALL
--------	select 1 as SlNo ,b.PCode,b.Description as ShortDesc,SUM(a.TotalAmount)/count(*) as Amount , count(*) as NoofQty , 
--------	SUM(a.TotalAmount) as Sales ,
--------	(SUM(a.TotalAmount * c.CollRatio)) as Coll ,  (SUM(a.TotalAmount * c.LessRatio)) as Less , 
--------	(SUM(a.TotalAmount * c.RtnRatio)) as RtnAmt , 'Indoor' as DeptName
--------	from PatientLedger a , ClinicalChart b , #z1 c
--------	where a.Code=b.PCode and a.BranchId = b.BranchId 
--------	and a.RefDate BETWEEN '2024-04-01' and '2024-04-01' and a.BranchId = 1
--------	and a.Valid <> 0 
--------	GROUP BY b.PCode,b.Description
--------	UNION ALL
--------	select 3 as SlNo ,a.storeId as PCode,b.SubsubPNo as ShortDesc,SUM(a.Sales) as Amount , 1 as NoofQty , 
--------	SUM(a.Sales) as Sales ,
--------	(SUM(a.Sales * c.CollRatio)) as Coll ,  (SUM(a.Sales * c.LessRatio)) as Less , 
--------	(SUM(a.Sales * c.RtnRatio)) as RtnAmt , 'Medicine' as DeptName
--------	from PharSalesLedger a , ProjectInformations b, #z2 c
--------	where a.storeId=b.PNoCode 
--------	and a.TrDate BETWEEN '2024-04-01' and '2024-04-01' and a.BranchId = 1
--------	and a.Valid <> 0 
--------	GROUP BY a.storeId,b.SubsubPNo
--------	UNION ALL
--------	SELECT 4,'-','Grand Total',SUM(cc.Sales) As Sales,1 as NoofQty,SUM(cc.Sales) As Sales,
--------	SUM(cc.Coll) As Coll,SUM(cc.Less) As Less,SUM(cc.RtnAmt) As RtnAmt,'GTotal' as DeptName
--------	FROM 
--------	(
--------	select Sales,Coll,Less,RtnAmt from #z
--------	UNION ALL
--------	select Sales,Coll,Less,RtnAmt from #z1
--------	UNION ALL
--------	select Sales,Coll,Less,RtnAmt from #z2) cc


END
GO
