CREATE PROCEDURE [dbo].[SP_TransferAcc](@AcDate date, @BranchId int, @UserName nvarchar(100))
AS BEGIN

EXEC SP_HP_SalesCollSummarized @AcDate, @AcDate, @BranchId
UPDATE tbl_TRANSACT set Valid = 0, LogDtls = 'Cancel by '+@UserName where Trans_dt = @AcDate and FrNo='AutoFromSP' 

DECLARE	@AcCode varchar(50), @AcName varchar(100), @MainDept varchar(50), @Sales float, @Less float, @ReturnAmt float, @CashAmt float, @CardAmt float, @ChequeAmt float, @CashReturn float
 
DECLARE CUR_TEST CURSOR FAST_FORWARD FOR
	----SELECT AcCode, Description, MainDept, Sales, Less, ReturnAmt, CashAmt, CardAmt, ChequeAmt, CashReturn
 ----   FROM tmp_TransToTransact
 ----   ORDER BY SlNo;
 	SELECT AcCode, Description, MainDept, Sales, Less, ReturnAmt, CashAmt, CardAmt, ChequeAmt, CashReturn
    FROM tmp_TransToTransact
    ORDER BY SlNo;
OPEN CUR_TEST
FETCH NEXT FROM CUR_TEST INTO @AcCode, @AcName, @MainDept, @Sales, @Less, @ReturnAmt, @CashAmt, @CardAmt, @ChequeAmt, @CashReturn

declare @trno nvarchar(50);
	set @trno = (select RIGHT('00' + Convert(varchar,YEAR(@AcDate)), 2) + RIGHT('00' + Convert(varchar,MONTH(@AcDate)), 2) + RIGHT('0000'+ Convert(varchar,ISNULL(Max(Convert(integer, RIGHT(TrNo, 4))),0)+ 1), 4) AS TrNo from tbl_TRANSACT WHERE YEAR(Trans_dt) = YEAR(@AcDate) AND MONTH(Trans_dt) = MONTH(@AcDate))
	Declare @rowId as int;
	SEt @rowId = 1;
WHILE @@FETCH_STATUS = 0
BEGIN

	/*Sales*/
	if @Sales > 0
	BEGIN
	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	@AcCode, 0, @Sales, @AcName, @AcName, @trno, @AcDate, 1, @rowId, 'JV', @UserName, GETDATE(), 1, '',
	'2106010001', 1, '', null, '', '','AutoFromSP', 'C', '1', @MainDept, 1, '', '');

	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	'2106010001', @Sales, 0, 'A/R From Patient' , 'A/R From Patient', @trno, @AcDate, 1, @rowId, 'JV', @UserName, GETDATE(), 1, '',
	@AcCode, 1, '', NULL, '', '', 'AutoFromSP', 'D', '1', @MainDept, 1, '', '');
	END

	/*Less*/
	if @Less > 0
	BEGIN
	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	@AcCode, @Less, 0, @AcName, 'Discount given', @trno, @AcDate, 1, @rowId, 'JV', @UserName, GETDATE(), 1, '',
	'2106010001', 1, '', NULL, '', '','AutoFromSP', 'C', '2', @MainDept, 1, '', '');

	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress ) VALUES(
	'2106010001', 0, @Less, 'A/R From Patient', 'Discount Given', @trno, @AcDate, 1, @rowId, 'JV', @UserName, GETDATE(), 1, '',
	@AcCode, 1, '', NULL, '', '','AutoFromSP', 'D', '2', @MainDept, 1, '', '');
	END
	/*Return*/
	if @ReturnAmt > 0
	BEGIN
	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	@AcCode, @ReturnAmt, 0, @AcName, 'Return to patient', @trno, @AcDate, 1, @rowId, 'JV', @UserName, GETDATE(), 1, '',
	'2106010001', 1, '', NULL, '', '','AutoFromSP', 'C', '3', @MainDept, 1, '', '');

	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	'2106010001', 0, @ReturnAmt, 'A/R From Patient' , 'Return to patient', @trno, @AcDate, 1, @rowId, 'JV', @UserName, GETDATE(), 1, '',
	@AcCode, 1, '', NULL, '', '','AutoFromSP', 'D', '3', @MainDept, 1, '', '');
	END
	/*Cash*/
	if @CashAmt > 0
	BEGIN
	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	'2101020001', @CashAmt, 0, @AcName, 'Cash collection from patient', @trno, @AcDate, 1, @rowId, 'CV', @UserName, GETDATE(), 1, '',
	'2106010001', 1, '', NULL, '', '', 'AutoFromSP', 'C', '4', @MainDept, 1, '', '');

	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	'2106010001', 0, @CashAmt, 'A/R From Patient' , 'Cash collection from patient', @trno, @AcDate, 1, @rowId, 'CV', @UserName, GETDATE(), 1, '', '2101020001', 1, '', NULL, '', '', 'AutoFromSP', 'D', '4', @MainDept, 1, '', '');
	END

	/*Card*/
	if @CardAmt > 0
	BEGIN
	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	'2101010002', @CardAmt, 0, @AcName, 'Card amount collection', @trno, @AcDate, 1, @rowId, 'BV', @UserName, GETDATE(), 1, '',
	'2106010001', 1, '', null, '', '','AutoFromSP', 'C', '5', @MainDept, 1, '', '');

	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	'2106010001', 0, @CardAmt, 'A/R From Patient' , 'Card amount collection',@trno, @AcDate, 1, @rowId, 'BV', @UserName, GETDATE(), 1, '',
	'2101010002', 1, '', NULL, '', '','AutoFromSP', 'D', '5', @MainDept, 1, '', '');
	END

	/*Cheque*/
	if @ChequeAmt > 0
	BEGIN
	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	'2101010001', @ChequeAmt, 0, @AcName, 'Cheque collection',@trno, @AcDate, 1, @rowId, 'BV', @UserName, GETDATE(), 1, '',
	'2106010001', 1, '', NULL, '', '','AutoFromSP', 'C', '6', @MainDept, 1, '', '');

	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	'2106010001', 0, @ChequeAmt, 'A/R From Patient' , 'Cheque collection', @trno, @AcDate, 1, @rowId, 'BV', @UserName, GETDATE(), 1, '',
	'2101010001', 1, '', NULL, '', '','AutoFromSP', 'D', '6', @MainDept, 1, '', '');
	END

	/*Cash Return*/
	if @CashReturn > 0
	BEGIN
	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	'3102010001', @CashReturn, 0, 'Cash return to patient', 'Cash return to patient', @trno, @AcDate, 1, @rowId, 'CV', @UserName, GETDATE(), 1, '',
	'2101020001', 1, '', NULL, '', '','AutoFromSP', 'C', '7', @MainDept, 1, '', '');

	INSERT INTO dbo.tbl_TRANSACT(
	Code, Debit, Credit, Naration, Remark, TrNo, Trans_dt, Pno, SubTrNo, VoucherType, UserName, EntryDate, Valid, RefNo, 
	ContraCode, CostCenter, LcNo, LcDate, ShipmentNo, ChequeNo, FrNo, CorD, VrRefNo, CostDept, BranchId, LogDtls, IpAddress) VALUES(
	'2101020001', 0, @CashReturn, @AcName , 'Cash In Hand', @trno, @AcDate, 1, @rowId, 'CV', @UserName, GETDATE(), 1, '',
	'3102010001', 1, '', NULL, '', '','AutoFromSP', 'D', '7', @MainDept, 1, '', '');	
	END
	set @rowId += 1;
	 
	FETCH NEXT FROM CUR_TEST INTO @AcCode, @AcName, @MainDept, @Sales, @Less, @ReturnAmt, @CashAmt, @CardAmt, @ChequeAmt, @CashReturn
END
CLOSE CUR_TEST
DEALLOCATE CUR_TEST

DELETE FROM tbl_TRANSACT where (Debit+Credit) = 0

END
GO
