CREATE PROC [dbo].[SP_WEB_AccPartyLedgerDetails] @BranchId int, @PartyCode VARCHAR(20), @FromDate DATE, @ToDate DATE
AS /*EXEC SP_WEB_AccPartyLedgerDetails 1, 'S0006', '2022-08-01','2022-09-16' */
BEGIN

SELECT ISNULL(SUM(a.Debit-a.Credit), 0) AS OB INTO #OP FROM tbl_TRANSACT a 
WHERE a.BranchId = @BranchId AND PartyCode = @partyCode AND a.Code LIKE '4%' AND a.Trans_dt < '2022-08-01'

SELECT a.Id, a.Trans_dt, a.TrNo, b.Description AS Particulars, a.Naration, a.PartyCode, a.PartyName, c.OB, a.Debit, a.Credit,
SUM(a.Debit-a.Credit+c.OB) OVER(ORDER BY a.Id) AS Balance
FROM tbl_TRANSACT a
LEFT JOIN tbl_CHART_OF_ACCOUNTS b ON a.Code = b.Code
CROSS JOIN #OP c
WHERE a.BranchId = 1 AND a.PartyCode = @partyCode AND a.Code LIKE '4%' AND  a.Trans_dt BETWEEN @FromDate ANd @ToDate
GROUP BY a.Id, a.Trans_dt, a.TrNo, b.Description, a.Naration, a.PartyCode, a.PartyName, a.Debit, a.Credit, c.OB
ORDER BY a.PartyCode
END
GO
/****** Object:  StoredProcedure [dbo].[SP_WEB_AccPartyLedgerSmz]    Script Date: 3/12/2026 6:25:16 AM ******/
