CREATE PROC [dbo].[SP_WEB_AccPartyLedgerSmz] @BranchId int, @FromDate DATE, @ToDate DATE
AS /* EXEC SP_WEB_AccPartyLedgerSmz 1, '2022-08-01','2022-09-16' */
BEGIN

SELECT a.PartyCode, a.PartyName, SUM(a.Debit) AS Debit, SUM(a.Credit) AS Credit, SUM(a.Debit-a.Credit) AS Balance
INTO #temp
FROM tbl_TRANSACT a
WHERE a.BranchId = @BranchId AND a.Code LIKE '4%' AND  a.Trans_dt BETWEEN @FromDate ANd @ToDate
GROUP BY a.PartyCode, a.PartyName
order BY a.PartyCode

select @FromDate AS DateFrom, @ToDate AS DateTo, PartyCode, PartyName, Debit, Credit, Balance, SUM(Balance) over(order by partycode) as CumBalance from #temp

END
GO
