CREATE PROCEDURE [dbo].[SP_WEB_ACLedger] (@lcAcCode nvarchar(20),@DateFrom DateTime,@DateTo datetime, @BranchId int, @CostCenter nvarchar(50))
AS 
DROP TABLE tmp_QueryAC
BEGIN
------select a.Code,b.Description ,a.ContraCode,
------a.Trans_dt ,a.TrNo ,(c.Description+SPACE(2)+'('+Naration+')') as 'Naration', 
------a.Debit ,a.Credit , 1 as SlNo
------INTO tmp_QueryAC
------from tbl_transact a , tbl_CHART_OF_ACCOUNTS b ,tbl_CHART_OF_ACCOUNTS c 
------where a.Code=b.Code AND a.ContraCode = c.Code 
------and a.Valid <> 0 
------and a.Code = '2101020001'

IF SUBSTRING(@lcAcCode,1,1) = '2'  
	BEGIN
		select a.id AS RowNo,a.Code,b.Description ,a.ContraCode,
		a.Trans_dt ,a.TrNo ,c.Description as ContraName, a.Naration , 
		ISNULL(SUM(a.Debit),0) AS Debit,ISNULL(SUM(a.Credit),0) AS Credit, 0 as OpBal,2 as SlNo , 0 AS CB
		INTO tmp_QueryAC
		from tbl_transact a , tbl_CHART_OF_ACCOUNTS b ,tbl_CHART_OF_ACCOUNTS c 
		where a.Code=b.Code AND a.ContraCode = c.Code 
		and a.Valid <> 0 
		and a.Code LIKE @lcAcCode+'%' AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
		AND a.Trans_dt BETWEEN @DateFrom AND @DateTo 
		GROUP BY a.Id,a.Code,b.Description ,a.ContraCode,a.Trans_dt ,a.TrNo ,c.Description,a.Naration
		UNION ALL 
		select 0,a.Code,b.Description ,'' AS ContraCode,
		@DateFrom-1 AS Trans_dt ,'' AS TrNo ,'-' as ContarName, 'Opening Balance', 
		0,0,ISNULL(SUM(a.Debit-a.Credit),0) , 2 as SlNo , 0
		from tbl_transact a , tbl_CHART_OF_ACCOUNTS b ,tbl_CHART_OF_ACCOUNTS c 
		where a.Code=b.Code AND a.ContraCode = c.Code  AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
		and a.Valid <> 0 
		and a.Code LIKE @lcAcCode+'%'
		AND a.Trans_dt <@DateFrom
		GROUP BY a.Code,b.Description

		--INSERT INTO tmp_QueryAC (RowNo,Code,TrNo,Trans_dt,ContraName,Naration,Debit,Credit,OpBal,SLNo,CB)
		--SELECT 999998,'-','-',@DateTo,'-', 'GRAND TOTAL',ISNULL(SUM(Debit),0),ISNULL(SUM(Credit),0),0,3,0
		--FROM tmp_QueryAC
		--where slno not in (3,4)
		
		--INSERT INTO tmp_QueryAC (RowNo,Code,TRNO,Trans_dt,ContraName,Naration,Debit,Credit,OpBal,SLNo,CB)
		--SELECT 999999,'-','-',@DateTo,'-', 'BALANCE OF A/C',ISNULL(SUM(Debit-Credit),0),0,0,4,ISNULL(SUM(Debit-Credit+OPBAL),0)
		--FROM tmp_QueryAC
		--where slno not in (3,4)
		
		UPDATE tmp_QueryAC SET description = '-' where description is null 
		UPDATE tmp_QueryAC SET contracode = '-' where contracode is null 

		select RowNo, Code, Description, ContraCode, Trans_dt, TrNo, ContraName, Naration, Debit, Credit, OpBal, SlNo, CB,
		SUM (Debit-credit+OPBAL) OVER (order by RowNo) AS CumTotal
		from tmp_QueryAC
		UNION ALL
		SELECT 999998,'-','-','',@dateTo,'-', 'GRAND TOTAL','-',ISNULL(SUM(Debit),0),ISNULL(SUM(Credit),0),0,3,0,0
		FROM tmp_QueryAC
		where slno not in (3,4)
		UNION ALL
		SELECT 999999,'-','-','',@dateTo,'-', 'BALANCE OF A/C','-',ISNULL(SUM(Debit-Credit),0),0,0,4,ISNULL(SUM(Debit-Credit+OPBAL),0),0
		FROM tmp_QueryAC
		where slno not in (3,4)
		ORDER BY RowNo ASC, Debit desc
		
--		SELECT * FROM tmp_QueryAC order by RowNo,slno,Trans_dt,TRNo 
		
	END
	ELSE IF SUBSTRING(@lcAcCode,1,1) = '4'  
		BEGIN
			select a.id AS RowNo,a.Code,b.Description ,a.ContraCode,
			a.Trans_dt ,a.TrNo ,c.Description as ContraName, a.Naration, 
			ISNULL(SUM(a.Debit),0) AS Debit ,ISNULL(SUM(a.Credit),0) AS Credit, 0 as OpBal,2 as SlNo , 0 AS CB
			INTO tmp_QueryAC
			from tbl_transact a , tbl_CHART_OF_ACCOUNTS b ,tbl_CHART_OF_ACCOUNTS c 
			where a.Code=b.Code AND a.ContraCode = c.Code 
			and a.Valid <> 0  AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
			and a.Code LIKE @lcAcCode+'%'
			AND a.Trans_dt BETWEEN @DateFrom AND @DateTo 
			GROUP BY a.id,a.Code,b.Description ,a.ContraCode,a.Trans_dt ,a.TrNo ,c.Description,a.Naration
			UNION ALL 
			select 0,a.Code,b.Description ,'' AS ContraCode,
			@DateFrom-1 AS Trans_dt ,'' AS TrNo ,'-' as ContarName, 'Opening Balance', 
			0,0,ISNULL(SUM(a.Debit-a.Credit),0) , 2 as SlNo ,0
			from tbl_transact a , tbl_CHART_OF_ACCOUNTS b ,tbl_CHART_OF_ACCOUNTS c 
			where a.Code=b.Code AND a.ContraCode = c.Code 
			and a.Valid <> 0  AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
			and a.Code LIKE @lcAcCode+'%'
			AND a.Trans_dt <@DateFrom
			GROUP BY a.Code,b.Description

			UPDATE tmp_QueryAC SET description = '-' where description is null 
			UPDATE tmp_QueryAC SET contracode = '-' where contracode is null 

			select RowNo, Code, Description, ContraCode, Trans_dt, TrNo, ContraName, Naration, Debit, Credit, OpBal, SlNo, CB,
			SUM (Debit-credit+OPBAL) OVER (order by RowNo) AS CumTotal
			from tmp_QueryAC
			UNION ALL
			SELECT 999998,'-','-','',@dateTo,'-', 'GRAND TOTAL','-',ISNULL(SUM(Debit),0),ISNULL(SUM(Credit),0),0,3,0,0
			FROM tmp_QueryAC
			where slno not in (3,4)
			UNION ALL
			SELECT 999999,'-','-','',@dateTo,'-', 'BALANCE OF A/C','-',ISNULL(SUM(Debit-Credit),0),0,0,4,ISNULL(SUM(Debit-Credit+OPBAL),0),0
			FROM tmp_QueryAC
			where slno not in (3,4)


			--------select RowNo, Code, Description, ContraCode, Trans_dt, TrNo, ContraName, Naration, Debit, Credit, OpBal, SlNo, CB,
			--------SUM (Debit-credit+OPBAL) OVER (order by RowNo) AS CumTotal
