			--------UNION ALL
			--------SELECT 999998,'-','-',@DateTo,'-', 'GRAND TOTAL',ISNULL(SUM(Debit),0),ISNULL(SUM(Credit),0),0,3
			--------FROM tmp_QueryAC
			--------where slno not in (3,4)
			--------UNION ALL
			--------SELECT 999999,'-','-',@DateTo,'-', 'BALANCE OF A/C',ISNULL(SUM(Debit-Credit),0),0,ISNULL(SUM(Debit-Credit+OPBAL),0),4
			--------FROM tmp_QueryAC
			--------where slno not in (3,4)


			--INSERT INTO tmp_QueryAC (Code,TrNo,Trans_dt,ContraName,Naration,Debit,Credit,OpBal,SLNo)
			--SELECT '-','-',@DateTo,'-', 'GRAND TOTAL',ISNULL(SUM(Debit),0),ISNULL(SUM(Credit),0),0,3
			--FROM tmp_QueryAC
			--where slno not in (3,4)
		
			--INSERT INTO tmp_QueryAC (Code,TRNO,Trans_dt,ContraName,Naration,Debit,Credit,OpBal,SLNo)
			--SELECT '-','-',@DateTo,'-', 'BALANCE OF A/C',ISNULL(SUM(Debit-Credit),0),0,ISNULL(SUM(Debit-Credit+OPBAL),0),4
			--FROM tmp_QueryAC
			--where slno not in (3,4)
		
			--UPDATE tmp_QueryAC SET description = '-' where description is null 
			--UPDATE tmp_QueryAC SET contracode = '-' where contracode is null 
		
		
			--SELECT * FROM tmp_QueryAC order by slno,Trans_dt,TRNo 



		END
	ELSE IF SUBSTRING(@lcAcCode,1,1) = '1'  
		BEGIN
			select a.id AS RowNo,a.Code,b.Description ,a.ContraCode,
			a.Trans_dt ,a.TrNo ,c.Description as ContraName, a.Naration, 
			ISNULL(SUM(a.Debit),0) AS Debit ,ISNULL(SUM(a.Credit),0) AS Credit, 0 as OpBal,2 as SlNo , 0 AS CB
			INTO tmp_QueryAC
			from tbl_transact a , tbl_CHART_OF_ACCOUNTS b ,tbl_CHART_OF_ACCOUNTS c 
			where a.Code=b.Code AND a.ContraCode = c.Code 
			and a.Valid <> 0  AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
			and a.Code LIKE @lcAcCode+'%'
			AND a.Trans_dt BETWEEN @DateFrom AND @DateTo 
			GROUP BY a.id,a.Code,b.Description ,a.ContraCode,a.Trans_dt ,a.TrNo ,c.Description,a.Naration
			UNION ALL 
			select 0,a.Code,b.Description ,'' AS ContraCode,
			@DateFrom-1 AS Trans_dt ,'' AS TrNo ,'-' as ContarName, 'Opening Balance', 
			0,0,ISNULL(SUM(a.Credit-a.Debit),0) , 2 as SlNo,0
			from tbl_transact a , tbl_CHART_OF_ACCOUNTS b ,tbl_CHART_OF_ACCOUNTS c 
			where a.Code=b.Code AND a.ContraCode = c.Code 
			and a.Valid <> 0  AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
			and a.Code LIKE @lcAcCode+'%'
			AND a.Trans_dt < @DateFrom
			GROUP BY a.Code,b.Description


			UPDATE tmp_QueryAC SET description = '-' where description is null 
			UPDATE tmp_QueryAC SET contracode = '-' where contracode is null 

			select RowNo, Code, Description, ContraCode, Trans_dt, TrNo, ContraName, Naration, Debit, Credit, OpBal, SlNo, CB,
			SUM (Credit-Debit+OPBAL) OVER (order by RowNo) AS CumTotal
			from tmp_QueryAC
			UNION ALL
			SELECT 999998,'-','-','',@dateTo,'-', 'GRAND TOTAL','-',ISNULL(SUM(Debit),0),ISNULL(SUM(Credit),0),0,3,0,0
			FROM tmp_QueryAC
			where slno not in (3,4)
			UNION ALL
			SELECT 999999,'-','-','',@dateTo,'-', 'BALANCE OF A/C','-',ISNULL(SUM(Credit-Debit),0),0,0,4,ISNULL(SUM(Credit-Debit+OPBAL),0),0
			FROM tmp_QueryAC
			where slno not in (3,4)



		--	INSERT INTO tmp_QueryAC (Code,TrNo,Trans_dt,ContraName,Naration,Debit,Credit,OpBal,SLNo)
		--	SELECT '-','-',@DateTo,'-', 'GRAND TOTAL',ISNULL(SUM(Debit),0),ISNULL(SUM(Credit),0),0,3
		--	FROM tmp_QueryAC
		--	where slno not in (3,4)
		
		--	INSERT INTO tmp_QueryAC (Code,TRNO,Trans_dt,ContraName,Naration,Debit,Credit,OpBal,SLNo)
		--	SELECT '-','-',@DateTo,'-', 'BALANCE OF A/C',0,ISNULL(SUM(Credit-Debit),0),ISNULL(SUM(Credit-Debit+OPBAL),0),4
		--	FROM tmp_QueryAC
		--	where slno not in (3,4)
		
		--	UPDATE tmp_QueryAC SET description = '-' where description is null 
		--	UPDATE tmp_QueryAC SET contracode = '-' where contracode is null 
		
		
		--	SELECT * FROM tmp_QueryAC order by slno,Trans_dt,TRNo 
		END
	ELSE IF SUBSTRING(@lcAcCode,1,1) = '3'  
		BEGIN
			select a.id AS RowNo, a.Code, b.Description ,a.ContraCode,
			a.Trans_dt ,a.TrNo ,c.Description as ContraName, a.Naration, 
			ISNULL(SUM(a.Debit),0) AS Debit, ISNULL(SUM(a.Credit),0) AS Credit, 0 as OpBal,2 as SlNo , 0 AS CB
			INTO tmp_QueryAC
			from tbl_transact a , tbl_CHART_OF_ACCOUNTS b ,tbl_CHART_OF_ACCOUNTS c 
			where a.Code=b.Code AND a.ContraCode = c.Code 
			and a.Valid <> 0  AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
			and a.Code LIKE @lcAcCode+'%'
			AND a.Trans_dt BETWEEN @DateFrom AND @DateTo 
			GROUP BY a.id,a.Code,b.Description ,a.ContraCode,a.Trans_dt ,a.TrNo ,c.Description,a.Naration
			UNION ALL 
			select 0,a.Code,b.Description ,'' AS ContraCode,
			@DateFrom-1 AS Trans_dt ,'' AS TrNo ,'-' as ContarName, 'Opening Balance', 
			0,0,ISNULL(SUM(a.Credit-a.Debit),0) , 2 as SlNo, 0 AS CB
			from tbl_transact a , tbl_CHART_OF_ACCOUNTS b ,tbl_CHART_OF_ACCOUNTS c 
			where a.Code=b.Code AND a.ContraCode = c.Code 
			and a.Valid <> 0  AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
			and a.Code LIKE @lcAcCode+'%'
			AND a.Trans_dt < @DateFrom
			GROUP BY a.Code,b.Description


			select RowNo, Code, Description, ContraCode, Trans_dt, TrNo, ContraName, Naration, Debit, Credit, OpBal, SlNo, CB,
			SUM (Credit-Debit+OPBAL) OVER (order by RowNo) AS CumTotal
			from tmp_QueryAC
			UNION ALL
			SELECT 999998,'-','-','',@dateTo,'-', 'GRAND TOTAL','-',ISNULL(SUM(Debit),0),ISNULL(SUM(Credit),0),0,3,0,0
			FROM tmp_QueryAC
			where slno not in (3,4)
			UNION ALL
			SELECT 999999,'-','-','',@dateTo,'-', 'BALANCE OF A/C','-',ISNULL(SUM(Credit-Debit),0),0,0,4,ISNULL(SUM(Credit-Debit+OPBAL),0),0
			FROM tmp_QueryAC
			where slno not in (3,4)




			--INSERT INTO tmp_QueryAC (Code,TrNo,Trans_dt,ContraName,Naration,Debit,Credit,OpBal,SLNo)
			--SELECT '-','-',@DateTo,'-', 'GRAND TOTAL',ISNULL(SUM(Debit),0),ISNULL(SUM(Credit),0),0,3
			--FROM tmp_QueryAC
			--where slno not in (3,4)
		
			--INSERT INTO tmp_QueryAC (Code,TRNO,Trans_dt,ContraName,Naration,Debit,Credit,OpBal,SLNo)
			--SELECT '-','-',@DateTo,'-', 'BALANCE OF A/C',0,ISNULL(SUM(Credit-Debit),0),ISNULL(SUM(Credit-Debit+OPBAL),0),4
			--FROM tmp_QueryAC
			--where slno not in (3,4)
		
			--UPDATE tmp_QueryAC SET description = '-' where description is null 
			--UPDATE tmp_QueryAC SET contracode = '-' where contracode is null 
		
		
			--SELECT * FROM tmp_QueryAC order by slno,Trans_dt,TRNo 
		END
END
