CREATE PROCEDURE [dbo].[SP_WEB_BalanceSheet] (@DateFrom DateTime , @DateTo datetime, @BranchId int, @CostCenter nvarchar(50),@levelId integer)
AS 

DROP TABLE tmpBlanceSheet

EXEC SP_WEB_ProfitAndLossForBS @DateFrom, @DateTo, @BranchId, @CostCenter
--- EXEC SP_WEB_ProfitAndLossForBS '2022-12-15','2022-12-15',1,1

BEGIN 
select 1 AS SlNo,a.Code,(space(10)+b.Description)  AS Description, SUM(a.Debit - a.Credit) AS InnerAmt , 0 AS Amount  
INTO tmpBlanceSheet
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.Code = b.Code 
and a.Valid = 1 AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and SUBSTRING(a.Code,1,1) IN ('2') 
and Trans_dt <= @DateTo 
Group BY a.Code,b.Description
UNION ALL
select 1 AS SlNo,(SUBSTRING(a.Code,1,6)+'0000') as Code ,b.Description , 0 AS InnerAmt , SUM(a.Debit - a.Credit) AS Amount  
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where SUBSTRING(a.Code,1,6)+'0000' = b.Code 
and a.Valid = 1 AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and SUBSTRING(a.Code,1,1) IN ('2') 
and Trans_dt <= @DateTo 
Group BY SUBSTRING(a.Code,1,6),b.Description
UNION ALL
SELECT 1 , '2999999998','Closing Stock',0,Amount
FROM tmpFCAcc 
where SlNO = 3
UNION ALL
select 2 AS SlNo,a.Code,(space(10)+b.Description) AS Description , SUM(a.Credit-a.Debit) AS InnerAmt ,  0 as Amount
from tbl_TRANSACT a, tbl_CHART_OF_ACCOUNTS b
where a.Code = b.Code 
and a.Valid = 1 AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and SUBSTRING(a.Code,1,1) IN ('1') 
and Trans_dt <= @DateTo 
Group BY a.Code,b.Description
UNION ALL
select 2 AS SlNo,(SUBSTRING(a.Code,1,6)+'0000') as Code ,b.Description , 0 AS InnerAmt , SUM(a.Credit-a.Debit) AS Amount 
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where SUBSTRING(a.Code,1,6)+'0000' = b.Code 
and a.Valid = 1 AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and SUBSTRING(a.Code,1,1) IN ('1') 
and Trans_dt <= @DateTo 
Group BY SUBSTRING(a.Code,1,6),b.Description
UNION ALL
SELECT 2 ,'1102010001','Current Year Profit/Loss',Amount,Amount
FROM tmpPLAC 
where SlNO = 10
UNION ALL
select 2,'1102010002','Previous Profit/Loss A/C',SUM(Credit-debit),SUM(Credit-debit) AS Balance  
from tbl_transact
where valid = 1 and substring(code,1,1) IN ('3','4')
and Trans_dt <@DateFrom AND BranchId = @BranchId
UNION ALL
SELECT 1 ,'2999999999','TOTAL ASSET',0,SUM(aa.Amount)
FROM (
select 1 AS SlNo,a.Code,(space(10)+b.Description) As Description , SUM(a.Debit - a.Credit) AS InnerAmt , 0 AS Amount  
from tbl_TRANSACT a, tbl_CHART_OF_ACCOUNTS b
where a.Code = b.Code 
and a.Valid = 1 AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and SUBSTRING(a.Code,1,1) IN ('2') 
and Trans_dt <= @DateTo 
Group BY a.Code,b.Description
UNION ALL
select 1 AS SlNo,(SUBSTRING(a.Code,1,6)+'0000') as Code ,b.Description , 0 AS InnerAmt , SUM(a.Debit - a.Credit) AS Amount  
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where SUBSTRING(a.Code,1,6)+'0000' = b.Code 
and a.Valid = 1 AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and SUBSTRING(a.Code,1,1) IN ('2') 
and Trans_dt <= @DateTo 
Group BY SUBSTRING(a.Code,1,6),b.Description
UNION ALL
SELECT 1 , '2999999999','Closing Stock',0,Amount
FROM tmpFCAcc 
where SlNO = 3
UNION ALL
select 2 AS SlNo,a.Code,(space(10)+b.Description) AS Description , SUM(a.Credit-a.Debit) AS InnerAmt ,  0 as Amount
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.Code = b.Code 
and a.Valid = 1 AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and SUBSTRING(a.Code,1,1) IN ('1') 
and Trans_dt <= @DateTo 
Group BY a.Code,b.Description ) aa
UNION ALL
SELECT 2,'1999999999','TOTAL LIABILITY',0, SUM(bb.Amount) AS Amount 
FROM (
select 2 AS SlNo,a.Code,b.Description , SUM(a.Credit-a.Debit) AS InnerAmt ,  0 as Amount
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.Code = b.Code 
and a.Valid = 1 AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and SUBSTRING(a.Code,1,1) IN ('1') 
and Trans_dt <= @DateTo 
Group BY a.Code,b.Description
UNION ALL
select 2 AS SlNo,(SUBSTRING(a.Code,1,6)+'0000') as Code ,b.Description , 0 AS InnerAmt , SUM(a.Credit-a.Debit) AS Amount
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where SUBSTRING(a.Code,1,6)+'0000' = b.Code 
and a.Valid = 1 AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and SUBSTRING(a.Code,1,1) IN ('1') 
and Trans_dt <= @DateTo 
Group BY SUBSTRING(a.Code,1,6),b.Description
UNION ALL
SELECT 2 ,'1102010001','Current Year Profit/Loss',0,Amount
FROM tmpPLAC 
where SlNO = 10
UNION ALL
select 2,'1102010002','Previous Profit/Loss A/C',0,SUM(Credit-debit) AS Balance  
from tbl_transact
where valid = 1 and substring(code,1,1) IN ('3','4')
and Trans_dt <@DateFrom AND BranchId = @BranchId
) bb
UNION ALL
SELECT 1,'2000000000','PROPERTY AND ASSET',0,0
UNION ALL
SELECT 2,'1000000000','CAPITAL AND LIABILITY',0,0

--------BEGIN 
--------select 1 AS SlNo,(space(10)+a.Code) AS Code,(space(10)+b.Description)  AS Description, SUM(a.Debit - a.Credit) AS InnerAmt , 0 AS Amount  
--------INTO tmpBlanceSheet
--------from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
--------where a.Code = b.Code 
--------and a.Valid = 1
--------and SUBSTRING(a.Code,1,1) IN ('2') 
--------and Trans_dt <= @DateTo 
