--------UNION ALL
--------SELECT 1,'2000000000','PROPERTY AND ASSET',0,0
--------UNION ALL
--------SELECT 2,'1000000000','CAPITAL AND LIABILITY',0,0

update tmpBlanceSheet set InnerAmt = 0 where InnerAmt IS NULL 
update tmpBlanceSheet set Amount = 0 where Amount IS NULL 






if @levelId = 5 
	begin
		SELECT SlNo, Code, Description, Isnull(InnerAmt,0) as InnerAmt, Isnull(Amount,0) as Amount 
		from tmpBlanceSheet 
		ORDER BY SlNo,Code 	
	end
if @levelId = 4 
	begin
		SELECT a.SlNO, b.code, b.Description, SUM(ISNULL(a.InnerAmt, 0)) as InnerAmt, 0 as Amount 
		FROM tmpBlanceSheet a , tbl_CHART_OF_ACCOUNTS b
		where SUBSTRING(a.Code,1,6)+'0000' = b.Code 
		GROUP BY a.SlNO, b.code, b.Description
		UNION ALL
		SELECT SlNO, code, Description, ISNULL(InnerAmt, 0) as InnerAmt, ISNULL(Amount, 0) as Amount 
		FROM tmpBlanceSheet 
		WHERE Code IN ('2999999999','1999999999')
		ORDER BY a.SlNo,b.Code 
	end

if @levelId = 3 
	begin
		SELECT a.SlNO, b.code, b.Description, SUM(ISNULL(a.InnerAmt, 0)) as InnerAmt, 0 as Amount 
		FROM tmpBlanceSheet a , tbl_CHART_OF_ACCOUNTS b
		where SUBSTRING(a.Code,1,4)+'000000' = b.Code 
		GROUP BY a.SlNO, b.code, b.Description
		UNION ALL
		SELECT SlNO, code, Description, ISNULL(InnerAmt, 0) as InnerAmt, ISNULL(Amount, 0) as Amount 
		FROM tmpBlanceSheet 
		WHERE Code IN ('2999999999','1999999999')
		ORDER BY a.SlNo,b.Code 
	end

if @levelId = 2 
	begin
		SELECT a.SlNO, b.code, b.Description, SUM(ISNULL(a.InnerAmt, 0)) as InnerAmt, 0 as Amount 
		FROM tmpBlanceSheet a , tbl_CHART_OF_ACCOUNTS b
		where SUBSTRING(a.Code,1,2)+'00000000' = b.Code 
		GROUP BY a.SlNO, b.code, b.Description
		UNION ALL
		SELECT SlNO, code, Description, ISNULL(InnerAmt, 0) as InnerAmt, ISNULL(Amount, 0) as Amount 
		FROM tmpBlanceSheet 
		WHERE Code IN ('2999999999','1999999999')
		ORDER BY a.SlNo,b.Code 
	end



END

