CREATE PROCEDURE [dbo].[SP_WEB_HospitalIncome_Details] (@DateFrom DateTime,@DateTo DateTime, @BranchId INT, @UnitId INT)
AS
IF  EXISTS (SELECT * FROM sys.objects WHERE object_id = OBJECT_ID(N'[dbo].[tmpWebIndoorCollDtls]') AND type in (N'U'))
	DROP TABLE [dbo].[tmpWebIndoorCollDtls];

CREATE TABLE [dbo].[tmpWebIndoorCollDtls](
	[Particulars] [varchar](100) NULL,
	[RefDate] [date] NOT NULL,
	[RefNo] [varchar](30) NOT NULL,
	[PatientID] [nvarchar](50) NOT NULL,
	[PatientName] [varchar](65) NULL,
	[Total] [money] NULL,
	[Less] [money] NOT NULL,
	[NetTotal] [money] NULL,
	[RecvAmt] [money] NULL,
	[Due] [int] NOT NULL,
	[DueColl] [money] NOT NULL,
	[TotalColl] [money] NULL,
	[Slno] [int] NOT NULL,
	[SlNo2] [int] NOT NULL
) ON [PRIMARY]

BEGIN /* EXEC SP_WEB_HospitalIncome_Details  '2023-07-01','2023-08-24', 1, 1 */

	INSERT INTO tmpWebIndoorCollDtls(Particulars, RefDate, RefNo, PatientID, PatientName, 
	Total, Less, NetTotal, RecvAmt, Due, DueColl, TotalColl, Slno, SlNo2)
	
	SELECT (aa.Particulars+SPACE(2)+ aa.GroupName) AS Particulars,aa.RefDate,aa.RefNo,aa.PatientID,(SPACE(15)+aa.PatientName)  AS PatientName,
	aa.Total, aa.Less, aa.NetTotal,aa.Collection as RecvAmt, aa.Due, aa.DueColl, (aa.Collection + aa.DueColl) AS TotalColl, aa.Slno , aa.SlNo2
	FROM (

		SELECT RefNo,PatientId,PatientName,RefDate,'' as DrName,0 as Total,0 as Less,0 As NetTotal,Collection,0 as Due,0 as DueColl,
		'Advance Collection' as Particulars,'Indoor' AS GroupName, 8 AS Slno , 1 as SlNo2 
		FROM PatientLedger
		WHERE RefDate BETWEEN @DateFrom  AND @DateTo and Collection>0 and Status='Advance Collection' AND Valid=1
		UNION ALL
		SELECT RefNo,PatientId,PatientName,RefDate,'',0,Less,0,Collection,0,0,
		'Amount Received At Settlement','Indoor' , 12 AS Slno , 1 as SlNo2 
		FROM PatientLedger
		WHERE RefDate BETWEEN @DateFrom  AND @DateTo and Collection>0 and Status='Patient Settlement' AND Valid=1
		UNION ALL
		SELECT RefNo,PatientId,PatientName,RefDate,'',0,Less,0,Collection,0,0,
		'Amount Received After Release','Indoor' , 12 AS Slno , 1 as SlNo2
		FROM PatientLedger  WHERE RefDate BETWEEN @DateFrom  AND @DateTo and Collection>0 and Status='Due Collection' AND Valid=1
		UNION ALL
		SELECT RefNo,PatientId,PatientName,RefDate,'',0,0,0,-ReturnAMt,0,0, 
		'Return Amount Indoor','Return Amount Indoor' , 16 AS Slno , 1 as SlNo2 
		FROM PatientLedger  
		WHERE ReturnAmt>0 AND  RefDate BETWEEN @DateFrom  AND @DateTo AND Valid=1

		UNION ALL
		SELECT a.RefNo,a.PatientId,a.Particulars as PatientName,a.RefDate,'',0,Less,0,0,0,a.Collection, 
		a.Department+' Due Collection','Out Door'  , 24 AS Slno , 1 as SlNo2 
		FROM SalesLedger a  
		WHERE Collection>0 AND  RefDate BETWEEN @DateFrom AND @DateTo and CRType='Collection' AND Valid=1
		UNION ALL
		SELECT RefNo,PatientId,Particulars,RefDate,'',0,0,0,-(isnull(ReturnAmount,0)),0,0,
		Department+' Cash Return','(Out Door)' , 32 AS Slno , 1 as SlNo2 
		FROM SalesLedger 
		WHERE RefDate BETWEEN @DateFrom AND @DateTo AND Valid=1 AND isnull(ReturnAmount,0)>0
		UNION ALL
		SELECT a.RefNo,a.PatientId,a.Particulars,a.RefDate,'',a.Sales,a.Less,a.Sales-a.Less,a.Collection,0,0, 
		a.Department+' Collection','Out Door'  , 36 AS Slno , 1 as SlNo2 
		FROM SalesLedger a  
		WHERE a.RefDate BETWEEN @DateFrom AND @DateTo and CRType='Sales' and Collection>0 AND Valid=1 
		GROUP BY a.RefNo,a.PatientId,a.Particulars,a.RefDate,a.Sales,a.Less,a.Collection, a.Department
	
	) aa
	
	ALTER TABLE tmpWebIndoorCollDtls ALTER COLUMN Total MONEY

	INSERT INTO tmpWebIndoorCollDtls (Particulars,RefDate,RefNo,PatientId,PatientName,Total,Less,NetTotal,RecvAmt,Due,
	DueColl,TotalColl,Slno,SlNo2)
	select Particulars,MIN(RefDate) as RefDate, '','',UPPER(Particulars), 0 as Total , 0 as Less , 0 as NetTotal,
	0 as RecvAmt, 0 AS Due, 0 as DueColl, 0 AS TotalColl,MAX(SlNO)-1,3 as SlNO2
	from tmpWebIndoorCollDtls
	WHERE SlNo2=1 
	GROUP BY Particulars	
	
	INSERT INTO tmpWebIndoorCollDtls (Particulars,RefDate,RefNo,PatientId,PatientName,Total,Less,NetTotal,RecvAmt,Due,
	DueColl,TotalColl,Slno,SlNo2)
	select Particulars,MAX(RefDate) as RefDate, '','',SPACE(5)+UPPER('Total of'+SPACE(2)+Particulars), SUM(Total) , SUM(Less) , SUM(NetTotal),
	SUM(RecvAmt), SUM(Due), SUM(DueColl), SUM(TotalColl),MAX(SlNO)+1,6 as SlNO2
	from tmpWebIndoorCollDtls
	WHERE SlNo2=1 
	GROUP BY Particulars

	INSERT INTO tmpWebIndoorCollDtls (Particulars,RefDate,RefNo,PatientId,PatientName,Total,Less,NetTotal,RecvAmt,Due,
	DueColl,TotalColl,Slno,SlNo2)
	select UPPER('Grand Total'), ISNULL(MAX(RefDate), GETDATE()) as RefDate, '', '', UPPER('Grand Total'), ISNULL(SUM(Total),0), 
	ISNULL(SUM(Less), 0), ISNULL(SUM(NetTotal),0), ISNULL(SUM(RecvAmt), 0), ISNULL(SUM(Due), 0), ISNULL(SUM(DueColl),0), 
	ISNULL(SUM(TotalColl), 0), ISNULL(MAX(SlNO)+1,0),60 as SlNO2
	from tmpWebIndoorCollDtls
	WHERE SlNo2=1 

	SELECT * from  tmpWebIndoorCollDtls WHERE Total+Less+NetTotal+RecvAmt+Due+DueColl+TotalColl != 0 ORDER BY Particulars,slno,RefDate,RefNo

END


GO
/****** Object:  StoredProcedure [dbo].[SP_WEB_HospitalIncome_Summarized]    Script Date: 3/12/2026 6:25:16 AM ******/
