CREATE PROCEDURE [dbo].[SP_WEB_HospitalIncome_Summarized] @DateFrom DateTime,@DateTo DateTime, @BranchId int, @UnitId int
AS
DROP TABLE tmpWebIndoorCollSmz

/*Condition for IsInclude Pharmacy bill*/
DECLARE @IncludePharmacy INT, @IsIncludePharmacy INT;
SELECT @IncludePharmacy = PharmacyInclude FROM tbl_ComInfo
IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END

BEGIN /* EXEC SP_WEB_HospitalIncome_Summarized '2023-07-01', '2023-07-31', 1, 1 */
	SELECT (aa.Particulars) AS Particulars  , SUM(aa.Paid+aa.DueColl) AS TotalColl , 1 as SlNo
	INTO tmpWebIndoorCollSmz
	FROM (
	SELECT RefNo,PatientID,PatientName,RefDate,DrName,0 AS Total, Less, (Collection-less) AS NetTotal,Collection AS Paid,0 AS Due,0 AS DueColl,
	'Collection From Hospital Service' AS Particulars,'Indoor' AS GroupName  
	FROM PatientLedger  
	WHERE RefDate BETWEEN @DateFrom  AND @DateTo AND Collection>0 And Valid=1 and BranchId = @BranchId
	UNION ALL
	SELECT RefNo,PatientId,PatientName,RefDate,'',0,0,0,-ReturnAmt,0,0, 'Return Amount Indoor','Return Amount Indoor' 
	FROM PatientLedger
	WHERE ReturnAmt<>0 AND  RefDate BETWEEN @DateFrom  AND @DateTo And Valid <> 0and BranchId = @BranchId
	UNION ALL
	SELECT RefNo,PatientId,Particulars,RefDate,'',Sales,Less,Sales-Less,Collection,0,0, 'Collection From '+Department,'Out Door' 
	FROM SalesLedger 
	WHERE RefDate BETWEEN @DateFrom  AND @DateTo AND Collection>0 AND Valid <> 0 and BranchId = @BranchId --and Department not in ('Dental', 'Physiotherapy')
	GROUP BY RefNo,PatientId,Particulars,RefDate,Sales,Less,Collection,Department
	UNION ALL
	SELECT '' as RefNo, a.PatientId, a.Particulars, '' as RefDate,'',0,0,0,-MAX(a.ReturnCash),0,0, 'Return From '+a.Department,'Out Door'  
	FROM SalesLedger a, InvReturn b 
	WHERE a.BranchId = b.BranchId AND a.PrevInvNo = b.InvNo and b.RtnInvDate BETWEEN @DateFrom and @DateTo AND b.Valid =1 and a.BranchId = @BranchId
	--and a.Department not in ('Dental', 'Physiotherapy')
	GROUP BY a.PatientId, a.Particulars, a.Department, a.PrevInvNo
	--SELECT a.RefNo, a.PatientId, a.Particulars, a.RefDate,'',0,0,0,-a.ReturnAmount,0,0, 'Return From '+a.Department,'Out Door'  
	--FROM SalesLedger a, InvReturn b 
	--WHERE a.PrevInvNo = b.InvNo and b.RtnInvDate BETWEEN @DateFrom  AND @DateTo AND a.ReturnAmount>0 AND a.Valid <> 0 
	----UNION ALL
	----SELECT TrNo,PatientId,Particulars,TrDate,'',Sales,LessAmt,Sales-LessAmt,Collection,0,0, 'Collection From Medicine Sales','Out Door'  FROM PharSalesLedger WHERE TrDate BETWEEN @DateFrom  AND @DateTo AND Collection>0 AND Valid <> 0
	----UNION ALL
	----SELECT TrNo,PatientId,Particulars,TrDate,'',0,0,0,-CashReturn,0,0, 'Return From Medicine Sales','Out Door'  FROM PharSalesLedger WHERE TrDate BETWEEN @DateFrom  AND @DateTo AND CashReturn>0 AND Valid <> 0
	UNION ALL
	SELECT TrNo, RegNo, PatientName, TrDate,'',Amount, 0, 0, Amount, 0, 0, 'Collection From Registration Card','Out Door'  
	FROM RegistrationFees 
	WHERE TrDate BETWEEN @DateFrom  AND @DateTo AND Amount>0 AND Valid=1 and BranchId = @BranchId
	UNION ALL
	SELECT TrNo, RegNo, Name, TrDate,'', Amount, 0, 0, Amount, 0, 0, 'Collection From OPD Ticket','Out Door' 
	FROM OPDTicketMaster 
	WHERE TrDate BETWEEN @DateFrom  AND @DateTo AND Amount>0 AND Valid=1 and BranchId = @BranchId
	UNION ALL
	SELECT TrNo, RegNo, PatientName, TrDate,'', 0, 0, 0, -Amount, 0, 0, 'Indoor Refund','Indoor' 
	FROM CashReturn 
	WHERE TrDate BETWEEN @DateFrom  AND @DateTo AND Amount>0 AND Valid=1
	----UNION ALL
	----select a.RtnInvNo, b.RegNo, b.PatientName, a.RtnInvDate, '', 0,0,0, -a.ReturnAmt, 0, 0, 'Outdoor Return', 'Out door' from InvReturn a, InvMaster b where a.InvNo = b.InvNo and a.InvDate = b.InvDate and RtnInvDate BETWEEN @DateFrom  AND @DateTo AND a.ReturnAmt>0 AND a.Valid=1
	UNION ALL
	--SELECT TrNo, RegNo, Name, TrDate,'', 0, 0, 0, -RtnAmount, 0, 0, 'OPD Ticket Refund','Out door' FROM OPDTicketMaster WHERE TrDate BETWEEN @DateFrom  AND @DateTo AND RtnAmount>0 AND Valid=1
	
	select b.TrNo, b.RegNo, b.Name, a.TrDate, '', 0, 0, 0, -b.RtnAmount, 0 ,0, 'OPD Ticket Refund','Out door' 
	from OPDTicketReturn a 
	LEFT JOIN OPDTicketMaster b ON a.OpdId = b.Id
	WHERE a.Valid = 1 and b.Valid = 1 and a.TrDate BETWEEN @DateFrom  AND @DateTo and BranchId = @BranchId
	UNION ALL
	select TrNo, RegNo, PatientName, TrDate, '', 0, 0, 0,-Amount, 0, 0, 'OPD Refund','Out door' 
	from InvRefund WHERE TrDate BETWEEN @DateFrom  AND @DateTo AND Amount > 0 AND Valid=1 and BranchId = @BranchId
	) aa
	GROUP BY aa.Particulars , aa.GroupName

	--INSERT INTO tmpWebIndoorCollSmz (Particulars,TotalColl,SlNo)
	--SELECT SPACE(15)+'GRAND COLLECTION',SUM(Totalcoll),2
	--FROM tmpWebIndoorCollSmz
	
	--SELECT * from tmpWebIndoorCollSmz ORDER BY slno,Particulars

	SELECT *,
	(SELECT dbo.NumberToWordWithLacCroreDecimal (ROUND(SUM(Totalcoll),0)) from tmpWebIndoorCollSmz) as NumInWord
	FROM tmpWebIndoorCollSmz
END
GO
/****** Object:  StoredProcedure [dbo].[SP_WEB_HospitalIncome_UserWise]    Script Date: 3/12/2026 6:25:16 AM ******/
SET ANSI_NULLS ON
GO
