GO

CREATE PROCEDURE [dbo].[SP_WEB_HospitalIncome_UserWise] (@DateFrom DateTime, @DateTo DateTime, @UserName nvarchar(20), @branchId int, @untiId int)
AS /* EXEC SP_WEB_HospitalIncome_UserWise '2024-11-01','2024-11-03', '', 1, 1 */

/*Condition for IsInclude Pharmacy bill*/
DECLARE @IncludePharmacy INT, @IsIncludePharmacy INT;
SELECT @IsIncludePharmacy = PharmacyInclude FROM tbl_ComInfo
IF @IsIncludePharmacy = 1 BEGIN SET @IncludePharmacy = 1 END ELSE BEGIN SET @IncludePharmacy = 5 END

BEGIN
	SELECT aa.Department, aa.RefNo, aa.RefDate, aa.PatientId, aa.PatientName, aa.UserName, SUM(AdvanceColl) AS AdvanceColl,
	SUM(aa.ReturnAmt) AS ReturnAmt, SUM(aa.DueColl) AS DueColl FROM (
		SELECT 'Indoor' as Department, RefNo, RefDate, PatientID, PatientName, UserName,
		Collection AS AdvanceColl, 0 AS ReturnAmt, 0 as DueColl
		FROM PatientLedger Where Valid = 1 And BranchId = @branchId AND RefDate Between @DateFrom and @DateTo 
		and Status = 'Advance Collection' AND CASE WHEN @UserName='' THEN '' ELSE UserName END = @UserName
		GROUP BY RefNo, RefDate, PatientID, PatientName, UserName, Collection, ReturnAmt
		HAVING Collection > 0
		UNION ALL
		SELECT 'Indoor' as Department, RefNo, RefDate, PatientID, PatientName, UserName, 
		0 AS AdvanceColl, ReturnAmt, Collection as DueColl
		FROM PatientLedger Where BranchId = @branchId AND Valid = 1 And RefDate Between @DateFrom and @DateTo 
		and Status != 'Advance Collection' AND CASE WHEN @UserName='' THEN '' ELSE UserName END = @UserName
		GROUP BY RefNo, RefDate, PatientID, PatientName, UserName, ReturnAmt, Collection
		HAVING Collection+ReturnAmt != 0
		UNION ALL		
		SELECT 'Indoor' AS Department, TrNo AS RefNo, TrDate AS RefDate, PatientId, PatientName, UserName,
		0 AS AdvanceColl, Amount As ReturnAmt, 0 AS DueColl 
		FROM CashReturn
		WHERE Valid=1 AND BranchId=@branchId AND TrDate BETWEEN @DateFrom AND @DateTo
		AND CASE WHEN @UserName='' THEN '' ELSE UserName END = @UserName

		UNION ALL
		SELECT a.Department, a.RefNo AS RefNo, a.RefDate AS Invdate, a.PatientId, a.Particulars AS PatientName, a.UserName,
		a.Collection, 0 ReturnNet, 0 as DueColl 
		FROM SalesLedger a WHERE BranchId = @branchId AND a.Valid = 1 AND a.CRType = 'Sales' 
		And a.Department <> 'Ambulance'
		AND a.RefDate BETWEEN @DateFrom AND @DateTo AND CASE WHEN @UserName='' THEN '' ELSE UserName END = @UserName
		GROUP BY a.Department, a.RefNo, a.RefDate, a.PatientId, a.Particulars, a.UserName, a.Collection, a.ReturnNet
		HAVING Collection+ReturnNet != 0	
		UNION ALL
		SELECT a.Department, a.RefNo AS RefNo, a.RefDate AS Invdate, a.PatientId, a.Particulars AS PatientName, a.UserName,
		0 AS Collection, 0 ReturnNet, Collection as DueColl 
		FROM SalesLedger a 
		WHERE a.Valid != 0 AND a.BranchId = @branchId AND a.CRType = 'Collection' 
		And a.Department <> 'Ambulance'
		AND a.RefDate BETWEEN @DateFrom AND @DateTo AND CASE WHEN @UserName='' THEN '' ELSE UserName END = @UserName
		GROUP BY a.Department, a.RefNo, a.RefDate, a.PatientId, a.Particulars, a.UserName, a.ReturnNet, a.Collection
		HAVING Collection+a.ReturnNet != 0

		/* Start Outdoor Return */
		UNION ALL
		SELECT b.DeptName AS Department, a.RtnInvNo AS RefNo, a.RtnInvDate AS InvDate, b.PatientId, b.PatientName, a.UserName,
		0 AS Collection, MAX(a.ReturnCash) AS CashReturn, 0 AS DueColl
		FROM InvReturn a
		LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
		WHERE a.Valid=1 And a.BranchId =@branchId AND a.RtnInvDate BETWEEN @DateFrom AND @DateTo AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName 
		GROUP BY b.DeptName, a.RtnInvNo, a.RtnInvDate, b.PatientId, b.PatientName, a.UserName

		UNION ALL
		SELECT b.DeptName AS Department, a.TrNo AS RefNo, a.TrDate AS InvDate, b.PatientId, b.PatientName, a.UserName,
		0 AS Collection, a.Amount AS CashReturn, 0 AS DueColl
		FROM InvRefund a
		LEFT JOIN InvMaster b ON a.BranchId = b.BranchId AND a.InvNo = b.InvNo
		WHERE a.Valid=1 And a.BranchId =@branchId AND a.TrDate BETWEEN @DateFrom AND @DateTo AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName
		/* End Outdoor Return */

		--Ambulance
		UNION ALL
		SELECT 'Ambulance' AS Department, a.RefNo AS RefNo, a.RefDate AS Invdate, a.PatientId, a.PatientName, a.UserName,
		a.ReceiveAmt AS Collection, 0 ReturnNet, 0 as DueColl 
		FROM AmbulanceLedger a 
		WHERE a.Valid != 0 AND a.BranchId = @branchId 
		AND a.InputFrom = 'Sales' AND CASE WHEN @UserName='' THEN '' ELSE UserName END = @UserName
		AND a.RefDate BETWEEN @DateFrom AND @DateTo
		GROUP BY a.RefNo, a.RefDate, a.PatientId, a.PatientName, a.UserName, a.ReceiveAmt
		HAVING ReceiveAmt != 0
		UNION ALL
		SELECT 'Ambulance' AS Department, a.RefNo AS RefNo, a.RefDate AS Invdate, a.PatientId, a.PatientName, a.UserName,
		0 AS Collection, 0 ReturnNet, a.ReceiveAmt as DueColl 
		FROM AmbulanceLedger a 
		WHERE a.Valid != 0 AND a.BranchId = @branchId AND a.InputFrom != 'Sales' 
		AND a.RefDate BETWEEN @DateFrom AND @DateTo AND CASE WHEN @UserName='' THEN '' ELSE UserName END = @UserName
		GROUP BY a.RefNo, a.RefDate, a.PatientId, a.PatientName, a.UserName, a.ReceiveAmt
		HAVING ReceiveAmt != 0			

		--------==Medicine==--------
		UNION ALL
		SELECT 'Medicine' AS Department, a.InvNo, a.InvDate, a.PatientId, a.PatientName, a.UserName, 
		a.Collection AS AdvanceColl, a.CashReturn AS ReturnAmt, a.DueColl 
		FROM PharSalesLedger a 
		WHERE BranchId = @branchId AND a.Valid = @IncludePharmacy 
		AND a.TrDate BETWEEN @DateFrom AND @DateTo AND CASE WHEN @UserName='' THEN '' ELSE UserName END = @UserName
		AND a.Collection+a.DueColl+a.CashReturn != 0
	
		-----OPD Ticket
		UNION ALL
		SELECT 'OPD Ticket', a.TrNo AS Refno, a.TrDate AS RefDate, '' AS RegNo, a.Name,
		a.UserName, a.Received AS AdvanceColl, 0 AS ReturnAmt, 0 AS DueColl
		FROM OPDTicketMaster a
		WHERE a.Valid=1 AND a.BranchId=@branchId AND a.TrDate BETWEEN @DateFrom AND @DateTo
		AND CASE WHEN @UserName='' THEN '' ELSE UserName END = @UserName
		AND a.Received != 0
		UNION ALL
		SELECT 'OPD Ticket', a.RefNo, a.RefDate, '' AS RegNo, b.Name,
		a.UserName, 0 AS AdvanceColl, 0 AS ReturnAmt, a.Received AS DueColl
		FROM OPDTicketDueCollection a
		LEFT JOIN OPDTicketMaster b On a.OpdTicketId=b.Id AND b.Valid=1
		WHERE a.Valid=1 AND a.BranchId=@branchId AND a.RefDate BETWEEN @DateFrom AND @DateTo
		AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName
		UNION ALL
		SELECT 'OPD Ticket', a.TrNo AS RefNo, a.TrDate AS RefDate, '' AS RegNo, b.Name,
		a.UserName, 0 AS AdvanceColl, b.RtnAmount AS ReturnAmt, 0 AS DueColl
		FROM OPDTicketReturn a
		LEFT JOIN OPDTicketMaster b On a.OpdId=b.Id AND b.Valid=1
		WHERE a.Valid=1 AND b.BranchId=@branchId AND a.TrDate BETWEEN @DateFrom AND @DateTo
		AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName

		--Registration
		UNION ALL
		SELECT 'OPD Ticket', a.TrNo AS RefNo, a.TrDate AS RefDate, '' AS RegNo, a.PatientName,
		a.UserName, Amount AS AdvanceColl, 0 AS ReturnAmt, 0 AS DueColl
		FROM RegistrationFees a
		WHERE a.Valid=1 AND a.BranchId=@branchId AND a.TrDate BETWEEN @DateFrom AND @DateTo
		AND CASE WHEN @UserName='' THEN '' ELSE a.UserName END = @UserName
	) aa
	GROUP BY aa.Department, aa.RefNo, aa.RefDate, aa.PatientId, aa.PatientName, aa.UserName
END
GO
