CREATE PROCEDURE [dbo].[SP_WEB_ListofTransaction] (@lcVRType nvarchar(20), @DateFrom DateTime, @DateTo datetime, @BranchId int)
AS 

if @lcVRType = '' 
	BEGIN
		select a.Code,b.Description ,Trans_dt , TrNo , VoucherType ,RefNo ,Naration ,Remark, CONVERT(int, SubTrNo) AS SubTrNo, a.CostDept, SUM(Debit) AS Dr,SUM(Credit) AS Cr
		from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
		WHERE a.Valid <> 0 AND a.Code = b.Code  AND CorD = 'D'
		AND a.Trans_dt BETWEEN @DateFrom AND @DateTo AND BranchId = @BranchId
		GROUP BY a.Code,b.Description ,Trans_dt , TrNo , VoucherType ,RefNo,Naration ,Remark, a.SubTrNo, a.CostDept
		UNION ALL
		select a.Code,b.Description ,Trans_dt , TrNo , VoucherType ,RefNo,Remark ,Remark , a.SubTrNo, a.CostDept, SUM(Debit) AS Dr,SUM(Credit) AS Cr
		from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
		WHERE a.Valid <> 0 AND a.Code = b.Code AND CorD = 'C'
		AND a.Trans_dt BETWEEN @DateFrom AND @DateTo AND BranchId = @BranchId
		GROUP BY a.Code,b.Description ,Trans_dt , TrNo , VoucherType ,RefNo,Remark, a.SubTrNo, a.CostDept
		ORDER BY Trans_dt, TrNo, CONVERT(int, SubTrNo), Cr
	END
ELSE	
	BEGIN
		select a.Code,b.Description ,Trans_dt , TrNo , VoucherType ,RefNo,Naration ,Remark , CONVERT(int, SubTrNo) AS SubTrNo, a.CostDept, SUM(Debit) AS Dr,SUM(Credit) AS Cr
		from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
		WHERE a.Valid <> 0 AND a.Code = b.Code  AND CorD = 'D'
		AND a.Trans_dt BETWEEN @DateFrom AND @DateTo AND BranchId = @BranchId
		AND VoucherType = @lcVRType 
		GROUP BY a.Code,b.Description ,Trans_dt , TrNo , VoucherType ,RefNo,Naration ,Remark, a.SubTrNo, a.CostDept
		UNION ALL
		select a.Code,b.Description ,Trans_dt , TrNo , VoucherType ,RefNo,Remark , Remark, a.SubTrNo, a.CostDept, SUM(Debit) AS Dr,SUM(Credit) AS Cr
		from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
		WHERE a.Valid <> 0 AND a.Code = b.Code AND CorD = 'C'
		AND a.Trans_dt BETWEEN @DateFrom AND @DateTo  AND BranchId = @BranchId
		AND VoucherType = @lcVRType 
		GROUP BY a.Code,b.Description ,Trans_dt , TrNo , VoucherType ,RefNo,Remark, a.SubTrNo, a.CostDept
		ORDER BY Trans_dt, TrNo, CONVERT(int, SubTrNo), Cr
	END


GO
