CREATE PROCEDURE [dbo].[SP_WEB_ManufacturingAC] (@DateFrom DateTime , @DateTo datetime, @BranchId int)
AS


BEGIN
	select 1 AS SlNO , 'Opening Balance' AS Narration , ISNULL(SUM((PurchasePrice * InQty)-(PurchasePrice * OutQty )-(PurchasePrice*PRtnQty) + (PurchasePrice*RtnQty)),0) AS Amount
	from tbl_STOCK_LEDGER 
	where valid =1 
	and TrDate < @DateFrom AND BranchId = @BranchId
	UNION ALL
	select 2 AS SlNO , 'ADD Purchase' AS Narration , ISNULL(SUM((PurchasePrice * InQty)),0) AS Amount
	from tbl_STOCK_LEDGER 
	where valid =1 
	and TrDate BETWEEN @DateFrom AND @DateTo AND BranchId = @BranchId
	UNION ALL
	select 3 AS SlNO , 'Less Closing Stock' AS Narration , ISNULL(SUM((PurchasePrice * InQty)-(PurchasePrice * OutQty )-(PurchasePrice*PRtnQty) + (PurchasePrice*RtnQty)),0) AS Amount
	from tbl_STOCK_LEDGER 
	where valid =1 
	and TrDate <= @DateTo AND BranchId = @BranchId
	UNION ALL
	SELECT 4 as Slno,'Cost of Good Sold',SUM(aa.amount) 
	FROM (
	select 1 AS SlNO , 'Opening Balance' AS Narration , ISNULL(SUM((PurchasePrice * InQty)-(PurchasePrice * OutQty )-(PurchasePrice*PRtnQty) + (PurchasePrice*RtnQty)), 0) AS Amount
	from tbl_STOCK_LEDGER 
	where valid = 1 
	and TrDate < @DateFrom AND BranchId = @BranchId
	UNION ALL
	select 2 AS SlNO , 'ADD Purchase' AS Narration , ISNULL(SUM((PurchasePrice * InQty)),0) AS Amount
	from tbl_STOCK_LEDGER 
	where valid =1 
	and TrDate BETWEEN @DateFrom AND @DateTo AND BranchId = @BranchId
	UNION ALL
	select 3 AS SlNO , 'Less Closing Stock' AS Narration , ISNULL(SUM((PurchasePrice * InQty)-(PurchasePrice * OutQty )-(PurchasePrice*PRtnQty) + (PurchasePrice*RtnQty)) * (-1),0) AS Amount
	from tbl_STOCK_LEDGER 
	where valid =1 
	and TrDate <= @DateTo AND BranchId = @BranchId 
	) aa 

END



GO
