CREATE PROCEDURE [dbo].[SP_WEB_ManufacturingACForPL] (@DateFrom DateTime , @DateTo datetime, @BranchId int, @CostCenter nvarchar(50))
AS

drop table tmpFCAcc 

BEGIN
	select 1 AS SlNO , 'Opening Balance' AS Narration , SUM((PurchasePrice * InQty)-(PurchasePrice * OutQty )-(PurchasePrice*PRtnQty) + (PurchasePrice*RtnQty)) AS Amount
	INTO tmpFCAcc 
	from tbl_STOCK_LEDGER 
	where valid =1 AND BranchId = @BranchId  
	and TrDate < @DateFrom
	UNION ALL
	select 2 AS SlNO , 'ADD Purchase' AS Narration , SUM((PurchasePrice * InQty)) AS Amount
	from tbl_STOCK_LEDGER 
	where valid =1  AND BranchId = @BranchId
	and TrDate BETWEEN @DateFrom AND @DateTo
	UNION ALL
	select 3 AS SlNO , 'Less Closing Stock' AS Narration , SUM((PurchasePrice * InQty)-(PurchasePrice * OutQty )-(PurchasePrice*PRtnQty) + (PurchasePrice*RtnQty)) AS Amount
	from tbl_STOCK_LEDGER 
	where valid =1  AND BranchId = @BranchId
	and TrDate <= @DateTo
	UNION ALL
	SELECT 4 as Slno,'Cost of Good Sold',SUM(aa.amount) 
	FROM (
	select 1 AS SlNO , 'Opening Balance' AS Narration , SUM((PurchasePrice * InQty)-(PurchasePrice * OutQty )-(PurchasePrice*PRtnQty) + (PurchasePrice*RtnQty)) AS Amount
	from tbl_STOCK_LEDGER 
	where valid = 1  AND BranchId = @BranchId
	and TrDate < @DateFrom
	UNION ALL
	select 2 AS SlNO , 'ADD Purchase' AS Narration , SUM((PurchasePrice * InQty)) AS Amount
	from tbl_STOCK_LEDGER 
	where valid =1  AND BranchId = @BranchId
	and TrDate BETWEEN @DateFrom AND @DateTo
	UNION ALL
	select 3 AS SlNO , 'Less Closing Stock' AS Narration , SUM((PurchasePrice * InQty)-(PurchasePrice * OutQty )-(PurchasePrice*PRtnQty) + (PurchasePrice*RtnQty)) * (-1) AS Amount
	from tbl_STOCK_LEDGER 
	where valid =1  AND BranchId = @BranchId
	and TrDate <= @DateTo) aa

--	SELECT * from tmpFCAcc ORDER BY slno 

END

