CREATE PROCEDURE [dbo].[SP_WEB_ProfitAndLoss] (@DateFrom DateTime, @DateTo datetime, @BranchId int, @CostCenter nvarchar(50),@levelId Integer)
AS

DROP TABLE tmpPLAC

EXEC SP_WEB_ManufacturingACForPL @DateFrom, @Dateto, @BranchId, @CostCenter

BEGIN
select 1 as SlNO,a.code , b.Description ,SUM(a.Credit-a.Debit) as InnerAmount ,  0 AS Amount
INTO tmpPLAC
from tbl_TRANSACT a, tbl_CHART_OF_ACCOUNTS b
where a.valid = 1 and a.code=b.code 
AND trans_dt BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and a.code LIKE '3'+'%'
GROUP BY a.code , b.Description
UNION ALL
SELECT 2,SPACE(20) AS Code,'TOTAL SALES' , 0 , SUM(a.Credit-a.Debit) As Amount
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.valid = 1 and a.code=b.code AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
AND trans_dt BETWEEN @DateFrom and @DateTo
and a.code LIKE '3'+'%'
UNION ALL
select 4 As SlNo,(SUBSTRING(a.code,1,6)+'0000') AS  Code , b.Description ,0,SUM(a.Debit-a.Credit) as Amount
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.valid = 1 and SUBSTRING(a.code,1,6)+'0000'=b.code 
AND trans_dt BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and a.code LIKE '4'+'%' and a.code NOT IN ('4101010001')
GROUP BY SUBSTRING(a.code,1,6),b.Description
UNION ALL
select 4 As SlNo,a.code , SPACE(10)+b.Description ,SUM(a.Debit-a.Credit) as InnerAmount ,  0
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.valid = 1 and a.code=b.code  AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
AND trans_dt BETWEEN @DateFrom and @DateTo
and a.code LIKE '4'+'%' and a.code NOT IN ('4101010001')
GROUP BY a.code , b.Description
UNION ALL
select 6 As SlNo,'-' , 'TOTAL EXPENSES' ,0 as InnerAmount ,  SUM(a.Debit-a.Credit) AS TotalAmount
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.valid = 1 and a.code=b.code AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
AND trans_dt BETWEEN @DateFrom and @DateTo
and a.code LIKE '4'+'%' and a.code NOT IN ('4101010001')
UNION ALL
SELECT 8 , '','GROSS PROFIT',0,SUM(aa.Amount) as Amount
FROM 
(select 1 as SlNO,a.code , b.Description ,SUM(a.Credit-a.Debit) as InnerAmount ,  0 AS Amount
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.valid = 1 and a.code=b.code AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
AND trans_dt BETWEEN @DateFrom and @DateTo
and a.code LIKE '3'+'%'
GROUP BY a.code , b.Description
UNION ALL
SELECT 2,SPACE(20) AS Code,'TOTAL SALES' , 0 , SUM(a.Credit-a.Debit) As Amount
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.valid = 1 and a.code=b.code AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
AND trans_dt BETWEEN @DateFrom and @DateTo
and a.code LIKE '3'+'%'
UNION ALL
select 4 As SlNo,(SUBSTRING(a.code,1,6)+'0000') AS  Code , b.Description ,0,0 as Amount
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.valid = 1 and SUBSTRING(a.code,1,6)+'0000'=b.code 
AND trans_dt BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and a.code LIKE '4'+'%'
and a.code NOT IN ('4101010001')
GROUP BY SUBSTRING(a.code,1,6),b.Description
UNION ALL
select 4 As SlNo,a.code , SPACE(10)+b.Description ,SUM(a.Debit-a.Credit) as InnerAmount ,  0
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.valid = 1 and a.code=b.code AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
AND trans_dt BETWEEN @DateFrom and @DateTo
and a.code LIKE '4'+'%'
and a.code NOT IN ('4101010001')
GROUP BY a.code , b.Description
UNION ALL
select 6 As SlNo,'-' , 'TOTAL EXPENSES' ,0 as InnerAmount ,  SUM(a.Debit-a.Credit) * (-1) AS TotalAmount
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.valid = 1 and a.code=b.code AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
AND trans_dt BETWEEN @DateFrom and @DateTo
and a.code NOT IN ('4101010001')
and a.code LIKE '4'+'%') aa
--UNION ALL
--SELECT 9,'','LESS COST OF GOODS SOLD',0,Amount
--FROM tmpFCAcc
--WHERE slno=4
UNION ALL
SELECT 10,'','NET PROFIT/LOSS',0,SUM(bb.InnerAmount)
FROM (
select 1 as SlNO,a.code , b.Description ,SUM(a.Credit-a.Debit) as InnerAmount ,  0 AS Amount
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.valid = 1 and a.code=b.code 
AND trans_dt BETWEEN @DateFrom and @DateTo AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
and a.code LIKE '3'+'%'
GROUP BY a.code , b.Description
UNION ALL
select 4 As SlNo,a.code ,b.Description ,SUM(a.Debit-a.Credit) * (-1) as InnerAmount ,  0
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
where a.valid = 1 and a.code=b.code AND a.BranchId = @BranchId --AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
AND trans_dt BETWEEN @DateFrom and @DateTo
and a.code NOT IN ('4101010001')
and a.code LIKE '4'+'%'
GROUP BY a.code , b.Description
--UNION ALL
--SELECT 9,'','LESS COST OF GOODS SOLD',Amount * (-1),0
--FROM tmpFCAcc
--WHERE slno=4
)  bb

if @levelId = 5 
	begin
		SELECT SlNO, code, Description, ISNULL(InnerAmount, 0) as InnerAmount, ISNULL(Amount, 0) as Amount 
		FROM tmpPLAC 
		ORDER BY SlNo,Code 
	end

if @levelId = 4 
	begin
		SELECT a.SlNO, b.code, b.Description, SUM(ISNULL(a.InnerAmount, 0)) as InnerAmount, 0 as Amount 
		FROM tmpPLAC a , tbl_CHART_OF_ACCOUNTS b
		where SUBSTRING(a.Code,1,6)+'0000' = b.Code 
		GROUP BY a.SlNO, b.code, b.Description
		UNION ALL
		SELECT SlNO, code, Description, ISNULL(InnerAmount, 0) as InnerAmount, ISNULL(Amount, 0) as Amount 
		FROM tmpPLAC 
		WHERE SlNO Not IN (1,4)
		ORDER BY a.SlNo,b.Code 
	end

if @levelId = 3 
	begin
		SELECT a.SlNO, b.code, b.Description, SUM(ISNULL(a.InnerAmount, 0)) as InnerAmount, 0 as Amount 
		FROM tmpPLAC a , tbl_CHART_OF_ACCOUNTS b
		where SUBSTRING(a.Code,1,4)+'000000' = b.Code 
		GROUP BY a.SlNO, b.code, b.Description
		UNION ALL
		SELECT SlNO, code, Description, ISNULL(InnerAmount, 0) as InnerAmount, ISNULL(Amount, 0) as Amount 
		FROM tmpPLAC 
		WHERE SlNO Not IN (1,4)
		ORDER BY a.SlNo,b.Code 
	end

if @levelId = 2 
	begin
		SELECT a.SlNO, b.code, b.Description, SUM(ISNULL(a.InnerAmount, 0)) as InnerAmount, 0 as Amount 
		FROM tmpPLAC a , tbl_CHART_OF_ACCOUNTS b
		where SUBSTRING(a.Code,1,2)+'00000000' = b.Code 
		GROUP BY a.SlNO, b.code, b.Description
		UNION ALL
		SELECT SlNO, code, Description, ISNULL(InnerAmount, 0) as InnerAmount, ISNULL(Amount, 0) as Amount 
		FROM tmpPLAC 
		WHERE SlNO Not IN (1,4)
		ORDER BY a.SlNo,b.Code 
	end
--- Ned To incorporate To MHL
----INSERT INTO tbl_CHART_OF_ACCOUNTS (code,Description , Type , UserName , Valid ,Pno , GId)
----VALUES ('4102080000','Electricity Bill Exp.' ,'Profit And Loss A/C','Arif',1,1,4)

----INSERT INTO tbl_CHART_OF_ACCOUNTS (code,Description , Type , UserName , Valid ,Pno , GId)
----VALUES ('2201040000','Furniture and fixtures' ,'Balance Sheet','Arif',1,1,4)


END
GO
