CREATE PROCEDURE [dbo].[SP_WEB_ReceiptPayment] (@lcAcCode nvarchar(20), @DateFrom DateTime, @DateTo datetime, @BranchId int, @CostCenter nvarchar(50), @PartyCode VARCHAR(20))
AS 
IF @lcAcCode <> '' 
	BEGIN
		SELECT cc.Code,cc.Description, cc.PartyCode, cc.PartyName,isnull(cc.OB,0) as OB, isnull(cc.Receive,0) as Receive, cc.Payment , 
		isnull(cc.CB,0) as CB,cc.SlNo 
		FROM (
		SELECT a.Code, b.Description, a.PartyCode, a.PartyName, 0 as OB, SUM(a.Debit) AS Payment, SUM(a.Credit) AS Receive, 0 as CB, 2 as SlNo 
		from tbl_TRANSACT a, tbl_CHART_OF_ACCOUNTS b
		where a.Valid <> 0 AND a.Code=b.Code AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
	--	and a.VoucherType IN ('Cash') 
		and a.ContraCode LIKE @lcAcCode+'%'
		and Trans_dt BETWEEN @DateFrom  and @DateFrom AND a.PartyCode LIKE '%'+@PartyCode+'%'
		GROUp BY a.Code, b.Description, a.PartyCode, a.PartyName
		UNION ALL
		SELECT '-', 'Opening Balance', '' AS PartyCode, '' AS PartyName, SUM(a.debit-a.Credit),0 ,0 , 0, 1 AS SlNo
		from tbl_TRANSACT a 
		where a.Valid <> 0  AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
	--	and a.VoucherType IN ('Cash') 
		AND a.trans_dt < @DateFrom 
		and a.code LIKE @lcAcCode+'%' AND a.PartyCode LIKE '%'+@PartyCode+'%'
		UNION ALL
		SELECT '-' ,'Closing Balance', '' AS PartyCode, '' AS PartyName, 0,0,0,SUM(a.debit-a.Credit), 4 AS SlNo
		from tbl_TRANSACT a
		where a.Valid <> 0 AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
	--	and a.VoucherType IN ('Cash') 
		AND a.trans_dt <= @DateFrom
		and a.code LIKE @lcAcCode+'%' AND a.PartyCode LIKE '%'+@PartyCode+'%'
		UNION ALL
		SELECT '-' ,'Total', '' AS PartyCode, '' AS PartyName,  0,ISNULL(SUM(a.Credit),0),ISNULL(SUM(a.debit),0),0, 3 AS SlNo
		from tbl_TRANSACT a
		where a.Valid <> 0 AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
	--	and a.VoucherType IN ('Cash') 
		and Trans_dt BETWEEN @DateFrom  and @DateFrom AND a.PartyCode LIKE '%'+@PartyCode+'%'
		and a.code LIKE @lcAcCode+'%') cc
		ORDER BY cc.SlNo, cc.Code

	END
ELSE
	BEGIN
		SELECT cc.Code,cc.Description, cc.PartyCode, cc.PartyName, isnull(cc.OB,0) as OB, isnull(cc.Receive,0) as Receive, cc.Payment , 
		isnull(cc.CB,0) as CB,cc.SlNo 
		FROM (
		SELECT a.Code ,b.Description, a.PartyCode, a.PartyName, 0 as OB , SUM(a.Debit) AS Payment,SUM(a.Credit) AS Receive  , 0 as CB, 2 as SlNo 
		from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b
		where a.Valid <> 0 AND a.Code=b.Code AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
	--	and a.VoucherType IN ('Cash') 
		and a.ContraCode LIKE '2101'+'%'
		and Trans_dt BETWEEN @DateFrom  and @DateTo AND a.PartyCode LIKE '%'+@PartyCode+'%'
		GROUp BY a.Code ,b.Description, a.PartyCode, a.PartyName
		UNION ALL
		SELECT '-' ,'Opening Balance', '' AS PartyCode, '' AS PartyName,  SUM(a.debit-a.Credit),0,0, 0 , 1 AS SlNo
		from tbl_TRANSACT a, tbl_CHART_OF_ACCOUNTS b
		where a.Valid <> 0 AND a.ContraCode=b.Code AND a.BranchId = @BranchId  AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
	--	and a.VoucherType IN ('Cash') 
		AND a.trans_dt < @DateFrom 
		and a.code LIKE '2101'+'%' AND a.PartyCode LIKE '%'+@PartyCode+'%'
		UNION ALL
		SELECT '-' ,'Closing Balance' , '' AS PartyCode, '' AS PartyName, 0,0,0,SUM(a.debit-a.Credit), 6 AS SlNo
		from tbl_TRANSACT a, tbl_CHART_OF_ACCOUNTS b
		where a.Valid <> 0 AND a.ContraCode=b.Code AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
	--	and a.VoucherType IN ('Cash') 
		AND a.trans_dt <= @DateTo 
		and a.code LIKE '2101'+'%' AND a.PartyCode LIKE '%'+@PartyCode+'%'
		UNION ALL
		SELECT '-' ,'Total' , '' AS PartyCode, '' AS PartyName, 0,ISNULL(SUM(a.Credit),0),ISNULL(SUM(a.debit),0),0, 3 AS SlNo
		from tbl_TRANSACT a, tbl_CHART_OF_ACCOUNTS b
		where a.Valid <> 0 AND a.ContraCode=b.Code AND a.BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
	--	and a.VoucherType IN ('Cash') 
		and Trans_dt BETWEEN @DateFrom and @DateTo AND a.PartyCode LIKE '%'+@PartyCode+'%'
		and a.code LIKE '2101'+'%') cc
		ORDER BY cc.SlNo , cc.Code
	END

GO
/****** Object:  StoredProcedure [dbo].[SP_WEB_ReceivePaymentCashBankDtls]    Script Date: 3/12/2026 6:25:16 AM ******/
