--- Given to Al Amin 15/06/2025 01:00pm
create PROCEDURE [dbo].[SP_WEB_ReceivePaymentCashBankDtls] (@DateFrom date , @DateTo date , @BranchId integer) 
AS 
BEGIN --EXEC SP_WEB_ReceivePaymentCashBankDtls '2023-02-12','2023-02-12',1

--drop table tmpRP1
--drop table tmpRP2



SELECT ROW_NUMBER() OVER (order by aa.TrNo) as SlNo ,aa.Trans_dt , aa.TrNo, aa.Code AS RecvCode,aa.ACName, aa.Description as RecvACName , SUM(aa.CashReceive) As CashReceive ,  SUM(aa.BankReceive) as BankReceive , aa.BalSlNo
INTO #tmpRP1
FROM (
select a.Trans_dt , a.TrNo , a.code,c.Description as ACName , b.Description , a.credit as CashReceive ,  0 as BankReceive , 1 as BalSlNo
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b  , tbl_CHART_OF_ACCOUNTS c
where a.Code = b.Code AND a.ContraCode = c.Code and a.BranchId = c.BranchId 
and a.valid = 1 AND a.BranchId = b.BranchId 
and a.trans_dt BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId 
and a.ContraCode like '210102'+'%'
and Credit <> 0
UNION ALL
select dateadd(day,-1,@DateFrom) as Trans_dt, 0 as TrNo , a.code,b.Description as ACName , 'Opening Balance ' as Description , SUM(a.Debit-a.credit) as CashReceive ,  
0 as BankReceive , 0 as BalSlNo
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b  
where a.Code = b.Code 
and a.valid = 1 AND a.BranchId = b.BranchId 
and a.trans_dt < @DateFrom  AND a.BranchId = @BranchId 
and a.Code like '210102'+'%'
and (Credit+Debit) <> 0
GROUP BY a.code,b.Description
UNION ALL
select a.Trans_dt , a.TrNo, a.code,c.Description as ACName , b.Description , 0 as CashReceive ,  a.credit as BankReceive , 1 as BalSlNo
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b  , tbl_CHART_OF_ACCOUNTS c
where a.Code = b.Code AND a.ContraCode = c.Code and a.BranchId = c.BranchId 
and a.valid = 1 AND a.BranchId = b.BranchId 
and a.trans_dt BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId 
and a.ContraCode like '210101'+'%'
and Credit <> 0
UNION ALL
select dateadd(day,-1,@DateFrom) as Trans_dt , 0 as TrNo, a.code,b.Description as ACName , 'Opening Balance' as Description , 0 as CashReceive ,  
SUM(a.Debit-a.credit) as BankReceive , 0 as BalSlNo
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b  
where a.Code = b.Code 
and a.valid = 1 AND a.BranchId = b.BranchId 
and a.trans_dt < @DateFrom AND a.BranchId = @BranchId 
and a.Code like '210101'+'%'
and (Credit+debit) <> 0
GROUP BY a.code,b.Description
UNION ALL
select dateadd(day,-1,@DateFrom) as Trans_dt , '99999980' as TrNo, '' as code,'' as ACName , '' as Description , 0 as CashReceive ,  
0 as BankReceive , 4 as BalSlNo
UNION ALL
select dateadd(day,-1,@DateFrom) as Trans_dt , '99999981' as TrNo, '' as code,'' as ACName , '' as Description , 0 as CashReceive ,  
0 as BankReceive , 4 as BalSlNo
UNION ALL 
select dateadd(day,-1,@DateFrom) as Trans_dt , '99999982' as TrNo, '' as code,'Total Receive With Opening' as ACName , 'Total Receive With Opening' as Description , 0 as CashReceive ,  
0 as BankReceive , 4 as BalSlNo) aa
GROUP BY aa.Trans_dt , aa.TrNo, aa.Code ,aa.ACName, aa.Description , aa.BalSlNo

declare @lnTotalCashReceive float;
declare @lnTotalBankReceive Float;

set @lnTotalCashReceive = (SELECT SUM(CashReceive) FROM #tmpRP1);
set @lnTotalBankReceive =(SELECT SUM(BankReceive) FROM #tmpRP1);



UPDATE #tmpRP1 SET CashReceive = @lnTotalCashReceive , BankReceive = @lnTotalBankReceive 
WHERE TrNo ='99999982'


SELECT ROW_NUMBER() OVER (order by bb.TrNo) as SlNoPay ,bb.Trans_dt as Trans_dtPay, bb.TrNo as TrNoPay ,bb.code as PayCode,bb.ACName AS PayAcHead,bb.Description as PayACName, SUM(bb.CashPayment) AS CashPayment ,  SUM(bb.BankPayment) AS BankPayment , bb.BalSlNoPay
INTO #tmpRP2
FROM (
select a.Trans_dt , a.TrNo ,a.code,c.Description as ACName,  b.Description , a.Debit as CashPayment ,  0 as BankPayment , 0 as BalSlNoPay
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b , tbl_CHART_OF_ACCOUNTS c
where a.Code = b.Code AND a.ContraCode = c.Code and a.BranchId = c.BranchId 
and a.valid = 1 
and a.trans_dt BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId 
and a.ContraCode like '210102'+'%'
and a.Debit <> 0
UNION ALL
select a.Trans_dt , a.TrNo ,a.code,c.Description as ACName,b.Description , 0 as CashPayment ,  a.Debit as BankPayment , 0 as BalSlNo
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b , tbl_CHART_OF_ACCOUNTS c
where a.Code = b.Code AND a.ContraCode = c.Code and a.BranchId = c.BranchId 
and a.trans_dt BETWEEN @DateFrom AND @DateTo AND a.BranchId = @BranchId 
and a.valid = 1 
and a.ContraCode like '210101'+'%'
and Debit <> 0
UNION ALL
select @DateTo as Trans_dt, '99999990' as TrNo , '','' as ACName , '' as Description , 0 as CashReceive ,  
0 as BankReceive  , 9 as BalSlNo
UNION ALL
select @DateTo as Trans_dt, '99999991' as TrNo , '','' as ACName , '' as Description , 0 as CashReceive ,  
0 as BankReceive  , 9 as BalSlNo
UNION ALL 
select @DateTo as Trans_dt, '99999992' as TrNo , '','' as ACName , '' as Description , 0 as CashReceive ,  
0 as BankReceive  , 9 as BalSlNo
UNION ALL
select @DateTo as Trans_dt, '99999999' as TrNo , a.code,b.Description as ACName , 'Closing Balance ' as Description , SUM(a.Debit-a.credit) as CashReceive ,  
0 as BankReceive  , 9 as BalSlNo
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b  
where a.Code = b.Code 
and a.valid = 1 AND a.BranchId = b.BranchId 
and a.trans_dt <= @DateTo AND a.BranchId = @BranchId 
and a.Code like '210102'+'%'
and (Credit+Debit) <> 0
GROUP BY a.code,b.Description
UNION ALL
select @DateTo as Trans_dt, '99999999' as TrNo , a.code,b.Description as ACName , 'Closing Balance ' as Description , 0 as CashReceive ,  
SUM(a.Debit-a.credit) as BankReceive , 9 as BalSlNo
from tbl_TRANSACT a , tbl_CHART_OF_ACCOUNTS b  
where a.Code = b.Code 
and a.valid = 1 AND a.BranchId = b.BranchId 
and a.trans_dt <= @DateTo AND a.BranchId = @BranchId 
and a.Code like '210101'+'%'
and (Credit+Debit) <> 0
GROUP BY a.code,b.Description) bb
GROUP BY bb.Trans_dt , bb.TrNo ,bb.code ,bb.ACName,bb.Description , bb.BalSlNoPay 


declare @lnTotalCashPay float;
declare @lnTotalBankPay Float;

set @lnTotalCashPay = (SELECT SUM(CashPayment) FROM #tmpRP2 WHERE BalSlNoPay <> 9);
set @lnTotalBankPay =(SELECT SUM(BankPayment) FROM #tmpRP2 WHERE BalSlNoPay <> 9);



UPDATE #tmpRP2 SET CashPayment = @lnTotalCashPay , BankPayment = @lnTotalBankPay , PayAcHead = 'Total Payment',PayACName = 'Total Payment'
WHERE TrNoPay ='99999991'



SELECT a.*, b.*
FROM #tmpRP1 a
FULL OUTER JOIN #tmpRP2 b ON a.SlNo = b.SlNoPay
ORDER BY b.slnoPay,b.BalSlNoPay

END

GO
