CREATE PROCEDURE [dbo].[SP_WEB_ReceivePaymentCashBankSMZ] (@DateFrom date , @DateTo date , @BranchId integer) 
AS 
BEGIN --EXEC SP_WEB_ReceivePaymentCashBankSMZ '2023-02-12','2023-02-12',1

--drop table tmpRP3

SELECT  aa.Code , bb.Description , SUM(aa.Opening) as Opening , SUM(aa.ReceiveAmt) as ReceiveAmt , SUM(aa.PaymentAmt)  as PaymentAmt, SUM(aa.Closing)  as Closing , LEFT(aa.Code ,6)+'0000' as GP , 0 as slno
INTO #tmpRP3
FROM (
select code, (Debit-Credit) AS Opening , 0 as ReceiveAmt , 0 as PaymentAmt , 0 as Closing
from tbl_TRANSACT 
where code like '2101'+'%' and valid=1 AND BranchId = @BranchId 
AND trans_dt < @DateFrom 
UNION ALL
select code, 0 AS Opening , DEBIT as ReceiveAmt , Credit as PaymentAmt , 0 as Closing
from tbl_TRANSACT 
where code like '2101'+'%' and valid=1 AND BranchId = @BranchId 
AND trans_dt BETWEEN @DateFrom  and @DateTo 
UNION ALL
select code, 0 AS Opening , 0 as ReceiveAmt , 0 as PaymentAmt , (Debit-Credit) as Closing
from tbl_TRANSACT 
where code like '2101'+'%' and valid=1 AND BranchId = @BranchId 
AND trans_dt <= @DateTo) aa , tbl_CHART_OF_ACCOUNTS bb
WHERE aa.code =bb.Code
GROUP BY aa.Code , bb.Description



--INSERT INTO #tmpRP3 (Code,Description,Opening,ReceiveAmt,PaymentAmt,Closing,GP,slno)
--select a.GP,'Total of ' + b.Description,SUM(a.Opening),SUM(a.ReceiveAmt),SUM(a.PaymentAmt),SUM(a.Closing),a.GP,2
--from tmprp3 a , tbl_CHART_OF_ACCOUNTS b
--where a.GP = b.Code 
--GROUP BY a.GP,b.Description


select * from #tmprp3 ORDER BY Code DESC,SLNO 


END
