CREATE PROCEDURE [dbo].[SP_WEB_TrialBalance] (@DateFrom DateTime , @DateTo datetime, @lcAcCode varchar(20), @lcLevel varchar(20), @BranchId varchar(20), @CostCenter varchar(50))
AS 
	DROP TABLE tmp_WEB_Trialbal
	DROP TABLE tmp_WEB_TB
	
	UPDATE tbl_chart_of_Accounts SET GId = 1 where code like '2'+'%'
	UPDATE tbl_chart_of_Accounts SET GId = 2 where code like '1'+'%'
	UPDATE tbl_chart_of_Accounts SET GId = 3 where code like '3'+'%'
	UPDATE tbl_chart_of_Accounts SET GId = 4 where code like '4'+'%'

	BEGIN
		SELECT aa.code,bb.Description, ISNULL(SUM(aa.Dr),0) AS DR, ISNULL(SUM(aa.Cr),0) AS CR  
		INTO tmp_WEB_Trialbal
		FROM (
		select Code, (Debit-Credit) as Dr , 0 as Cr 
		FROM tbl_transact   
		WHERE Valid <> 0 AND BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
		AND SUBSTRING(Code,1,1) IN ('2')
		and trans_dt <= @DateTo
		UNION ALL 
		select Code,0 AS Dr, (Credit-Debit) as Cr 
		FROM tbl_transact   
		WHERE Valid <> 0 AND BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
		AND SUBSTRING(Code,1,1) IN ('1')
		and trans_dt <= @DateTo
		UNION ALL 
		select Code, 0 AS Dr, (Credit-Debit) as Cr 
		FROM tbl_transact   
		WHERE Valid <> 0 AND BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
		AND SUBSTRING(Code,1,1) IN ('3')
		and trans_dt BETWEEN @Datefrom and @DateTo
		UNION ALL
		select Code, (Debit-Credit) AS Dr, 0 as Cr 
		FROM tbl_transact   
		WHERE Valid <> 0 AND BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
		AND SUBSTRING(Code,1,1) IN ('4')
		and trans_dt BETWEEN @Datefrom and @DateTo		
		) aa , tbl_chart_of_Accounts bb
		where aa.code=BB.code 
		and aa.code LIKE @lcAcCode + '%'
		GROUP BY aa.code ,bb.Description

		if @lcLevel = '1' 
		begin
			SELECT (SUBSTRING(a.code,1,1)+'000000000') AS Code,(SPACE(5)+b.description) AS description,SUM(a.DR) AS DR ,SUM(a.CR) AS Cr , b.GId
			INTO tmp_WEB_TB
			FROM tmp_WEB_Trialbal a , tbl_chart_of_Accounts b
			where SUBSTRING(a.code,1,1)+'000000000'=b.code
			GROUP BY SUBSTRING(a.code,1,1)+'000000000',b.description, b.GId
		end
		else if @lcLevel = '2' 
		begin
					SELECT (SUBSTRING(a.code,1,2)+'00000000') AS Code,(SPACE(5)+b.description) AS description,SUM(a.DR) AS DR ,SUM(a.CR) AS Cr , b.GId
					INTO tmp_WEB_TB					
					FROM tmp_WEB_Trialbal a , tbl_chart_of_Accounts b
					where SUBSTRING(a.code,1,2)+'00000000'=b.code
					GROUP BY SUBSTRING(a.code,1,2)+'00000000',b.description, b.GId
		end
		else if @lcLevel = '3' 
		begin
					SELECT (SUBSTRING(a.code,1,4)+'000000') AS Code,(SPACE(5)+b.description) AS description,SUM(a.DR) AS DR ,SUM(a.CR) AS Cr, b.GId
					INTO tmp_WEB_TB					
					FROM tmp_WEB_Trialbal a , tbl_chart_of_Accounts b
					where SUBSTRING(a.code,1,4)+'000000'=b.code
					GROUP BY SUBSTRING(a.code,1,4)+'000000',b.description, b.GId
		end
		else if @lcLevel = '4' 
		begin
					SELECT (SUBSTRING(a.code,1,6)+'0000') AS Code,(SPACE(5)+b.description) AS description,SUM(a.DR) AS DR ,SUM(a.CR) AS Cr, b.GId
					INTO tmp_WEB_TB
					FROM tmp_WEB_Trialbal a , tbl_chart_of_Accounts b
					where SUBSTRING(a.code,1,6)+'0000'=b.code
					GROUP BY SUBSTRING(a.code,1,6)+'0000',b.description, b.GId
		end
		else if @lcLevel = '5' 
		begin
			SELECT a.code,(SPACE(5)+b.description) AS description,SUM(a.DR) AS DR ,SUM(a.CR) AS Cr, b.GId
			INTO tmp_WEB_TB
			FROM tmp_WEB_Trialbal a , tbl_chart_of_Accounts b
			where a.code=b.code
			GROUP BY a.code,b.description, b.GId
		end

		ALTER table tmp_WEB_TB ADD SlNo integer
		UPDATE tmp_WEB_TB SET SlNo = 2


		-- For Group A/C Insert	

		if @lcLevel = '5' 
		begin
			INSERT INTO tmp_WEB_TB (Code,description,DR,CR,SlNo,GID)
			SELECT (SUBSTRING(a.code,1,6)+'0000') AS Code,b.description,SUM(a.DR) AS DR ,SUM(a.CR) AS Cr,1, b.GId
			FROM tmp_WEB_Trialbal a , tbl_chart_of_Accounts b
			where SUBSTRING(a.code,1,6)+'0000'=b.code
			GROUP BY SUBSTRING(a.code,1,6)+'0000',b.description, b.GId
		end

		if @lcLevel = '4' 
		begin
			INSERT INTO tmp_WEB_TB (Code,description,DR,CR,SlNo,Gid)
			SELECT (SUBSTRING(a.code,1,4)+'000000') AS Code,b.description,SUM(a.DR) AS DR ,SUM(a.CR) AS Cr,1, b.GId
			FROM tmp_WEB_Trialbal a , tbl_chart_of_Accounts b
			where SUBSTRING(a.code,1,4)+'000000'=b.code
			GROUP BY SUBSTRING(a.code,1,4)+'000000',b.description, b.GId
		end

		if @lcLevel = '3' 
		begin
			INSERT INTO tmp_WEB_TB (Code,description,DR,CR,SlNo,GID)
			SELECT (SUBSTRING(a.code,1,2)+'00000000') AS Code,b.description,SUM(a.DR) AS DR ,SUM(a.CR) AS Cr,1, b.GId
			FROM tmp_WEB_Trialbal a , tbl_chart_of_Accounts b
			where SUBSTRING(a.code,1,2)+'00000000'=b.code
			GROUP BY SUBSTRING(a.code,1,2)+'00000000',b.description, b.GId
		end
		
				
		UPDATE tmp_WEB_TB SET DR = 0 , Cr = ABS(Dr) WHERE DR<0 
		UPDATE tmp_WEB_TB SET DR = ABS(CR) , Cr = 0 WHERE CR<0 

		INSERT INTO tmp_WEB_TB (Code,Description,Dr,Cr,GId,SlNo )
		select '1102010002','Previous Profit and Loss A/C',0,SUM(Dr-Cr) as Bal ,2,2
		from tmp_WEB_TB 
		where slno = 2
		HAVING SUM(Dr-Cr) > 0 

		INSERT INTO tmp_WEB_TB (Code,Description,Dr,Cr,GId,SlNo )
		select '1102010002','Previous Profit and Loss A/C',ABS(SUM(Dr-Cr)),0 as Bal ,2,2
		from tmp_WEB_TB 
		where slno = 2
		HAVING SUM(Dr-Cr) < 0 
		
		INSERT INTO tmp_WEB_TB (Code,Description,Dr,Cr,Slno,GId) 
		SELECT '9999999999','GRAND TOTAL',SUM(Dr),SUM(CR),5,5
		FROM tmp_WEB_TB 
		WHERE Slno = 2

		select Code, Description, ISNULL(DR,0) AS DR, ISNULL(Cr,0) AS CR, GId, SlNo from tmp_WEB_TB ORDER BY GID,Code 
END		
GO
