CREATE PROCEDURE [dbo].[SP_WEB_TrMovement] (@DateFrom DateTime , @DateTo datetime,@lcAcCode nvarchar(20),@lcLevel nvarchar(1), @BranchId int, @CostCenter nvarchar(50))
AS 
DECLARE  @lcActualAcCode nvarchar(20);

 --------if(@ParLngId = 0)
 --------       begin
 --------           Insert Into T_Param values ('PHY', 'Extranet Client', Null, Null, 'T', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL)
 --------           SET @ParLngId = @@IDENTITY
 --------       End
	SET @lcActualAcCode = @lcAcCode

	if (RIGHT(@lcAcCode,4)='0000')
		BEGIN
			SET @lcActualAcCode = LEFT(@lcAcCode,6)
		END
	if (RIGHT(@lcAcCode,6)='000000')
		BEGIN
			SET @lcActualAcCode = LEFT(@lcAcCode,4)
		END	

	if (RIGHT(@lcAcCode,8)='00000000')
		BEGIN
			SET @lcActualAcCode = LEFT(@lcAcCode,2)
		END
		

--	ALTER TABLE tbl_chart_of_Accounts ADD GId integer default 1

	


	DROP TABLE tmp_WEB_TrMovement

	UPDATE tbl_chart_of_Accounts SET GId = 1 where code like '2'+'%'
	UPDATE tbl_chart_of_Accounts SET GId = 2 where code like '1'+'%'
	UPDATE tbl_chart_of_Accounts SET GId = 3 where code like '3'+'%'
	UPDATE tbl_chart_of_Accounts SET GId = 4 where code like '4'+'%'

	BEGIN
		SELECT aa.code,bb.Description, SUM(aa.OPDr) AS OPDr, SUM(aa.OPCr) AS OPCr, SUM(aa.Dr) AS DR, 
		SUM(aa.Cr) AS CR  , SUM(aa.CBDr) AS CBDr, SUM(aa.CBCr) AS CBCr, aa.BranchId
		INTO tmp_WEB_TrMovement
		FROM (
		select Code, (Debit-Credit) as OPDr, 0 as OPCr, 0 as Dr, 0 as Cr, 0 AS CBDr, 0 AS CBCr, BranchId
		FROM tbl_transact   
		WHERE Valid <> 0 AND BranchId = @BranchId  AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
		AND SUBSTRING(Code, 1, 1) IN ('2','4')
		and trans_dt < @DateFrom 
		UNION ALL 
		select Code, 0 as OPDr, (Credit-Debit) as OPCR, 0 as Dr, 0 AS Cr, 0 AS CBDr, 0 AS CBCr, BranchId
		FROM tbl_transact   
		WHERE Valid <> 0 AND BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
		AND SUBSTRING(Code,1,1) IN ('1','3')
		and trans_dt < @DateFrom 
		UNION ALL
		select Code, 0, 0, (Debit) as Dr, (Credit) as Cr, 0 AS CBDr, 0 AS CBCr, BranchId
		FROM tbl_transact   
		WHERE Valid <> 0 AND BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
		and trans_dt BETWEEN @DateFrom  AND @DateTo  
		UNION ALL
		select Code, 0 as OPDr, 0 as OPCr, 0 as Dr, 0 as Cr, (Debit-Credit) AS CBDr, 0 AS CBCr, BranchId
		FROM tbl_transact   
		WHERE Valid <> 0 AND BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
		AND SUBSTRING(Code,1,1) IN ('2','4')
		and trans_dt <= @DateTo  
		UNION ALL
		select Code,0 as OPDr , 0 as OPCr , 0 as Dr,0 as Cr , 0 AS CBDr, (Credit-Debit) AS CBCr, BranchId
		FROM tbl_transact   
		WHERE Valid <> 0 AND BranchId = @BranchId AND RTRIM(LTRIM(CostDept)) LIKE '%'+@CostCenter+'%'
		AND SUBSTRING(Code,1,1) IN ('1','3')
		and trans_dt <= @DateTo ) aa, tbl_chart_of_Accounts bb
		where aa.code = BB.code AND aa.BranchId=bb.BranchId
		and bb.BranchId = @BranchId
		--and aa.code LIKE @lcAcCode + '%'
		and aa.code LIKE @lcActualAcCode + '%'
		GROUP BY aa.code ,bb.Description, aa.BranchId		
		
		--SELECT aa.code,bb.Description, SUM(aa.OPDr) AS OPDr, SUM(aa.OPCr) AS OPCr, SUM(aa.Dr) AS DR, 
		--SUM(aa.Cr) AS CR  , SUM(aa.CBDr) AS CBDr, SUM(aa.CBCr) AS CBCr 
		--INTO tmp_WEB_TrMovement
		--FROM (
		--select Code,(Debit-Credit) as OPDr , 0 as OPCr , 0 as Dr,0 as Cr , 0 AS CBDr, 0 AS CBCr
		--FROM tbl_transact   
		--WHERE Valid <> 0 
		--AND SUBSTRING(Code,1,1) IN ('2','4')
		--and trans_dt < @DateFrom 
		--UNION ALL 
		--select Code,0 as OPDr , (Credit-Debit) as OPCR,0 as Dr,0 AS Cr , 0 AS CBDr, 0 AS CBCr
		--FROM tbl_transact   
		--WHERE Valid <> 0 
		--AND SUBSTRING(Code,1,1) IN ('1','3')
		--and trans_dt < @DateFrom
		--UNION ALL
		--select Code,0,0,(Debit) as Dr , (Credit) as Cr , 0 AS CBDr, 0 AS CBCr
		--FROM tbl_transact   
		--WHERE Valid <> 0 
		--and trans_dt BETWEEN @DateFrom AND @DateTo 
		--UNION ALL
		--select Code,0 as OPDr , 0 as OPCr , 0 as Dr,0 as Cr , (Debit-Credit) AS CBDr, 0 AS CBCr
		--FROM tbl_transact   
		--WHERE Valid <> 0 
		--AND SUBSTRING(Code,1,1) IN ('2','4')
		--and trans_dt <= @DateTo 
		--UNION ALL
		--select Code,0 as OPDr , 0 as OPCr , 0 as Dr,0 as Cr , 0 AS CBDr, (Credit-Debit) AS CBCr
		--FROM tbl_transact   
		--WHERE Valid <> 0 
		--AND SUBSTRING(Code,1,1) IN ('1','3')
		--and trans_dt <= @DateTo ) aa , tbl_chart_of_Accounts bb
		--where aa.code=BB.code 
		--and aa.code LIKE @lcAcCode + '%'
		--GROUP BY aa.code ,bb.Description

		if @lcLevel = '1' 
		begin
			SELECT (SUBSTRING(a.code,1,1)+'000000000') AS Code,b.description,SUM(a.OPDr) AS OPDr ,SUM(a.OPCr) AS OPCr,
			SUM(a.DR) AS DR ,SUM(a.CR) AS Cr,SUM(a.CBDr) AS CBDR,SUM(a.CBCr) AS CBCr ,b.GID 
			FROM tmp_WEB_TrMovement a, tbl_chart_of_Accounts b
			where SUBSTRING(a.code,1,1)+'000000000'=b.code AND a.BranchId = @BranchId ANd a.BranchId=b.BranchId
			GROUP BY SUBSTRING(a.code,1,1)+'000000000',b.description,b.GID 
			ORDER BY b.GID,SUBSTRING(a.code,1,1)+'000000000'
		end
		else if @lcLevel = '2' 
		begin
			SELECT (SUBSTRING(a.code,1,2)+'00000000') AS Code,b.description,SUM(a.OPDr) AS OPDr ,SUM(a.OPCr) AS OPCr,
			SUM(a.DR) AS DR ,SUM(a.CR) AS Cr,SUM(a.CBDr) AS CBDR,SUM(a.CBCr) AS CBCr ,b.GID 
			FROM tmp_WEB_TrMovement a , tbl_chart_of_Accounts b
			where SUBSTRING(a.code,1,2)+'00000000'=b.code AND a.BranchId = @BranchId ANd a.BranchId=b.BranchId
			GROUP BY SUBSTRING(a.code,1,2)+'00000000',b.description,b.GID 
			ORDER BY b.GID ,SUBSTRING(a.code,1,2)+'00000000'
		end
		else if @lcLevel = '3' 
		begin
			SELECT (SUBSTRING(a.code,1,4)+'000000') AS Code,b.description,SUM(a.OPDr) AS OPDr ,SUM(a.OPCr) AS OPCr,
			SUM(a.DR) AS DR ,SUM(a.CR) AS Cr,SUM(a.CBDr) AS CBDR,SUM(a.CBCr) AS CBCr ,b.GID 
			FROM tmp_WEB_TrMovement a , tbl_chart_of_Accounts b
			where SUBSTRING(a.code,1,4)+'000000'=b.code AND a.BranchId = @BranchId ANd a.BranchId=b.BranchId
			GROUP BY SUBSTRING(a.code,1,4)+'000000',b.description,b.GID 
			ORDER BY b.GID, SUBSTRING(a.code,1,4)+'000000'
		end
		else if @lcLevel = '4' 
		begin
			SELECT (SUBSTRING(a.code,1,6)+'0000') AS Code,b.description,SUM(a.OPDr) AS OPDr ,SUM(a.OPCr) AS OPCr,
			SUM(a.DR) AS DR ,SUM(a.CR) AS Cr,SUM(a.CBDr) AS CBDR,SUM(a.CBCr) AS CBCr ,b.GID 
			FROM tmp_WEB_TrMovement a , tbl_chart_of_Accounts b
			where SUBSTRING(a.code,1,6)+'0000'=b.code AND a.BranchId = @BranchId ANd a.BranchId=b.BranchId
			GROUP BY SUBSTRING(a.code,1,6)+'0000',b.description,b.GID 
			ORDER BY b.GID ,SUBSTRING(a.code,1,6)+'0000'
		end
		else if @lcLevel = '5' 
		begin
			SELECT a.code,b.description,SUM(a.OPDr) AS OPDr ,SUM(a.OPCr) AS OPCr,
			SUM(a.DR) AS DR ,SUM(a.CR) AS Cr,SUM(a.CBDr) AS CBDR,SUM(a.CBCr) AS CBCr ,b.GID 
			FROM tmp_WEB_TrMovement a , tbl_chart_of_Accounts b
			where a.code=b.code AND a.BranchId = @BranchId ANd a.BranchId=b.BranchId
			GROUP BY a.code,b.description,b.GID 
			ORDER BY b.GID ,a.code
		end
END		
GO
