CREATE PROC [dbo].[SP_WorkingStatusOverview]  @FromDate Date, @ToDate Date, @DeptCode nvarchar(20), @DesigCode nvarchar(20), @BranchId int, @WorkingStatusId INT
AS
BEGIN -- SP_WorkingStatusOverview '2023-01-01', '2024-10-20', '', '', 1, 2

	SELECT a.Code, a.Name, a.NID, a.MobileNo, a.Gender, a.Religion, a.DeptCode, a.Department, a.DesigCode, a.Designation, a.WorkingStatus, a.WorkingStatusId, b.Remarks 
	FROM HREmployeeMaster AS a 
	LEFT JOIN EmpWorkingStatus AS b ON a.Code = b.EmpCode AND a.Valid = b.Valid
	WHERE a.BranchId=@BranchId AND a.WorkingStatusId = @WorkingStatusId
	AND (CASE WHEN a.WorkingStatusId=1 THEN a.DateOfJoining ELSE b.FromDate END) BETWEEN @FromDate AND @ToDate
	AND a.DeptCode LIKE '%'+@DeptCode+'%' AND a.DesigCode LIKE '%'+@DesigCode+'%'
END
GO
