CREATE PROC [dbo].[TMP_RPT_TotalSalesByDr](@dateFrom date, @DateTo date, @drCode nvarchar(50))
AS
BEGIN
SELECT aa.PatientId, aa.PatientName, SUM(HospitalBill) AS HospitalBill, SUM(aa.OTCharge) AS OTCharge, SUM(aa.Diagnostic) AS Diagnostic FROM (

select a.PatientId, a.PatientName, SUM(b.NoU*b.Charge-b.Less) As HospitalBill, 0 AS OTCharge, 0 AS Diagnostic from PatientAdmission a
LEFT JOIN PatientLedger b ON a.PatientId = b.PatientId AND b.Valid = 1
LEFT JOIN ClinicalChart c ON b.Code = c.PCode
where a.Valid = 1 AND a.UnderDrCode = @drCode AND a.AdmissionDate BETWEEN @dateFrom AND @DateTo AND b.Code != '0011' AND c.SubSubDeptName != 'General OT'
GROUP BY a.PatientId, a.PatientName
UNION ALL
select a.PatientId, a.PatientName, 0 AS HospitalBill, SUM(b.NoU*b.Charge-b.Less) As OTCharge, 0 AS Diagnostic from PatientAdmission a
LEFT JOIN PatientLedger b ON a.PatientId = b.PatientId AND b.Valid = 1
LEFT JOIN ClinicalChart c ON b.Code = c.PCode
where a.Valid = 1 AND a.UnderDrCode = @drCode AND a.AdmissionDate BETWEEN @dateFrom AND @DateTo AND b.Code != '0011' AND c.SubSubDeptName = 'General OT'
GROUP BY a.PatientId, a.PatientName
UNION ALL
select a.PatientId, a.PatientName, 0, 0, SUM(b.Sales-b.Less) AS Diagn from InvMaster a
LEFT JOIN SalesLedger b ON a.BranchId = b.BranchId AND a.InvNo = b.PrevInvNo
WHERE a.ConsultantCode = @drCode AND a.InvDate BETWEEN @dateFrom AND @DateTo and a.PtStatus = 'Indoor'
GROUP BY a.PatientId, a.PatientName

--select a.PatientId, a.PatientName, SUM(b.NoU*b.Charge) As HospitalBill, 0 AS OTCharge, 0 AS Diagnostic from PatientAdmission a
--LEFT JOIN PatientLedger b ON a.PatientId = b.PatientId AND b.Valid = 1
--LEFT JOIN ClinicalChart c ON b.Code = c.PCode
--where a.Valid = 1 AND a.UnderDrCode = @drCode AND a.AdmissionDate BETWEEN @dateFrom AND @DateTo AND c.SubSubDeptName != 'General OT'
--GROUP BY a.PatientId, a.PatientName
--UNION ALL
--select a.PatientId, a.PatientName, 0 AS HospitalBill, SUM(b.NoU*b.Charge) As OTCharge, 0 AS Diagnostic from PatientAdmission a
--LEFT JOIN PatientLedger b ON a.PatientId = b.PatientId AND b.Valid = 1
--LEFT JOIN ClinicalChart c ON b.Code = c.PCode
--where a.Valid = 1 AND a.UnderDrCode = @drCode AND a.AdmissionDate BETWEEN @dateFrom AND @DateTo AND c.SubSubDeptName = 'General OT'
--GROUP BY a.PatientId, a.PatientName
--UNION ALL
--select PatientId, PatientName, 0, 0, SUM(TotalAmt) AS Diagn from InvMaster a
--WHERE ConsultantCode = @drCode AND InvDate BETWEEN @dateFrom AND @DateTo and PtStatus = 'Indoor'
--GROUP BY PatientId, PatientName
) aa
GROUP BY aa.PatientId, aa.PatientName
END
GO
